// --- Built-in menu command ids ----------------------------------------
//
// The host's built-in WM_COMMAND ids live in 1000..=1999. Plugin
// command ids start at PLUGIN_CMD_ID_BASE = 50000, well above any
// host-built-in. Two ranges inside 1000..=1999 are *dynamic* ŌĆö the
// cmd id encodes a parameter the WM_COMMAND handler decodes back:
//
//   ID_LANGUAGE_BASE..ID_LANGUAGE_END  ŌåÆ LangType id
//   ID_WINDOW_BASE..ID_WINDOW_END      ŌåÆ tab index
//
// The static ids below avoid those two ranges so a click on a static
// item never collides with a dynamic one.
//
// File (1000-1099)
const ID_FILE_SAVE: u16 = 1000;
const ID_FILE_EXIT: u16 = 1001;
const ID_FILE_CLOSE: u16 = 1002;
const ID_FILE_NEW: u16 = 1003;
const ID_FILE_OPEN: u16 = 1004;
const ID_FILE_SAVE_AS: u16 = 1005;
const ID_FILE_SAVE_ALL: u16 = 1006;
const ID_FILE_CLOSE_ALL: u16 = 1007;
const ID_FILE_RELOAD: u16 = 1008;
const ID_FILE_PRINT: u16 = 1009;
const ID_FILE_RENAME: u16 = 1010;
/// File ŌåÆ Open in Default Viewer. Passes the active tab's on-disk
/// path to the OS's registered handler for that file's extension
/// via `ShellExecuteW("open", ...)`. Greyed when the active tab
/// has no on-disk path (untitled) or its extension has no
/// registered handler on the current machine. Refreshed on every
/// `WM_INITMENUPOPUP` for the File menu ŌĆö see
/// [`refresh_file_menu`].
const ID_FILE_OPEN_IN_DEFAULT_VIEWER: u16 = 1011;
/// File ŌåÆ Open Folder as Workspace... Opens the OS folder picker;
/// the chosen folder becomes the root of the Workspace panel
/// (left of the tab strip / editor). Reveals the panel if hidden.
/// Wired progressively across four milestones ŌĆö see the plan on
/// the Phase 4.6 "Workspace" feature:
///   * m1: menu entry defined, logs on click (this commit).
///   * m2: folder picker + panel frame + header X close.
///   * m3: `SysTreeView32` body with lazy `read_dir` on expand,
///     three action buttons.
///   * m4: `Session` round-trip + View menu toggle.
const ID_FILE_OPEN_FOLDER_AS_WORKSPACE: u16 = 1012;

// Workspace tree right-click context menu (1013-1021) ŌĆö surfaced by
// `show_workspace_tree_context_menu` when the user right-clicks a
// node in the Folder-as-Workspace `SysTreeView32`. The clicked
// item's path + kind are stashed on
// `WindowState.workspace_ctx_target` just before `TrackPopupMenu`;
// the WM_COMMAND handler for each id reads them back and drops the
// stash. Ids are dispatched by `main_wnd_proc` (not the panel's
// wnd_proc) because the popup is posted with `TPM_RETURNCMD` +
// `PostMessageW` to the main window ŌĆö same routing shape as the
// status-bar language menu.
const ID_WORKSPACE_CTX_REMOVE: u16 = 1013;
const ID_WORKSPACE_CTX_COPY_PATH: u16 = 1014;
const ID_WORKSPACE_CTX_COPY_FILE_NAME: u16 = 1015;
const ID_WORKSPACE_CTX_FIND_IN_FILES: u16 = 1016;
const ID_WORKSPACE_CTX_OPEN_FILE: u16 = 1017;
const ID_WORKSPACE_CTX_RUN_BY_SYSTEM: u16 = 1018;
const ID_WORKSPACE_CTX_EXPLORER: u16 = 1019;
const ID_WORKSPACE_CTX_CMD: u16 = 1020;
const ID_WORKSPACE_CTX_POWERSHELL: u16 = 1021;

// File ŌåÆ Open Containing Folder submenu (1022-1025). Each entry
// acts on the parent directory of the active tab's on-disk path;
// all four are greyed by `refresh_file_menu` when the active tab
// is untitled (no path). Explorer / cmd / PowerShell share the
// shell-launcher helpers the workspace-tree context menu uses;
// "Folder as Workspace" routes to `show_workspace_panel` at the
// parent directory (opens the panel if hidden, re-roots in place
// if already open ŌĆö same idempotent path the picker uses).
const ID_FILE_OPEN_CONTAINING_EXPLORER: u16 = 1022;
const ID_FILE_OPEN_CONTAINING_CMD: u16 = 1023;
const ID_FILE_OPEN_CONTAINING_POWERSHELL: u16 = 1024;
const ID_FILE_OPEN_CONTAINING_WORKSPACE: u16 = 1025;

// File ŌåÆ Close Multiple Documents submenu (1026-1030). Each entry
// closes a specific subset of open tabs. All five share the same
// underlying loop as ID_FILE_CLOSE_ALL: repeatedly pick the next
// target tab per a variant-specific predicate, activate it (so
// its Scintilla document is bound and the dirty-check + save
// prompt work correctly), then reuse `handle_close_active_tab_with_outcome`
// so per-tab dirty prompts + `CloseOutcome::Aborted` short-circuit
// exactly like Close All. Greyed by `refresh_file_menu` per
// per-entry preconditions (only-one-tab, no-tabs-to-left, etc.).
const ID_FILE_CLOSE_ALL_BUT_ACTIVE: u16 = 1026;
const ID_FILE_CLOSE_ALL_BUT_PINNED: u16 = 1027;
const ID_FILE_CLOSE_ALL_TO_LEFT: u16 = 1028;
const ID_FILE_CLOSE_ALL_TO_RIGHT: u16 = 1029;
const ID_FILE_CLOSE_ALL_UNCHANGED: u16 = 1030;

/// File ŌåÆ Move to Recycle Bin. Shows a confirmation dialog with
/// the active file's absolute path; on OK, closes the active
/// tab (discarding any unsaved edits ŌĆö deleting a file is an
/// "I'm done with it" action; prompting to save first before
/// moving to trash is nonsensical) and hands the path to
/// `SHFileOperationW(FO_DELETE | FOF_ALLOWUNDO)` so the OS
/// performs its standard recycle-bin move (identical to a
/// user-initiated Delete in Explorer). Greyed for untitled
/// buffers via `refresh_file_menu`.
const ID_FILE_MOVE_TO_RECYCLE_BIN: u16 = 1031;

/// File ŌåÆ Print Preview... ŌĆö opens a modal window showing the active
/// document paginated against the default printer's metrics.
/// Navigation via [< First / < Prev / > Next / >| Last] plus keyboard
/// (arrows + PgUp/PgDn + Home/End); the Print button chains into
/// the same OS `PrintDlg` flow as [`ID_FILE_PRINT`] once the preview
/// closes.
const ID_FILE_PRINT_PREVIEW: u16 = 1034;

/// File ŌåÆ Load Session... ŌĆö pick a Notepad++-shaped session XML from
/// disk, parse its `<File>` list, and open every path referenced. The
/// per-file metadata (caret position, pin state, language override)
/// is applied automatically by `Shell::apply_load_result` because we
/// pre-populate `shell.session.tabs` with the parsed entries before
/// kicking each load ŌĆö same lookup mechanism the internal
/// startup-restore path uses.
const ID_FILE_LOAD_SESSION: u16 = 1032;
/// File ŌåÆ Save Session... ŌĆö prompt for a `.xml` path and write the
/// currently-open, path-bound tabs in Notepad++'s session shape
/// (`<NotepadPlus><Session><mainView><File .../></mainView></Session></NotepadPlus>`).
/// Untitled buffers are skipped (no path to record). Interchange-only:
/// the internal auto-persist `session.xml` uses Code++'s native
/// schema and is unaffected.
const ID_FILE_SAVE_SESSION: u16 = 1033;

// Edit (1100-1199) ŌĆö most route directly to Scintilla via SCI_*.
const ID_EDIT_UNDO: u16 = 1100;
const ID_EDIT_REDO: u16 = 1101;
const ID_EDIT_CUT: u16 = 1102;
const ID_EDIT_COPY: u16 = 1103;
const ID_EDIT_PASTE: u16 = 1104;
const ID_EDIT_DELETE: u16 = 1105;
const ID_EDIT_SELECTALL: u16 = 1106;

// Search (1200-1299) ŌĆö disabled stubs until Phase 4 m3 wires
// Find/Replace dialogs.
const ID_SEARCH_FIND: u16 = 1200;
const ID_SEARCH_FINDNEXT: u16 = 1201;
const ID_SEARCH_FINDPREV: u16 = 1202;
const ID_SEARCH_REPLACE: u16 = 1203;
const ID_SEARCH_FINDINFILES: u16 = 1204;
const ID_SEARCH_GOTOLINE: u16 = 1205;

// View (1300-1399).
const ID_VIEW_WORDWRAP: u16 = 1300;
const ID_VIEW_SHOWWS: u16 = 1301;
const ID_VIEW_SHOWEOL: u16 = 1302;
const ID_VIEW_ZOOMIN: u16 = 1303;
const ID_VIEW_ZOOMOUT: u16 = 1304;
const ID_VIEW_ZOOMRESET: u16 = 1305;
// Toolbar-only View entries ŌĆö no menu items in M2; clicking these
// fires `WM_COMMAND` that falls through to the default arm until
// a future commit wires the underlying feature.
const ID_VIEW_SHOW_ALL_CHARS: u16 = 1306;
const ID_VIEW_SHOW_INDENT_GUIDE: u16 = 1307;
const ID_VIEW_SYNC_V_SCROLL: u16 = 1308;
const ID_VIEW_SYNC_H_SCROLL: u16 = 1309;
const ID_VIEW_DOCMAP: u16 = 1310;
const ID_VIEW_DOCLIST: u16 = 1311;
const ID_VIEW_FUNCLIST: u16 = 1312;
const ID_VIEW_FOLDER_AS_WORKSPACE: u16 = 1313;

// Encoding (1400-1499) ŌĆö m1 ships the menu shape with disabled
// conversion stubs; the radio marker reflects the active buffer's
// encoding for plugins/users that read the menu state. m5 wires
// the conversions.
//
// Order matters: `CheckMenuRadioItem` takes a [first_id, last_id]
// closed range to clear-then-set. If the range is inverted the
// "clear other items in range" pass becomes a no-op and stale
// radio marks pile up. Keep these strictly ascending.
const ID_ENCODING_ANSI: u16 = 1400;
const ID_ENCODING_UTF8: u16 = 1401;
const ID_ENCODING_UTF8_BOM: u16 = 1402;
const ID_ENCODING_UTF16_LE: u16 = 1403;
const ID_ENCODING_UTF16_BE: u16 = 1404;

// Language (1500-1599) ŌĆö *dynamic*: cmd id = ID_LANGUAGE_BASE +
// LangType numeric id. LangType ids run 0..=93 in the N++ ABI; we
// reserve a 100-wide window so the full set fits. `_END` is the
// last valid id (inclusive), giving 100 slots [BASE, END].
const ID_LANGUAGE_BASE: u16 = 1500;
const ID_LANGUAGE_END: u16 = 1599;
const ID_LANGUAGE_CAP: usize = (ID_LANGUAGE_END - ID_LANGUAGE_BASE + 1) as usize;

// Settings / Tools / Macro / Run (1600-1699) ŌĆö disabled stubs.
const ID_SETTINGS_PREFERENCES: u16 = 1600;
const ID_SETTINGS_STYLECONFIGURATOR: u16 = 1601;

// Window (1700-1799) ŌĆö *dynamic*: cmd id = ID_WINDOW_BASE + tab idx.
// 100-wide window caps the visible-by-shortcut tab list. `_END` is
// inclusive (last valid id); `_CAP` is the count of usable slots.
const ID_WINDOW_BASE: u16 = 1700;
const ID_WINDOW_END: u16 = 1799;
const ID_WINDOW_CAP: usize = (ID_WINDOW_END - ID_WINDOW_BASE + 1) as usize;

// Help (1800-1899).
const ID_HELP_ABOUT: u16 = 1800;
/// Help ŌåÆ Code++ Home. Opens [`HELP_HOME_URL`] in the user's
/// default browser via the shared [`open_url_in_browser`] helper.
const ID_HELP_HOME: u16 = 1801;
/// Help ŌåÆ Code++ Project Page. Opens [`HELP_PROJECT_URL`].
const ID_HELP_PROJECT: u16 = 1802;
/// Help ŌåÆ Code++ Online User Manual. Greyed until the manual site
/// exists ŌĆö the command id is reserved so the menu is consistent
/// across builds even while the target isn't wired.
const ID_HELP_MANUAL: u16 = 1803;
/// Help ŌåÆ Code++ Community (Forum). Opens [`HELP_COMMUNITY_URL`].
const ID_HELP_COMMUNITY: u16 = 1804;
/// Help ŌåÆ Update Code++. Greyed until an update mechanism is
/// implemented; id reserved so the menu placement is stable.
const ID_HELP_UPDATE: u16 = 1805;

/// Home page for Code++. Compile-time constant so no
/// user-controlled string ever reaches `ShellExecuteW`. Same
/// safety rationale as [`UDL_COLLECTION_URL`].
const HELP_HOME_URL: &str = "https://code-plus-plus.org/";
/// Public "project page" for Code++ ŌĆö the GitHub mirror.
/// DESIGN.md ┬¦9.3 documents git.fiedler.live/tux/code-plus-plus
/// as the canonical Forgejo instance and describes the GitHub
/// mirror as read-only; this URL is the specific mirror the
/// project's owner chose to publish under. The user-facing
/// "project page" menu entry lands here rather than the Forgejo
/// URL because the GitHub view is what most drive-by contributors
/// expect from a "project page" link.
const HELP_PROJECT_URL: &str = "https://github.com/TheFlipside/code-plus-plus";
/// Discourse-style community forum for Code++ users.
const HELP_COMMUNITY_URL: &str = "https://community.code-plus-plus.org/";

// Tools (1900-1999) ŌĆö toolbar-only entries for features that aren't
// implemented yet. Clicking falls through; the IDs reserve the
// command space so the toolbar's button table is complete.
const ID_TOOLS_DEFINE_LANG: u16 = 1900;
const ID_TOOLS_MONITORING: u16 = 1901;

// UDL (User Defined Language) menu ŌĆö Phase 4.6 m2.
//
// Three static command IDs for the fixed "User-Defined language"
// submenu entries. `DEFINE_LANGUAGE` stays greyed until m3 lands
// the editor modal; the two `OPEN_*` handlers wire `ShellExecuteW`
// to launch the OS file-explorer and the default browser
// respectively. The dynamic list of loaded UDLs lands with m1b
// (startup scan) and m1d (menu wiring); it will occupy a separate
// reserved range immediately below `ID_UDL_ITEM_END` so a click on
// a UDL entry can be dispatched with a single range check.
const ID_UDL_DEFINE_LANGUAGE: u16 = 2100;
const ID_UDL_OPEN_FOLDER: u16 = 2101;
const ID_UDL_OPEN_COLLECTION: u16 = 2102;
// Dynamic loaded-UDL menu items. `ID_UDL_ITEM_BASE +
// (lang_type_id - UDL_LANG_TYPE_BASE)` becomes the item's command
// id ŌĆö same encoding scheme as the built-in `ID_LANGUAGE_BASE +
// lang.as_npp_id()` rows. The range accommodates ~900 UDLs, which
// is comfortably past any realistic user's collection size. Wired
// by `append_udls_to_menu` (menu build), `set_udl_radio_mark` +
// `clear_all_language_menu_marks` (state refresh), and the
// `WM_COMMAND` dispatch arm that inverts the encoding back to a
// `LangType` id.
const ID_UDL_ITEM_BASE: u16 = 2200;
const ID_UDL_ITEM_END: u16 = 3099;

/// Notepad++ User Defined Languages Collection URL ŌĆö the community
/// showcase of UDL XML files linked from N++'s own Language menu.
/// Opened by [`ID_UDL_OPEN_COLLECTION`] via `ShellExecuteW("open",
/// url, ...)` which routes to the user's default browser. Constant
/// so the URL is (a) an unmodifiable compile-time value that
/// cannot be reached by an attacker-controlled path and (b) easy
/// to grep for when N++ eventually renames or moves the repo.
const UDL_COLLECTION_URL: &str = "https://github.com/notepad-plus-plus/userDefinedLanguages";
/// Plugins ŌåÆ Plugin Manager... menu item. Opens the modal admin
/// dialog that lists installed plugins and lets the user toggle
/// the per-plugin enabled flag (persisted to
/// `<plugins_config_dir>/disabled.txt`).
const ID_PLUGINS_ADMIN: u16 = 1910;

// Macro (2000-2099) ŌĆö toolbar-only entries; same M2 status.
const ID_MACRO_RECORD: u16 = 2000;
const ID_MACRO_STOP: u16 = 2001;
const ID_MACRO_PLAY: u16 = 2002;
const ID_MACRO_RUN_MULTIPLE: u16 = 2003;
const ID_MACRO_SAVE: u16 = 2004;

/// Our cross-thread wake-up message. Producer threads `PostMessage`
/// this to drag the UI thread out of its `GetMessageW` idle and into
/// the `Shell::drain` path.
const WM_APP_WAKE: u32 = WM_APP + 1;

/// Timer id used by `SetTimer` for the periodic session auto-save.
/// The value is local to the main window's timer table; any
/// non-zero `usize` distinct from other timers on the same HWND
/// works. We have only one timer on the main window, so `1` is
/// fine.
const AUTOSAVE_TIMER_ID: usize = 1;
/// Height of the marquee progress bar overlay shown during the
/// async "Unfold All" walk. Standard Win32 progress bar height.
const WORKSPACE_UNFOLD_PROGRESS_HEIGHT_PX: i32 = 16;
/// Gap between the progress bar and its "Expanding folders: N"
/// label directly below it.
const WORKSPACE_UNFOLD_PROGRESS_GAP_PX: i32 = 6;
/// Height reserved for the status label under the progress bar.
const WORKSPACE_UNFOLD_LABEL_HEIGHT_PX: i32 = 18;
/// Batch size for the async "Unfold All" walk ŌĆö folders processed
/// per `WM_TIMER` tick. Because the tree is hidden during the
/// walk (see `Self::workspace_unfold_progress`), mid-tick paint
/// isn't visible, so we can be a bit aggressive here without
/// re-introducing the flicker. 20 folders ├Ś ~15 ms tick =
/// ~1300 folders/sec ŌĆö a 5000-folder workspace unfolds in ~4 s.
const WORKSPACE_UNFOLD_BATCH_SIZE: usize = 20;
/// `PBM_SETMARQUEE` (`WM_USER + 10`) ŌĆö turns marquee animation
/// on/off. `WPARAM = 1` to start with an interval of `LPARAM`
/// milliseconds; `WPARAM = 0` to stop. Not exposed by windows-rs
/// 0.62 under a stable name, so declared here as a literal.
const PBM_SETMARQUEE: u32 = 0x040A;
/// `PBS_MARQUEE` (0x08) ŌĆö window style that makes the progress
/// bar accept `PBM_SETMARQUEE` and animate. Not exposed under a
/// stable name in windows-rs 0.62.
const PBS_MARQUEE: u32 = 0x08;

/// Timer id for the async "Unfold All" walk on the workspace
/// tree. Each tick processes one folder ŌĆö expanding it (which
/// fires `TVN_ITEMEXPANDING` ŌåÆ lazy `read_dir`) and enqueueing
/// its subfolders for later ticks. Fires every 5 ms while
/// `workspace_unfold_pending` is non-empty; the timer is killed
/// when the queue drains. Bounded work per tick keeps the UI
/// responsive on very large workspaces ŌĆö the alternative (one
/// synchronous walk of the entire tree) froze the app on any
/// workspace big enough to notice, which is exactly the N++
/// behaviour we set out to avoid.
const WORKSPACE_UNFOLD_TIMER_ID: usize = 2;

/// Auto-save period in milliseconds. 7 s matches Notepad++'s
/// default for its "auto-save unsaved buffers" backup loop ŌĆö
/// short enough that a crash loses at most a few seconds of work,
/// long enough that the per-tick capture (one `SCI_GETMODIFY` per
/// tab plus a `SCI_GETTEXT` for each dirty tab) doesn't introduce
/// perceptible cost during normal use.
const AUTOSAVE_INTERVAL_MS: u32 = 7_000;

const MAIN_CLASS: PCWSTR = w!("CodePlusPlusMainWindow");
