/// Tab strip height in pixels. Bumped ~1.4x above the 22-px Win32
/// default so the tab bar reads as its own chrome band ŌĆö the
/// tighter default cell felt cramped once the surrounding toolbar /
/// status bar sat in Code++'s light chrome ŌĆö but held back from a
/// full 2x (44) which read as excessive next to the toolbar. The
/// cell height is bumped in lockstep via [`TAB_TEXT_PADDING_Y_PX`]
/// so the tab cells fill the strip and don't leave a bare band on
/// top. Once `layout_children` becomes DPI-aware (Phase 4 polish
/// item) this becomes a measured value via `TCM_GETITEMRECT`.
/// Promoted to a module-level constant so the splitter clamp
/// computation in `splitter_wnd_proc` shares the same source of
/// truth.
const TAB_HEIGHT_PX: i32 = 30;

/// Status bar height in pixels. Same DPI-deferral rationale as
/// `TAB_HEIGHT_PX`.
const STATUS_HEIGHT_PX: i32 = 22;

/// Pixel inset between the Scintilla view and the surrounding
/// chrome (tab strip above, status bar below, window edges left
/// and right). The parent's `WM_ERASEBKGND` paints the strips
/// revealed by this inset in [`editor_border_brush`], producing
/// a clearly visible delimiter around the edit area on every
/// side. 2 px reads cleanly at 96 DPI; 1 px was visually subtle
/// in screenshots.
const EDITOR_BORDER_PX: i32 = 2;

/// Height of the splitter handle between the editor and the FIF
/// results dock. 4 px is the smallest band that's still draggable
/// without the user having to pixel-hunt; matches the splitter
/// thickness in N++.
const SPLITTER_HEIGHT_PX: i32 = 4;
/// Initial dock height the first time the user shows the FIF panel.
/// Persistence across sessions is a Phase 4 m4 step 4 polish item;
/// for now every shell launch starts at this default.
const DEFAULT_DOCK_HEIGHT_PX: i32 = 200;
/// Minimum dock height while the panel is shown. Below this the
/// listview can't render even one usable row, so the splitter
/// clamps to this value when the user drags down.
const MIN_DOCK_HEIGHT_PX: i32 = 60;
/// Minimum Scintilla height the splitter preserves while the dock
/// is shown. The user can shrink the dock but never the editor;
/// this matches N++'s "the editor is the priority surface" feel.
const MIN_SCINTILLA_HEIGHT_PX: i32 = 60;

/// Width of the vertical splitter between the workspace panel and
/// the tab-strip / editor column. Matches [`SPLITTER_HEIGHT_PX`]'s
/// 4 px rationale ŌĆö draggable without pixel-hunting.
const WORKSPACE_SPLITTER_WIDTH_PX: i32 = 4;
/// Initial workspace-panel width the first time the user opens a
/// folder. Enough for a ~30-char folder name at a typical
