const FR_CHECKBOX_X: i32 = 14;
const FR_CHECKBOX_W: i32 = 200;
const FR_CHECKBOX_H: i32 = 20;
const FR_CHECKBOX_GAP: i32 = 22;
const FR_DLG_ROW1_Y: i32 = 50;
const FR_DLG_ROW_GAP: i32 = 32;
const FR_DLG_REPLACE_ROW_Y: i32 = FR_DLG_ROW1_Y + FR_DLG_ROW_GAP;
const FR_DLG_FIF_FILTERS_Y: i32 = FR_DLG_REPLACE_ROW_Y + FR_DLG_ROW_GAP;
const FR_DLG_FIF_DIRECTORY_Y: i32 = FR_DLG_FIF_FILTERS_Y + FR_DLG_ROW_GAP;
/// Y of the topmost checkbox in the dialog. The 40 px offset
/// past the last edit row leaves space for the combobox dropdown
/// arrow without clipping.
const FR_CHECKBOX_TOP: i32 = FR_DLG_FIF_DIRECTORY_Y + 40;

/// `IDCANCEL` re-projected as `u16` for use in match arms. `IDCANCEL`
/// itself is `MESSAGEBOX_RESULT(2)` in windows-rs and can't appear as
/// a u16 pattern directly.
const IDCANCEL_U16: u16 = IDCANCEL.0 as u16;

/// One per-file FIF outcome buffered while a search is running.
/// The owning [`WindowState`] flushes these into the listview on
/// `FifEvent::Done`.
struct FifPendingFile {
    path: PathBuf,
    matches: Vec<codepp_core::FifMatch>,
    truncated: bool,
}

/// Mapping from a listview row index back to a source location.
/// The `NM_DBLCLK` handler queues an open + a post-load caret jump
/// to the matched span. Line is 1-based as the search engine
/// reports it; cols are UTF-8 byte offsets within the line, which
/// is what Scintilla's position arithmetic expects. Selecting the
/// span (rather than just placing the caret) makes the match
/// instantly visible without further user interaction.
#[derive(Clone)]
struct FifListviewRow {
    path: PathBuf,
    line_no: u32,
    col_start: u32,
    col_end: u32,
}

/// Drag-tracking state captured on `WM_LBUTTONDOWN` over the FIF
/// splitter and consumed on each `WM_MOUSEMOVE` until the matching
/// `WM_LBUTTONUP`. Stored on `WindowState` rather than the splitter
/// itself so the splitter `wnd_proc` stays a thin forwarder; reading
/// the parent's state is one `state_from_hwnd(GetParent(...))` away.
#[derive(Debug, Clone, Copy)]
struct SplitterDrag {
    /// Cursor Y in screen coords at the moment the user pressed.
    /// Compared against `GetCursorPos` on each `WM_MOUSEMOVE` so the
    /// drag tracks the cursor rather than the splitter (which is
    /// itself moving as the user drags).
    start_screen_y: i32,
    /// Dock height when the user started the drag. The new height
    /// is `dock_height_at_start + (start_screen_y - current_y)` ŌĆö
    /// dragging up grows the dock.
    dock_height_at_start: i32,
}

/// Horizontal-axis sibling of [`SplitterDrag`] ŌĆö captured by the
/// workspace splitter's `WM_LBUTTONDOWN`, consumed on each
/// `WM_MOUSEMOVE`, cleared on `WM_LBUTTONUP`. Kept as a
/// distinct type from `SplitterDrag` so the axis is visible in
/// the field's type and a mixup between the two splitters would
/// fail to compile.
#[derive(Debug, Clone, Copy)]
struct WorkspaceSplitterDrag {
    /// Cursor X in screen coords at drag start. New workspace
    /// width = `width_at_start + (current_x - start_screen_x)` ŌĆö
    /// dragging right grows the panel.
    start_screen_x: i32,
    /// Workspace column width at drag start.
    width_at_start: i32,
}

/// Drag-tracking state for the Document Map splitter ŌĆö mirror of
/// [`WorkspaceSplitterDrag`] on the right column. The sign
/// convention flips: dragging LEFT grows the panel because the
/// panel sits at the right edge, splitter to its left.
#[derive(Debug, Clone, Copy)]
struct DocMapSplitterDrag {
    /// Cursor X in screen coords at drag start. New docmap width
    /// = `width_at_start - (current_x - start_screen_x)` ŌĆö
    /// dragging left grows the panel.
    start_screen_x: i32,
    /// Docmap column width at drag start.
    width_at_start: i32,
}

/// Drag-tracking state for scroll-by-drag on the Document Map's
/// miniature view. On mouse-down inside the map view, the map's
/// `wnd_proc` subclass takes capture and stores this marker;
/// every subsequent `WM_MOUSEMOVE` while the marker is present
/// scrolls the main editor to the line under the cursor.
/// Released on `WM_LBUTTONUP` or `WM_CAPTURECHANGED`. Stored on
/// the parent state rather than on the subclass so the map's
/// subclass `wnd_proc` stays a thin forwarder ŌĆö same pattern the
/// workspace
/// splitter uses.
#[derive(Debug, Clone, Copy)]
struct DocMapScrollDrag {
    /// Non-empty marker. No fields today ŌĆö the current-cursor
    /// position is read fresh on every `WM_MOUSEMOVE` via
    /// `SCI_POSITIONFROMPOINTCLOSE`. A struct rather than a
    /// bare bool leaves room for future scroll-drag state
    /// (initial-line snapshot for "cancel to original scroll,"
    /// scroll offset accumulator, ŌĆ”) without a wire-format
    /// change to `WindowState`.
    _priv: (),
}

/// Drag-tracking state for tab reordering. Captured on
/// `WM_LBUTTONDOWN` over a tab by the tab control's subclass proc
/// and consumed on each `WM_MOUSEMOVE` until the matching
/// `WM_LBUTTONUP`/`WM_CAPTURECHANGED`. Lives on `WindowState`
/// (alongside `SplitterDrag`) rather than the subclass proc itself
/// so the proc stays a thin forwarder.
#[derive(Debug, Clone, Copy)]
struct TabDrag {
    /// Index in `Shell.tabs` of the tab the user grabbed. Updated
    /// after every successful neighbour-swap so subsequent
    /// `WM_MOUSEMOVE`s "carry" the dragged tab toward the cursor.
    source_idx: usize,
    /// Cursor X in tab-control client coords at the moment the
    /// user pressed. Movement past `TAB_DRAG_THRESHOLD_PX` from
    /// this anchor flips `threshold_passed` and starts the
    /// reorder; before that point a click that happens to wiggle
    /// a pixel doesn't trigger a phantom no-op drag.
    start_x: i32,
    /// `false` until the user has moved more than
    /// `TAB_DRAG_THRESHOLD_PX` from `start_x`; once set, every
    /// further `WM_MOUSEMOVE` evaluates a swap with the tab under
    /// the cursor. The flag is sticky for the duration of the
    /// drag ŌĆö once a click qualifies as a drag, dragging back
    /// over the original tab still allows further reordering.
    threshold_passed: bool,
}

/// Pixels the cursor must travel from its `WM_LBUTTONDOWN` anchor
/// before a tab click promotes to a drag. Matches the system's
/// drag-detection threshold closely enough that clicks feel
/// instant; could be replaced by `GetSystemMetrics(SM_CXDRAG)` if
/// per-user calibration ever matters.
const TAB_DRAG_THRESHOLD_PX: i32 = 4;

/// One plugin-registered docking dialog. Plugins call
/// `NPPM_DMMREGASDCKDLG` with a `tTbData` whose `h_client` is the
/// plugin's pre-built dialog HWND; the host wraps that HWND in a
/// `frame_hwnd` it owns and re-parents `h_client` into the frame's
/// client area. The frame's title comes from `name`; the
/// `module_name` is kept so `NPPM_DMMGETPLUGINHWNDBYNAME` can
/// disambiguate when two plugins register dialogs with the same
/// display name.
///
/// Floating-only mode (Phase 4 m4) does not yet act on the
/// docking-position bits in `u_mask` (`DWS_DF_CONT_*`), the
/// `pszAddInfo` add-info string, or the `iPrevCont` previous-
/// container hint. Those become live in the Phase 5 docking
/// manager bring-up.
struct DockEntry {
    /// Plugin's pre-built dialog HWND. Re-parented into
    /// `frame_hwnd`'s client area at registration time. The
    /// plugin retains lifetime ownership; the host MUST NOT
    /// `DestroyWindow` it.
    h_client: HWND,
    /// Host-owned floating frame. Created `WS_OVERLAPPEDWINDOW |
    /// WS_EX_TOOLWINDOW`-style so the user gets a normal
    /// resizable mini-window with title and close buttons but no
    /// taskbar entry. Destroyed by Win32 when the main window
    /// dies (the frame is `owned` by the main HWND).
    frame_hwnd: HWND,
    /// Display title ŌĆö also the lookup key for
    /// `NPPM_DMMGETPLUGINHWNDBYNAME`. Owned `String`; re-read
    /// from the plugin's `pszName` at registration and not
    /// updated thereafter (Phase 5 polish: refresh on
    /// `NPPM_DMMUPDATEDISPINFO`).
    name: String,
    /// Plugin DLL filename without extension; the optional
    /// disambiguator for the two-arg form of
    /// `NPPM_DMMGETPLUGINHWNDBYNAME`.
    module_name: String,
    /// `tTbData.dlg_id` ŌĆö carried in `nmhdr.idFrom` for any
    /// future `DMN_*` notification routed back to the plugin
    /// (`DMN_CLOSE` in particular, deferred to Phase 5).
    #[allow(dead_code)]
    dlg_id: i32,
    /// Snapshot of `tTbData.u_mask` at registration time.
    /// Floating-only mode currently checks only `DWS_ICONTAB`;
    /// the other bits are kept for Phase 5.
    #[allow(dead_code)]
    u_mask: u32,
}

/// Per-window state. Box-allocated, pointer stashed in
/// `GWLP_USERDATA`. `wnd_proc` reads it back via
/// `GetWindowLongPtrW(GWLP_USERDATA)` on every message. The main
/// window's own HWND is passed to `wnd_proc` on every dispatch, so we
/// don't store it here.
struct WindowState {
    scintilla_hwnd: HWND,
    status_hwnd: HWND,
    /// Toolbar control HWND. Sits between the menu bar and the tab
    /// strip; populated with file/edit/search/view/macro buttons
    /// bound to existing menu IDs (see `mod toolbar`). One image
    /// list shared by every button ŌĆö destroyed in `WM_DESTROY`.
    toolbar_hwnd: HWND,
    /// Image list that backs `toolbar_hwnd`. Owned by the window ŌĆö
    /// `ImageList_Destroy` runs on shutdown so the bitmaps don't
    /// outlive the toolbar that draws them.
    toolbar_image_list: windows::Win32::UI::Controls::HIMAGELIST,
    /// Bitmap pixel size (24 or 48) chosen at toolbar creation
    /// time based on system DPI. Cached on `WindowState` so the
    /// layout pass doesn't repeat the DPI probe ŌĆö `toolbar_height_px`
    /// derives from this.
    toolbar_bitmap_px: i32,
    /// Win32 tab control HWND. Sits between the menu bar and the
    /// Scintilla view; one tab item per `Shell.tabs[i]`. Multi-tab
    /// (Phase 3 milestone 6b) uses `SCI_SETDOCPOINTER` to repoint
    /// the single Scintilla view at the active tab's document on
    /// each click.
    tab_hwnd: HWND,
    /// Number of tab items currently inserted into [`Self::tab_hwnd`].
    /// Compared against `state.shell.tabs.len()` after each drain
    /// so newly-pushed Shell tabs get a tab-control item without
    /// rebuilding the whole strip from scratch.
    synced_tab_count: usize,
    /// HMENU for the main menu bar ŌĆö the parent of File/Edit/.../Plugins.
    /// Plugins query this via `NPPM_GETMENUHANDLE(NPPMAINMENU)` to
    /// install accelerator-bound items at the top level.
    main_menu: HMENU,
    /// Accelerator table the message pump consults via
    /// `TranslateAcceleratorW`. Lives on `WindowState` (rather
    /// than as a `run()`-local) so plugin-driven mutations
    /// (`NPPM_REMOVESHORTCUTBYCMDID` and the future
    /// `NPPM_SHORTCUT*` write paths) can replace the handle:
    /// Win32 has no in-place accelerator-table mutation API, so
    /// "remove a binding" is implemented as
    /// "copy ŌåÆ filter ŌåÆ create new ŌåÆ destroy old ŌåÆ swap." The
    /// pump reads this slot fresh on every iteration so a
    /// recreate inside a `WM_COMMAND` / NPPM dispatch takes
    /// effect on the very next keystroke. Cleaned up via
    /// `DestroyAcceleratorTable` in `WM_DESTROY`.
    accel_handle: HACCEL,
    /// HMENU for the per-plugin submenu under "Plugins". Plugins query
    /// this via `NPPM_GETMENUHANDLE(NPPPLUGINMENU)` to add their menu
    /// items. Populated lazily on the first `WM_INITMENUPOPUP` for
    /// this submenu (DESIGN.md ┬¦6.4 lazy-load contract).
    plugin_menu: HMENU,
    /// Set once the lazy-load + menu-population dance has run for
    /// `plugin_menu`. Subsequent `WM_INITMENUPOPUP` for the same
    /// menu skip the work; we never reload plugins after the first
    /// touch, even if the user re-opens the menu.
    plugins_menu_initialized: bool,
    /// HMENUs of the five menus whose contents reflect live state
    /// (File ŌåÆ Open in Default Viewer greyed state, encoding
    /// radio, language radio, View toggle/check marks, Window's
    /// per-tab list). The popup HMENU on `WM_INITMENUPOPUP` is
    /// matched against these to dispatch the right refresh
    /// routine.
    file_menu: HMENU,
    view_menu: HMENU,
    encoding_menu: HMENU,
    language_menu: HMENU,
    window_menu: HMENU,
    /// Right-edge open-tabs `Ō¢╝` popup. Same content as `window_menu`
    /// ŌĆö rebuilt on `WM_INITMENUPOPUP` by `refresh_window_menu`.
    /// Kept as a separate HMENU so the menu-bar match in the popup
    /// dispatcher can identify which one is opening.
    right_shortcuts_menu: HMENU,
    /// HWND of the modeless Find/Replace dialog, lazily created on
    /// the first Ctrl+F / Ctrl+H / menu click. The main message
    /// loop reads this in `IsDialogMessageW(dlg, &msg)` so Tab /
    /// Enter / Esc work inside the dialog while it's open.
    find_replace_dlg: Option<HWND>,
    /// HWND of the modeless UDL editor dialog (Phase 4.6 m3),
    /// lazily created on the first "Define your languageŌĆ”"
    /// menu click. Same discipline as `find_replace_dlg`: the
    /// main message pump routes `IsDialogMessageW` to it, and a
    /// second menu click reuses the existing HWND rather than
    /// opening a duplicate. Cleared on the editor's `WM_DESTROY`
    /// via the [`udl_editor::WM_APP_UDL_CLOSED`] notification.
    udl_editor_dlg: Option<HWND>,
    /// Plugin-registered modeless-dialog HWNDs. Plugins call
    /// `NPPM_MODELESSDIALOG(MODELESSDIALOGADD, hwnd)` to add a
    /// dialog so the message pump consults it via
    /// `IsDialogMessageW` (Tab / Enter / Esc / mnemonic
    /// handling); `MODELESSDIALOGREMOVE` removes it. Plugins own
    /// the dialog lifetime ŌĆö they're contracted to call REMOVE
    /// before destroying the HWND. Stored as a Vec because
    /// multiple plugins can each register their own dialogs
    /// (unlike `find_replace_dlg`, which is host-owned and
    /// single-instance).
    plugin_modeless_dialogs: Vec<HWND>,
    /// Plugin-registered dockable dialogs (floating-only mode for
    /// Phase 4 m4 ŌĆö the multi-zone docking manager lands in Phase
    /// 5). Each entry pairs the plugin's `h_client` HWND with the
    /// host-owned floating frame that wraps it. Driven by the
    /// `NPPM_DMM*` family; the Vec is small (typically 1ŌĆō4
    /// entries) so linear scans are fine for show / hide / lookup.
    /// Cleaned up implicitly when the main window dies ŌĆö the
    /// frames are owned by the main HWND so Win32 destroys them
    /// alongside.
    dock_dialogs: Vec<DockEntry>,
    /// FIF results dock (Phase 4 m4 step 3). Hidden until a search
    /// completes and step 4b populates the listview.
    fif_dock_hwnd: HWND,
    /// `SysListView32` child of `fif_dock_hwnd`. Three columns: File
    /// / Line / Match. Cleared on each new search; populated on
    /// the terminal `FifEvent::Done` event.
    fif_listview_hwnd: HWND,
    /// Status STATIC pinned to the dock header ŌĆö "X matches in Y
    /// files" when results are present.
    fif_dock_status: HWND,
    /// Close-X button at the dock header's right edge. Click
    /// hides the dock without losing the listview contents.
    fif_dock_close: HWND,
    /// Draggable handle that resizes the dock vs. the editor when
    /// the dock is visible. Hidden alongside `fif_dock_hwnd`.
    fif_splitter_hwnd: HWND,
    /// Whether the dock + splitter are currently shown. Set true
    /// when the search-completion drain reveals results; cleared
    /// when the user closes the dock (step 4b's ├Ś button) or
    /// starts a new search that yields no results.
    fif_dock_visible: bool,
    /// Persisted dock height across show/hide cycles within one
    /// session. Cross-session persistence lands with the rest of
    /// the FIF dialog state.
    fif_dock_height: i32,
    /// `Some` iff the user is currently mid-drag on the splitter.
    fif_splitter_drag: Option<SplitterDrag>,

    // --- Workspace panel (Phase 4.6 m1+) ---
    //
    // The "Folder as Workspace" panel ŌĆö the left-column tree view
    // reachable via File ŌåÆ Open Folder as Workspace... Both HWNDs
    // are created eagerly at startup (mirroring the FIF-dock
    // pattern) and toggled visible only when the user opens a
    // folder or restores a persisted session.
    //
    // m1 ships all fields present + zero-effect wiring: the panel
    // is created hidden, `workspace_visible` starts false, and
    // `layout_children` short-circuits the workspace column when
    // hidden. Subsequent milestones fill in the picker (m2), the
    // tree body (m3), and cross-session persistence (m4).
    /// Container HWND for the workspace panel. Header bar + action
    /// bar + tree body land inside as children in m2/m3.
    workspace_hwnd: HWND,
    /// Vertical splitter between the workspace panel and the tab
    /// strip / editor column. Hidden alongside `workspace_hwnd`.
    workspace_splitter_hwnd: HWND,
    /// Whether the workspace panel + splitter are currently shown.
    /// Toggled by the File ŌåÆ Open Folder as Workspace... flow
    /// (m2), the View ŌåÆ Folder as Workspace check (m4), the
    /// header's X button (m2), and session restore (m4).
    workspace_visible: bool,
    /// Persisted workspace-column width across show/hide cycles
    /// within one session. Cross-session persistence lands with
    /// [`codepp_core::session::Session`] in m4.
    workspace_width: i32,
    /// `Some` iff the user is currently mid-drag on the workspace
    /// splitter. Mirror of `fif_splitter_drag` for the horizontal
    /// axis ŌĆö see [`WorkspaceSplitterDrag`].
    workspace_splitter_drag: Option<WorkspaceSplitterDrag>,
    /// Root path of the currently-shown workspace. `None` when
    /// the panel has never been opened this session (or was
    /// closed without re-opening). Set by the folder picker in
    /// [`show_workspace_panel_prompting`]; consumed by the tree
    /// populate in m3.
    #[allow(dead_code, reason = "consumed by the tree populate in m3")]
    workspace_root: Option<PathBuf>,
    // In-panel child controls (all children of `workspace_hwnd`).
    // Positioned by the panel's own `WM_SIZE` handler; visible
    // whenever the panel is visible (their parent's visibility
    // gates them).
    /// Header row: `SS_ETCHEDFRAME` STATIC enclosing the title
    /// label + close-├Ś button as one visually-grouped box. Same
    /// technique as the About dialog's "MIT License" frame ŌĆö
    /// paints under the label + close via z-order (created
    /// before them so they sit above at paint time).
    workspace_header_frame: HWND,
    /// Header row: fixed title STATIC ("Folder as Workspace") on
    /// the left; the close-├Ś button on the right. Both painted
    /// on top of [`Self::workspace_header_frame`].
    workspace_header_label: HWND,
    workspace_close_hwnd: HWND,
    /// Action row: three narrow buttons on the right ŌĆö unfold
    /// all, fold all, locate current file. m2 lays them out and
    /// wires the close-only path; the three action buttons'
    /// click handlers (walk-and-expand, walk-and-collapse,
    /// walk-ancestors-and-reveal) land in m3 alongside the tree
    /// body itself.
    workspace_action_unfold: HWND,
    workspace_action_fold: HWND,
    workspace_action_locate: HWND,
    /// `SysTreeView32` filling the panel body. Populated lazily
    /// ŌĆö the initial [`show_workspace_panel`] call reads only
    /// the root's direct children (fast, one `read_dir`); each
    /// subfolder gets a hidden placeholder child so the `[+]`
    /// chevron appears; expanding a subfolder fires
    /// `TVN_ITEMEXPANDINGW`, which replaces the placeholder
    /// with a real `read_dir` for that folder only. Contrast
    /// with N++, which walks the whole tree eagerly on open
    /// and freezes on large workspaces.
    workspace_tree_hwnd: HWND,
    /// DFS queue for the async "Unfold All" walk. Non-empty Ōćö
    /// walk in progress. On each `WM_TIMER(WORKSPACE_UNFOLD_TIMER_ID)`
    /// tick we pop one folder, expand it (which fires
    /// `TVN_ITEMEXPANDING` ŌåÆ lazy `read_dir`), and push any of
    /// its unexpanded subfolders back onto the queue. When
    /// empty the timer is killed. This keeps the UI thread
    /// free between ticks so paints / mouse / keys still flow
    /// ŌĆö the alternative (one synchronous walk of the whole
    /// tree) froze the app end-to-end.
    workspace_unfold_pending: Vec<HTREEITEM>,
    /// Count of folders processed so far in the current
    /// "Unfold All" walk. Used to update
    /// [`Self::workspace_unfold_label`]'s text on each tick.
    /// Resets to 0 in [`start_workspace_unfold_all`].
    workspace_unfold_count: usize,
    /// Marquee progress bar shown while an "Unfold All" walk is
    /// in progress. Sibling of `workspace_tree_hwnd` inside
    /// `workspace_hwnd`; the tree is hidden and this + the
    /// counter label take its place. Hides again when the walk
    /// completes. Prevents the per-tick tree repaint from being
    /// visible to the user ŌĆö the tree only paints once, at the
    /// end, showing the final expanded state.
    workspace_unfold_progress: HWND,
    /// STATIC child that shows "Expanding folders: N" during the
    /// walk. Paired with [`Self::workspace_unfold_progress`].
    workspace_unfold_label: HWND,
    /// Path + kind of the workspace tree item that was
    /// right-clicked. Populated by
    /// [`show_workspace_tree_context_menu`] immediately before
    /// `TrackPopupMenu` and consumed (`.take()`) by the `WM_COMMAND`
    /// handler for `ID_WORKSPACE_CTX_*`. Between click and command
    /// dispatch it lives here rather than being encoded into the
    /// command id so cmd ids stay static (menu-check enable/grey
    /// paths depend on that) and so the target can carry a full
    /// `PathBuf` without pointer marshalling.
    ///
    /// `.take()` on the command side is deliberate ŌĆö a stale
    /// target from a previous click that never fired (e.g. user
    /// dismissed the popup by clicking elsewhere) MUST NOT be
    /// picked up by the next click. Each context menu populates
    /// this field afresh.
    workspace_ctx_target: Option<WorkspaceCtxTarget>,
    /// Container HWND for the right-side Document Map panel.
    /// Mirror of [`Self::workspace_hwnd`].
    docmap_hwnd: HWND,
    /// Vertical splitter on the LEFT edge of the docmap panel
    /// ŌĆö mirror of [`Self::workspace_splitter_hwnd`] on the
    /// opposite column. Drag events forward to
    /// [`layout_children`] with a new docmap width.
    docmap_splitter_hwnd: HWND,
    /// Whether the docmap panel + splitter are currently shown.
    /// Toggled by the View ŌåÆ Document Map menu, the docmap
    /// toolbar button, the header's close-├Ś button, and session
    /// restore.
    docmap_visible: bool,
    /// Persisted docmap-column width across show/hide cycles
    /// AND across interactive splitter drags. Cross-session
    /// persistence rides
    /// [`codepp_core::session::DocMapSession::width`].
    docmap_width: i32,
    /// `Some` iff the user is currently mid-drag on the docmap
    /// splitter. Mirror of [`Self::workspace_splitter_drag`].
    docmap_splitter_drag: Option<DocMapSplitterDrag>,
    /// `Some` iff the user is currently mid-drag on the docmap
    /// Scintilla view (drag-to-scroll ŌĆö see [`DocMapScrollDrag`]).
    /// Every `WM_MOUSEMOVE` while this is `Some` scrolls the main
    /// editor to the line under the cursor.
    docmap_scroll_drag: Option<DocMapScrollDrag>,
    /// Header row `SS_ETCHEDFRAME` STATIC ŌĆö same construction as
    /// [`Self::workspace_header_frame`].
    docmap_header_frame: HWND,
    /// Header row title STATIC ("Document Map"). Painted on top
    /// of [`Self::docmap_header_frame`].
    docmap_header_label: HWND,
    /// Header row close-├Ś button. Consumed by the panel's own
    /// `wnd_proc` via [`IDC_DOCMAP_CLOSE`].
    docmap_close_hwnd: HWND,
    /// Second Scintilla control ŌĆö the miniature view. Bound to
    /// the active tab's document via `SCI_SETDOCPOINTER` so it
    /// mirrors the main editor's text without duplicating any
    /// bytes; the two views share the same `Document` at
    /// Scintilla's level. Configured once at creation
    /// (read-only, invisible caret, no scrollbars, no margins,
    /// heavy zoom-out) and re-bound on every tab switch. The
    /// viewport indicator + drag-to-scroll wiring lands in
    /// later commits of the Document Map feature.
    docmap_scintilla_hwnd: HWND,
    /// Direct-call handle for the map's Scintilla control ŌĆö
    /// speed-path counterpart to [`Self::editor`] but for the
    /// miniature view. Even though the map isn't a hot path
    /// (config-only messages), using an `EditorHandle` matches
    /// the codebase convention and keeps every `send` call
    /// shape-identical to the main editor's.
    docmap_editor: EditorHandle,
    /// Modeless top-level progress window shown while a FIF job
    /// is running. `None` until the user clicks Find All; the
    /// terminal `FifEvent` (Done or Cancelled) destroys it and
    /// resets back to None.
    fif_progress_hwnd: Option<HWND>,
    /// Job id of the currently-running FIF search. Filters stale
    /// events when a second `start_fif` preempts the first.
    /// Cleared on terminal event.
    fif_active_job: Option<u64>,
    /// Per-file outcomes accumulated during the active job. Drained
    /// into the listview on the terminal `Done` event so the user
    /// sees the full result set at once rather than rows
    /// trickling in.
    fif_pending_results: Vec<FifPendingFile>,
    /// Backing store for the listview's items so `NM_DBLCLK` can
    /// resolve the clicked row index back to a file path + line
    /// number. Index here matches the listview row index 1:1.
    fif_listview_index: Vec<FifListviewRow>,
    /// Caret jumps queued by `NM_DBLCLK` and applied after the
    /// matching file's load completes. Each entry carries the same
    /// (path, line, col) data as a [`FifListviewRow`] ŌĆö reusing
    /// the struct keeps the dblclk handler free of conversion
    /// noise. The drain applies the jump as a `SCI_SETSEL` so the
    /// matched span is selected (and scrolled into view).
    fif_pending_jumps: Vec<FifListviewRow>,
    /// `(files_modified, total_replacements)` produced by the
    /// in-buffer Replace-in-Files pass that runs *before* the
    /// worker for any open tab whose path falls under the FIF root
    /// and matches the include filter. Set in
    /// `start_fif_from_snapshot` and merged into the displayed
    /// stats by `finalize_fif_job`. `None` for plain Find in Files
    /// or when no open tabs matched. Cleared on the terminal
    /// `FifEvent` so a subsequent search starts fresh.
    fif_in_buffer_counts: Option<(usize, usize)>,
    /// `Some` iff the user is mid-drag on a tab. Captured on
    /// `WM_LBUTTONDOWN` over a tab item by the tab control's
    /// subclass proc; cleared on `WM_LBUTTONUP` /
    /// `WM_CAPTURECHANGED`. The subclass proc reads/writes via
    /// `state_from_hwnd(GetParent(...))`, mirroring the FIF
    /// splitter's drag-state pattern.
    tab_drag: Option<TabDrag>,
    /// 32bpp premultiplied-BGRA `HBITMAP` rendered from
    /// `assets/icons/tab-save.png` (and `@2x.png` for `HiDPI`).
    /// Painted into each tab cell's left margin by
    /// [`paint_tab_item`] when the buffer is clean; the dirty
    /// variant is in [`Self::tab_save_red_hbm`]. Owned by
    /// `WindowState`; freed in `WM_DESTROY` alongside the toolbar
    /// image list.
    tab_save_blue_hbm: HBITMAP,
    /// Companion to [`Self::tab_save_blue_hbm`] ŌĆö same icon recoloured
    /// red for the dirty-buffer state. Same lifetime contract.
    tab_save_red_hbm: HBITMAP,
    /// 16 or 32 ŌĆö edge length of the loaded tab icons in pixels.
    /// Picked once at construction via [`pick_tab_bitmap_size`]
    /// based on the system DPI, mirroring the toolbar's 24/48 split.
    tab_bitmap_px: i32,
    /// Index of the tab the cursor is currently over, or `None` when
    /// the cursor is outside the tab strip. Tracked via
    /// `WM_MOUSEMOVE` / `WM_MOUSELEAVE` in the tab subclass proc and
    /// read by [`paint_tab_item`] to decide whether to render the
    /// close-X (visible on hover for inactive tabs).
    tab_hover_idx: Option<usize>,
    /// True iff the cursor sits over the close-X clickable rect of
    /// the tab in [`Self::tab_hover_idx`]. Drives the colour swap
    /// (grey ŌåÆ light red) regardless of which tab is active. Always
    /// `false` when [`Self::tab_hover_idx`] is `None`.
    tab_hover_close_x: bool,
    /// True iff `TrackMouseEvent(TME_LEAVE)` is armed for the tab
    /// strip. Win32 expects the call to be re-armed once per hover
    /// session; without the flag we'd re-arm on every mousemove (a
    /// bound on `TrackMouseEvent` calls per second is documented as
    /// "implementation-defined" ŌĆö being explicit is safer).
    tab_mouse_tracking: bool,
    /// `Some(idx)` while the user is mid-click on a close-X glyph
    /// (mouse pressed but not yet released). The close fires on the
    /// matching `WM_LBUTTONUP` only if the cursor is still over the
    /// same X ŌĆö Win32 button convention. Clears on `WM_CAPTURECHANGED`
    /// so a click-and-drag-away pattern cancels the close instead of
    /// firing it on a release outside the X.
    tab_close_armed: Option<usize>,
    /// True iff the cursor sits over the pin-toggle clickable rect
    /// of the tab in [`Self::tab_hover_idx`]. Symmetric to
    /// [`Self::tab_hover_close_x`] ŌĆö drives the pin's hover paint
    /// tint (a small colour shift signalling clickability) and
    /// gates the click-through disable so `WM_LBUTTONDOWN` on the
    /// pin doesn't also fall through to tab activation / drag
    /// detection. Always `false` when [`Self::tab_hover_idx`] is
    /// `None`.
    tab_hover_pin: bool,
    /// `Some(idx)` while the user is mid-click on a pin glyph
    /// (pressed but not yet released). The pin toggle fires on
    /// the matching `WM_LBUTTONUP` only if the cursor is still
    /// over the same pin ŌĆö Win32 button convention, mirroring
    /// [`Self::tab_close_armed`]. A click-and-drag-away cancels
    /// the toggle instead of firing on release outside the pin.
    tab_pin_armed: Option<usize>,
    editor: EditorHandle,
    shell: Shell,
}

impl WindowState {
    /// Split into a (shell, ui-platform) pair so we can call
    /// `shell.drain(ui)` without aliasing `&mut self`. `Win32Ui` is
    /// Copy-cheap (two pointer-sized values + `EditorHandle`) so we just
    /// produce a fresh one per call.
    fn split(&mut self) -> (&mut Shell, Win32Ui) {
        let ui = Win32Ui {
            status_hwnd: self.status_hwnd,
            tab_hwnd: self.tab_hwnd,
            toolbar_hwnd: self.toolbar_hwnd,
            main_menu: self.main_menu,
            // SAFETY: `&raw mut` on a field of `*self` produces
            // a pointer valid for the lifetime of `WindowState`
            // (heap-allocated, pinned via `GWLP_USERDATA` for
            // the window's lifetime). The pointer is only
            // dereferenced on the UI thread while `Win32Ui` is
            // in scope ŌĆö see the `accel_handle` field doc on
            // `Win32Ui` for the full safety argument.
            accel_handle: &raw mut self.accel_handle,
            plugin_modeless_dialogs: &raw mut self.plugin_modeless_dialogs,
            dock_dialogs: &raw mut self.dock_dialogs,
            udl_registry: &raw const self.shell.udl_registry,
            editor: self.editor,
            docmap_editor: self.docmap_editor,
        };
        (&mut self.shell, ui)
    }

    /// Build the per-call `HostHandles` the plugin dispatcher consumes.
    /// Centralized so the route in `WM_USER+1000..` and any future
    /// notification call site share one definition of "what the host's
    /// handles are right now." `HWND` and `HMENU` in windows-rs 0.62
    /// are both `pub struct(pub *mut c_void)`, so `.0` already has
    /// the `Hwnd = *mut c_void` shape the plugin-host crate expects.
    fn host_handles(&self, npp_hwnd: HWND) -> HostHandles {
        HostHandles {
            npp_hwnd: npp_hwnd.0,
            scintilla_main: self.scintilla_hwnd.0,
            scintilla_secondary: core::ptr::null_mut(),
            plugin_menu: self.plugin_menu.0,
            main_menu: self.main_menu.0,
        }
    }
}

/// `UiPlatform` impl. Lightweight ŌĆö just carries the HWND values
/// `Shell::drain` needs to reach the editor, status bar, and tab
/// strip. The main HWND is intentionally absent: dialogs that
/// need it are deferred (`PendingDialog`) and shown by `wnd_proc`
/// using its own HWND parameter; methods that need to post back
/// to the main window (e.g. `set_tabbar_hidden`'s deferred
/// relayout) derive it via `GetParent(self.tab_hwnd)`.
#[derive(Clone, Copy)]
struct Win32Ui {
    status_hwnd: HWND,
    tab_hwnd: HWND,
    /// Toolbar control HWND. Carried alongside `tab_hwnd` /
    /// `status_hwnd` so the chrome-toggle messages
    /// (`NPPM_HIDETOOLBAR` and friends) can `ShowWindow` it
    /// without re-resolving from `WindowState`.
    toolbar_hwnd: HWND,
    /// Main menu bar HMENU. The chrome-toggle messages flip the
    /// main window's menu between this and NULL via `SetMenu` /
    /// `DrawMenuBar`. Read-only after window creation.
    main_menu: HMENU,
    /// Pointer to `WindowState.accel_handle` so the dispatcher
    /// can both read (via `CopyAcceleratorTableW`, used by
    /// `NPPM_GETSHORTCUTBYCMDID`) and write (via the
    /// recreate-and-swap dance, used by
    /// `NPPM_REMOVESHORTCUTBYCMDID`) the live accelerator
    /// table. `Win32Ui` stays Copy by carrying the raw pointer
    /// rather than a borrow.
    ///
    /// # Safety
    ///
    /// The pointer is dereferenced on the UI thread only, while
    /// the containing `WindowState` (which holds the slot the
    /// pointer addresses) is alive. `WindowState` is heap-
    /// allocated and pinned via `GWLP_USERDATA` for the life of
    /// the main window; `Win32Ui` instances are produced by
    /// `WindowState::split` and never outlive that scope. No
    /// other code mutates `accel_handle` while a `Win32Ui` is in
    /// use ŌĆö Win32 dispatches messages serially on the owning
    /// thread, and `state_from_hwnd` refuses re-entrant borrows
    /// via `PluginCallGuard`.
    accel_handle: *mut HACCEL,
    /// Pointer to `WindowState.plugin_modeless_dialogs` so
    /// `NPPM_MODELESSDIALOG` dispatch can register and
    /// unregister plugin-owned dialogs. Carries the same
    /// "`Win32Ui` stays Copy, UI-thread-only access" invariant
    /// as `accel_handle`. Multiple plugins can each register
    /// their own dialogs; the Vec is iterated by the message
    /// pump once per `GetMessageW` to call `IsDialogMessageW`
    /// against each.
    plugin_modeless_dialogs: *mut Vec<HWND>,
    /// Pointer to `WindowState.dock_dialogs` so the
    /// `NPPM_DMM*` family can register / show / hide / look up
    /// floating frames. Same "`Win32Ui` stays Copy, UI-thread-only
    /// access" invariant as `accel_handle` and
    /// `plugin_modeless_dialogs`. The Vec is mutated by
    /// `register_dock_dialog` (push) and read by every other
    /// DMM method.
    dock_dialogs: *mut Vec<DockEntry>,
    /// Pointer to `WindowState.shell.udl_registry` so
    /// `apply_udl_lang` can read the loaded UDLs without
    /// reaching back through `state_from_hwnd(GetParent(...))`
    /// ŌĆö the reach-back would produce a **second** overlapping
    /// `&mut WindowState` in the callers that already hold one
    /// (`handle_close_active_tab_inner`, `handle_tab_selchange`,
    /// `handle_style_config_menu`), aliasing UB under Rust's
    /// `noalias` optimizer even before behavioural bugs
    /// manifest. Same "raw pointer, UI-thread-only,
    /// non-aliased-by-construction" invariant as
    /// [`Self::accel_handle`] and friends.
    ///
    /// **Aliasing discipline.** The registry is populated once
    /// at `Shell::new` and never mutated after ŌĆö every read
    /// through this pointer is shared, no `&mut` ever crosses
    /// the FFI boundary via this field. When m3's editor modal
    /// mutates the registry, the mutation must go through
    /// `state_from_hwnd(state)` (no `Win32Ui` involvement) so
    /// this pointer never observes a `&mut UdlRegistry`.
    udl_registry: *const codepp_udl::UdlRegistry,
    editor: EditorHandle,
    /// Direct-call handle for the Document Map's miniature
    /// Scintilla view. Carried alongside [`Self::editor`] so
    /// every Shell-driven `activate_tab` ŌĆö FileŌåÆOpen, FileŌåÆNew,
    /// session restore, plugin `NPPM_SWITCHTOFILE`, and the
    /// `ensure_one_tab` fallback ŌĆö can rebind the map view in
    /// lockstep with the main view. Skipping the map here (the
    /// Win32-side handlers alone are not enough) leaves the map
    /// pinned to a stale document that's already been closed or
    /// bypassed, which is both a UX bug (shows the wrong buffer)
    /// and a resource leak (the map's implicit ref keeps the
    /// closed doc resident until the next real tab switch).
    docmap_editor: EditorHandle,
}

// -----------------------------------------------------------------
// Notepad++ ABI menu-command ids (IDM_*).
//
// These are the numeric values plugins pass to `NPPM_MENUCOMMAND` and
// `NPPM_SETMENUITEMCHECK` (declared in
// `plugins/nppcompat-headers/menuCmdID.h`). Kept as Rust constants
// alongside Code++'s own [`ID_*`] block so the mapping function below
// can be a single `match` without a magic-number soup. Only the ids
// Code++ actually implements a target for are declared here; new
// mappings add a matching constant when they land.
//
// The values MUST match `menuCmdID.h` exactly ŌĆö a plugin compiled
// against those constants sends those numeric ids over the ABI, and
// a mismatch here would silently drop the dispatch.
const IDM_BASE: i32 = 40000;
const IDM_FILE: i32 = IDM_BASE + 1000;
const IDM_EDIT: i32 = IDM_BASE + 2000;
const IDM_SEARCH: i32 = IDM_BASE + 3000;
const IDM_VIEW: i32 = IDM_BASE + 4000;
const IDM_FORMAT: i32 = IDM_BASE + 5000;

const IDM_FILE_NEW: i32 = IDM_FILE + 1;
const IDM_FILE_OPEN: i32 = IDM_FILE + 2;
const IDM_FILE_CLOSE: i32 = IDM_FILE + 3;
const IDM_FILE_CLOSEALL: i32 = IDM_FILE + 4;
const IDM_FILE_SAVE: i32 = IDM_FILE + 6;
const IDM_FILE_SAVEALL: i32 = IDM_FILE + 7;
const IDM_FILE_SAVEAS: i32 = IDM_FILE + 8;
const IDM_FILE_PRINT: i32 = IDM_FILE + 9;
const IDM_FILE_EXIT: i32 = IDM_FILE + 11;
const IDM_FILE_RELOAD: i32 = IDM_FILE + 14;
const IDM_FILE_RENAME: i32 = IDM_FILE + 17;

const IDM_EDIT_CUT: i32 = IDM_EDIT + 1;
const IDM_EDIT_COPY: i32 = IDM_EDIT + 2;
const IDM_EDIT_UNDO: i32 = IDM_EDIT + 3;
const IDM_EDIT_REDO: i32 = IDM_EDIT + 4;
const IDM_EDIT_PASTE: i32 = IDM_EDIT + 5;
const IDM_EDIT_DELETE: i32 = IDM_EDIT + 6;
const IDM_EDIT_SELECTALL: i32 = IDM_EDIT + 7;

const IDM_SEARCH_FIND: i32 = IDM_SEARCH + 1;
const IDM_SEARCH_FINDNEXT: i32 = IDM_SEARCH + 2;
const IDM_SEARCH_REPLACE: i32 = IDM_SEARCH + 3;
const IDM_SEARCH_GOTOLINE: i32 = IDM_SEARCH + 4;
const IDM_SEARCH_FINDINFILES: i32 = IDM_SEARCH + 9;

const IDM_VIEW_ZOOMIN: i32 = IDM_VIEW + 3;
const IDM_VIEW_ZOOMOUT: i32 = IDM_VIEW + 4;
const IDM_VIEW_ZOOMRESTORE: i32 = IDM_VIEW + 5;
const IDM_VIEW_WRAP: i32 = IDM_VIEW + 7;

const IDM_FORMAT_ANSI: i32 = IDM_FORMAT + 1;
const IDM_FORMAT_UTF_8: i32 = IDM_FORMAT + 2;
const IDM_FORMAT_UTF_16BE: i32 = IDM_FORMAT + 3;
const IDM_FORMAT_UTF_16LE: i32 = IDM_FORMAT + 4;
const IDM_FORMAT_AS_UTF_8: i32 = IDM_FORMAT + 5;

/// Returns `true` if `idm` falls inside the plugin-owned cmd-id
/// range ŌĆö either the `FuncItem` band (from `getFuncsArray`,
/// starting at [`PLUGIN_CMD_ID_BASE`]) or the `NPPM_ALLOCATECMDID`
/// pool (which caps at [`PLUGIN_ALLOC_CMD_LIMIT`]). Ids outside this
/// range are either built-in `IDM_*` values (below the base) or
/// garbage (above the limit).
///
/// **Upper bound matters.** `main_wnd_proc`'s `WM_COMMAND` handler
/// keys off only the low 16 bits of `wparam`, so an `idm` above
/// `u16::MAX` posted through `dispatch_npp_menu_command` would
/// truncate down and alias onto whatever built-in `ID_*` sits at
/// that low id (e.g. `ID_FILE_SAVE = 1000`). Refusing values past
/// the alloc-pool ceiling makes buggy plugins fail closed
/// (`dispatch_npp_menu_command` returns `false` on the unknown id)
/// instead of silently triggering an unrelated host command.
#[cfg(target_os = "windows")]
fn is_plugin_cmd_id(idm: i32) -> bool {
    (PLUGIN_CMD_ID_BASE..=PLUGIN_ALLOC_CMD_LIMIT).contains(&idm)
}

/// Translate a Notepad++-ABI `IDM_*` command id into the Code++
/// internal [`ID_*`] `WM_COMMAND` id that runs the equivalent action.
/// Returns `None` for `IDM_*` values Code++ has no target for
/// (e.g. Notepad++ features Code++ doesn't implement yet).
///
/// Plugin-allocated cmd ids (from `getFuncsArray` `FuncItem` entries
/// or `NPPM_ALLOCATECMDID`) are **not** mapped ŌĆö the caller detects
/// those via [`is_plugin_cmd_id`] and passes them through untouched
/// so a plugin's own menu items dispatch through the same route.
fn map_npp_idm_to_local(idm: i32) -> Option<u16> {
    match idm {
        IDM_FILE_NEW => Some(ID_FILE_NEW),
        IDM_FILE_OPEN => Some(ID_FILE_OPEN),
        IDM_FILE_CLOSE => Some(ID_FILE_CLOSE),
        IDM_FILE_CLOSEALL => Some(ID_FILE_CLOSE_ALL),
        IDM_FILE_SAVE => Some(ID_FILE_SAVE),
        IDM_FILE_SAVEALL => Some(ID_FILE_SAVE_ALL),
        IDM_FILE_SAVEAS => Some(ID_FILE_SAVE_AS),
        IDM_FILE_PRINT => Some(ID_FILE_PRINT),
        IDM_FILE_EXIT => Some(ID_FILE_EXIT),
        IDM_FILE_RELOAD => Some(ID_FILE_RELOAD),
        IDM_FILE_RENAME => Some(ID_FILE_RENAME),
        IDM_EDIT_CUT => Some(ID_EDIT_CUT),
        IDM_EDIT_COPY => Some(ID_EDIT_COPY),
        IDM_EDIT_UNDO => Some(ID_EDIT_UNDO),
        IDM_EDIT_REDO => Some(ID_EDIT_REDO),
        IDM_EDIT_PASTE => Some(ID_EDIT_PASTE),
        IDM_EDIT_DELETE => Some(ID_EDIT_DELETE),
        IDM_EDIT_SELECTALL => Some(ID_EDIT_SELECTALL),
        IDM_SEARCH_FIND => Some(ID_SEARCH_FIND),
        IDM_SEARCH_FINDNEXT => Some(ID_SEARCH_FINDNEXT),
        IDM_SEARCH_REPLACE => Some(ID_SEARCH_REPLACE),
        IDM_SEARCH_GOTOLINE => Some(ID_SEARCH_GOTOLINE),
        IDM_SEARCH_FINDINFILES => Some(ID_SEARCH_FINDINFILES),
        IDM_VIEW_ZOOMIN => Some(ID_VIEW_ZOOMIN),
        IDM_VIEW_ZOOMOUT => Some(ID_VIEW_ZOOMOUT),
        IDM_VIEW_ZOOMRESTORE => Some(ID_VIEW_ZOOMRESET),
        IDM_VIEW_WRAP => Some(ID_VIEW_WORDWRAP),
        IDM_FORMAT_ANSI => Some(ID_ENCODING_ANSI),
        IDM_FORMAT_UTF_8 => Some(ID_ENCODING_UTF8),
        IDM_FORMAT_AS_UTF_8 => Some(ID_ENCODING_UTF8_BOM),
        IDM_FORMAT_UTF_16LE => Some(ID_ENCODING_UTF16_LE),
        IDM_FORMAT_UTF_16BE => Some(ID_ENCODING_UTF16_BE),
        _ => None,
    }
}

impl UiPlatform for Win32Ui {
    fn activate_tab(&mut self, _idx: usize, scintilla_doc: isize) -> isize {
        // Resolve the document pointer. A zero `scintilla_doc` is
        // the contract for "no document yet, please create one"
        // ŌĆö happens the first time a Tab is bound to the view.
        // SCI_CREATEDOCUMENT(wparam = bytes hint, lparam = options)
        // returns the new doc pointer with refcount 1. We then
        // SCI_SETDOCPOINTER to bind it; that bumps the refcount
        // and decrements the previously-bound doc's refcount, but
        // doesn't free either ŌĆö Scintilla keeps the previous
        // document alive as long as anyone holds a refcount or
        // it's still pointed at.
        let (doc, freshly_created) = if scintilla_doc != 0 {
            (scintilla_doc, false)
        } else {
            (
                self.editor
                    .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT),
                true,
            )
        };
        // Bind the resolved document to the single Scintilla view.
        // wparam is unused; lparam is the doc pointer.
        self.editor.send(SCI_SETDOCPOINTER, 0, doc);
        // Change-history is per-document state ŌĆö enable on every
        // freshly-minted doc so its lines start tracking edits
        // against the save-point. Bound docs that already existed
        // (the `scintilla_doc != 0` branch) had history enabled at
        // their own creation site, so the call would be a no-op.
        if freshly_created {
            enable_change_history(&self.editor);
            // Tab width is per-document Scintilla state (mutates
            // `pdoc->tabInChars`), so every fresh doc needs it
            // re-applied ŌĆö otherwise the doc starts with
            // Scintilla's built-in default of 8, mis-drawing
            // indent guides for 4-space-indented code.
            apply_tab_width(&self.editor);
        }
        // Always refresh the visible window's line numbers on
        // attach: a brand-new doc needs line 0 seeded; an existing
        // doc may have been edited off-screen since last populate
        // (its width or content may have shifted), or its current
        // viewport may sit on a region the populate hasn't reached
        // yet. Cost is bounded by viewport height (~50 lines), not
        // file size ŌĆö cheap to run unconditionally.
        populate_visible_line_numbers(&self.editor);
        // Rebind the Document Map's miniature view to the same
        // document in lockstep with the main view. This is the
        // shared chokepoint for every Shell-driven activation
        // (FileŌåÆOpen, FileŌåÆNew, session restore, plugin
        // `NPPM_SWITCHTOFILE`, `ensure_one_tab`); Win32-side
        // tab-switch / tab-close paths also call
        // `sync_docmap_to_active_tab` on top for defence in
        // depth (redundant same-doc rebinds are Scintilla
        // no-ops). Without this call the map view stays pinned
        // to whatever doc it was last bound to, both showing
        // stale content AND leaking a Scintilla `Document` ref
        // on any tab the user closed.
        //
        // The viewport-highlight indicator paints against the
        // now-bound document via
        // `update_docmap_viewport_indicator` ŌĆö same rationale
        // as [`sync_docmap_to_active_tab`]'s own trailing call:
        // without the update the highlight would show the
        // previous tab's visible range against this tab's text
        // until the next scroll event fires an update.
        self.docmap_editor.send(SCI_SETDOCPOINTER, 0, doc);
        // Kick the viewport-highlight update with the two
        // handles directly ŌĆö no `state_from_hwnd` reach-back,
        // which matters because this method is called from
        // inside `shell.method(&mut ui)` chains where a `&mut
        // WindowState` is already alive via `state.split()`'s
        // reborrow. A second live `&mut WindowState` here would
        // be aliasing UB. Both handles are already `Copy` on
        // `self`, so this is a straight pass-through.
        unsafe {
            update_docmap_viewport_indicator(self.editor, self.docmap_editor);
        }
        doc
    }

    fn set_buffer_text(&mut self, text: &str, cursor: u64) {
        // SCI_SETTEXT requires a null-terminated UTF-8 string. Build
        // a single buffer; the address is valid for the duration of
        // the synchronous direct-call.
        let mut bytes = Vec::with_capacity(text.len() + 1);
        bytes.extend_from_slice(text.as_bytes());
        bytes.push(0);
        self.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
        // Loaded buffers start clean ŌĆö clear the undo history (Scintilla
        // would otherwise let Ctrl+Z undo the load itself, then mark
        // everything as deleted) and reset the save point so the title
        // bar isn't asterisk'd.
        self.editor.send(SCI_EMPTYUNDOBUFFER, 0, 0);
        self.editor.send(SCI_SETSAVEPOINT, 0, 0);
        self.editor.send(SCI_GOTOPOS, cursor as usize, 0);
        // Wipe any per-line margin text the doc carried from its
        // previous state ŌĆö `SCI_SETTEXT` replaces text but Scintilla
        // keeps `SCI_MARGINSETTEXT` annotations on per-line storage,
        // and they end up landing on lines of the *new* content
        // (the bug: `activate_tab`'s populate set "1" on line 0 of
        // the empty starter doc; after `SCI_SETTEXT`-with-multiline
        // that "1" surfaced on the last line of the new content).
        self.editor.send(SCI_MARGINTEXTCLEARALL, 0, 0);
        // Populate the full document. The visible-only populate
        // would miss off-screen lines during session restore
        // (where this method runs *before* the window is laid out
        // and `SCI_LINESONSCREEN` reports 0). Bounded by the
        // doc's line count ŌĆö fine for a once-per-load operation.
        // Incremental edits still go through the cheaper
        // `populate_visible_line_numbers` path on `SCN_MODIFIED`.
        populate_all_line_numbers(&self.editor);
        // Refresh the Document Map's viewport highlight so it
        // covers the newly-loaded content. `Win32Ui::activate_tab`
        // ran BEFORE this call ŌĆö at that point the doc was empty
        // (Scintilla's built-in single-line placeholder) so
        // `update_docmap_viewport_indicator`'s empty-buffer guard
        // returned without painting. Now that `SCI_SETTEXT` has
        // populated real content, re-fire the update so the
        // highlight paints from the first `WM_PAINT` ŌĆö without
        // this the map stays visibly empty until the user's
        // first scroll gesture triggers an `SCN_UPDATEUI` with
        // `SC_UPDATE_V_SCROLL`.
        unsafe {
            update_docmap_viewport_indicator(self.editor, self.docmap_editor);
        }
    }

    fn get_buffer_text(&mut self) -> String {
        let len = self.editor.send(SCI_GETLENGTH, 0, 0);
        if len <= 0 {
            return String::new();
        }
        // SCI_GETTEXT writes len+1 bytes (null-terminator inclusive)
        // into our buffer; the wparam is the buffer size including
        // the null.
        let cap = len as usize + 1;
        let mut buf = vec![0u8; cap];
        let written = self
            .editor
            .send(SCI_GETTEXT, cap, buf.as_mut_ptr() as isize);
        if written <= 0 {
            return String::new();
        }
        // Drop the trailing null Scintilla wrote.
        buf.truncate(written as usize);
        // Scintilla stores text as the user types ŌĆö bytes are valid
        // UTF-8 if the buffer is in UTF-8 mode (our default). Use
        // from_utf8_lossy as a defensive measure: if some weird code
        // path inserted invalid bytes, we get U+FFFD rather than
        // panicking. The save path will then surface an encoding
        // error if those bytes can't be re-encoded.
        String::from_utf8_lossy(&buf).into_owned()
    }

    fn get_cursor_pos(&mut self) -> u64 {
        let pos = self.editor.send(SCI_GETCURRENTPOS, 0, 0);
        pos.max(0) as u64
    }

    fn update_status(
        &mut self,
        lang: codepp_core::LangType,
        encoding: &Encoding,
        eol: Eol,
        _byte_len: u64,
    ) {
        // Sync Scintilla's per-document EOL mode with the tab's
        // authoritative EOL. Fires on every normal user-visible
        // tab-activation and metadata-refresh path ŌĆö
        // `handle_tab_selchange`'s lazy-populate, the tab-close
        // lazy-materialise, the initial post-load status refresh,
        // and the plugin-driven apply_lang / apply_default_style
        // follow-ups ŌĆö because the Shell layer routes every such
        // transition through `update_status`. Without this,
        // Scintilla's built-in CRLF default (Windows) applies
        // universally, breaking the EOL-preservation contract per
        // DESIGN.md ┬¦5.2: pressing Enter in a pure-LF file would
        // inject CRLF-terminated lines into an otherwise LF file.
        //
        // **Known gaps** (tracked follow-ups, not blockers for the
        // common tab-activation paths):
        //   - `Shell::save_all` reactivates each dirty tab via
        //     `ui.activate_tab(idx, stored_doc)` in a loop without
        //     a subsequent `update_status` call. Only reachable
        //     when a tab loaded in the background never had its
        //     Scintilla doc materialised ŌĆö the deeper bug there
        //     is that `save_all` would then save an empty file,
        //     so the EOL slice is subsumed.
        //   - `Shell::set_buffer_format` (the NPPM_SETBUFFERFORMAT
        //     dispatcher) flips `tab.eol` metadata but doesn't
        //     call `SCI_CONVERTEOLS` or `update_status` on the
        //     active tab. Full fix requires the doc-pointer-swap
        //     dance already tracked as Phase 5 polish work in
        //     DESIGN.md ┬¦7.4.
        apply_eol_mode(&self.editor, eol);
        // Multi-part status bar (see `setup_status_parts` for the
        // 7-slot layout). This call writes the metadata-driven
        // parts (lang / EOL / encoding); the caret-driven parts
        // (length-lines / cursor / INS-OVR) are refreshed by
        // `refresh_status_dynamic_parts` so they pick up the
        // current Scintilla state on every call (including after
        // a file load whose `byte_len` arg here is now stale-by-
        // construction ŌĆö Scintilla has the authoritative number
        // since the buffer is fully populated by the time
        // `update_status` runs).
        //
        // SAFETY on `&*self.udl_registry`: same as
        // `apply_udl_lang` ŌĆö the registry is populated once at
        // `Shell::new`, read-only from here, and outlives every
        // `Win32Ui` value that captures a pointer to it.
        let lang_label = resolve_lang_label(lang, unsafe { &*self.udl_registry });
        write_status_part(
            self.status_hwnd,
            STATUS_PART_LANG,
            &format!("  {lang_label}"),
        );
        write_status_part(
            self.status_hwnd,
            STATUS_PART_EOL,
            &format!("  {}", eol.long_label()),
        );
        write_status_part(
            self.status_hwnd,
            STATUS_PART_ENCODING,
            &format!("  {}", encoding.label()),
        );
        // Spring (part 1) stays empty so the status bar can absorb
        // window-resize delta there.
        refresh_status_dynamic_parts(self.status_hwnd, &self.editor);
    }

    fn set_plugin_status(&mut self, section: usize, text: &str) {
        // NPPM_SETSTATUSBAR sections: 0 = doc info, 1 = type, 2 =
        // encoding, etc. The Phase 3 status bar is single-part, so
        // we collapse all plugin-supplied sections onto part 0; the
        // next `update_status` call repaints the standard fields.
        //
        // **Known limitation:** a plugin that calls NPPM_SETSTATUSBAR
        // twice with different sections sees only the last write
        // until milestone 6's multi-part status bar lands. Plugins
        // that depend on per-section persistence will visibly
        // misbehave; this is a documented surface deviation, not a
        // bug to file.
        let _ = section;
        write_status_part(self.status_hwnd, 0, text);
    }

    fn mark_saved(&mut self) {
        // Clear the modified flag on the currently-bound document.
        // Scintilla's dirty glyph (and SCI_GETMODIFY) keys off this.
        self.editor.send(SCI_SETSAVEPOINT, 0, 0);
    }

    fn apply_lang(&mut self, lang: LangType) {
        // Phase 4.6 m1c-3b-1: UDL container-lexer routing. When
        // the target LangType is a UDL id (dynamically-assigned
        // at startup in `Shell.udl_registry`), take the
        // container-lexer path instead of `set_lexer_by_name`:
        //   1. `clear_lexer` = `SCI_SETILEXER(0, 0)` ŌĆö puts
        //      Scintilla in container-lexer mode; styling now
        //      fires as `SCN_STYLENEEDED` notifications the
        //      WM_NOTIFY handler dispatches to
        //      `udl_paint::paint_udl_range`.
        //   2. `apply_default_styles` resets every style index
        //      so the previous lexer's per-style colours don't
        //      bleed onto our 24 UDL slots.
        //   3. `apply_udl_styles` writes the UDL's own palette
        //      into indices 0..=23 (matching `UdlStyleSlot`
        //      discriminants).
        //   4. Force a full-buffer initial paint immediately ŌĆö
        //      resetting `endStyled` to 0 via `SCI_STARTSTYLING`
        //      and painting the whole document in one pass ŌĆö
        //      so the visible content shows the new highlighting
        //      without waiting for a scroll to trigger
        //      `SCN_STYLENEEDED`.
        if codepp_udl::is_udl_lang_id(lang.as_npp_id()) {
            self.apply_udl_lang(lang);
            return;
        }
        // Look up the Lexilla lexer name in core::lang. None means
        // either L_TEXT (no lexer wanted) or a language whose lexer
        // isn't yet in build.rs's static-link set ŌĆö both fall through
        // to clear_lexer so the view renders as plain text instead
        // of carrying the previous tab's lexer state.
        let Some(name) = lang.lexer_name() else {
            self.editor.clear_lexer();
            // Reset the styles to a single default ŌĆö otherwise the
            // previous lexer's per-style colours stay applied to
            // whatever style indices Scintilla picks for unstyled
            // text, producing visual contamination on tab switch.
            apply_default_styles(&self.editor);
            // Force the now-clear lexer state to repaint immediately
            // ŌĆö without a colourise call, residual style bytes from
            // the previous lexer linger until the user scrolls or
            // edits.
            self.editor.send(SCI_COLOURISE, 0, -1);
            return;
        };
        if !self.editor.set_lexer_by_name(name) {
            // Lexilla returned NULL ŌĆö the static build doesn't
            // contain this lexer. Trace and fall through to plain
            // rendering.
            tracing::warn!(lexer = name, "CreateLexer returned NULL");
            self.editor.clear_lexer();
            apply_default_styles(&self.editor);
            self.editor.send(SCI_COLOURISE, 0, -1);
            return;
        }
        // Dispatch to the per-language theme table. The framework
        // (see `lang_theme` below) returns `Some(&theme)` for any
        // language with explicit keyword classes + style mappings
        // wired on the host side; `None` for languages whose
        // Lexilla lexer is attached but doesn't yet have host
        // configuration (the ­¤¤Ī rows in `docs/lexers-coverage.md`).
        //
        // Order for the themed branch:
        //   1. Install keyword classes ŌĆö these mutate only the
        //      lexer's internal word lists, not the visual styles.
        //   2. `apply_default_styles` ŌĆö resets every style index
        //      back to STYLE_DEFAULT, clearing the previous lexer's
        //      per-style fore/back colours.
        //   3. Per-style fore colours from the theme's `styles`
        //      table ŌĆö each (SCE_*_INDEX, StyleSlot) pair sets one
        //      style's foreground via the shared palette.
        //   4. Per-style italic / bold flags from the theme's
        //      `italic` / `bold` lists (typically comments ŌåÆ italic
        //      and primary keywords ŌåÆ bold).
        //
        // For the unthemed branch (Lexilla lexer attached but no
        // host theme yet), we still call `apply_default_styles` so
        // the previous lexer's per-style colours don't bleed
        // through onto the now-different style indices the new
        // lexer emits. The lexer still tokenises correctly; comments
        // / strings / numbers just render at the default colour
        // until a Phase 4.5 follow-on commit adds this language's
        // row to the table.
        if let Some(theme) = lang_theme(lang) {
            for &(class, words) in theme.keywords {
                self.editor.set_keywords(class, words);
            }
            apply_default_styles(&self.editor);
            for &(style, slot) in theme.styles {
                self.editor.style_set_fore(style, slot_color(slot));
            }
            for &style in theme.italic {
                self.editor.style_set_italic(style, true);
            }
            for &style in theme.bold {
                self.editor.style_set_bold(style, true);
            }
        } else {
            apply_default_styles(&self.editor);
        }
        // Fold properties MUST be issued here, not once at editor
        // creation: `LexState::PropSet` at
        // `ScintillaBase.cxx:687-694` is `if (instance) { ŌĆ” }` ŌĆö
        // silently no-op with no lexer bound ŌĆö and every
        // `SCI_SETILEXER` mints a fresh `ILexer5` instance with its
        // own default `options.fold = false` (see e.g.
        // `LexCPP.cxx:400`). Scintilla does NOT copy properties from
        // the outgoing instance to the incoming one, so we re-issue
        // the universal fold trio on every language switch.
        //
        // The `apply_fold_margin` call at editor creation sets up
        // the margin *geometry* (type, mask, sensitivity, marker
        // shapes, colours, automatic-fold flags) ŌĆö none of which
        // depend on a lexer being attached. Only the fold *classifier*
        // properties are language-instance-local, and they live here.
        //
        // Batch and Makefile lexers have no `Fold` function of their
        // own ŌĆö the property is silently ignored, so we issue it
        // unconditionally rather than gating on lexer support.
        self.editor.set_property("fold", "1");
        self.editor.set_property("fold.compact", "0");
        self.editor.set_property("fold.comment", "1");
        for &(name, value) in extra_fold_properties(lang) {
            self.editor.set_property(name, value);
        }
        // Trigger a full re-style of the buffer through the now-set
        // lexer. Scintilla doesn't auto-restyle on `SCI_SETILEXER`
        // ŌĆö it only re-styles regions on edit / scroll / explicit
        // colourise. Without this call, switching the language on
        // a buffer that already has text (e.g. via the Language
        // menu or a session restore that picked up a persisted
        // override) leaves the existing text rendered with the
        // previous lexer's classification (or unstyled, if there
        // was no previous lexer) until the user scrolls or types.
        // `lparam = -1` styles to end-of-document; the redraw is
        // implicit. Runs even for the unthemed branch ŌĆö the lexer
        // still classifies tokens, which is the "best-effort
        // highlighting" the user expects when pointing an arbitrary
        // file at a known lexer.
        self.editor.send(SCI_COLOURISE, 0, -1);
    }

    fn apply_default_style(&mut self, styles: &codepp_core::styles::Styles) {
        let entry = styles.effective_default();
        let transparency = styles.effective_transparency();

        // Resolve fg / bg. Malformed hex (impossible from a
        // round-tripped doc but possible if a user hand-edits
        // styles.xml) falls back to the built-in default so the
        // editor stays readable rather than rendering invisible
        // text on the user's mistake.
        let fg_rgb = codepp_core::styles::parse_rgb_hex(&entry.fg).unwrap_or((0, 0, 0));
        let bg_rgb = codepp_core::styles::parse_rgb_hex(&entry.bg).unwrap_or((0xFF, 0xFF, 0xFF));
        let fg_cref = rgb_to_colorref(fg_rgb);
        let bg_cref = rgb_to_colorref(bg_rgb);

        // Configure STYLE_DEFAULT first ŌĆö `SCI_STYLECLEARALL`
        // copies STYLE_DEFAULT to every other style index, so
        // the font / size / colours seed every per-lexer style
        // before the per-lexer overrides re-paint over them.
        self.editor.style_set_font(STYLE_DEFAULT, &entry.font_name);
        self.editor
            .style_set_size(STYLE_DEFAULT, i32::from(entry.font_size));
        self.editor.style_set_fore(STYLE_DEFAULT, fg_cref);
        self.editor.style_set_back(STYLE_DEFAULT, bg_cref);
        self.editor.style_set_bold(STYLE_DEFAULT, entry.bold);
        self.editor.style_set_italic(STYLE_DEFAULT, entry.italic);
        self.editor
            .style_set_underline(STYLE_DEFAULT, entry.underline);

        // Propagate STYLE_DEFAULT to every other style index, then
        // re-apply the line-number margin, brace-highlight styles,
        // and indent-guide style (all sit in the 32-39 predefined-
        // style range that `SCI_STYLECLEARALL` resets to
        // `STYLE_DEFAULT`, losing their per-slot colour pairs).
        self.editor.style_clear_all();
        apply_line_number_margin(&self.editor);
        apply_brace_styles(&self.editor);
        apply_indent_guide_style(&self.editor);

        // Transparency. WS_EX_LAYERED is required for
        // `SetLayeredWindowAttributes` to take effect; when
        // disabled, we strip the bit so the editor doesn't pay
        // the layered-window compositing cost. The conversion
        // from "opacity percent" to the alpha byte is
        // `percent * 255 / 100` (so 100% ŌåÆ 255 fully opaque).
        let main_hwnd = unsafe { GetParent(self.tab_hwnd).unwrap_or_default() };
        if main_hwnd.is_invalid() {
            // The tab strip is always a child of the main window
            // by construction (see `run`); reaching this branch
            // means `GetParent` failed unexpectedly. Log so the
            // missing transparency is observable rather than a
            // silent skip ŌĆö the alternative is the user wondering
            // why their checked-on transparency setting has no
            // visible effect.
            tracing::warn!(
                "apply_default_style: GetParent on tab_hwnd returned invalid HWND; transparency not applied"
            );
        } else {
            unsafe {
                apply_window_transparency(main_hwnd, &transparency);
            }
        }

        // The current lexer's classifications need to be re-applied
        // on top of the new STYLE_DEFAULT (which `style_clear_all`
        // has just propagated to every style index). Without a
        // forced re-styling, comments / keywords / strings would
        // all render with the new default colour until the user
        // scrolls or edits. The lexer's keyword classes survive
        // SCI_STYLECLEARALL, so a single colourise repaints
        // correctly.
        self.editor.send(SCI_COLOURISE, 0, -1);
    }

    fn search_next(&mut self, query: &str, flags: SearchFlags) -> Option<u64> {
        // Collapse the selection to its END before re-anchoring.
        // `SCI_SEARCHANCHOR` snaps to `SelectionStart` ŌĆö without
        // the collapse, a Find Next after a successful match
        // would re-anchor to the start of the previous hit and
        // re-find the same match. Collapsing to the end advances
        // past it. `search_next` takes flags directly via wparam,
        // so no sticky-state surprise from a previous Replace All
        // having left SCFIND_REGEX set.
        let end = self.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as usize;
        self.editor.send(SCI_SETEMPTYSELECTION, end, 0);
        self.editor.search_anchor();
        match self.editor.search_next(query, flags.bits()) {
            -1 => None,
            pos => {
                center_caret_if_offscreen(&self.editor);
                Some(pos as u64)
            }
        }
    }

    fn search_prev(&mut self, query: &str, flags: SearchFlags) -> Option<u64> {
        // Symmetric to `search_next`: collapse to the START so the
        // re-anchor doesn't re-find the previous match when going
        // backward.
        let start = self.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as usize;
        self.editor.send(SCI_SETEMPTYSELECTION, start, 0);
        self.editor.search_anchor();
        match self.editor.search_prev(query, flags.bits()) {
            -1 => None,
            pos => {
                center_caret_if_offscreen(&self.editor);
                Some(pos as u64)
            }
        }
    }

    fn replace_current(&mut self, query: &str, replacement: &str, flags: SearchFlags) -> bool {
        // Defense-in-depth empty-query guard: `Shell::replace_current`
        // also gates this, but a future caller that bypasses the
        // shell-level wrapper would otherwise hit Scintilla's
        // permissive empty-target-match behaviour and replace the
        // selection with `replacement` regardless of content.
        if query.is_empty() {
            return false;
        }
        // Use the target range to verify the current selection
        // matches the search query before replacing ŌĆö guards
        // against the user dragging a different selection between
        // a Find and the Replace click. SCI_GET{SELECTIONSTART,END}
        // gives the selection range; SCI_SETTARGETRANGE pins it as
        // the target; SCI_SEARCHINTARGET returns nonneg iff the
        // target text matches `query` under `flags`. SEARCHINTARGET
        // (unlike SEARCH{NEXT,PREV}) reads flags from the sticky
        // state set by SCI_SETSEARCHFLAGS, so set them first.
        let sel_start = self.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as u64;
        let sel_end = self.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as u64;
        if sel_start == sel_end {
            return false;
        }
        self.editor.set_search_flags(flags.bits());
        self.editor.set_target_range(sel_start, sel_end);
        if self.editor.search_in_target(query) < 0 {
            return false;
        }
        // SEARCHINTARGET narrows the target to the match; replace
        // exactly that. Then re-anchor selection on the inserted
        // text so a subsequent Find Next walks past it.
        let _ = self.editor.replace_target(replacement);
        let new_end = self.editor.target_end();
        self.editor
            .send(SCI_SETSELECTIONSTART, sel_start as usize, 0);
        self.editor.send(SCI_SETSELECTIONEND, new_end as usize, 0);
        true
    }

    fn replace_all(&mut self, query: &str, replacement: &str, flags: SearchFlags) -> usize {
        if query.is_empty() {
            return 0;
        }
        // Wrap the whole iteration in a single Scintilla undo group
        // so Ctrl+Z reverts the entire Replace All in one step.
        // SEARCHINTARGET reads flags from the sticky state set
        // here once before the loop.
        self.editor.set_search_flags(flags.bits());
        self.editor.send(SCI_BEGINUNDOACTION, 0, 0);
        let mut count = 0usize;
        let mut cursor = 0u64;
        loop {
            // Re-read the document length each iteration ŌĆö the
            // previous replace_target may have grown or shrunk
            // the document, so a precomputed end would miss
            // matches past the size delta or stop short of them.
            let doc_len = self.editor.send(SCI_GETLENGTH, 0, 0).max(0) as u64;
            self.editor.set_target_range(cursor, doc_len);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            let _ = self.editor.replace_target(replacement);
            // Resume just past the inserted replacement; without
            // this, replacing "a" with "ab" would re-match the
            // newly-inserted "a" and loop forever.
            cursor = self.editor.target_end();
            count += 1;
        }
        self.editor.send(SCI_ENDUNDOACTION, 0, 0);
        count
    }

    fn count_matches(&mut self, query: &str, flags: SearchFlags) -> usize {
        if query.is_empty() {
            return 0;
        }
        // Whole-buffer iteration via SEARCHINTARGET so the user's
        // selection is never disturbed.
        self.editor.set_search_flags(flags.bits());
        let doc_len = self.editor.send(SCI_GETLENGTH, 0, 0).max(0) as u64;
        let mut count = 0usize;
        let mut cursor = 0u64;
        while cursor < doc_len {
            self.editor.set_target_range(cursor, doc_len);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            count += 1;
            let next = self.editor.target_end();
            // Zero-width regex matches need an explicit byte
            // advance ŌĆö but using +1 directly would land
            // mid-codepoint on multi-byte UTF-8. SCI_POSITIONAFTER
            // walks one whole character forward.
            cursor = if next > cursor {
                next
            } else {
                self.editor.send(SCI_POSITIONAFTER, next as usize, 0).max(0) as u64
            };
        }
        count
    }

    fn search_next_in_range(
        &mut self,
        query: &str,
        flags: SearchFlags,
        start: u64,
        end: u64,
    ) -> Option<u64> {
        if query.is_empty() || end <= start {
            return None;
        }
        self.editor.set_search_flags(flags.bits());
        // Anchor at the caret if it's strictly inside the range,
        // otherwise restart from `start`. Without the
        // strict-inside check a forward selection (caret == end)
        // would produce a zero-width target and silently miss
        // every match in the snapshotted range.
        let caret = self.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as u64;
        let lo = if caret >= start && caret < end {
            caret
        } else {
            start
        };
        self.editor.set_target_range(lo, end);
        let hit = self.editor.search_in_target(query);
        if hit < 0 {
            return None;
        }
        let pos = self.editor.target_start();
        let match_end = self.editor.target_end();
        self.editor.send(SCI_SETSELECTIONSTART, pos as usize, 0);
        self.editor.send(SCI_SETSELECTIONEND, match_end as usize, 0);
        center_caret_if_offscreen(&self.editor);
        Some(pos)
    }

    fn search_prev_in_range(
        &mut self,
        query: &str,
        flags: SearchFlags,
        start: u64,
        end: u64,
    ) -> Option<u64> {
        if query.is_empty() || end <= start {
            return None;
        }
        self.editor.set_search_flags(flags.bits());
        // Symmetric upper-bound choice to search_next_in_range:
        // use the caret if it's strictly past `start`, else
        // restart from `end`.
        let caret = self.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as u64;
        let upper = if caret > start && caret <= end {
            caret
        } else {
            end
        };
        // Scintilla's SEARCHINTARGET only walks forward, so we
        // accumulate every match in [start, upper) and keep the
        // last one as the "previous" hit relative to the caret.
        let mut last: Option<(u64, u64)> = None;
        let mut cursor = start;
        while cursor < upper {
            self.editor.set_target_range(cursor, upper);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            let pos = self.editor.target_start();
            let me = self.editor.target_end();
            last = Some((pos, me));
            cursor = if me > cursor {
                me
            } else {
                self.editor.send(SCI_POSITIONAFTER, me as usize, 0).max(0) as u64
            };
        }
        let (pos, match_end) = last?;
        self.editor.send(SCI_SETSELECTIONSTART, pos as usize, 0);
        self.editor.send(SCI_SETSELECTIONEND, match_end as usize, 0);
        center_caret_if_offscreen(&self.editor);
        Some(pos)
    }

    fn replace_all_in_range(
        &mut self,
        query: &str,
        replacement: &str,
        flags: SearchFlags,
        start: u64,
        end: u64,
    ) -> (usize, u64) {
        if query.is_empty() || end <= start {
            return (0, end);
        }
        self.editor.set_search_flags(flags.bits());
        self.editor.send(SCI_BEGINUNDOACTION, 0, 0);
        let mut count = 0usize;
        let mut cursor = start;
        let mut range_end = end;
        loop {
            self.editor.set_target_range(cursor, range_end);
            let hit = self.editor.search_in_target(query);
            if hit < 0 {
                break;
            }
            let match_start = self.editor.target_start();
            let match_end = self.editor.target_end();
            let _ = self.editor.replace_target(replacement);
            // The actual byte length inserted is read back from
            // `target_end()` after `replace_target` ŌĆö using
            // `replacement.len()` would be wrong under regex
            // mode where a `$1` backref expands to whatever the
            // captured group held, not the format-string length.
            // `saturating_sub` defends against a hypothetical
            // Scintilla edge case where `target_end` reports a
            // value below `match_start` ŌĆö without it the u64
            // wrap would propagate into `range_end` and lock the
            // loop into an infinite spin.
            let new_target_end = self.editor.target_end();
            let actual_replacement_len = new_target_end.saturating_sub(match_start);
            let delta = actual_replacement_len as i64 - (match_end as i64 - match_start as i64);
            cursor = new_target_end;
            range_end = (range_end as i64 + delta).max(cursor as i64) as u64;
            count += 1;
            if cursor >= range_end {
                break;
            }
        }
        self.editor.send(SCI_ENDUNDOACTION, 0, 0);
        (count, range_end)
    }

    // confirm_reload and show_error were intentionally removed from
    // UiPlatform: each runs `MessageBoxW` whose nested message pump
    // can re-enter the wnd_proc and produce aliasing UB on the
    // GWLP_USERDATA-borrowed WindowState. Modal dialogs are deferred
    // ŌĆö `Shell::drain` returns `Vec<PendingDialog>` that the wnd_proc
    // shows after the borrow is dropped (see `WM_APP_WAKE`).

    fn is_tabbar_hidden(&self) -> bool {
        // SAFETY: `self.tab_hwnd` was captured from the live tab
        // control during `WindowState::split`; `IsWindowVisible` is
        // a read-only Win32 query that never re-enters wnd_proc.
        // Returns FALSE for an invalid HWND, which we surface as
        // "not hidden" (matching the unstarted-window default).
        // INVARIANT: UI-thread-only. `IsWindowVisible` reads the
        // window's `WS_VISIBLE` style flag; pairing that read with
        // `ShowWindow` writes from another thread is formally a
        // race on the window-style word. Every call site here
        // runs on the UI thread (all `dispatch_nppm` invocations
        // are on the wnd_proc thread).
        !unsafe { IsWindowVisible(self.tab_hwnd).as_bool() }
    }

    fn set_tabbar_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_tabbar_hidden();
        // ShowWindow + a deferred relayout via PostMessage(WM_SIZE).
        // Synchronous SendMessage would re-enter the wnd_proc on
        // this thread, and any plugin call dispatching this is
        // already inside `PluginCallGuard` ŌĆö `state_from_hwnd`
        // would refuse the re-borrow and the layout would no-op.
        // PostMessage queues the size message for after the guard
        // drops; the message-pump dequeue then runs WM_SIZE
        // normally with full state access.
        let cmd = if hidden { SW_HIDE } else { SW_SHOW };
        unsafe {
            let _ = ShowWindow(self.tab_hwnd, cmd);
            relayout_main_window_via_post(self.tab_hwnd);
        }
        prev
    }

    fn is_toolbar_hidden(&self) -> bool {
        // Same INVARIANT note as `is_tabbar_hidden` ŌĆö UI-thread-only,
        // reads `WS_VISIBLE` on the toolbar HWND. Returns FALSE for
        // an invalid HWND, surfaced as "not hidden".
        !unsafe { IsWindowVisible(self.toolbar_hwnd).as_bool() }
    }

    fn set_toolbar_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_toolbar_hidden();
        let cmd = if hidden { SW_HIDE } else { SW_SHOW };
        unsafe {
            let _ = ShowWindow(self.toolbar_hwnd, cmd);
            // Same deferred-relayout pattern as `set_tabbar_hidden`:
            // PostMessage(WM_SIZE) so the editor area refills the
            // freed band without re-entering wnd_proc under
            // `PluginCallGuard`.
            relayout_main_window_via_post(self.toolbar_hwnd);
        }
        prev
    }

    fn is_menu_hidden(&self) -> bool {
        // GetMenu returns NULL when the main window has no menu ŌĆö
        // i.e. the menu is currently hidden. Cheap UI-thread read.
        // SAFETY: every call site is on the UI thread; the parent
        // HWND is derived from `tab_hwnd`, owned by us for the
        // window's lifetime.
        unsafe {
            let Ok(parent) = GetParent(self.tab_hwnd) else {
                return false;
            };
            GetMenu(parent).is_invalid()
        }
    }

    fn set_menu_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_menu_hidden();
        // SAFETY: UI-thread-only; parent HWND derived from
        // `tab_hwnd` (owned by us). `SetMenu(parent, None)` removes
        // the menu without destroying it; `DrawMenuBar` repaints
        // the non-client area so the freed / re-added band is
        // visible immediately. `None` (rather than
        // `Some(HMENU::default())`) is the documented windows-rs
        // 0.62 idiom for "remove menu" ŌĆö both happen to produce a
        // zero handle today, but `None` is what the binding's
        // `Option<HMENU>` parameter is meant for and won't break
        // if a future windows-rs minor version stops zeroing
        // handles on `unwrap_or`.
        unsafe {
            let Ok(parent) = GetParent(self.tab_hwnd) else {
                return prev;
            };
            let _ = SetMenu(parent, if hidden { None } else { Some(self.main_menu) });
            let _ = DrawMenuBar(parent);
            // Force a full relayout: removing / restoring the menu
            // changes the client-area height by one menu's worth
            // of pixels, which `WM_SIZE` propagates to the
            // editor / toolbar / status-bar stack.
            relayout_main_window_via_post(self.tab_hwnd);
        }
        prev
    }

    fn is_statusbar_hidden(&self) -> bool {
        !unsafe { IsWindowVisible(self.status_hwnd).as_bool() }
    }

    fn set_statusbar_hidden(&mut self, hidden: bool) -> bool {
        let prev = self.is_statusbar_hidden();
        let cmd = if hidden { SW_HIDE } else { SW_SHOW };
        unsafe {
            let _ = ShowWindow(self.status_hwnd, cmd);
            relayout_main_window_via_post(self.status_hwnd);
        }
        prev
    }

    fn editor_zoom_level(&self) -> i32 {
        // SCI_GETZOOM returns the zoom delta in points (signed
        // int, typically [-10, 20]). Direct-call read, no message
        // pump ŌĆö same hot-path shape as every other Scintilla
        // query.
        self.editor.send(SCI_GETZOOM, 0, 0) as i32
    }

    fn editor_default_fg_color(&self) -> i32 {
        // `SCI_STYLEGETFORE(STYLE_DEFAULT)` returns Win32
        // `COLORREF` (`0x00BBGGRR`). The `as i32` cast is the
        // identity bit pattern ŌĆö Scintilla's return is `intptr_t`
        // (`isize`), but only the low 24 bits of the COLORREF
        // are populated.
        self.editor.send(SCI_STYLEGETFORE, STYLE_DEFAULT, 0) as i32
    }

    fn editor_default_bg_color(&self) -> i32 {
        self.editor.send(SCI_STYLEGETBACK, STYLE_DEFAULT, 0) as i32
    }

    fn set_smooth_font(&mut self, smooth: bool) -> bool {
        // `SCI_SETFONTQUALITY` accepts one of the
        // `SC_EFF_QUALITY_*` enum values; LCD-optimised matches
        // the modern Win32 ClearType default for `smooth == true`,
        // and non-antialiased gives "smoothing off" an
        // observable on-screen effect.
        //
        // Scintilla doesn't expose a `SCI_GETFONTQUALITY` peer in
        // the public message set, so we shadow the state in a
        // process-wide atomic. Single-view Code++ has one editor
        // ŌĆö the shadow is correct as long as the chrome doesn't
        // race the plugin call (UI-thread-only invariant, same
        // as the chrome toggles).
        let prev = SMOOTH_FONT_STATE.load(std::sync::atomic::Ordering::Relaxed);
        let quality = if smooth {
            SC_EFF_QUALITY_LCD_OPTIMIZED
        } else {
            SC_EFF_QUALITY_NON_ANTIALIASED
        };
        self.editor.send(SCI_SETFONTQUALITY, quality as usize, 0);
        SMOOTH_FONT_STATE.store(smooth, std::sync::atomic::Ordering::Relaxed);
        prev
    }

    fn set_editor_border_edge(&mut self, enable: bool) -> bool {
        // Read the current `WS_EX_CLIENTEDGE` flag, mutate, then
        // tell the window the non-client area changed via
        // `SetWindowPos(SWP_FRAMECHANGED)` so the chrome repaints.
        // SAFETY: `self.editor.hwnd()` is the live editor HWND
        // owned by `WindowState` for the window's lifetime ŌĆö
        // `EditorHandle::hwnd()` exposes it as `*mut c_void` to
        // keep `editor` free of `windows`-crate types, so we wrap
        // it back into a `HWND` newtype here.
        //
        // `GetWindowLongPtrW` returns `isize` (pointer-width) ŌĆö
        // not `u32`. On 64-bit Windows the extended-style word is
        // returned through the full 64 bits, so a `as u32` cast
        // here would silently drop bits 32+ before the round-trip
        // through `SetWindowLongPtrW`, clearing whatever flags
        // future Microsoft expansions might add. Stay in `isize`
        // throughout the read-modify-write; widen the
        // `WS_EX_CLIENTEDGE` mask (declared `u32` in windows-rs)
        // to `isize` for the bit ops.
        let scintilla = HWND(self.editor.hwnd());
        let prev_ex = unsafe { GetWindowLongPtrW(scintilla, GWL_EXSTYLE) };
        let edge_mask = WS_EX_CLIENTEDGE.0 as isize;
        let prev_has_edge = (prev_ex & edge_mask) != 0;
        if prev_has_edge != enable {
            let new_ex = if enable {
                prev_ex | edge_mask
            } else {
                prev_ex & !edge_mask
            };
            unsafe {
                SetWindowLongPtrW(scintilla, GWL_EXSTYLE, new_ex);
                let _ = SetWindowPos(
                    scintilla,
                    None,
                    0,
                    0,
                    0,
                    0,
                    SWP_NOMOVE | SWP_NOSIZE | SWP_NOZORDER | SWP_FRAMECHANGED,
                );
            }
        }
        prev_has_edge
    }

    fn set_line_number_width_mode(&mut self, mode: i32) -> bool {
        // Code++'s line-number margin uses dynamic width by
        // default. The constant-mode path is a Phase 4 polish
        // item ŌĆö the dispatcher accepts the request and the
        // host records it, but the visible width does not yet
        // stop growing. Returning `true` means the host
        // accepted the value; the GET side reports DYNAMIC
        // unconditionally until the polish lands.
        tracing::trace!(
            mode,
            "NPPM_SETLINENUMBERWIDTHMODE: recorded (CONSTANT-mode pin is Phase 4 polish)"
        );
        true
    }

    fn shortcut_for_cmd_id(&self, cmd_id: i32) -> Option<codepp_plugin_host::ShortcutKey> {
        // Live introspection of the current accelerator table ŌĆö
        // reads the same HACCEL the message pump consults via
        // `TranslateAcceleratorW`. When
        // `NPPM_REMOVESHORTCUTBYCMDID` rebuilds the table the
        // change shows up here on the next call without any
        // cache invalidation: there's no cache.
        //
        // SAFETY: `self.accel_handle` was set by
        // `WindowState::split` (or the wnd_proc construction
        // sites) to point at `WindowState.accel_handle`. The
        // dereference reads the live HACCEL on the UI thread.
        // See `Win32Ui.accel_handle` field doc for the full
        // safety argument. `CopyAcceleratorTableW` is a
        // read-only Win32 query that doesn't re-enter
        // wnd_proc.
        let haccel = unsafe { *self.accel_handle };
        if haccel.is_invalid() {
            return None;
        }
        let count = unsafe { CopyAcceleratorTableW(haccel, None) };
        if count <= 0 {
            return None;
        }
        let mut entries: Vec<ACCEL> = vec![ACCEL::default(); count as usize];
        let written = unsafe { CopyAcceleratorTableW(haccel, Some(&mut entries)) };
        if written <= 0 {
            return None;
        }
        entries.truncate(written as usize);
        let needle = cmd_id as u16;
        let entry = entries.iter().find(|a| a.cmd == needle)?;
        Some(decode_accel_to_shortcut_key(entry))
    }

    fn register_modeless_dialog(&mut self, dlg: codepp_plugin_host::Hwnd, register: bool) -> bool {
        // The plugin's `Hwnd` opaque pointer is the same
        // `*mut c_void` Win32 ABI uses for `HWND` ŌĆö wrap it
        // back into windows-rs's newtype here. We never
        // dereference it; we only feed it to
        // `IsDialogMessageW` from the message pump (and even
        // that is the plugin's responsibility to keep valid via
        // the contract that REMOVE precedes destroy).
        let hwnd = HWND(dlg);
        if hwnd.is_invalid() {
            return false;
        }
        // SAFETY: same Win32Ui field invariants as `accel_handle`
        // ŌĆö the pointer addresses `WindowState.plugin_modeless_dialogs`
        // which is alive for the window's lifetime, dereferenced
        // only on the UI thread, and not aliased while Win32Ui
        // is in scope.
        let dialogs = unsafe { &mut *self.plugin_modeless_dialogs };
        if register {
            // De-duplicate: a plugin that registers the same
            // HWND twice should not double-iterate it in the
            // pump (would cause `IsDialogMessageW` to fire
            // twice per keystroke, breaking Tab/Enter
            // semantics inside the dialog).
            if !dialogs.iter().any(|h| h.0 == hwnd.0) {
                dialogs.push(hwnd);
            }
        } else {
            dialogs.retain(|h| h.0 != hwnd.0);
        }
        true
    }

    fn add_toolbar_icon(&mut self, cmd_id: i32, hicon: codepp_plugin_host::Hwnd) -> bool {
        // Add the plugin's HICON to the toolbar's HIMAGELIST,
        // then append a TBBUTTON bound to `cmd_id` so a click
        // posts `WM_COMMAND` with the plugin's id ŌĆö the same
        // path Code++'s built-in toolbar buttons use.
        //
        // SAFETY: every Win32 call here runs on the UI thread
        // (the trait method is invoked from a NPPM dispatch).
        // `self.toolbar_hwnd` is the live toolbar HWND owned by
        // `WindowState`. The plugin's HICON is read-only here;
        // `ImageList_ReplaceIcon` internally copies the bits,
        // so the plugin can free its handle immediately after
        // the call returns.
        use windows::Win32::UI::Controls::{
            ImageList_ReplaceIcon, HIMAGELIST, TBBUTTON, TBSTATE_ENABLED, TBSTYLE_BUTTON,
            TB_ADDBUTTONS, TB_AUTOSIZE, TB_GETIMAGELIST,
        };
        let icon_hwnd = HICON(hicon);
        if icon_hwnd.is_invalid() {
            return false;
        }
        unsafe {
            // Pull the toolbar's imagelist via TB_GETIMAGELIST.
            // wparam = imagelist index (0 ŌĆö the toolbar's
            // primary list, the one `build_image_list`
            // populated at startup); lparam unused.
            let himl_raw =
                SendMessageW(self.toolbar_hwnd, TB_GETIMAGELIST, Some(WPARAM(0)), None).0;
            if himl_raw == 0 {
                tracing::warn!(
                    cmd = cmd_id,
                    "NPPM_ADDTOOLBARICON: TB_GETIMAGELIST returned NULL"
                );
                return false;
            }
            let himl = HIMAGELIST(himl_raw);
            // `ImageList_ReplaceIcon(himl, -1, hicon)` appends
            // the icon and returns its new index. -1 on failure
            // (out of memory / bad icon).
            let new_idx = ImageList_ReplaceIcon(himl, -1, icon_hwnd);
            if new_idx < 0 {
                tracing::warn!(
                    cmd = cmd_id,
                    "NPPM_ADDTOOLBARICON: ImageList_ReplaceIcon returned -1"
                );
                return false;
            }
            // Build the TBBUTTON. `iBitmap` is the imagelist
            // index just returned; `idCommand` is the plugin's
            // cmd id; `fsState` enables the button; `fsStyle` is
            // BTNS_BUTTON (a plain push button ŌĆö no check, no
            // separator). `iString` and `dwData` are unused
            // (plugin-driven tooltips arrive via TBN_GETINFOTIP
            // notifications, a future polish item handles).
            let btn = TBBUTTON {
                iBitmap: new_idx,
                idCommand: cmd_id,
                fsState: TBSTATE_ENABLED as u8,
                fsStyle: TBSTYLE_BUTTON as u8,
                bReserved: [0; 6],
                dwData: 0,
                iString: 0,
            };
            let added = SendMessageW(
                self.toolbar_hwnd,
                TB_ADDBUTTONS,
                Some(WPARAM(1)),
                Some(LPARAM(&raw const btn as isize)),
            );
            if added.0 == 0 {
                tracing::warn!(
                    cmd = cmd_id,
                    "NPPM_ADDTOOLBARICON: TB_ADDBUTTONS rejected the new TBBUTTON"
                );
                return false;
            }
            // Refresh layout so the new button is visible
            // immediately. No relayout-via-post needed: the
            // toolbar's own auto-size handles the chrome
            // refresh and the parent's WM_SIZE-driven layout
            // picks up the new toolbar height (if any) on the
            // next paint cycle.
            SendMessageW(self.toolbar_hwnd, TB_AUTOSIZE, None, None);
        }
        true
    }

    fn is_dark_mode_enabled(&self) -> bool {
        // Code++ Phase 4 has no host-side dark-mode rendering
        // (DESIGN.md ┬¦7.4 Phase-5 polish item). The honest
        // answer is FALSE; plugins watching `NPPN_DARKMODECHANGED`
        // and gating on this query gracefully skip their
        // dark-mode code paths until the host-side dark mode
        // lands.
        false
    }

    fn dark_mode_colors(&self, _out: &mut codepp_plugin_host::NppDarkModeColors) -> bool {
        // No host-side dark mode ŌåÆ no palette to share. The
        // dispatcher already gated on size + nullness, so
        // returning false is the only honest answer here. When
        // Phase 5 wires dark-mode rendering, this writes the
        // 12 active COLORREFs into `out` and returns true.
        false
    }

    fn create_plugin_scintilla(
        &mut self,
        parent: codepp_plugin_host::Hwnd,
    ) -> codepp_plugin_host::Hwnd {
        // Create a Scintilla control as a child of the
        // plugin-supplied `parent`. The Scintilla window class
        // is already registered (`Scintilla_RegisterClasses`
        // runs at startup), so `CreateWindowExW` against
        // `SCINTILLA_CLASS` produces a fresh control with its
        // own document, undo stack, and direct-call function
        // pointer. The plugin owns the new HWND's lifetime.
        //
        // SAFETY: every Win32 call here runs on the UI thread
        // (the trait method is invoked from a NPPM dispatch).
        // The plugin's `Hwnd` opaque pointer is the same
        // `*mut c_void` Win32 ABI uses for `HWND` ŌĆö we wrap it
        // back into windows-rs's newtype here. We never
        // dereference it; we only feed it to `IsWindow` and
        // pass it as the parent to `CreateWindowExW`.
        //
        // The returned HWND escapes into plugin address space:
        // the plugin holds it past this function's lifetime
        // and is contractually obliged to `DestroyWindow` it
        // before the parent dies. The host has no lifetime
        // hook to detect a misbehaving plugin's use-after-
        // destroy; this is the same in-process "trust the
        // plugin not to crash us" model Notepad++ uses (and
        // documented in DESIGN.md ┬¦6.5).
        let parent_hwnd = HWND(parent);
        // Belt-and-suspenders null check. The dispatcher's
        // `lparam <= 0` guard already rejects NULL via the
        // NPPM path, but the `HostServices` trait is `pub` ŌĆö
        // a future direct caller (e.g. a Phase-5 GTK/Cocoa
        // NPPM bridge) could bypass the dispatcher.
        // `is_invalid()` is the canonical windows-rs null
        // test; the `IsWindow` call below catches dead-but-
        // non-null parents.
        if parent_hwnd.is_invalid() {
            return core::ptr::null_mut();
        }
        unsafe {
            // Defensive: a plugin that passes a HWND it has
            // already destroyed would otherwise feed a dead
            // HWND to `CreateWindowExW`, which Win32 reports as
            // a confusing "invalid window handle" error. Reject
            // up front instead. `IsWindow` also rejects the
            // `HWND_BROADCAST` pseudo-HWND (0xFFFF), the only
            // positive Win32 pseudo-HWND value that would
            // survive the dispatcher's `lparam <= 0` guard.
            //
            // TOCTOU note: Win32 has no atomic "create only if
            // parent is live" syscall, so a plugin that
            // destroys `parent_hwnd` from a worker thread
            // between this `IsWindow` check and the
            // `CreateWindowExW` call can race the host into
            // either a `CreateWindowExW` failure (benign,
            // logged below) or a child whose parent is
            // garbage-collected indeterminately. The plugin is
            // contractually responsible for not racing
            // destroy-against-create on its own HWNDs; the
            // host stays UI-thread-only for its own state, so
            // it cannot itself introduce the race.
            if !IsWindow(Some(parent_hwnd)).as_bool() {
                tracing::warn!(
                    parent = parent_hwnd.0 as usize,
                    "NPPM_CREATESCINTILLAHANDLE: parent HWND is not a live window"
                );
                return core::ptr::null_mut();
            }
            // The host's executable module handle is the right
            // hInstance for `CreateWindowExW` here ŌĆö Scintilla's
            // window class was registered against this module
            // by `Scintilla_RegisterClasses` at startup. Using
            // the plugin's DLL hInstance here would be wrong;
            // the class is host-owned, not plugin-owned.
            let instance = match GetModuleHandleW(None) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(
                        error = %e,
                        "NPPM_CREATESCINTILLAHANDLE: GetModuleHandleW failed"
                    );
                    return core::ptr::null_mut();
                }
            };
            // WS_CHILD: parented control, no caption / no system menu.
            // No WS_VISIBLE: the plugin decides when to show ŌĆö typical
            // pattern is to size + show inside the plugin's own
            // dialog/container after creation. WS_CLIPCHILDREN keeps
            // any future child redraws (Scintilla itself doesn't add
            // any in this configuration, but plugins occasionally
            // overlay tooltips) from flickering. WS_VSCROLL /
            // WS_HSCROLL match the styles N++ uses for plugin-owned
            // Scintillas so plugin scroll messages have a real bar to
            // drive.
            let new_hwnd = match CreateWindowExW(
                WINDOW_EX_STYLE::default(),
                SCINTILLA_CLASS,
                PCWSTR::null(),
                WS_CHILD | WS_CLIPCHILDREN | WS_VSCROLL | WS_HSCROLL,
                0,
                0,
                0,
                0,
                Some(parent_hwnd),
                None,
                Some(instance.into()),
                None,
            ) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(
                        error = %e,
                        parent = parent_hwnd.0 as usize,
                        "NPPM_CREATESCINTILLAHANDLE: CreateWindowExW failed"
                    );
                    return core::ptr::null_mut();
                }
            };
            // Initialise the codepage to UTF-8 so plugin-owned
            // Scintillas inherit the host's UTF-8-internal
            // invariant. Scintilla 5.x defaults to SC_CP_UTF8
            // already, but setting it explicitly is robust to
            // a future Scintilla version flipping the default.
            // Plugins that need a different codepage can
            // override after the call returns.
            SendMessageW(
                new_hwnd,
                SCI_SETCODEPAGE,
                Some(WPARAM(SC_CP_UTF8 as usize)),
                None,
            );
            new_hwnd.0
        }
    }

    fn register_dock_dialog(&mut self, params: codepp_plugin_host::DockDialogParams) -> bool {
        // Floating-only mode (Phase 4 m4): wrap the plugin's
        // h_client in a host-owned WS_OVERLAPPEDWINDOW frame and
        // re-parent h_client into the frame's client area. The
        // frame is hidden until NPPM_DMMSHOW.
        //
        // SAFETY: every Win32 call here runs on the UI thread
        // (the trait method is invoked from a NPPM dispatch).
        // `dock_dialogs` points at `WindowState.dock_dialogs`,
        // alive for the main window's lifetime; UI-thread-only
        // access is guaranteed by `state_from_hwnd`'s
        // `PluginCallGuard`.
        let h_client = HWND(params.h_client);
        if h_client.is_invalid() {
            return false;
        }
        unsafe {
            if !IsWindow(Some(h_client)).as_bool() {
                tracing::warn!(
                    h = h_client.0 as usize,
                    "NPPM_DMMREGASDCKDLG: h_client is not a live window"
                );
                return false;
            }
            // Reject duplicate registrations of the same h_client.
            // Walking the Vec is O(n) but n is small (typically
            // <= 4 docks per session) and this is the only
            // call-site that grows it.
            let dialogs = &mut *self.dock_dialogs;
            if dialogs.iter().any(|e| e.h_client.0 == h_client.0) {
                tracing::warn!(
                    h = h_client.0 as usize,
                    "NPPM_DMMREGASDCKDLG: h_client already registered"
                );
                return false;
            }
            // Bound the number of registered frames so a buggy
            // / malicious plugin can't exhaust the per-process
            // GDI handle table by flooding REGASDCKDLG with
            // fresh HWNDs.
            if dialogs.len() >= DOCK_DIALOG_REGISTRATION_CAP {
                tracing::warn!(
                    cap = DOCK_DIALOG_REGISTRATION_CAP,
                    "NPPM_DMMREGASDCKDLG: registration cap reached; rejecting"
                );
                return false;
            }
            register_dock_frame_class();
            let instance = match GetModuleHandleW(None) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(error = %e, "NPPM_DMMREGASDCKDLG: GetModuleHandleW failed");
                    return false;
                }
            };
            // Initial position: use the plugin's `rc_float` if
            // it's non-empty (right > left, bottom > top); else
            // fall back to a default size centred on the
            // primary monitor's working area (cheap, predictable
            // ŌĆö Phase 5 docking-manager work places the frame
            // relative to the host window).
            let (x, y, width, height) = compute_dock_frame_position(&params.rc_float);
            // Encode the title in UTF-16 for SetWindowTextW. An
            // empty name (plugin sent NULL pszName, or all bad
            // surrogates) falls back to the module name; if
            // both are empty, use "Plugin Dialog".
            let title = if !params.name.is_empty() {
                params.name.as_str()
            } else if !params.module_name.is_empty() {
                params.module_name.as_str()
            } else {
                "Plugin Dialog"
            };
            let title_utf16: Vec<u16> = title.encode_utf16().chain(core::iter::once(0)).collect();
            // Owned by the main window so Win32 destroys the
            // frame when the host shuts down (no leak on
            // forgetful plugins). WS_EX_TOOLWINDOW keeps the
            // frame off the taskbar ŌĆö these are accessory
            // panels, not standalone documents.
            //
            // Bail if `GetParent` fails: a null owner would make
            // the frame unowned, breaking the "Win32 destroys
            // the frame when the main window dies" invariant
            // and leaking the frame plus the re-parented
            // h_client. Same early-return pattern as the rest
            // of the file's `GetParent(self.tab_hwnd)` call
            // sites.
            let main_hwnd_owner = match GetParent(self.tab_hwnd) {
                Ok(p) if !p.is_invalid() => p,
                _ => {
                    tracing::warn!("NPPM_DMMREGASDCKDLG: GetParent(tab_hwnd) returned no owner");
                    return false;
                }
            };
            let frame = match CreateWindowExW(
                WS_EX_TOOLWINDOW,
                DOCK_FRAME_CLASS,
                PCWSTR(title_utf16.as_ptr()),
                WS_OVERLAPPEDWINDOW,
                x,
                y,
                width,
                height,
                Some(main_hwnd_owner),
                None,
                Some(instance.into()),
                // Plugin's h_client passed via lpCreateParams;
                // dock_frame_wnd_proc stashes it in
                // GWLP_USERDATA at WM_NCCREATE.
                Some(h_client.0.cast_const()),
            ) {
                Ok(h) => h,
                Err(e) => {
                    tracing::warn!(error = %e, "NPPM_DMMREGASDCKDLG: CreateWindowExW failed");
                    return false;
                }
            };
            // Re-parent the plugin's h_client into the frame's
            // client area. SetParent returns the previous parent
            // on success (the value we don't need); on failure
            // (different desktop, threading mismatch, etc.) it
            // returns Err. We MUST treat failure as fatal
            // here ŌĆö otherwise we'd push a DockEntry whose
            // frame_hwnd has no child, and dock_frame_wnd_proc's
            // WM_SIZE would resize an unrelated plugin HWND
            // that's still attached to the plugin's original
            // parent (silent UI corruption).
            //
            // TOCTOU note: between the `IsWindow(h_client)`
            // check above and this `SetParent` call there's a
            // window where the plugin could destroy h_client
            // from another thread. Same race the
            // `create_plugin_scintilla` path documents: Win32
            // has no atomic "act on HWND only if alive"
            // primitive, the plugin owns the destroy contract,
            // and the host stays UI-thread-only. SetParent
            // failure here is the catch-all for any reason
            // h_client became unusable after the IsWindow
            // check.
            if SetParent(h_client, Some(frame)).is_err() {
                tracing::warn!(
                    h = h_client.0 as usize,
                    "NPPM_DMMREGASDCKDLG: SetParent failed; tearing down frame"
                );
                let _ = DestroyWindow(frame);
                return false;
            }
            // Resize h_client to the frame's client area
            // immediately so the first paint shows it filling
            // the client area; subsequent WM_SIZE on the frame
            // does the same via dock_frame_wnd_proc.
            let mut rc = RECT::default();
            if GetClientRect(frame, &raw mut rc).is_ok() {
                let _ = MoveWindow(h_client, 0, 0, rc.right, rc.bottom, true);
            }
            // Make the plugin's dialog visible inside the frame.
            // The frame itself stays hidden until NPPM_DMMSHOW.
            let _ = ShowWindow(h_client, SW_SHOW);
            dialogs.push(DockEntry {
                h_client,
                frame_hwnd: frame,
                name: params.name,
                module_name: params.module_name,
                dlg_id: params.dlg_id,
                u_mask: params.u_mask,
            });
        }
        true
    }

    fn show_dock_dialog(&mut self, h_client: codepp_plugin_host::Hwnd) -> bool {
        let h = HWND(h_client);
        if h.is_invalid() {
            return false;
        }
        // SAFETY: `dock_dialogs` is alive while `Win32Ui` is in
        // scope; UI-thread-only access ŌĆö see the field doc on
        // `Win32Ui::dock_dialogs`.
        unsafe {
            let dialogs = &*self.dock_dialogs;
            for entry in dialogs {
                if entry.h_client.0 == h.0 {
                    let _ = ShowWindow(entry.frame_hwnd, SW_SHOW);
                    return true;
                }
            }
        }
        false
    }

    fn hide_dock_dialog(&mut self, h_client: codepp_plugin_host::Hwnd) -> bool {
        let h = HWND(h_client);
        if h.is_invalid() {
            return false;
        }
        unsafe {
            let dialogs = &*self.dock_dialogs;
            for entry in dialogs {
                if entry.h_client.0 == h.0 {
                    let _ = ShowWindow(entry.frame_hwnd, SW_HIDE);
                    return true;
                }
            }
        }
        false
    }

    fn update_dock_disp_info(&mut self, h_client: codepp_plugin_host::Hwnd) -> bool {
        // Floating-only mode (Phase 4 m4): the registration's
        // cached strings (name, module_name) were read once at
        // REGASDCKDLG time and aren't refreshed here. The full
        // re-read (re-walking the plugin's `tTbData`'s wide
        // strings and updating the frame title) is a Phase 5
        // docking-manager polish item ŌĆö most real plugins set
        // their title once at registration and never update,
        // so the gap is invisible in practice. Returns success
        // for any registered HWND so plugins that gate on the
        // boolean return don't bail out.
        let h = HWND(h_client);
        if h.is_invalid() {
            return false;
        }
        unsafe {
            let dialogs = &*self.dock_dialogs;
            dialogs.iter().any(|e| e.h_client.0 == h.0)
        }
    }

    fn dock_hwnd_by_name(&self, name: &str, module_name: Option<&str>) -> codepp_plugin_host::Hwnd {
        unsafe {
            let dialogs = &*self.dock_dialogs;
            for entry in dialogs {
                if entry.name == name && module_name.is_none_or(|m| m == entry.module_name) {
                    return entry.h_client.0;
                }
            }
        }
        core::ptr::null_mut()
    }

    fn remove_shortcut_for_cmd_id(&mut self, cmd_id: i32) -> bool {
        // Win32 has no in-place mutation API for accelerator
        // tables, so "remove a binding" is implemented as
        // copy ŌåÆ filter ŌåÆ create-new ŌåÆ destroy-old ŌåÆ swap.
        // The new HACCEL is written through `self.accel_handle`
        // back to `WindowState`; the message pump reads the
        // slot fresh on every iteration so the removed binding
        // stops translating on the very next keystroke.
        //
        // SAFETY: same UI-thread, single-mutator invariant as
        // `shortcut_for_cmd_id` above. The destroy-old step
        // happens AFTER the new HACCEL is written, so the
        // pump (which can in principle race the recreate on a
        // future async-dispatched plugin call) never reads a
        // freshly-destroyed handle.
        let old_haccel = unsafe { *self.accel_handle };
        if old_haccel.is_invalid() {
            return false;
        }
        let count = unsafe { CopyAcceleratorTableW(old_haccel, None) };
        if count <= 0 {
            return false;
        }
        let mut entries: Vec<ACCEL> = vec![ACCEL::default(); count as usize];
        let written = unsafe { CopyAcceleratorTableW(old_haccel, Some(&mut entries)) };
        if written <= 0 {
            return false;
        }
        entries.truncate(written as usize);
        let needle = cmd_id as u16;
        let before = entries.len();
        entries.retain(|a| a.cmd != needle);
        if entries.len() == before {
            // Nothing matched ŌĆö the cmd id had no binding in
            // the table, return `false` so the plugin sees
            // "no removal happened" rather than a misleading
            // success.
            return false;
        }
        // Build the new HACCEL. If creation fails (extremely
        // rare ŌĆö only possible on resource exhaustion), keep
        // the old one so the host stays in a known-good state.
        let new_haccel = match unsafe { CreateAcceleratorTableW(&entries) } {
            Ok(h) => h,
            Err(e) => {
                tracing::warn!(error = %e, "NPPM_REMOVESHORTCUTBYCMDID: CreateAcceleratorTableW failed, keeping old HACCEL");
                return false;
            }
        };
        // Order matters: write the new handle through the
        // pointer FIRST, then destroy the old one. The pump
        // can read the slot at any time; write-then-destroy
        // ensures the read either sees the old (still valid)
        // handle or the new one ŌĆö never a destroyed one.
        unsafe {
            *self.accel_handle = new_haccel;
        }
        let _ = unsafe { DestroyAcceleratorTable(old_haccel) };
        true
    }

    fn capture_text_from_doc(&mut self, scintilla_doc: isize) -> String {
        if scintilla_doc == 0 {
            // Sentinel for "no document attached yet" ŌĆö there's
            // nothing to read. Surface as empty rather than asking
            // Scintilla to dereference a null doc pointer.
            return String::new();
        }
        let prior_doc = self.editor.send(SCI_GETDOCPOINTER, 0, 0);
        if prior_doc == scintilla_doc {
            // Already bound ŌĆö read directly without round-tripping
            // through SCI_SETDOCPOINTER twice. Common case for the
            // active tab.
            return <Self as UiPlatform>::get_buffer_text(self);
        }
        // Snapshot the prior doc's view state BEFORE the swap.
        // Scintilla's `Editor::SetDocPointer` (Editor.cxx:5464)
        // calls `sel.Clear()` on every doc swap ŌĆö including the
        // swap-back to the prior doc ŌĆö so without this snapshot
        // the active tab's caret and scroll get reset to (0, 0)
        // every auto-save tick.
        let view = self.snapshot_active_view();
        self.editor.send(SCI_SETDOCPOINTER, 0, scintilla_doc);
        let text = <Self as UiPlatform>::get_buffer_text(self);
        if prior_doc != 0 {
            self.editor.send(SCI_SETDOCPOINTER, 0, prior_doc);
            self.restore_active_view(view);
        }
        text
    }

    fn is_doc_dirty(&mut self, scintilla_doc: isize) -> bool {
        if scintilla_doc == 0 {
            return false;
        }
        let prior_doc = self.editor.send(SCI_GETDOCPOINTER, 0, 0);
        if prior_doc == scintilla_doc {
            return self.editor.send(SCI_GETMODIFY, 0, 0) != 0;
        }
        // Same view-snapshot dance as `capture_text_from_doc`.
        let view = self.snapshot_active_view();
        self.editor.send(SCI_SETDOCPOINTER, 0, scintilla_doc);
        let dirty = self.editor.send(SCI_GETMODIFY, 0, 0) != 0;
        if prior_doc != 0 {
            self.editor.send(SCI_SETDOCPOINTER, 0, prior_doc);
            self.restore_active_view(view);
        }
        dirty
    }

    #[cfg(target_os = "windows")]
    fn dispatch_npp_menu_command(&mut self, idm: i32) -> bool {
        // Resolve the built-in mapping first. Plugin-allocated cmd
        // ids (FuncItem entries or `NPPM_ALLOCATECMDID` allocations)
        // land inside the range checked by [`is_plugin_cmd_id`];
        // those are already installed as menu items owned by the
        // plugin's own submenu and can be dispatched as-is. Unmapped
        // built-in ids AND ids past the plugin-alloc ceiling get
        // logged and dropped ŌĆö the alternative (posting an
        // unrecognised WM_COMMAND) would either hit the fall-through
        // arm or, worse, collide with an unrelated Code++ ID_* value
        // via `main_wnd_proc`'s low-16-bit `WM_COMMAND` keying.
        let target: u32 = if let Some(local) = map_npp_idm_to_local(idm) {
            u32::from(local)
        } else if is_plugin_cmd_id(idm) {
            // Plugin-allocated cmd id ŌĆö safe to pass through: it
            // was minted by our own allocator (or came out of the
            // plugin's own FuncItem table) and points at an item
            // in the plugin's submenu. `idm as u32` widens
            // losslessly because `is_plugin_cmd_id` guaranteed
            // `idm >= PLUGIN_CMD_ID_BASE`, which is positive.
            #[allow(clippy::cast_sign_loss)]
            {
                idm as u32
            }
        } else {
            tracing::trace!(idm, "NPPM_MENUCOMMAND: no target for idm");
            return false;
        };
        // Post rather than send: this method runs inside
        // `dispatch_plugin_message`, which holds `&mut Shell` +
        // `&mut Win32Ui` borrows. A synchronous `SendMessageW`
        // would re-enter `main_wnd_proc` on this thread and hit
        // `PluginCallGuard`'s re-borrow refusal (or worse, land
        // in a WM_COMMAND handler that expects those borrows to
        // be free). PostMessage defers the dispatch to the next
        // pump iteration.
        //
        // SAFETY: `self.tab_hwnd`'s parent is the main window,
        // owned by `WindowState` which outlives every `Win32Ui`
        // instance. `PostMessageW` only enqueues; no wnd_proc
        // reentry happens synchronously.
        unsafe {
            let Ok(main_hwnd) = GetParent(self.tab_hwnd) else {
                tracing::warn!("NPPM_MENUCOMMAND: no parent HWND on tab strip");
                return false;
            };
            let _ = PostMessageW(
                Some(main_hwnd),
                WM_COMMAND,
                WPARAM(target as usize),
                LPARAM(0),
            );
        }
        true
    }

    #[cfg(target_os = "windows")]
    fn set_npp_menu_item_check(&mut self, idm: i32, checked: bool) -> bool {
        // Same id-shape decoding as `dispatch_npp_menu_command`:
        // built-in ids go through the mapping table, plugin cmd
        // ids pass through (bounded by `is_plugin_cmd_id`), and
        // everything else is rejected with a trace log. Rejection
        // is symmetric with `dispatch_npp_menu_command` even though
        // `CheckMenuItem` itself doesn't truncate ŌĆö a plugin
        // sending garbage-past-the-alloc-ceiling is a bug either
        // way, and failing closed on both paths keeps the two
        // dispatch shapes consistent.
        let target: u32 = if let Some(local) = map_npp_idm_to_local(idm) {
            u32::from(local)
        } else if is_plugin_cmd_id(idm) {
            #[allow(clippy::cast_sign_loss)]
            {
                idm as u32
            }
        } else {
            tracing::trace!(idm, "NPPM_SETMENUITEMCHECK: no target for idm");
            return false;
        };
        // `MF_BYCOMMAND` makes `CheckMenuItem` search recursively
        // through every submenu of `self.main_menu` for an item
        // matching `target`. Covers both built-in items (which
        // live in the File / Edit / Search / View submenus) and
        // plugin cmd ids (which live in the Plugins submenu).
        // Returns `-1u32` on failure (item not found) which we
        // surface as `false`; a plugin calling this on an id that
        // has no menu item gets a clean rejection instead of a
        // silent no-op.
        //
        // SAFETY: `self.main_menu` is populated at window
        // construction and never destroyed until window teardown;
        // `Win32Ui` instances are UI-thread-only. `CheckMenuItem`
        // does not re-enter our wnd_proc.
        let flags = MF_BYCOMMAND.0
            | if checked {
                MF_CHECKED.0
            } else {
                MF_UNCHECKED.0
            };
        let prev = unsafe { CheckMenuItem(self.main_menu, target, flags) };
        // `CheckMenuItem` returns `-1u32` (`0xFFFF_FFFF`) when the
        // item can't be found. Every other value is a legitimate
        // previous state (`MF_CHECKED`/`MF_UNCHECKED`).
        prev != u32::MAX
    }

    fn mark_active_buffer_dirty(&mut self) {
        // Scintilla has no direct "flip the modified flag" API ŌĆö
        // the modified state is derived from whether the current
        // undo position matches the last save-point. To force
        // "dirty" without touching text, we add an opaque
        // container action to the undo stack: that shifts the
        // undo position past the save-point, so `SCI_GETMODIFY`
        // starts returning true.
        //
        // No-op when the buffer is already dirty ŌĆö a plugin that
        // redundantly re-marks (say, once per keystroke) would
        // otherwise pile up phantom `SC_MOD_CONTAINER` entries the
        // user has to Ctrl+Z past. Once-per-transition matches
        // Notepad++'s own semantic (its `Buffer::setDirty(true)`
        // is idempotent).
        //
        // The container action itself sits on the undo stack as
        // an opaque token (0) with no side effects: if the user
        // does Ctrl+Z all the way back, they'll pass through one
        // phantom step that fires `SCN_MODIFIED` with
        // `SC_MOD_CONTAINER` ŌĆö Code++ has no `SC_MOD_CONTAINER`
        // handler, so the notification is dropped and the buffer
        // reaches the save-point again (clean). That's the cost
        // of buffer-level "make dirty" without touching text.
        if self.editor.send(SCI_GETMODIFY, 0, 0) != 0 {
            return;
        }
        self.editor.send(SCI_ADDUNDOACTION, 0, 0);
    }
}

/// Snapshot of the editor's view state ŌĆö the bits Scintilla wipes
/// on `SCI_SETDOCPOINTER` (selection, caret, scroll). Captured
/// before a document-pointer swap by `capture_text_from_doc` and
/// `is_doc_dirty` so that swapping out and back doesn't reset the
/// user's caret to position 0 every auto-save tick.
#[derive(Clone, Copy)]
struct ScintillaViewState {
    /// `SCI_GETCURRENTPOS` ŌĆö caret end of the selection.
    caret: isize,
    /// `SCI_GETANCHOR` ŌĆö opposite end of the selection. Equal to
    /// `caret` for a collapsed selection.
    anchor: isize,
    /// `SCI_GETFIRSTVISIBLELINE` ŌĆö top line of the viewport. Used
    /// with a `SCI_LINESCROLL` delta to restore vertical scroll.
    top_line: isize,
    /// `SCI_GETXOFFSET` ŌĆö horizontal scroll in pixels. Restored
    /// directly via `SCI_SETXOFFSET`.
    x_offset: isize,
}

impl Win32Ui {
    /// UDL branch of `<Self as UiPlatform>::apply_lang` ŌĆö set
    /// container-lexer mode, apply the UDL's own style palette,
    /// and immediately paint the whole buffer via the m1c-2
    /// tokeniser. Inherent (not-a-trait-method) so the trait
    /// impl stays focused on Lexilla-lexer routing; UDL is a
    /// different enough dispatch shape (no lexer name, host-side
    /// styling) that co-mingling the two branches would obscure
    /// both.
    ///
    /// Registry lookup runs through `state_from_hwnd(main_hwnd)`
    /// because `Win32Ui` doesn't hold a Shell reference ŌĆö the
    /// main HWND is derived via `GetParent(self.tab_hwnd)`, the
    /// same pattern `apply_default_style` uses for its
    /// `WindowState` access. If the registry doesn't contain the
    /// requested id (shouldn't happen ŌĆö Shell only hands out ids
    /// it registered ŌĆö but defensive), or `GetParent` returns
    /// null (impossible by construction), fall through to plain
    /// text.
    fn apply_udl_lang(&mut self, lang: LangType) {
        // Read the UDL from the pre-populated raw pointer rather
        // than reaching back through `state_from_hwnd` ŌĆö that
        // would produce a second `&WindowState` overlapping with
        // the outer callers' `&mut WindowState` borrow (aliasing
        // UB in `handle_close_active_tab_inner`,
        // `handle_tab_selchange`, `handle_style_config_menu`).
        // The registry is populated once at `Shell::new` and
        // read-only from here.
        //
        // SAFETY: `self.udl_registry` was captured from
        // `WindowState.shell.udl_registry` at Win32Ui
        // construction. `WindowState` outlives `Win32Ui` (which
        // is Copy but only ever exists as a short-lived value
        // during dispatch), the registry is never mutated after
        // `Shell::new`, and we only take a shared reference
        // for the duration of the clone.
        // Clone only what we need: the style palette (Vec of 24
        // small structs) and the Arc of compiled rules (pointer
        // bump). Was `entry.definition.clone()` ŌĆö that copied
        // hundreds of keyword strings on every language switch.
        // Both fields survive the registry borrow ending here so
        // the block below can proceed without holding a live
        // `&UdlEntry`.
        let styles_and_rules = unsafe { &*self.udl_registry }
            .find_by_lang_type_id(lang.as_npp_id())
            .map(|entry| {
                (
                    entry.definition.styles.clone(),
                    std::sync::Arc::clone(&entry.compiled),
                )
            });
        let Some((styles, compiled_rules)) = styles_and_rules else {
            tracing::warn!(
                lang = lang.as_npp_id(),
                "UDL LangType not in registry; falling back to plain text"
            );
            self.editor.clear_lexer();
            apply_default_styles(&self.editor);
            self.editor.send(SCI_COLOURISE, 0, -1);
            return;
        };
        // Container-lexer mode: no Lexilla lexer attached. Every
        // subsequent `SCN_STYLENEEDED` on this document fires
        // through the WM_NOTIFY dispatch in `main_wnd_proc` and
        // routes to `udl_paint::paint_udl_range`.
        //
        // **Why the paint below is bounded rather than full-
        // document.** `clear_lexer()` doesn't reset Scintilla's
        // `endStyled` cursor (verified against
        // `vendor/scintilla/src/Document.cxx:65-67` ŌĆö
        // `SCI_SETILEXER(0, 0)` swaps only the lexer pointer
        // and leaves `endStyled` alone). Without an explicit
        // paint the previously-Lexilla-styled bytes keep their
        // old style indices ŌĆö which now point at the freshly-
        // cleared per-style palette we just installed above ŌĆö
        // producing visually-empty styling for the whole
        // document until the user scrolls. So an initial
        // paint IS required.
        //
        // But full-document paint here would violate DESIGN.md
        // ┬¦8's UI-never-blocks constraint on the tens-of-MB
        // range. Instead we cap the synchronous initial paint
        // at [`INITIAL_PAINT_CAP`] bytes; the rest fills in
        // via `SCN_STYLENEEDED` as the user scrolls. 64 KiB
        // comfortably covers viewport-sized files AND the
        // visible window on multi-MB files, and the m1c-2
        // tokeniser is linear-time so this bounds the initial-
        // paint wall clock deterministically.
        self.editor.clear_lexer();
        apply_default_styles(&self.editor);
        udl_paint::apply_udl_styles(&self.editor, &styles);
        const INITIAL_PAINT_CAP: usize = 64 * 1024;
        let doc_len = self.editor.send(SCI_GETLENGTH, 0, 0).max(0) as usize;
        let cap = doc_len.min(INITIAL_PAINT_CAP);
        // Align to end-of-line so the tokeniser doesn't see a
        // mid-line partial delimiter span at the cap.
        let end_line = self.editor.line_from_position(cap);
        let paint_end = self
            .editor
            .position_from_line(end_line + 1)
            .unwrap_or(doc_len)
            .min(doc_len);
        if paint_end > 0 {
            if let Some(bytes) = self.editor.get_range_bytes(0, paint_end) {
                udl_paint::paint_udl_range(&self.editor, &compiled_rules, 0, &bytes);
            }
        }
    }

    /// Capture every piece of view state that `SCI_SETDOCPOINTER`
    /// would wipe on the swap-back. See `ScintillaViewState`.
    fn snapshot_active_view(&self) -> ScintillaViewState {
        ScintillaViewState {
            caret: self.editor.send(SCI_GETCURRENTPOS, 0, 0),
            anchor: self.editor.send(SCI_GETANCHOR, 0, 0),
            top_line: self.editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0),
            x_offset: self.editor.send(SCI_GETXOFFSET, 0, 0),
        }
    }

    /// Restore the snapshotted view state on the currently-bound
    /// document. Caller must have already swapped back to the
    /// document the snapshot belongs to. Selection is restored
    /// via `SCI_SETSEL`; vertical scroll via the delta between
    /// the now-zero `firstvisibleline` and the snapshotted one;
    /// horizontal scroll via `SCI_SETXOFFSET`.
    fn restore_active_view(&self, snap: ScintillaViewState) {
        // SCI_SETSEL takes (anchor, caret) in (wparam, lparam).
        self.editor
            .send(SCI_SETSEL, snap.anchor.max(0) as usize, snap.caret);
        let cur_top = self.editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0);
        let delta = snap.top_line - cur_top;
        if delta != 0 {
            // SCI_LINESCROLL takes (column_delta, line_delta).
            self.editor.send(SCI_LINESCROLL, 0, delta);
        }
        self.editor
            .send(SCI_SETXOFFSET, snap.x_offset.max(0) as usize, 0);
    }
}

// --- Phase 4 m1 default theme -------------------------------------------
//
// Scintilla colours are `COLORREF`-encoded `0x00BBGGRR`: the low byte is
// red, middle is green, high is blue. The values below are a single
// hand-picked light-background scheme ŌĆö black on white, with greenish
// comments, blue keywords, brick-red strings, magenta numbers. Phase 4
// m2 will route the theme through a dedicated module so users can
// switch schemes; the inline approach here is the smallest thing that
// makes the demo gate ("open .cpp, see colour") visible.

// The pre-Phase-4.5 `FG_DEFAULT` / `BG_DEFAULT` constants are
// gone: STYLE_DEFAULT's fore / back are now owned by the user-
// configurable Style Configurator (via `Win32Ui::apply_default_style`
// reading `styles.xml`), not by hardcoded host values. The lexer
// theme palette below carries on as before ŌĆö those colours overlay
// the user's STYLE_DEFAULT through `LangTheme.styles` mappings.
const FG_COMMENT: u32 = 0x00_00_80_00; // green (BBGGRR)
const FG_KEYWORD: u32 = 0x00_FF_00_00; // blue
const FG_KEYWORD2: u32 = 0x00_C0_60_00; // steel blue
const FG_STRING: u32 = 0x00_22_22_99; // brick red (BBGGRR -> R=99 G=22 B=22)
const FG_NUMBER: u32 = 0x00_80_00_80; // magenta
const FG_PREPROC: u32 = 0x00_80_40_80; // purple
const FG_OPERATOR: u32 = 0x00_30_30_30; // dark grey
const FG_LIFETIME: u32 = 0x00_00_60_C0; // amber
const FG_MACRO: u32 = 0x00_80_30_80; // violet

// Line-number margin colours: a near-white strip on the left, soft
// medium-grey numerals ŌĆö high enough contrast to read at a glance
// without competing visually with the editor body. BBGGRR encoded;
// R=G=B because the colours are pure greys.
const BG_LINE_NUMBER: u32 = 0x00_E4_E4_E4; // ~RGB(228,228,228) near-white
const FG_LINE_NUMBER: u32 = 0x00_70_70_70; // ~RGB(112,112,112) medium grey

/// Foreground colour of Scintilla's indent-guide dotted lines
/// (`STYLE_INDENTGUIDE`, index 37). N++ uses `#BEBEBE`
/// (RGB(190,190,190), palindromic BBGGRR) ŌĆö a light-mid grey that
/// reads clearly on the white editor body without competing with
/// text. Must be re-applied in [`apply_default_styles`] after
/// every `SCI_STYLECLEARALL` ŌĆö same re-application discipline as
/// [`STYLE_LINENUMBER`] / [`STYLE_BRACELIGHT`] / [`STYLE_BRACEBAD`],
/// all of which live in the 32-39 predefined range Scintilla
/// resets on clear.
const FG_INDENT_GUIDE: u32 = 0x00_BE_BE_BE;

/// Visible width of a TAB character in units of one space, and
/// (via Scintilla's `SCI_SETINDENT = 0` default fall-through) the
/// effective indent-level width the indent-guide algorithm uses.
/// 4 matches the modern language convention (Rust / Python / TS
/// / JSON / YAML ŌĆö every wired lexer with a canonical style guide
/// prescribes 4 spaces). Scintilla's own default is 8, which
/// mis-draws guides on 4-space-indented code: a function body at
/// column 4 sits before the first guide column at width=8, so
/// no guide appears at level 1. **Per-document Scintilla state**
/// (mutates `pdoc->tabInChars` per `vendor/scintilla/src/
/// Editor.cxx:7011-7015`), so [`apply_tab_width`] must fire at
/// every `SCI_CREATEDOCUMENT` site ŌĆö same discipline as
/// [`enable_change_history`]. Per-language overrides (e.g.
/// Makefile ŌåÆ 8) are future work; when they land, the override
/// must repeat at every doc creation for the same reason.
const TAB_WIDTH_DEFAULT: usize = 4;

/// Background tint Scintilla paints behind the caret's line so the
/// user always sees which line is active. `0x00FAE8D6` is BGR for
/// RGB(214, 232, 250) ŌĆö a soft pale blue that's clearly distinct
/// from [`BG_DEFAULT`] (white) without compromising the contrast of
/// black foreground text.
const BG_CARET_LINE: u32 = 0x00_FA_E8_D6;

/// Margin index for line numbers. Scintilla exposes 5 margins;
/// margin 0 is the conventional line-number slot, with margin 1
/// reserved for symbols/bookmarks and margin 2 for fold markers
/// when those land in a later phase.
const LINE_NUMBER_MARGIN: u32 = 0;

/// Pixel width of [`LINE_NUMBER_MARGIN`]. Fixed rather than
/// font-metric-derived because the brief is a deliberately roomy
/// bar that fits comfortably for typical files without ever
/// needing to grow during editing. A future settings-driven view
/// toggle will flip the width between this value and `0` (Scintilla
/// hides a margin via width-zero without resetting its type or
/// styles).
const LINE_NUMBER_MARGIN_PX: i32 = 50;

/// Initialise `STYLE_DEFAULT` then reset every other style to it. This is
/// Scintilla's idiomatic "blank slate before lexer-specific styling"
/// sequence and stops the previous lexer's colours from leaking through
/// on lexer switch. Editor must already be bound to the document the
/// caller wants to style.
fn apply_default_styles(editor: &EditorHandle) {
    // Propagate the current `STYLE_DEFAULT` to every other style
    // index, then re-apply the line-number margin.
    //
    // **`STYLE_DEFAULT` is deliberately not reset here.** That state
    // is owned by `Win32Ui::apply_default_style` (the trait method
    // applying the user's `styles.xml` configuration) ŌĆö it's called
    // at startup and on every Save & Close from the Style
    // Configurator dialog. Resetting STYLE_DEFAULT here on every
    // language switch would clobber the user's font / colour
    // choices the next time `apply_lang` fired (Phase 4.5
    // framework path), which is the exact bug that bit us when this
    // function used to call `style_set_fore` / `style_set_back`.
    // `style_clear_all` copies the *current* STYLE_DEFAULT (font,
    // size, fore, back) to every other style; the per-lexer theme
    // then layers its own fore-colour overrides on top via the
    // `LangTheme.styles` table.
    editor.style_clear_all();
    // SCI_STYLECLEARALL also clobbers STYLE_LINENUMBER (and the rest
    // of the 32ŌĆō39 predefined styles), so the line-number margin's
    // colours and width ŌĆö which are font-metric-dependent ŌĆö must be
    // re-applied after every clear. Same reasoning for the brace-
    // highlight pair (STYLE_BRACELIGHT = 34, STYLE_BRACEBAD = 35)
    // and the indent-guide colour (STYLE_INDENTGUIDE = 37) ŌĆö all
    // live inside the 32-39 range `SCI_STYLECLEARALL` resets.
    apply_line_number_margin(editor);
    apply_brace_styles(editor);
    apply_indent_guide_style(editor);
}

/// Configure the line-number margin: type, width, and the
/// `STYLE_LINENUMBER` colour pair. Idempotent ŌĆö safe to call
/// repeatedly. Called both at editor creation (margin appears
/// before the first paint) and at the tail of [`apply_default_styles`]
/// (re-applies after `SCI_STYLECLEARALL` has reset
/// `STYLE_LINENUMBER` back to `STYLE_DEFAULT`).
///
/// A future "show line numbers" view toggle becomes
/// `editor.set_margin_width(LINE_NUMBER_MARGIN, if on { LINE_NUMBER_MARGIN_PX } else { 0 })`.
///
/// We use `SC_MARGIN_TEXT` (left-aligned per-line text we manage
/// ourselves) rather than `SC_MARGIN_NUMBER` (right-aligned,
/// auto-rendered by Scintilla) ŌĆö the right-aligned built-in mode
/// floats short numbers to the right edge of the bar and there's
/// no Scintilla setting to override that. Population happens at
/// document creation in `Win32Ui::activate_tab` and incrementally
/// via the `SCN_MODIFIED` handler when line count changes.
fn apply_line_number_margin(editor: &EditorHandle) {
    editor.set_margin_type(LINE_NUMBER_MARGIN, SC_MARGIN_TEXT);
    editor.style_set_fore(STYLE_LINENUMBER, FG_LINE_NUMBER);
    editor.style_set_back(STYLE_LINENUMBER, BG_LINE_NUMBER);
    editor.set_margin_width(LINE_NUMBER_MARGIN, LINE_NUMBER_MARGIN_PX);
}

/// Enable caret-line background highlighting and paint the active
/// line with [`BG_CARET_LINE`]. The visibility flag and back colour
/// are view state (not a style index), so unlike
/// [`apply_line_number_margin`] this does not need to be re-applied
/// after `SCI_STYLECLEARALL` ŌĆö one call at editor creation is
/// enough.
fn apply_caret_line_highlight(editor: &EditorHandle) {
    editor.set_caret_line_back(BG_CARET_LINE);
    editor.set_caret_line_visible(true);
}

/// Margin index for the change-history strip ŌĆö the narrow vertical
/// orange bar that flags lines edited since the last save. Skips
/// the conventionally-reserved indices (1 = symbols/bookmarks,
/// 2 = fold markers, 3 = future use) so a future plugin-installed
/// marker margin can't collide with it.
const CHANGE_HISTORY_MARGIN: u32 = 4;
/// Pixel width of [`CHANGE_HISTORY_MARGIN`] when populated. 4 px
/// is wide enough for a strip to read at every supported DPI
/// without competing with the line-number column to its left.
const CHANGE_HISTORY_MARGIN_PX: i32 = 4;
/// Marker bitmask for [`CHANGE_HISTORY_MARGIN`]. Includes only the
/// `SC_MARKNUM_HISTORY_MODIFIED` slot so a plugin marker assigned
/// to a different number can't bleed into the strip. Built as
/// `1 << SC_MARKNUM_HISTORY_MODIFIED`; the const-fn shape is
/// preferred over a raw literal so the relationship to the marker
/// number stays auditable.
const CHANGE_HISTORY_MARGIN_MASK: u32 = 1 << SC_MARKNUM_HISTORY_MODIFIED;
/// Stroke colour for the change-history strip ŌĆö same Material
/// `orange 400` shade [`TAB_ACTIVE_INDICATOR`] uses for the
/// active-tab indicator. Reusing the colour ties the two
/// "you're editing this" cues into one visual language.
const CHANGE_HISTORY_COLOR: u32 = 0x00_26_A7_FF;

/// Configure the change-history margin: type, width, mask, and the
/// `SC_MARKNUM_HISTORY_MODIFIED` marker's symbol + colour. The
/// marker symbol is `SC_MARK_FULLRECT` so it fills the full margin
/// column for any line Scintilla flags as modified. The margin
/// settings are stored on the **view** (not the document), so this
/// one call is enough ŌĆö surviving every `SCI_SETDOCPOINTER` cycle
/// the tab strip drives. Per-document change-history *enablement*
/// is a separate per-doc setting (see [`enable_change_history`]).
///
/// Critical detail: Scintilla's default mask for margin 1 is
/// `~SC_MASK_FOLDERS` ŌĆö covering markers 0-24, which *includes*
/// the history-marker family at 21-24. With
/// `SC_CHANGE_HISTORY_MARKERS` enabled, every margin whose mask
/// matches the marker bit renders it. So without explicit cleanup,
/// the history strip would also render in margin 1 at margin 1's
/// width ŌĆö visually a strip much wider than the 4-px slice we want.
/// Defensively clear margins 1-3's masks (and zero their widths in
/// case a Scintilla update bumps the default) so the strip is
/// confined to margin 4. A future bookmarks/folder-marker feature
/// claiming one of those indices will reconfigure both sides.
fn apply_change_history_margin(editor: &EditorHandle) {
    for unused in 1..=3u32 {
        editor.set_margin_mask(unused, 0);
        editor.set_margin_width(unused, 0);
    }
    // Silence the three sibling history markers we don't want to
    // visualise. Scintilla 5.x's `SC_CHANGE_HISTORY_MARKERS` flag
    // *auto-applies* every member of the family
    // (`REVERTED_TO_ORIGIN`, `SAVED`, `MODIFIED`,
    // `REVERTED_TO_MODIFIED`) to the lines they describe ŌĆö and
    // each marker carries Scintilla's default symbol/colour until
    // overridden. In particular `SC_MARKNUM_HISTORY_SAVED` paints
    // a green line-background under every line that was modified
    // before the last save (i.e. essentially every line of the
    // file at first display, since the SCI_SETSAVEPOINT after
    // load reclassifies all inserted lines as "saved"). Setting
    // those three to `SC_MARK_EMPTY` makes them no-op visually
    // while preserving Scintilla's internal tracking, so a future
    // feature can light them up without re-enabling the history
    // engine.
    use codepp_scintilla_sys::{
        SC_MARKNUM_HISTORY_REVERTED_TO_MODIFIED, SC_MARKNUM_HISTORY_REVERTED_TO_ORIGIN,
        SC_MARKNUM_HISTORY_SAVED,
    };
    for silenced in [
        SC_MARKNUM_HISTORY_REVERTED_TO_ORIGIN,
        SC_MARKNUM_HISTORY_SAVED,
        SC_MARKNUM_HISTORY_REVERTED_TO_MODIFIED,
    ] {
        editor.marker_define(silenced, SC_MARK_EMPTY);
    }
    editor.set_margin_type(CHANGE_HISTORY_MARGIN, SC_MARGIN_SYMBOL);
    editor.set_margin_mask(CHANGE_HISTORY_MARGIN, CHANGE_HISTORY_MARGIN_MASK);
    editor.marker_define(SC_MARKNUM_HISTORY_MODIFIED, SC_MARK_FULLRECT);
    editor.marker_set_back(SC_MARKNUM_HISTORY_MODIFIED, CHANGE_HISTORY_COLOR);
    editor.set_margin_width(CHANGE_HISTORY_MARGIN, CHANGE_HISTORY_MARGIN_PX);
}

/// Enable Scintilla's change-history tracking on the **currently
/// bound** document. Per-document setting ŌĆö every fresh document
/// minted via `SCI_CREATEDOCUMENT` starts with history disabled,
/// so this must be called on each new doc immediately after
/// binding it via `SCI_SETDOCPOINTER`. Margin configuration lives
/// on the view ([`apply_change_history_margin`]); only the
/// per-doc enablement is repeated here.
fn enable_change_history(editor: &EditorHandle) {
    editor.set_change_history(SC_CHANGE_HISTORY_ENABLED | SC_CHANGE_HISTORY_MARKERS);
}

// --- Brace-match highlight colours ----------------------------------
//
// N++ defaults from `PowerEditor/src/stylers.model.xml` "Brace
// highlight" (fg=FF0000 bold) and "Bad brace colour" (fg=800000).
// Scintilla wants COLORREF (0x00BBGGRR), so N++'s RGB #FF0000 red
// becomes 0x0000FF here and #800000 dark red becomes 0x000080.
const FG_BRACE_LIGHT: u32 = 0x00_00_00_FF;
const FG_BRACE_BAD: u32 = 0x00_00_00_80;
const BG_BRACE_LIGHT: u32 = 0x00_FF_FF_FF;

// --- Fold margin colours + geometry ---------------------------------
//
// N++'s "Fold" and "Fold margin" entries in stylers.model.xml (verified
// against ScintillaEditView.cpp:3236-3245 and :4624-4640) apply the
// XML `bgColor` to the marker foreground and `fgColor` to the marker
// background ŌĆö a deliberate swap. The effective palette:
//   - marker outline (fore): #F3F3F3 light grey
//   - marker fill (back):    #808080 mid grey
//   - marker active (hover): #FF0000 red (matches STYLE_BRACELIGHT)
//   - margin strip base:     #E9E9E9 near-white
//   - margin strip hover:    #FFFFFF pure white
// Encoded here as COLORREF (BBGGRR). Greys and white are palindromic.
const FOLD_MARKER_FG: u32 = 0x00_F3_F3_F3;
const FOLD_MARKER_BG: u32 = 0x00_80_80_80;
const FOLD_MARKER_ACTIVE: u32 = 0x00_00_00_FF;
const FOLD_MARGIN_BG: u32 = 0x00_E9_E9_E9;
const FOLD_MARGIN_HI: u32 = 0x00_FF_FF_FF;

/// Margin index for the fold column. Sits between the line-number
/// margin (index 0) and the change-history strip (index 4). N++
/// uses index 3, but Code++'s layout puts change-history at 4, not
/// between bookmark and fold ŌĆö so fold lands at index 2.
const FOLD_MARGIN: u32 = 2;
/// Pixel width of [`FOLD_MARGIN`]. 14 px matches N++'s default.
const FOLD_MARGIN_PX: i32 = 14;

/// Configure the two reserved brace-highlight styles (34, 35) with
/// N++'s red / dark-red palette. Idempotent ŌĆö safe to call after
/// any `SCI_STYLECLEARALL`. Called at three sites (editor creation
/// in [`Win32Ui::run`], the tail of [`apply_default_styles`], and
/// the tail of [`Win32Ui::apply_default_style`]) because
/// `STYLE_BRACELIGHT` / `STYLE_BRACEBAD` are in the 32-39 predefined
/// range that `SCI_STYLECLEARALL` resets to `STYLE_DEFAULT` ŌĆö same
/// re-application pattern as `STYLE_LINENUMBER`.
fn apply_brace_styles(editor: &EditorHandle) {
    editor.style_set_fore(STYLE_BRACELIGHT, FG_BRACE_LIGHT);
    editor.style_set_back(STYLE_BRACELIGHT, BG_BRACE_LIGHT);
    editor.style_set_bold(STYLE_BRACELIGHT, true);
    editor.style_set_fore(STYLE_BRACEBAD, FG_BRACE_BAD);
    editor.style_set_back(STYLE_BRACEBAD, BG_BRACE_LIGHT);
    editor.style_set_bold(STYLE_BRACEBAD, false);
}

/// Configure the `STYLE_INDENTGUIDE` (37) foreground colour for
/// Scintilla's vertical dotted indent guides. Idempotent ŌĆö safe
/// to call after any `SCI_STYLECLEARALL`. Same re-application
/// pattern as [`apply_line_number_margin`] and
/// [`apply_brace_styles`]: `STYLE_INDENTGUIDE` sits in the 32-39
/// predefined range that `SCI_STYLECLEARALL` resets to
/// `STYLE_DEFAULT`, so without re-application the guides would
/// take whatever the current per-language `STYLE_DEFAULT`
/// foreground is (often matching the text colour, which reads
/// as invisible-or-wrong depending on the theme). Called at
/// editor creation in [`Win32Ui::run`] AND from the tail of
/// [`apply_default_styles`] so every per-language re-style
/// preserves the guide's grey. The `SCI_SETINDENTATIONGUIDES`
/// mode itself is view state (not a style-index), so it doesn't
/// need re-application here ŌĆö its toggle is handled entirely by
/// the toolbar's `ID_VIEW_SHOW_INDENT_GUIDE` handler.
fn apply_indent_guide_style(editor: &EditorHandle) {
    editor.style_set_fore(STYLE_INDENTGUIDE, FG_INDENT_GUIDE);
}

/// Map [`Eol`] to Scintilla's `SC_EOL_*` code and issue
/// `SCI_SETEOLMODE` on the currently-bound document. Sets the
/// byte sequence Scintilla inserts when the user presses Enter
/// (and the target sequence for a subsequent `SCI_CONVERTEOLS`).
///
/// **Per-document Scintilla state.** `SCI_SETEOLMODE` mutates
/// `pdoc->eolMode`, so every fresh document minted via
/// `SCI_CREATEDOCUMENT` starts at Scintilla's built-in default
/// (CRLF on Windows) regardless of the loaded file's actual EOL.
/// Called from [`Win32Ui::update_status`] on every tab switch
/// (which already receives the tab's authoritative `eol` from
/// the Shell layer), plus once at editor construction in
/// [`Win32Ui::run`] with [`Eol::default`] for the initial
/// implicit document.
///
/// **`Eol::Mixed` maps to LF.** Scintilla has no "mixed" mode ŌĆö
/// the enum is a Code++-level bookkeeping construct for
/// "preserve each line's original ending on re-write." When the
/// user presses Enter in a Mixed buffer, LF is the least
/// surprising choice and matches [`Eol::bytes`]'s own Mixed
/// fall-through convention.
///
/// Without this call, Scintilla's built-in default of CRLF on
/// Windows applies universally ŌĆö pressing Enter in a pure-LF
/// file silently starts injecting CRLF-terminated lines into an
/// otherwise LF file, breaking the EOL-preservation contract
/// documented in DESIGN.md ┬¦5.2.
fn apply_eol_mode(editor: &EditorHandle, eol: Eol) {
    let sc_eol = match eol {
        Eol::CrLf => SC_EOL_CRLF,
        Eol::Cr => SC_EOL_CR,
        // Mixed collapses to LF, matching `Eol::bytes()`'s own
        // convention for "preserve on re-write, but if we must
        // pick one here, use LF."
        Eol::Lf | Eol::Mixed => SC_EOL_LF,
    };
    editor.send(SCI_SETEOLMODE, sc_eol, 0);
}

/// Set the visible TAB-character width to [`TAB_WIDTH_DEFAULT`]
/// (4 columns) on the currently-bound document. Also implicitly
/// sets the effective indent-level width the indent-guide
/// algorithm uses, because Scintilla's per-document
/// `SCI_SETINDENT` defaults to 0 (which means "use tab width").
///
/// **Per-document Scintilla state.** `SCI_SETTABWIDTH` mutates
/// `pdoc->tabInChars` on the currently-bound document
/// (`vendor/scintilla/src/Editor.cxx:7011-7015`) and does NOT
/// survive `SCI_SETDOCPOINTER` onto a different document.
/// Every fresh document minted via `SCI_CREATEDOCUMENT` starts
/// with Scintilla's built-in `tabInChars = 8`, so this must be
/// called immediately after each such creation ŌĆö same
/// discipline as [`enable_change_history`]. Currently called at
/// four sites: editor creation in [`Win32Ui::run`], and each of
/// the three real-doc `SCI_CREATEDOCUMENT` sites in
/// [`Win32Ui::activate_tab`], the post-close-tab lazy-materialise
/// path, and the `handle_tab_selchange` lazy-populate path. The
/// short-lived placeholder doc in the tab-close path
/// deliberately skips this call ŌĆö the doc is bound for one
/// paint cycle and immediately released, and no indent-guide
/// paint on a blank buffer would be observable.
///
/// Without this call, Scintilla defaults to 8 and the
/// indent-guide algorithm draws guides at multiples of 8 ŌĆö
/// which mis-aligns entirely with the 4-space convention used
/// by every Lexilla-linked lexer with a canonical style guide
/// (Rust / Python / TS / JSON / YAML): a function body at
/// column 4 sits *before* the first guide column (8), so no
/// guide appears at indent level 1, only at level 2. Per-
/// language overrides (e.g. Makefile ŌåÆ 8) are future work; when
/// they land, the same per-doc-repeat discipline applies.
fn apply_tab_width(editor: &EditorHandle) {
    editor.send(SCI_SETTABWIDTH, TAB_WIDTH_DEFAULT, 0);
}

/// Configure the fold margin's view state: allocate margin 2 as a
/// `SC_MASK_FOLDERS` symbol margin, define the BOXPLUS/BOXMINUS
/// shape family with CONNECTED variants for mid-region markers
/// (N++'s default "Box" style), set marker + margin-strip colours,
/// enable selected-marker highlighting, install the "draw
/// horizontal line below collapsed region" flag, and delegate
/// click / marker visibility / auto-expand-on-edit to Scintilla
/// via `SCI_SETAUTOMATICFOLD`.
///
/// **Must be called AFTER [`apply_change_history_margin`]** ŌĆö that
/// function's defensive `set_margin_mask(1..=3, 0)` loop would
/// otherwise wipe [`FOLD_MARGIN`]'s mask right back to zero. The
/// call order at editor creation is
/// [`apply_change_history_margin`] ŌåÆ [`enable_change_history`] ŌåÆ
/// [`apply_fold_margin`].
///
/// The `fold` property itself is NOT set here ŌĆö it lives on the
/// attached lexer instance (which doesn't exist yet at editor
/// creation) and, critically, does not carry across
/// `SCI_SETILEXER`: every fresh `CreateLexer` call in
/// [`Win32Ui::apply_lang`] mints a new instance whose
/// `options.fold` starts `false`. `LexState::PropSet` at
/// `ScintillaBase.cxx:687-694` is `if (instance) { ŌĆ” }` ŌĆö a
/// silent no-op with no lexer bound. See
/// [`Win32Ui::apply_lang`] where the universal `fold` /
/// `fold.compact` / `fold.comment` trio is (re-)issued on every
/// language switch alongside the per-lexer extras.
fn apply_fold_margin(editor: &EditorHandle) {
    editor.set_margin_type(FOLD_MARGIN, SC_MARGIN_SYMBOL);
    editor.set_margin_mask(FOLD_MARGIN, SC_MASK_FOLDERS);
    editor.set_margin_sensitive(FOLD_MARGIN, true);
    editor.set_margin_width(FOLD_MARGIN, FOLD_MARGIN_PX);

    // Marker shapes ŌĆö N++ default "Box" style, verified against
    // ScintillaEditView.cpp:4624-4640. The CONNECTED variants for
    // FOLDEREND / FOLDEROPENMID render the vertical continuation
    // line through the +/- glyph when nested inside a parent fold.
    for (marker, shape) in [
        (SC_MARKNUM_FOLDEROPEN, SC_MARK_BOXMINUS),
        (SC_MARKNUM_FOLDER, SC_MARK_BOXPLUS),
        (SC_MARKNUM_FOLDERSUB, SC_MARK_VLINE),
        (SC_MARKNUM_FOLDERTAIL, SC_MARK_LCORNER),
        (SC_MARKNUM_FOLDEREND, SC_MARK_BOXPLUSCONNECTED),
        (SC_MARKNUM_FOLDEROPENMID, SC_MARK_BOXMINUSCONNECTED),
        (SC_MARKNUM_FOLDERMIDTAIL, SC_MARK_TCORNER),
    ] {
        editor.marker_define(marker, shape);
        editor.marker_set_fore(marker, FOLD_MARKER_FG);
        editor.marker_set_back(marker, FOLD_MARKER_BG);
        editor.marker_set_back_selected(marker, FOLD_MARKER_ACTIVE);
    }
    editor.marker_enable_highlight(true);

    editor.set_fold_margin_colour(true, FOLD_MARGIN_BG);
    editor.set_fold_margin_hi_colour(true, FOLD_MARGIN_HI);

    // 0x10 = SC_FOLDFLAG_LINEAFTER_CONTRACTED ŌĆö draws the horizontal
    // rule below a collapsed region so the user always sees a
    // "you-collapsed-a-region-here" cue.
    editor.set_fold_flags(SC_FOLDFLAG_LINEAFTER_CONTRACTED);

    // Vanilla click-to-toggle + marker visibility + auto-expand on
    // edit. Shift/Ctrl-click extensions (fold-all-children) would
    // require a manual SCN_MARGINCLICK handler; deferred.
    editor.set_automatic_fold(
        SC_AUTOMATICFOLD_SHOW | SC_AUTOMATICFOLD_CLICK | SC_AUTOMATICFOLD_CHANGE,
    );
}

/// Return `true` if `c` is one of the six ASCII bracket characters
/// that Scintilla's `SCI_BRACEMATCH` recognises: `()`, `[]`, `{}`,
/// `<>`. N++ matches without filtering by lexer (spurious `<>`
/// matches in non-HTML buffers are the exact N++ behaviour).
#[inline]
const fn is_brace(c: u8) -> bool {
    matches!(c, b'(' | b')' | b'[' | b']' | b'{' | b'}' | b'<' | b'>')
}

/// Dispatch brace-match highlight on the current caret position.
/// Called from the `SCN_UPDATEUI` handler on every selection or
/// content change. Total cost per call: 3-6 direct-call round-trips
/// (get pos, 2├Ś get char, 0-1 `brace_match`, 1 highlight, 1 `bad_light`)
/// ŌĆö sub-┬Ąs on the direct-call path, well inside the 5 ms p99
/// keystroke budget.
fn update_brace_highlight(editor: &EditorHandle) {
    let pos = editor.current_pos() as i64;
    let ch_before = if pos > 0 {
        editor.char_at((pos - 1) as u64)
    } else {
        0
    };
    let ch_at = editor.char_at(pos as u64);

    let brace_pos: i64 = if is_brace(ch_before) {
        pos - 1
    } else if is_brace(ch_at) {
        pos
    } else {
        -1
    };

    // SCI_BRACEHIGHLIGHT and SCI_BRACEBADLIGHT both write into Scintilla's
    // single shared `braces[2]` + `bracesMatchStyle` slot (Editor.cxx:8237,
    // 8248 ŌåÆ SetBraceHighlight at :5407-5423). If we call the "bad" clear
    // AFTER the "good" set, we wipe the state we just wrote and PaintText
    // never overwrites the brace's style byte to STYLE_BRACELIGHT
    // (PositionCache.cxx:219 gate `rangeLine.ContainsCharacter(braces[i])`
    // is false because braces[] is now [-1, -1]). Order: clear the opposite
    // state FIRST, then set the desired one.
    if brace_pos >= 0 {
        let match_pos = editor.brace_match(brace_pos as u64);
        if match_pos >= 0 {
            editor.brace_bad_light(-1);
            editor.brace_highlight(brace_pos, match_pos);
        } else {
            editor.brace_highlight(-1, -1);
            editor.brace_bad_light(brace_pos);
        }
    } else {
        editor.brace_bad_light(-1);
        editor.brace_highlight(-1, -1);
    }
}

/// Number of lines beyond the visible window's bottom edge to
/// pre-populate. A small overscan covers the gap between
/// `SCI_LINESONSCREEN`'s integer-truncated row count and a partial
/// line clipped by the viewport, plus one row of margin so a small
/// scroll doesn't reveal a blank line before the next
/// `SCN_UPDATEUI` lands.
const LINE_NUMBER_OVERSCAN: u64 = 4;

/// Number of decimal digits needed to render `line_count` (so a
/// 100-line buffer wants width `3`, a 99-line buffer wants `2`).
/// The width drives the right-alignment column for every visible
/// line number ŌĆö when the file grows across a 9ŌåÆ10 / 99ŌåÆ100 /
/// etc. boundary, every visible row's text shifts one column
/// right in lockstep, so 3-digit "100" lines up over the 2-digit
/// "99" with their last digits in the same column.
fn line_number_width(line_count: u64) -> usize {
    let mut digits: usize = 1;
    let mut n = line_count.max(1);
    while n >= 10 {
        digits += 1;
        n /= 10;
    }
    digits
}

/// Write per-line line-number text for lines `[start, end)` into
/// the `LINE_NUMBER_MARGIN` of the currently-bound document, styled
/// as `STYLE_LINENUMBER`. Format is `" {N+1:>width$}"` ŌĆö a fixed
/// 1-char left pad followed by the line number right-aligned in a
/// `width`-char column, so the rightmost digit of every line falls
/// on the same column. `width` is supplied by the caller (always
/// from [`line_number_width`] of the current document line count)
/// rather than computed per-line so the value is stable across the
/// whole batch.
fn populate_line_numbers_range(editor: &EditorHandle, start: u64, end: u64, width: usize) {
    if start >= end {
        return;
    }
    // Per-call scratch buffer: leading space + right-aligned
    // digits + NUL. `u64` tops out at 20 digits; `" "` + 20 + `\0`
    // = 22 bytes. 32 covers it without a heap alloc.
    let mut buf = [0u8; 32];
    for line in start..end {
        use std::io::Write;
        // `cursor` is re-bound on each iteration, so `write!`
        // always begins at `buf[0]` ŌĆö `Write for &mut [u8]`
        // advances `cursor` (the slice header) but never `buf`
        // itself, so `buf.as_ptr()` keeps pointing at the bytes
        // we just wrote. Trailing bytes from the previous
        // iteration are harmless: Scintilla reads up to the NUL
        // we wrote and stops.
        let mut cursor = &mut buf[..];
        // " " + {N+1, right-aligned to `width`} + "\0". Line
        // indices are 0-based in Scintilla, 1-based for the user.
        write!(cursor, " {:>width$}\0", line + 1, width = width)
            .expect("32-byte scratch buffer exhausted formatting line number");
        // `line as usize` is sound on every supported target:
        // Scintilla's 2 GiB buffer ceiling caps line count at ~2
        // billion (one byte per line) on 32-bit and 64-bit alike,
        // well within `u32::MAX` and therefore `usize::MAX`.
        editor.send(SCI_MARGINSETTEXT, line as usize, buf.as_ptr() as isize);
        editor.send(SCI_MARGINSETSTYLE, line as usize, STYLE_LINENUMBER as isize);
    }
}

/// Populate line-number text for the lines currently visible in
/// the viewport (plus a small overscan). Cheap and bounded ŌĆö
/// scales with viewport height, not file size, so a 100k-line
/// file load doesn't stall the UI thread.
///
/// Width is derived from the *total* document line count, not just
/// the visible range. This way the rightmost digit always falls in
/// the same column for every line in the document ŌĆö when the file
/// grows past a boundary (e.g. 99 ŌåÆ 100) the next call here shifts
/// every visible line one column right uniformly, instead of
/// leaving the visible window with a mix of widths.
///
/// Off-screen lines stay with whatever margin text they last had
/// (typically empty for newly-created lines, or numbers laid out
/// at a stale width from before the latest line-count change).
/// Either is invisible to the user; the `SCN_UPDATEUI` vertical-
/// scroll hook re-populates the new visible window with the
/// current width just before those lines enter the viewport.
///
/// Margin text is per-document state in Scintilla, so this is the
/// right level of write ŌĆö it survives `SCI_SETDOCPOINTER` cycles
/// and only needs re-running when content changes or the visible
/// range shifts.
/// Populate every line in the document with its margin number.
/// Bounded by document line count, not viewport ŌĆö used after a
/// bulk content replace (`SCI_SETTEXT` in `set_buffer_text`)
/// when the visible-only populate would miss off-screen lines.
///
/// Cost: ~2 direct-call invocations per line. For typical
/// untitled buffers (a few hundred lines) this is sub-millisecond;
/// for a 100k-line file it's around 100 ms ŌĆö acceptable on a
/// once-per-load operation. The lazy `SCN_UPDATEUI`-driven path
/// is still the right choice for incremental edits.
///
/// Used specifically because session-restore calls
/// `set_buffer_text` *before* the window has been laid out, so
/// `SCI_LINESONSCREEN` returns 0 / 1 and the visible-only
/// populate covers only the first few lines ŌĆö leaving the rest
/// blank (or worse, with stale margin text from the previous
/// doc state, e.g. line 0's "1" from `activate_tab`'s populate
/// of the empty starter doc).
fn populate_all_line_numbers(editor: &EditorHandle) {
    let total = editor.send(SCI_GETLINECOUNT, 0, 0).max(1) as u64;
    let width = line_number_width(total);
    populate_line_numbers_range(editor, 0, total, width);
}

fn populate_visible_line_numbers(editor: &EditorHandle) {
    // Scintilla guarantees `SCI_GETLINECOUNT >= 1` for any document
    // (an empty document still has line 0); clamp to 1 so the
    // formatting code downstream ŌĆö and `line_number_width` ŌĆö
    // always sees a sensible floor instead of relying on the
    // invariant implicitly.
    let total = editor.send(SCI_GETLINECOUNT, 0, 0).max(1) as u64;
    let first = editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0).max(0) as u64;
    let on_screen = editor.send(SCI_LINESONSCREEN, 0, 0).max(0) as u64;
    let last = first
        .saturating_add(on_screen)
        .saturating_add(LINE_NUMBER_OVERSCAN)
        .min(total);
    let width = line_number_width(total);
    populate_line_numbers_range(editor, first.min(total), last, width);
}

/// Bring the caret line into view: if it's already in the visible
/// region just leave the viewport alone (Notepad++ style ŌĆö quiet
/// on small jumps), otherwise scroll so the caret line lands at
/// the centre of the viewport. Used after Find Next / Find
/// Previous so the user sees the new selection without the view
/// snapping to the bottom edge.
///
/// Note: line numbers here are document lines, which equal visual
/// lines while we're not running with folding or word wrap on.
/// If those land later, swap to `SCI_VISIBLEFROMDOCLINE` for the
/// match-line conversion.
fn center_caret_if_offscreen(editor: &EditorHandle) {
    center_caret_impl(editor, false);
}

/// Unconditionally center the caret line in the viewport.
///
/// Use this after Scintilla messages that auto-scroll (`SCI_SETSEL`,
/// `SCI_SETSELECTIONSTART/END`, `SCI_GOTOPOS`), where
/// [`center_caret_if_offscreen`] would short-circuit because the
/// preceding command already pulled the line on-screen at the
/// nearest edge. Find Next uses `SCI_SEARCHNEXT` which doesn't
/// scroll, so its centring helper can rely on the offscreen check;
/// the FIF "open at result" jump uses `SCI_SETSEL` and needs the
/// re-scroll to land the match in the middle of the editor ŌĆö even
/// more important when the bottom dock is showing and the editor's
/// usable height is reduced.
fn center_caret(editor: &EditorHandle) {
    center_caret_impl(editor, true);
}

/// Shared centring math. With `force = false` we early-return if
/// the caret line is already on-screen (Find Next behaviour: don't
/// jump the viewport on every successful match); with `force = true`
/// we always re-scroll (FIF dblclk behaviour: `SCI_SETSEL` has just
/// pulled the line edge-visible, so "already on-screen" means "at
/// the bottom edge under the dock" ŌĆö which is what we're trying to
/// avoid).
fn center_caret_impl(editor: &EditorHandle, force: bool) {
    let pos = editor.send(SCI_GETCURRENTPOS, 0, 0).max(0) as usize;
    let line = editor.send(SCI_LINEFROMPOSITION, pos, 0).max(0);
    let first = editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0).max(0);
    let lines = editor.send(SCI_LINESONSCREEN, 0, 0).max(1);
    if !force && line >= first && line < first + lines {
        return;
    }
    let target_first = (line - lines / 2).max(0);
    let delta = target_first - first;
    if delta != 0 {
        editor.send(SCI_LINESCROLL, 0, delta);
    }
}

// ---------------------------------------------------------------------------
// Phase 4.5 ŌĆö table-driven language theme framework
//
// Adding a language is mechanical:
//   1. Confirm the lexer's `SCE_*_*` style constants are declared
//      in `crates/scintilla-sys/src/lib.rs`. The Phase 4.5 starter
//      set (Python, JSON, Bash, Lua, SQL, YAML, TOML, CSS) is
//      already there; new lexers append a batch.
//   2. Add a `<LANG>_KEYWORDS` const for the language's primary
//      keyword list (and additional `_KEYWORDS2`, `_KEYWORDS3`
//      consts if the lexer uses more than one keyword class).
//      Keep these in `core::lang` so any future tool (test
//      harnesses, lang inspector plugins) can reuse them.
//   3. Build a `<LANG>_STYLES: &[(usize, StyleSlot)]` table
//      mapping each style index the lexer emits onto a palette
//      slot.
//   4. Build `<LANG>_ITALIC` / `<LANG>_BOLD` lists for the style
//      indices that want those font modifiers (typically
//      comments ŌåÆ italic, primary keywords ŌåÆ bold).
//   5. Build a `<LANG>_THEME: LangTheme` const wiring all of the
//      above together.
//   6. Add an `else if lang == L_<LANG> { Some(&<LANG>_THEME) }`
//      branch to `lang_theme()`. The dispatch is an `if/else if`
//      chain (not a `match`) because `LangType`'s const-pattern
//      story is fiddly across compiler versions; the chain is
//      explicit and bulletproof.
//   7. Update the corresponding row in `docs/lexers-coverage.md`
//      from ­¤¤Ī to Ō£ģ.
//
// See DESIGN.md ┬¦7.2 Phase 4.5 for the binding completion gate.
// ---------------------------------------------------------------------------

/// One slot in the shared per-language palette. Each variant maps
/// to a single `0x00BBGGRR` colour via [`slot_color`]; the colour
/// constants themselves live above this block alongside the rest
/// of the theme palette so a future redesign of the editor's
/// visual scheme is a single coordinated edit.
///
/// Slots are deliberately coarser than the full Scintilla style
/// vocabulary ŌĆö Lexilla emits 10ŌĆō25 SCE_* indices per lexer, but
/// only a handful of *visual* categories matter for readable
/// highlighting. Two lexers' "comment" indices both map to
/// [`StyleSlot::Comment`] and pick up the same green; that's the
/// design.
///
/// New slots are added here as new languages need them. Don't
/// invent a new slot per language; reuse what fits semantically
/// (e.g. a regex literal in Perl is still a [`StyleSlot::String`];
/// HTML's tag names are [`StyleSlot::Keyword`]).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum StyleSlot {
    /// Block / line / doc comments. Rendered italic green.
    Comment,
    /// Primary keyword class (the language's reserved words).
    /// Rendered bold blue.
    Keyword,
    /// Secondary keyword class ŌĆö typically types (`int`,
    /// `String`), built-in constants (`true`, `nil`), or stdlib
    /// identifiers. Rendered steel-blue.
    Keyword2,
    /// String and character literals.
    String,
    /// Numeric literals.
    Number,
    /// Preprocessor directives (`#include`, `#define`) ŌĆö also
    /// reused for HTML / XML doctype, processing instructions, and
    /// HTML entities (`&amp;` / `&#160;`): all categories the user's
    /// eye reads as "out-of-band syntax marker" rather than content,
    /// which is the slot's visual meaning.
    Preprocessor,
    /// Operators (`+`, `==`, `->`, ŌĆ”).
    Operator,
    /// Rust lifetimes (`'a`). Distinct slot because no other
    /// language has this exact concept; reuse for similar
    /// "scoped binding" highlights if applicable.
    Lifetime,
    /// Rust macros (`println!`). Distinct slot for the same
    /// reason as [`StyleSlot::Lifetime`].
    Macro,
}

/// Resolve a [`StyleSlot`] to its `0x00BBGGRR` colour. The
/// individual `FG_*` constants are defined above with the rest
/// of the editor's visual palette so a coordinated theme change
/// is a single edit. Marked `const` so a future palette refactor
/// to compile-time table lookup is mechanical.
const fn slot_color(slot: StyleSlot) -> u32 {
    match slot {
        StyleSlot::Comment => FG_COMMENT,
        StyleSlot::Keyword => FG_KEYWORD,
        StyleSlot::Keyword2 => FG_KEYWORD2,
        StyleSlot::String => FG_STRING,
        StyleSlot::Number => FG_NUMBER,
        StyleSlot::Preprocessor => FG_PREPROC,
        StyleSlot::Operator => FG_OPERATOR,
        StyleSlot::Lifetime => FG_LIFETIME,
        StyleSlot::Macro => FG_MACRO,
    }
}

/// One row of the per-language theme table. Carries everything
/// the host needs to install for a given language's editor
/// configuration: keyword classes (each (`class_index`, words))
/// and style mappings (each (SCE_*_INDEX, palette slot)) plus
/// font-modifier lists.
struct LangTheme {
    /// Keyword classes to install via `SCI_SETKEYWORDS`. Each
    /// tuple is `(class_index, words)`; most lexers use just
    /// class 0, some (Lua, SQL, HTML) use multiple classes. An
    /// empty list is legal ŌĆö the lexer still tokenises by
    /// syntax, just without keyword discrimination.
    keywords: &'static [(u32, &'static str)],
    /// Per-style foreground colour assignments. Each tuple is
    /// `(SCE_*_INDEX, slot)`. Applied after `apply_default_styles`
    /// resets every style to `STYLE_DEFAULT`.
    styles: &'static [(usize, StyleSlot)],
    /// Style indices to render in italic (typically comments).
    italic: &'static [usize],
    /// Style indices to render in bold (typically the primary
    /// keyword class).
    bold: &'static [usize],
}

// --- LexCPP family ---
// `LexCPP` covers C, C++, C#, Java, JavaScript, TypeScript,
// Objective-C, Swift, Go, Resource file. The style indices are
// identical (LexCPP emits the same SCE_C_* enum regardless of
// the language family member); only the keyword list differs.
// CPP_STYLES / CPP_ITALIC / CPP_BOLD are shared across every
// future LexCPP-family theme row.

const CPP_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_C_COMMENT, StyleSlot::Comment),
    (SCE_C_COMMENTLINE, StyleSlot::Comment),
    (SCE_C_COMMENTDOC, StyleSlot::Comment),
    (SCE_C_COMMENTLINEDOC, StyleSlot::Comment),
    (SCE_C_WORD, StyleSlot::Keyword),
    (SCE_C_WORD2, StyleSlot::Keyword2),
    (SCE_C_STRING, StyleSlot::String),
    (SCE_C_CHARACTER, StyleSlot::String),
    (SCE_C_NUMBER, StyleSlot::Number),
    (SCE_C_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_C_OPERATOR, StyleSlot::Operator),
];
// Doc-comment styles (`SCE_C_COMMENTDOC`, `SCE_C_COMMENTLINEDOC`)
// are deliberately *not* italicised ŌĆö preserves the pre-refactor
// behaviour where only plain `/* */` and `//` were italic. A
// future visual rebalancing pass could italicise doc comments
// too, but it should be a coordinated decision across Rust as
// well (where the omission mirrors).
const CPP_ITALIC: &[usize] = &[SCE_C_COMMENT, SCE_C_COMMENTLINE];
const CPP_BOLD: &[usize] = &[SCE_C_WORD];

/// Convert `(r, g, b)` (display order) to a Win32 `COLORREF`
/// (`0x00BBGGRR`). The same packing Scintilla expects for its
/// style colour messages.
fn rgb_to_colorref((r, g, b): (u8, u8, u8)) -> u32 {
    (u32::from(b) << 16) | (u32::from(g) << 8) | u32::from(r)
}

/// Apply the user's transparency settings to the main window.
///
/// Enabling transparency:
///   - Adds `WS_EX_LAYERED` to the window's extended style
///     (required for `SetLayeredWindowAttributes`).
///   - Converts opacity-percent (20..=100) to an 8-bit alpha
///     value: `255 * percent / 100`.
///   - Issues `SetLayeredWindowAttributes(..., alpha, LWA_ALPHA)`.
///
/// Disabling transparency:
///   - Strips `WS_EX_LAYERED` so the window stops paying the
///     compositing cost. A no-op when the bit wasn't set (e.g.
///     first call at startup with `enabled=false`).
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn apply_window_transparency(hwnd: HWND, t: &codepp_core::styles::Transparency) {
    // Keep the extended-style word in `isize` throughout to
    // avoid a u32 narrowing of `GetWindowLongPtrW`'s 64-bit
    // return value on 64-bit Windows. Win32 currently fits
    // every extended style bit into the low 32 bits, but the
    // signature is `isize` and the rest of this codebase (e.g.
    // the Scintilla border-style toggle around line 1694)
    // already follows the keep-it-signed pattern.
    let cur_ex = unsafe { GetWindowLongPtrW(hwnd, GWL_EXSTYLE) };
    let layered = WS_EX_LAYERED.0 as isize;
    if t.enabled {
        let want_ex = cur_ex | layered;
        if want_ex != cur_ex {
            unsafe {
                SetWindowLongPtrW(hwnd, GWL_EXSTYLE, want_ex);
            }
        }
        // Clamp percent into the documented 20..=100 range. The
        // dialog's slider enforces the same bounds, but a
        // hand-edited styles.xml could carry anything; treating
        // out-of-range values as "snap to the nearest endpoint"
        // is the safest graceful-degradation choice (the
        // alternative for values below 20 would be the editor
        // becoming barely-visible or invisible). The trace below
        // makes the snap observable so a debugger / log reader
        // can tell that the on-disk value didn't survive verbatim.
        if !(20..=100).contains(&t.percent) {
            tracing::warn!(
                percent = t.percent,
                "transparency percent outside 20..=100; clamping"
            );
        }
        let percent = u32::from(t.percent.clamp(20, 100));
        let alpha = ((255u32 * percent) / 100) as u8;
        let _ = unsafe { SetLayeredWindowAttributes(hwnd, COLORREF(0), alpha, LWA_ALPHA) };
    } else {
        let want_ex = cur_ex & !layered;
        if want_ex != cur_ex {
            unsafe {
                SetWindowLongPtrW(hwnd, GWL_EXSTYLE, want_ex);
            }
        }
    }
}

// LexCPP-family themes install **two** keyword classes:
//   - class 0 (`SCE_C_WORD`)  ŌåÆ `StyleSlot::Keyword`  (blue)
//   - class 1 (`SCE_C_WORD2`) ŌåÆ `StyleSlot::Keyword2` (steel blue)
//
// Primitive types live in class 1 so they render distinctly from
// control-flow / modifier keywords ŌĆö matches Notepad++'s default
// blue-vs-steel-blue C / C++ / C# rendering. The `CPP_STYLES` table
// at the top of this section already maps `SCE_C_WORD2` to
// `StyleSlot::Keyword2`; adding the second `(class_index, list)`
// tuple here is what makes the colour actually fire.
//
// Java / JS / TS / Go / Obj-C / Swift follow the same two-class
// shape when wired (one keyword list const, one type list const, one
// `else if` arm). RC (Windows resource scripts) likely stays single-
// class ŌĆö the lexer's `SCE_C_WORD2` colour is only meaningful for
// languages with a distinct primitive-type vocabulary, which `.rc`
// resource statements don't have in any conventional sense.
const C_THEME: LangTheme = LangTheme {
    keywords: &[(0, C_KEYWORDS), (1, C_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
const CPP_THEME: LangTheme = LangTheme {
    keywords: &[(0, CPP_KEYWORDS), (1, CPP_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
const CS_THEME: LangTheme = LangTheme {
    keywords: &[(0, CS_KEYWORDS), (1, CS_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
const OBJC_THEME: LangTheme = LangTheme {
    keywords: &[(0, OBJC_KEYWORDS), (1, OBJC_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
const JAVA_THEME: LangTheme = LangTheme {
    keywords: &[(0, JAVA_KEYWORDS), (1, JAVA_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
// JavaScript rides `LexCPP` (per `L_JAVASCRIPT`'s LangEntry
// `lexer: Some("cpp")`) ŌĆö same shared `CPP_STYLES` / `CPP_ITALIC`
// / `CPP_BOLD` reused across every LexCPP-family theme
// (C / C++ / C# / Java / Objective-C / RC). Only the class-0 +
// class-1 keyword pair differs:
//   - class 0 = `JAVASCRIPT_KEYWORDS` (49 tokens covering ES5 ŌåÆ
//     ES2017+ reserved words + strict-mode future-reserved +
//     language literals). Renders bold.
//   - class 1 = `JAVASCRIPT_KEYWORDS_2` (51 tokens covering the
//     MDN Standard built-in objects ŌĆö `Array`, `Object`,
//     `Math`, `JSON`, `Promise`, `Iterator` (ES2025), the Error
//     hierarchy, the typed-array family including `Float16Array`
//     (ES2025), and language / host globals `console` /
//     `globalThis` / `NaN` / `Infinity`). Renders accent-color.
//     See the wordlist's docstring for the class-0-excludes-these
//     / class-1-owns-these rationale.
const JAVASCRIPT_THEME: LangTheme = LangTheme {
    keywords: &[(0, JAVASCRIPT_KEYWORDS), (1, JAVASCRIPT_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
// TypeScript rides `LexCPP` (per `L_TYPESCRIPT`'s LangEntry
// `lexer: Some("cpp")`, extensions `.ts` / `.tsx`) ŌĆö the SAME
// shared `CPP_STYLES` / `CPP_ITALIC` / `CPP_BOLD` reused across
// every LexCPP-family theme. Only the class-0 + class-1 keyword
// pair differs from JavaScript:
//   - class 0 = `TYPESCRIPT_KEYWORDS` (66 tokens ŌĆö the 49-token
//     JavaScript baseline plus 17 TS-specific reserved words:
//     `type` / `namespace` / `declare` / `abstract` / `readonly`
//     / `override` / `accessor` / `is` / `asserts` / `keyof` /
//     `infer` / `as` / `satisfies` / `unique` / `intrinsic` /
//     `using` / `out`).
//   - class 1 = `TYPESCRIPT_KEYWORDS_2` (60 tokens ŌĆö the
//     9 TS primitive-type identifiers `string` / `number` /
//     `boolean` / `any` / `never` / `unknown` / `object` /
//     `symbol` / `bigint` plus the 51-token JavaScript
//     built-ins baseline from `JAVASCRIPT_KEYWORDS_2`).
//
// **Superset discipline.** TypeScript is a strict syntactic
// superset of JavaScript at the grammar level ŌĆö every JS
// reserved word is also a TS reserved word, and every JS
// built-in constructor is also a TS built-in. That's why the
// baseline is duplicated (each list is independently valid
// input to `SCI_SETKEYWORDS`); the alternative ŌĆö sharing the
// underlying storage ŌĆö would fight `LexCPP`'s wordlist contract
// (each descriptor slot is one flat wordlist). Content drift
// between JS and TS would break intended TS-runs-on-JS-runtime
// semantics; the invariant test in `tests` pins the
// baseline-equality contract affirmatively.
const TYPESCRIPT_THEME: LangTheme = LangTheme {
    keywords: &[(0, TYPESCRIPT_KEYWORDS), (1, TYPESCRIPT_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
// Go rides `LexCPP` (per `L_GOLANG`'s LangEntry
// `lexer: Some("cpp")`, extension `.go`) ŌĆö reuses the shared
// `CPP_STYLES` / `CPP_ITALIC` / `CPP_BOLD` table verbatim. Same
// class-0 + class-1 shape as every other LexCPP-family theme;
// only the wordlist content differs:
//   - class 0 = `GO_KEYWORDS` (29 tokens ŌĆö the 25 Go reserved
//     words from Go spec ┬¦"Keywords": `break` / `case` / `chan`
//     / `const` / `continue` / `default` / `defer` / `else` /
//     `fallthrough` / `for` / `func` / `go` / `goto` / `if` /
//     `import` / `interface` / `map` / `package` / `range` /
//     `return` / `select` / `struct` / `switch` / `type` /
//     `var`, plus the 4 predeclared-literal identifiers
//     `true` / `false` / `nil` / `iota`, placed in class 0 per
//     editorial convention ŌĆö matches every mainstream Go styler).
//   - class 1 = `GO_KEYWORDS_2` (40 tokens ŌĆö 20 predeclared
//     primitive types `bool` / `byte` / `int*` / `uint*` /
//     `float*` / `complex*` / `rune` / `string` / `uintptr` /
//     `error`, plus 2 Go 1.18+ generic-typing predeclared
//     identifiers `any` / `comparable`, plus 18 built-in
//     functions `append` / `cap` / `clear` (1.21+) / `close` /
//     `complex` / `copy` / `delete` / `imag` / `len` / `make` /
//     `max` (1.21+) / `min` (1.21+) / `new` / `panic` /
//     `print` / `println` / `real` / `recover`).
//
// **Spec adherence.** Go's reserved-word set is a **closed
// enumeration** ŌĆö the Go language spec explicitly lists all 25
// keywords, and no additions have been made in any 1.x release
// since Go 1.0. `true` / `false` / `nil` / `iota` are strictly
// speaking predeclared identifiers per spec ┬¦"Predeclared
// identifiers" (they live in the universe block, not the
// reserved-words list), but they're placed in class 0 for the
// same editorial-placement reason `null` / `undefined` land in
// `JAVASCRIPT_KEYWORDS` class 0: they read as language flow-
// control keywords in every real Go program. The class-1
// wordlist owns the predeclared *types* (`bool`, `int`,
// `string`, `error`) and predeclared *functions* (`make`,
// `new`, `append`, `len`, `cap`, `panic`, `recover`, etc.)
// where the accent-color "types + built-ins" convention
// applies uniformly.
const GO_THEME: LangTheme = LangTheme {
    keywords: &[(0, GO_KEYWORDS), (1, GO_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};
// Swift rides `LexCPP` (per `L_SWIFT`'s LangEntry
// `lexer: Some("cpp")`, extension `.swift`) ŌĆö reuses the shared
// `CPP_STYLES` / `CPP_ITALIC` / `CPP_BOLD` table verbatim. Same
// class-0 + class-1 shape as every other LexCPP-family theme
// (C / C++ / C# / Java / JavaScript / TypeScript / Go /
// Objective-C / Resource file); only the wordlist content
// differs:
//   - class 0 = `SWIFT_KEYWORDS` (71 tokens: 27 declaration
//     keywords + 19 statement keywords + 12 expression/type
//     keywords + 2 concurrency additions (`actor` + `async`) +
//     11 member modifiers).
//   - class 1 = `SWIFT_KEYWORDS_2` (46 tokens: 15 numeric
//     primitives + 8 non-numeric primitives + 8 collection
//     types + `Error` + 9 common protocols + 5 concurrency
//     types).
//
// **Swift 5.9+ baseline** ŌĆö includes ownership modifiers
// (`borrowing`/`consuming`, added 5.9) and structured
// concurrency (`actor`/`async`/`await`, added 5.5). `Self`
// (capital, current-type placeholder) is spec-distinct from
// lowercase `self` (current instance); both are class-0
// keywords.
//
// **`#`-prefixed compile-time directives** ŌĆö **partial handling**.
// `LexCPP.cxx:1370-1372` gates `SCE_C_PREPROCESSOR` on
// `sc.ch == '#' && visibleChars == 0` ŌĆö the source comment
// literally reads "Preprocessor commands are alone on their
// line." So line-leading directives (`#if` / `#else` /
// `#elseif` / `#endif` / `#warning` / `#error`) render
// correctly as PREPROCESSOR. **Inline / mid-expression
// directives** (`#selector(handleTap)` / `#keyPath(\.foo)` /
// `#available(iOS 15, *)` / `#colorLiteral(...)`) do NOT ŌĆö
// `LexCPP` tokenises them as operator + identifier past the
// `#`, rendering unstyled. This is a known gap in `LexCPP`'s
// Swift handling; a Swift-native lexer would classify all
// `#name` uniformly. Not fixable at the wordlist layer.
//
// **Contextual identifier-shaped tokens excluded from class 0**:
// `some` (opaque-return-type qualifier, `some View`) / `any`
// (existential-type qualifier lowercase, `any Collection`) /
// `optional` (`@objc protocol` member modifier) / `get` /
// `set` / `didSet` / `willSet` / operator-declaration
// contextuals (`associativity` / `left` / `right` / `none` /
// `infix` / `postfix` / `prefix` / `precedence`). Same
// identifier-collision rationale as TypeScript's `get`/`set`
// exclusion: `let some = ...` is common Swift code.
// Capital-A `Any` (existential-any type) IS included in the
// expression-group per spec.
//
// **Foundation / SwiftUI / UIKit types deliberately excluded**
// from class 1 (framework-specific dynamic set ŌĆö same
// exclusion rationale as GDScript's engine singletons and
// Go's stdlib package names). Users get Xcode-style
// framework symbol highlighting from `sourcekit-lsp`, not
// from a lexer wordlist.
const SWIFT_THEME: LangTheme = LangTheme {
    keywords: &[(0, SWIFT_KEYWORDS), (1, SWIFT_KEYWORDS_2)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};

// --- LexFortran ---
// LexFortran serves BOTH free-form (`L_FORTRAN`, extensions
// `.f90` / `.f95` / `.f2k` / `.f03` / `.f08` / `.f15`, Lexilla
// name `"fortran"`, SCLEX_FORTRAN = 36) and fixed-form
// (`L_FORTRAN_77`, extensions `.f` / `.for` / `.f77` / `.ftn`,
// Lexilla name `"f77"`, SCLEX_F77 = 37). One `LexFortran.cxx`
// registers two `LexerModule` instances (`:723-724`) that share
// `ColouriseFortranDoc` with just an `isFixFormat` boolean
// toggling column-oriented parsing at `:92-122`. Same SCE_F_*
// enum, same three-class wordlist descriptor at `:696-701`.
// Both language rows dispatch through the shared branch
// `L_FORTRAN || L_FORTRAN_77 ŌåÆ &FORTRAN_THEME` ŌĆö same
// discipline as `L_JSON || L_JSON5 ŌåÆ &JSON_THEME`.
//
// **13 style mappings.** `SCE_F_DEFAULT` (0) and
// `SCE_F_IDENTIFIER` (7) unmapped per framework convention
// (bare identifiers paint at STYLE_DEFAULT). The remaining 13
// SCE_F_* slots all map:
//   - `COMMENT` (1) ŌåÆ Comment.
//   - `NUMBER` (2) ŌåÆ Number.
//   - `STRING1` (3) + `STRING2` (4) + `STRINGEOL` (5) ŌåÆ
//     String. Three flavours collapse: `'...'`, `"..."`, and
//     the unterminated-string error state.
//   - `OPERATOR` (6) + `OPERATOR2` (12) ŌåÆ Operator. `.eq.` /
//     `.and.` / `.true.` etc. `.name.` forms all get the same
//     colour as `+`/`-`/`==`. Two operator flavours collapse
//     ŌĆö same collapse discipline as R's INFIX + INFIXEOL.
//   - `WORD` (8) ŌåÆ Keyword (bold ŌĆö primary language keywords).
//   - `WORD2` (9) ŌåÆ Keyword2 (accent ŌĆö standard intrinsic
//     functions).
//   - `WORD3` (10) ŌåÆ Keyword2 (accent ŌĆö F2003+ extended
//     intrinsics). Two intrinsic-function classes collapse to
//     one accent slot ŌĆö same collapse discipline as R's
//     BASEKWORD + OTHERKWORD and JSON's WORD2 +
//     PROPERTYNAME + URI + COMPACTIRI + LDKEYWORD.
//   - `PREPROCESSOR` (11) ŌåÆ Preprocessor (compiler directives
//     `!DEC$` / `!DIR$` / `!MS$` + C-preprocessor `#include` /
//     `#define`).
//   - `LABEL` (13) ŌåÆ Keyword2 (accent ŌĆö statement labels are
//     branch targets, structurally significant).
//   - `CONTINUATION` (14) ŌåÆ Operator (line-continuation marker
//     ŌĆö visually similar to punctuation).
const FORTRAN_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_F_COMMENT, StyleSlot::Comment),
    (SCE_F_NUMBER, StyleSlot::Number),
    (SCE_F_STRING1, StyleSlot::String),
    (SCE_F_STRING2, StyleSlot::String),
    (SCE_F_STRINGEOL, StyleSlot::String),
    (SCE_F_OPERATOR, StyleSlot::Operator),
    (SCE_F_WORD, StyleSlot::Keyword),
    (SCE_F_WORD2, StyleSlot::Keyword2),
    (SCE_F_WORD3, StyleSlot::Keyword2),
    (SCE_F_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_F_OPERATOR2, StyleSlot::Operator),
    (SCE_F_LABEL, StyleSlot::Keyword2),
    (SCE_F_CONTINUATION, StyleSlot::Operator),
];

// Italic on the single COMMENT state ŌĆö matches the universal
// Code++ comment-slot convention.
const FORTRAN_ITALIC: &[usize] = &[SCE_F_COMMENT];

// Bold on WORD only. Matches the "one bold class = language
// reserved words" rule (same as C / Rust / D / COBOL /
// PowerShell / R / CoffeeScript). WORD2 / WORD3 / LABEL use
// Keyword2 weight (accent, not bold).
const FORTRAN_BOLD: &[usize] = &[SCE_F_WORD];

// Three-class install matches `FortranWordLists[]` at
// `LexFortran.cxx:696-701`. Class order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and
// `LexerJSON`'s counterpart in LexFortran probes wordlists
// 0/1/2 first-match-wins at `:167-179`.
const FORTRAN_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, FORTRAN_KEYWORDS),
        (1, FORTRAN_INTRINSICS),
        (2, FORTRAN_EXTENDED),
    ],
    styles: FORTRAN_STYLES,
    italic: FORTRAN_ITALIC,
    bold: FORTRAN_BOLD,
};

// --- LexGDScript ---
// LexGDScript serves Godot Engine's GDScript source (extension `.gd`).
// `L_GDSCRIPT` (id 86) is the only language row using this lexer.
// Dispatches `SCLEX_GDSCRIPT` (= 135) via a two-class wordlist
// descriptor at `LexGDScript.cxx:171-175` ("Keywords" and
// "Highlighted identifiers"). See the SCE_GD_* banner in
// `crates/scintilla-sys/src/lib.rs` for the state machine, the
// four-flavour string handling, `@`-annotation position gating,
// and `$`/`%` nodepath sigil rules.
//
// **15 style mappings** covering 17 defined SCE_GD_* states (0..=16).
// `SCE_GD_DEFAULT` (0) and `SCE_GD_IDENTIFIER` (11) are intentionally
// unmapped per the universal framework convention (bare identifiers
// paint at STYLE_DEFAULT ŌĆö same discipline as C's `SCE_C_IDENTIFIER`
// and Python's `SCE_P_IDENTIFIER`).
//
//   - `COMMENTLINE` (1) + `COMMENTBLOCK` (12) ŌåÆ Comment. Both `#`
//     and `##` line-comment forms collapse to the same paint;
//     italic on both per `GDSCRIPT_ITALIC`. Same collapse
//     discipline as Bash's `SCE_SH_COMMENTLINE` / D's
//     `SCE_D_COMMENTLINE` + `SCE_D_COMMENTLINEDOC`.
//   - `NUMBER` (2) ŌåÆ Number. Covers decimal, hex (`0x`), binary
//     (`0b`), octal (`0o`).
//   - `STRING` (3) + `CHARACTER` (4) + `TRIPLE` (6) +
//     `TRIPLEDOUBLE` (7) + `STRINGEOL` (13) ŌåÆ String. Five
//     string flavours collapse to one paint ŌĆö same collapse
//     discipline as Python's SCE_P_STRING / _CHARACTER / _TRIPLE
//     / _TRIPLEDOUBLE / _STRINGEOL unification, and matches the
//     `_STRINGEOL ŌåÆ String` established convention (JS / VHDL /
//     Ada / Verilog / Haskell / D / TypeScript precedent).
//   - `WORD` (5) ŌåÆ Keyword (bold ŌĆö class-0 wordlist hit).
//   - `WORD2` (14) ŌåÆ Keyword2 (accent ŌĆö class-1 wordlist hit,
//     Godot built-in globals).
//   - `CLASSNAME` (8) + `FUNCNAME` (9) ŌåÆ Keyword2. Position-
//     derived declaration slots (identifier after `class` or
//     `func`). Matches Python's `SCE_P_CLASSNAME` /
//     `SCE_P_DEFNAME` and Ruby's `SCE_RB_CLASSNAME` /
//     `SCE_RB_DEFNAME` precedent ŌĆö the same "declaration-site
//     identifier gets the type-slot colour" convention across
//     the framework.
//   - `OPERATOR` (10) ŌåÆ Operator.
//   - `ANNOTATION` (15) ŌåÆ Preprocessor (bold ŌĆö matches Python's
//     `SCE_P_DECORATOR` precedent; `@onready` / `@export` /
//     `@rpc` are structurally decorators, same `@name` mechanism
//     as Python's `@decorator`, same rendering role).
//   - `NODEPATH` (16) ŌåÆ Lifetime. Structural sigil-tagged scene-
//     tree reference (`$Node/Path`, `%SceneName`). Matches the
//     established Lifetime-slot precedent for sigil-prefixed
//     structural anchors (Bash `SCE_SH_SCALAR` / `SCE_SH_PARAM`,
//     Lisp `SCE_LISP_SYMBOL`, Perl `SCE_PL_SCALAR`).
//
// Italic on both comment states matches the universal
// framework convention; bold on both `WORD` (primary reserved-word
// class) and `ANNOTATION` (structural decorator anchor) matches
// Python's `SCE_P_WORD` + `SCE_P_DECORATOR` bold pair.
const GDSCRIPT_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_GD_COMMENTLINE, StyleSlot::Comment),
    (SCE_GD_NUMBER, StyleSlot::Number),
    (SCE_GD_STRING, StyleSlot::String),
    (SCE_GD_CHARACTER, StyleSlot::String),
    (SCE_GD_WORD, StyleSlot::Keyword),
    (SCE_GD_TRIPLE, StyleSlot::String),
    (SCE_GD_TRIPLEDOUBLE, StyleSlot::String),
    (SCE_GD_CLASSNAME, StyleSlot::Keyword2),
    (SCE_GD_FUNCNAME, StyleSlot::Keyword2),
    (SCE_GD_OPERATOR, StyleSlot::Operator),
    (SCE_GD_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_GD_STRINGEOL, StyleSlot::String),
    (SCE_GD_WORD2, StyleSlot::Keyword2),
    (SCE_GD_ANNOTATION, StyleSlot::Preprocessor),
    (SCE_GD_NODEPATH, StyleSlot::Lifetime),
];

const GDSCRIPT_ITALIC: &[usize] = &[SCE_GD_COMMENTLINE, SCE_GD_COMMENTBLOCK];
const GDSCRIPT_BOLD: &[usize] = &[SCE_GD_WORD, SCE_GD_ANNOTATION];

const GDSCRIPT_THEME: LangTheme = LangTheme {
    keywords: &[(0, GDSCRIPT_KEYWORDS), (1, GDSCRIPT_KEYWORDS_2)],
    styles: GDSCRIPT_STYLES,
    italic: GDSCRIPT_ITALIC,
    bold: GDSCRIPT_BOLD,
};

// --- LexHollywood ---
// LexHollywood serves Hollywood ŌĆö a proprietary Lua-inspired
// multimedia programming language by Andreas Falkenhahn. `L_HOLLYWOOD`
// (id 87) is the only language row using this lexer. Dispatches
// `SCLEX_HOLLYWOOD` (= 130) via a four-class wordlist descriptor at
// `LexHollywood.cxx:235-241` ŌĆö "Hollywood keywords" / "Hollywood
// standard API functions" / "Hollywood plugin API functions" /
// "Hollywood plugin methods". Code++'s default install populates
// class 0 + class 1 (language reserved words + stdlib API);
// classes 2 and 3 (plugin-provided vocabulary) are left empty per
// framework-specific-dynamic-set convention ŌĆö a user with plugins
// installed can add their plugin's wordlists via a future
// configuration override.
//
// See the SCE_HOLLYWOOD_* banner in `crates/scintilla-sys/src/lib.rs`
// for the case-insensitive `GetCurrentLowered` classifier,
// last-match-wins cross-class discipline, `[[..]]` block-string
// syntax, `$xxx` / `0xxxx` hex literals, `#`-prefix CONSTANT
// state (`#RED` / `#WHITE`), and `@`-prefix PREPROCESSOR state
// (`@REQUIRE` / `@INCLUDE` / `@VERSION` / `@DISPLAY`).
//
// **13 style mappings** covering 15 defined SCE_HOLLYWOOD_* states
// (0..=14). `SCE_HOLLYWOOD_DEFAULT` (0) and
// `SCE_HOLLYWOOD_IDENTIFIER` (12) are intentionally unmapped per
// the universal framework convention (bare identifiers paint at
// STYLE_DEFAULT ŌĆö same discipline as C's `SCE_C_IDENTIFIER` and
// Python's `SCE_P_IDENTIFIER`).
//
//   - `COMMENT` (1) + `COMMENTBLOCK` (2) ŌåÆ Comment. Both `;`-line
//     and `/*..*/` block comments collapse ŌĆö italic on both per
//     `HOLLYWOOD_ITALIC`. Same collapse discipline as C's
//     SCE_C_COMMENT / _COMMENTLINE unification.
//   - `NUMBER` (3) + `HEXNUMBER` (14) ŌåÆ Number. Two numeric
//     flavours (decimal + hex, either `$abc` or `0xabc`)
//     collapse to one paint ŌĆö same collapse discipline as
//     C's SCE_C_NUMBER (which handles both).
//   - `KEYWORD` (4) ŌåÆ Keyword (bold ŌĆö class-0 wordlist hit).
//   - `STDAPI` (5) + `PLUGINAPI` (6) + `PLUGINMETHOD` (7) ŌåÆ
//     Keyword2. Three separate wordlist hits, one paint slot ŌĆö
//     the framework's "type-like accent" convention. Hollywood
//     splits its API surface across three wordlist classes for
//     plugin-set granularity (users can independently populate
//     class 2 / class 3 without touching Code++'s class-1
//     stdlib baseline), but visually they collapse to one accent
//     colour matching the LexCPP-family "SCE_C_WORD2 (class 1)
//     = types + globals" precedent.
//   - `STRING` (8) + `STRINGBLOCK` (9) ŌåÆ String. Two string
//     flavours (`"..."` and Lua-style `[[..]]`) collapse to one
//     paint ŌĆö same discipline as Python's SCE_P_STRING /
//     SCE_P_TRIPLE / SCE_P_TRIPLEDOUBLE unification and
//     TypeScript's five-flavour string collapse.
//   - `PREPROCESSOR` (10) ŌåÆ Preprocessor (bold ŌĆö `@`-prefixed
//     compile-time directives `@REQUIRE`, `@INCLUDE`, etc.).
//     Matches Python's `SCE_P_DECORATOR` bold-preprocessor
//     precedent ŌĆö same `@name` mechanism, same structural role.
//   - `OPERATOR` (11) ŌåÆ Operator.
//   - `CONSTANT` (13) ŌåÆ Lifetime. Structural sigil-tagged
//     `#`-prefixed named-constant reference (`#RED`, `#WHITE`,
//     `#TRUE`). Matches the established Lifetime-slot precedent
//     for sigil-prefixed structural anchors (Bash SCE_SH_SCALAR
//     / Lisp SCE_LISP_SYMBOL / Perl SCE_PL_SCALAR / GDScript
//     SCE_GD_NODEPATH).
//
// Italic on both comment states matches the universal framework
// convention; bold on both `KEYWORD` (primary reserved-word
// class) and `PREPROCESSOR` (`@`-directive structural anchor)
// matches Python's `SCE_P_WORD` + `SCE_P_DECORATOR` bold pair.
const HOLLYWOOD_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_HOLLYWOOD_COMMENT, StyleSlot::Comment),
    (SCE_HOLLYWOOD_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_HOLLYWOOD_NUMBER, StyleSlot::Number),
    (SCE_HOLLYWOOD_KEYWORD, StyleSlot::Keyword),
    (SCE_HOLLYWOOD_STDAPI, StyleSlot::Keyword2),
    (SCE_HOLLYWOOD_PLUGINAPI, StyleSlot::Keyword2),
    (SCE_HOLLYWOOD_PLUGINMETHOD, StyleSlot::Keyword2),
    (SCE_HOLLYWOOD_STRING, StyleSlot::String),
    (SCE_HOLLYWOOD_STRINGBLOCK, StyleSlot::String),
    (SCE_HOLLYWOOD_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_HOLLYWOOD_OPERATOR, StyleSlot::Operator),
    (SCE_HOLLYWOOD_CONSTANT, StyleSlot::Lifetime),
    (SCE_HOLLYWOOD_HEXNUMBER, StyleSlot::Number),
];

const HOLLYWOOD_ITALIC: &[usize] = &[SCE_HOLLYWOOD_COMMENT, SCE_HOLLYWOOD_COMMENTBLOCK];
const HOLLYWOOD_BOLD: &[usize] = &[SCE_HOLLYWOOD_KEYWORD, SCE_HOLLYWOOD_PREPROCESSOR];

const HOLLYWOOD_THEME: LangTheme = LangTheme {
    keywords: &[(0, HOLLYWOOD_KEYWORDS), (1, HOLLYWOOD_STDAPI)],
    styles: HOLLYWOOD_STYLES,
    italic: HOLLYWOOD_ITALIC,
    bold: HOLLYWOOD_BOLD,
};

// --- LexRaku ---
// LexRaku serves Raku (the current name of what was previously
// called "Perl 6"). `L_RAKU` (id 89) is the only language row
// using this lexer. Dispatches `SCLEX_RAKU` (= 131) via a
// **seven-class** wordlist descriptor at `LexRaku.cxx:106-115`.
// Extensions `.raku` / `.rakumod`. See the SCE_RAKU_* banner in
// `crates/scintilla-sys/src/lib.rs` for the state machine, the
// first-match-wins classifier order across classes 0-5, and the
// class-6 `:`-gated adverb classification.
//
// **26 style mappings** covering 29 defined SCE_RAKU_* states
// (0..=28). `SCE_RAKU_DEFAULT` (0) and `SCE_RAKU_IDENTIFIER` (21)
// are intentionally unmapped per the universal framework
// convention (bare identifiers paint at STYLE_DEFAULT).
// `SCE_RAKU_ERROR` (1) is unmapped per the deferred-`StyleSlot::Error`
// migration convention (same discipline as Visual Prolog's
// STRING_ESCAPE_ERROR unmapping). Note that two of the 26 mapped
// slots (`SCE_RAKU_CHARACTER` and `SCE_RAKU_PREPROCESSOR`) are
// upstream **reserved-but-unemitted** states ŌĆö see the SCE_RAKU_*
// banner in `crates/scintilla-sys/src/lib.rs` for why they get
// defined paints anyway (future-proofing for upstream changes).
//
//   - `COMMENTLINE` (2) + `COMMENTEMBED` (3) + `POD` (4) ŌåÆ
//     Comment. Three comment flavours collapse ŌĆö `#`-line
//     comments, `#|`/`#=` declarator-doc embed comments, and
//     `=begin pod`/`=end pod` block-doc POD. All italic per
//     `RAKU_ITALIC`.
//   - `CHARACTER` (5) + `HEREDOC_Q` (6) + `HEREDOC_QQ` (7) +
//     `STRING` (8) + `STRING_Q` (9) + `STRING_QQ` (10) +
//     `STRING_Q_LANG` (11) + `STRING_VAR` (12) ŌåÆ String.
//     **Eight string-family states collapse to one paint** ŌĆö
//     the richest string-flavour collapse in Phase 4.5. See
//     the SCE_RAKU_* banner for what each state represents;
//     visually they render identically as string-content
//     paint.
//   - `REGEX` (13) + `REGEX_VAR` (14) ŌåÆ String. Regex bodies
//     paint as string (Bash / Perl / VHDL convention for
//     regex-family styling).
//   - `ADVERB` (15) ŌåÆ Keyword2. `:sym` / `:qq` / `:to` /
//     `:heredoc` ŌĆö modifier tokens with structural role but
//     no bold weight (bold is reserved for language flow-
//     control keywords).
//   - `NUMBER` (16) ŌåÆ Number.
//   - `PREPROCESSOR` (17) ŌåÆ Preprocessor bold. `use v6.d` /
//     `use MONKEY-TYPING` / `use nqp` pragma directives.
//   - `OPERATOR` (18) ŌåÆ Operator.
//   - `WORD` (19) ŌåÆ Keyword bold ŌĆö class-0 wordlist hit
//     (Raku language keywords + phasers).
//   - `FUNCTION` (20) ŌåÆ Keyword2 ŌĆö class-1 wordlist hit
//     (Raku built-in functions).
//   - `TYPEDEF` (22) ŌåÆ Keyword2 ŌĆö classes 2/3/4/5 wordlist
//     hits collapse into ONE style slot (see the SCE_RAKU_*
//     banner ŌĆö LexRaku upstream keeps four separate wordlists
//     as source data but paints them identically).
//   - `MU` (23) + `POSITIONAL` (24) + `ASSOCIATIVE` (25) +
//     `CALLABLE` (26) ŌåÆ Lifetime. **Four sigil-tagged variable
//     states** all route to the framework's sigil-anchor slot ŌĆö
//     `$foo` scalar (MU) / `@foo` positional / `%foo`
//     associative / `&foo` callable. Matches Bash SCALAR /
//     PARAM / Lisp SYMBOL / Perl SCALAR / GDScript NODEPATH
//     precedent for `$`/`&`/`%`/`@` sigil-prefixed structural
//     anchors.
//   - `GRAMMAR` (27) + `CLASS` (28) ŌåÆ Keyword2. Position-
//     derived declaration slots ŌĆö identifier following the
//     `grammar` or `class` keyword. Matches Python's
//     `SCE_P_CLASSNAME` / GDScript's `SCE_GD_CLASSNAME`
//     precedent (declaration-site identifier gets the type-
//     slot colour).
//
// Italic on the three comment states (`COMMENTLINE` +
// `COMMENTEMBED` + `POD`) matches the universal framework
// convention. Bold on `WORD` (primary reserved-word class) +
// `PREPROCESSOR` (`use`-pragma structural anchor) matches
// Python's `SCE_P_WORD` + `SCE_P_DECORATOR` bold pair ŌĆö same
// discipline as GDScript's (KEYWORD + ANNOTATION) and
// Hollywood's (KEYWORD + PREPROCESSOR).
const RAKU_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_RAKU_COMMENTLINE, StyleSlot::Comment),
    (SCE_RAKU_COMMENTEMBED, StyleSlot::Comment),
    (SCE_RAKU_POD, StyleSlot::Comment),
    (SCE_RAKU_CHARACTER, StyleSlot::String),
    (SCE_RAKU_HEREDOC_Q, StyleSlot::String),
    (SCE_RAKU_HEREDOC_QQ, StyleSlot::String),
    (SCE_RAKU_STRING, StyleSlot::String),
    (SCE_RAKU_STRING_Q, StyleSlot::String),
    (SCE_RAKU_STRING_QQ, StyleSlot::String),
    (SCE_RAKU_STRING_Q_LANG, StyleSlot::String),
    (SCE_RAKU_STRING_VAR, StyleSlot::String),
    (SCE_RAKU_REGEX, StyleSlot::String),
    (SCE_RAKU_REGEX_VAR, StyleSlot::String),
    (SCE_RAKU_ADVERB, StyleSlot::Keyword2),
    (SCE_RAKU_NUMBER, StyleSlot::Number),
    (SCE_RAKU_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_RAKU_OPERATOR, StyleSlot::Operator),
    (SCE_RAKU_WORD, StyleSlot::Keyword),
    (SCE_RAKU_FUNCTION, StyleSlot::Keyword2),
    (SCE_RAKU_TYPEDEF, StyleSlot::Keyword2),
    (SCE_RAKU_MU, StyleSlot::Lifetime),
    (SCE_RAKU_POSITIONAL, StyleSlot::Lifetime),
    (SCE_RAKU_ASSOCIATIVE, StyleSlot::Lifetime),
    (SCE_RAKU_CALLABLE, StyleSlot::Lifetime),
    (SCE_RAKU_GRAMMAR, StyleSlot::Keyword2),
    (SCE_RAKU_CLASS, StyleSlot::Keyword2),
];

const RAKU_ITALIC: &[usize] = &[SCE_RAKU_COMMENTLINE, SCE_RAKU_COMMENTEMBED, SCE_RAKU_POD];
const RAKU_BOLD: &[usize] = &[SCE_RAKU_WORD, SCE_RAKU_PREPROCESSOR];

const RAKU_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, RAKU_KEYWORDS),
        (1, RAKU_FUNCTIONS),
        (2, RAKU_TYPES_BASIC),
        (3, RAKU_TYPES_COMPOSITE),
        (4, RAKU_TYPES_DOMAIN),
        (5, RAKU_TYPES_EXCEPTION),
        (6, RAKU_ADVERBS),
    ],
    styles: RAKU_STYLES,
    italic: RAKU_ITALIC,
    bold: RAKU_BOLD,
};

// --- LexHex (S-Record) ---
// Motorola S-Record files (extensions `.srec` / `.s19` / `.s28` /
// `.s37`) ŌĆö a text-based ROM-image record format where each line
// is `S<type><count><address><data...><checksum>`. `L_SREC` (id 61)
// is the only language row using the `srec` lexer name; the
// underlying `LexHex.cxx` file also serves Intel HEX (`ihex`) and
// Tektronix extended HEX (`tehex`) via separate `LexerModule`
// registrations that share the SCE_HEX_* style constants but not
// the same theme. See the SCE_HEX_* banner in
// `crates/scintilla-sys/src/lib.rs` for the full state matrix,
// which fields each record type populates, and per-lexer state
// usage.
//
// **Zero wordlists.** `LexerModule lmSrec(SCLEX_SREC,
// ColouriseSrecDoc, "srec", 0, NULL)` at `LexHex.cxx:1046` ŌĆö the
// five-argument constructor form with `NULL` for the
// `wordListDesc[]` parameter. Same discipline as Registry's
// `WordListSet` (which returns -1 rejecting installs) and INI /
// Properties (which ignore the wordlist parameter): the paint
// function's signature accepts a `WordList *[]` argument but
// **never references it**. Framework consequence:
// `SREC_THEME.keywords` MUST be empty; installing anything is a
// silent no-op.
//
// **11 style mappings** covering 19 defined SCE_HEX_* states
// (0..=18). Eight states unmapped: `DEFAULT` (0) per framework
// convention; six authoritative parse-failure states
// (`RECTYPE_UNKNOWN`/`BYTECOUNT_WRONG`/`ADDRESSFIELD_UNKNOWN`/
// `DATA_UNKNOWN`/`CHECKSUM_WRONG`/`GARBAGE`) per the deferred
// `StyleSlot::Error` migration convention (same discipline as
// Visual Prolog's STRING_ESCAPE_ERROR + COMMENT_KEY_ERROR
// unmapping); and `EXTENDEDADDRESS` (11) which is IHEX-only ŌĆö
// never emitted by Srec's paint loop, so mapping it would be
// dead code.
//
//   - `SCE_HEX_RECSTART` (1) ŌåÆ Preprocessor bold. The leading
//     `S` character is a per-line structural marker ŌĆö matches
//     Python `SCE_P_DECORATOR` / Hollywood `PREPROCESSOR` bold
//     precedent for `@`-style structural anchors.
//   - `SCE_HEX_RECTYPE` (2) ŌåÆ Keyword bold. The record type
//     digit (S0=header, S1/S2/S3=data at 16/24/32-bit addr,
//     S5=count, S7/S8/S9=start-address at 32/24/16-bit) drives
//     the record's semantics; matches the "primary language
//     flow-control" bold-keyword convention.
//   - `SCE_HEX_BYTECOUNT` (4) ŌåÆ Number.
//   - `SCE_HEX_NOADDRESS` (6) + `SCE_HEX_DATAADDRESS` (7) +
//     `SCE_HEX_RECCOUNT` (8) + `SCE_HEX_STARTADDRESS` (9) ŌåÆ
//     Number. **Four address-field flavours collapse** ŌĆö the
//     lexer classifies the address field differently per record
//     type (S0 ŌåÆ NOADDRESS, S1/S2/S3 ŌåÆ DATAADDRESS, S5 ŌåÆ
//     RECCOUNT, S7/S8/S9 ŌåÆ STARTADDRESS) for potential future
//     per-flavour styling, but all four represent 16/24/32-bit
//     hex numeric fields at the paint layer. Same collapse
//     discipline as Fortran's three STRING flavours or
//     TypeScript's five-flavour string collapse.
//   - `SCE_HEX_DATA_ODD` (12) + `SCE_HEX_DATA_EVEN` (13) ŌåÆ
//     String. **Alternating-byte pair collapses** ŌĆö LexHex
//     tags each hex-pair in the data payload as ODD or EVEN
//     for potential stripe rendering at the terminal layer;
//     the framework routes both to the same paint slot.
//   - `SCE_HEX_DATA_EMPTY` (15) ŌåÆ Comment italic. Padding /
//     trailing empty data ŌĆö visually deemphasised, matching the
//     "comment-family gets italic" universal convention.
//   - `SCE_HEX_CHECKSUM` (16) ŌåÆ Lifetime. Integrity anchor at
//     the trailing byte of every record ŌĆö structural role
//     matching the Bash SCALAR / Lisp SYMBOL / GDScript
//     NODEPATH / Perl SCALAR precedent for sigil-like
//     structural markers (in Srec's case, the anchor is a
//     position-derived tail rather than a leading sigil, but
//     the framework's structural-anchor discipline applies
//     symmetrically).
//
// Italic on DATA_EMPTY matches comment-family convention. Bold
// on RECSTART + RECTYPE matches "structural marker + primary
// keyword" bold pair convention.
const SREC_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_HEX_RECSTART, StyleSlot::Preprocessor),
    (SCE_HEX_RECTYPE, StyleSlot::Keyword),
    (SCE_HEX_BYTECOUNT, StyleSlot::Number),
    (SCE_HEX_NOADDRESS, StyleSlot::Number),
    (SCE_HEX_DATAADDRESS, StyleSlot::Number),
    (SCE_HEX_RECCOUNT, StyleSlot::Number),
    (SCE_HEX_STARTADDRESS, StyleSlot::Number),
    (SCE_HEX_DATA_ODD, StyleSlot::String),
    (SCE_HEX_DATA_EVEN, StyleSlot::String),
    (SCE_HEX_DATA_EMPTY, StyleSlot::Comment),
    (SCE_HEX_CHECKSUM, StyleSlot::Lifetime),
];

const SREC_ITALIC: &[usize] = &[SCE_HEX_DATA_EMPTY];
const SREC_BOLD: &[usize] = &[SCE_HEX_RECSTART, SCE_HEX_RECTYPE];

const SREC_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: SREC_STYLES,
    italic: SREC_ITALIC,
    bold: SREC_BOLD,
};

// --- LexHex (Intel HEX) ---
// Intel HEX files (extensions `.hex` / `.ihex`) ŌĆö a text-based
// ROM-image record format where each line is
// `:<count><address><type><data...><checksum>`. `L_IHEX` (id 62)
// is the only language row using the `ihex` lexer name;
// dispatches `SCLEX_IHEX` (= 118) via
// `LexerModule lmIHex(SCLEX_IHEX, ColouriseIHexDoc, "ihex",
// FoldIHexDoc, NULL)` at `LexHex.cxx:1047`. **Sibling to S-Record**:
// same `LexHex.cxx` source file, same shared `SCE_HEX_*` style
// constant namespace, same zero-wordlist contract (NULL
// `wordListDesc[]` argument; `WordList *[]` unnamed + never
// referenced in `ColouriseIHexDoc` at `:775`).
//
// **Differences from S-Record's wiring** (see SCE_HEX_* banner
// in `crates/scintilla-sys/src/lib.rs` for the full state
// matrix and per-lexer state usage from `LexHex.cxx:40-52`):
//   - **Line-leader differs**: Intel HEX uses `:` (colon) as
//     the RECSTART character; Srec uses `S`. Framework
//     consequence: none ŌĆö the `SCE_HEX_RECSTART` state itself
//     is emitted identically by both paint loops; only the
//     source byte that triggers it differs.
//   - **`SCE_HEX_RECCOUNT` (8) is NOT used** by IHEX
//     (`LexHex.cxx:40-52` records-layout comment omits it).
//     Srec uses it for the S5 record-count-of-preceding-data-
//     records field; IHEX has no equivalent record type.
//     Framework consequence: RECCOUNT is unmapped in
//     `IHEX_STYLES` (would be dead code ŌĆö never emitted).
//   - **`SCE_HEX_EXTENDEDADDRESS` (11) IS used** by IHEX
//     (record types 0x02 = extended-segment-address and
//     0x04 = extended-linear-address populate it via the
//     data-field classifier at `LexHex.cxx:519, :863`).
//     Framework consequence: EXTENDEDADDRESS ŌåÆ Number in
//     `IHEX_STYLES` (Srec left it unmapped as dead code).
//
// Net effect: 11 style mappings, same TOTAL count as SREC but
// with RECCOUNT swapped for EXTENDEDADDRESS.
//
// **Italic + bold sets are IDENTICAL to Srec's** ŌĆö DATA_EMPTY
// alone italic; RECSTART + RECTYPE bold. Both bold sets carry
// the same "structural-marker + primary-keyword" pair
// discipline documented in the SREC_STYLES banner. Rather than
// duplicate the const definitions, `IHEX_THEME` **reuses
// `SREC_ITALIC` + `SREC_BOLD` verbatim** ŌĆö cross-lexer const
// aliasing is safe here because both lexers share the same
// SCE_HEX_* namespace (the constants encode style-slot indices,
// not per-language semantics). Precedent: Fortran's free-form
// + fixed-form sharing `FORTRAN_THEME` at `L_FORTRAN ||
// L_FORTRAN_77 ŌåÆ &FORTRAN_THEME`. In IHEX's case only the
// styles table differs (RECCOUNT Ōåö EXTENDEDADDRESS swap) so
// full theme sharing isn't possible; italic + bold sharing is.
const IHEX_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_HEX_RECSTART, StyleSlot::Preprocessor),
    (SCE_HEX_RECTYPE, StyleSlot::Keyword),
    (SCE_HEX_BYTECOUNT, StyleSlot::Number),
    (SCE_HEX_NOADDRESS, StyleSlot::Number),
    (SCE_HEX_DATAADDRESS, StyleSlot::Number),
    (SCE_HEX_STARTADDRESS, StyleSlot::Number),
    (SCE_HEX_EXTENDEDADDRESS, StyleSlot::Number),
    (SCE_HEX_DATA_ODD, StyleSlot::String),
    (SCE_HEX_DATA_EVEN, StyleSlot::String),
    (SCE_HEX_DATA_EMPTY, StyleSlot::Comment),
    (SCE_HEX_CHECKSUM, StyleSlot::Lifetime),
];

const IHEX_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: IHEX_STYLES,
    italic: SREC_ITALIC,
    bold: SREC_BOLD,
};

// --- LexHex (Tektronix extended HEX) ---
// Tektronix extended HEX files (extension `.tek` ŌĆö note: this
// is the FILE extension per `L_TEHEX`'s `LangEntry` in
// `crates/core/src/lang.rs`; `tehex` is only the Lexilla lexer
// name string, matching `LexerModule lmTEHex(..., "tehex", ...)`
// registration). A text-based ROM-image record format where
// each line is `%<length><type><checksum><address><data...>`.
// Third and final
// LexHex.cxx-family lexer completing the trio (Srec / IHEX /
// TEHEX). `L_TEHEX` (id 63) dispatches `SCLEX_TEHEX` (= 119) via
// `LexerModule lmTEHex(SCLEX_TEHEX, ColouriseTEHexDoc, "tehex",
// 0, NULL)` at `LexHex.cxx:1048`. Same zero-wordlist contract
// (5-arg NULL `wordListDesc[]`, `WordList *[]` parameter unnamed
// + never referenced in `ColouriseTEHexDoc` at `:939-1044`).
//
// **Distinctive record-line structure** (per the field-layout
// matrix at `LexHex.cxx:66-86` ŌĆö differs from both Srec and IHEX):
//   - `%` leader (NOT `S` like Srec, NOT `:` like IHEX).
//   - **length** field (2 hex digits ŌĆö is BYTECOUNT in the
//     SCE_HEX_* namespace).
//   - **type** field (1 hex digit ŌĆö NOT 2 like IHEX, NOT the
//     single-digit-after-S like Srec).
//   - **checksum** BEFORE address (unique to TEHEX ŌĆö Srec and
//     IHEX have checksum LAST). This layout choice makes TEHEX
//     parsers robust against arbitrary-length data fields.
//   - **address** field (9 hex digits ŌĆö matches IHEX's 8-digit
//     linear-address max plus type-digit continuation).
//   - **data** field (0..241 hex digits ŌĆö half the size of
//     Srec/IHEX max because of the fixed 8-digit address).
//
// **Style emissions used** (verified by grepping the paint-loop
// SCE_HEX_* references at `LexHex.cxx:949-1039`):
//   - RECSTART / BYTECOUNT / BYTECOUNT_WRONG / RECTYPE /
//     RECTYPE_UNKNOWN / CHECKSUM / CHECKSUM_WRONG / DATAADDRESS /
//     STARTADDRESS / ADDRESSFIELD_UNKNOWN / DATA_ODD / DATA_EVEN /
//     GARBAGE / DEFAULT.
//
// **Style emissions NOT used** by TEHEX (mapping would be dead
// code):
//   - `SCE_HEX_NOADDRESS` ŌĆö Srec S0-header-style zero-address
//     flavour has no TEHEX equivalent.
//   - `SCE_HEX_RECCOUNT` ŌĆö Srec-only (S5 record-count field).
//   - `SCE_HEX_EXTENDEDADDRESS` ŌĆö IHEX-only (record types
//     0x02 / 0x04).
//   - `SCE_HEX_DATA_EMPTY` ŌĆö TEHEX doesn't classify padding
//     bytes separately; malformed / empty data lines emit
//     GARBAGE instead.
//   - `SCE_HEX_DATA_UNKNOWN` ŌĆö never emitted (paint loop
//     goes GARBAGE for malformed data).
//
// **8 style mappings** ŌĆö smallest of the three LexHex-family
// themes (SREC = 11, IHEX = 11, TEHEX = 8) because TEHEX's
// simpler grammar means fewer classification flavours.
//
//   - `SCE_HEX_RECSTART` (1) ŌåÆ Preprocessor bold. Structural
//     per-line marker (`%` leader).
//   - `SCE_HEX_RECTYPE` (2) ŌåÆ Keyword bold.
//   - `SCE_HEX_BYTECOUNT` (4) ŌåÆ Number.
//   - `SCE_HEX_DATAADDRESS` (7) + `SCE_HEX_STARTADDRESS` (9) ŌåÆ
//     Number. **Two-flavour address collapse** ŌĆö smaller than
//     Srec's four-flavour or IHEX's four-flavour because
//     TEHEX only distinguishes DATAADDRESS (data records) from
//     STARTADDRESS (terminator records).
//   - `SCE_HEX_DATA_ODD` (12) + `SCE_HEX_DATA_EVEN` (13) ŌåÆ
//     String.
//   - `SCE_HEX_CHECKSUM` (16) ŌåÆ Lifetime. Same sigil-anchor
//     structural role as in Srec/IHEX.
//
// **Italic set is EMPTY** ŌĆö TEHEX has no DATA_EMPTY equivalent
// so there's no comment-family state to italicise. Framework
// consequence: `TEHEX_ITALIC = &[]`. Bold set matches Srec/IHEX
// (RECSTART + RECTYPE) ŌĆö reused verbatim via `SREC_BOLD` aliased
// pointer.
const TEHEX_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_HEX_RECSTART, StyleSlot::Preprocessor),
    (SCE_HEX_RECTYPE, StyleSlot::Keyword),
    (SCE_HEX_BYTECOUNT, StyleSlot::Number),
    (SCE_HEX_DATAADDRESS, StyleSlot::Number),
    (SCE_HEX_STARTADDRESS, StyleSlot::Number),
    (SCE_HEX_DATA_ODD, StyleSlot::String),
    (SCE_HEX_DATA_EVEN, StyleSlot::String),
    (SCE_HEX_CHECKSUM, StyleSlot::Lifetime),
];

const TEHEX_ITALIC: &[usize] = &[];

const TEHEX_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: TEHEX_STYLES,
    italic: TEHEX_ITALIC,
    bold: SREC_BOLD,
};

// --- LexCsound ---
// LexCsound serves Csound orchestra (`.orc`) and score (`.sco`)
// source, plus unified `.csd` files. `L_CSOUND` (id 70) is the
// only language row using this lexer. Dispatches
// SCLEX_CSOUND (= 74) via a three-class wordlist descriptor at
// `LexCsound.cxx:208-213`.
//
// **11 style mappings** covering every state the paint loop
// actually emits. Five of the sixteen SCE_CSOUND_* enum slots
// are unmapped:
//   - DEFAULT (0) and IDENTIFIER (5) per framework convention.
//   - INSTR (4) ŌĆö enum slot defined but never entered by the
//     paint loop; `instr` opcode routes through class-1
//     HEADERSTMT instead.
//   - COMMENTBLOCK (9) ŌĆö enum slot defined but the paint loop
//     has no `/* ... */` handling, only `;`-to-EOL line
//     comments.
//   - STRINGEOL (15) ŌĆö only referenced as an `initStyle` guard
//     at `LexCsound.cxx:63-64`; no `SetState` call targets it.
//
// **Slot rationale:**
//   - COMMENT (1) ŌåÆ Comment (italic).
//   - NUMBER (2) ŌåÆ Number. Also styles `0dbfs` since it starts
//     with a digit.
//   - OPERATOR (3) ŌåÆ Operator.
//   - OPCODE (6) ŌåÆ Keyword (bold ŌĆö the ~325 primary audio
//     opcodes).
//   - HEADERSTMT (7) + USERKEYWORD (8) ŌåÆ Keyword2. Two accent
//     categories collapse: header/section markers +
//     control-flow user-keywords. Same collapse discipline as
//     R's BASEKWORD + OTHERKWORD, JSON's WORD2 + PROPERTYNAME
//     + URI + COMPACTIRI + LDKEYWORD, and Fortran's WORD2 +
//     WORD3.
//   - PARAM (10) ŌåÆ Preprocessor. `p1`/`p2`/... instrument-
//     parameter references are structural inputs, distinct
//     visually from rate-typed variables.
//   - ARATE_VAR (11) + KRATE_VAR (12) + IRATE_VAR (13) +
//     GLOBAL_VAR (14) ŌåÆ Keyword2. Four rate-prefix categories
//     collapse to the accent color ŌĆö matches the collapse
//     discipline established across the phase. Rate variables
//     are Csound's signature (every variable carries its
//     evaluation rate in the name), so visual grouping to
//     Keyword2 is coherent.
const CSOUND_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_CSOUND_COMMENT, StyleSlot::Comment),
    (SCE_CSOUND_NUMBER, StyleSlot::Number),
    (SCE_CSOUND_OPERATOR, StyleSlot::Operator),
    (SCE_CSOUND_OPCODE, StyleSlot::Keyword),
    (SCE_CSOUND_HEADERSTMT, StyleSlot::Keyword2),
    (SCE_CSOUND_USERKEYWORD, StyleSlot::Keyword2),
    (SCE_CSOUND_PARAM, StyleSlot::Preprocessor),
    (SCE_CSOUND_ARATE_VAR, StyleSlot::Keyword2),
    (SCE_CSOUND_KRATE_VAR, StyleSlot::Keyword2),
    (SCE_CSOUND_IRATE_VAR, StyleSlot::Keyword2),
    (SCE_CSOUND_GLOBAL_VAR, StyleSlot::Keyword2),
];

// Italic on the single COMMENT state ŌĆö matches the universal
// Code++ comment-slot convention.
const CSOUND_ITALIC: &[usize] = &[SCE_CSOUND_COMMENT];

// Bold on OPCODE only. Matches the "one bold class = language
// reserved words" rule.
const CSOUND_BOLD: &[usize] = &[SCE_CSOUND_OPCODE];

// Three-class install matches `csoundWordListDesc[]` at
// `LexCsound.cxx:208-213`. Order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and
// the identifier classifier at `:95-100` probes class 0 first
// (OPCODE), then class 1 (HEADERSTMT), then class 2
// (USERKEYWORD).
const CSOUND_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, CSOUND_OPCODES),
        (1, CSOUND_HEADERSTMT),
        (2, CSOUND_USERKW),
    ],
    styles: CSOUND_STYLES,
    italic: CSOUND_ITALIC,
    bold: CSOUND_BOLD,
};

// --- LexErlang ---
// LexErlang serves Erlang (`.erl` source) + Erlang headers
// (`.hrl`). `L_ERLANG` (id 71) is the only language row using
// this lexer. Dispatches SCLEX_ERLANG (= 53, per `SciLexer.h:69`)
// via a **six-class wordlist descriptor** at
// `LexErlang.cxx:616-624` (`erlangWordListDesc[]`).
//
// **23 style mappings** covering every emitted SCE_ERLANG_*
// slot the paint loop actually emits. Three of the 26 defined
// slots are unmapped per framework convention:
//   - DEFAULT (0) ŌĆö whitespace / unclassified.
//   - ATOM (7) ŌĆö bare lowercase-first identifier. Erlang atoms
//     are the most common identifier form; framework convention
//     is to leave the bare-identifier slot unmapped so atoms
//     paint at STYLE_DEFAULT. Same convention as CSound
//     IDENTIFIER, R IDENTIFIER, JSON string/property (not
//     literally ŌĆö JSON has no bare identifier).
//   - UNKNOWN (31) ŌĆö transient parse state. Never emitted; the
//     paint loop settles UNKNOWN to a real style before commit.
//
// **Slot rationale:**
//   - COMMENT (1) + COMMENT_FUNCTION (14) + COMMENT_MODULE (15)
//     + COMMENT_DOC (16) + COMMENT_DOC_MACRO (17) ŌåÆ Comment
//     (italic). Five comment states collapse ŌĆö the `%`/`%%`/`%%%`
//     ratchet levels and the embedded edoc `@tag`/`{@macro}`
//     variants are all semantically comments, so they share the
//     comment color. Same collapse discipline as D's four
//     COMMENT / COMMENTDOC / COMMENTLINE / COMMENTNESTED slots.
//   - VARIABLE (2) ŌåÆ Keyword2. Erlang variables (uppercase-first
//     or `_`-prefixed) are semantically significant ŌĆö pattern
//     matching binds them, and their case distinction from atoms
//     is meaningful. Keyword2 (the accent color) makes them
//     visually distinct from atoms (unmapped, paints as default).
//   - NUMBER (3) ŌåÆ Number.
//   - KEYWORD (4) + BIFS (22) ŌåÆ Keyword (bold). Reserved words
//     and BIFs both are "part of the language" ŌĆö same bold slot,
//     matches CPP's WORD + WORD2 ŌåÆ Keyword + Keyword2 (JS did
//     it the other way; here we group both as primary since
//     BIFs are as core to Erlang as reserved words). Same
//     collapse discipline as Fortran's F_WORD + F_WORD2 (kept
//     separate) ŌĆö inverted here because Erlang's `is_atom` /
//     `spawn` / etc. read as syntax-level primitives.
//   - STRING (5) + CHARACTER (9) + ATOM_QUOTED (18) ŌåÆ String.
//     All three are quoted lexical forms ŌĆö double-quoted string,
//     `$c` character, and `'quoted atom'` all share the string
//     color. Same collapse discipline as Lua LITERALSTRING +
//     CHARACTER + STRING.
//   - OPERATOR (6) ŌåÆ Operator.
//   - FUNCTION_NAME (8) + RECORD (11) + NODE_NAME (13) +
//     RECORD_QUOTED (20) + NODE_NAME_QUOTED (21) + MODULES (23)
//     ŌåÆ Keyword2. Six accent categories collapse: function
//     references, records, node names (both quoted and unquoted
//     variants), and module prefixes. All are structural
//     markers pointing at a bound entity. Same collapse
//     discipline as CSound's ARATE_VAR + KRATE_VAR + IRATE_VAR
//     + GLOBAL_VAR + HEADERSTMT + USERKEYWORD ŌåÆ Keyword2.
//   - MACRO (10) + MACRO_QUOTED (19) ŌåÆ Macro. Erlang's `?MACRO`
//     preprocessor-style references pattern-match Rust's
//     `macro!()` invocations well; using the Macro slot keeps
//     them visually distinct from records (which use `#name`)
//     and from module attributes (which use `-name` and go to
//     Preprocessor). Reuse rationale mirrors Rust SCE_RUST_MACRO
//     ŌåÆ StyleSlot::Macro.
//   - PREPROC (12) + MODULES_ATT (24) ŌåÆ Preprocessor. Both are
//     `-`-prefixed and belong to the compiler-directive family
//     (conditional compilation + module metadata). Same collapse
//     discipline as C's PREPROCESSOR + comment-preproc / D's
//     PREPROCESSOR alone (single-slot).
const ERLANG_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_ERLANG_COMMENT, StyleSlot::Comment),
    (SCE_ERLANG_VARIABLE, StyleSlot::Keyword2),
    (SCE_ERLANG_NUMBER, StyleSlot::Number),
    (SCE_ERLANG_KEYWORD, StyleSlot::Keyword),
    (SCE_ERLANG_STRING, StyleSlot::String),
    (SCE_ERLANG_OPERATOR, StyleSlot::Operator),
    (SCE_ERLANG_FUNCTION_NAME, StyleSlot::Keyword2),
    (SCE_ERLANG_CHARACTER, StyleSlot::String),
    (SCE_ERLANG_MACRO, StyleSlot::Macro),
    (SCE_ERLANG_RECORD, StyleSlot::Keyword2),
    (SCE_ERLANG_PREPROC, StyleSlot::Preprocessor),
    (SCE_ERLANG_NODE_NAME, StyleSlot::Keyword2),
    (SCE_ERLANG_COMMENT_FUNCTION, StyleSlot::Comment),
    (SCE_ERLANG_COMMENT_MODULE, StyleSlot::Comment),
    (SCE_ERLANG_COMMENT_DOC, StyleSlot::Comment),
    (SCE_ERLANG_COMMENT_DOC_MACRO, StyleSlot::Comment),
    (SCE_ERLANG_ATOM_QUOTED, StyleSlot::String),
    (SCE_ERLANG_MACRO_QUOTED, StyleSlot::Macro),
    (SCE_ERLANG_RECORD_QUOTED, StyleSlot::Keyword2),
    (SCE_ERLANG_NODE_NAME_QUOTED, StyleSlot::Keyword2),
    (SCE_ERLANG_BIFS, StyleSlot::Keyword),
    (SCE_ERLANG_MODULES, StyleSlot::Keyword2),
    (SCE_ERLANG_MODULES_ATT, StyleSlot::Preprocessor),
];

// Italic on all five COMMENT states ŌĆö matches the universal
// Code++ comment-slot convention. The five states correspond
// to `%`/`%%`/`%%%` ratchet levels and embedded edoc `@tag` /
// `{@macro}` variants; all read as comments visually.
const ERLANG_ITALIC: &[usize] = &[
    SCE_ERLANG_COMMENT,
    SCE_ERLANG_COMMENT_FUNCTION,
    SCE_ERLANG_COMMENT_MODULE,
    SCE_ERLANG_COMMENT_DOC,
    SCE_ERLANG_COMMENT_DOC_MACRO,
];

// Bold on KEYWORD + BIFS ŌĆö matches the "bold class = language
// reserved words" rule. Both wordlists are "part of the
// language" (KEYWORD is `case`/`if`/`fun`/... reserved,
// BIFS is `spawn`/`is_atom`/... built-ins), so they share
// visual weight. Two-item bold is inside our discipline ŌĆö
// Fortran's F_WORD alone; here two related classes share it.
const ERLANG_BOLD: &[usize] = &[SCE_ERLANG_KEYWORD, SCE_ERLANG_BIFS];

// Six-class install matches `erlangWordListDesc[]` at
// `LexErlang.cxx:616-624`. Order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and the
// classifier at `:213-217` probes class 0 (KEYWORD) first,
// class 1 (BIFS) second. Preprocessor state at `:397-400`
// probes class 2 (PREPROC) first, class 3 (MODULES_ATT)
// second. Doc-comment state at `:157-172` probes class 5
// (DOC_MACRO) first (only when parse_state ==
// COMMENT_DOC_MACRO), class 4 (DOC) second.
const ERLANG_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, ERLANG_KEYWORDS),
        (1, ERLANG_BIFS),
        (2, ERLANG_PREPROC),
        (3, ERLANG_MODULE_ATT),
        (4, ERLANG_DOC),
        (5, ERLANG_DOC_MACRO),
    ],
    styles: ERLANG_STYLES,
    italic: ERLANG_ITALIC,
    bold: ERLANG_BOLD,
};

// --- LexEScript ---
// LexEScript serves ESCRIPT ŌĆö POL (Penultima Online)'s server-side
// scripting language for Ultima Online emulator scripts, extension
// `.em`. `L_ESCRIPT` (id 72) is the only language row using this
// lexer. Dispatches SCLEX_ESCRIPT (= 41, per `SciLexer.h:57`) via a
// three-class wordlist descriptor at `LexEScript.cxx:270-275`.
//
// **10 style mappings** covering every emitted SCE_ESCRIPT_* state
// the paint loop actually produces (plus COMMENTDOC as best-effort
// forward-compat for a currently-orphan enum slot). Two of the 12
// defined slots stay unmapped per framework convention:
//   - DEFAULT (0) ŌĆö whitespace / unclassified.
//   - IDENTIFIER (8) ŌĆö transient, settles to DEFAULT / WORD /
//     WORD2 / WORD3 before commit.
//
// **Semantic-label mismatch is intentional.** The upstream lexer's
// class-2 wordlist is labelled "Extended and user defined functions"
// (`ESCRIPTWordLists[2]` at `:273`), but the fold classifier at
// `:232-243` only fires on class-2-styled tokens ŌĆö forcing the
// language's fold-critical control-flow keywords (`for`/`if`/
// `while`/`endif`/etc.) into class 2. The theme compensates by
// routing `SCE_ESCRIPT_WORD3` to `StyleSlot::Keyword` (bold,
// matching the semantic weight of language keywords), NOT to the
// `Keyword2` accent slot that would follow the descriptor's label.
// Two-way collapse of WORD (5) + WORD3 (11) ŌåÆ Keyword mirrors the
// same discipline as Erlang's KEYWORD + BIFS ŌåÆ Keyword collapse
// (two class-membership categories with the same semantic weight
// share the primary slot).
//
// **Slot rationale:**
//   - COMMENT (1) + COMMENTLINE (2) + COMMENTDOC (3) ŌåÆ Comment
//     (italic). Three comment states collapse ŌĆö `/* ... */`
//     block, `// ...` line, and the orphan `/** ... */` doc-block
//     variant that the current lexer never emits (mapped for
//     forward-compat if upstream re-enables the entry).
//   - NUMBER (4) ŌåÆ Number.
//   - WORD (5) ŌåÆ Keyword (bold ŌĆö primary keyword vocabulary:
//     declarations `var` / `const` / `struct`, booleans
//     `true` / `false` / `nil`, exit statements `return` /
//     `break`, boolean operators `and` / `or` / `not`).
//   - STRING (6) ŌåÆ String.
//   - OPERATOR (7) ŌåÆ Operator (restricted set: `+ - * / = < >
//     & | ! ? :`).
//   - BRACE (9) ŌåÆ Operator (structural braces `{ }` ŌĆö LexEScript
//     splits them from OPERATOR but semantically they're
//     punctuation; collapse to the same slot).
//   - WORD2 (10) ŌåÆ Keyword2 (intrinsic-function accent ŌĆö POL
//     `basic.em` / `uo.em` / `os.em` module intrinsics).
//   - WORD3 (11) ŌåÆ Keyword (bold ŌĆö fold-critical control-flow
//     keywords, semantic collapse with WORD despite the
//     descriptor's "user-defined functions" label).
const ESCRIPT_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_ESCRIPT_COMMENT, StyleSlot::Comment),
    (SCE_ESCRIPT_COMMENTLINE, StyleSlot::Comment),
    (SCE_ESCRIPT_COMMENTDOC, StyleSlot::Comment),
    (SCE_ESCRIPT_NUMBER, StyleSlot::Number),
    (SCE_ESCRIPT_WORD, StyleSlot::Keyword),
    (SCE_ESCRIPT_STRING, StyleSlot::String),
    (SCE_ESCRIPT_OPERATOR, StyleSlot::Operator),
    (SCE_ESCRIPT_BRACE, StyleSlot::Operator),
    (SCE_ESCRIPT_WORD2, StyleSlot::Keyword2),
    (SCE_ESCRIPT_WORD3, StyleSlot::Keyword),
];

// Italic on all three comment states ŌĆö universal Code++ comment
// convention. COMMENTDOC (3) is orphan per source but included for
// forward-compat.
const ESCRIPT_ITALIC: &[usize] = &[
    SCE_ESCRIPT_COMMENT,
    SCE_ESCRIPT_COMMENTLINE,
    SCE_ESCRIPT_COMMENTDOC,
];

// Bold on WORD (5) + WORD3 (11) ŌĆö both semantically "language
// keywords" despite the descriptor's misleading class-2 label.
// Same discipline as Erlang KEYWORD + BIFS ŌåÆ Keyword (two related
// classes share bold).
const ESCRIPT_BOLD: &[usize] = &[SCE_ESCRIPT_WORD, SCE_ESCRIPT_WORD3];

// Three-class install matches `ESCRIPTWordLists[]` at
// `LexEScript.cxx:270-275`. Order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and the
// identifier classifier at `:92-97` probes class 0 first, class 1
// second, class 2 third (first-match-wins cascade). This means a
// token duplicated in class 0 wins over its class-2 sibling ŌĆö the
// wordlist invariants pin cross-list disjointness to prevent a
// fold-critical token from being silently downgraded to WORD.
const ESCRIPT_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, ESCRIPT_KEYWORDS),
        (1, ESCRIPT_INTRINSICS),
        (2, ESCRIPT_FOLDWORDS),
    ],
    styles: ESCRIPT_STYLES,
    italic: ESCRIPT_ITALIC,
    bold: ESCRIPT_BOLD,
};

// --- LexForth ---
// LexForth serves Forth ŌĆö the stack-based concatenative
// programming language, extension `.forth`. `L_FORTH` (id 73) is
// the only language row using this lexer. Dispatches SCLEX_FORTH
// (= 52, per `SciLexer.h:68`) via a six-class wordlist descriptor
// at `LexForth.cxx:161-169`.
//
// **10 style mappings** covering every SCE_FORTH_* state the paint
// loop actually emits. Two of the 12 defined slots stay unmapped:
//   - DEFAULT (0) ŌĆö whitespace / unclassified.
//   - IDENTIFIER (3) ŌĆö transient bare-identifier state that
//     settles to CONTROL / KEYWORD / DEFWORD / PREWORD1 /
//     PREWORD2 / STRING / DEFAULT before commit. Framework
//     convention: leave unmapped so unmatched bare words paint
//     at STYLE_DEFAULT.
//
// **Six-class descriptor is the widest of Phase 4.5** (tied with
// Erlang's six-class set). LexForth uses class-slot granularity
// to express Forth's traditional word categorization: structural
// control-flow, general vocabulary, definition words, and two
// tiers of compile-time next-token consumers.
//
// **Slot rationale:**
//   - COMMENT (1) + COMMENT_ML (2) ŌåÆ Comment (italic). Line
//     comments start with `\ ` (whitespace-delimited backslash);
//     block comments use `( ... )`. Both are semantically
//     comments and share the italic slot.
//   - CONTROL (4) + KEYWORD (5) ŌåÆ Keyword (bold). Two class
//     categories collapse to the primary bold slot ŌĆö control-
//     flow structural words and general runtime vocabulary
//     both read as "language keywords". Same collapse
//     discipline as Erlang's KEYWORD + BIFS ŌåÆ Keyword, and
//     ESCRIPT's WORD + WORD3 ŌåÆ Keyword.
//   - DEFWORD (6) ŌåÆ Keyword2 (accent). Definition words that
//     create new dictionary entries deserve the accent color
//     to visually mark word-boundary events. Also styles the
//     auto-emitted `:` and `;` markers at LexForth.cxx:138-149.
//   - PREWORD1 (7) + PREWORD2 (8) ŌåÆ Preprocessor. Two tiers
//     of compile-time next-token consumers collapse to the
//     preprocessor slot ŌĆö semantically equivalent to Erlang's
//     `-`-prefixed preprocessor + module-attribute pair
//     (PREPROC + MODULES_ATT ŌåÆ Preprocessor).
//   - NUMBER (9) ŌåÆ Number.
//   - STRING (10) ŌåÆ String.
//   - LOCALE (11) ŌåÆ Keyword2. Forth-2012 `{ name1 name2 ... }`
//     local-variable declarations. Keyword2 accent matches
//     DEFWORD since locals define named bindings, semantically
//     a lightweight definition form.
const FORTH_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_FORTH_COMMENT, StyleSlot::Comment),
    (SCE_FORTH_COMMENT_ML, StyleSlot::Comment),
    (SCE_FORTH_CONTROL, StyleSlot::Keyword),
    (SCE_FORTH_KEYWORD, StyleSlot::Keyword),
    (SCE_FORTH_DEFWORD, StyleSlot::Keyword2),
    (SCE_FORTH_PREWORD1, StyleSlot::Preprocessor),
    (SCE_FORTH_PREWORD2, StyleSlot::Preprocessor),
    (SCE_FORTH_NUMBER, StyleSlot::Number),
    (SCE_FORTH_STRING, StyleSlot::String),
    (SCE_FORTH_LOCALE, StyleSlot::Keyword2),
];

// Italic on both comment states ŌĆö universal Code++ comment
// convention.
const FORTH_ITALIC: &[usize] = &[SCE_FORTH_COMMENT, SCE_FORTH_COMMENT_ML];

// Bold on CONTROL + KEYWORD ŌĆö the two "language vocabulary"
// classes semantically collapsed. Same discipline as Erlang
// KEYWORD + BIFS ŌåÆ bold, ESCRIPT WORD + WORD3 ŌåÆ bold.
const FORTH_BOLD: &[usize] = &[SCE_FORTH_CONTROL, SCE_FORTH_KEYWORD];

// Six-class install matches `forthWordLists[]` at
// `LexForth.cxx:161-169`. Order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and the
// identifier classifier at `:75-88` probes class 0 ŌåÆ 5 in exactly
// this order first-match-wins. A token duplicated in an earlier
// class silently wins over its later-class sibling, so
// cross-class disjointness is required for correct styling; the
// invariant test enforces this pairwise across all 15 class
// pairs.
const FORTH_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, FORTH_CONTROL),
        (1, FORTH_KEYWORD),
        (2, FORTH_DEFWORD),
        (3, FORTH_PREWORD1),
        (4, FORTH_PREWORD2),
        (5, FORTH_STRINGS),
    ],
    styles: FORTH_STYLES,
    italic: FORTH_ITALIC,
    bold: FORTH_BOLD,
};

// --- LexMMIXAL ---
// LexMMIXAL serves MMIXAL ŌĆö Donald Knuth's MMIX assembly language
// from The Art of Computer Programming Vol 1 Fascicle 1, extension
// `.mms`. `L_MMIXAL` (id 75) is the only language row using this
// lexer. Dispatches SCLEX_MMIXAL (= 44, per `SciLexer.h:60`) via
// a three-class wordlist descriptor at `LexMMIXAL.cxx:178-183`.
//
// **11 style mappings** covering every SCE_MMIXAL_* state the
// paint loop reliably emits as a semantically visible token.
// Seven of the 18 defined slots stay unmapped:
//   - LEADWS (0) ŌĆö leading-whitespace entry state per line.
//   - OPCODE (3) ŌĆö transient collect state for the opcode
//     mnemonic; settles to OPCODE_VALID or OPCODE_UNKNOWN.
//   - OPCODE_PRE (4) ŌĆö transient whitespace between label and
//     opcode.
//   - OPCODE_UNKNOWN (6) ŌĆö opcode mnemonic that missed the
//     opcodes wordlist. Leave unmapped so unrecognized
//     opcodes paint at STYLE_DEFAULT ŌĆö a MMIXAL source file
//     with user-defined macros or an incomplete wordlist
//     should show those tokens plainly rather than mis-styled.
//     **Deliberately excluded from the deferred-`StyleSlot::Error`
//     migration list** (SCE_H_SGML_ERROR / SCE_SQL_COMMENTDOCKEYWORDERROR
//     / STRINGEOL family / SCE_PL_ERROR / ŌĆ”) because user
//     macros legitimately hit this state ŌĆö unlike STRINGEOL /
//     *_ERROR which are unambiguous parse failures. If a
//     future `StyleSlot::Error` migration lands, do NOT sweep
//     `SCE_MMIXAL_OPCODE_UNKNOWN` into it; the "invalid"
//     signal here is ambiguous, not authoritative.
//   - OPCODE_POST (7) ŌĆö transient state after opcode
//     validation.
//   - OPERANDS (8) ŌĆö transient dispatch state between operands.
//   - REF (10) ŌĆö bare identifier that missed both class 1
//     (special_register) and class 2 (predef_symbols). Almost
//     always a user-defined label reference ŌĆö paint at
//     STYLE_DEFAULT so the label reads plainly.
//
// **Three-class descriptor** (like CSound / ESCRIPT). LexMMIXAL
// splits its identifiable tokens into opcodes (class 0),
// special registers (class 1), and predefined symbols (class 2)
// ŌĆö the three "vocabulary" categories MMIXAL programmers rely
// on. All three are byte-exact `sc.GetCurrent(s, ...)` probes,
// not `GetCurrentLowered`.
//
// **Slot rationale:**
//   - COMMENT (1) ŌåÆ Comment (italic). MMIXAL comments are
//     everything on a line after the operands (no leading
//     comment char required ŌĆö the lexer switches to COMMENT
//     state as soon as whitespace-terminated operand parsing
//     ends at `:156-157`, and any line whose first non-space
//     token isn't word-like enters COMMENT at `:74-75`).
//   - LABEL (2) ŌåÆ Keyword2 (accent). Column-0 label
//     declarations mark the start of a symbolic address ŌĆö
//     semantically a definition. Same accent-slot treatment
//     as Forth's DEFWORD and ESCRIPT's WORD2 (types).
//   - OPCODE_VALID (5) ŌåÆ Keyword (bold). The CPU instruction
//     mnemonics ŌĆö the visual anchor of any assembly source.
//     Bold on the primary-vocabulary class matches CSound's
//     OPCODE ŌåÆ bold ŌĆö the closest three-class sibling using
//     single-class bold. (Larger-class lexers pair a second
//     class into bold: Erlang KEYWORD+BIFS, ESCRIPT WORD+WORD3,
//     Forth CONTROL+KEYWORD.) MMIXAL's `OPCODE_UNKNOWN` sibling
//     stays unmapped so unrecognized opcode-position tokens
//     paint at STYLE_DEFAULT, keeping bold reserved for
//     wordlist-validated CPU mnemonics only.
//   - NUMBER (9) + HEX (14) ŌåÆ Number. `#`-prefixed hex and
//     decimal are both numeric literals.
//   - CHAR (11) + STRING (12) ŌåÆ String. `'a'` char literal and
//     `"..."` string literal are both quoted-literal forms.
//   - REGISTER (13) ŌåÆ Keyword2. Two entry paths converge on
//     this state: `$`-prefixed numeric registers via `:166-167`
//     and named special registers (`rA`, `rZZ`) via the REF
//     settle at `:109-110`. Both are addressing-mode markers
//     that name storage ŌĆö accent slot matches LABEL and SYMBOL.
//   - OPERATOR (15) ŌåÆ Operator. `+-|^*/%<>&~$,()[]` from
//     `isMMIXALOperator` at `:39-49`.
//   - SYMBOL (16) ŌåÆ Keyword2. Predefined symbol via REF hit on
//     class 2 (`Fputs`, `StdOut`, `ROUND_NEAR`). Same accent as
//     LABEL and REGISTER ŌĆö these are all named-storage or
//     named-value markers semantically.
//   - INCLUDE (17) ŌåÆ Preprocessor. `@include` directive ŌĆö the
//     one MMIXAL preprocessor mechanism.
const MMIXAL_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_MMIXAL_COMMENT, StyleSlot::Comment),
    (SCE_MMIXAL_LABEL, StyleSlot::Keyword2),
    (SCE_MMIXAL_OPCODE_VALID, StyleSlot::Keyword),
    (SCE_MMIXAL_NUMBER, StyleSlot::Number),
    (SCE_MMIXAL_CHAR, StyleSlot::String),
    (SCE_MMIXAL_STRING, StyleSlot::String),
    (SCE_MMIXAL_REGISTER, StyleSlot::Keyword2),
    (SCE_MMIXAL_HEX, StyleSlot::Number),
    (SCE_MMIXAL_OPERATOR, StyleSlot::Operator),
    (SCE_MMIXAL_SYMBOL, StyleSlot::Keyword2),
    (SCE_MMIXAL_INCLUDE, StyleSlot::Preprocessor),
];

// Italic on comment ŌĆö universal Code++ comment convention.
const MMIXAL_ITALIC: &[usize] = &[SCE_MMIXAL_COMMENT];

// Bold on OPCODE_VALID only ŌĆö the CPU instruction mnemonics
// are the visual anchor of assembly source. Same
// single-class-bold shape as CSound's OPCODE (its closest
// three-class sibling); larger-class lexers pair a second
// class in (Erlang KEYWORD+BIFS, ESCRIPT WORD+WORD3, Forth
// CONTROL+KEYWORD), but MMIXAL's three-class descriptor
// doesn't have a natural second-vocabulary-class sibling to
// pair here ŌĆö special_register (class 1) and predef_symbols
// (class 2) both live in the accent slot (Keyword2), not the
// bold slot.
const MMIXAL_BOLD: &[usize] = &[SCE_MMIXAL_OPCODE_VALID];

// Three-class install matches `MMIXALWordListDesc[]` at
// `LexMMIXAL.cxx:178-183`. Order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and the
// REF settle at `:101-115` probes class 1 before class 2
// first-match-wins; class 0 (opcodes) is probed in a distinct
// state (OPCODE) so its cross-class disjointness with 1 and 2 is
// definitional (an OPCODE-state probe cannot cross into a REF-
// state probe). The invariant test enforces disjointness across
// all three pairs anyway.
const MMIXAL_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, MMIXAL_OPCODES),
        (1, MMIXAL_SPECIAL_REGISTERS),
        (2, MMIXAL_PREDEF_SYMBOLS),
    ],
    styles: MMIXAL_STYLES,
    italic: MMIXAL_ITALIC,
    bold: MMIXAL_BOLD,
};

// --- LexNim ---
// LexNim serves Nim ŌĆö the statically-typed compiled systems
// programming language with Python-like indentation-based
// syntax, extension `.nim`. `L_NIM` (id 76) is the only
// language row using this lexer. Dispatches SCLEX_NIM (= 126,
// per `SciLexer.h:142`) via a single-class wordlist descriptor
// at `LexNim.cxx:182-185`.
//
// **13 style mappings** covering every SCE_NIM_* state the
// paint loop emits as a semantically visible token. Four of
// the 17 defined slots stay unmapped:
//   - DEFAULT (0) ŌĆö whitespace / unclassified.
//   - STRINGEOL (13) ŌĆö unterminated backtick def-name
//     (FUNCNAME source, `LexNim.cxx:495`) / string (`:555`) /
//     char (`:567`) / backticks (`:575`) that hit
//     end-of-line ŌĆö four distinct paint-loop sources.
//     Deliberately excluded from the visible-style set;
//     belongs to the deferred-`StyleSlot::Error` migration
//     list (SCE_H_SGML_ERROR / SCE_SQL_COMMENTDOCKEYWORDERROR
//     / SCE_B_STRINGEOL / SCE_PL_ERROR / ŌĆ”) tracked at the
//     sibling-lexer sites. When `StyleSlot::Error` lands,
//     sweep this into it with the rest of the STRINGEOL /
//     *_ERROR family ŌĆö the signal here IS authoritative
//     (parse failure), unlike MMIXAL's `OPCODE_UNKNOWN` which
//     is ambiguous.
//   - NUMERROR (14) ŌĆö malformed numeric literal. Same
//     deferred-`StyleSlot::Error` family as STRINGEOL ŌĆö
//     authoritative parse failure, sweep into `StyleSlot::Error`
//     when that migration lands.
//   - IDENTIFIER (16) ŌĆö transient identifier-collect state
//     entered at `:690`, settles to WORD / FUNCNAME /
//     stays-IDENTIFIER at `:446-465` on completion. Framework
//     convention: leave unmapped so unmatched bare identifiers
//     paint at STYLE_DEFAULT.
//
// **Single-class descriptor** ŌĆö the sole wordlist is just
// `"Keywords"`. `LexRust` is the only other same-family
// theme in this file that stays single-class (Python /
// Lua / most Phase 4.5 hosts install Ōēź 2 wordlist classes;
// see `PYTHON_THEME` / `LUA_THEME` above). `LexNim` expresses
// its entire vocabulary through paint-loop mechanics: comments
// have four sub-styles distinguished by the `#`/`##`/`#[`/
// `##[` prefix, strings have **four** sub-styles (`STRING` +
// `CHARACTER` + `TRIPLE` + `TRIPLEDOUBLE`) distinguished by
// delimiter shape (BACKTICKS is a separate "operator
// definition" state per `LexNim.cxx:213`, not a string), and
// the identifier-vs-keyword-vs-definition-name distinction is
// fully paint-loop-driven. The single wordlist just says
// "which identifier tokens are reserved keywords" ŌĆö one class
// is enough.
//
// **Slot rationale:**
//   - COMMENT + COMMENTDOC + COMMENTLINE + COMMENTLINEDOC ŌåÆ
//     Comment (italic). All four comment sub-styles collapse
//     to the italic slot ŌĆö same discipline as Rust's
//     `COMMENTBLOCK` + `COMMENTLINE` + `COMMENTBLOCKDOC` +
//     `COMMENTLINEDOC` four-way collapse (see `RUST_STYLES`
//     above).
//   - WORD ŌåÆ Keyword (bold). The reserved-keyword hits (one
//     of 66 tokens per Nim manual ┬¦3.2) ŌĆö the visual anchor
//     for control flow, declarations, and word operators.
//     Bold matches Rust's `RUST_WORD` ŌåÆ bold ŌĆö the closest
//     genuinely single-class sibling.
//   - STRING + CHARACTER + TRIPLE + TRIPLEDOUBLE ŌåÆ String.
//     Four string variants ŌĆö bare double-quote, single-quote
//     char, triple-single-quote, triple-double-quote ŌĆö all
//     read as "quoted-literal" semantically and collapse to
//     the shared String slot. Same discipline as Rust's
//     `STRING` + `CHARACTER` ŌåÆ String pair, extended for
//     Nim's richer string syntax.
//   - BACKTICKS ŌåÆ Keyword2 (accent). At `LexNim.cxx:681-687`,
//     the paint loop enters BACKTICKS ONLY when the backtick
//     span is NOT immediately following one of the seven
//     routine-def keywords (proc/func/macro/method/template/
//     iterator/converter tracked by `funcNameExists` via
//     `IsFuncName` at `:85-103`) ŌĆö def-position backtick
//     spans go to FUNCNAME instead (`:682-683`). So
//     BACKTICKS covers **identifier references** that escape
//     reserved words / symbolic operators for use in
//     identifier position (e.g. the `` `+` `` in
//     `a.` + `(b)`, or `` `if` `` used as a variable name in
//     `let `` `if` `` = 5`). It is NOT a definition marker ŌĆö
//     LexNim's own `lexicalClasses[]` row at `:213` has
//     category tag "operator definition" but display-name
//     "Identifiers"; the display column is the semantic
//     truth. Keyword2 here is a visual-disambiguation
//     compromise: the framework has no dedicated
//     "identifier accent" slot and backtick-quoted
//     identifiers are a distinctive Nim form worth
//     surfacing. **TODO:** if Keyword2 is later specialized
//     for definition markers (e.g. bold-italic on
//     FUNCNAME/DEFWORD/LABEL/WORD2 in a future theme pass),
//     revisit BACKTICKS ŌĆö reference sites would then inherit
//     definition styling, which is semantically wrong.
//   - FUNCNAME ŌåÆ Keyword2 (accent). Auto-styled identifier
//     immediately following a definition keyword (`proc`/
//     `func`/`macro`/`method`/`template`/`iterator`/
//     `converter`) or a backtick-quoted def-position span
//     from `:682-683`. Names a new routine ŌĆö accent color
//     visually marks the definition event. Same slot as
//     Forth's DEFWORD, ESCRIPT's WORD2, MMIXAL's LABEL.
//     BACKTICKS above lands in the same visible slot for a
//     different reason (visual disambiguation of the
//     backtick-quoted identifier form, not a shared
//     definition-marker semantic).
//   - NUMBER ŌåÆ Number.
//   - OPERATOR ŌåÆ Operator. Nim's symbolic operator set from
//     `:713` (`"()[]{}:=;-\\/&%$!+<>|^?,.*~@"`); the word
//     operators `and`/`or`/`not`/`xor`/`shl`/`shr`/`div`/
//     `mod`/`in`/`notin`/`is`/`isnot`/`of`/`as`/`from` route
//     through WORD (not OPERATOR) because they're reserved
//     keywords collected by the identifier path.
const NIM_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_NIM_COMMENT, StyleSlot::Comment),
    (SCE_NIM_COMMENTDOC, StyleSlot::Comment),
    (SCE_NIM_COMMENTLINE, StyleSlot::Comment),
    (SCE_NIM_COMMENTLINEDOC, StyleSlot::Comment),
    (SCE_NIM_NUMBER, StyleSlot::Number),
    (SCE_NIM_STRING, StyleSlot::String),
    (SCE_NIM_CHARACTER, StyleSlot::String),
    (SCE_NIM_WORD, StyleSlot::Keyword),
    (SCE_NIM_TRIPLE, StyleSlot::String),
    (SCE_NIM_TRIPLEDOUBLE, StyleSlot::String),
    (SCE_NIM_BACKTICKS, StyleSlot::Keyword2),
    (SCE_NIM_FUNCNAME, StyleSlot::Keyword2),
    (SCE_NIM_OPERATOR, StyleSlot::Operator),
];

// Italic on all four comment states ŌĆö universal Code++ comment
// convention.
const NIM_ITALIC: &[usize] = &[
    SCE_NIM_COMMENT,
    SCE_NIM_COMMENTDOC,
    SCE_NIM_COMMENTLINE,
    SCE_NIM_COMMENTLINEDOC,
];

// Bold on WORD only ŌĆö the reserved-keyword hits. Same
// single-class-bold shape as Rust's `RUST_WORD` ŌåÆ bold ŌĆö
// `LexRust` is the closest genuinely single-class sibling in
// this file (Python's `LexPython` has 2 wordlists, Lua's
// `LexLua` has 8 ŌĆö neither is single-class).
const NIM_BOLD: &[usize] = &[SCE_NIM_WORD];

// Single-class install matches `nimWordListDesc[]` at
// `LexNim.cxx:182-185` ŌĆö one wordlist, `"Keywords"`. Order is
// trivially load-bearing (only one class exists); the
// framework's invariant-test discipline still pins the single
// class's index (0) and the wordlist content.
const NIM_THEME: LangTheme = LangTheme {
    keywords: &[(0, NIM_KEYWORDS)],
    styles: NIM_STYLES,
    italic: NIM_ITALIC,
    bold: NIM_BOLD,
};

// --- LexNncrontab ---
// LexNncrontab (compiled from `LexCrontab.cxx`) serves NNCrontab
// ŌĆö nnCron's extended crontab format for a Windows scheduler /
// event monitor by Nick Nemtsev. Extension `.tab`. `L_NNCRONTAB`
// (id 77) is the only language row using this lexer. Dispatches
// SCLEX_NNCRONTAB (= 26, per `SciLexer.h:44`) via a three-class
// wordlist descriptor at `LexCrontab.cxx:220-225`.
//
// **9 style mappings** covering every SCE_NNCRONTAB_* state
// the paint loop emits as a semantically visible token. Two
// slots stay unmapped:
//   - DEFAULT (0) ŌĆö whitespace / unclassified / unmatched
//     identifier. Framework convention: leave unmapped so
//     unmatched bare identifiers paint at STYLE_DEFAULT.
//   - IDENTIFIER (10) ŌĆö transient collect state entered at
//     `LexCrontab.cxx:102-106`, settles to SECTION / KEYWORD /
//     MODIFIER / DEFAULT at `:185-196`. Framework convention:
//     leave unmapped.
//
// **Three-class descriptor.** The wordlist descriptor names the
// classes `"Section keywords and Forth words"` (class 0),
// `"nnCrontab keywords"` (class 1), and `"Modifiers"` (class 2).
// `LexCrontab.cxx:185-196` probes classes 0 ŌåÆ 1 ŌåÆ 2 in exact
// order first-match-wins ŌĆö cross-class disjointness is
// required, enforced by the invariant test.
//
// **Slot rationale:**
//   - COMMENT (1) ŌåÆ Comment (italic). `#`-to-EOL and
//     `\ `-to-EOL line comments (nnCron / Forth conventions).
//   - TASK (2) ŌåÆ Preprocessor. `#(` / `)#` task-delimiter
//     markers structurally frame each task definition ŌĆö
//     preprocessor slot matches similar "meta-file-structure"
//     markers in sibling lexers (e.g. NSIS section headers,
//     `@include` in MMIXAL).
//   - SECTION (3) ŌåÆ Keyword (bold). nnCron section markers
//     (`Task`/`Time`/`Rule`/`When`) and Forth control words
//     (`IF`/`THEN`/`DO`/`LOOP`) ŌĆö the structural vocabulary of
//     a task definition. Bold matches other primary-keyword
//     slots (Forth CONTROL, MMIXAL OPCODE_VALID, Erlang
//     KEYWORD).
//   - KEYWORD (4) ŌåÆ Keyword (bold). nnCron's directive
//     vocabulary (`RUN`/`FILE-COPY`/`WIN-ACTIVATE`) ŌĆö action
//     verbs and built-in variable readers. Collapses to the
//     same bold slot as SECTION; both classes are "language
//     vocabulary" semantically and the collapse discipline
//     matches Forth CONTROL + KEYWORD ŌåÆ bold.
//   - MODIFIER (5) ŌåÆ Keyword2 (accent). Task-execution
//     modifiers (`HighPriority`, `ShowMaximized`, `RunOnce`,
//     `WatchSubtree`) that qualify how a task or watch
//     directive behaves. Accent color visually distinguishes
//     modifiers from action verbs.
//   - ASTERISK (6) ŌåÆ Operator. The `*` cron wildcard ŌĆö
//     "match every value in this field" is semantically an
//     operator on the time-field grammar.
//   - NUMBER (7) ŌåÆ Number.
//   - STRING (8) ŌåÆ String.
//   - ENVIRONMENT (9) ŌåÆ Keyword2 (accent). `%VAR%` and
//     `<%VAR%>` environment-variable expansions are
//     named-value references ŌĆö accent slot matches similar
//     named-value markers (MMIXAL SYMBOL, Nim FUNCNAME).
const NNCRONTAB_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_NNCRONTAB_COMMENT, StyleSlot::Comment),
    (SCE_NNCRONTAB_TASK, StyleSlot::Preprocessor),
    (SCE_NNCRONTAB_SECTION, StyleSlot::Keyword),
    (SCE_NNCRONTAB_KEYWORD, StyleSlot::Keyword),
    (SCE_NNCRONTAB_MODIFIER, StyleSlot::Keyword2),
    (SCE_NNCRONTAB_ASTERISK, StyleSlot::Operator),
    (SCE_NNCRONTAB_NUMBER, StyleSlot::Number),
    (SCE_NNCRONTAB_STRING, StyleSlot::String),
    (SCE_NNCRONTAB_ENVIRONMENT, StyleSlot::Keyword2),
];

// Italic on COMMENT ŌĆö universal Code++ comment convention.
const NNCRONTAB_ITALIC: &[usize] = &[SCE_NNCRONTAB_COMMENT];

// Bold on SECTION + KEYWORD ŌĆö two "language vocabulary"
// classes semantically collapsed to bold. Same discipline as
// Forth CONTROL + KEYWORD ŌåÆ bold and Erlang KEYWORD + BIFS ŌåÆ
// bold.
const NNCRONTAB_BOLD: &[usize] = &[SCE_NNCRONTAB_SECTION, SCE_NNCRONTAB_KEYWORD];

// Three-class install matches `cronWordListDesc[]` at
// `LexCrontab.cxx:220-225`. Order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and
// `LexCrontab.cxx:185-196`'s InList cascade probes classes 0 ŌåÆ
// 1 ŌåÆ 2 first-match-wins. A token duplicated in an earlier
// class silently masks its later-class sibling; the invariant
// test enforces pairwise cross-class disjointness across all
// three pairs.
const NNCRONTAB_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, NNCRONTAB_SECTIONS),
        (1, NNCRONTAB_KEYWORDS),
        (2, NNCRONTAB_MODIFIERS),
    ],
    styles: NNCRONTAB_STYLES,
    italic: NNCRONTAB_ITALIC,
    bold: NNCRONTAB_BOLD,
};

// --- LexOScript ---
// LexOScript serves OScript ŌĆö the object-oriented programming
// language for OpenText `Livelink` (now OpenText Content Server),
// extension `.osx`. `L_OSCRIPT` (id 78) is the only language row
// using this lexer. Dispatches SCLEX_OSCRIPT (= 106, per
// `SciLexer.h:122`) via a **six-class wordlist** descriptor at
// `LexOScript.cxx:539-547`. Tied with Forth and Erlang for the
// widest wordlist descriptor of Phase 4.5.
//
// **17 style mappings** covering every SCE_OSCRIPT_* state the
// paint loop emits as a semantically visible token. Two of
// the 19 defined slots stay unmapped:
//   - DEFAULT (0) ŌĆö whitespace / unclassified.
//   - IDENTIFIER (9) ŌĆö transient bare-identifier collect state.
//     Settles to a specific style at `:232-250` via the
//     `IdentifierClassifier` at `:132-181`. Framework
//     convention: leave unmapped so unmatched bare identifiers
//     paint at STYLE_DEFAULT.
//
// **PROPERTY (17) IS a visible paint state**, not a transient
// collect state. `LexOScript.cxx:255-266` exits PROPERTY via
// `SetState(DEFAULT)` with only a conditional
// `ChangeState(METHOD)` guarded by `sc.Match('(')` at `:262`.
// When the identifier is NOT followed by `(` ŌĆö the very common
// `obj.propertyName := ...`, `dapi.rootNode.title`, `msg.body`
// idiom ŌĆö the range commits with state 17 (PROPERTY) and
// paints as its mapped style. Both PROPERTY (bare access) and
// METHOD (call site) get Keyword2 accent ŌĆö otherwise `obj`
// would style but `.prop` and `.method(...)` would fall to
// STYLE_DEFAULT for the bare-access half.
//
// **Six-class descriptor** (tied with Forth 6 and Erlang 6 for
// widest of Phase 4.5). LexOScript uses class-slot granularity
// to categorize OScript's rich vocabulary: syntactic keywords,
// value literals (TRUE/FALSE/undefined constants), word operators
// (and/or/eq/ne), built-in types (Integer/String), library
// functions (Echo/Length), and Livelink singletons (DAPI/WAPI).
//
// **Case-INSENSITIVE.** LexOScript calls `sc.GetCurrentLowered`
// on both classification paths ŌĆö the paren-path at `:141`
// (inside `if (sc.Match('('))` at `:139-153`) and the no-paren
// path at `:156` (inside the `else` at `:154-180`) ŌĆö so
// wordlist tokens must be lowercase. Same discipline as
// PASCAL_KEYWORDS / ESCRIPT_KEYWORDS / FORTH_KEYWORD.
//
// **Two-phase classifier.** `IdentifierClassifier` at
// `:132-181` dispatches by syntactic context:
//   - **Parenthesis path** (`sc.Match('(')`): probes KEYWORD ŌåÆ
//     OPERATOR ŌåÆ FUNCTION ŌåÆ METHOD (default). Any identifier
//     followed by `(` is treated as a call site.
//   - **Dot-suffix path** (`sc.Match('.') && objects.InList`):
//     probes OBJECT only. If matched, the `.` becomes
//     OPERATOR.
//   - **No-paren, no-dot path**: probes KEYWORD ŌåÆ CONSTANT ŌåÆ
//     OPERATOR ŌåÆ TYPE ŌåÆ FUNCTION in order via `sc.ChangeState`.
//     If any probe hits, the identifier's state moves to the
//     matched class; if ALL miss, the identifier span STAYS
//     as `SCE_OSCRIPT_IDENTIFIER` (9) ŌĆö the trailing
//     `SetState(DEFAULT)` at `:178` sets the state that begins
//     at the NEXT character, not this one. The wordlist-miss
//     path only paints as STYLE_DEFAULT because
//     `SCE_OSCRIPT_IDENTIFIER` is unmapped in `OSCRIPT_STYLES`
//     (framework convention).
//
// **Slot rationale:**
//   - LINE_COMMENT (1) + BLOCK_COMMENT (2) + DOC_COMMENT (3) ŌåÆ
//     Comment (italic). All three comment sub-styles collapse
//     to the italic slot. DOC_COMMENT covers the
//     `#ifdef DOC ... #endif` conditional-preprocessor
//     documentation block.
//   - PREPROCESSOR (4) ŌåÆ Preprocessor. OScript's
//     `#ifdef`/`#ifndef`/`#endif` directives.
//   - NUMBER (5) ŌåÆ Number.
//   - SINGLEQUOTE_STRING (6) + DOUBLEQUOTE_STRING (7) ŌåÆ String.
//   - CONSTANT (8) ŌåÆ Keyword2 (accent). Literal-value
//     constants (TRUE/FALSE/undefined) plus the *Type
//     identifier constants used in reflection.
//   - GLOBAL (10) ŌåÆ Keyword2 (accent). `$xxx` / `$$xxx`
//     process/thread-global variables. Named-value marker,
//     matches CONSTANT accent slot.
//   - KEYWORD (11) ŌåÆ Keyword (bold). Reserved words and
//     control-flow keywords ŌĆö the visual anchor.
//   - OPERATOR (12) ŌåÆ Operator. Symbolic operators plus word
//     operators from wordlist class 2 (and/or/not/xor/eq/ne
//     etc.).
//   - LABEL (13) ŌåÆ Keyword2 (accent). Column-0
//     `identifier:` label ŌĆö auto-styled without wordlist
//     lookup. Matches other label-like markers (MMIXAL LABEL,
//     Nim FUNCNAME).
//   - TYPE (14) ŌåÆ Keyword2 (accent). Built-in value and
//     reference types.
//   - FUNCTION (15) ŌåÆ Keyword2 (accent). Built-in global
//     functions and unclassified call-site identifiers via
//     the paren-path FUNCTION probe.
//   - OBJECT (16) ŌåÆ Keyword2 (accent). Livelink singleton
//     identifiers (DAPI/WAPI/etc.) when followed by `.`.
//   - PROPERTY (17) ŌåÆ Keyword2 (accent). Bare property
//     access `.identifier` NOT followed by `(` ŌĆö settles from
//     the PROPERTY collect state at `LexOScript.cxx:255-266`
//     via `SetState(DEFAULT)`, committing the identifier span
//     with state 17. Accent matches OBJECT / METHOD so the
//     three components of an `obj.prop.method(...)` chain all
//     get consistent styling.
//   - METHOD (18) ŌåÆ Keyword2 (accent). Auto-styled method
//     names ŌĆö either the paren-path default at `:150-151`
//     when the identifier is followed by `(` and misses all
//     wordlists, or a PROPERTY upgraded to METHOD at
//     `:262-263` when followed by `(`.
const OSCRIPT_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_OSCRIPT_LINE_COMMENT, StyleSlot::Comment),
    (SCE_OSCRIPT_BLOCK_COMMENT, StyleSlot::Comment),
    (SCE_OSCRIPT_DOC_COMMENT, StyleSlot::Comment),
    (SCE_OSCRIPT_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_OSCRIPT_NUMBER, StyleSlot::Number),
    (SCE_OSCRIPT_SINGLEQUOTE_STRING, StyleSlot::String),
    (SCE_OSCRIPT_DOUBLEQUOTE_STRING, StyleSlot::String),
    (SCE_OSCRIPT_CONSTANT, StyleSlot::Keyword2),
    (SCE_OSCRIPT_GLOBAL, StyleSlot::Keyword2),
    (SCE_OSCRIPT_KEYWORD, StyleSlot::Keyword),
    (SCE_OSCRIPT_OPERATOR, StyleSlot::Operator),
    (SCE_OSCRIPT_LABEL, StyleSlot::Keyword2),
    (SCE_OSCRIPT_TYPE, StyleSlot::Keyword2),
    (SCE_OSCRIPT_FUNCTION, StyleSlot::Keyword2),
    (SCE_OSCRIPT_OBJECT, StyleSlot::Keyword2),
    (SCE_OSCRIPT_PROPERTY, StyleSlot::Keyword2),
    (SCE_OSCRIPT_METHOD, StyleSlot::Keyword2),
];

// Italic on all three comment sub-styles ŌĆö universal Code++
// comment convention.
const OSCRIPT_ITALIC: &[usize] = &[
    SCE_OSCRIPT_LINE_COMMENT,
    SCE_OSCRIPT_BLOCK_COMMENT,
    SCE_OSCRIPT_DOC_COMMENT,
];

// Bold on KEYWORD only ŌĆö reserved-word hits are the visual
// anchor. Same single-class-bold discipline as MMIXAL
// (OPCODE_VALID) and CSound (OPCODE) ŌĆö both six-class
// alternatives (Forth CONTROL+KEYWORD, Erlang KEYWORD+BIFS)
// pair a second class in, but OScript's six-class split
// distributes named-value markers across CONSTANT / TYPE /
// FUNCTION / OBJECT / METHOD (all Keyword2 accent) leaving
// KEYWORD as the natural single-class bold.
const OSCRIPT_BOLD: &[usize] = &[SCE_OSCRIPT_KEYWORD];

// Six-class install matches `oscriptWordListDesc[]` at
// `LexOScript.cxx:539-547`. Order is load-bearing ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order and the
// `IdentifierClassifier` cascade at `:132-181` probes:
//   - Paren path: KEYWORD (0) ŌåÆ OPERATOR (2) ŌåÆ FUNCTION (4).
//   - No-paren path: KEYWORD (0) ŌåÆ CONSTANT (1) ŌåÆ OPERATOR (2)
//     ŌåÆ TYPE (3) ŌåÆ FUNCTION (4).
//   - Dot-suffix path: OBJECT (5) only.
// Classes 0-4 share the no-paren cascade first-match-wins, so
// cross-class disjointness across those five classes is
// strictly enforced. Class 5 (OBJECT) is disjoint from 0-4 at
// the paint-loop level (dot-suffix vs no-dot syntactic
// contexts), so `script` and `file` legitimately appear in
// both TYPES (class 3) and OBJECTS (class 5) ŌĆö the invariant
// test relaxes cross-class disjointness for class-5 pairs.
const OSCRIPT_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, OSCRIPT_KEYWORDS),
        (1, OSCRIPT_CONSTANTS),
        (2, OSCRIPT_OPERATORS),
        (3, OSCRIPT_TYPES),
        (4, OSCRIPT_FUNCTIONS),
        (5, OSCRIPT_OBJECTS),
    ],
    styles: OSCRIPT_STYLES,
    italic: OSCRIPT_ITALIC,
    bold: OSCRIPT_BOLD,
};

// --- LexRebol ---
// LexRebol serves REBOL ŌĆö Carl Sassenrath's homoiconic
// message-passing dialect language (extensions `.reb` /
// `.rebol`). `L_REBOL` (id 79) is the only language row using
// this lexer. Dispatches SCLEX_REBOL (= 71, per
// `SciLexer.h:87`) via an eight-class wordlist at
// `LexRebol.cxx:74-81` (upstream registers only one descriptor
// slot at `:320-323` but the paint loop accesses all 8).
//
// **27 style mappings** covering every SCE_REBOL_* state the
// paint loop emits as a semantically visible token. Two of
// the 29 defined slots stay unmapped:
//   - DEFAULT (0) ŌĆö whitespace / unclassified.
//   - IDENTIFIER (20) ŌĆö transient bare-identifier collect
//     state. Settles to URL / EMAIL / MONEY at `:145-153` or
//     to WORD..WORD8 at `:156-183`. Framework convention:
//     leave unmapped so unmatched bare identifiers paint at
//     STYLE_DEFAULT.
//
// **Eight-class descriptor** ŌĆö widest of Phase 4.5, exceeding
// Forth 6, Erlang 6, and OScript 6. LexRebol uses class-slot
// granularity to categorize REBOL's rich vocabulary across
// semantic tiers: primary keywords, datatypes, math, I/O,
// series ops, plus 3 additional reserved tiers for
// domain-specific dialects (currently unpopulated per SciTE
// convention).
//
// **Reverse-first-match-wins cascade.** `LexRebol.cxx:162-178`
// probes classes **7 ŌåÆ 0** in REVERSE. Higher classes
// SHADOW lower classes on collision ŌĆö the invariant test
// enforces cross-class disjointness across all populated
// pairs to prevent silent shadowing.
//
// **Case-INSENSITIVE** via `sc.GetCurrentLowered` at
// `:160` ŌĆö wordlist tokens must be lowercase.
//
// **Slot rationale:**
//   - COMMENTLINE (1) + COMMENTBLOCK (2) ŌåÆ Comment (italic).
//     Both `;`-to-EOL and `comment {...}` block forms.
//   - PREFACE (3) ŌåÆ Comment (italic). Preamble prose before
//     the `REBOL [...]` header ŌĆö semantically documentation,
//     same italic treatment.
//   - OPERATOR (4) ŌåÆ Operator. Symbolic operators from
//     `IsAnOperator` at `:46-63`.
//   - CHARACTER (5) + QUOTEDSTRING (6) + BRACEDSTRING (7) ŌåÆ
//     String. Three string sub-styles collapse.
//   - NUMBER (8) ŌåÆ Number.
//   - PAIR (9) + TUPLE (10) + BINARY (11) ŌåÆ Number. REBOL's
//     first-class syntactic value types that carry numeric
//     semantics (`640x480` pair, `1.2.3` tuple, `#{DEADBEEF}`
//     binary).
//   - MONEY (12) ŌåÆ Number. `$xxx` monetary literal ŌĆö numeric
//     value with currency semantics.
//   - ISSUE (13) ŌåÆ String. `#xxx` issue values are REBOL
//     `issue!` value literals ŌĆö arbitrary user-authored
//     symbolic constants that behave semantically like
//     strings with `#` prefix. Same String slot as the
//     other prefix-delimited value literals (FILE / EMAIL /
//     URL) ŌĆö Keyword2 would misplace them in the bounded-
//     vocabulary class.
//   - TAG (14) ŌåÆ String. `<xxx>` tag values are REBOL
//     first-class `tag!` value literals (strings with `<>`
//     delimiters), not markup metadata. Same String slot
//     as CHARACTER / QUOTEDSTRING / BRACEDSTRING / FILE /
//     EMAIL / URL for uniform value-literal treatment.
//   - FILE (15) ŌåÆ String. `%xxx` file paths are semantically
//     path literals.
//   - EMAIL (16) + URL (17) ŌåÆ String. Value-literal
//     references to external resources.
//   - DATE (18) + TIME (19) ŌåÆ Number. Post-settled from
//     NUMBER; semantically numeric literals with unit
//     interpretation.
//   - WORD (21) ŌåÆ Keyword (bold). Primary keyword hits ŌĆö
//     control flow, definition, evaluators. Visual anchor.
//   - WORD2 (22) ŌåÆ Keyword2 (accent). Datatypes.
//   - WORD3 (23) ŌåÆ Keyword2 (accent). Math / conversion
//     natives.
//   - WORD4 (24) ŌåÆ Keyword2 (accent). I/O / system natives.
//   - WORD5 (25) ŌåÆ Keyword2 (accent). Series / block ops.
//   - WORD6 (26) + WORD7 (27) + WORD8 (28) ŌåÆ Keyword2
//     (accent). Additional wordlist tiers ŌĆö mapped
//     defensively so a future populated tier renders with
//     accent styling instead of falling to STYLE_DEFAULT.
const REBOL_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_REBOL_COMMENTLINE, StyleSlot::Comment),
    (SCE_REBOL_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_REBOL_PREFACE, StyleSlot::Comment),
    (SCE_REBOL_OPERATOR, StyleSlot::Operator),
    (SCE_REBOL_CHARACTER, StyleSlot::String),
    (SCE_REBOL_QUOTEDSTRING, StyleSlot::String),
    (SCE_REBOL_BRACEDSTRING, StyleSlot::String),
    (SCE_REBOL_NUMBER, StyleSlot::Number),
    (SCE_REBOL_PAIR, StyleSlot::Number),
    (SCE_REBOL_TUPLE, StyleSlot::Number),
    (SCE_REBOL_BINARY, StyleSlot::Number),
    (SCE_REBOL_MONEY, StyleSlot::Number),
    (SCE_REBOL_ISSUE, StyleSlot::String),
    (SCE_REBOL_TAG, StyleSlot::String),
    (SCE_REBOL_FILE, StyleSlot::String),
    (SCE_REBOL_EMAIL, StyleSlot::String),
    (SCE_REBOL_URL, StyleSlot::String),
    (SCE_REBOL_DATE, StyleSlot::Number),
    (SCE_REBOL_TIME, StyleSlot::Number),
    (SCE_REBOL_WORD, StyleSlot::Keyword),
    (SCE_REBOL_WORD2, StyleSlot::Keyword2),
    (SCE_REBOL_WORD3, StyleSlot::Keyword2),
    (SCE_REBOL_WORD4, StyleSlot::Keyword2),
    (SCE_REBOL_WORD5, StyleSlot::Keyword2),
    (SCE_REBOL_WORD6, StyleSlot::Keyword2),
    (SCE_REBOL_WORD7, StyleSlot::Keyword2),
    (SCE_REBOL_WORD8, StyleSlot::Keyword2),
];

// Italic on comment / preface ŌĆö universal Code++ comment
// convention. PREFACE (3) is semantically documentation prose
// before the REBOL header block, so it gets the same italic
// treatment as COMMENTLINE / COMMENTBLOCK.
const REBOL_ITALIC: &[usize] = &[
    SCE_REBOL_COMMENTLINE,
    SCE_REBOL_COMMENTBLOCK,
    SCE_REBOL_PREFACE,
];

// Bold on WORD only ŌĆö the primary keyword tier. Same
// single-class-bold discipline as MMIXAL (OPCODE_VALID),
// CSound (OPCODE), and OScript (KEYWORD) ŌĆö WORD2..WORD8 all
// carry Keyword2 accent rather than sharing bold.
const REBOL_BOLD: &[usize] = &[SCE_REBOL_WORD];

// Eight-class install ŌĆö only five slots (0-4) are installed
// with canonical REBOL vocabulary tiers. Classes 5/6/7 are
// intentionally NOT registered here at all; the `WordList`
// instances inside Scintilla for those descriptor indices
// stay default-constructed, and the paint loop's `InList`
// probe at `LexRebol.cxx:162-166` returns false for every
// identifier ŌĆö so `SCE_REBOL_WORD6`/`WORD7`/`WORD8` states
// never fire in practice. The theme still maps those SCE
// slots to `Keyword2` defensively (see the `REBOL_STYLES`
// banner above) so that if a future host populates class
// 5/6/7 the WORD6/7/8 states render with accent styling
// instead of falling to `STYLE_DEFAULT`.
const REBOL_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, REBOL_WORD),
        (1, REBOL_WORD2),
        (2, REBOL_WORD3),
        (3, REBOL_WORD4),
        (4, REBOL_WORD5),
    ],
    styles: REBOL_STYLES,
    italic: REBOL_ITALIC,
    bold: REBOL_BOLD,
};

// --- LexRegistry ---
// Windows Registry Editor export files (`.reg`). `L_REGISTRY`
// (id 80) is the only language row using this lexer. LexRegistry
// is the strongest ZERO-WORDLIST lexer in Phase 4.5:
// `RegistryWordListDesc[]` at `LexRegistry.cxx:38-40` is
// `{ 0 }` and `WordListSet` at `:191-193` unconditionally
// REJECTS any keyword install (returns -1). Classification is
// purely state-machine driven ŌĆö see the `LexRegistry` banner
// in `scintilla-sys/src/lib.rs` for the paint-loop citations.
//
// Style-to-slot decisions:
//   * `COMMENT` (1) ŌåÆ Comment (green italic) ŌĆö `;`-to-EOL
//     comments. Universal Code++ comment convention.
//   * `VALUENAME` (2) ŌåÆ String ŌĆö value names are quoted strings
//     (`"ValueName"=...`). Painting them the same as string
//     literals matches Notepad++ defaults and preserves the
//     visual pairing with `SCE_REG_STRING` on the RHS.
//   * `STRING` (3) ŌåÆ String ŌĆö value string literals on RHS of
//     `=`. Universal string slot.
//   * `HEXDIGIT` (4) ŌåÆ Number ŌĆö hex-comma data like
//     `41,42,43,ff` in `hex:` / `hex(b):` value tails, and
//     dword hex `00000001`. All numeric, all Number slot.
//   * `VALUETYPE` (5) ŌåÆ Keyword2 ŌĆö `dword` / `hex` / `hex(b)` /
//     `hex(7)` type-tag tokens that precede the `:` in
//     `Name=type:...` ŌĆö a small enumerable vocabulary that
//     reads as secondary-keyword accent.
//   * `ADDEDKEY` (6) ŌåÆ Keyword (bold blue) ŌĆö `[HKEY_...\path]`
//     full keypath declarations. These are the PRIMARY
//     structural anchors a reader scans for, playing the same
//     role as `SCE_C_WORD` (C keywords) / `SCE_MAKE_TARGET`
//     (Makefile targets) / `SCE_PROPS_SECTION` (INI sections).
//     Gets bold treatment.
//   * `DELETEDKEY` (7) ŌåÆ Preprocessor ŌĆö `[-HKEY_...\path]`
//     deletion directives are out-of-band "remove this" markers,
//     same semantic role as C's `#undef` or Batch's leading `@`
//     echo-suppress ŌĆö all Preprocessor.
//   * `ESCAPED` (8) ŌåÆ Lifetime ŌĆö `\"` / `\\` escape sequences
//     inside strings. Small distinct highlighting that reads as
//     "not the surrounding string" ŌĆö same accent slot used for
//     Rust lifetime tags, which sit adjacent to strings and
//     want visual separation without dominating.
//   * `KEYPATH_GUID` (9) ŌåÆ Macro ŌĆö `{XXXXXXXX-...-XXXXXXXXXXXX}`
//     GUID sub-tokens inside a keypath. GUIDs deserve a
//     distinctive colour so a reader can spot them at a glance
//     inside otherwise-uniform keypaths; Macro is the accent
//     slot for "special identifier form".
//   * `STRING_GUID` (10) ŌåÆ Macro ŌĆö same GUID recognition inside
//     a string / value name. Same Macro accent for consistent
//     visual treatment across both host contexts.
//   * `PARAMETER` (11) ŌåÆ Preprocessor ŌĆö `%0` / `%1` / `%*`
//     format parameters inside strings are out-of-band markers
//     for runtime substitution, same "directive" semantics as
//     DELETEDKEY.
//   * `OPERATOR` (12) ŌåÆ Operator ŌĆö the `-,.=:\\@()` character
//     set from `setOperators` at `LexRegistry.cxx:219`.
//     Universal Operator slot.
//
// `SCE_REG_DEFAULT` (0) intentionally unmapped ŌĆö free text on
// lines without an `=` or `[` opener stays at `STYLE_DEFAULT`
// foreground. Same convention as every other Phase 4.5 theme.
const REGISTRY_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_REG_COMMENT, StyleSlot::Comment),
    (SCE_REG_VALUENAME, StyleSlot::String),
    (SCE_REG_STRING, StyleSlot::String),
    (SCE_REG_HEXDIGIT, StyleSlot::Number),
    (SCE_REG_VALUETYPE, StyleSlot::Keyword2),
    (SCE_REG_ADDEDKEY, StyleSlot::Keyword),
    (SCE_REG_DELETEDKEY, StyleSlot::Preprocessor),
    (SCE_REG_ESCAPED, StyleSlot::Lifetime),
    (SCE_REG_KEYPATH_GUID, StyleSlot::Macro),
    (SCE_REG_STRING_GUID, StyleSlot::Macro),
    (SCE_REG_PARAMETER, StyleSlot::Preprocessor),
    (SCE_REG_OPERATOR, StyleSlot::Operator),
];

// Italic on COMMENT only ŌĆö universal Code++ comment convention.
const REGISTRY_ITALIC: &[usize] = &[SCE_REG_COMMENT];

// Bold on ADDEDKEY only ŌĆö `[HKEY_...\path]` full keypath
// declarations are the primary structural anchor a reader
// scans for. Same single-class-bold discipline as PROPS
// (SECTION), Makefile (TARGET), and every LexCPP-family theme
// (WORD).
const REGISTRY_BOLD: &[usize] = &[SCE_REG_ADDEDKEY];

// Zero-wordlist theme ŌĆö same pattern as PROPS / LaTeX / TeX.
// `keywords: &[]` is REQUIRED here, not just a preference: the
// lexer's `WordListSet` at `LexRegistry.cxx:191-193`
// unconditionally returns -1, so installing anything would be
// silently rejected by Scintilla. Excluded from
// `wired_languages_have_complete_themes` for the same reason
// PROPS / LaTeX are: that test's `!keywords.is_empty()` floor
// calibrates for the majority of lexers that have at least one
// wordlist. The dedicated `registry_uses_lexregistry_zero_class_theme`
// test below pins the empty-keywords invariant, the 12-mapping
// shape, style-routing pins, and cross-language non-reuse.
const REGISTRY_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: REGISTRY_STYLES,
    italic: REGISTRY_ITALIC,
    bold: REGISTRY_BOLD,
};

// --- LexSpice ---
// SPICE (Simulation Program with Integrated Circuit Emphasis)
// circuit netlist files (extensions `.sp` / `.spice`). `L_SPICE`
// (id 82) is the only language row using this lexer.
// Three-class wordlist descriptor (Keywords / Keywords2 /
// Keywords3) per `LexSpice.cxx:42-46`. First-match-wins cascade
// class 0 ŌåÆ 1 ŌåÆ 2 (forward order, unlike REBOL's reverse
// cascade) ŌĆö see the `LexSpice` banner in
// `scintilla-sys/src/lib.rs` for the paint-loop citations.
//
// Style-to-slot decisions (6 mappings across 9 defined slots):
//   * `KEYWORD` (2) ŌåÆ Keyword (bold blue) ŌĆö SPICE simulator
//     directive stems (`tran` / `dc` / `model` / `subckt` /
//     ŌĆ”). These are the PRIMARY structural anchors of a
//     `.SPICE` netlist ŌĆö every simulation-command line begins
//     with one, prefixed by a `.` delimiter. Same bold-blue
//     Keyword treatment as C `if` / Rust `fn` / SPICE's own
//     dot prefix (rendered as Operator via DELIMITER).
//   * `KEYWORD2` (3) ŌåÆ Keyword2 ŌĆö expression functions
//     (`sin` / `cos` / `exp` / `if` / `ddt` / ŌĆ”) used inside
//     `{...}` behavioural sources. Same accent role as
//     Python's `len`/`range` builtins ŌåÆ Keyword2.
//   * `KEYWORD3` (4) ŌåÆ Preprocessor ŌĆö model type / source
//     waveform / sweep specifier tokens (`nmos` / `pulse` /
//     `dec` / `gmin` / ŌĆ”). These read as declaration
//     modifiers rather than structural anchors ŌĆö same
//     Preprocessor accent used for INI's `DEFVAL`, Batch's
//     leading `@`, Registry's `DELETEDKEY` / `PARAMETER`.
//   * `NUMBER` (5) ŌåÆ Number ŌĆö decimal / floating-point /
//     scientific-notation / SPICE-engineering-suffix
//     (`1u` / `10k` / `1meg`) numeric literals plus the
//     `#`-lead numeric form. All go through the same
//     `ColouriseNumber` state.
//   * `DELIMITER` (6) ŌåÆ Operator ŌĆö single-char delimiter set
//     `& ' ( ) * + , - . / : ; < = > |`. Universal Operator
//     slot. Notably the `.` in `.tran` paints as Operator,
//     not as part of the keyword (dot is a lexer-level
//     delimiter ŌĆö see the banner).
//   * `COMMENTLINE` (8) ŌåÆ Comment (green italic) ŌĆö line
//     comments starting with `*` in column 0 (traditional
//     Berkeley SPICE) or `*~` mid-line (SciTE / LTspice
//     extension). Universal Comment slot.
//
// Unmapped slots (framework convention):
//   * `DEFAULT` (0) ŌĆö leave unmapped, fall through to
//     STYLE_DEFAULT. Standard framework convention for
//     whitespace / unclassified regions.
//   * `IDENTIFIER` (1) ŌĆö transient collect state that stays
//     visible when a bare word misses all three wordlist
//     probes. Framework convention leaves it unmapped so
//     unmatched user-defined names (net names, component
//     designators like `Vin1`, subckt-parameter references)
//     paint at STYLE_DEFAULT. Same convention as
//     `SCE_C_IDENTIFIER` / `SCE_REBOL_IDENTIFIER` /
//     `SCE_OSCRIPT_IDENTIFIER`.
//   * `VALUE` (7) ŌĆö DEAD STATE. Verified: the paint loop has
//     ZERO call sites emitting `SCE_SPICE_VALUE` (no
//     `SetState` / `ChangeState` / `ForwardSetState`). The
//     slot is reserved in `SciLexer.h` but never entered at
//     runtime. Leave unmapped since no bytes ever paint into
//     it. If a future Lexilla update ever activates this
//     slot, the invariant test's highest-defined-pin would
//     still pass and the map is safely additive.
const SPICE_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_SPICE_KEYWORD, StyleSlot::Keyword),
    (SCE_SPICE_KEYWORD2, StyleSlot::Keyword2),
    (SCE_SPICE_KEYWORD3, StyleSlot::Preprocessor),
    (SCE_SPICE_NUMBER, StyleSlot::Number),
    (SCE_SPICE_DELIMITER, StyleSlot::Operator),
    (SCE_SPICE_COMMENTLINE, StyleSlot::Comment),
];

// Italic on COMMENTLINE ŌĆö universal Code++ comment convention.
const SPICE_ITALIC: &[usize] = &[SCE_SPICE_COMMENTLINE];

// Bold on KEYWORD (class 0 ŌĆö simulator directive stems) ŌĆö
// primary structural anchor. Same single-class-bold discipline
// as PROPS (SECTION), Makefile (TARGET), REBOL (WORD), OScript
// (KEYWORD), and every LexCPP-family theme (WORD).
const SPICE_BOLD: &[usize] = &[SCE_SPICE_KEYWORD];

// Three-class install matching descriptor order at
// `LexSpice.cxx:42-46`. All three populated; first-match-wins
// cascade at `:113-130` probes class 0 ŌåÆ 1 ŌåÆ 2 in forward order
// so cross-class disjointness is strictly enforced by the
// invariant test.
const SPICE_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, SPICE_KEYWORDS),
        (1, SPICE_KEYWORDS2),
        (2, SPICE_KEYWORDS3),
    ],
    styles: SPICE_STYLES,
    italic: SPICE_ITALIC,
    bold: SPICE_BOLD,
};

// --- LexAsn1 ---
// ASN.1 / SNMP MIB modules ŌĆö extension `.asn1`. `L_ASN1` (id 65)
// is the only language row using this lexer. Four-wordlist lexer
// (Keywords / Attributes / Descriptors / Types) with first-match-
// wins classification per `LexAsn1.cxx:95-106`. See the `LexAsn1`
// banner in `scintilla-sys/src/lib.rs` for the paint-loop
// citations and per-state emission analysis.
//
// **9 style mappings** covering 11 defined SCE_ASN1_* states
// (0..=10). `SCE_ASN1_DEFAULT` (0) and `SCE_ASN1_IDENTIFIER` (2)
// stay unmapped per the framework's fall-through-to-STYLE_DEFAULT
// convention for the boundary + bareword-collect slots ŌĆö same
// discipline as [`SCE_C_DEFAULT`] / [`SCE_C_IDENTIFIER`] /
// [`SCE_REBOL_DEFAULT`] / [`SCE_SPICE_DEFAULT`] /
// [`SCE_SPICE_IDENTIFIER`].
//
// Mapped slots (first-match-wins colour discipline matching the
// classifier's Keyword ŌåÆ Attribute ŌåÆ Descriptor ŌåÆ Type probe
// order):
//   * `COMMENT` (1) ŌåÆ Comment (green italic) ŌĆö `--`-to-EOL line
//     comments. Universal Code++ comment slot.
//   * `STRING` (3) ŌåÆ String ŌĆö `"..."` double-quoted strings.
//   * `OID` (4) ŌåÆ Number ŌĆö decimal digits inside a `{...}` OID
//     definition following `::=`. Semantic-distinct from SCALAR
//     at the lexer level (see the SCE_ASN1_* banner) but shares
//     the Number colour slot; a future palette pass could add a
//     dedicated "OID accent" slot.
//   * `SCALAR` (5) ŌåÆ Number ŌĆö bare decimal digit runs at any
//     other position.
//   * `KEYWORD` (6) ŌåÆ Keyword (bold blue) ŌĆö class 0 structural
//     reserved words (`SEQUENCE` / `BEGIN` / `IMPORTS` / ...).
//     Primary anchor slot.
//   * `ATTRIBUTE` (7) ŌåÆ Keyword2 (steel blue) ŌĆö class 1 SMI
//     macro headers + attribute field names (`OBJECT-TYPE` /
//     `SYNTAX` / `ACCESS` / ...). Secondary anchor slot.
//     Matches the `SCE_C_WORD2` ŌåÆ Keyword2 convention (primitive
//     types get the accent slot in LexCPP family; here the SMI
//     macro headers do).
//   * `DESCRIPTOR` (8) ŌåÆ Preprocessor ŌĆö class 2 lowercase MIB
//     descriptors (`current` / `read-only` / `iso` / ...).
//     Distinct third colour so the ACCESS / STATUS enumeration
//     values paint separately from the structural macros that
//     invoke them.
//   * `TYPE` (9) ŌåÆ Lifetime ŌĆö class 3 primitive types + SMI
//     TCs (`INTEGER` / `Counter32` / `DisplayString` / ...).
//     Distinct fourth colour so leaf types paint separately
//     from the type-BUILDER keywords in class 0.
//   * `OPERATOR` (10) ŌåÆ Operator ŌĆö the `::=` affectation
//     operator's bytes. Other punctuation stays in DEFAULT per
//     the state machine at `LexAsn1.cxx:66-83`.
//
// Palette rationale for the 4-way keyword-class spread: LexAsn1's
// 4-class descriptor is unusual for a Scintilla lexer (most have
// 1-2 classes). Mapping each to a distinct StyleSlot lets the
// SNMP MIB reader visually distinguish the four archetypes
// simultaneously without needing to squint at font-weight or
// consult the outline view. The Keyword / Keyword2 / Preprocessor
// / Lifetime spread reuses established Code++ palette slots
// without inventing new ones ŌĆö same rationale as Raku's 7-class
// classifier collapsing to StyleSlot { Keyword, Function,
// Typedef, Class, Grammar, Adverb, ... }.
const ASN1_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_ASN1_COMMENT, StyleSlot::Comment),
    (SCE_ASN1_STRING, StyleSlot::String),
    (SCE_ASN1_OID, StyleSlot::Number),
    (SCE_ASN1_SCALAR, StyleSlot::Number),
    (SCE_ASN1_KEYWORD, StyleSlot::Keyword),
    (SCE_ASN1_ATTRIBUTE, StyleSlot::Keyword2),
    (SCE_ASN1_DESCRIPTOR, StyleSlot::Preprocessor),
    (SCE_ASN1_TYPE, StyleSlot::Lifetime),
    (SCE_ASN1_OPERATOR, StyleSlot::Operator),
];

// Italic on COMMENT ŌĆö universal Code++ comment convention.
const ASN1_ITALIC: &[usize] = &[SCE_ASN1_COMMENT];

// Bold on KEYWORD (class 0 ŌĆö structural reserved words) ŌĆö primary
// anchor slot. Same single-class-bold discipline as SPICE (KEYWORD),
// PROPS (SECTION), Makefile (TARGET), REBOL (WORD), OScript
// (KEYWORD), and every LexCPP-family theme (WORD).
const ASN1_BOLD: &[usize] = &[SCE_ASN1_KEYWORD];

// Four-class install matching `asn1WordLists[]` order at
// `LexAsn1.cxx:181-186`. All four populated; first-match-wins
// cascade at `:95-106` probes class 0 ŌåÆ 1 ŌåÆ 2 ŌåÆ 3 in forward order
// so cross-class disjointness is strictly enforced by the invariant
// test (see the `asn1_wordlists_are_disjoint` case in `tests`).
const ASN1_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, ASN1_KEYWORDS),
        (1, ASN1_ATTRIBUTES),
        (2, ASN1_DESCRIPTORS),
        (3, ASN1_TYPES),
    ],
    styles: ASN1_STYLES,
    italic: ASN1_ITALIC,
    bold: ASN1_BOLD,
};

// --- LexBaan ---
// Baan 4GL ŌĆö proprietary ERP scripting language (extension `.baan`).
// `L_BAANC` (id 60) is the only language row using this lexer.
// Nine-wordlist descriptor with first-match-wins classification per
// `LexBaan.cxx:556-599` plus position-tracked overrides
// (`lineHasDomain` / `lineHasFunction` promote the next identifier
// to DOMDEF / FUNCDEF regardless of wordlist). See the `LexBaan`
// banner in `scintilla-sys/src/lib.rs` for the paint-loop citations
// and per-state emission analysis.
//
// **22 style mappings** covering 25 defined SCE_BAAN_* states
// (0..=24). Three unmapped per the framework's fall-through-to-
// STYLE_DEFAULT convention:
//   * `DEFAULT` (0) ŌĆö whitespace / unclassified.
//   * `IDENTIFIER` (8) ŌĆö bareword collect state at
//     `LexBaan.cxx:678`. Barewords that don't match any wordlist
//     AND don't match any `IsAnyOtherIdentifier` pattern fall
//     through to STYLE_DEFAULT. Same convention as
//     [`SCE_C_IDENTIFIER`] / [`SCE_ASN1_IDENTIFIER`].
//   * `STRINGEOL` (9) ŌĆö parse-failure state emitted at `:653`
//     when a string doesn't terminate before line end. Left
//     unmapped per the framework's deferred `StyleSlot::Error`
//     convention. Same discipline as Visual Prolog / LexBasic
//     (which uses SCE_B_ERROR for the same purpose).
//
// **Framework routing choices:**
//   * `COMMENT` (1) ŌåÆ Comment italic ŌĆö `|`-prefixed line
//     comments (Baan 4GL's distinctive comment syntax, unlike
//     `;` / `//` / `#`).
//   * `COMMENTDOC` (2) ŌåÆ Comment italic ŌĆö `dllusage...enddllusage`
//     and `functionusage...endfunctionusage` doc blocks.
//   * `NUMBER` (3) ŌåÆ Number.
//   * `WORD` (4) ŌåÆ Keyword bold ŌĆö class 0 reserved keywords
//     (`if` / `for` / `while` / `function` / ...).
//   * `STRING` (5) ŌåÆ String.
//   * `PREPROCESSOR` (6) ŌåÆ Preprocessor ŌĆö `#`-prefixed built-in
//     directives (`#define` / `#include` / `#pragma` / `#ifdef`
//     / etc. ŌĆö the 13-token whitelist at `LexBaan.cxx:518-521`).
//   * `OPERATOR` (7) ŌåÆ Operator.
//   * `WORD2` (10) ŌåÆ Keyword2 accent ŌĆö class 1 "Baan Standard
//     functions". Slot mapped for future user config; empty by
//     default so state never emits with stock wordlist install.
//   * `WORD3` (11) ŌåÆ Keyword2 ŌĆö class 2 "Baan Functions
//     Abridged" (only fires if next char is `(` per
//     `LexBaan.cxx:577-580`). Same slot as WORD2 since both are
//     function-call archetypes.
//   * `WORD4` (12) ŌåÆ Preprocessor ŌĆö class 3 section headers
//     ("Baan Main Sections"). Structurally similar to
//     `#`-directive paint. Empty by default.
//   * `WORD5` (13) ŌåÆ Macro ŌĆö class 4 sub-section headers ("Baan
//     Sub Sections"). Distinct slot so main/sub sections paint
//     differently. Empty by default.
//   * `WORD6` (14) ŌåÆ Lifetime ŌĆö class 5 pre-defined variables.
//     Empty by default.
//   * `WORD7` (15) ŌåÆ Lifetime ŌĆö class 6 pre-defined attributes.
//     Same slot as WORD6 (attribute/variable archetype).
//   * `WORD8` (16) ŌåÆ Macro ŌĆö class 7 enumerates.
//   * `WORD9` (17) ŌåÆ Macro ŌĆö class 8 unused slot (no descriptor
//     name at `LexBaan.cxx:71-81`; only accessible via
//     `WordListSet` case 8 at `:484-486`). Slot mapped for a
//     hypothetical future user extension.
//   * `TABLEDEF` (18) ŌåÆ Macro ŌĆö pattern-matched table names
//     (`^^^^^###` etc. per `IsAnyOtherIdentifier` at `:135-206`).
//   * `TABLESQL` (19) ŌåÆ Macro ŌĆö pattern-matched SQL table
//     references.
//   * `FUNCTION` (20) ŌåÆ Lifetime ŌĆö pattern-matched function
//     names (`^^^^^.dll####.` etc.).
//   * `DOMDEF` (21) ŌåÆ Preprocessor ŌĆö identifier following the
//     `domain` keyword (position-tracked at `:565-567`). Marks
//     a domain-declaration site.
//   * `FUNCDEF` (22) ŌåÆ Preprocessor ŌĆö identifier following the
//     `function` keyword. Marks a function-declaration site.
//   * `OBJECTDEF` (23) ŌåÆ Macro ŌĆö identifier following `#pragma`
//     / `#include` (position-tracked at `:600-603`).
//   * `DEFINEDEF` (24) ŌåÆ Macro ŌĆö identifier following `#define`
//     / `#undef` / `#ifdef` / etc. (position-tracked at
//     `:604-607`).
//
// Palette rationale: Baan 4GL's 25-state / 9-wordlist descriptor
// is the richest in Lexilla. The seven semantic-position states
// (TABLEDEF / TABLESQL / FUNCTION / DOMDEF / FUNCDEF / OBJECTDEF
// / DEFINEDEF) plus the nine wordlist-driven WORD* states each
// get a distinct StyleSlot along the Keyword / Keyword2 /
// Preprocessor / Lifetime / Macro axes, giving the Baan reader
// visual
// distinction between reserved words, function calls, section
// markers, declaration sites, and pattern-matched identifiers.
// Same "map ahead" discipline as AviSynth's class-5 USERDFN
// (mapped even though unpopulated by config).
//
// **Default install: class 0 only.** [`BAAN_KEYWORDS`] covers
// ~44 reserved keywords; the other 8 wordlist classes stay
// empty by design. States WORD2..=WORD9 don't emit with the
// stock install; the mappings are inert until a user extends
// the config. Position-tracked states (DOMDEF / FUNCDEF /
// OBJECTDEF / DEFINEDEF) DO fire regardless of wordlist config
// since they're triggered by class-0 keyword matches (`domain`
// / `function`) or preprocessor state (`#define` / `#pragma`).
// Pattern-matched states (TABLEDEF / TABLESQL / FUNCTION) also
// fire regardless of wordlist install since
// `IsAnyOtherIdentifier` at `:135-206` runs on every unmatched
// identifier.
const BAAN_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_BAAN_COMMENT, StyleSlot::Comment),
    (SCE_BAAN_COMMENTDOC, StyleSlot::Comment),
    (SCE_BAAN_NUMBER, StyleSlot::Number),
    (SCE_BAAN_WORD, StyleSlot::Keyword),
    (SCE_BAAN_STRING, StyleSlot::String),
    (SCE_BAAN_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_BAAN_OPERATOR, StyleSlot::Operator),
    (SCE_BAAN_WORD2, StyleSlot::Keyword2),
    (SCE_BAAN_WORD3, StyleSlot::Keyword2),
    (SCE_BAAN_WORD4, StyleSlot::Preprocessor),
    (SCE_BAAN_WORD5, StyleSlot::Macro),
    (SCE_BAAN_WORD6, StyleSlot::Lifetime),
    (SCE_BAAN_WORD7, StyleSlot::Lifetime),
    (SCE_BAAN_WORD8, StyleSlot::Macro),
    (SCE_BAAN_WORD9, StyleSlot::Macro),
    (SCE_BAAN_TABLEDEF, StyleSlot::Macro),
    (SCE_BAAN_TABLESQL, StyleSlot::Macro),
    (SCE_BAAN_FUNCTION, StyleSlot::Lifetime),
    (SCE_BAAN_DOMDEF, StyleSlot::Preprocessor),
    (SCE_BAAN_FUNCDEF, StyleSlot::Preprocessor),
    (SCE_BAAN_OBJECTDEF, StyleSlot::Macro),
    (SCE_BAAN_DEFINEDEF, StyleSlot::Macro),
];

// Italic on both comment forms ŌĆö universal Code++ comment
// convention.
const BAAN_ITALIC: &[usize] = &[SCE_BAAN_COMMENT, SCE_BAAN_COMMENTDOC];

// Bold on WORD (class 0 ŌĆö Baan reserved keywords) ŌĆö primary
// structural anchor. Same discipline as every other Code++
// theme.
const BAAN_BOLD: &[usize] = &[SCE_BAAN_WORD];

// One-class install. Only [`BAAN_KEYWORDS`] (class 0) is
// populated by default. Classes 1..=8 (standard functions,
// abridged functions, main sections, sub sections, predefined
// variables, predefined attributes, enumerates, unused-slot)
// stay uninstalled ŌĆö their SCE_BAAN_WORD*/WORD*/WORD9 states
// don't emit with the stock config. Their mappings in
// `BAAN_STYLES` are preserved so a future user-config
// extension gets defined paint immediately.
const BAAN_THEME: LangTheme = LangTheme {
    keywords: &[(0, BAAN_KEYWORDS)],
    styles: BAAN_STYLES,
    italic: BAAN_ITALIC,
    bold: BAAN_BOLD,
};

// --- LexAVS ---
// AviSynth ŌĆö video-editing scripting language (extensions `.avs` /
// `.avsi`). `L_AVS` (id 66) is the only language row using this
// lexer. Six-wordlist descriptor (Keywords / Filters / Plugins /
// Functions / ClipProperties / UserDefined) with first-match-wins
// classification per `LexAVS.cxx:101-113`. Case-INSENSITIVE per
// `LexAVS.cxx:99, :189` ŌĆö wordlist entries MUST be lowercase.
// See the `LexAVS` banner in `scintilla-sys/src/lib.rs` for the
// paint-loop citations and per-state emission analysis.
//
// **12 style mappings** covering 15 defined SCE_AVS_* states
// (0..=14). `SCE_AVS_DEFAULT` (0), `SCE_AVS_IDENTIFIER` (6), and
// `SCE_AVS_USERDFN` (14) stay unmapped per the framework's
// fall-through-to-STYLE_DEFAULT convention:
//   * DEFAULT ŌĆö whitespace / unclassified. Standard framework
//     convention.
//   * IDENTIFIER ŌĆö the transient collect state at `:180`. Bytes
//     that don't match any of the six wordlists stay in this
//     state and paint at STYLE_DEFAULT. Same convention as
//     `SCE_C_IDENTIFIER` / `SCE_ASN1_IDENTIFIER` /
//     `SCE_SPICE_IDENTIFIER`.
//   * USERDFN ŌĆö class 5 "User defined functions" wordlist is NOT
//     installed by the theme (`AVS_THEME.keywords` has only 5
//     entries, classes 0..=4). Class 5 stays empty at Scintilla,
//     `userDefined.InList(s)` always returns false, and the
//     USERDFN state is never emitted. Same "config-driven dead
//     state" pattern as Spice's SCE_SPICE_VALUE ŌĆö the slot exists
//     in Lexilla but the emission path is unreachable given our
//     wordlist configuration. Leaving unmapped keeps the framework
//     honest: if a future config change installs a class-5
//     wordlist, USERDFN bytes will paint at STYLE_DEFAULT until
//     the theme adds an explicit mapping.
//
// Mapped slots (first-match-wins colour discipline matching the
// classifier's Keywords ŌåÆ Filters ŌåÆ Plugins ŌåÆ Functions ŌåÆ
// ClipProperties probe order):
//   * `COMMENTBLOCK` (1) ŌåÆ Comment italic ŌĆö `/*...*/` C-family
//     nested block comments.
//   * `COMMENTBLOCKN` (2) ŌåÆ Comment italic ŌĆö `[*...*]` AviSynth's
//     own nested block form. Distinct SCE_ slot so the two
//     nesting families track independent depths, but same visual
//     paint per framework convention.
//   * `COMMENTLINE` (3) ŌåÆ Comment italic ŌĆö `#`-to-EOL line
//     comments.
//   * `NUMBER` (4) ŌåÆ Number ŌĆö decimal / dot-fractional / signed-
//     fractional literals per `LexAVS.cxx:40-45`'s permissive
//     `IsANumberChar`.
//   * `OPERATOR` (5) ŌåÆ Operator ŌĆö anything `isoperator(ch)`
//     accepts (arithmetic / comparison / assignment / grouping).
//   * `STRING` (7) ŌåÆ String ŌĆö `"..."` double-quoted strings.
//   * `TRIPLESTRING` (8) ŌåÆ String ŌĆö `"""..."""` verbatim strings.
//     Same collapse discipline as Python's SCE_P_STRING /
//     _CHARACTER / _TRIPLE / _TRIPLEDOUBLE unification and
//     Raku's Q-language collapse.
//   * `KEYWORD` (9) ŌåÆ Keyword bold ŌĆö class 0 structural control
//     words (`function` / `return` / `if` / `else` / ...). Primary
//     anchor slot.
//   * `FILTER` (10) ŌåÆ Keyword2 accent ŌĆö class 1 built-in AviSynth
//     filter verbs (`avisource` / `crop` / `trim` / `overlay` /
//     ...). Secondary anchor ŌĆö the main vocabulary users compose
//     scripts from.
//   * `PLUGIN` (11) ŌåÆ Preprocessor ŌĆö class 2 third-party plugin
//     function names (`ffvideosource` / `qtgmc` / ...). Distinct
//     colour so external plugin surface reads differently from
//     stock builtins.
//   * `FUNCTION` (12) ŌåÆ Lifetime ŌĆö class 3 built-in utility /
//     math / string functions (`abs` / `min` / `sin` / `chr` /
//     ...). Distinct fourth colour separating scalar helpers from
//     clip transforms.
//   * `CLIPPROP` (13) ŌåÆ Macro ŌĆö class 4 clip properties
//     (`width` / `height` / `framecount` / `isyv12` / ...).
//     Distinct fifth colour for the property-accessor archetype.
//
// Palette rationale for the 5-way keyword-class spread: LexAVS's
// 6-class descriptor is second only to Raku's 7-class in Lexilla
// richness. Mapping 5 of them to distinct StyleSlots (Keyword /
// Keyword2 / Preprocessor / Lifetime / Macro) lets the AviSynth
// scripter visually distinguish structural / filter / plugin /
// utility / property archetypes simultaneously ŌĆö the same
// discipline as ASN.1's 4-way spread but with an added Macro slot
// for the property archetype. USERDFN (class 5) collapses to
// STYLE_DEFAULT since the class is unpopulated by design.
const AVS_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_AVS_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_AVS_COMMENTBLOCKN, StyleSlot::Comment),
    (SCE_AVS_COMMENTLINE, StyleSlot::Comment),
    (SCE_AVS_NUMBER, StyleSlot::Number),
    (SCE_AVS_OPERATOR, StyleSlot::Operator),
    (SCE_AVS_STRING, StyleSlot::String),
    (SCE_AVS_TRIPLESTRING, StyleSlot::String),
    (SCE_AVS_KEYWORD, StyleSlot::Keyword),
    (SCE_AVS_FILTER, StyleSlot::Keyword2),
    (SCE_AVS_PLUGIN, StyleSlot::Preprocessor),
    (SCE_AVS_FUNCTION, StyleSlot::Lifetime),
    (SCE_AVS_CLIPPROP, StyleSlot::Macro),
];

// Italic on all three comment forms ŌĆö universal Code++ comment
// convention. Both `/*...*/` and `[*...*]` block comments plus
// `#`-line comments.
const AVS_ITALIC: &[usize] = &[
    SCE_AVS_COMMENTBLOCK,
    SCE_AVS_COMMENTBLOCKN,
    SCE_AVS_COMMENTLINE,
];

// Bold on KEYWORD (class 0 ŌĆö structural control words) ŌĆö primary
// anchor slot. Same single-class-bold discipline as ASN.1
// (KEYWORD), SPICE (KEYWORD), PROPS (SECTION), Makefile (TARGET),
// REBOL (WORD), OScript (KEYWORD), and every LexCPP-family theme
// (WORD).
const AVS_BOLD: &[usize] = &[SCE_AVS_KEYWORD];

// Five-class install matching descriptor order at
// `LexAVS.cxx:284-292` (Keywords, Filters, Plugins, Functions,
// Clip properties). Class 5 "User defined functions" left
// unpopulated by design ŌĆö users who want per-script user-function
// highlighting can extend the wordlist in their local config; the
// framework's default keeps the state as dead code so no
// accidental cross-class collision surprises the reader.
// First-match-wins cascade at `:101-113` probes class 0 ŌåÆ 1 ŌåÆ 2
// ŌåÆ 3 ŌåÆ 4 in forward order; cross-class disjointness is strictly
// enforced by the invariant test.
const AVS_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, AVS_KEYWORDS),
        (1, AVS_FILTERS),
        (2, AVS_PLUGINS),
        (3, AVS_FUNCTIONS),
        (4, AVS_CLIPPROPS),
    ],
    styles: AVS_STYLES,
    italic: AVS_ITALIC,
    bold: AVS_BOLD,
};

// --- LexBasic (BlitzBasic dialect) ---
// BlitzBasic 3D ŌĆö game / 3D scripting language (extension `.bb`).
// `L_BLITZBASIC` (id 67) is the row for the classic Blitz3D
// dialect; the same `LexBasic` lexer also serves PureBasic and
// FreeBasic (both currently ­¤¤Ī unwired) ŌĆö those two will get
// their own themes in follow-on commits, reusing the shared
// `SCE_B_*` namespace with per-family wordlists and comment-char
// differences. See the `LexBasic` dispatch citation in
// `scintilla-sys/src/lib.rs` for the three-way lexer sharing
// analysis and the last-match-wins classifier discipline.
//
// **17 style mappings** covering 23 defined SCE_B_* states
// (0..=22). Six unmapped per the framework's fall-through-to-
// STYLE_DEFAULT convention:
//   * `DEFAULT` (0) ŌĆö whitespace / unclassified.
//   * `IDENTIFIER` (7) ŌĆö transient bareword collect state at
//     `LexBasic.cxx:333`. Same convention as `SCE_C_IDENTIFIER` /
//     `SCE_ASN1_IDENTIFIER` / `SCE_AVS_IDENTIFIER`.
//   * `DATE` (8) ŌĆö DEAD STATE. Grep confirms `LexBasic.cxx` has
//     ZERO `SetState`/`ChangeState`/`ForwardSetState` sites
//     referencing `SCE_B_DATE`; the slot exists in `SciLexer.h`
//     only for `LexVB` (which does emit `#1/1/2024#` date
//     literals). LexBasic never enters this state.
//   * `STRINGEOL` (9) ŌĆö DEAD STATE. LexBasic uses `SCE_B_ERROR`
//     instead ŌĆö `:385-388` changes state to `SCE_B_ERROR` when
//     a string doesn't terminate before line end. STRINGEOL is
//     `LexVB`-only.
//   * `ASM` (14) ŌĆö DEAD STATE. Reserved in `SciLexer.h` for a
//     potential inline-assembly annotation, but `LexBasic` has
//     no `SetState` site. Unreachable.
//   * `ERROR` (16) ŌĆö authoritative parse-failure state emitted
//     at `LexBasic.cxx:386, :467`. Left unmapped per the
//     framework's `StyleSlot::Error`-migration convention
//     (deferred to a future dedicated error slot). Same
//     discipline as Visual Prolog's error state.
//
// Mapped slots (17):
//   * `COMMENT` (1) ŌåÆ Comment italic ŌĆö `;`-to-EOL line comments
//     (`BlitzBasic`'s comment character per `LexerFactoryBlitzBasic`
//     at `LexBasic.cxx:277`).
//   * `NUMBER` (2) ŌåÆ Number ŌĆö decimal digit runs.
//   * `KEYWORD` (3) ŌåÆ Keyword bold ŌĆö class 0 language keywords
//     (`function` / `if` / `for` / `type` / ...).
//   * `STRING` (4) ŌåÆ String ŌĆö `"..."` double-quoted strings.
//   * `PREPROCESSOR` (5) ŌåÆ Preprocessor ŌĆö reserved but
//     **unreachable in BlitzBasic**. The trigger at
//     `LexBasic.cxx:437` is gated on `comment_char == '\''`
//     (FreeBasic-only, the "deprecated QBASIC `'$Include`" hack).
//     `BlitzBasic`'s comment char is `;`, so PREPROCESSOR never
//     fires. Mapping preserves the paint for future FreeBasic
//     wiring; harmless for BlitzBasic.
//   * `OPERATOR` (6) ŌåÆ Operator ŌĆö arithmetic / comparison /
//     assignment plus the sigil chars `.` / `$` / `%` / `#` at
//     `:355-358` (type-suffix operators like `foo$` = string).
//   * `KEYWORD2` (10) ŌåÆ Keyword2 accent ŌĆö class 1 Blitz3D
//     built-in library commands (`sin` / `chr` / `graphics3d` /
//     `renderworld` / ...).
//   * `KEYWORD3` (11) ŌåÆ Preprocessor ŌĆö class 2 user-defined
//     wordlist. Empty by config; slot mapped for future
//     population.
//   * `KEYWORD4` (12) ŌåÆ Lifetime ŌĆö class 3 user-defined
//     wordlist. Empty by config; slot mapped for future
//     population.
//   * `CONSTANT` (13) ŌåÆ Macro ŌĆö `#`-prefixed bareword constants
//     (`#PI` / `#TWO_PI` ŌĆö user's own named constants). Entered
//     at `LexBasic.cxx:460`.
//   * `LABEL` (15) ŌåÆ Macro ŌĆö labels for `goto` / `gosub`
//     targets. Two emission paths:
//     - Line-leading `.name` on non-FreeBasic (`comment_char !=
//       '\''`) at `:429-430` ŌĆö the dot-prefix Blitz label form,
//       SetState directly to LABEL.
//     - Colon-triggered promotion at `:336-338` ŌĆö an
//       identifier collected as `SCE_B_IDENTIFIER` gets
//       `ChangeState(SCE_B_LABEL)` when the terminating
//       character is `:`. Covers both plain `name:` and the
//       line-leading `#name:` form (line-leading `#name`
//       initially enters IDENTIFIER at `:431-433`, then the
//       colon-check promotes to LABEL if present ŌĆö otherwise
//       the identifier stays and is classified by wordlist
//       lookup normally).
//   * `HEXNUMBER` (17) ŌåÆ Number ŌĆö `$hex` or `&h...` / `&H...`
//     hex literals (Blitz uses `$FF` per `:455`).
//   * `BINNUMBER` (18) ŌåÆ Number ŌĆö `%bin` or `&b...` / `&B...`
//     binary literals.
//   * `COMMENTBLOCK` (19) ŌåÆ Comment italic ŌĆö `/'... '/` block
//     comment form. Not idiomatic BlitzBasic but Lexilla
//     enables it universally per `:444-449`; mapping keeps the
//     paint consistent.
//   * `DOCLINE` (20) ŌåÆ Comment italic ŌĆö `'*` / `'!` line-doc
//     comments (FreeBasic idiom). Technically unreachable in
//     BlitzBasic since the trigger at `:439` hard-codes `'` not
//     `comment_char`, but mapping preserves the paint for
//     future FreeBasic wiring.
//   * `DOCBLOCK` (21) ŌåÆ Comment italic ŌĆö `/'*` / `/'!` block-
//     doc form (gtk-doc / Doxygen). Same rationale as DOCLINE.
//   * `DOCKEYWORD` (22) ŌåÆ Preprocessor ŌĆö `\keyword` / `@keyword`
//     inline doc tags at `:397-400, :417-420` inside DOCLINE /
//     DOCBLOCK. Distinct paint so the reader sees the tag
//     separately from the surrounding doc-comment prose.
//
// Palette rationale: `BlitzBasic`'s classic use-case is game +
// script code with strong control-flow anchors and a large
// standard library. The Keyword / Keyword2 split cleanly
// separates language grammar from stdlib API surface. CONSTANT
// (`#foo`) and LABEL (`.foo`) both map to Macro ŌĆö both are
// anchor-shaped identifiers with a leading sigil, structurally
// similar enough to share the paint slot. Doc-comment states
// (DOCLINE / DOCBLOCK / DOCKEYWORD) are FreeBasic-family
// idiom preserved for future FreeBasic wiring; harmless in
// BlitzBasic since they're never emitted with `;` comment char.
const BLITZBASIC_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_B_COMMENT, StyleSlot::Comment),
    (SCE_B_NUMBER, StyleSlot::Number),
    (SCE_B_KEYWORD, StyleSlot::Keyword),
    (SCE_B_STRING, StyleSlot::String),
    (SCE_B_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_B_OPERATOR, StyleSlot::Operator),
    (SCE_B_KEYWORD2, StyleSlot::Keyword2),
    (SCE_B_KEYWORD3, StyleSlot::Preprocessor),
    (SCE_B_KEYWORD4, StyleSlot::Lifetime),
    (SCE_B_CONSTANT, StyleSlot::Macro),
    (SCE_B_LABEL, StyleSlot::Macro),
    (SCE_B_HEXNUMBER, StyleSlot::Number),
    (SCE_B_BINNUMBER, StyleSlot::Number),
    (SCE_B_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_B_DOCLINE, StyleSlot::Comment),
    (SCE_B_DOCBLOCK, StyleSlot::Comment),
    (SCE_B_DOCKEYWORD, StyleSlot::Preprocessor),
];

// Italic on all four comment forms ŌĆö universal Code++ comment
// convention. Includes DOCLINE / DOCBLOCK (technically dead in
// BlitzBasic per the banner) so a future FreeBasic wiring can
// reuse this list.
const BLITZBASIC_ITALIC: &[usize] = &[
    SCE_B_COMMENT,
    SCE_B_COMMENTBLOCK,
    SCE_B_DOCLINE,
    SCE_B_DOCBLOCK,
];

// Bold on KEYWORD (class 0 ŌĆö language keywords) ŌĆö primary
// structural anchor. Same single-class-bold discipline as ASN.1
// (KEYWORD), AviSynth (KEYWORD), SPICE (KEYWORD), and every
// LexCPP-family theme (WORD).
const BLITZBASIC_BOLD: &[usize] = &[SCE_B_KEYWORD];

// Two-class install. Classes 0 (language keywords) and 1 (Blitz3D
// built-in library) are populated; classes 2 (user2) and 3
// (user3) ŌĆö the second and third user-customization slots per
// `blitzbasicWordListDesc[]` at `LexBasic.cxx:180-186` ŌĆö stay
// uninstalled by design. Their SCE_ slots (KEYWORD3 / KEYWORD4)
// ARE mapped in `BLITZBASIC_STYLES` so a future user config that
// populates them via LOCAL wordlist injection gets a defined paint.
//
// LexBasic's classifier at `:348-352` uses **last-match-wins**;
// class 0 and class 1 stay disjoint (invariant-tested) so a
// stdlib function name never accidentally renders as language
// keyword or vice versa.
const BLITZBASIC_THEME: LangTheme = LangTheme {
    keywords: &[(0, BLITZBASIC_KEYWORDS), (1, BLITZBASIC_BUILTINS)],
    styles: BLITZBASIC_STYLES,
    italic: BLITZBASIC_ITALIC,
    bold: BLITZBASIC_BOLD,
};

// --- LexBasic (PureBasic dialect) ---
// PureBasic ŌĆö general-purpose programming language (extension
// `.pb`) with strong compile-time metaprogramming features
// (procedures, structures, modules, macros, compiler directives).
// `L_PUREBASIC` (id 68) rides the same shared `LexBasic` lexer as
// BlitzBasic; per-family differences are only the comment
// character (`;` ŌĆö shared with BlitzBasic per
// `LexBasic.cxx:280`), the fold-check function
// (`CheckPureFoldPoint` at `:116-131` recognises
// `procedure` / `enumeration` / `interface` / `structure` as
// fold points), and the wordlist descriptor
// (`purebasicWordListDesc[]` at `:188-194`).
//
// **Class 1 has semantic meaning here ŌĆö unlike BlitzBasic.**
// `purebasicWordListDesc[]:190` labels class 1 as `"PureBasic
// PreProcessor Keywords"` ŌĆö the ONLY member of the `LexBasic`
// family whose class 1 has a specific assigned purpose. Code++
// therefore routes `SCE_B_KEYWORD2` ŌåÆ `StyleSlot::Preprocessor`
// for the PureBasic theme (magenta / distinct color), rather
// than the generic Keyword2 accent used by BlitzBasic. This
// visually separates compile-time directives (`CompilerIf` /
// `EnableExplicit` / `IncludeFile`) from language keywords
// (`Procedure` / `If` / `For`) ŌĆö matching the C-family
// `SCE_C_PREPROCESSOR` convention that renders `#if` / `#define`
// distinctly from `if` / `while`.
//
// Same paint-loop as BlitzBasic ŌĆö see the BLITZBASIC_STYLES
// banner above for the full per-state analysis. This banner
// documents only the PureBasic-specific deviations:
//
//   * `KEYWORD2` (10) ŌåÆ **Preprocessor** (magenta) ŌĆö class 1
//     compile-time directives. BlitzBasic routes this to
//     Keyword2; PureBasic routes to Preprocessor since the
//     class semantically IS preprocessor per the descriptor.
//   * `KEYWORD3` (11) ŌåÆ Preprocessor ŌĆö class 2 user-defined 1.
//     Kept at Preprocessor same as BlitzBasic for consistency;
//     empty by config.
//   * `KEYWORD4` (12) ŌåÆ Lifetime ŌĆö class 3 user-defined 2.
//     Kept at Lifetime same as BlitzBasic; empty by config.
//   * All other slots (COMMENT / NUMBER / KEYWORD / STRING /
//     PREPROCESSOR / OPERATOR / CONSTANT / LABEL / HEXNUMBER /
//     BINNUMBER / COMMENTBLOCK / DOCLINE / DOCBLOCK /
//     DOCKEYWORD) route identically to BlitzBasic.
//
// **DOCLINE / DOCBLOCK / PREPROCESSOR (SCE_B_PREPROCESSOR ŌĆö the
// FreeBasic `'$Include` hack)** all remain dead in PureBasic
// same as BlitzBasic ŌĆö their triggers hard-code `'`, not the
// per-family comment_char. Mapping preserves the paint for
// future FreeBasic wiring; harmless for PureBasic.
const PUREBASIC_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_B_COMMENT, StyleSlot::Comment),
    (SCE_B_NUMBER, StyleSlot::Number),
    (SCE_B_KEYWORD, StyleSlot::Keyword),
    (SCE_B_STRING, StyleSlot::String),
    (SCE_B_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_B_OPERATOR, StyleSlot::Operator),
    (SCE_B_KEYWORD2, StyleSlot::Preprocessor),
    (SCE_B_KEYWORD3, StyleSlot::Preprocessor),
    (SCE_B_KEYWORD4, StyleSlot::Lifetime),
    (SCE_B_CONSTANT, StyleSlot::Macro),
    (SCE_B_LABEL, StyleSlot::Macro),
    (SCE_B_HEXNUMBER, StyleSlot::Number),
    (SCE_B_BINNUMBER, StyleSlot::Number),
    (SCE_B_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_B_DOCLINE, StyleSlot::Comment),
    (SCE_B_DOCBLOCK, StyleSlot::Comment),
    (SCE_B_DOCKEYWORD, StyleSlot::Preprocessor),
];

// Italic on all four comment forms ŌĆö matches BlitzBasic
// discipline verbatim. DOCLINE / DOCBLOCK dead in PureBasic
// per the banner but preserved for future FreeBasic reuse.
const PUREBASIC_ITALIC: &[usize] = &[
    SCE_B_COMMENT,
    SCE_B_COMMENTBLOCK,
    SCE_B_DOCLINE,
    SCE_B_DOCBLOCK,
];

// Bold on KEYWORD (class 0) ŌĆö same discipline as BlitzBasic /
// every other Code++ theme with a primary structural anchor.
const PUREBASIC_BOLD: &[usize] = &[SCE_B_KEYWORD];

// Two-class install matching `purebasicWordListDesc[]` at
// `LexBasic.cxx:188-194`. Class 0 is "PureBasic Keywords"
// (language grammar), class 1 is "PureBasic PreProcessor
// Keywords" (compile-time directives). Classes 2 and 3
// ("user defined 1" / "user defined 2") remain uninstalled
// by config ŌĆö same discipline as `BlitzBasic`'s user1/user2
// slots. Last-match-wins across the four classes; class-0-vs-
// class-1 disjointness is invariant-tested.
const PUREBASIC_THEME: LangTheme = LangTheme {
    keywords: &[(0, PUREBASIC_KEYWORDS), (1, PUREBASIC_PREPROCESSOR)],
    styles: PUREBASIC_STYLES,
    italic: PUREBASIC_ITALIC,
    bold: PUREBASIC_BOLD,
};

// --- LexBasic (FreeBASIC dialect) ---
// FreeBASIC ŌĆö QuickBASIC-compatible language with modern
// object-oriented extensions (extension `.bas`). `L_FREEBASIC`
// (id 69) is the THIRD and final `LexBasic` family member ŌĆö
// completing the shared-lexer trio (BlitzBasic + PureBasic +
// FreeBasic).
//
// Per-family differences from BlitzBasic + PureBasic:
//   * **Comment character** ŌĆö FreeBASIC uses `'` (apostrophe)
//     per `LexerFactoryFreeBasic` at `LexBasic.cxx:283`. This
//     is the ONLY member using apostrophe; BlitzBasic and
//     PureBasic both use `;`. Structural consequence: several
//     `LexBasic.cxx` states that are DEAD in BB/PB are LIVE
//     in FB (see below).
//   * **Fold-check function** ŌĆö `CheckFreeFoldPoint` at
//     `:133-156` recognises EIGHT fold points
//     (`function` / `sub` / `enum` / `type` / `union` /
//     `property` / `destructor` / `constructor`) vs
//     BlitzBasic's TWO (`function` / `type`) and PureBasic's
//     FOUR (`procedure` / `enumeration` / `interface` /
//     `structure`). Reflects FreeBASIC's richer OO surface.
//   * **Wordlist descriptor** ŌĆö `freebasicWordListDesc[]` at
//     `:196-202` names class 1 as `"FreeBasic PreProcessor
//     Keywords"` ŌĆö same semantic assignment as PureBasic.
//
// **DEAD-STATE STATUS INVERSION vs BlitzBasic/PureBasic.** Four
// SCE_B_* states that were dead in BB/PB are LIVE in FreeBASIC
// because their triggers are gated on the apostrophe comment
// char:
//   * `SCE_B_PREPROCESSOR` (5) ŌĆö trigger at `:437` gated on
//     `comment_char == '\''`. Fires on `'$Include` (deprecated
//     QBASIC syntax preserved via the `LexBasic.cxx:435-438`
//     "hack" comment). LIVE in FB, dead in BB/PB.
//   * `SCE_B_DOCLINE` (20) ŌĆö trigger at `:439-441` hard-codes
//     `\'` (apostrophe). Fires on `'*` / `'!` line-doc
//     comments (QBASIC / FreeBASIC idiom). LIVE in FB (since
//     apostrophe IS the comment char), dead in BB/PB (since
//     their `;` comment char precludes the `'*` sequence
//     from being reachable via the outer `sc.Match(comment_char)`
//     gate at `:434`).
//   * `SCE_B_DOCBLOCK` (21) ŌĆö trigger at `:444-448` also uses
//     `/'` regardless of comment_char. **This state fires the
//     same way in all three families** since block-comment
//     entry doesn't care about comment_char ŌĆö but the doc-tag
//     variants (`/'*` / `/'!`) are only semantically meaningful
//     when apostrophe is the line-comment char. Framework maps
//     to Comment for all three families for consistency.
//   * `SCE_B_DOCKEYWORD` (22) ŌĆö trigger at `:397-400` inside
//     DOCLINE / DOCBLOCK on `\keyword` / `@keyword`. LIVE in
//     FB (since DOCLINE fires), effectively dead in BB/PB
//     (since DOCLINE doesn't fire in either).
//
// **17 style mappings identical to PureBasic.** Since FreeBASIC
// and PureBasic share the same class-1 = preprocessor
// descriptor assignment, and every other SCE_B_* slot has the
// same semantic role across the two families, `FREEBASIC_STYLES`
// / `_ITALIC` / `_BOLD` **alias** to the corresponding
// `PUREBASIC_*` constants verbatim. Same const-aliasing
// discipline as the SREC / IHEX / TEHEX trio's cross-lexer
// bold/italic sharing.
//
// Note: The theme tables are structurally identical to
// PureBasic's, but the SEMANTIC live/dead status of the slots
// differs ŌĆö PREPROCESSOR / DOCLINE are dead in PB but live in
// FB per the analysis above. The paint mapping stays the same
// so a `'$Include` directive in FB paints correctly as
// Preprocessor magenta.
const FREEBASIC_STYLES: &[(usize, StyleSlot)] = PUREBASIC_STYLES;
const FREEBASIC_ITALIC: &[usize] = PUREBASIC_ITALIC;
const FREEBASIC_BOLD: &[usize] = PUREBASIC_BOLD;

// Two-class install matching `freebasicWordListDesc[]` at
// `LexBasic.cxx:196-202`. Class 0 is "FreeBasic Keywords"
// (language grammar ŌĆö 116 tokens covering QBASIC-inherited
// statements plus FreeBASIC OO extensions), class 1 is
// "FreeBasic PreProcessor Keywords" (bareword compile-time
// operators ŌĆö 9 tokens). Classes 2 and 3 stay uninstalled
// by design (same as BB / PB user1 / user2 slots).
//
// Last-match-wins across the four classes; class-0-vs-class-1
// disjointness is invariant-tested. Both directions matter:
// a class-0 keyword duplicated in class 1 would render as
// Preprocessor (wrong ŌĆö should be Keyword), and a class-1
// operator duplicated in class 0 would ALSO render as
// Preprocessor (correct paint but wrong-authorship-intent
// path ŌĆö the class-1 install becomes silent decoration).
const FREEBASIC_THEME: LangTheme = LangTheme {
    keywords: &[(0, FREEBASIC_KEYWORDS), (1, FREEBASIC_PREPROCESSOR)],
    styles: FREEBASIC_STYLES,
    italic: FREEBASIC_ITALIC,
    bold: FREEBASIC_BOLD,
};

// --- LexTxt2tags ---
// txt2tags ŌĆö lightweight-markup / plain-text-to-many-formats
// converter (extension `.t2t`). `L_TXT2TAGS` (id 83) is the only
// language row using this lexer. Zero-wordlist markup lexer per
// `LexTxt2tags.cxx:479` (3-argument `LexerModule` registration
// with no `wordListDesc`) ŌĆö same family as PROPS / LaTeX / TeX /
// Registry. See the `LexTxt2tags` banner in
// `scintilla-sys/src/lib.rs` for the paint-loop citations.
//
// Style-to-slot decisions (22 mappings across 26 defined slots):
//
//   * `STRONG1` (2) ŌåÆ Keyword (bold) ŌĆö `**bold**` inline strong
//     text. Same Keyword+bold treatment as HEADER slots below;
//     STRONG is inline strong emphasis, HEADER is line-scoped
//     structural emphasis. Both deserve visible weight.
//   * `EM1` (4) ŌåÆ Keyword (italic) ŌĆö `//italic//` inline
//     emphasis. Keyword base colour to visually pair with STRONG,
//     italic modifier to distinguish semantically.
//   * `EM2` (5) ŌåÆ Keyword (italic) ŌĆö `__underline__` inline
//     emphasis. Same Keyword+italic as EM1; underline is a
//     secondary emphasis style rendered visually as italic in
//     Notepad++-style theming.
//   * `HEADER1..HEADER6` (6..11) ŌåÆ Keyword (bold) ŌĆö six levels
//     of `= H1 =` / `+ H1 +` / ŌĆ” / `====== H6 ======` /
//     `++++++ H6 ++++++`. All six deserve prominent structural
//     emphasis; the level distinction is documented by count of
//     `=` / `+` in the source, not by colour (matches Notepad++
//     defaults for Markdown-family lexers).
//   * `ULIST_ITEM` (13) ŌåÆ Preprocessor ŌĆö `- item` unordered
//     list bullet marker. Same "out-of-band structural marker"
//     accent as INI's DEFVAL, Batch's leading `@`, Registry's
//     DELETEDKEY / PARAMETER.
//   * `OLIST_ITEM` (14) ŌåÆ Preprocessor ŌĆö `1. item` numbered or
//     `+ item` alternate ordered list marker. Same accent as
//     ULIST_ITEM for structural parity.
//   * `BLOCKQUOTE` (15) ŌåÆ Comment (italic) ŌĆö `""" quote`
//     blockquote marker. Same Comment+italic as line comments ŌĆö
//     quotes are semantically "out-of-band prose" like comments.
//   * `STRIKEOUT` (16) ŌåÆ Keyword2 ŌĆö `--strike--` inline
//     strikeout. Distinct Keyword2 accent so struck text reads
//     as visually deprecated relative to STRONG/EM.
//   * `HRULE` (17) ŌåÆ Operator ŌĆö 20+-hyphen horizontal-rule
//     separator. Structural divider role ŌĆö same Operator slot
//     as punctuation delimiters.
//   * `LINK` (18) ŌåÆ String ŌĆö `[text]` / `[text url]` /
//     `![image]` link and image markup. URLs paint universally
//     as String across every lexer.
//   * `CODE` (19) ŌåÆ String ŌĆö `|table row|` pipe-delimited
//     table row. Table cells are literal data ŌĆö String slot
//     matches the universal literal-value convention.
//   * `CODE2` (20) ŌåÆ String ŌĆö `` `` inline code `` `` ŌĆö same
//     literal-code semantics as CODE.
//   * `CODEBK` (21) ŌåÆ String ŌĆö `` ``` `` fenced code block.
//     Same String slot for consistent code visualisation
//     across inline / block / table forms.
//   * `COMMENT` (22) ŌåÆ Comment (italic) ŌĆö `%`-to-EOL line
//     comment. Universal Comment slot.
//   * `OPTION` (23) ŌåÆ Preprocessor ŌĆö `%!key : value` document
//     option directive.
//   * `PREPROC` (24) ŌåÆ Preprocessor ŌĆö `%!preproc: pattern
//     replacement` directive.
//   * `POSTPROC` (25) ŌåÆ Preprocessor ŌĆö `%!postproc: pattern
//     replacement` directive. OPTION / PREPROC / POSTPROC all
//     share the Preprocessor slot for consistent
//     directive-family highlighting.
//
// Unmapped slots (framework convention, 4 total):
//
//   * `DEFAULT` (0) ŌĆö plain body text. Standard framework
//     convention ŌĆö falls through to `STYLE_DEFAULT`.
//   * `LINE_BEGIN` (1) ŌĆö transient line-start scan state
//     entered at every newline / role-exit. Any byte painted
//     into LINE_BEGIN is the newline itself; leave unmapped
//     so it inherits the DEFAULT foreground.
//   * `STRONG2` (3) ŌĆö DEAD STATE. Verified: zero call sites
//     in `LexTxt2tags.cxx` emit the slot (no `SetState`,
//     `ChangeState`, or `ForwardSetState`). Reserved in
//     `SciLexer.h` but never entered at runtime. Leave
//     unmapped since no bytes ever paint into it.
//   * `PRECHAR` (12) ŌĆö transient leading-whitespace scan state
//     between LINE_BEGIN and the settled role state (DEFAULT /
//     ULIST_ITEM / OLIST_ITEM / BLOCKQUOTE). Same rationale as
//     LINE_BEGIN.
const TXT2TAGS_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_TXT2TAGS_STRONG1, StyleSlot::Keyword),
    (SCE_TXT2TAGS_EM1, StyleSlot::Keyword),
    (SCE_TXT2TAGS_EM2, StyleSlot::Keyword),
    (SCE_TXT2TAGS_HEADER1, StyleSlot::Keyword),
    (SCE_TXT2TAGS_HEADER2, StyleSlot::Keyword),
    (SCE_TXT2TAGS_HEADER3, StyleSlot::Keyword),
    (SCE_TXT2TAGS_HEADER4, StyleSlot::Keyword),
    (SCE_TXT2TAGS_HEADER5, StyleSlot::Keyword),
    (SCE_TXT2TAGS_HEADER6, StyleSlot::Keyword),
    (SCE_TXT2TAGS_ULIST_ITEM, StyleSlot::Preprocessor),
    (SCE_TXT2TAGS_OLIST_ITEM, StyleSlot::Preprocessor),
    (SCE_TXT2TAGS_BLOCKQUOTE, StyleSlot::Comment),
    (SCE_TXT2TAGS_STRIKEOUT, StyleSlot::Keyword2),
    (SCE_TXT2TAGS_HRULE, StyleSlot::Operator),
    (SCE_TXT2TAGS_LINK, StyleSlot::String),
    (SCE_TXT2TAGS_CODE, StyleSlot::String),
    (SCE_TXT2TAGS_CODE2, StyleSlot::String),
    (SCE_TXT2TAGS_CODEBK, StyleSlot::String),
    (SCE_TXT2TAGS_COMMENT, StyleSlot::Comment),
    (SCE_TXT2TAGS_OPTION, StyleSlot::Preprocessor),
    (SCE_TXT2TAGS_PREPROC, StyleSlot::Preprocessor),
    (SCE_TXT2TAGS_POSTPROC, StyleSlot::Preprocessor),
];

// Italic on COMMENT + BLOCKQUOTE (universal prose-out-of-band
// convention) + EM1 + EM2 (semantic italic / underline emphasis
// markers ŌĆö visually rendered as italic).
const TXT2TAGS_ITALIC: &[usize] = &[
    SCE_TXT2TAGS_COMMENT,
    SCE_TXT2TAGS_BLOCKQUOTE,
    SCE_TXT2TAGS_EM1,
    SCE_TXT2TAGS_EM2,
];

// Bold on STRONG1 (semantic bold marker) + all six HEADER
// levels. Multi-slot bold discipline (7 slots) ŌĆö same pattern
// applied to headers as prior lexers apply to structural
// anchors, but txt2tags has genuinely 6 header levels + 1
// inline strong that all deserve the treatment.
const TXT2TAGS_BOLD: &[usize] = &[
    SCE_TXT2TAGS_STRONG1,
    SCE_TXT2TAGS_HEADER1,
    SCE_TXT2TAGS_HEADER2,
    SCE_TXT2TAGS_HEADER3,
    SCE_TXT2TAGS_HEADER4,
    SCE_TXT2TAGS_HEADER5,
    SCE_TXT2TAGS_HEADER6,
];

// Zero-wordlist theme ŌĆö same pattern as PROPS / LaTeX / TeX /
// Registry. `keywords: &[]` is REQUIRED here: the lexer's
// `LexerModule` registration at `LexTxt2tags.cxx:479` takes no
// `wordListDesc` argument and the paint function's WordList**
// parameter is unnamed and never referenced. Excluded from
// `wired_languages_have_complete_themes` because
// `TXT2TAGS_THEME.keywords = &[]` violates that test's
// `!keywords.is_empty()` floor ŌĆö matches the PROPS / LATEX /
// REGISTRY precedents. The dedicated
// `txt2tags_uses_lextxt2tags_zero_class_theme` test below pins
// the 22-mapping shape, empty-keywords invariant, style-routing
// pins, and cross-language non-reuse.
const TXT2TAGS_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: TXT2TAGS_STYLES,
    italic: TXT2TAGS_ITALIC,
    bold: TXT2TAGS_BOLD,
};

// --- LexTOML ---
// TOML (Tom's Obvious, Minimal Language) ŌĆö configuration file
// format (extension `.toml`). `L_TOML` (id 90) is the only
// language row using this lexer. Single-wordlist descriptor (just
// bareword literals `true` / `false` / `inf` / `nan`) with a
// complex state machine covering four string flavours, ISO date-
// time literals, and TOML-specific TABLE / KEY structural anchor
// states. See the `LexTOML` banner in `scintilla-sys/src/lib.rs`
// for the paint-loop citations.
//
// **12 style mappings** covering 16 defined SCE_TOML_* states
// (0..=15). Four unmapped per the framework's fall-through-to-
// STYLE_DEFAULT convention:
//   * `DEFAULT` (0) ŌĆö whitespace / unclassified.
//   * `IDENTIFIER` (2) ŌĆö transient bareword-collect state at
//     `LexTOML.cxx:207-214`. The state never survives to paint ŌĆö
//     `IsTOMLKey` at `:122-142` either promotes to KEY (when the
//     next non-whitespace is `=`/`.`/`-` in inline-table context)
//     or KEYWORD (when the collected token is in the wordlist),
//     or falls through to DEFAULT. Framework leaves unmapped per
//     the transient-collect-fallthrough convention.
//   * `ERROR` (7) ŌĆö parse-failure state at `:353` for bad line-
//     start characters. Left unmapped per the framework's
//     deferred `StyleSlot::Error`-migration convention.
//   * `STRINGEOL` (15) ŌĆö parse-failure state at `:281-282` for
//     unterminated single-line strings (SQ or DQ, NOT triple
//     variants which span lines). Same deferred `Error`
//     convention.
//
// Mapped slots (12):
//   * `COMMENT` (1) ŌåÆ Comment italic ŌĆö `#`-to-EOL line comments.
//   * `KEYWORD` (3) ŌåÆ Keyword bold ŌĆö TOML's four bareword
//     literals (`true`/`false`/`inf`/`nan` per the upstream
//     fixture at `crates/scintilla-sys/vendor/lexilla/test/
//     examples/toml/SciTE.properties`).
//   * `NUMBER` (4) ŌåÆ Number ŌĆö integer + float + hex (`0x`) +
//     octal (`0o`) + binary (`0b`) + `_`-separator numeric
//     literals per TOML v1.0.0 ┬¦Integer and ┬¦Float.
//   * `TABLE` (5) ŌåÆ Preprocessor ŌĆö `[table]` and
//     `[[array.of.tables]]` header lines. Structural anchor
//     archetype, same slot as `[section]` markers in PROPS /
//     Registry / INI.
//   * `KEY` (6) ŌåÆ Keyword2 ŌĆö key names on LHS of `key = value`
//     assignments, including dot-separated (`foo.bar.baz`) and
//     quoted variants. Distinct accent from KEYWORD so a TOML
//     reader visually separates keys from values.
//   * `OPERATOR` (8) ŌåÆ Operator ŌĆö TOML operator set
//     (`[`/`]`/`{`/`}`/`,`/`=`/`.`/`+`/`-` per `IsTOMLOperator`
//     at `LexTOML.cxx:91-93`).
//   * `STRING_SQ` (9) ŌåÆ String ŌĆö single-quoted literal strings.
//   * `STRING_DQ` (10) ŌåÆ String ŌĆö double-quoted basic strings
//     (with escape processing).
//   * `TRIPLE_STRING_SQ` (11) ŌåÆ String ŌĆö `'''...'''` multi-line
//     literal.
//   * `TRIPLE_STRING_DQ` (12) ŌåÆ String ŌĆö `"""..."""` multi-line
//     basic (with escapes).
//   * `ESCAPECHAR` (13) ŌåÆ Preprocessor ŌĆö escape sequences inside
//     DQ / TRIPLE_STRING_DQ variants (`\n` / `\uXXXX` / `\xNN` /
//     etc.). Distinct accent from surrounding string content ŌĆö
//     matches the `SCE_RUST_BYTEESCAPE` convention for "escape
//     stands out visually".
//   * `DATETIME` (14) ŌåÆ Number ŌĆö RFC 3339 ISO date-time literals
//     (`1979-05-27T07:32:00-07:00` and local variants). Numeric-
//     literal archetype per TOML spec ŌĆö datetimes ARE numeric
//     constants.
//
// Palette rationale: TOML's spec-mandated four string flavours
// all collapse to String (same discipline as Python / Raku
// multi-quote unification). The TABLE / KEY split is TOML-
// specific ŌĆö Preprocessor for headers (structural markers) and
// Keyword2 for keys (LHS accent) ŌĆö gives the reader visual
// hierarchy that matches TOML's "sections of key = value"
// document model.
const TOML_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_TOML_COMMENT, StyleSlot::Comment),
    (SCE_TOML_KEYWORD, StyleSlot::Keyword),
    (SCE_TOML_NUMBER, StyleSlot::Number),
    (SCE_TOML_TABLE, StyleSlot::Preprocessor),
    (SCE_TOML_KEY, StyleSlot::Keyword2),
    (SCE_TOML_OPERATOR, StyleSlot::Operator),
    (SCE_TOML_STRING_SQ, StyleSlot::String),
    (SCE_TOML_STRING_DQ, StyleSlot::String),
    (SCE_TOML_TRIPLE_STRING_SQ, StyleSlot::String),
    (SCE_TOML_TRIPLE_STRING_DQ, StyleSlot::String),
    (SCE_TOML_ESCAPECHAR, StyleSlot::Preprocessor),
    (SCE_TOML_DATETIME, StyleSlot::Number),
];

// Italic on COMMENT ŌĆö universal Code++ comment convention.
const TOML_ITALIC: &[usize] = &[SCE_TOML_COMMENT];

// Bold on KEYWORD ŌĆö primary structural anchor (the four bareword
// literals). Same single-class-bold discipline as every other
// Code++ theme.
const TOML_BOLD: &[usize] = &[SCE_TOML_KEYWORD];

// Single-class install matching `tomlWordListDesc[]` at
// `LexTOML.cxx:489-492` ŌĆö one wordlist entry `"Keywords"`
// carrying the four bareword literals.
const TOML_THEME: LangTheme = LangTheme {
    keywords: &[(0, TOML_KEYWORDS)],
    styles: TOML_STYLES,
    italic: TOML_ITALIC,
    bold: TOML_BOLD,
};

// --- LexSAS ---
// SAS (Statistical Analysis System) ŌĆö proprietary statistical
// programming language and analytics platform from SAS Institute
// Inc. (extension `.sas`). `L_SAS` (id 91) is the only language
// row using this lexer. Four-class wordlist descriptor per
// `LexSAS.cxx:41-44` (macro keywords / block keywords / macro
// functions / statements ŌĆö despite the upstream header at
// `:216-221` listing only three names before the null
// terminator). See the `LexSAS` banner in
// `scintilla-sys/src/lib.rs` for the dispatch semantics and the
// header/body naming mismatch analysis.
//
// **11 style mappings** covering 16 defined SCE_SAS_* states
// (0..=15). Five unmapped per framework conventions:
//   * `DEFAULT` (0) ŌĆö whitespace / unclassified.
//   * `IDENTIFIER` (6) ŌĆö transient bareword-collect state
//     (`:85-97`). Can survive to paint when the collected token
//     matches neither `statements` nor `blockKeywords` ŌĆö the
//     "unknown identifier" fall-through. Framework leaves
//     unmapped per the transient-collect-fallthrough convention
//     (same discipline as `SCE_TOML_IDENTIFIER`); default paint
//     applies. SAS user variables and PROC-specific keywords
//     that aren't in `statements` fall through here.
//   * `TYPE` (8), `WORD` (9), `GLOBAL_MACRO` (10) ŌĆö declared in
//     SciLexer.h but ZERO references in the `LexSAS.cxx` body
//     (verified via grep). Included in `SCE_SAS_*` constants for
//     numeric-contiguity correctness at the FFI boundary;
//     framework leaves them unmapped per the declared-but-
//     unemitted convention.
//
// Mapped slots (11):
//   * `COMMENT` (1) ŌåÆ Comment italic ŌĆö legacy `* text ;`
//     line-start comment (`LexSAS.cxx:128-130`).
//   * `COMMENTLINE` (2) ŌåÆ Comment italic ŌĆö `// text ;` line
//     comment (`:135-137`).
//   * `COMMENTBLOCK` (3) ŌåÆ Comment italic ŌĆö `/* text */` block
//     comment (`:131-134`).
//   * `NUMBER` (4) ŌåÆ Number ŌĆö numeric literals (integer / float
//     / hex-suffixed, per `:63-68` accepting any word-set char
//     including `.`).
//   * `OPERATOR` (5) ŌåÆ Operator ŌĆö SAS operator set (per
//     `isoperator` at `:146-149`).
//   * `STRING` (7) ŌåÆ String ŌĆö `"..."` double-quoted string.
//     SAS supports both single- and double-quoted forms but the
//     lexer only recognises double-quoted at `:138-141`.
//   * `MACRO` (11) ŌåÆ Macro ŌĆö `%name` reference that didn't
//     match any wordlist. Semantically a user macro invocation
//     (the "unknown %macro" fall-through). Same slot as C's
//     `SCE_C_PREPROCESSOR` fall-through and Rust's macro
//     invocation slot.
//   * `MACRO_KEYWORD` (12) ŌåÆ Preprocessor ŌĆö SAS macro-language
//     directives (`%do` / `%mend` / `%if` ŌĆö from class 0). See
//     the `LexSAS` banner style-routing rationale.
//   * `BLOCK_KEYWORD` (13) ŌåÆ Keyword bold ŌĆö DATA / PROC / RUN
//     step delimiters (from class 1). Primary structural
//     accent.
//   * `MACRO_FUNCTION` (14) ŌåÆ Preprocessor ŌĆö macro intrinsic
//     functions (`%eval` / `%str` / `%sysfunc` ŌĆö from class 2).
//     Same accent as MACRO_KEYWORD (macro-namespace family).
//   * `STATEMENT` (15) ŌåÆ Keyword2 ŌĆö DATA-step / PROC-step
//     statements (`set` / `if` / `where` ŌĆö from class 3).
//     Secondary structural accent.
//
// Palette rationale: SAS has three comment forms which all
// collapse to Comment (universal Code++ discipline). The
// three macro states (MACRO / MACRO_KEYWORD / MACRO_FUNCTION)
// intentionally use two distinct accent slots ŌĆö Macro for the
// user-macro invocation, Preprocessor for the built-in macro
// directives and intrinsics. This visually separates
// "user-defined macro call" from "built-in macro language
// element," a distinction SAS programmers rely on when reading
// macro-heavy code.
const SAS_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_SAS_COMMENT, StyleSlot::Comment),
    (SCE_SAS_COMMENTLINE, StyleSlot::Comment),
    (SCE_SAS_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_SAS_NUMBER, StyleSlot::Number),
    (SCE_SAS_OPERATOR, StyleSlot::Operator),
    (SCE_SAS_STRING, StyleSlot::String),
    (SCE_SAS_MACRO, StyleSlot::Macro),
    (SCE_SAS_MACRO_KEYWORD, StyleSlot::Preprocessor),
    (SCE_SAS_BLOCK_KEYWORD, StyleSlot::Keyword),
    (SCE_SAS_MACRO_FUNCTION, StyleSlot::Preprocessor),
    (SCE_SAS_STATEMENT, StyleSlot::Keyword2),
];

// Italic on the three comment states ŌĆö universal Code++ comment
// convention. Italic-on-comment is the sole cross-language accent
// discipline the theme framework mandates.
const SAS_ITALIC: &[usize] = &[SCE_SAS_COMMENT, SCE_SAS_COMMENTLINE, SCE_SAS_COMMENTBLOCK];

// Bold on `BLOCK_KEYWORD` only ŌĆö primary structural anchor (DATA
// / PROC / RUN step delimiters, from class 1). Single-class-bold
// discipline (Keyword bold, Keyword2 not bold) per every other
// Code++ theme.
const SAS_BOLD: &[usize] = &[SCE_SAS_BLOCK_KEYWORD];

// Four-class install matching the actual `LexSAS.cxx:41-44`
// binding order (`keywords` / `blockKeywords` / `functionKeywords`
// / `statements`) ŌĆö NOT the misleading upstream header order at
// `:216-221`. Both header and body agree on the class-index
// integers; they disagree only on the human-readable class name.
const SAS_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, SAS_KEYWORDS),
        (1, SAS_BLOCK_KEYWORDS),
        (2, SAS_MACRO_FUNCTIONS),
        (3, SAS_STATEMENTS),
    ],
    styles: SAS_STYLES,
    italic: SAS_ITALIC,
    bold: SAS_BOLD,
};

// --- LexErrorList ---
// ErrorList (no default file extension ŌĆö manually selectable via
// Language menu) ŌĆö the historical output-pane lexer authored by
// Neil Hodgson himself in 1998-2001 for SciTE. Semantically parses
// compiler / linter / interpreter diagnostic output line-by-line
// via pattern matching in `RecogniseErrorListLine`
// (`LexErrorList.cxx:232-452`). Notepad++ (and Code++) expose it
// for viewing captured tool output. `L_ERRORLIST` (id 92) is the
// only language row using this lexer. See the `LexErrorList`
// banner in `scintilla-sys/src/lib.rs` for the state-space
// enumeration and slot-routing rationale.
//
// **Zero-wordlist lexer** ŌĆö `emptyWordListDesc[]` at
// `LexErrorList.cxx:44-46` is `{nullptr}`. Classification is
// entirely pattern-based (StartsWith / Contains checks against
// tool-specific message-format signatures). Excluded from
// `wired_languages_have_complete_themes` because
// `ERRORLIST_THEME.keywords = &[]` violates that test's
// `!keywords.is_empty()` floor ŌĆö matches the PROPS / LATEX /
// REGISTRY / TXT2TAGS precedents. The dedicated
// `errorlist_uses_lexerrorlist_zero_class_theme` test below pins
// the 26-mapping shape, empty-keywords invariant, all
// style-routing decisions, ANSI-color-slot deliberately-unmapped
// architectural pin, and cross-language non-reuse.
//
// **26 style mappings** covering the 27 emitted states in
// range 0..=26. One of those 27 stays unmapped:
//   * `DEFAULT` (0) ŌĆö framework fall-through convention.
//
// Additional 29 unmapped slots outside the mapped range:
//   * 27..=31 (5 slots) ŌĆö "unused" per the LexicalClass table at
//     `LexErrorList.cxx:92-96`.
//   * 32..=39 (8 slots) ŌĆö "predefined" per
//     `LexErrorList.cxx:97-104`; framework-reserved indices in
//     the Scintilla `STYLE_*` range.
//   * 40..=55 (16 slots) ŌĆö ANSI escape-sequence color states
//     (`SCE_ERR_ES_BLACK` through `SCE_ERR_ES_WHITE`). Framework
//     leaves these unmapped intentionally ŌĆö see the extensive
//     rationale in the `LexErrorList` banner in
//     `scintilla-sys/src/lib.rs`. TL;DR: the semantic IS
//     "text in specific ANSI color N", and our `StyleSlot`
//     enum has no ANSI-color slot. Mapping any of them would
//     collapse 16 distinct semantic colors into one visual
//     paint.
//
// Mapped slots (26):
//   * 15 diagnostic states (PYTHON / GCC / MS / BORLAND /
//     PERL / NET / LUA / PHP / ELF / IFC / IFORT / ABSF /
//     TIDY / JAVA_STACK / BASH) ŌåÆ Keyword ŌĆö primary
//     attention-getting archetype for "error/warning line
//     from tool X." Also bold.
//   * 4 context / navigation states (CTAG / VALUE /
//     GCC_INCLUDED_FROM / GCC_EXCERPT) ŌåÆ Keyword2 ŌĆö
//     supporting information adjacent to a diagnostic.
//   * `CMD` (4) ŌåÆ Preprocessor ŌĆö SciTE Output pane command
//     echo (`>`-prefixed lines).
//   * `DIFF_ADDITION` (11) ŌåÆ String ŌĆö added-line marker
//     (green tint by String convention).
//   * `DIFF_DELETION` (12) ŌåÆ Macro ŌĆö deleted-line marker
//     (red-orange tint by Macro convention).
//   * `DIFF_CHANGED` (10) ŌåÆ Number ŌĆö changed-line marker
//     (yellow tint by Number convention).
//   * `DIFF_MESSAGE` (13) ŌåÆ Comment ŌĆö diff header
//     (`---`/`+++`-prefixed). Metadata annotation archetype;
//     italic.
//   * `ESCSEQ` (23), `ESCSEQ_UNKNOWN` (24) ŌåÆ Operator ŌĆö
//     terminal control markers; syntactic delimiter role.
//
// Palette rationale: ErrorList's semantic domain (colored
// terminal output + tool diagnostics) doesn't map cleanly onto
// the language-focused `StyleSlot` enum. The framework
// collapses tool-specific diagnostic distinctions into a
// single Keyword accent ŌĆö user's eye needs to pick error
// lines out of surrounding output, and the tool identity is
// preserved at the lexer level even if visually unified.
// Diff-marker states use four DISTINCT semantic slots because
// diff readers need to visually distinguish addition /
// deletion / modification / metadata by color.
const ERRORLIST_STYLES: &[(usize, StyleSlot)] = &[
    // 15 diagnostic states ŌåÆ Keyword bold.
    (SCE_ERR_PYTHON, StyleSlot::Keyword),
    (SCE_ERR_GCC, StyleSlot::Keyword),
    (SCE_ERR_MS, StyleSlot::Keyword),
    (SCE_ERR_BORLAND, StyleSlot::Keyword),
    (SCE_ERR_PERL, StyleSlot::Keyword),
    (SCE_ERR_NET, StyleSlot::Keyword),
    (SCE_ERR_LUA, StyleSlot::Keyword),
    (SCE_ERR_PHP, StyleSlot::Keyword),
    (SCE_ERR_ELF, StyleSlot::Keyword),
    (SCE_ERR_IFC, StyleSlot::Keyword),
    (SCE_ERR_IFORT, StyleSlot::Keyword),
    (SCE_ERR_ABSF, StyleSlot::Keyword),
    (SCE_ERR_TIDY, StyleSlot::Keyword),
    (SCE_ERR_JAVA_STACK, StyleSlot::Keyword),
    (SCE_ERR_BASH, StyleSlot::Keyword),
    // 4 context / navigation states ŌåÆ Keyword2.
    (SCE_ERR_CTAG, StyleSlot::Keyword2),
    (SCE_ERR_VALUE, StyleSlot::Keyword2),
    (SCE_ERR_GCC_INCLUDED_FROM, StyleSlot::Keyword2),
    (SCE_ERR_GCC_EXCERPT, StyleSlot::Keyword2),
    // CMD ŌåÆ Preprocessor (shell prompt echo).
    (SCE_ERR_CMD, StyleSlot::Preprocessor),
    // 4 diff states ŌåÆ distinct semantic slots per diff role.
    (SCE_ERR_DIFF_ADDITION, StyleSlot::String),
    (SCE_ERR_DIFF_DELETION, StyleSlot::Macro),
    (SCE_ERR_DIFF_CHANGED, StyleSlot::Number),
    (SCE_ERR_DIFF_MESSAGE, StyleSlot::Comment),
    // 2 escape-sequence states ŌåÆ Operator.
    (SCE_ERR_ESCSEQ, StyleSlot::Operator),
    (SCE_ERR_ESCSEQ_UNKNOWN, StyleSlot::Operator),
];

// Italic on `DIFF_MESSAGE` (diff header ŌĆö metadata annotation).
// The DIFF_MESSAGE state routes to Comment which conventionally
// gets italic across every Code++ theme; adding to this list
// pins the italic explicitly.
const ERRORLIST_ITALIC: &[usize] = &[SCE_ERR_DIFF_MESSAGE];

// Bold on the 15 diagnostic states ŌĆö primary attention-getting
// role. `>`-prefixed CMD lines are also visually prominent in
// tool output but are NOT bold because they're commands the user
// ran (not errors the user needs to fix).
const ERRORLIST_BOLD: &[usize] = &[
    SCE_ERR_PYTHON,
    SCE_ERR_GCC,
    SCE_ERR_MS,
    SCE_ERR_BORLAND,
    SCE_ERR_PERL,
    SCE_ERR_NET,
    SCE_ERR_LUA,
    SCE_ERR_PHP,
    SCE_ERR_ELF,
    SCE_ERR_IFC,
    SCE_ERR_IFORT,
    SCE_ERR_ABSF,
    SCE_ERR_TIDY,
    SCE_ERR_JAVA_STACK,
    SCE_ERR_BASH,
];

// Zero-class install matching `emptyWordListDesc[]` at
// `LexErrorList.cxx:44-46` (single-element null-terminated array
// ŌĆö zero real classes).
const ERRORLIST_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: ERRORLIST_STYLES,
    italic: ERRORLIST_ITALIC,
    bold: ERRORLIST_BOLD,
};

// --- LexVisualProlog ---
// Visual Prolog (extension `.vip`) ŌĆö Prolog Development Center's
// OOP-flavoured Prolog dialect with typed classes and interfaces.
// `L_VISUALPROLOG` (id 84) is the only language row using this
// lexer. Four-class wordlist descriptor per
// `LexVisualProlog.cxx:60-66` (Major / Minor / Directive / Doc).
// See the `LexVisualProlog` banner in
// `scintilla-sys/src/lib.rs` for the paint-loop citations.
//
// **Case-sensitive** ŌĆö the lexer uses `GetCurrent` + `strcmp`
// throughout, no lowercasing anywhere. Visual Prolog is
// strictly case-sensitive: lowercase-lead identifiers are
// atoms/predicates (IDENTIFIER), UPPERCASE-lead are variables
// (VARIABLE), `_`-lead are anonymous variables (ANONYMOUS).
//
// **Cross-class disjointness.** Classes 0 and 1 share the
// same call site at `LexVisualProlog.cxx:411-415` (forward
// first-match-wins), so they must be strictly disjoint ŌĆö
// enforced by the invariant test. Classes 2 (directives) and
// 3 (doc keywords) are guarded by distinct entry points (`#`-lead
// for directive, `@`-lead in comment for doc), so token
// overlap between them and classes 0/1 CANNOT collide at paint
// time. Per upstream `visualprolog/SciTE.properties`,
// `externally` is the single documented cross-class overlap:
// it appears in BOTH class 1 (a modifier keyword) AND class 2
// (`#externally` compiler directive form). Invariant 7
// affirmatively asserts this documented overlap.
//
// Style-to-slot decisions (17 mappings across 25 defined slots):
//
//   * `KEY_MAJOR` (1) ŌåÆ Keyword (bold blue) ŌĆö class 0
//     structural declarations (`class`, `predicates`,
//     `clauses`, ...). PRIMARY structural anchors of a `.vip`
//     module.
//   * `KEY_MINOR` (2) ŌåÆ Keyword2 ŌĆö class 1 primitive types /
//     control flow (`if`, `foreach`, `try`, `integer64`, ...)
//     ŌĆö secondary accent for statement-level structure and
//     type vocabulary.
//   * `KEY_DIRECTIVE` (3) ŌåÆ Preprocessor ŌĆö class 2 `#`-lead
//     preprocessor directives (`#include`, `#requires`). Same
//     Preprocessor slot as C/C++ `#include`.
//   * `COMMENT_BLOCK` (4) ŌåÆ Comment (italic) ŌĆö `/* ... */`
//     multiline. Universal comment slot.
//   * `COMMENT_LINE` (5) ŌåÆ Comment (italic) ŌĆö `%`-to-EOL
//     line comment. **Note**: Visual Prolog uses `%` for line
//     comments (Prolog tradition, contra `//` in C-family).
//   * `COMMENT_KEY` (6) ŌåÆ Keyword2 ŌĆö class 3 doc keyword
//     (`@short`, `@detail`, `@end`, ...) inside a comment.
//     Javadoc-analogous accent inside comment prose.
//   * `COMMENT_KEY_ERROR` (7) ŌåÆ Comment (italic) ŌĆö `@xxx` that
//     misses docKeywords. Stays comment-coloured so
//     unrecognised tags don't visually leap out; the missing
//     accent tells the user something's off.
//   * `VARIABLE` (9) ŌåÆ Lifetime ŌĆö UPPERCASE-lead Prolog
//     variable. `Lifetime` slot is Code++'s "distinct-
//     identifier form" accent (used by Rust `'a` lifetimes,
//     Registry escape sequences); Prolog variables fit the
//     semantic role (a special identifier form that reads
//     structurally).
//   * `ANONYMOUS` (10) ŌåÆ Lifetime ŌĆö `_`-lead anonymous
//     variable. Same slot as VARIABLE for consistent
//     variable-family highlighting.
//   * `NUMBER` (11) ŌåÆ Number ŌĆö decimal / hex / octal
//     literal.
//   * `OPERATOR` (12) ŌåÆ Operator ŌĆö punctuation, `\`, or `@`
//     when verbatim-strings option disabled.
//   * `STRING_QUOTE` (16) ŌåÆ String ŌĆö literal string delimiter
//     characters (opening/closing quote).
//   * `STRING_ESCAPE` (17) ŌåÆ Lifetime ŌĆö recognised `\`-escapes
//     (`\n`, `\t`, `ßł┤`). Same accent slot as Rust
//     lifetimes / Registry escapes (small distinct
//     highlighting adjacent to strings).
//   * `STRING` (20) ŌåÆ String ŌĆö string body. Universal string
//     slot.
//   * `STRING_EOL` (22) ŌåÆ String ŌĆö verbatim-string end-of-line
//     continuation marker. **Not** an anomaly ŌĆö it's the
//     benign multi-line continuation form used by verbatim
//     strings when `ls.verbatim` is true at `LexVisualProlog.cxx:494`.
//     Matches the convention established by 7 sibling lexers
//     (`SCE_VHDL_STRINGEOL` / `SCE_ADA_STRINGEOL` /
//     `SCE_V_STRINGEOL` / `SCE_HA_STRINGEOL` /
//     `SCE_D_STRINGEOL` / ŌĆ”), all mapped to `StyleSlot::String`
//     to blend with the surrounding string colour.
//   * `EMBEDDED` (23) ŌåÆ Macro ŌĆö `[| ... |]` embedded-syntax
//     literal. `Macro` slot for distinct special-construct
//     accent, matching how Rust `println!` uses the same slot.
//   * `PLACEHOLDER` (24) ŌåÆ Macro ŌĆö `{| ... |}:ident`
//     placeholder in embedded syntax. Same Macro slot as
//     EMBEDDED for family cohesion.
//
// Unmapped slots (framework convention, 8 total):
//
//   * `DEFAULT` (0) ŌĆö plain body text.
//   * `IDENTIFIER` (8) ŌĆö transient collect state; unmatched
//     lowercase-lead identifiers (atoms / predicates) paint
//     at STYLE_DEFAULT. Same convention as `SCE_C_IDENTIFIER`.
//   * `UNUSED1` (13) ŌĆö DEAD STATE per `lexicalClasses[:92]`
//     (`"unused"` tag, empty description). Verified: zero
//     call sites emit the slot.
//   * `UNUSED2` (14) ŌĆö DEAD STATE per `:93`.
//   * `UNUSED3` (15) ŌĆö DEAD STATE per `:94`.
//   * `STRING_ESCAPE_ERROR` (18) ŌĆö invalid or incomplete
//     escape sequence. **Authoritative parse failure** ŌĆö
//     belongs to the deferred-`StyleSlot::Error` migration
//     list already tracked at ~20+ sibling lexer sites
//     (Nim's STRINGEOL / NUMERROR, VHDL / SQL / Basic /
//     Perl `_ERROR` variants). Left unmapped until
//     `StyleSlot::Error` lands, then sweep this in with the
//     rest of the family. Paints at STYLE_DEFAULT for now.
//   * `UNUSED4` (19) ŌĆö DEAD STATE per `:98`.
//   * `UNUSED5` (21) ŌĆö DEAD STATE per `:100`.
const VISUALPROLOG_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_VISUALPROLOG_KEY_MAJOR, StyleSlot::Keyword),
    (SCE_VISUALPROLOG_KEY_MINOR, StyleSlot::Keyword2),
    (SCE_VISUALPROLOG_KEY_DIRECTIVE, StyleSlot::Preprocessor),
    (SCE_VISUALPROLOG_COMMENT_BLOCK, StyleSlot::Comment),
    (SCE_VISUALPROLOG_COMMENT_LINE, StyleSlot::Comment),
    (SCE_VISUALPROLOG_COMMENT_KEY, StyleSlot::Keyword2),
    (SCE_VISUALPROLOG_COMMENT_KEY_ERROR, StyleSlot::Comment),
    (SCE_VISUALPROLOG_VARIABLE, StyleSlot::Lifetime),
    (SCE_VISUALPROLOG_ANONYMOUS, StyleSlot::Lifetime),
    (SCE_VISUALPROLOG_NUMBER, StyleSlot::Number),
    (SCE_VISUALPROLOG_OPERATOR, StyleSlot::Operator),
    (SCE_VISUALPROLOG_STRING_QUOTE, StyleSlot::String),
    (SCE_VISUALPROLOG_STRING_ESCAPE, StyleSlot::Lifetime),
    (SCE_VISUALPROLOG_STRING, StyleSlot::String),
    (SCE_VISUALPROLOG_STRING_EOL, StyleSlot::String),
    (SCE_VISUALPROLOG_EMBEDDED, StyleSlot::Macro),
    (SCE_VISUALPROLOG_PLACEHOLDER, StyleSlot::Macro),
];

// Italic on all four comment states ŌĆö universal Code++ comment
// convention plus the two `@`-in-comment sub-states.
const VISUALPROLOG_ITALIC: &[usize] = &[
    SCE_VISUALPROLOG_COMMENT_BLOCK,
    SCE_VISUALPROLOG_COMMENT_LINE,
    SCE_VISUALPROLOG_COMMENT_KEY,
    SCE_VISUALPROLOG_COMMENT_KEY_ERROR,
];

// Bold on KEY_MAJOR (class 0 ŌĆö primary structural anchor).
// Same single-class-bold discipline as REBOL (WORD), OScript
// (KEYWORD), SPICE (KEYWORD), Registry (ADDEDKEY).
const VISUALPROLOG_BOLD: &[usize] = &[SCE_VISUALPROLOG_KEY_MAJOR];

// Four-class install matching descriptor order at
// `LexVisualProlog.cxx:60-66`. All four populated.
const VISUALPROLOG_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, VISUALPROLOG_MAJOR_KEYWORDS),
        (1, VISUALPROLOG_MINOR_KEYWORDS),
        (2, VISUALPROLOG_DIRECTIVE_KEYWORDS),
        (3, VISUALPROLOG_DOC_KEYWORDS),
    ],
    styles: VISUALPROLOG_STYLES,
    italic: VISUALPROLOG_ITALIC,
    bold: VISUALPROLOG_BOLD,
};

// RC (Win32 resource scripts) is the first SINGLE-class LexCPP-family
// theme ŌĆö RC has no primitive-type vocabulary worth a class-1 split,
// so it installs only class 0. The rest of the family (C / C++ /
// C# / Objective-C / Java) install both. `lexcpp_family_installs_class_0_and_class_1`
// deliberately does NOT include `L_RC` in its iteration; the
// dedicated `rc_uses_single_class_lexcpp_theme` test pins this
// language's single-class shape.
const RC_THEME: LangTheme = LangTheme {
    keywords: &[(0, RC_KEYWORDS)],
    styles: CPP_STYLES,
    italic: CPP_ITALIC,
    bold: CPP_BOLD,
};

// --- LexRust ---
// LexRust's SCE_RUST_* enum is distinct from LexCPP's SCE_C_*.
// Notably LexRust splits CHARACTER and STRING the same way LexCPP
// does, but adds LIFETIME and MACRO slots that LexCPP lacks.

const RUST_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_RUST_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_RUST_COMMENTLINE, StyleSlot::Comment),
    (SCE_RUST_COMMENTBLOCKDOC, StyleSlot::Comment),
    (SCE_RUST_COMMENTLINEDOC, StyleSlot::Comment),
    (SCE_RUST_WORD, StyleSlot::Keyword),
    (SCE_RUST_WORD2, StyleSlot::Keyword2),
    (SCE_RUST_STRING, StyleSlot::String),
    (SCE_RUST_CHARACTER, StyleSlot::String),
    (SCE_RUST_NUMBER, StyleSlot::Number),
    (SCE_RUST_OPERATOR, StyleSlot::Operator),
    (SCE_RUST_LIFETIME, StyleSlot::Lifetime),
    (SCE_RUST_MACRO, StyleSlot::Macro),
];
const RUST_ITALIC: &[usize] = &[SCE_RUST_COMMENTBLOCK, SCE_RUST_COMMENTLINE];
const RUST_BOLD: &[usize] = &[SCE_RUST_WORD];

const RUST_THEME: LangTheme = LangTheme {
    keywords: &[(0, RUST_KEYWORDS)],
    styles: RUST_STYLES,
    italic: RUST_ITALIC,
    bold: RUST_BOLD,
};

// --- LexHTML (hypertext) family ---
// `LexHTML` is a multi-mode lexer: emits SCE_H_* for the HTML
// portion, SCE_HPHP_* inside `<?php ?>`, SCE_HJ_* inside `<script>`,
// SCE_HB_* inside VBScript blocks, SCE_HP_* inside Python blocks.
// Phase 4.5 wires HTML + PHP first. The style table below covers
// both ranges so any language sharing the lexer ŌĆö HTML, ASP, JSP,
// PHP ŌĆö can ride this exact mapping; only the per-language keyword
// list differs. This mirrors how `CPP_STYLES` is shared across all
// LexCPP-family languages.
//
// PHP variables (`$foo`, `${...}`, and `$foo`-inside-strings) map to
// `StyleSlot::Keyword2`. They're not keywords proper but they're the
// most visually distinctive PHP token; the steel-blue colour reads
// as "special identifier" and matches conventional editor themes.

const HYPERTEXT_STYLES: &[(usize, StyleSlot)] = &[
    // HTML range ŌĆö `<tag attr="value">text<!-- comment --></tag>`.
    // `*UNKNOWN` (custom elements, non-standard attrs like Web
    // Components) intentionally share the slot of their known
    // counterparts ŌĆö Code++'s palette is deliberately coarse, and
    // a separate "unknown" visual today would imply judgement
    // (warning? error?) the host can't substantiate. Revisit if a
    // future palette redesign adds a neutral "unknown identifier"
    // slot.
    (SCE_H_TAG, StyleSlot::Keyword),
    (SCE_H_TAGUNKNOWN, StyleSlot::Keyword),
    (SCE_H_TAGEND, StyleSlot::Keyword),
    (SCE_H_ATTRIBUTE, StyleSlot::Keyword2),
    (SCE_H_ATTRIBUTEUNKNOWN, StyleSlot::Keyword2),
    (SCE_H_DOUBLESTRING, StyleSlot::String),
    (SCE_H_SINGLESTRING, StyleSlot::String),
    (SCE_H_VALUE, StyleSlot::String),
    (SCE_H_NUMBER, StyleSlot::Number),
    (SCE_H_COMMENT, StyleSlot::Comment),
    (SCE_H_ENTITY, StyleSlot::Preprocessor),
    (SCE_H_OTHER, StyleSlot::Operator),
    (SCE_H_QUESTION, StyleSlot::Preprocessor), // `<?` / `<?php`
    (SCE_H_XMLSTART, StyleSlot::Preprocessor), // `<?xml`
    (SCE_H_XMLEND, StyleSlot::Preprocessor),   // `?>` of XML decl
    (SCE_H_ASP, StyleSlot::Preprocessor),      // `<%`
    (SCE_H_ASPAT, StyleSlot::Preprocessor),    // `<%@`
    (SCE_H_CDATA, StyleSlot::String),
    (SCE_H_XCCOMMENT, StyleSlot::Comment),
    // PHP range ŌĆö code inside `<?php ?>`
    (SCE_HPHP_WORD, StyleSlot::Keyword),
    (SCE_HPHP_HSTRING, StyleSlot::String),
    (SCE_HPHP_SIMPLESTRING, StyleSlot::String),
    (SCE_HPHP_NUMBER, StyleSlot::Number),
    (SCE_HPHP_VARIABLE, StyleSlot::Keyword2),
    (SCE_HPHP_HSTRING_VARIABLE, StyleSlot::Keyword2),
    (SCE_HPHP_COMPLEX_VARIABLE, StyleSlot::Keyword2),
    (SCE_HPHP_COMMENT, StyleSlot::Comment),
    (SCE_HPHP_COMMENTLINE, StyleSlot::Comment),
    (SCE_HPHP_OPERATOR, StyleSlot::Operator),
    // SGML / DTD sub-language range ŌĆö fires inside `<!DOCTYPE [ ... ]>`
    // blocks. Benefits every hypertext-family theme: every HTML file
    // with a `<!DOCTYPE html>` declaration gets the DTD-keyword
    // styling, every XML file with an internal DTD subset highlights
    // its `<!ELEMENT>` / `<!ATTLIST>` / `<!ENTITY>` declarations.
    //
    // Four indices are intentionally NOT mapped here:
    //   - `SCE_H_SGML_DEFAULT` (21) and `SCE_H_SGML_BLOCK_DEFAULT`
    //     (31): match the existing `SCE_H_DEFAULT` / `SCE_HPHP_DEFAULT`
    //     omission pattern ŌĆö fall through to `STYLE_DEFAULT` so the
    //     user's chosen body-text colour shows through.
    //   - `SCE_H_SGML_ERROR` (26): the lexer-detected DTD syntax
    //     error indicator. Unmapped pending a future
    //     `StyleSlot::Error` palette addition ŌĆö Code++'s current
    //     palette has no Error/Warning slot, and `Operator` or
    //     `Macro` would visually misrepresent the error as
    //     intentional syntax.
    //   - `SCE_H_SGML_1ST_PARAM_COMMENT` (30): Lexilla documents this
    //     state at `LexHTML.cxx:888` as "error comment ŌĆö lexer
    //     internal. It is an error if any text is in this style."
    //     Same rationale as ERROR ŌĆö styling it as `Comment` (italic
    //     green) would visually present malformed-input parse
    //     content as intentional commentary. Unmapped so it falls
    //     through to STYLE_DEFAULT alongside `ERROR`, joining the
    //     same future `StyleSlot::Error` migration.
    (SCE_H_SGML_COMMAND, StyleSlot::Keyword),
    (SCE_H_SGML_1ST_PARAM, StyleSlot::Keyword2),
    (SCE_H_SGML_DOUBLESTRING, StyleSlot::String),
    (SCE_H_SGML_SIMPLESTRING, StyleSlot::String),
    (SCE_H_SGML_SPECIAL, StyleSlot::Preprocessor),
    (SCE_H_SGML_ENTITY, StyleSlot::Preprocessor),
    (SCE_H_SGML_COMMENT, StyleSlot::Comment),
    // ----------------------------------------------------------------
    // Embedded-script ranges ŌĆö fire inside `<script>` (client-side)
    // and `<% %>` (ASP server-side) blocks of any hypertext-family
    // document. Wired here once; every theme riding `HYPERTEXT_STYLES`
    // benefits. `ASP_THEME` (added in the same commit) is the
    // primary motivation, but `HTML_THEME` / `XML_THEME` / `PHP_THEME`
    // and the future `L_JSP` / `L_JAVASCRIPT` rows pick up correct
    // embedded-script colouring at zero incremental cost.
    //
    // Naming: the `A` infix means "ASP" upstream ŌĆö `SCE_HJA_*` is the
    // ASP-block twin of `SCE_HJ_*`, `SCE_HBA_*` the ASP-block twin of
    // `SCE_HB_*`. The lexer drives whichever variant fires based on
    // whether the block boundary is `<script>` or `<% %>`; both are
    // wired so a single `.asp` file with mixed `<script>` blocks AND
    // `<% %>` blocks colours uniformly.
    //
    // Slot mapping rationale: each non-ASP range and its ASP twin
    // share the same slot ŌĆö there is no visual reason to colour a
    // client-side string differently from a server-side string. The
    // duplication is mechanical, not semantic.
    //
    // Note on follow-up: `HTML_THEME` and `PHP_THEME` will start
    // resolving `SCE_HJ_*` / `SCE_HB_*` slots after this commit (their
    // `<script>` blocks now reach the keyword/comment/string mappings
    // here), but they only get visible bold-blue keyword highlighting
    // when their themes ALSO install class 1 / class 2 wordlists.
    // Tracked in `docs/lexers-coverage.md` as a follow-up note on the
    // HTML and PHP rows.
    // ----------------------------------------------------------------
    // Embedded JavaScript ŌĆö client-side `<script>` blocks.
    // `SCE_HJ_START` (40) / `SCE_HJ_DEFAULT` (41) intentionally
    // unmapped (boundary / fall-through, mirrors `SCE_H_DEFAULT`).
    // `SCE_HJ_STRINGEOL` (51) unmapped pending `StyleSlot::Error`
    // (mirrors `SCE_H_SGML_ERROR` / `SCE_PAS_STRINGEOL`).
    (SCE_HJ_COMMENT, StyleSlot::Comment),
    (SCE_HJ_COMMENTLINE, StyleSlot::Comment),
    (SCE_HJ_COMMENTDOC, StyleSlot::Comment),
    (SCE_HJ_NUMBER, StyleSlot::Number),
    (SCE_HJ_WORD, StyleSlot::Keyword),
    (SCE_HJ_KEYWORD, StyleSlot::Keyword),
    (SCE_HJ_DOUBLESTRING, StyleSlot::String),
    (SCE_HJ_SINGLESTRING, StyleSlot::String),
    (SCE_HJ_SYMBOLS, StyleSlot::Operator),
    (SCE_HJ_REGEX, StyleSlot::String),
    (SCE_HJ_TEMPLATELITERAL, StyleSlot::String),
    // Embedded JavaScript ŌĆö ASP server-side `<% %>` blocks.
    (SCE_HJA_COMMENT, StyleSlot::Comment),
    (SCE_HJA_COMMENTLINE, StyleSlot::Comment),
    (SCE_HJA_COMMENTDOC, StyleSlot::Comment),
    (SCE_HJA_NUMBER, StyleSlot::Number),
    (SCE_HJA_WORD, StyleSlot::Keyword),
    (SCE_HJA_KEYWORD, StyleSlot::Keyword),
    (SCE_HJA_DOUBLESTRING, StyleSlot::String),
    (SCE_HJA_SINGLESTRING, StyleSlot::String),
    (SCE_HJA_SYMBOLS, StyleSlot::Operator),
    (SCE_HJA_REGEX, StyleSlot::String),
    (SCE_HJA_TEMPLATELITERAL, StyleSlot::String),
    // Embedded VBScript ŌĆö client-side `<script language=VBScript>`.
    // VBScript has only `_COMMENTLINE` (single-line via `'` or `Rem`,
    // no block-comment form) and one `_STRING` class (no single-
    // quoted strings ŌĆö `'` starts a comment). `SCE_HB_START` (70) /
    // `SCE_HB_DEFAULT` (71) / `SCE_HB_IDENTIFIER` (76) intentionally
    // unmapped (boundary / fall-through / generic identifier).
    // `SCE_HB_STRINGEOL` (77) unmapped pending `StyleSlot::Error`.
    (SCE_HB_COMMENTLINE, StyleSlot::Comment),
    (SCE_HB_NUMBER, StyleSlot::Number),
    (SCE_HB_WORD, StyleSlot::Keyword),
    (SCE_HB_STRING, StyleSlot::String),
    // Embedded VBScript ŌĆö ASP server-side `<% %>` blocks (the
    // dominant Classic ASP case: `<% If x > 0 Then Response.Write
    // "hi" End If %>`).
    (SCE_HBA_COMMENTLINE, StyleSlot::Comment),
    (SCE_HBA_NUMBER, StyleSlot::Number),
    (SCE_HBA_WORD, StyleSlot::Keyword),
    (SCE_HBA_STRING, StyleSlot::String),
];
const HYPERTEXT_ITALIC: &[usize] = &[
    SCE_H_COMMENT,
    SCE_H_XCCOMMENT,
    SCE_HPHP_COMMENT,
    SCE_HPHP_COMMENTLINE,
    SCE_H_SGML_COMMENT,
    // Embedded JavaScript comments ŌĆö block, line, and JSDoc all share
    // the green-italic comment treatment. Same set repeated for the
    // ASP-block (`SCE_HJA_*`) twin.
    SCE_HJ_COMMENT,
    SCE_HJ_COMMENTLINE,
    SCE_HJ_COMMENTDOC,
    SCE_HJA_COMMENT,
    SCE_HJA_COMMENTLINE,
    SCE_HJA_COMMENTDOC,
    // Embedded VBScript ŌĆö only one comment class per range. `'`
    // apostrophe-prefixed lines and `Rem` statements both tokenise to
    // `SCE_HB_COMMENTLINE` (or `SCE_HBA_COMMENTLINE` inside `<% %>`).
    SCE_HB_COMMENTLINE,
    SCE_HBA_COMMENTLINE,
];
const HYPERTEXT_BOLD: &[usize] = &[
    SCE_H_TAG,
    SCE_HPHP_WORD,
    SCE_H_SGML_COMMAND,
    // Embedded JavaScript reserved words ŌĆö both `_WORD` (primary
    // class) and `_KEYWORD` (legacy ECMAScript class, same wordlist)
    // render bold, matching the `SCE_H_TAG` / `SCE_HPHP_WORD`
    // precedent. Same set repeated for the ASP-block twin.
    SCE_HJ_WORD,
    SCE_HJ_KEYWORD,
    SCE_HJA_WORD,
    SCE_HJA_KEYWORD,
    // Embedded VBScript reserved words.
    SCE_HB_WORD,
    SCE_HBA_WORD,
];

// HTML rides the same hypertext lexer as PHP ŌĆö same shared
// `HYPERTEXT_STYLES` / `HYPERTEXT_ITALIC` / `HYPERTEXT_BOLD` tables
// already wired during the PHP commit. Single class 0 install:
// `HTML_KEYWORDS` (tag names). The PHP-specific class 4 keyword
// install only applies inside `<?php ?>` blocks, which won't appear
// in a `.html` file ŌĆö installing it for L_HTML would be harmless but
// is omitted for clarity.
//
// Embedded `<script>` JavaScript blocks inside HTML files tokenise
// as `SCE_HJ_*` ŌĆö and after the ASP wiring commit those style
// indices ARE in `HYPERTEXT_STYLES`. Result: a `<script>` block
// inside an `.html` file gets correct comment / string / number /
// operator styling for free. The piece still missing is class 1
// (JavaScript) wordlist install on `HTML_THEME` ŌĆö without it, JS
// reserved words inside `<script>` blocks render at the default
// foreground instead of bold blue. Adding `(1, JAVASCRIPT_KEYWORDS)`
// to `HTML_THEME.keywords` is a one-line follow-up tracked on the
// HTML row of `docs/lexers-coverage.md`. Embedded `<style>` CSS
// (`SCE_CSS_*`) is still deferred until the `L_CSS` row is wired.
//
// XML uses Lexilla's `xml` lexer (`lmXML` ŌĆö same factory family as
// `hypertext` but constructed with `isXml=true`). The lexer reserves
// class 5 for SGML / DTD vocabulary. XML's class 0 is empty by
// design: XML has no canonical element vocabulary, every document
// defines its own via DTD or schema. The shared `HYPERTEXT_STYLES`
// table covers `SCE_H_*` (XML markup), `SCE_HPHP_*` (irrelevant for
// XML but harmless ŌĆö PHP code doesn't appear in `.xml` files), the
// `SCE_H_SGML_*` range ŌĆö DTD blocks inside `<!DOCTYPE [ ... ]>`
// highlight uniformly across XML and HTML files ŌĆö AND the new
// embedded-script ranges added by the ASP wiring (no-op for XML,
// since XML documents don't embed `<script>` / `<% %>` blocks).
const XML_THEME: LangTheme = LangTheme {
    keywords: &[(5, XML_KEYWORDS)],
    styles: HYPERTEXT_STYLES,
    italic: HYPERTEXT_ITALIC,
    bold: HYPERTEXT_BOLD,
};

// --- LexProps (INI / `.properties` files) ---
// LexProps is the smallest lexer in the framework so far ŌĆö a
// pure line-prefix classifier with NO wordlists. Each line is
// inspected by its first non-whitespace character: `#` / `!` /
// `;` ŌåÆ COMMENT, `[` ŌåÆ SECTION, `@` ŌåÆ DEFVAL (Java's default-
// value syntax for `.properties` resource bundles), otherwise
// scan up to the first `=` or `:` and emit KEY ŌåÆ ASSIGNMENT ŌåÆ
// DEFAULT for the value tail. Value text itself stays DEFAULT
// by design ŌĆö INI values are arbitrary user data with no
// canonical meaning to colour, mirroring the `SCE_C_DEFAULT` /
// `SCE_C_IDENTIFIER` omission pattern in `CPP_STYLES`.
//
// Both `L_INI` and `L_PROPS` route to the same `props` lexer
// and share this single `PROPS_THEME`. The two `LangType` rows
// exist because Notepad++ surfaces them as distinct menu
// entries (one defaults to `.ini`, the other to `.properties`)
// ŌĆö the LANG_TABLE keeps the menu split but the lexer and
// theme are unified.
//
// Style-to-slot decisions:
//   * `COMMENT` (1) ŌåÆ Comment (green italic) ŌĆö the universal
//     comment slot. Covers `#` / `!` / `;` line comments.
//   * `SECTION` (2) ŌåÆ Keyword (bold blue) ŌĆö `[section]` headers
//     are the structural anchors a reader scans for, the same
//     role `SCE_MAKE_TARGET` plays in Makefiles, which is also
//     mapped to Keyword bold.
//   * `ASSIGNMENT` (3) ŌåÆ Operator ŌĆö the `=` or `:` separator;
//     matches every other lexer's punctuation ŌåÆ Operator
//     mapping.
//   * `DEFVAL` (4) ŌåÆ Preprocessor ŌĆö `@`-prefixed default-value
//     syntax is an out-of-band marker (Java `.properties`
//     resource-bundle default), same "directive" semantics as
//     Batch's leading `@` echo-suppress (also Preprocessor).
//   * `KEY` (5) ŌåÆ Keyword2 (steel blue) ŌĆö key names are named
//     identifiers on the left of the assignment, distinct from
//     SECTION's structural bold treatment. Same precedent as
//     Makefile's `$(VAR)` ŌåÆ Keyword2 mapping.
//
// `SCE_PROPS_DEFAULT` (0) intentionally unmapped ŌĆö falls
// through to STYLE_DEFAULT. Value text (post-`=`) is the
// dominant occupant of this slot and stays at default
// foreground.
const PROPS_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_PROPS_COMMENT, StyleSlot::Comment),
    (SCE_PROPS_SECTION, StyleSlot::Keyword),
    (SCE_PROPS_ASSIGNMENT, StyleSlot::Operator),
    (SCE_PROPS_DEFVAL, StyleSlot::Preprocessor),
    (SCE_PROPS_KEY, StyleSlot::Keyword2),
];
const PROPS_ITALIC: &[usize] = &[SCE_PROPS_COMMENT];
const PROPS_BOLD: &[usize] = &[SCE_PROPS_SECTION];

const PROPS_THEME: LangTheme = LangTheme {
    // Zero-wordlist lexer ŌĆö `LexProps::ColourisePropsDoc` ignores
    // the `WordList *[]` parameter entirely; classification is
    // line-prefix-based. Installing keywords would have no visible
    // effect but is harmless; we install none to keep the wiring
    // honest.
    keywords: &[],
    styles: PROPS_STYLES,
    italic: PROPS_ITALIC,
    bold: PROPS_BOLD,
};

// --- LexBatch (Windows cmd.exe scripts) ---
// LexBatch is a small case-insensitive lexer emitting 9 distinct
// style classes (`SCE_BAT_DEFAULT` 0 .. `SCE_BAT_AFTER_LABEL` 8),
// of which `BATCH_STYLES` maps 7 ŌĆö line comments (REM / `::`), two
// distinct keyword classes (cmd.exe intrinsics in wordlist 0 ŌåÆ
// `SCE_BAT_WORD`, PATH-discovered external programs in wordlist 1 ŌåÆ
// `SCE_BAT_COMMAND`), `:label` markers, the leading `@` echo-suppress
// directive, operator punctuation, and "after-label" trailing text
// the interpreter ignores. The remaining two (`SCE_BAT_DEFAULT` and
// `SCE_BAT_IDENTIFIER`) intentionally fall through to STYLE_DEFAULT
// ŌĆö see the omission rationale at the bottom of this banner.
//
// Style-to-slot decisions:
//   * `WORD` (intrinsics) ŌåÆ Keyword (bold blue) ŌĆö the primary
//     control-flow / builtin keyword class.
//   * `COMMAND` (externals) ŌåÆ Keyword2 (steel blue) ŌĆö distinct from
//     control-flow keywords so readers can tell "cmd parsed this"
//     from "cmd spawned this" at a glance. Same precedent as
//     `SCE_C_WORD2` ŌåÆ Keyword2 in `CPP_STYLES`.
//   * `LABEL` (`:setup`) ŌåÆ Preprocessor ŌĆö `StyleSlot` has no `Label`
//     variant; Preprocessor is the documented "out-of-band syntax
//     marker" slot and visually the closest analogue to Notepad++'s
//     default brown label colour.
//   * `HIDE` (leading `@`) ŌåÆ Preprocessor ŌĆö same "directive marker"
//     read as a label, and the LexBatch class name HIDE matches that
//     directive-shape semantics.
//   * `AFTER_LABEL` ŌåÆ Comment ŌĆö LexBatch's own `lexicalClasses[]`
//     describes class 8 as comment-class (text trailing a `:label` is
//     ignored by the interpreter just like a comment), so reusing the
//     `Comment` slot honours the lexer's classification.
//
// `SCE_BAT_DEFAULT` (0) and `SCE_BAT_IDENTIFIER` (6) intentionally
// unmapped ŌĆö mirrors the `SCE_C_DEFAULT` / `SCE_C_IDENTIFIER`
// omission pattern in `CPP_STYLES` (generic identifiers and `%VAR%`
// expansion bodies carry no language-specific meaning beyond the
// default foreground).
const BATCH_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_BAT_COMMENT, StyleSlot::Comment),
    (SCE_BAT_WORD, StyleSlot::Keyword),
    (SCE_BAT_LABEL, StyleSlot::Preprocessor),
    (SCE_BAT_HIDE, StyleSlot::Preprocessor),
    (SCE_BAT_COMMAND, StyleSlot::Keyword2),
    (SCE_BAT_OPERATOR, StyleSlot::Operator),
    (SCE_BAT_AFTER_LABEL, StyleSlot::Comment),
];
const BATCH_ITALIC: &[usize] = &[SCE_BAT_COMMENT, SCE_BAT_AFTER_LABEL];
const BATCH_BOLD: &[usize] = &[SCE_BAT_WORD, SCE_BAT_LABEL, SCE_BAT_HIDE];

const BATCH_THEME: LangTheme = LangTheme {
    keywords: &[(0, BATCH_KEYWORDS), (1, BATCH_KEYWORDS_2)],
    styles: BATCH_STYLES,
    italic: BATCH_ITALIC,
    bold: BATCH_BOLD,
};

// --- LexMake (Makefile) ---
// LexMake is a small line-oriented lexer with a compact style table
// ŌĆö five emission slots that actually carry colour, plus DEFAULT (0)
// and IDEOL (9) that fall through to STYLE_DEFAULT pending a future
// `StyleSlot::Error`. The lexer takes a single keyword class
// (descriptor "Directives") for GNU Make first-word-on-line
// directives; NMAKE `!`-prefixed lines are styled via the `!`
// trigger and don't need wordlist entries.
//
// TARGET ŌåÆ Keyword (bold blue): build target names are the
// "declarations" of a Makefile ŌĆö the structural anchors a reader
// scans for, equivalent to function / type names in code.
// IDENTIFIER ŌåÆ Keyword2 (steel blue): `$(VAR)` references are
// named identifiers, mirroring how PHP's `$variable` maps to
// Keyword2 in HYPERTEXT_STYLES.
const MAKEFILE_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_MAKE_COMMENT, StyleSlot::Comment),
    (SCE_MAKE_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_MAKE_IDENTIFIER, StyleSlot::Keyword2),
    (SCE_MAKE_OPERATOR, StyleSlot::Operator),
    (SCE_MAKE_TARGET, StyleSlot::Keyword),
];
const MAKEFILE_ITALIC: &[usize] = &[SCE_MAKE_COMMENT];
const MAKEFILE_BOLD: &[usize] = &[SCE_MAKE_TARGET];

const MAKEFILE_THEME: LangTheme = LangTheme {
    keywords: &[(0, MAKEFILE_KEYWORDS)],
    styles: MAKEFILE_STYLES,
    italic: MAKEFILE_ITALIC,
    bold: MAKEFILE_BOLD,
};

// --- LexPascal ---
// Pascal has a substantial 13-mapping style table ŌĆö three syntactic
// comment forms ({...} / (*...*) / //...) all map to Comment; two
// preprocessor dialects ({$...} and (*$...*) both Delphi/FPC
// directives) both to Preprocessor; decimal and `$`-hex numbers
// both to Number; single-quoted strings, `#nn` character literals,
// and Delphi-11+ triple-quoted multiline strings all to String;
// `SCE_PAS_WORD` to Keyword (bold blue, matched against
// `PASCAL_KEYWORDS`); `SCE_PAS_OPERATOR` to Operator; and
// `SCE_PAS_ASM` to Keyword2 (steel blue ŌĆö the inline-assembler
// block content between `asm` and `end` deserves a distinct visual
// treatment, matching Notepad++'s Pascal scheme).
//
// `SCE_PAS_DEFAULT` (0) / `SCE_PAS_IDENTIFIER` (1) intentionally
// unmapped ŌĆö mirrors the `SCE_C_DEFAULT` / `SCE_C_IDENTIFIER`
// omission pattern in `CPP_STYLES`. `SCE_PAS_STRINGEOL` (11) also
// unmapped, pending the future `StyleSlot::Error` palette
// addition (same deferral as `SCE_H_SGML_ERROR` / `SCE_MAKE_IDEOL`).
const PASCAL_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_PAS_COMMENT, StyleSlot::Comment),
    (SCE_PAS_COMMENT2, StyleSlot::Comment),
    (SCE_PAS_COMMENTLINE, StyleSlot::Comment),
    (SCE_PAS_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_PAS_PREPROCESSOR2, StyleSlot::Preprocessor),
    (SCE_PAS_NUMBER, StyleSlot::Number),
    (SCE_PAS_HEXNUMBER, StyleSlot::Number),
    (SCE_PAS_WORD, StyleSlot::Keyword),
    (SCE_PAS_STRING, StyleSlot::String),
    (SCE_PAS_CHARACTER, StyleSlot::String),
    (SCE_PAS_OPERATOR, StyleSlot::Operator),
    (SCE_PAS_ASM, StyleSlot::Keyword2),
    (SCE_PAS_MULTILINESTRING, StyleSlot::String),
];
const PASCAL_ITALIC: &[usize] = &[SCE_PAS_COMMENT, SCE_PAS_COMMENT2, SCE_PAS_COMMENTLINE];
const PASCAL_BOLD: &[usize] = &[SCE_PAS_WORD];

const PASCAL_THEME: LangTheme = LangTheme {
    keywords: &[(0, PASCAL_KEYWORDS)],
    styles: PASCAL_STYLES,
    italic: PASCAL_ITALIC,
    bold: PASCAL_BOLD,
};

// --- LexSQL ---
// LexSQL is case-insensitive: every candidate token is lowercased
// (`LexSQL.cxx:786` `MakeLowerCase`) before keyword comparison, so
// `SQL_KEYWORDS` / `SQL_KEYWORDS_2` are stored all-lowercase. SQL
// source can use any casing (`SELECT` / `Select` / `select` all match
// `select`); the case-insensitive convention is honoured
// transparently.
//
// The lexer exposes EIGHT wordlist classes via `sqlWordListDesc[]`
// (`LexSQL.cxx:266-275`): class 0 "Keywords", class 1 "Database
// Objects", class 2 "PLDoc", class 3 "SQL*Plus", classes 4-7 "User
// Keywords 1-4". `SQL_THEME` installs classes 0 + 1 today; classes
// 2-7 are left out of the `keywords` array (the lexer accepts up to
// 8 wordlists but doesn't require all eight to be set).
//
// Style-to-slot decisions:
//   * COMMENT / COMMENTLINE / COMMENTDOC / COMMENTLINEDOC /
//     SQLPLUS_COMMENT ŌåÆ Comment. All five comment-class indices the
//     lexer emits share the same visual treatment (matches the
//     C-family precedent of collapsing four comment forms onto one
//     slot, plus SQL*Plus's REM-style line comment).
//   * NUMBER ŌåÆ Number, STRING / CHARACTER ŌåÆ String, OPERATOR ŌåÆ
//     Operator. Standard mappings, identical to every other lexer.
//   * WORD (class 0) ŌåÆ Keyword (bold blue). Primary SQL reserved
//     words ŌĆö the structural anchors a SQL reader scans for.
//   * WORD2 (class 1) ŌåÆ Keyword2 (steel blue). Types and built-in
//     functions, distinct from primary keywords ŌĆö same precedent as
//     `SCE_C_WORD2` in `CPP_STYLES`.
//   * SQLPLUS (class 3, Oracle SQL*Plus client-tool commands like
//     `SPOOL` / `CONNECT` / `@script` / `PROMPT`) ŌåÆ Preprocessor.
//     SQL*Plus commands are evaluated by the client, not the database
//     engine ŌĆö the canonical "out-of-band syntax marker" semantic the
//     Preprocessor slot covers, same precedent as `SCE_BAT_HIDE` in
//     `BATCH_STYLES`. Mapping to Keyword would conflate true SQL
//     reserved words with client-tool directives.
//   * SQLPLUS_PROMPT ŌåÆ Preprocessor. Same family as SQLPLUS ŌĆö text
//     rendered by the client tool, not interpreted by SQL.
//   * COMMENTDOCKEYWORD (class 2, PLDoc `@tag` inside `/** */` doc
//     comments) ŌåÆ Keyword2. PLDoc tags live inside a Comment-styled
//     region but mark structural annotation; Keyword2's steel blue
//     keeps them readable against the green comment background while
//     signalling "this is a tag, not prose". The mapping fires
//     unconditionally on lexer-detected `@tag` syntax; the class 2
//     wordlist controls which tags get this style vs. the error
//     style (left unmapped for v1, see below).
//
// Intentionally unmapped (fall through to STYLE_DEFAULT):
//   * SCE_SQL_DEFAULT (0) ŌĆö generic background text (same omission
//     pattern as SCE_C_DEFAULT).
//   * SCE_SQL_IDENTIFIER (11) ŌĆö bare table / column / variable
//     references (same omission as SCE_C_IDENTIFIER /
//     SCE_PAS_IDENTIFIER).
//   * SCE_SQL_QUOTEDIDENTIFIER (23) ŌĆö `"customer_id"` style. Still an
//     identifier semantically; the quoting is a syntactic dodge of
//     reserved-word conflicts, not a visual category. The StyleSlot
//     enum has no Identifier variant by design.
//   * SCE_SQL_QOPERATOR (24) ŌĆö Oracle `q'[...]'` alternate-quote
//     markers. Could map to Operator, but they bookend a String
//     region the lexer is already styling; leaving them at
//     STYLE_DEFAULT keeps them visually subordinate to the string
//     body (which IS coloured).
//   * SCE_SQL_COMMENTDOCKEYWORDERROR (18) ŌĆö unrecognised PLDoc tag,
//     error indicator. Unmapped pending `StyleSlot::Error` (same
//     deferral as `SCE_PAS_STRINGEOL` / `SCE_MAKE_IDEOL` /
//     `SCE_H_SGML_ERROR` and the four embedded-script STRINGEOLs
//     added by the ASP commit ŌĆö error-slot migration list now at 9).
//   * SCE_SQL_USER1..USER4 (19-22) ŌĆö user-customisable wordlist
//     ranges. Deferred until a per-user wordlist UI lands and can
//     carry coordinated colour-choice decisions.
const SQL_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_SQL_COMMENT, StyleSlot::Comment),
    (SCE_SQL_COMMENTLINE, StyleSlot::Comment),
    (SCE_SQL_COMMENTDOC, StyleSlot::Comment),
    (SCE_SQL_COMMENTLINEDOC, StyleSlot::Comment),
    (SCE_SQL_SQLPLUS_COMMENT, StyleSlot::Comment),
    (SCE_SQL_NUMBER, StyleSlot::Number),
    (SCE_SQL_WORD, StyleSlot::Keyword),
    (SCE_SQL_WORD2, StyleSlot::Keyword2),
    (SCE_SQL_STRING, StyleSlot::String),
    (SCE_SQL_CHARACTER, StyleSlot::String),
    (SCE_SQL_OPERATOR, StyleSlot::Operator),
    (SCE_SQL_SQLPLUS, StyleSlot::Preprocessor),
    (SCE_SQL_SQLPLUS_PROMPT, StyleSlot::Preprocessor),
    (SCE_SQL_COMMENTDOCKEYWORD, StyleSlot::Keyword2),
];
// All five comment forms italic ŌĆö matches CPP_ITALIC / PASCAL_ITALIC
// precedent of italicising every comment-class index (CPP includes
// `SCE_C_COMMENTDOC` / `SCE_C_COMMENTLINEDOC`, PASCAL italicises all
// three of its comment forms). Skipping the doc-comment forms would
// leave PLDoc `/** */` blocks visually less marked than the less
// structured `/* */` and `--` lines, the opposite of what the
// distinction is meant to convey.
const SQL_ITALIC: &[usize] = &[
    SCE_SQL_COMMENT,
    SCE_SQL_COMMENTLINE,
    SCE_SQL_COMMENTDOC,
    SCE_SQL_COMMENTLINEDOC,
    SCE_SQL_SQLPLUS_COMMENT,
];
const SQL_BOLD: &[usize] = &[SCE_SQL_WORD];

const SQL_THEME: LangTheme = LangTheme {
    keywords: &[(0, SQL_KEYWORDS), (1, SQL_KEYWORDS_2)],
    styles: SQL_STYLES,
    italic: SQL_ITALIC,
    bold: SQL_BOLD,
};

// --- LexVB (Visual Basic ŌĆö VB.NET / VBScript / VBA / VB Classic) ---
// LexVB is case-insensitive: every candidate token is lowercased
// (`LexVB.cxx:208` `sc.GetCurrentLowered`) before keyword lookup, so
// `VB_KEYWORDS` and `VB_KEYWORDS_2` MUST be all-lowercase. VB source
// can use any casing (`If` / `IF` / `if` all match `if`) ŌĆö the
// case-insensitive convention is honoured transparently. Same
// convention as `LexSQL`, `LexPascal`, `LexBatch`.
//
// The lexer exposes FOUR wordlist classes via `vbWordListDesc[]`
// (`LexVB.cxx:68-73`). Upstream descriptors are `"Keywords"` /
// `"user1"` / `"user2"` / `"user3"` ŌĆö slightly misleading: the three
// `userN` slots aren't user-customisable, they ARE the secondary
// keyword classes feeding `SCE_B_KEYWORD2..KEYWORD4`. `VB_THEME`
// installs classes 0 + 1 ŌĆö matches Notepad++'s shipped
// `<Language name="vb">` two-class convention (richer than
// Notepad++'s actual single-`instre1` ship, matching our
// C / C++ / TypeScript precedent). Classes 2 + 3 are left out of
// the `keywords` array; their style indices (`SCE_B_KEYWORD3` /
// `SCE_B_KEYWORD4`) are still mapped to `Keyword2` so a future
// project-specific wordlist install picks up sensible colouring
// without re-wiring the theme.
//
// Style-to-slot decisions:
//   * COMMENT (`'` line comment, plus `Rem` lines which LexVB
//     hard-codes at `LexVB.cxx:212-213` before wordlist lookup)
//     ŌåÆ Comment.
//   * NUMBER (decimal + `&H` hex + `&O` octal + `&B` binary) and
//     DATE (`#1/1/2024#` literal) both ŌåÆ Number. The date-literal
//     form is structurally a literal value (parsed by the compiler
//     into a typed DateTime); Number is the closest semantic slot,
//     matching `SCE_PAS_HEXNUMBER` ŌåÆ Number precedent.
//   * KEYWORD (class 0) ŌåÆ Keyword (bold blue) ŌĆö primary reserved
//     words, the structural anchors a VB reader scans for.
//   * KEYWORD2 (class 1) ŌåÆ Keyword2 (steel blue) ŌĆö primitive type
//     names plus intrinsic-constant vocabulary. Same precedent as
//     `SCE_C_WORD2`, `SCE_SQL_WORD2`.
//   * KEYWORD3 / KEYWORD4 (classes 2 / 3, both unused for v1) ŌåÆ
//     Keyword2 ŌĆö empty wordlists today, but the style mapping is
//     pre-wired so a project-specific install picks up sensible
//     colouring with no theme edit.
//   * STRING (`"double quoted"` ŌĆö VB has no single-quote string
//     form; single quote starts a comment) ŌåÆ String.
//   * PREPROCESSOR (`#If` / `#Else` / `#Region` / `#Const` /
//     `#ExternalSource` / `#Disable Warning` / `#Enable Warning`)
//     ŌåÆ Preprocessor (bold). Mapped via the leading `#` not via
//     wordlist membership.
//   * OPERATOR ŌåÆ Operator.
//
// Intentionally unmapped (fall through to STYLE_DEFAULT):
//   * SCE_B_DEFAULT (0) ŌĆö generic background text (universal
//     omission, matches `SCE_C_DEFAULT` / `SCE_PAS_DEFAULT` /
//     `SCE_SQL_DEFAULT`).
//   * SCE_B_IDENTIFIER (7) ŌĆö bare variable / procedure references
//     (matches `SCE_C_IDENTIFIER` / `SCE_PAS_IDENTIFIER` /
//     `SCE_SQL_IDENTIFIER` precedent).
//   * SCE_B_STRINGEOL (9) ŌĆö unterminated-string error indicator.
//     Unmapped pending `StyleSlot::Error`. Brings the codebase's
//     deferred-Error-slot migration list to 10 entries (the prior
//     9 plus this).
const VB_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_B_COMMENT, StyleSlot::Comment),
    (SCE_B_NUMBER, StyleSlot::Number),
    (SCE_B_KEYWORD, StyleSlot::Keyword),
    (SCE_B_STRING, StyleSlot::String),
    (SCE_B_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_B_OPERATOR, StyleSlot::Operator),
    (SCE_B_DATE, StyleSlot::Number),
    (SCE_B_KEYWORD2, StyleSlot::Keyword2),
    (SCE_B_KEYWORD3, StyleSlot::Keyword2),
    (SCE_B_KEYWORD4, StyleSlot::Keyword2),
];
// Comment italic ŌĆö matches universal Code++ convention.
const VB_ITALIC: &[usize] = &[SCE_B_COMMENT];
// Primary keywords + preprocessor directives bold ŌĆö matches
// Notepad++'s VB default and the Pascal/C precedent of bolding
// both `SCE_C_WORD` and `SCE_C_PREPROCESSOR`.
const VB_BOLD: &[usize] = &[SCE_B_KEYWORD, SCE_B_PREPROCESSOR];

const VB_THEME: LangTheme = LangTheme {
    keywords: &[(0, VB_KEYWORDS), (1, VB_KEYWORDS_2)],
    styles: VB_STYLES,
    italic: VB_ITALIC,
    bold: VB_BOLD,
};

// --- LexCSS (CSS ŌĆö Cascading Style Sheets) ---
// LexCSS is case-insensitive: every candidate token is lowercased
// (`LexCSS.cxx:419` `sc.GetCurrentLowered`) before keyword lookup,
// so all five CSS wordlists MUST be all-lowercase. CSS source can
// use any casing (`COLOR` / `Color` / `color` all match) ŌĆö the
// case-insensitive convention is honoured transparently. Same
// shape contract as LexSQL / LexPascal / LexBatch / LexVB.
//
// The lexer exposes EIGHT wordlist classes via `cssWordListDesc[]`
// (`LexCSS.cxx:78-86`):
//   * 0 = CSS1 properties (`CSS_PROPERTIES_CSS1`)
//   * 1 = standard pseudo-classes (`CSS_PSEUDO_CLASSES`)
//   * 2 = CSS2 properties (`CSS_PROPERTIES_CSS2`)
//   * 3 = CSS3 properties (`CSS_PROPERTIES_CSS3`)
//   * 4 = standard pseudo-elements (`CSS_PSEUDO_ELEMENTS`)
//   * 5 = extended / vendor-prefixed properties (EMPTY v1)
//   * 6 = extended pseudo-classes (EMPTY v1)
//   * 7 = extended pseudo-elements (EMPTY v1)
// `CSS_THEME` installs classes 0 + 1 + 2 + 3 + 4 ŌĆö every standard
// wordlist Lexilla can populate. Classes 5 / 6 / 7 stay empty for
// v1; vendor-prefixed properties (`-webkit-*` / `-moz-*`) and
// browser-specific pseudos cascade-miss into `SCE_CSS_UNKNOWN_*`,
// which falls through to STYLE_DEFAULT ŌĆö acceptable until a
// dedicated extension wordlist lands.
//
// **Four-way IDENTIFIER cascade** (`LexCSS.cxx:425-438`).
// Property-name tokens are matched against classes 0 / 2 / 3 / 5
// in priority order: class 0 hit ŌåÆ `SCE_CSS_IDENTIFIER`, class 2
// hit ŌåÆ `SCE_CSS_IDENTIFIER2`, class 3 hit ŌåÆ `SCE_CSS_IDENTIFIER3`,
// class 5 hit ŌåÆ `SCE_CSS_EXTENDED_IDENTIFIER`, no match ŌåÆ
// `SCE_CSS_UNKNOWN_IDENTIFIER`. `CSS_STYLES` themes 6 / 15 / 17 /
// 19 identically (Keyword bold) so property-name colour stays
// consistent regardless of which spec generation a property comes
// from ŌĆö distinct lexer-side indices exist for plugins that want
// to differentiate generations, not because they should render
// differently by default.
//
// **Legitimate state-disambiguated cross-namespace overlap.**
// `left` / `right` appear in both class 1 (paged-media
// pseudo-classes `:left` / `:right`) AND class 2 (positional
// properties); `cue` appears in both class 2 (CSS2 aural
// property) AND class 4 (`::cue` pseudo-element). Lexilla
// disambiguates by lexer state ŌĆö wordlist queries fire only in
// the matching syntactic state (post-`:` selector vs post-`{`
// property-name vs post-`::` pseudo-element). The same token in
// multiple lists is the correct representation, NOT a duplicate
// to remove. Pinned in the dedicated CSS test.
//
// **Style-slot palette constraint.** Code++'s `StyleSlot` enum has
// nine variants: Comment / Keyword / Keyword2 / String / Number /
// Preprocessor / Operator / Lifetime / Macro. CSS has more distinct
// emission categories than the palette has slots; multiple CSS
// concepts collapse to the same visual category by design. The
// precedent for this is HYPERTEXT (HTML/XML) where `SCE_H_TAG` ŌåÆ
// Keyword and `SCE_H_ATTRIBUTE` ŌåÆ Keyword2 ŌĆö distinct lexer
// concepts, shared palette slot. CSS follows the same pattern.
//
// Style-to-slot decisions:
//   * COMMENT (`/* ... */` block comment) ŌåÆ Comment italic.
//   * TAG (element selector `div` / `p`) ŌåÆ Keyword bold. Matches
//     HTML's `SCE_H_TAG` ŌåÆ Keyword precedent (CSS element
//     selectors are syntactically tag names ŌĆö same as HTML).
//   * IDENTIFIER / IDENTIFIER2 / IDENTIFIER3 / EXTENDED_IDENTIFIER
//     (the four-way property-name cascade) ŌåÆ Keyword bold. Identical
//     theming makes the cascade transparent at render time; bold
//     weight matches the N++ light theme's property-emphasis
//     convention. Property names and tag names share Keyword bold
//     because both are "primary structural anchor" tokens ŌĆö they
//     never co-occur in the same syntactic position so visual
//     conflation is acceptable.
//   * CLASS (`.foo`) / ID (`#foo`) / ATTRIBUTE (`[type="text"]`) /
//     VARIABLE (SCSS `$name` / Less `@name`) ŌåÆ Keyword2 steel-blue.
//     All four are "non-primary selector / variable accents".
//     ATTRIBUTE specifically mirrors HTML's `SCE_H_ATTRIBUTE` ŌåÆ
//     Keyword2 precedent. The palette has no dedicated ID / variable
//     accent slot; Keyword2 is the closest semantic match.
//   * PSEUDOCLASS / PSEUDOELEMENT / EXTENDED_PSEUDOCLASS /
//     EXTENDED_PSEUDOELEMENT ŌåÆ Keyword2. Pseudo accents share the
//     same "selector decoration" visual weight as class / id /
//     variable.
//   * IMPORTANT (`!important`) ŌåÆ Preprocessor bold. Distinct
//     "look at me" emphasis; visually pairs with at-rule directives.
//   * DIRECTIVE (`@import` / `@charset` / `@font-face` /
//     `@keyframes` / `@page` / `@namespace` / `@layer` /
//     `@container` / `@property` / ...) ŌåÆ Preprocessor bold.
//   * GROUP_RULE ŌåÆ Preprocessor bold. `LexCSS.cxx:460-463`
//     `strcmp`-upgrades exactly four at-rules (`media` / `supports`
//     / `document` / `-moz-document`) from DIRECTIVE to GROUP_RULE;
//     identical theming preserves N++-parity visual since the
//     distinction is for plugin tooling, not for human readers.
//   * OPERATOR (`{` / `}` / `:` / `;` / `>` / `,`) ŌåÆ Operator.
//   * DOUBLESTRING / SINGLESTRING (`"foo"` / `'foo'`) ŌåÆ String.
//   * VARIABLE ŌĆö see CLASS / ID grouping above. For the L_CSS row
//     the lexer never emits this state (would require
//     `lexer.css.scss.language` / `lexer.css.less.language`
//     properties); pre-themed for a future SCSS / Less wiring.
//
// Intentionally unmapped (fall through to STYLE_DEFAULT):
//   * SCE_CSS_DEFAULT (0) ŌĆö generic background text (universal
//     omission, matches `SCE_C_DEFAULT` / `SCE_PAS_DEFAULT`).
//   * SCE_CSS_UNKNOWN_PSEUDOCLASS (4) ŌĆö wordlist-miss fallback
//     for unrecognised pseudo-classes (e.g. `:-moz-focusring`).
//     Renders at default fg ŌĆö matches N++ light-theme behaviour
//     and the framework's `SCE_C_IDENTIFIER` precedent (unmatched
//     identifiers stay default-coloured, not error-flagged).
//   * SCE_CSS_UNKNOWN_IDENTIFIER (7) ŌĆö wordlist-miss fallback for
//     unrecognised property names (e.g. CSS custom properties
//     `--foo`, vendor-prefixed `-webkit-foo` while class 5 is
//     empty, or non-standard property names). Default-fg.
//   * SCE_CSS_VALUE (8) ŌĆö right-of-colon literal text
//     (`color: RED` ŌĆö the `RED` is VALUE). Default-fg matches N++
//     light theme and keeps CSS unit literals (`10px` / `1.5em` /
//     `auto` / colour names) readable without overloading the
//     Number / String / Identifier slots.
const CSS_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_CSS_TAG, StyleSlot::Keyword),
    (SCE_CSS_CLASS, StyleSlot::Keyword2),
    (SCE_CSS_PSEUDOCLASS, StyleSlot::Keyword2),
    (SCE_CSS_OPERATOR, StyleSlot::Operator),
    (SCE_CSS_IDENTIFIER, StyleSlot::Keyword),
    (SCE_CSS_COMMENT, StyleSlot::Comment),
    (SCE_CSS_ID, StyleSlot::Keyword2),
    (SCE_CSS_IMPORTANT, StyleSlot::Preprocessor),
    (SCE_CSS_DIRECTIVE, StyleSlot::Preprocessor),
    (SCE_CSS_DOUBLESTRING, StyleSlot::String),
    (SCE_CSS_SINGLESTRING, StyleSlot::String),
    (SCE_CSS_IDENTIFIER2, StyleSlot::Keyword),
    (SCE_CSS_ATTRIBUTE, StyleSlot::Keyword2),
    (SCE_CSS_IDENTIFIER3, StyleSlot::Keyword),
    (SCE_CSS_PSEUDOELEMENT, StyleSlot::Keyword2),
    (SCE_CSS_EXTENDED_IDENTIFIER, StyleSlot::Keyword),
    (SCE_CSS_EXTENDED_PSEUDOCLASS, StyleSlot::Keyword2),
    (SCE_CSS_EXTENDED_PSEUDOELEMENT, StyleSlot::Keyword2),
    (SCE_CSS_GROUP_RULE, StyleSlot::Preprocessor),
    (SCE_CSS_VARIABLE, StyleSlot::Keyword2),
];
// Comment italic ŌĆö matches universal Code++ convention.
const CSS_ITALIC: &[usize] = &[SCE_CSS_COMMENT];
// Property-name cascade + at-rule directives + !important bold ŌĆö
// matches Notepad++ light-theme CSS default and the C/C++ precedent
// of bolding `SCE_C_WORD` + `SCE_C_PREPROCESSOR`.
const CSS_BOLD: &[usize] = &[
    SCE_CSS_IDENTIFIER,
    SCE_CSS_IDENTIFIER2,
    SCE_CSS_IDENTIFIER3,
    SCE_CSS_EXTENDED_IDENTIFIER,
    SCE_CSS_IMPORTANT,
    SCE_CSS_DIRECTIVE,
    SCE_CSS_GROUP_RULE,
];

const CSS_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, CSS_PROPERTIES_CSS1),
        (1, CSS_PSEUDO_CLASSES),
        (2, CSS_PROPERTIES_CSS2),
        (3, CSS_PROPERTIES_CSS3),
        (4, CSS_PSEUDO_ELEMENTS),
    ],
    styles: CSS_STYLES,
    italic: CSS_ITALIC,
    bold: CSS_BOLD,
};

// --- LexPerl (Perl) ---
// LexPerl is byte-exact case-sensitive: `LexPerl.cxx:96-104`
// (`isPerlKeyword`) copies token bytes verbatim into a stack buffer
// and calls `keywords.InList(s)` with no case folding. Most entries
// in `PERL_KEYWORDS` are lowercase per standard Perl convention, but
// 13 entries (BEGIN / END / INIT / CHECK / UNITCHECK / AUTOLOAD /
// DESTROY phase blocks, plus the __FILE__ / __LINE__ / __PACKAGE__ /
// __SUB__ / __DATA__ / __END__ family) are stored UPPERCASE because
// Perl source spells them uppercase by language requirement and the
// lexer would never match a lowercase form. The 13-token uppercase
// subset is structurally pinned in the dedicated Perl test.
//
// **__DATA__ / __END__ uppercase entries are load-bearing for the
// SCE_PL_DATASECTION ŌåÆ Comment mapping below.** `LexPerl.cxx:872-
// 877` only recolours these markers to `SCE_PL_DATASECTION` from
// inside the `SCE_PL_WORD` state (i.e. after a wordlist match) ŌĆö so
// without the uppercase entries, the trailing data section never
// picks up the de-emphasised paint.
//
// **Single wordlist class.** `perlWordListDesc[]` declares one
// `"Keywords"` slot; `PERL_THEME` installs class 0 only.
//
// Style-to-slot decisions:
//   * COMMENTLINE (`# ...`) ŌåÆ Comment italic.
//   * POD (`=head1 ... =cut` prose blocks) ŌåÆ Comment italic ŌĆö same
//     archetype as line comments, de-emphasised relative to code.
//   * POD_VERB (verbatim POD lines, indented) ŌåÆ Comment italic.
//   * DATASECTION (everything after `__DATA__` / `__END__`) ŌåÆ
//     Comment italic. Trailing non-executable data is de-emphasised
//     prose; italic preserves the "this isn't code" cue.
//   * NUMBER ŌåÆ Number.
//   * WORD (wordlist hit ŌĆö every Perl built-in / reserved word /
//     named operator / `__TOKEN__` literal) ŌåÆ Keyword bold.
//   * STRING (`"..."` double-quoted, interpolating) ŌåÆ String.
//   * CHARACTER (`'...'` single-quoted, no interpolation) ŌåÆ String.
//   * OPERATOR ŌåÆ Operator.
//   * SCALAR / ARRAY / HASH / SYMBOLTABLE (sigil-tagged variables ŌĆö
//     `$x` / `@x` / `%x` / `*x`) ŌåÆ Lifetime. The "purple sigil-tagged
//     identifier" archetype: Perl sigils share the visual feel of
//     Rust lifetimes (short identifier-decorator, distinct from both
//     keywords and bare identifiers), and `StyleSlot::Lifetime` is
//     documented as reusable for "scoped binding" highlights at the
//     enum declaration. Mapping all four sigil styles uniformly keeps
//     `$/@/%/*` variables visually consistent regardless of which
//     namespace they belong to.
//   * REGEX (`m//` body) / REGSUBST (`s///` body) ŌåÆ String. Perl's
//     palette doesn't have a Regex slot; String collapse is the
//     established convention.
//   * BACKTICKS (`` `cmd` ``) ŌåÆ String. Shell-command-as-string.
//   * HERE_DELIM (`<<EOF` opening marker line) ŌåÆ Keyword2 bold. The
//     delimiter is a structural marker, distinct from the body ŌĆö
//     Keyword2 + bold gives it the "structural anchor" feel without
//     colliding with the WORD keyword slot.
//   * HERE_Q / HERE_QQ / HERE_QX (heredoc body ŌĆö single-quoted /
//     interpolating / backtick-style respectively) ŌåÆ String.
//   * STRING_Q / STRING_QQ / STRING_QX / STRING_QR / STRING_QW
//     (`q{...}` / `qq{...}` / `qx{...}` / `qr{...}` / `qw{...}`
//     quote-operator bodies) ŌåÆ String.
//   * SUB_PROTOTYPE (text between `(` and `)` in `sub NAME (...)` ŌĆö
//     the `$@%*\` characters declaring a sub's signature) ŌåÆ Keyword2
//     bold. Structural type-sig declaration, deserves its own
//     accent.
//   * FORMAT_IDENT (the `NAME =` header in `format NAME = ...`) ŌåÆ
//     Keyword2 bold. Structural declarator.
//   * FORMAT (the picture-body of a `format` template up to the
//     terminating `.` line) ŌåÆ String. Templated content.
//   * XLAT (`tr/abc/xyz/` / `y/abc/xyz/` transliteration body) ŌåÆ
//     String.
//   * All _VAR interpolation shadows (STRING_VAR (43) / REGEX_VAR
//     (54) / REGSUBST_VAR (55) / BACKTICKS_VAR (57) / HERE_QQ_VAR
//     (61) / HERE_QX_VAR (62) / STRING_QQ_VAR (64) / STRING_QX_VAR
//     (65) / STRING_QR_VAR (66)) ŌåÆ Lifetime. These are interpolated
//     `$var` / `@var` references INSIDE a string / regex / heredoc /
//     backticks body; the sigil archetype carries through so an
//     interpolated variable reads in the same purple as a top-level
//     `$x`, against the surrounding String body. The +37 shift
//     (`INTERPOLATE_SHIFT` at `LexPerl.cxx:94`) defines the band; the
//     theme maps every populated slot uniformly so a future contributor
//     adding regex highlighting (say, switching REGEX from String to a
//     hypothetical Regex slot) only changes the body, not the variable.
//
// Intentionally unmapped (fall through to STYLE_DEFAULT):
//   * SCE_PL_DEFAULT (0) ŌĆö generic background text (universal
//     omission, matches `SCE_C_DEFAULT` / `SCE_CSS_DEFAULT`).
//   * SCE_PL_ERROR (1) ŌĆö soft-warning state for unbalanced delimiters
//     / unterminated quotes. Pending `StyleSlot::Error` palette
//     addition (now at 11 entries on the deferred-Error-slot
//     migration list ŌĆö Perl's ERROR joins the 10 prior STRINGEOL-
//     family slots).
//   * SCE_PL_PUNCTUATION (8) ŌĆö Lexilla marks "currently not used";
//     punctuation flows to SCE_PL_OPERATOR.
//   * SCE_PL_PREPROCESSOR (9) ŌĆö Lexilla marks "preprocessor unused";
//     Perl has no real preprocessor. Mapped slot would be dead.
//   * SCE_PL_IDENTIFIER (11) ŌĆö bare identifier (post-keyword-miss);
//     matches `SCE_C_IDENTIFIER` / `SCE_PAS_IDENTIFIER` /
//     `SCE_VB_IDENTIFIER` precedent.
//   * SCE_PL_VARIABLE_INDEXER (16) ŌĆö Lexilla marks "allocated but
//     unused"; sigil-with-subscript stays in SCALAR style.
//   * SCE_PL_LONGQUOTE (19) ŌĆö Lexilla marks "obsolete: replaced by
//     qq/qx/qr/qw"; modern lexer emits STRING_QQ/QX/QR/QW instead.
const PERL_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_PL_COMMENTLINE, StyleSlot::Comment),
    (SCE_PL_POD, StyleSlot::Comment),
    (SCE_PL_NUMBER, StyleSlot::Number),
    (SCE_PL_WORD, StyleSlot::Keyword),
    (SCE_PL_STRING, StyleSlot::String),
    (SCE_PL_CHARACTER, StyleSlot::String),
    (SCE_PL_OPERATOR, StyleSlot::Operator),
    (SCE_PL_SCALAR, StyleSlot::Lifetime),
    (SCE_PL_ARRAY, StyleSlot::Lifetime),
    (SCE_PL_HASH, StyleSlot::Lifetime),
    (SCE_PL_SYMBOLTABLE, StyleSlot::Lifetime),
    (SCE_PL_REGEX, StyleSlot::String),
    (SCE_PL_REGSUBST, StyleSlot::String),
    (SCE_PL_BACKTICKS, StyleSlot::String),
    (SCE_PL_DATASECTION, StyleSlot::Comment),
    (SCE_PL_HERE_DELIM, StyleSlot::Keyword2),
    (SCE_PL_HERE_Q, StyleSlot::String),
    (SCE_PL_HERE_QQ, StyleSlot::String),
    (SCE_PL_HERE_QX, StyleSlot::String),
    (SCE_PL_STRING_Q, StyleSlot::String),
    (SCE_PL_STRING_QQ, StyleSlot::String),
    (SCE_PL_STRING_QX, StyleSlot::String),
    (SCE_PL_STRING_QR, StyleSlot::String),
    (SCE_PL_STRING_QW, StyleSlot::String),
    (SCE_PL_POD_VERB, StyleSlot::Comment),
    (SCE_PL_SUB_PROTOTYPE, StyleSlot::Keyword2),
    (SCE_PL_FORMAT_IDENT, StyleSlot::Keyword2),
    (SCE_PL_FORMAT, StyleSlot::String),
    (SCE_PL_STRING_VAR, StyleSlot::Lifetime),
    (SCE_PL_XLAT, StyleSlot::String),
    (SCE_PL_REGEX_VAR, StyleSlot::Lifetime),
    (SCE_PL_REGSUBST_VAR, StyleSlot::Lifetime),
    (SCE_PL_BACKTICKS_VAR, StyleSlot::Lifetime),
    (SCE_PL_HERE_QQ_VAR, StyleSlot::Lifetime),
    (SCE_PL_HERE_QX_VAR, StyleSlot::Lifetime),
    (SCE_PL_STRING_QQ_VAR, StyleSlot::Lifetime),
    (SCE_PL_STRING_QX_VAR, StyleSlot::Lifetime),
    (SCE_PL_STRING_QR_VAR, StyleSlot::Lifetime),
];
// Comment italic ŌĆö matches universal Code++ convention. POD,
// POD_VERB, DATASECTION all carry italic via the Comment slot to
// preserve the "non-executable prose" cue.
const PERL_ITALIC: &[usize] = &[
    SCE_PL_COMMENTLINE,
    SCE_PL_POD,
    SCE_PL_POD_VERB,
    SCE_PL_DATASECTION,
];
// Primary keyword + heredoc delimiter + sub prototype + format
// header bold ŌĆö matches Notepad++ Perl default and the C/C++
// precedent of bolding the structural-anchor families.
const PERL_BOLD: &[usize] = &[
    SCE_PL_WORD,
    SCE_PL_HERE_DELIM,
    SCE_PL_SUB_PROTOTYPE,
    SCE_PL_FORMAT_IDENT,
];

const PERL_THEME: LangTheme = LangTheme {
    keywords: &[(0, PERL_KEYWORDS)],
    styles: PERL_STYLES,
    italic: PERL_ITALIC,
    bold: PERL_BOLD,
};

// --- LexPython (Python 3) ---
// LexPython is byte-exact case-sensitive: `LexPython.cxx:671` calls
// `keywords.InList(identifier)` with no case folding (confirmed by
// zero matches for `tolower` / `MakeLowerCase` / `GetCurrentLowered`
// in the source). Wordlists must use source-canonical casing ŌĆö
// lowercase for the bulk of reserved words; CAPITALISED for
// `True` / `False` / `None`; CamelCase for exception classes;
// dunder-underscores for `__init__` etc.
//
// **Two wordlist classes.** `pythonWordListDesc[]` declares two
// slots: `"Keywords"` (class 0, `PYTHON_KEYWORDS`) and
// `"Highlighted identifiers"` (class 1, `PYTHON_KEYWORDS_2`).
// Class 0 drives `SCE_P_WORD` (Keyword bold); class 1 drives
// `SCE_P_WORD2` (Keyword2 steel-blue). Lexilla checks class 0
// first ŌĆö a cross-class duplicate would silently demote the
// class-1 entry. The Python test asserts no-overlap structurally.
//
// **`True` / `False` / `None` placement.** Code++ deliberately
// places these in class 0 (Keyword bold), NOT class 1, because
// Python 3 makes them hard reserved words (`True = 5` raises
// SyntaxError). Notepad++ historically put them in WORD2 for
// Python 2 backward compatibility ŌĆö Code++ diverges to honour
// the modern language semantics.
//
// **`match` / `case` soft keywords (Python 3.10+).** Included in
// class 0; LexPython's `IsMatchOrCaseIdentifier` helper
// (`LexPython.cxx:258-289`) disambiguates non-pattern context so
// `match = 1` and `obj.match()` correctly degrade to
// `SCE_P_IDENTIFIER`.
//
// Style-to-slot decisions:
//   * COMMENTLINE (`# ...`) ŌåÆ Comment italic.
//   * COMMENTBLOCK (`##`-prefixed comment lines) ŌåÆ Comment italic.
//     Lexilla emits this at `LexPython.cxx:914` when `sc.chNext ==
//     '#'`; pre-themed for safety so the convention isn't
//     uncoloured.
//   * NUMBER (decimal / hex / oct / bin / underscore-separated /
//     `0x` / `0b` / `0o` / `_`-grouped) ŌåÆ Number.
//   * WORD (class-0 wordlist hit ŌĆö Python reserved words) ŌåÆ
//     Keyword bold.
//   * WORD2 (class-1 wordlist hit ŌĆö built-in functions, exception
//     types, `self` / `cls`, dunders) ŌåÆ Keyword2.
//   * STRING (`"..."`) / CHARACTER (`'...'`) ŌåÆ String. Python
//     makes no semantic char/string split; both single- and
//     double-quoted variants render identically.
//   * TRIPLE (`'''...'''`) / TRIPLEDOUBLE (`"""..."""`) ŌåÆ String.
//     The lexer has no docstring-specific lex state ŌĆö a triple-
//     quoted literal mid-expression (`x = """hello"""`) emits the
//     same state as a module-level docstring. Styling these as
//     Comment would mis-colour multi-line SQL queries, regex
//     VERBOSE patterns, embedded HTML/JSON fixtures, and inline
//     data blobs ŌĆö all common in real Python. The docstring role
//     is a runtime convention (`__doc__` binding), not a lexical
//     one. PyCharm / VS Code / Sublime / Notepad++ all paint
//     triple-quoted strings as String.
//   * F-string family ŌĆö FSTRING (`f"..."`) / FCHARACTER (`f'...'`)
//     / FTRIPLE (`f'''...'''`) / FTRIPLEDOUBLE (`f"""..."""`) ŌåÆ
//     all String. The `{}` interpolation sub-lexer is internal to
//     Lexilla. Activation is `stringsF = true` by default
//     (`LexPython.cxx:297`); Code++ doesn't override.
//   * CLASSNAME (post-`class ` identifier) / DEFNAME (post-`def `
//     identifier) ŌåÆ Keyword2. The lexer's kwLast state machine
//     (lines 673-676) auto-reclassifies the identifier after a
//     `class` / `def` wordlist hit. No wordlist install needed for
//     the names themselves. Code++ rides Keyword2's non-bold weight
//     even though N++ paints them bold ŌĆö palette discipline keeps
//     the `std::` / `mod` / Python class-name accent visually
//     consistent across languages.
//   * DECORATOR (`@foo` at line start) ŌåÆ Preprocessor bold. The
//     line-start gate is internal to LexPython (line 916,
//     `IsFirstNonWhitespace`), so mid-expression `@` matrix-mul
//     (Python 3.5+) correctly degrades to `SCE_P_OPERATOR`. The
//     Preprocessor slot's dark-green bold matches the "out-of-band
//     annotation" visual weight N++ assigns to `#include` etc.
//   * OPERATOR (`+ - * / = ( ) [ ] : , .` and the family) ŌåÆ
//     Operator.
//   * ATTRIBUTE (`obj.foo` post-decorator attribute access) ŌåÆ
//     Keyword2. **Pre-themed only.** The lexer never emits this
//     state under Code++'s defaults ŌĆö `lexer.python.identifier.
//     attributes` and `lexer.python.decorator.attributes` both
//     default to 0 (`LexPython.cxx:305-306`) and Code++ never
//     calls `SetProperty` to enable them. Wired for forward-
//     compat ŌĆö costs one table row, gains zero-effort activation
//     if the property is ever flipped. Same pattern as CSS
//     EXTENDED_PSEUDOCLASS pre-theming.
//
// Intentionally unmapped (fall through to STYLE_DEFAULT):
//   * SCE_P_DEFAULT (0) ŌĆö generic background text (universal
//     omission, matches `SCE_C_DEFAULT` / `SCE_PL_DEFAULT`).
//   * SCE_P_IDENTIFIER (11) ŌĆö bare identifier (post-keyword-miss);
//     matches `SCE_C_IDENTIFIER` / `SCE_PAS_IDENTIFIER` /
//     `SCE_PL_IDENTIFIER` precedent.
//   * SCE_P_STRINGEOL (13) ŌĆö unterminated-string error indicator.
//     Joins the deferred-Error-slot migration list ŌĆö currently at
//     12 entries (Perl ERROR + VB STRINGEOL + 9 others + this).
const PYTHON_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_P_COMMENTLINE, StyleSlot::Comment),
    (SCE_P_NUMBER, StyleSlot::Number),
    (SCE_P_STRING, StyleSlot::String),
    (SCE_P_CHARACTER, StyleSlot::String),
    (SCE_P_WORD, StyleSlot::Keyword),
    (SCE_P_TRIPLE, StyleSlot::String),
    (SCE_P_TRIPLEDOUBLE, StyleSlot::String),
    (SCE_P_CLASSNAME, StyleSlot::Keyword2),
    (SCE_P_DEFNAME, StyleSlot::Keyword2),
    (SCE_P_OPERATOR, StyleSlot::Operator),
    (SCE_P_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_P_WORD2, StyleSlot::Keyword2),
    (SCE_P_DECORATOR, StyleSlot::Preprocessor),
    (SCE_P_FSTRING, StyleSlot::String),
    (SCE_P_FCHARACTER, StyleSlot::String),
    (SCE_P_FTRIPLE, StyleSlot::String),
    (SCE_P_FTRIPLEDOUBLE, StyleSlot::String),
    (SCE_P_ATTRIBUTE, StyleSlot::Keyword2),
];
// Line comments AND `##` block-style comments both italic ŌĆö matches
// universal Code++ convention for comment slots.
const PYTHON_ITALIC: &[usize] = &[SCE_P_COMMENTLINE, SCE_P_COMMENTBLOCK];
// Primary keyword + decorator bold ŌĆö matches Notepad++ Python
// default and the C/C++ precedent of bolding `SCE_C_WORD` +
// `SCE_C_PREPROCESSOR`.
const PYTHON_BOLD: &[usize] = &[SCE_P_WORD, SCE_P_DECORATOR];

const PYTHON_THEME: LangTheme = LangTheme {
    keywords: &[(0, PYTHON_KEYWORDS), (1, PYTHON_KEYWORDS_2)],
    styles: PYTHON_STYLES,
    italic: PYTHON_ITALIC,
    bold: PYTHON_BOLD,
};

// LexLua emits 21 styles (0..=20). Code++ maps the 18 visually
// meaningful ones below. Three are intentionally unmapped (fall
// through to STYLE_DEFAULT):
//   * SCE_LUA_DEFAULT (0) ŌĆö generic background text (universal
//     omission, matches `SCE_C_DEFAULT` / `SCE_P_DEFAULT`).
//   * SCE_LUA_IDENTIFIER (11) ŌĆö bare identifier (post-keyword-miss);
//     matches `SCE_C_IDENTIFIER` / `SCE_P_IDENTIFIER` /
//     `SCE_PL_IDENTIFIER` precedent.
//   * SCE_LUA_STRINGEOL (12) ŌĆö unterminated-string error indicator.
//     Joins the deferred-Error-slot migration list ŌĆö currently at
//     13 entries (Perl ERROR + VB STRINGEOL + Python STRINGEOL +
//     10 others including this one).
//
// Routing decisions worth flagging:
//   * COMMENT / COMMENTLINE / COMMENTDOC all ŌåÆ Comment italic. The
//     three slots cover `--[[ ]]` block comments, `-- ...` line
//     comments (including the top-of-file shebang at
//     LexLua.cxx:280), and `---`-initiated LDoc-style doc comments
//     plus their cross-line continuations. LDoc tag handling
//     (`---@param`, `---@return`) is NOT a separate state ŌĆö the
//     entire run from `---` to EOL is one flat COMMENTDOC token
//     per LexLua.cxx:542-544, so a single italic-comment treatment
//     covers them all.
//   * STRING / CHARACTER / LITERALSTRING all ŌåÆ String. Lua makes
//     no semantic char/string split (single-quoted and double-
//     quoted are functionally identical, only differ in which
//     quote needs escaping). LITERALSTRING covers `[[...]]` /
//     `[=[...]=]` long-bracket form per LexLua.cxx:525-532;
//     `LongDelimCheck` allows up to 254 `=` chars between brackets.
//     Treating all three String-uniform matches Python's
//     TRIPLE / TRIPLEDOUBLE ŌåÆ String precedent.
//   * WORD ŌåÆ Keyword bold (class 0 reserved-word hit). WORD2 ..
//     WORD8 ŌåÆ Keyword2 (classes 1-7 secondary library / user
//     customisation slots ŌĆö all 7 secondary classes pre-themed
//     for forward-compat even though Code++ m1 only ships
//     [`LUA_KEYWORDS_2`] for class 1; classes 2/3/4-7 stay empty
//     today but the styles are wired so a `LUA_KEYWORDS_3` /
//     `_4` follow-on commit needs only a one-line `keywords:`
//     extension in `LUA_THEME` to activate). Same forward-compat
//     pattern as CSS EXTENDED_PSEUDOCLASS and Python ATTRIBUTE.
//   * PREPROCESSOR ŌåÆ Preprocessor (NOT bold). LexLua.cxx:548-549
//     emits this ONLY for `$` at column 0 ŌĆö obsolete Lua-pre-4.0
//     preprocessor directive ("Obsolete since Lua 4.0, but still
//     in old code"). The `#!` shebang at file top is handled
//     separately at LexLua.cxx:278-281 and types as COMMENTLINE,
//     NOT PREPROCESSOR. Kept visually identifiable via the
//     Preprocessor slot but NOT bold ŌĆö boldening dead syntax
//     misleads.
//   * LABEL ŌåÆ Preprocessor (structural anchor for `::name::` goto
//     labels and `goto target` resolution targets). LexLua.cxx:
//     320-396 implements two paths: `::label::` definition (the
//     four-segment scan emits LABEL for the brackets and the
//     identifier, with a `!keywords.InList` guard at :335
//     rejecting `::reserved_word::` constructs) and `goto target`
//     downstream-identifier styling (the post-`goto` identifier
//     is LABEL unless it turned out to be a reserved keyword, in
//     which case it downgrades to WORD at :393). Both paths
//     require `goto` to live in class 0 ŌĆö pinned in the test.
//     Routing to Preprocessor matches Python's SCE_P_DECORATOR
//     precedent ŌĆö both are "out-of-band annotation" structural
//     anchors. Bold-tagged in `LUA_BOLD` alongside `SCE_LUA_WORD`
//     for visual weight matching the structural-anchor role.
const LUA_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_LUA_COMMENT, StyleSlot::Comment),
    (SCE_LUA_COMMENTLINE, StyleSlot::Comment),
    (SCE_LUA_COMMENTDOC, StyleSlot::Comment),
    (SCE_LUA_NUMBER, StyleSlot::Number),
    (SCE_LUA_WORD, StyleSlot::Keyword),
    (SCE_LUA_STRING, StyleSlot::String),
    (SCE_LUA_CHARACTER, StyleSlot::String),
    (SCE_LUA_LITERALSTRING, StyleSlot::String),
    (SCE_LUA_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_LUA_OPERATOR, StyleSlot::Operator),
    (SCE_LUA_WORD2, StyleSlot::Keyword2),
    (SCE_LUA_WORD3, StyleSlot::Keyword2),
    (SCE_LUA_WORD4, StyleSlot::Keyword2),
    (SCE_LUA_WORD5, StyleSlot::Keyword2),
    (SCE_LUA_WORD6, StyleSlot::Keyword2),
    (SCE_LUA_WORD7, StyleSlot::Keyword2),
    (SCE_LUA_WORD8, StyleSlot::Keyword2),
    (SCE_LUA_LABEL, StyleSlot::Preprocessor),
];
// All three comment family styles italic ŌĆö matches universal
// Code++ comment-slot convention (Python COMMENTLINE +
// COMMENTBLOCK, Perl COMMENTLINE + POD family, Rust
// COMMENTBLOCK + COMMENTLINE).
const LUA_ITALIC: &[usize] = &[SCE_LUA_COMMENT, SCE_LUA_COMMENTLINE, SCE_LUA_COMMENTDOC];
// Primary keyword + label bold ŌĆö `SCE_LUA_WORD` (class 0 reserved
// word hit) gets the classic keyword-bold treatment matching
// `SCE_C_WORD` / `SCE_P_WORD` precedent; `SCE_LUA_LABEL` carries
// matching weight as a structural anchor (parallels Python
// `SCE_P_DECORATOR` bold). SCE_LUA_PREPROCESSOR deliberately
// excluded ŌĆö Lua's `$` preprocessor was obsolete in Lua 4.0
// (LexLua.cxx:549 comment is explicit) and boldening dead syntax
// misleads.
const LUA_BOLD: &[usize] = &[SCE_LUA_WORD, SCE_LUA_LABEL];

const LUA_THEME: LangTheme = LangTheme {
    keywords: &[(0, LUA_KEYWORDS), (1, LUA_KEYWORDS_2)],
    styles: LUA_STYLES,
    italic: LUA_ITALIC,
    bold: LUA_BOLD,
};

// LexTeX (plain TeX). Five mappings: SCE_TEX_TEXT (plain prose
// fall-through, state 5) is intentionally unmapped per the
// scintilla-sys banner. SCE_TEX_DEFAULT routes to Comment
// because ŌĆö counter to the slot's name ŌĆö it is the comment-body
// emission state (the leading `%` is SCE_TEX_SYMBOL, every
// subsequent char until EOL is SCE_TEX_DEFAULT; see the
// scintilla-sys banner for the load-bearing rationale and the
// `LexTeX.cxx:248-254` cite).
const TEX_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_TEX_DEFAULT, StyleSlot::Comment),
    (SCE_TEX_SPECIAL, StyleSlot::Operator),
    (SCE_TEX_GROUP, StyleSlot::Operator),
    (SCE_TEX_SYMBOL, StyleSlot::Operator),
    (SCE_TEX_COMMAND, StyleSlot::Keyword),
];

// Italic on the comment body (SCE_TEX_DEFAULT) ŌĆö universal
// comment-slot italic convention.
const TEX_ITALIC: &[usize] = &[SCE_TEX_DEFAULT];

// Bold on `\command` runs (SCE_TEX_COMMAND) ŌĆö primary-keyword
// bold convention, matches the Lua / Python / CPP precedent.
const TEX_BOLD: &[usize] = &[SCE_TEX_COMMAND];

// Empty keywords ŌĆö TEX_THEME ships no wordlists per N++ default
// parity. Populated wordlists would silently downgrade unknown
// `\command` tokens to plain text via the `:230-245` filter,
// which surprises users opening `.tex` files containing LaTeX
// content. See the scintilla-sys banner for the full rationale.
const TEX_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: TEX_STYLES,
    italic: TEX_ITALIC,
    bold: TEX_BOLD,
};

// LexLaTeX. 11 mappings ŌĆö DEFAULT (state 0, plain-prose
// fall-through) and ERROR (state 12, deferred Error slot) are
// intentionally unmapped per the scintilla-sys banner.
//
// Routing decisions: COMMAND / SHORTCMD ŌåÆ Keyword (the `\foo`
// and single-char `\\` / `\!` etc. control sequences are
// LaTeX's verbs); TAG / TAG2 / CMDOPT ŌåÆ Keyword2 (environment
// names in `\begin{env}` / `\end{env}` and the `[opt]` option
// blocks are structural identifiers, matches the
// `SCE_P_CLASSNAME` precedent); MATH / MATH2 / VERBATIM ŌåÆ
// String (math regions and `\verb` content are literal regions
// semantically, matches the Perl regex-as-String precedent);
// COMMENT / COMMENT2 ŌåÆ Comment (both `%`-to-EOL and the
// `\begin{comment}` block-comment from the `comment` package
// are comment slots); SPECIAL ŌåÆ Operator (the eight escaped
// punctuation characters `\#` / `\$` / `\%` / `\&` / `\_` /
// `\{` / `\}` / `\<space>`).
const LATEX_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_L_COMMAND, StyleSlot::Keyword),
    (SCE_L_TAG, StyleSlot::Keyword2),
    (SCE_L_MATH, StyleSlot::String),
    (SCE_L_COMMENT, StyleSlot::Comment),
    (SCE_L_TAG2, StyleSlot::Keyword2),
    (SCE_L_MATH2, StyleSlot::String),
    (SCE_L_COMMENT2, StyleSlot::Comment),
    (SCE_L_VERBATIM, StyleSlot::String),
    (SCE_L_SHORTCMD, StyleSlot::Keyword),
    (SCE_L_SPECIAL, StyleSlot::Operator),
    (SCE_L_CMDOPT, StyleSlot::Keyword2),
];

// Italic on both comment families. VERBATIM stays roman
// (verbatim is typically rendered monospace, not italic).
const LATEX_ITALIC: &[usize] = &[SCE_L_COMMENT, SCE_L_COMMENT2];

// Bold on every command-shaped state ŌĆö primary keyword + the
// `\begin` / `\end` structural anchors. Matches Lua's
// WORD + LABEL precedent.
const LATEX_BOLD: &[usize] = &[SCE_L_COMMAND, SCE_L_SHORTCMD, SCE_L_TAG, SCE_L_TAG2];

// Empty keywords ŌĆö the lexer's `emptyWordListDesc` at
// `LexLaTeX.cxx:561` declares zero wordlist classes; the host
// must not install any (they'd be silently dropped). See the
// scintilla-sys banner.
const LATEX_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: LATEX_STYLES,
    italic: LATEX_ITALIC,
    bold: LATEX_BOLD,
};

// LexBash (Bash / POSIX shell). 11 mappings ŌĆö DEFAULT (state 0,
// generic background text), IDENTIFIER (state 8, post-keyword-miss
// bare identifier and dominant fall-through per LexBash.cxx:677,
// :694, :703, :710, :717, :723, :728, :796, :1012, :1028, :1044,
// :1047, :1050, :1080, :1099), and ERROR (state 1, malformed
// numeric / unterminated heredoc / out-of-range base-N digit ŌĆö
// joins the deferred-Error-slot migration list) are intentionally
// unmapped per the scintilla-sys banner.
//
// Routing decisions:
//   * COMMENTLINE ŌåÆ Comment ŌĆö `#`-to-EOL line comments, with the
//     POSIX shell precondition that `#` mid-identifier stays in
//     the word (`LexBash.cxx:1029-1035`).
//   * NUMBER ŌåÆ Number ŌĆö decimal / hex (`0x`) / base-N (`DD#...`)
//     per `LexBash.cxx:745-799`. Floats are NOT a Bash concept;
//     `123.45` reclassifies as IDENTIFIER mid-token at `:793-797`.
//   * WORD ŌåÆ Keyword ŌĆö driven by `BASH_KEYWORDS` (class 0); hit
//     only at command-Start position per `:726-728`. Structural
//     reserved words (`if`/`then`/`fi`/`while`/`for`/`case`/etc.)
//     ALSO route here via the hard-wired `bashStruct` /
//     `bashStruct_in` sets at `:706, :713`.
//   * STRING ŌåÆ String ŌĆö `"..."` double-quoted, may contain `$var`
//     expansions per `:1053-1055`.
//   * CHARACTER ŌåÆ String ŌĆö `'...'` single-quoted, no expansion;
//     same dual-quoteŌåÆString collapse as Python (SCE_P_STRING /
//     SCE_P_CHARACTER) and Lua (SCE_LUA_STRING / SCE_LUA_CHARACTER).
//   * OPERATOR ŌåÆ Operator ŌĆö the shell operator set
//     `^&%()-+=|{}[]:;>,*/<?!.~@` per `:580` plus the command-
//     delimiter sub-set `| || |& & && ; ;; ( ) { }` at `:491`.
//   * SCALAR ŌåÆ Lifetime ŌĆö `$var` / `$1` / `$@` / `$#` sigil-tagged
//     variable. Routes through `StyleSlot::Lifetime` (the
//     "scoped binding" palette slot, documented at the `StyleSlot`
//     enum declaration in `crates/ui_win32/src/lib.rs:3074-3077`)
//     ŌĆö direct precedent at `SCE_PL_SCALAR ŌåÆ Lifetime` at line
//     4211 below. Bash's `$x` is the canonical version of the
//     sigil-tagged-variable archetype Perl inherited from sh.
//   * PARAM ŌåÆ Lifetime ŌĆö `${param}` / `${param:-default}` /
//     `${#array[@]}` parameter expansion (braced form). Same
//     archetype as SCALAR ŌĆö uniform `Lifetime` mapping mirrors
//     Perl's uniform SCALAR/ARRAY/HASH/SYMBOLTABLE ŌåÆ Lifetime
//     collapse at lines 4211-4214.
//   * BACKTICKS ŌåÆ String ŌĆö `` `cmd` `` (and `$(cmd)` at the
//     default `lexer.bash.command.substitution = 0` per
//     `LexBash.cxx:231-234`, 381-383). Shell-command-as-string
//     archetype, matches `SCE_PL_BACKTICKS ŌåÆ String` at line 4217.
//   * HERE_DELIM ŌåÆ Keyword2 ŌĆö `<<EOF` / `<<'EOF'` / `<<-EOF`
//     opening marker line AND the closing-delimiter line per
//     `:896`. Structural anchor distinct from the body ŌĆö matches
//     `SCE_PL_HERE_DELIM ŌåÆ Keyword2 + bold` at line 4219.
//   * HERE_Q ŌåÆ String ŌĆö heredoc body. Single state covering both
//     quoted and unquoted bodies per `:806-867`; LexBash, unlike
//     LexPerl, does not split into HERE_Q / HERE_QQ / HERE_QX.
//     The `Q` suffix in the constant name is a misnomer inherited
//     from LexPerl's taxonomy ŌĆö see the scintilla-sys banner.
const BASH_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_SH_COMMENTLINE, StyleSlot::Comment),
    (SCE_SH_NUMBER, StyleSlot::Number),
    (SCE_SH_WORD, StyleSlot::Keyword),
    (SCE_SH_STRING, StyleSlot::String),
    (SCE_SH_CHARACTER, StyleSlot::String),
    (SCE_SH_OPERATOR, StyleSlot::Operator),
    (SCE_SH_SCALAR, StyleSlot::Lifetime),
    (SCE_SH_PARAM, StyleSlot::Lifetime),
    (SCE_SH_BACKTICKS, StyleSlot::String),
    (SCE_SH_HERE_DELIM, StyleSlot::Keyword2),
    (SCE_SH_HERE_Q, StyleSlot::String),
];

// Italic on `#`-to-EOL comments. Matches universal Code++
// comment-slot convention (Python COMMENTLINE + COMMENTBLOCK,
// Perl COMMENTLINE + POD, Rust COMMENTBLOCK + COMMENTLINE, Lua
// COMMENT + COMMENTLINE + COMMENTDOC, LaTeX COMMENT + COMMENT2,
// TeX DEFAULT).
const BASH_ITALIC: &[usize] = &[SCE_SH_COMMENTLINE];

// Primary keyword bold + heredoc-delimiter bold. WORD gets the
// classic keyword-bold treatment matching the C / C++ / Lua /
// Python / Perl precedent. HERE_DELIM is the structural anchor
// for the `<<EOF` / `<<-EOF` / closing-delimiter machinery ŌĆö
// bolding matches the Perl `SCE_PL_HERE_DELIM` precedent at line
// 4257 (structural-anchor convention). SCALAR / PARAM /
// BACKTICKS deliberately excluded ŌĆö they carry visual
// distinction through their colour slots (Lifetime / String),
// exactly as Perl's SCALAR / ARRAY / HASH stay non-bold at
// lines 4211-4214 despite using the `Lifetime` slot.
const BASH_BOLD: &[usize] = &[SCE_SH_WORD, SCE_SH_HERE_DELIM];

// Single class 0 install. `bashWordListDesc[]` at
// `LexBash.cxx:205-208` declares exactly one named slot
// (`"Keywords"`); `LexerBash::WordListSet` at `:558-572` only
// dispatches `case 0:` and no-ops for any other class. There is
// no `BASH_KEYWORDS_2`. See the scintilla-sys banner for the
// structural-reserved-word handling rationale (`bashStruct` /
// `bashStruct_in` are hard-wired, NOT in `BASH_KEYWORDS`).
const BASH_THEME: LangTheme = LangTheme {
    keywords: &[(0, BASH_KEYWORDS)],
    styles: BASH_STYLES,
    italic: BASH_ITALIC,
    bold: BASH_BOLD,
};

// --- LexNsis (NSIS installer script) ---
//
// 19 emission states (0..=18). 17 routed; DEFAULT (0) follows the
// universal background-fall-through convention. No ERROR state
// exists in LexNsis ŌĆö the lexer simply walks back to DEFAULT on
// any unmatched character (contrast with `SCE_SH_ERROR` /
// `SCE_PL_ERROR` which join the deferred-Error-slot migration).
//
// Style routing rationale per slot:
//   * COMMENT ŌåÆ Comment ŌĆö `;` and `#` line comments per
//     `LexNsis.cxx:316`. Universal Comment-slot convention.
//   * COMMENTBOX ŌåÆ Comment ŌĆö `/* ... */` block comments per
//     `:357-361, :490-495`. Matches the Lua COMMENT + COMMENTLINE
//     + COMMENTDOC uniform-Comment-slot precedent at line 4487.
//   * STRINGDQ ŌåÆ String ŌĆö `"..."` per `:322-326, :388-393`.
//   * STRINGLQ ŌåÆ String ŌĆö `` `...` `` per `:335-342, :395-400`.
//   * STRINGRQ ŌåÆ String ŌĆö `'...'` per `:327-334, :402-407`.
//     All three string flavours collapse to the same `String`
//     slot ŌĆö uniform-archetype matches the Lua LITERALSTRING +
//     CHARACTER + STRING triple collapse at line 4424-4431.
//   * FUNCTION ŌåÆ Keyword ŌĆö class-0 wordlist hit per `:233-234`.
//     Despite the upstream slot name `"Functions"`, semantically
//     this is the NSIS instruction set (`MessageBox` /
//     `WriteRegStr` / `File` / `SetOutPath` / `IfFileExists` /
//     `!define` / `!include` / etc.). Matches `SCE_C_WORD` /
//     `SCE_SH_WORD` / `SCE_P_WORD` ŌåÆ Keyword bold-blue precedent.
//   * VARIABLE ŌåÆ Lifetime ŌĆö class-1 wordlist hit, `${...}` shape,
//     and (when `nsis.uservars=1`) bare `$user` per `:236-237,
//     :245-248, :252-265`. Sigil-tagged variable archetype ŌĆö
//     matches the Bash SCALAR / PARAM ŌåÆ Lifetime precedent at
//     line 4653-4654 and Perl's SCALAR / ARRAY / HASH /
//     SYMBOLTABLE ŌåÆ Lifetime collapse rationale.
//   * LABEL ŌåÆ Preprocessor ŌĆö class-2 wordlist hit per `:239-240`.
//     Structural out-of-band jump-target anchor. Matches
//     `SCE_LUA_LABEL` ŌåÆ Preprocessor precedent (Lua's `::name::`
//     goto labels) for the same archetypal "structural anchor"
//     reason ŌĆö labels are not content, they're addressing marks.
//   * USERDEFINED ŌåÆ Keyword2 ŌĆö class-3 wordlist hit per `:242-243`.
//     User-extension slot for `!define`d / `!macro`-defined names
//     the user wants explicitly highlighted. Matches `SCE_LUA_WORD2`
//     ŌåÆ Keyword2 precedent for "secondary library / user
//     customisation".
//   * SECTIONDEF / SUBSECTIONDEF / SECTIONGROUP / PAGEEX /
//     FUNCTIONDEF ŌåÆ Keyword ŌĆö hard-wired structural keywords per
//     `:218-231`. `Section` / `SectionEnd` / `SubSection` /
//     `SubSectionEnd` / `SectionGroup` / `SectionGroupEnd` /
//     `PageEx` / `PageExEnd` / `Function` / `FunctionEnd` all
//     get the same Keyword bold treatment matching N++ default
//     scheme ŌĆö structural-keyword cluster.
//   * IFDEFINEDEF / MACRODEF ŌåÆ Preprocessor ŌĆö hard-wired
//     `!`-prefixed compile-time directives per `:206-216`. `!macro`
//     / `!macroend` / `!if` / `!ifdef` / `!ifndef` / `!endif` /
//     `!else` / `!ifmacrodef` / `!ifmacrondef`. Direct precedent:
//     `SCE_C_PREPROCESSOR` for `#ifdef` / `#endif` / `#define` ŌĆö
//     compile-time directives are Preprocessor by archetype.
//   * STRINGVAR ŌåÆ Lifetime ŌĆö `$var` / `${var}` interpolation
//     inside an active string body per `:518, :527-530, :536`.
//     Same sigil-tagged-variable archetype as bare VARIABLE,
//     routes to the same slot ŌĆö uniform handling matches Bash's
//     mid-string SCALAR handling.
//   * NUMBER ŌåÆ Number ŌĆö decimal-only literals per `:282, :351-352,
//     :461-462`. Universal Number-slot convention.
const NSIS_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_NSIS_COMMENT, StyleSlot::Comment),
    (SCE_NSIS_STRINGDQ, StyleSlot::String),
    (SCE_NSIS_STRINGLQ, StyleSlot::String),
    (SCE_NSIS_STRINGRQ, StyleSlot::String),
    (SCE_NSIS_FUNCTION, StyleSlot::Keyword),
    (SCE_NSIS_VARIABLE, StyleSlot::Lifetime),
    (SCE_NSIS_LABEL, StyleSlot::Preprocessor),
    (SCE_NSIS_USERDEFINED, StyleSlot::Keyword2),
    (SCE_NSIS_SECTIONDEF, StyleSlot::Keyword),
    (SCE_NSIS_SUBSECTIONDEF, StyleSlot::Keyword),
    (SCE_NSIS_IFDEFINEDEF, StyleSlot::Preprocessor),
    (SCE_NSIS_MACRODEF, StyleSlot::Preprocessor),
    (SCE_NSIS_STRINGVAR, StyleSlot::Lifetime),
    (SCE_NSIS_NUMBER, StyleSlot::Number),
    (SCE_NSIS_SECTIONGROUP, StyleSlot::Keyword),
    (SCE_NSIS_PAGEEX, StyleSlot::Keyword),
    (SCE_NSIS_FUNCTIONDEF, StyleSlot::Keyword),
    (SCE_NSIS_COMMENTBOX, StyleSlot::Comment),
];

// Italic on `;` / `#` line comments AND `/* ... */` block
// comments ŌĆö both render as comment-semantic prose. Matches the
// Lua COMMENT + COMMENTLINE + COMMENTDOC triple-italic
// convention (every comment-class state gets italic) rather
// than the Bash COMMENTLINE-only single-italic case ŌĆö NSIS has
// two distinct comment families that BOTH benefit from
// italicisation, and there's no doc-style third family to
// elevate. Universal Code++ comment-slot convention.
const NSIS_ITALIC: &[usize] = &[SCE_NSIS_COMMENT, SCE_NSIS_COMMENTBOX];

// Bold the entire structural-keyword cluster (FUNCTION +
// FUNCTIONDEF + SECTIONDEF + SUBSECTIONDEF + SECTIONGROUP +
// PAGEEX) matching Notepad++ default NSIS scheme ŌĆö all five
// dedicated `*DEF` / `*GROUP` / `PAGEEX` slots get keyword-bold
// treatment alongside the wordlist-driven FUNCTION instruction
// hits (`MessageBox` / `WriteRegStr` / etc.). Plus IFDEFINEDEF
// + MACRODEF, mirroring the `SCE_C_PREPROCESSOR` bold precedent
// for `#ifdef` / `#define` ŌĆö `!`-prefixed compile-time
// directives are structurally anchoring code blocks. LABEL
// deliberately NOT bolded ŌĆö labels appear frequently inside
// long Section bodies; bolding would create visual noise. The
// Preprocessor slot's distinct colour already carries the
// out-of-band-anchor cue, matching `SCE_LUA_PREPROCESSOR`
// staying non-bold at line 4492-4495. VARIABLE / STRINGVAR /
// USERDEFINED deliberately excluded ŌĆö they carry visual
// distinction through their colour slots (Lifetime / Keyword2),
// exactly as Bash SCALAR / PARAM stay non-bold despite using
// Lifetime at line 4677.
const NSIS_BOLD: &[usize] = &[
    SCE_NSIS_FUNCTION,
    SCE_NSIS_FUNCTIONDEF,
    SCE_NSIS_SECTIONDEF,
    SCE_NSIS_SUBSECTIONDEF,
    SCE_NSIS_SECTIONGROUP,
    SCE_NSIS_PAGEEX,
    SCE_NSIS_IFDEFINEDEF,
    SCE_NSIS_MACRODEF,
];

// Classes 0 + 1 installed. `nsisWordLists[]` at
// `LexNsis.cxx:658-663` declares four classes: `"Functions"`
// (class 0 ŌĆö NSIS instruction set + non-hard-wired
// `!`-directives), `"Variables"` (class 1 ŌĆö predefined
// `$INSTDIR` / `$WINDIR` / `$0..$9` / etc.), `"Lables"` [sic]
// (class 2 ŌĆö user-supplied label names; ships empty in N++
// default), `"UserDefined"` (class 3 ŌĆö user-supplied
// `!define`d / `!macro`-defined names; ships empty in N++
// default). Code++ matches N++ by populating only classes
// 0 and 1.
//
// Case + scope contract. LexNsis reads two runtime properties
// (`nsis.ignorecase` defaulting to 0; `nsis.uservars` defaulting
// to 0) at `LexNsis.cxx:178, :184, :508`. Code++ matches the
// LEXER defaults today ŌĆö `LangTheme` has no `properties` slot, so
// neither property is installed, and the lexer runs at strict
// byte-exact comparison with no bare-`$user` fallback. Wordlist
// contents below are stored in their **canonical mixed-case**
// form per the NSIS Users Manual (`MessageBox` / `SetOutPath` /
// `WriteRegStr` / `$INSTDIR` / etc.) ŌĆö matching the source
// spelling an NSIS author writes and matching the hard-wired
// branches at `:206-231` (`Section`, `Function`, `SectionGroup`,
// etc.) which also compare canonical mixed-case. This is the
// same default-set behaviour Notepad++ would exhibit if its own
// `nsis.ignorecase=1` property install were removed ŌĆö Code++'s
// shape is consistent with author-intent and the lexer source.
//
// Consequence of NOT installing `nsis.uservars=1`: user-declared
// variables (`Var MyVar` ŌåÆ `$MyVar`) lex as `SCE_NSIS_DEFAULT`
// instead of `SCE_NSIS_VARIABLE`. Only the predefined `$INSTDIR`
// / `$WINDIR` / etc. names in `NSIS_VARIABLES` highlight. Tracked
// in `docs/lexers-coverage.md` for a follow-up that adds a
// `properties: &[(&str, &str)]` slot to `LangTheme` and threads
// `SCI_SETPROPERTY` through `apply_lang` ŌĆö the same plumbing
// also unlocks CSS's `lexer.css.scss.language` and Python's
// `lexer.python.identifier.attributes` forward-compat hooks
// already referenced in their respective banners. Once the slot
// lands, installing `nsis.ignorecase=1` is optional ŌĆö canonical
// mixed-case keeps working under both property values, so the
// follow-up will install `nsis.uservars=1` for user-var
// highlighting without needing to flip case handling.
const NSIS_THEME: LangTheme = LangTheme {
    keywords: &[(0, NSIS_FUNCTIONS), (1, NSIS_VARIABLES)],
    styles: NSIS_STYLES,
    italic: NSIS_ITALIC,
    bold: NSIS_BOLD,
};

// --- LexTCL ---
// `LexTCL.cxx` defines 22 contiguous emission states (0..=21). 20
// of them get a paint slot below; SCE_TCL_DEFAULT (0) and
// SCE_TCL_IDENTIFIER (7) deliberately stay unmapped per the
// universal-omission pattern (background-text + bare-identifier
// render at STYLE_DEFAULT ŌĆö same as SCE_C_DEFAULT /
// SCE_C_IDENTIFIER, SCE_LUA_DEFAULT / SCE_LUA_IDENTIFIER,
// SCE_PL_DEFAULT / SCE_PL_IDENTIFIER, SCE_SH_DEFAULT precedent).
// No SCE_TCL_ERROR state exists ŌĆö LexTCL has no recovery /
// malformed-token branch, so no deferred-Error-slot entry needed
// (contrast with SCE_SH_ERROR / SCE_LUA_STRINGEOL joining the
// deferred-Error cluster).
const TCL_STYLES: &[(usize, StyleSlot)] = &[
    // Four-state comment cluster ŌĆö `#`-line at command position
    // (COMMENT), `#`-line elsewhere (COMMENTLINE), `#~` block
    // (BLOCK_COMMENT), and `#-` / `##` line-leading box
    // continuation (COMMENT_BOX). All collapse to Comment per
    // the universal-comment convention; matches Lua COMMENT +
    // COMMENTLINE + COMMENTDOC triple-collapse and NSIS's
    // COMMENT + COMMENTBOX collapse precedent.
    (SCE_TCL_COMMENT, StyleSlot::Comment),
    (SCE_TCL_COMMENTLINE, StyleSlot::Comment),
    (SCE_TCL_COMMENT_BOX, StyleSlot::Comment),
    (SCE_TCL_BLOCK_COMMENT, StyleSlot::Comment),
    // Numeric literals.
    (SCE_TCL_NUMBER, StyleSlot::Number),
    // String body ŌĆö `"..."` content (IN_QUOTE, entered at `:308`,
    // exited at `:261-263`). Routed to String per the
    // uniform-string-body archetype.
    (SCE_TCL_IN_QUOTE, StyleSlot::String),
    // Mid-string keyword hits (WORD_IN_QUOTE) ŌĆö defensive
    // routing only. The ternary at `:158-167` would emit this
    // when a quoted token matched any of keywords 0..3, BUT the
    // word-resolution entry guard at `:150` is
    // `sc.state == SCE_TCL_IDENTIFIER || sc.state == SCE_TCL_MODIFIER`,
    // so the `quote` flag at `:158` is always false at runtime
    // and `SCE_TCL_WORD_IN_QUOTE` is never emitted by upstream
    // LexTCL today. Kept in the table at String so a future
    // Lexilla patch that activates the slot (already implemented
    // in some downstream forks) doesn't render it un-coloured.
    (SCE_TCL_WORD_IN_QUOTE, StyleSlot::String),
    // Operator ŌĆö brackets / braces / `;` / `,` / parens /
    // backslash-escape per `:111, :124, :128, :134, :266, :311,
    // :316, :326, :336, :352`. Note: `$` is NOT here ŌĆö bare `$`
    // triggers SUBSTITUTION at `:331` and `${` triggers SUB_BRACE
    // at `:336-337`; the OPERATOR character class covers the
    // structural punctuation only.
    (SCE_TCL_OPERATOR, StyleSlot::Operator),
    // Variable-substitution pair ŌĆö `$var` (SUBSTITUTION,
    // `:120-136, :334`) and `${var}` body (SUB_BRACE, `:115,
    // :338`). Both ŌåÆ Lifetime per the sigil-tagged-variable
    // archetype; matches Bash SCALAR / PARAM (`:9-10` in
    // scintilla-sys SCE_SH numbering) and NSIS VARIABLE /
    // STRINGVAR (`:6, :13`) precedent.
    (SCE_TCL_SUBSTITUTION, StyleSlot::Lifetime),
    (SCE_TCL_SUB_BRACE, StyleSlot::Lifetime),
    // Command-option modifier `-flag` ŌĆö entered at `:348` via
    // the disambiguator `IsADigit(sc.chNext) ? NUMBER : MODIFIER`
    // so `-1` is a number while `-flag` is a modifier. Routed to
    // Keyword2 (secondary-keyword archetype) ŌĆö option flags
    // appear densely in any TCL command invocation; the steel-
    // blue Keyword2 colour signals "command modifier" without the
    // bold weight a Keyword slot would add. Considered routing
    // to Preprocessor but Preprocessor is conventionally reserved
    // for line-leading directives, and `-flag` is mid-command.
    (SCE_TCL_MODIFIER, StyleSlot::Keyword2),
    // `{keyword}` exact-brace expansion class (EXPAND) ŌĆö fires
    // only when class 4 (`expand`) wordlist matches inside
    // literal `{...}` braces per `:168-170`. Routed to Keyword
    // matching the primary WORD archetype ŌĆö when the brace-
    // context check fires, this is structurally a TCL keyword
    // operating under the `{*}` expansion mechanism.
    (SCE_TCL_EXPAND, StyleSlot::Keyword),
    // Primary built-in command class (TCL Keywords) ŌåÆ Keyword
    // bold blue. Same role as SCE_SH_WORD / SCE_NSIS_FUNCTION.
    (SCE_TCL_WORD, StyleSlot::Keyword),
    // Secondary library / extension classes ŌĆö Tk widget creation
    // (WORD2), iTcl / TclOO (WORD3), Tk management (WORD4), and
    // four user-customisation slots (WORD5..WORD8). All ŌåÆ
    // Keyword2 (steel blue), matching the Lua WORD2..WORD8
    // precedent. WORD5..WORD8 are pre-themed despite empty host
    // install for forward-compat ŌĆö costs four table rows, gains
    // zero-effort activation if a future commit adds custom
    // wordlists. Same pattern as Lua WORD2..WORD8 pre-theming
    // and Python ATTRIBUTE pre-theming.
    (SCE_TCL_WORD2, StyleSlot::Keyword2),
    (SCE_TCL_WORD3, StyleSlot::Keyword2),
    (SCE_TCL_WORD4, StyleSlot::Keyword2),
    (SCE_TCL_WORD5, StyleSlot::Keyword2),
    (SCE_TCL_WORD6, StyleSlot::Keyword2),
    (SCE_TCL_WORD7, StyleSlot::Keyword2),
    (SCE_TCL_WORD8, StyleSlot::Keyword2),
];

// Italic on all four comment families ŌĆö COMMENT (command-position
// `#`) + COMMENTLINE (elsewhere `#`) + COMMENT_BOX (`#-`/`##`
// box) + BLOCK_COMMENT (`#~`). Universal Code++ comment-slot
// convention; matches Lua COMMENT + COMMENTLINE + COMMENTDOC
// triple-italic and NSIS COMMENT + COMMENTBOX double-italic
// precedent. The four-italic count is the richest comment surface
// in the framework; the theme test pins `tcl.italic.len() == 4`
// structurally so a future "let's drop one" regression is loud.
const TCL_ITALIC: &[usize] = &[
    SCE_TCL_COMMENT,
    SCE_TCL_COMMENTLINE,
    SCE_TCL_COMMENT_BOX,
    SCE_TCL_BLOCK_COMMENT,
];

// Bold the primary built-in command class (WORD) and the
// brace-context expansion class (EXPAND) ŌĆö both carry the
// "this is a TCL keyword" structural cue and match the Bash
// SCE_SH_WORD / NSIS SCE_NSIS_FUNCTION bold precedent. WORD2..
// WORD8 deliberately NOT bolded ŌĆö they already carry distinct
// steel-blue Keyword2 colour, and bolding the Tk + iTCL +
// tkCommands + user1..4 bands alongside core TCL keywords would
// create excessive visual weight in Tk-heavy GUI scripts.
// Mirrors Perl SCE_PL_WORD bold while SCE_PL_HASH / SCE_PL_ARRAY
// stay non-bold. MODIFIER (`-flag`) deliberately NOT bolded ŌĆö
// flags appear densely (e.g. `string match -nocase -- $foo`)
// and bolding them would overwhelm the surrounding command.
// SUBSTITUTION / SUB_BRACE deliberately NOT bolded ŌĆö same
// convention as SCE_SH_SCALAR / SCE_SH_PARAM staying non-bold
// despite using Lifetime.
const TCL_BOLD: &[usize] = &[SCE_TCL_WORD, SCE_TCL_EXPAND];

// Classes 0-3 installed. `tclWordListDesc[]` at
// `LexTCL.cxx:361-372` declares NINE classes terminated by `0`:
// `"TCL Keywords"` (class 0 ŌĆö TCL built-in commands), `"TK Keywords"`
// (class 1 ŌĆö Tk widget-creation), `"iTCL Keywords"` (class 2 ŌĆö
// `[incr Tcl]` / TclOO extensions), `"tkCommands"` (class 3 ŌĆö Tk
// geometry / event / introspection), `"expand"` (class 4 ŌĆö special
// brace-context-only class; ships empty in N++ default), and
// `"user1".."user4"` (classes 5-8 ŌĆö user customisation; all four
// ship empty in N++ default).
//
// Code++ matches N++'s `langs.model.xml` default-set by populating
// classes 0-3 only. Classes 4-8 ship empty ŌĆö class 4 because the
// `expand` brace-context check is an opt-in mechanism for TCL
// `{*}` expansion sentinels (rare in default scripts), and classes
// 5-8 because they're explicitly user-extension slots. The four
// populated wordlists maintain disjoint membership across all
// four classes ŌĆö structurally pinned by the
// `tcl_uses_lextcl_nine_class_theme` test's `HashSet` no-overlap
// guard.
//
// Case + property posture. LexTCL is case-sensitive byte-exact
// (no case folding anywhere on the wordlist-match path ŌĆö see the
// scintilla-sys banner for verification). The only runtime
// properties (`fold.comment` / `fold.compact`) affect folding
// only, not token emission; Code++ runs both at the lexer default
// (`LangTheme` has no `properties` slot today). Wordlist contents
// are stored in their canonical lowercase form per the Tcl/Tk
// Reference Manual ŌĆö matching the source spelling a TCL author
// writes byte-for-byte.
const TCL_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, TCL_KEYWORDS),
        (1, TCL_TK_KEYWORDS),
        (2, TCL_ITCL_KEYWORDS),
        (3, TCL_TK_COMMANDS),
    ],
    styles: TCL_STYLES,
    italic: TCL_ITALIC,
    bold: TCL_BOLD,
};

// --- LexLisp (Common Lisp / Scheme) ---
//
// Style-routing rationale (per public state, low index to high):
//   * SCE_LISP_COMMENT (1) ŌåÆ Comment ŌĆö `;`-to-EOL line comment
//     per `LexLisp.cxx:114-117, 208-212`.
//   * SCE_LISP_NUMBER (2) ŌåÆ Number ŌĆö decimal literals via the
//     `classifyWordLisp` digit-only path at `:54-58, :62`, plus
//     radix-prefix literals `#x` / `#o` / `#b` / `#NrDDD` routed
//     through the private MACRO_DISPATCH (31) and MACRO (30)
//     states before emission.
//   * SCE_LISP_KEYWORD (3) ŌåÆ Keyword ŌĆö class-0 wordlist hit per
//     `:64-65`. Primary function / special-operator archetype;
//     matches SCE_C_WORD / SCE_SH_WORD / SCE_TCL_WORD precedent.
//   * SCE_LISP_KEYWORD_KW (4) ŌåÆ Keyword2 ŌĆö class-1 wordlist hit
//     per `:66-67`. `&`-prefixed lambda-list markers; secondary-
//     keyword archetype matches SCE_LUA_WORD2 / SCE_TCL_WORD2.
//   * SCE_LISP_SYMBOL (5) ŌåÆ Lifetime ŌĆö `:kw` keyword-package
//     symbols (entered at `:107-109`) AND `'foo` quoted symbols
//     after the `'` operator (entered at `:121-123, :141-143,
//     :203-205`). Sigil-tagged-value archetype matches Bash
//     SCALAR / PARAM and NSIS VARIABLE / STRINGVAR precedent.
//     The `:kw` reads to the KEYWORD package ŌĆö semantically a
//     name binding, not a syntactic keyword; distinct slot.
//   * SCE_LISP_STRING (6) ŌåÆ String ŌĆö `"..."` per `:125-128,
//     :220-229`.
//   * SCE_LISP_OPERATOR (10) ŌåÆ Operator ŌĆö `(` `)` `[` `]` `{`
//     `}` `'` `` ` `` per `isLispoperator` at `:36-42`; emitted
//     at `:118-124, :138-144, :166, :172, :200-206`. Every
//     emission is a one-byte `ColourTo(i, SCE_LISP_OPERATOR)` ŌĆö
//     `))` produces two separate spans; foreground-only styling
//     recommended.
//   * SCE_LISP_SPECIAL (11) ŌåÆ Keyword ŌĆö overloaded across four
//     unrelated tokens: (a) earmuffed globals `*foo*` / `+bar+`
//     per `classifyWordLisp:68-70`, (b) `#\c` character literals
//     via the internal CHARACTER (29) state at `:158, :187-191`,
//     (c) `#'foo` function-quote reader-macro at `:162-163,
//     :196-199`, (d) radix-prefixed numeric payloads via the
//     MACRO (30) state at `:181`. All four are "this is a Lisp
//     semantic anchor" cues ŌĆö routed to Keyword bold matching
//     the structural-anchor archetype (SCE_TCL_EXPAND precedent).
//   * SCE_LISP_MULTI_COMMENT (12) ŌåÆ Comment ŌĆö `#| ... |#` block
//     comment per `:151, :213-219`. Universal Comment-slot
//     convention; matches Lua's COMMENT + COMMENTLINE +
//     COMMENTDOC triple and NSIS's COMMENT + COMMENTBOX double.
//
// SCE_LISP_DEFAULT (0), SCE_LISP_IDENTIFIER (9), SCE_LISP_STRINGEOL
// (8) intentionally UNMAPPED. DEFAULT + IDENTIFIER follow the
// universal-omission pattern per SCE_C_DEFAULT / SCE_C_IDENTIFIER,
// SCE_LUA_DEFAULT / SCE_LUA_IDENTIFIER, SCE_TCL_DEFAULT /
// SCE_TCL_IDENTIFIER. STRINGEOL joins the deferred-Error-slot
// migration list alongside SCE_SH_ERROR, SCE_LUA_STRINGEOL,
// SCE_L_ERROR ŌĆö and additionally `SCE_LISP_STRINGEOL` is
// permanently unreachable at runtime (see scintilla-sys banner
// note; grep of LexLisp.cxx for the constant returns zero hits).
const LISP_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_LISP_COMMENT, StyleSlot::Comment),
    (SCE_LISP_NUMBER, StyleSlot::Number),
    (SCE_LISP_KEYWORD, StyleSlot::Keyword),
    (SCE_LISP_KEYWORD_KW, StyleSlot::Keyword2),
    (SCE_LISP_SYMBOL, StyleSlot::Lifetime),
    (SCE_LISP_STRING, StyleSlot::String),
    (SCE_LISP_OPERATOR, StyleSlot::Operator),
    (SCE_LISP_SPECIAL, StyleSlot::Keyword),
    (SCE_LISP_MULTI_COMMENT, StyleSlot::Comment),
];

// Italic on both comment families ŌĆö `;`-to-EOL COMMENT +
// `#|...|#` MULTI_COMMENT. Universal Code++ comment-slot
// convention; matches NSIS COMMENT + COMMENTBOX double-italic
// and Lua triple-italic precedent.
const LISP_ITALIC: &[usize] = &[SCE_LISP_COMMENT, SCE_LISP_MULTI_COMMENT];

// Bold the primary keyword class (KEYWORD, class-0 wordlist hit)
// and the structural-anchor state (SPECIAL, earmuffed globals +
// reader-macro emissions). Matches TCL_BOLD's WORD + EXPAND
// two-entry precedent: "primary keyword + one structural anchor".
// KEYWORD_KW deliberately NOT bolded ŌĆö carries distinct Keyword2
// colour; boldening alongside class-0 hits would over-weight the
// lambda-list markers. SYMBOL deliberately NOT bolded ŌĆö sigil-
// tagged archetype carries weight via Lifetime slot, exactly as
// Bash SCALAR / PARAM stay non-bold.
const LISP_BOLD: &[usize] = &[SCE_LISP_KEYWORD, SCE_LISP_SPECIAL];

// Two-class install. `lispWordListDesc[]` at LexLisp.cxx:280-284
// declares exactly two classes:
//   - class 0 "Functions and special operators" ŌåÆ SCE_LISP_KEYWORD
//   - class 1 "Keywords" ŌåÆ SCE_LISP_KEYWORD_KW
// Same shape as Lua's two-populated install. No runtime properties
// consulted (LexLisp has no OptionSet; SCI_SETPROPERTY is a no-op).
// Wordlist contents in canonical lowercase per byte-exact case
// contract.
const LISP_THEME: LangTheme = LangTheme {
    keywords: &[(0, LISP_KEYWORDS), (1, LISP_KEYWORDS_KW)],
    styles: LISP_STYLES,
    italic: LISP_ITALIC,
    bold: LISP_BOLD,
};

// Scheme rides the shared `lisp` Lexilla lexer per LANG_TABLE:815-822
// ŌĆö same lexer as L_LISP, distinct R7RS wordlists. The style /
// italic / bold tables ARE the exact `LISP_*` slices (same
// `&'static` references, not copies) ŌĆö verified by
// `std::ptr::eq(scheme.styles, lisp.styles)` in
// `scheme_reuses_lexlisp_theme_with_r7rs_wordlists`. Only the
// keyword content differs: `SCHEME_KEYWORDS` replaces Common Lisp
// `defun` / `labels` / `rplaca` / `atom` / `null` with R7RS
// `define` / `letrec` / `syntax-rules` / `call/cc`;
// `SCHEME_KEYWORDS_KW` replaces `&`-prefixed lambda-list markers
// with the `?` / `!` predicate/mutator contract vocabulary
// (`null?`, `pair?`, `set-car!`, `vector-fill!`, ŌĆ”).
//
// This is the first "shared Lexilla lexer, distinct wordlists"
// wiring for a two-class lexer ŌĆö precedent from `HYPERTEXT_STYLES`
// across HTML / PHP / ASP / XML (single-class installs). Reusable
// template for future shared-lexer siblings (e.g. JSON5 riding
// `json` once wired): copy the `LangTheme` struct; keep
// styles/italic/bold pointing at the shared `&'static` slice; swap
// only the `keywords: &[ŌĆ”]` pair.
const SCHEME_THEME: LangTheme = LangTheme {
    keywords: &[(0, SCHEME_KEYWORDS), (1, SCHEME_KEYWORDS_KW)],
    styles: LISP_STYLES,
    italic: LISP_ITALIC,
    bold: LISP_BOLD,
};

// --- Assembly (LexAsm) style + theme ----------------------------------
//
// LexAsm has 17 SCE_ASM_* slots (0..=16) ŌĆö see the paint-loop banner in
// `crates/scintilla-sys/src/lib.rs`'s SCE_ASM_* block for the full state
// model. Six of them carry the wordlist-classifier archetypes we want
// distinct colours on:
//
//   * CPUINSTRUCTION (6) ŌĆö the primary keyword archetype; the main
//     visual "this is assembly code" cue ŌåÆ Keyword (bold blue).
//   * MATHINSTRUCTION (7) ŌĆö x87 FPU mnemonics, semantically CPU-adjacent
//     but visually secondary ŌåÆ Keyword2 (steel-blue).
//   * REGISTER (8) ŌĆö the most-tokenised element in typical assembly.
//     Distinct colour matters more here than for any other class
//     because visually scanning `rax` / `xmm7` / `k3` at a glance
//     is the primary way an assembly reader tracks data flow ŌåÆ
//     Lifetime slot (LISP_SYMBOL / Bash SCALAR precedent for "sigil-
//     tagged archetype that wants its own hue").
//   * DIRECTIVE (9) ŌĆö assembler pseudo-ops (`.text`, `%macro`,
//     `proc`, `global`); reads as "out-of-band syntax marker"
//     rather than as code ŌåÆ Preprocessor slot (same slot the C
//     `#include` / `#define` family uses, precedent set by the
//     StyleSlot::Preprocessor doc-comment).
//   * DIRECTIVEOPERAND (10) ŌĆö size / distance / attribute qualifiers
//     (`byte`, `ptr`, `near`, `readonly`); attributes of directives
//     rather than directives themselves ŌåÆ Keyword2 (same slot as
//     MATHINSTRUCTION ŌĆö both are "secondary keyword" archetypes).
//   * EXTINSTRUCTION (14) ŌĆö SSE/AVX/AVX-512/MMX SIMD mnemonics.
//     Visually distinct from scalar instructions so vectorised
//     inner loops pop out; deserves its own hue ŌåÆ Macro slot
//     (same "special-flavor instruction" feel as Rust's
//     `println!`). Precedent: no other language uses Macro for a
//     non-Rust archetype today, but the slot's doc-comment
//     explicitly invites reuse "for similar 'scoped binding'
//     highlights if applicable" ŌĆö SIMD-vs-scalar visual
//     distinction is exactly that.
//
// Plus six straightforward slots (COMMENT, NUMBER, STRING, OPERATOR,
// CHARACTER-as-String, STRINGBACKQUOTE-as-String), an active MASM
// COMMENTDIRECTIVE (15) ŌåÆ Comment mapping ŌĆö reached at
// `LexAsm.cxx:354-356` when the classifier sees the literal
// `"comment"` DIRECTIVE token ŌĆö plus one currently-unused state
// mapped defensively for future paint paths (COMMENTBLOCK (11) ŌåÆ
// Comment; per the `LexAsm.cxx:6` header note this state is
// reserved for future GNU-as colouring and the lexer never enters
// it today), and three deliberately unmapped states (DEFAULT,
// IDENTIFIER, STRINGEOL ŌĆö the transient / error states ŌĆö same
// convention as LISP_STYLES's LISP_IDENTIFIER + LISP_STRINGEOL
// skip and every other LangTheme's DEFAULT skip). Count check:
// 6 archetypes + 6 straightforward + 1 active + 1 defensive = 14,
// matching `ASM_STYLES.len()` asserted by
// `asm_uses_lexasm_six_class_theme`.
const ASM_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_ASM_COMMENT, StyleSlot::Comment),
    (SCE_ASM_NUMBER, StyleSlot::Number),
    (SCE_ASM_STRING, StyleSlot::String),
    (SCE_ASM_OPERATOR, StyleSlot::Operator),
    (SCE_ASM_CPUINSTRUCTION, StyleSlot::Keyword),
    (SCE_ASM_MATHINSTRUCTION, StyleSlot::Keyword2),
    (SCE_ASM_REGISTER, StyleSlot::Lifetime),
    (SCE_ASM_DIRECTIVE, StyleSlot::Preprocessor),
    (SCE_ASM_DIRECTIVEOPERAND, StyleSlot::Keyword2),
    (SCE_ASM_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_ASM_CHARACTER, StyleSlot::String),
    (SCE_ASM_EXTINSTRUCTION, StyleSlot::Macro),
    (SCE_ASM_COMMENTDIRECTIVE, StyleSlot::Comment),
    (SCE_ASM_STRINGBACKQUOTE, StyleSlot::String),
];

// Italic on the full comment family: line COMMENT (1), unused-but-
// forward-mapped COMMENTBLOCK (11), and MASM's COMMENT-directive
// block state (15). Universal Code++ comment-slot convention;
// matches Lisp COMMENT + MULTI_COMMENT and NSIS COMMENT + COMMENTBOX
// double-italic precedent.
const ASM_ITALIC: &[usize] = &[
    SCE_ASM_COMMENT,
    SCE_ASM_COMMENTBLOCK,
    SCE_ASM_COMMENTDIRECTIVE,
];

// Bold the primary CPU-instruction archetype. The visual weight of
// the CPU class is the main "this line does work" cue. FPU (7) /
// EXT (14) intentionally NOT bolded: they carry distinct hues
// (Keyword2 / Macro) that already differentiate them from CPU
// without over-weighting the strip when vectorised code dominates
// the buffer. DIRECTIVE (9) NOT bolded either ŌĆö Preprocessor slot
// carries its own weight, and assembler pseudo-ops are usually
// line-leading so already visually anchored. Precedent: LISP_BOLD
// bolds only KEYWORD + SPECIAL (the primary class + one structural
// anchor); TCL_BOLD bolds WORD + EXPAND (same pattern). Assembly's
// primary anchor is line-leading DIRECTIVE, but boldening it
// would collide with the Preprocessor slot's semantic weight, so
// this row sticks to the single-entry pattern (Rust's RUST_BOLD =
// WORD only, precedent for one-entry primary-class-bold).
const ASM_BOLD: &[usize] = &[SCE_ASM_CPUINSTRUCTION];

// Six-class install. `asmWordListDesc[]` at LexAsm.cxx:80-90 declares
// eight classes; the first six carry instruction / register /
// directive vocabulary and get populated below. Classes 6/7
// (`Directives4Foldstart` / `Directives4Foldend`) are consulted only
// by the folder at `:490-500` and left empty here ŌĆö populating them
// with matched directive pairs (e.g. `proc`/`endp`, `%macro`/`%endmacro`)
// is a future enhancement that adds directive-pair folding without
// disturbing the classifier.
//
// **First-match-wins ordering matters at the LEXER, not here.** The
// classifier chains through classes 0ŌåÆ5 at `:335-347`; a mnemonic
// listed in both CPU (0) and EXT (5) paints from CPU. The wordlists
// in `core::lang` verify no cross-class duplicates via
// `asm_uses_lexasm_six_class_theme` (its `HashSet` intersection
// guard walking `asm.keywords`), same shape as the LISP two-class
// guard.
const ASM_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, ASM_CPU_KEYWORDS),
        (1, ASM_FPU_KEYWORDS),
        (2, ASM_REG_KEYWORDS),
        (3, ASM_DIRECTIVE_KEYWORDS),
        (4, ASM_DIRECTIVE_OP_KEYWORDS),
        (5, ASM_EXT_KEYWORDS),
    ],
    styles: ASM_STYLES,
    italic: ASM_ITALIC,
    bold: ASM_BOLD,
};

// --- LexDiff ---
//
// Line-shape classifier ŌĆö no tokeniser, no wordlists
// (`emptyWordListDesc[]` at LexDiff.cxx:149-151). Each
// SCE_DIFF_* index below corresponds to one line archetype
// the classifier at `:38-101` emits based on the leading
// characters of the line.
//
// **Slot mapping rationale (12 classes ŌåÆ 6 palette slots).**
// Diff's semantic contract is that added lines read GREEN
// and removed lines read RED. Code++'s palette already
// carries both ŌĆö `FG_COMMENT` (green) and `FG_STRING`
// (brick red) ŌĆö so the row reuses each for its COLOUR value
// while suppressing the italic modifier on the added /
// removed archetypes (italic is per-index, not per-slot;
// see `DIFF_ITALIC` below):
//   - COMMENT (1)              ŌåÆ Comment (green italic).
//                                Preamble prose ("Only in
//                                ...").
//   - COMMAND (2)              ŌåÆ Keyword (blue bold). Reads
//                                as the top-of-diff command
//                                anchor (`diff ...` /
//                                `Index: ...`).
//   - HEADER (3)               ŌåÆ Preprocessor (purple). Slot
//                                doc says "out-of-band syntax
//                                marker"; file boundaries fit.
//   - POSITION (4)             ŌåÆ Number (magenta). Hunk /
//                                position markers are
//                                dominated by numeric line
//                                ranges (`@@ -12,7 +34,8 @@`);
//                                Number is the natural match.
//   - DELETED (5)              ŌåÆ String (brick red). Removed
//                                content ŌĆö the palette entry's
//                                colour value carries the
//                                semantics, its slot name is
//                                immaterial here.
//   - ADDED (6)                ŌåÆ Comment (green, NOT italic).
//                                Reuses the green colour but
//                                is excluded from
//                                `DIFF_ITALIC` so added lines
//                                stay upright.
//   - CHANGED (7)              ŌåÆ Lifetime (amber). Context-
//                                diff `!` lines ŌĆö a third
//                                distinct colour that avoids
//                                both green and red.
//   - PATCH_ADD (8)            ŌåÆ Comment (green, not italic).
//                                Combined `++` ŌĆö both parents
//                                added; unambiguous net-add.
//   - PATCH_DELETE (9)         ŌåÆ String (red). Combined `+-`.
//   - REMOVED_PATCH_ADD (10)   ŌåÆ String (red). Combined `-+`.
//   - REMOVED_PATCH_DELETE (11)ŌåÆ String (red). Combined `--`
//                                ŌĆö both parents removed;
//                                unambiguous net-delete.
//                                (For `+-` and `-+`, git's
//                                combined-diff markers encode
//                                per-parent add/remove state
//                                and don't reduce to a single
//                                "net" outcome; grouping them
//                                with delete is an author
//                                choice for visual simplicity,
//                                keeping the red/green palette
//                                to two colours rather than
//                                introducing a fifth semantic
//                                slot for merge-conflict
//                                variants.)
//
// DEFAULT (0) intentionally NOT mapped ŌĆö context lines keep
// `STYLE_DEFAULT` (black on white) so they don't compete with
// the added / removed / changed lines the reviewer is
// scanning for. Same convention every other `LangTheme` uses
// for its `*_DEFAULT` archetype.
const DIFF_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_DIFF_COMMENT, StyleSlot::Comment),
    (SCE_DIFF_COMMAND, StyleSlot::Keyword),
    (SCE_DIFF_HEADER, StyleSlot::Preprocessor),
    (SCE_DIFF_POSITION, StyleSlot::Number),
    (SCE_DIFF_DELETED, StyleSlot::String),
    (SCE_DIFF_ADDED, StyleSlot::Comment),
    (SCE_DIFF_CHANGED, StyleSlot::Lifetime),
    (SCE_DIFF_PATCH_ADD, StyleSlot::Comment),
    (SCE_DIFF_PATCH_DELETE, StyleSlot::String),
    (SCE_DIFF_REMOVED_PATCH_ADD, StyleSlot::String),
    (SCE_DIFF_REMOVED_PATCH_DELETE, StyleSlot::String),
];

// Italic only on the preamble prose class. Added / removed
// / changed content stays upright ŌĆö the reviewer is meant to
// scan those fast, and italicising blocks of source code
// would work against that goal. Same convention as CPP's
// `SCE_C_COMMENTDOC` skip (doc-strings NOT italicised).
const DIFF_ITALIC: &[usize] = &[SCE_DIFF_COMMENT];

// Bold only the top-of-diff `diff ` / `Index: ` command
// anchor ŌĆö same one-entry pattern as `RUST_BOLD` /
// `ASM_BOLD` (primary class only). HEADER / POSITION /
// DELETED / ADDED / etc. rely on colour for
// differentiation, no boldness needed.
const DIFF_BOLD: &[usize] = &[SCE_DIFF_COMMAND];

const DIFF_THEME: LangTheme = LangTheme {
    keywords: &[],
    styles: DIFF_STYLES,
    italic: DIFF_ITALIC,
    bold: DIFF_BOLD,
};

// --- LexPS (PostScript) ---
//
// PostScript is a stack-based page-description language with
// a small operator vocabulary (~250 Level 1 ops, ~80 Level 2
// additions, ~30 Level 3 additions) and a token grammar
// dominated by self-delimiting punctuation (`[` `]` `{` `}`
// `/` `<` `>` `(` `)` `%`). The classifier at
// `LexPS.cxx:67-270` runs a per-character state machine
// over `SCE_C_DEFAULT` neutral state, entering typed states
// (NUMBER, NAME, LITERAL, TEXT, HEXSTRING, ŌĆ”) on the
// leading character and terminating on the next
// self-delimiting / whitespace char.
//
// **13-mapping style table.** 16 `SCE_PS_*` slots minus
// three deliberate omissions:
//   - `SCE_PS_DEFAULT` (0)       ŌĆö neutral state; keeps
//                                  `STYLE_DEFAULT` (universal
//                                  convention).
//   - `SCE_PS_NAME` (5)          ŌĆö bare identifier that
//                                  didn't match any wordlist;
//                                  stays default-coloured. If
//                                  the lexer's `:156-159`
//                                  wordlist chain matches,
//                                  `ChangeState` at `:160`
//                                  promotes to `KEYWORD` and
//                                  the keyword slot's colour
//                                  takes over ŌĆö so leaving
//                                  `NAME` unmapped means
//                                  "unknown symbol renders in
//                                  the buffer's default text
//                                  colour", the standard
//                                  Code++ convention for
//                                  user-defined identifiers.
//   - `SCE_PS_BADSTRINGCHAR` (15)ŌĆö error marker. Applied
//                                  inline via
//                                  `styler.ColourTo` at
//                                  `:184, :192, :225` for a
//                                  non-hex / non-base85 char
//                                  inside a `<ŌĆ”>` or `<~ŌĆ”~>`
//                                  string. Leaving it
//                                  unmapped means bad
//                                  characters render
//                                  default-coloured (same
//                                  precedent as `SCE_ASM_STRINGEOL`
//                                  and `SCE_LISP_STRINGEOL`).
//
// **Slot mapping rationale.**
//   - `COMMENT` (1)         ŌåÆ Comment (green italic). `%...`
//                             line comments.
//   - `DSC_COMMENT` (2)     ŌåÆ Preprocessor (purple, italic).
//                             `%%directive` DSC lines are
//                             structural file metadata, not
//                             executable code ŌĆö Preprocessor
//                             slot's "out-of-band syntax
//                             marker" semantic is the
//                             natural match (same slot the
//                             CPP theme picks for `#define`
//                             / `#include`).
//   - `DSC_VALUE` (3)       ŌåÆ String. The value part of a
//                             DSC directive (e.g.
//                             `%%Title: My Document`) is
//                             textual data, not code.
//   - `NUMBER` (4)          ŌåÆ Number (magenta).
//   - `KEYWORD` (6)         ŌåÆ Keyword (bold blue). Primary
//                             operator archetype.
//   - `LITERAL` (7)         ŌåÆ Keyword2 (steel blue). `/name`
//                             literal-name literal ŌĆö a name
//                             pushed onto the stack as a
//                             symbol without execution;
//                             semantically a symbol
//                             reference, closest match to
//                             the `Keyword2` "secondary
//                             keyword / identifier" slot.
//   - `IMMEVAL` (8)         ŌåÆ Macro (violet). `//name`
//                             immediately-evaluated name is
//                             a distinct Level-2 concept
//                             (evaluates at scan time, not
//                             execution time) ŌĆö the `Macro`
//                             slot's "special-flavour
//                             instruction" semantic
//                             differentiates it visually
//                             from plain `LITERAL`.
//   - `PAREN_ARRAY` (9)     ŌåÆ Operator (dark grey). `[` /
//                             `]` array delimiter.
//   - `PAREN_DICT` (10)     ŌåÆ Operator (dark grey). `<<` /
//                             `>>` dict delimiter.
//   - `PAREN_PROC` (11)     ŌåÆ Operator (dark grey). `{` /
//                             `}` procedure delimiter.
//                             (All three PAREN_* stylings
//                             consistently Operator; the
//                             underlying `[` `{` `<<`
//                             constructs remain
//                             differentiable by shape at a
//                             glance ŌĆö colour doesn't need
//                             to over-differentiate.)
//   - `TEXT` (12)           ŌåÆ String (brick red). `(...)`
//                             string literal.
//   - `HEXSTRING` (13)      ŌåÆ String. `<...>` hex-encoded
//                             string.
//   - `BASE85STRING` (14)   ŌåÆ String. `<~...~>` base-85
//                             encoded string.
const PS_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_PS_COMMENT, StyleSlot::Comment),
    (SCE_PS_DSC_COMMENT, StyleSlot::Preprocessor),
    (SCE_PS_DSC_VALUE, StyleSlot::String),
    (SCE_PS_NUMBER, StyleSlot::Number),
    (SCE_PS_KEYWORD, StyleSlot::Keyword),
    (SCE_PS_LITERAL, StyleSlot::Keyword2),
    (SCE_PS_IMMEVAL, StyleSlot::Macro),
    (SCE_PS_PAREN_ARRAY, StyleSlot::Operator),
    (SCE_PS_PAREN_DICT, StyleSlot::Operator),
    (SCE_PS_PAREN_PROC, StyleSlot::Operator),
    (SCE_PS_TEXT, StyleSlot::String),
    (SCE_PS_HEXSTRING, StyleSlot::String),
    (SCE_PS_BASE85STRING, StyleSlot::String),
];

// Italic on the full comment family: line `COMMENT` (1) and
// the DSC directive prefix `DSC_COMMENT` (2). `DSC_VALUE` (3)
// stays upright ŌĆö it's the actual textual payload of a DSC
// directive (title text, filenames, bounding-box coords),
// visually part of the string family. Universal Code++
// convention: italic tags "human prose" classes, not "data
// payload" classes.
const PS_ITALIC: &[usize] = &[SCE_PS_COMMENT, SCE_PS_DSC_COMMENT];

// Bold on the primary keyword class. Same single-entry
// pattern as `RUST_BOLD` / `ASM_BOLD` / `DIFF_BOLD` ŌĆö the
// primary operator archetype gets the visual weight; other
// classes rely on colour for differentiation.
const PS_BOLD: &[usize] = &[SCE_PS_KEYWORD];

// **Three-class install.** `psWordListDesc[]` at
// `LexPS.cxx:327-334` declares FIVE classes (Level 1 / Level
// 2 / Level 3 operators + RIP + user-defined); classes 0..=2
// are populated here, classes 3 (RIP-specific) and 4
// (user-defined) are omitted from the install. The classifier
// at `:156-159` queries all five with `InList`, but
// `WordList::InList` on a default-constructed empty wordlist
// returns `false` ŌĆö so skipping the install for the two
// parked classes is safe and gets the same result as
// installing empty strings. Downstream users who want to
// bolt on printer-driver-specific (`RIP`) or
// site-specific-macro (`user`) operators can extend the
// install without disturbing the level-tier vocabulary.
// Precedent: `ASM_THEME` skips its two fold-only classes
// (6/7) for the same reason.
const PS_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, PS_LEVEL1_KEYWORDS),
        (1, PS_LEVEL2_KEYWORDS),
        (2, PS_LEVEL3_KEYWORDS),
    ],
    styles: PS_STYLES,
    italic: PS_ITALIC,
    bold: PS_BOLD,
};

// --- LexRuby ---
//
// Ruby is a dynamically-typed OOP language with rich literal
// syntax (16 distinct string archetypes, sigil-tagged
// variables, symbols, regexes, heredocs). LexRuby is the
// largest single-file lexer in Lexilla (2191 lines) ŌĆö its
// classifier state machine at `LexRuby.cxx:1043-1770`
// distinguishes context-sensitive uses of `if` / `do` /
// `while` (statement leader vs trailing modifier) and infers
// the type of an identifier from its sigil prefix (`$` global,
// `@` instance, `@@` class, `:` symbol) and its position
// (post-`class` ŌåÆ `CLASSNAME`, post-`def` ŌåÆ `DEFNAME`,
// post-`module` ŌåÆ `MODULE_NAME`).
//
// **34-mapping style table.** Emissible-slot arithmetic:
// 32 slots at indices 0..=31 + 5 slots at indices 40..=44 =
// 37 emissible slots (indices 32..=39 are a sub-style
// reservation range for `SCE_RB_IDENTIFIER` per
// `LexRuby.cxx:156, :211` and are never emitted directly).
// Subtract the 3 deliberate omissions below: 37 ŌłÆ 3 = 34.
//
// Deliberate omissions:
//   - `DEFAULT` (0)          ŌĆö neutral state, keeps
//                              `STYLE_DEFAULT`.
//   - `ERROR` (1)            ŌĆö unterminated / malformed
//                              token. Left unmapped so the
//                              buffer's default text colour
//                              flags the bad token to the
//                              user's eye without an
//                              opinionated "error red" the
//                              palette doesn't carry.
//   - `IDENTIFIER` (11)      ŌĆö bare identifier that didn't
//                              match the keyword wordlist
//                              and isn't sigil-prefixed ŌĆö
//                              plain user names / variables.
//                              Universal Code++ convention
//                              (same as C's plain
//                              identifier: no dedicated
//                              colour, just default text).
//   - `UPPER_BOUND` (45)     ŌĆö pseudo-style
//                              (`SCE_RB_IDENTIFIER_PREFERRE`
//                              per `LexRuby.cxx:333`) never
//                              emitted to the host. No mapping.
//
// **Slot mapping rationale ŌĆö leveraging the sigil/context
// distinctions LexRuby exposes:**
//
//   Comment family (green italic):
//     `COMMENTLINE` (2)      ŌĆö `#` line comment.
//     `POD` (3)              ŌĆö `=begin`/`=end` block.
//     `DATASECTION` (19)     ŌĆö post-`__END__` data payload;
//                              semantically "commentary" once
//                              the interpreter treats it as
//                              text-only via the `DATA` file
//                              object. Coloured Comment but
//                              deliberately NOT italicised
//                              (see `RB_ITALIC` ŌĆö italicising
//                              a potentially long block of
//                              inline data would visually
//                              dominate).
//
//   Keyword family (blue):
//     `WORD` (5)             ŌĆö primary keyword (`if`, `def`,
//                              `class`, ŌĆ”). BOLD.
//     `WORD_DEMOTED` (29)    ŌĆö same keyword used as a
//                              trailing modifier
//                              (`stmt if cond`). Same
//                              Keyword slot for a matched
//                              colour but NOT bold ŌĆö the
//                              visual weight change flags
//                              the modifier role to the
//                              reader while keeping the
//                              language-level identity of
//                              the token clear.
//
//   Definition names (steel-blue `Keyword2`):
//     `CLASSNAME` (8)        ŌĆö the identifier after `class`.
//     `DEFNAME` (9)          ŌĆö the identifier after `def`.
//     `MODULE_NAME` (15)     ŌĆö the identifier after `module`.
//                              (All three are the same
//                              semantic category: "the
//                              thing being defined".)
//
//   String family (brick red):
//     Direct literals ŌĆö `STRING` (6, `"..."`), `CHARACTER`
//     (7, `'...'` ŌĆö LexRuby's legacy name; Ruby has no
//     C-style char literal), `BACKTICKS` (18,
//     `` `cmd` ``), `REGEX` (12, `/regex/`).
//     Percent-literal generic-brace family ŌĆö `STRING_Q`
//     (24, `%q()`), `STRING_QQ` (25, `%Q()`),
//     `STRING_QX` (26, `%x()`), `STRING_QR` (27, `%r()`),
//     `STRING_QW` (28, `%W()` interp string array),
//     `STRING_W` (41, `%w()` non-interp), `STRING_I` (42,
//     `%i()` non-interp symbol array), `STRING_QI` (43,
//     `%I()` interp symbol array).
//     Heredoc family ŌĆö `HERE_DELIM` (20, the `<<HEREDOC`
//     word itself), `HERE_Q` / `HERE_QQ` / `HERE_QX` (21,
//     22, 23 ŌĆö body variants by quoting).
//
//   Sigil-tagged bindings (amber `Lifetime`):
//     `INSTANCE_VAR` (16, `@foo`) and `CLASS_VAR` (17,
//     `@@foo`) ŌĆö Ruby's per-object / per-class scoped
//     bindings. The `Lifetime` slot's doc-comment says
//     "reuse for similar 'scoped binding' highlights if
//     applicable" ŌĆö `@` and `@@` sigils are exactly that.
//
//   Globals (violet `Macro`):
//     `GLOBAL` (13, `$foo`, `$0`..`$9`, `$_`, `$~`, `$&`,
//     `$'`, `` $` ``) ŌĆö Ruby's `$`-prefixed globals and
//     magic special-variable set. Distinct slot from
//     instance/class vars so the reader sees at a glance
//     which scope a sigil refers to. **Divergence from Perl
//     (see `PERL_STYLES` above).** Perl routes all sigil
//     variables (`$` / `@` / `%` / `*`) uniformly to
//     `Lifetime`, treating sigil-tagging as one visual
//     class. Ruby splits `$` (global scope, `Macro`) from
//     `@` / `@@` (per-object / per-class scope, `Lifetime`)
//     because Ruby users regularly need to spot the scope
//     of a variable at a glance ŌĆö global mutation vs
//     instance mutation is a semantically meaningful
//     distinction that the palette can afford to show. Perl
//     users typically care less about the sigil's specific
//     scope (in Perl a `$` sigil can name a scalar, a hash
//     element, or a scalar-context array access; the sigil
//     is more about context than scope), so the uniform
//     treatment fits Perl better.
//
//   Symbols and standard-stream constants (purple
//   `Preprocessor` ŌĆö the "out-of-band syntax marker" slot):
//     `SYMBOL` (14, `:foo`) and `STRING_QS` (44, `%s()`
//     bare-symbol generic-brace) ŌĆö Ruby symbols are
//     immutable name references, a distinct namespace
//     from strings.
//     `STDIN` (30), `STDOUT` (31), `STDERR` (40) ŌĆö
//     built-in file objects. LexRuby directly emits these
//     as dedicated styles rather than letting them fall
//     through to `IDENTIFIER`; the theme honours that by
//     colouring them distinctly.
//
//   Numbers (magenta `Number`):
//     `NUMBER` (4) ŌĆö all numeric-literal forms.
//
//   Operator (dark grey):
//     `OPERATOR` (10) ŌĆö punctuation.
const RB_STYLES: &[(usize, StyleSlot)] = &[
    // Comment family
    (SCE_RB_COMMENTLINE, StyleSlot::Comment),
    (SCE_RB_POD, StyleSlot::Comment),
    (SCE_RB_DATASECTION, StyleSlot::Comment),
    // Numeric
    (SCE_RB_NUMBER, StyleSlot::Number),
    // Keywords (primary + demoted-modifier)
    (SCE_RB_WORD, StyleSlot::Keyword),
    (SCE_RB_WORD_DEMOTED, StyleSlot::Keyword),
    // Definition names
    (SCE_RB_CLASSNAME, StyleSlot::Keyword2),
    (SCE_RB_DEFNAME, StyleSlot::Keyword2),
    (SCE_RB_MODULE_NAME, StyleSlot::Keyword2),
    // Operator
    (SCE_RB_OPERATOR, StyleSlot::Operator),
    // String family (direct literals)
    (SCE_RB_STRING, StyleSlot::String),
    (SCE_RB_CHARACTER, StyleSlot::String),
    (SCE_RB_BACKTICKS, StyleSlot::String),
    (SCE_RB_REGEX, StyleSlot::String),
    // Percent-literal generic-brace family
    (SCE_RB_STRING_Q, StyleSlot::String),
    (SCE_RB_STRING_QQ, StyleSlot::String),
    (SCE_RB_STRING_QX, StyleSlot::String),
    (SCE_RB_STRING_QR, StyleSlot::String),
    (SCE_RB_STRING_QW, StyleSlot::String),
    (SCE_RB_STRING_W, StyleSlot::String),
    (SCE_RB_STRING_I, StyleSlot::String),
    (SCE_RB_STRING_QI, StyleSlot::String),
    // Heredoc family
    (SCE_RB_HERE_DELIM, StyleSlot::String),
    (SCE_RB_HERE_Q, StyleSlot::String),
    (SCE_RB_HERE_QQ, StyleSlot::String),
    (SCE_RB_HERE_QX, StyleSlot::String),
    // Sigil-tagged scoped bindings
    (SCE_RB_INSTANCE_VAR, StyleSlot::Lifetime),
    (SCE_RB_CLASS_VAR, StyleSlot::Lifetime),
    // Globals
    (SCE_RB_GLOBAL, StyleSlot::Macro),
    // Symbols + standard streams
    (SCE_RB_SYMBOL, StyleSlot::Preprocessor),
    (SCE_RB_STRING_QS, StyleSlot::Preprocessor),
    (SCE_RB_STDIN, StyleSlot::Preprocessor),
    (SCE_RB_STDOUT, StyleSlot::Preprocessor),
    (SCE_RB_STDERR, StyleSlot::Preprocessor),
];

// Italic on the human-prose comment classes only:
// `COMMENTLINE` and `POD`. `DATASECTION` shares the Comment
// slot's colour but is NOT italicised ŌĆö post-`__END__`
// content is often a large embedded data block (e.g. a YAML
// payload accessed via `DATA.read`), and italicising a long
// block hurts readability more than helps.
const RB_ITALIC: &[usize] = &[SCE_RB_COMMENTLINE, SCE_RB_POD];

// Bold only the primary keyword class. `WORD_DEMOTED` (the
// trailing-modifier usage of an ambiguous keyword) shares the
// blue Keyword colour but stays non-bold ŌĆö the visual weight
// change flags the modifier role at a glance while keeping
// the keyword's identity clear. Single-primary-class-bold
// precedent: `RUST_BOLD` / `ASM_BOLD` / `DIFF_BOLD` /
// `PS_BOLD`.
const RB_BOLD: &[usize] = &[SCE_RB_WORD];

// One-class install (matches LexRuby's single-class
// `rubyWordListDesc[]` at `LexRuby.cxx:142-145`).
const RB_THEME: LangTheme = LangTheme {
    keywords: &[(0, RUBY_KEYWORDS)],
    styles: RB_STYLES,
    italic: RB_ITALIC,
    bold: RB_BOLD,
};

// --- LexSmalltalk ---
//
// Smalltalk is a pure-OO message-send language where syntax
// is famously "everything is a message." The classifier at
// `LexSmalltalk.cxx:272-322` is a compact character-class
// dispatcher (330 lines total) with 17 style classes. Five
// language constants (`self` / `super` / `nil` / `true` /
// `false`) are hardcoded at `:257-266` with dedicated
// `SCE_ST_SELF` / `SUPER` / `NIL` / `BOOL` styles, so the
// theme paints them distinctly from wordlist-matched
// selectors.
//
// **16-mapping style table.** 17 slots (0..=16) minus one
// deliberate omission:
//   - `DEFAULT` (0)         ŌĆö whitespace and unclassified
//                             tokens (temp-var names between
//                             `|` bars, method parameters
//                             like `aString`). Keeps
//                             `STYLE_DEFAULT` ŌĆö the universal
//                             convention.
//
// **Slot mapping rationale ŌĆö leveraging LexSmalltalk's
// deliberate keyword split into 6 semantic slots:**
//
//   Comment (green italic):
//     `COMMENT` (3)         ŌĆö `"..."` block comment.
//                             Smalltalk uses double-quote
//                             for comments and single-quote
//                             for strings (opposite of every
//                             other C-family convention).
//
//   Language constants (blue bold):
//     `SELF` (7)            ŌĆö `self`.
//     `SUPER` (8)           ŌĆö `super`.
//     `NIL` (9)             ŌĆö `nil`.
//     `BOOL` (6)            ŌĆö `true` / `false`.
//     `RETURN` (11)         ŌĆö `^` return operator.
//     `SPEC_SEL` (16)       ŌĆö Wordlist-matched control-flow
//                             selectors (`ifTrue:`,
//                             `whileTrue:`, `and:`, ŌĆ”). All
//                             six route to `StyleSlot::Keyword`
//                             and appear in `ST_BOLD` ŌĆö these
//                             are Smalltalk's language
//                             keywords and control-flow
//                             primitives, deserving the
//                             strongest visual emphasis.
//
//   Class/global + keyword-send (steel blue Keyword2):
//     `GLOBAL` (10)         ŌĆö UpperCase-first identifier ŌĆö
//                             Smalltalk convention for class
//                             names + globals (`Object`,
//                             `Array`, `String`,
//                             `Transcript`). Emitted
//                             directly by the classifier at
//                             `:254-255` based on
//                             `isUpper(first-char)`.
//     `KWSEND` (13)         ŌĆö Keyword-send message part
//                             ending in `:` that did NOT
//                             match the special-selector
//                             wordlist (`at:`, `put:`, `do:`,
//                             `collect:`, `printOn:`). These
//                             are ordinary message sends ŌĆö
//                             steel blue keeps them visually
//                             prominent (they carry semantic
//                             meaning) without over-bolding.
//
//   String / character (brick red):
//     `STRING` (1)          ŌĆö `'...'` string.
//     `CHARACTER` (15)      ŌĆö `$c` character literal.
//
//   Number (magenta):
//     `NUMBER` (2)          ŌĆö integer / radix / decimal /
//                             scientific / scaled-decimal.
//
//   Symbol (purple Preprocessor):
//     `SYMBOL` (4)          ŌĆö `#foo` symbol literal, `#'x'`
//                             quoted symbol, `#at:put:`
//                             compound-keyword symbol.
//                             Symbols in Smalltalk are
//                             immutable name references ŌĆö
//                             `StyleSlot::Preprocessor`'s
//                             "distinct namespace" semantic
//                             fits (same slot Ruby uses for
//                             its `:foo` symbols).
//
//   Operator (dark grey):
//     `BINARY` (5)          ŌĆö Binary-selector message name
//                             (`+`, `-`, `*`, `<=`, `->`,
//                             etc. ŌĆö from the
//                             `isBinSel` set at
//                             `LexSmalltalk.cxx:86`).
//     `SPECIAL` (12)        ŌĆö Punctuation `()`, `[]`, `{}`,
//                             `;`, `.`, `:` ŌĆö from the
//                             `isSpecial` set at `:44`.
//     `ASSIGN` (14)         ŌĆö `:=` assignment operator.
const ST_STYLES: &[(usize, StyleSlot)] = &[
    // Comment (block)
    (SCE_ST_COMMENT, StyleSlot::Comment),
    // Language constants + control flow (all Keyword, all bold)
    (SCE_ST_SELF, StyleSlot::Keyword),
    (SCE_ST_SUPER, StyleSlot::Keyword),
    (SCE_ST_NIL, StyleSlot::Keyword),
    (SCE_ST_BOOL, StyleSlot::Keyword),
    (SCE_ST_RETURN, StyleSlot::Keyword),
    (SCE_ST_SPEC_SEL, StyleSlot::Keyword),
    // Class/global + keyword-send (both Keyword2)
    (SCE_ST_GLOBAL, StyleSlot::Keyword2),
    (SCE_ST_KWSEND, StyleSlot::Keyword2),
    // String family
    (SCE_ST_STRING, StyleSlot::String),
    (SCE_ST_CHARACTER, StyleSlot::String),
    // Numeric
    (SCE_ST_NUMBER, StyleSlot::Number),
    // Symbols (Preprocessor ŌĆö matches Ruby's `:foo` slot)
    (SCE_ST_SYMBOL, StyleSlot::Preprocessor),
    // Operator family
    (SCE_ST_BINARY, StyleSlot::Operator),
    (SCE_ST_SPECIAL, StyleSlot::Operator),
    (SCE_ST_ASSIGN, StyleSlot::Operator),
];

// Italic only on the block comment. Same universal
// convention: italicise prose-family classes only. Smalltalk
// has no doc-comment convention, no POD/JSDoc block, so
// `COMMENT` is the only italic member.
const ST_ITALIC: &[usize] = &[SCE_ST_COMMENT];

// Bold on ALL six language-keyword classes: the four
// hardcoded constants (`SELF` / `SUPER` / `NIL` / `BOOL`),
// the `RETURN` operator `^`, and the wordlist-matched
// control-flow special-selector class. **Divergence from
// the single-entry `RUST_BOLD` / `ASM_BOLD` / `DIFF_BOLD`
// / `PS_BOLD` / `RB_BOLD` precedent** ŌĆö Smalltalk's
// classifier deliberately splits its keyword archetype
// across 6 dedicated SCE indices (unlike LexRuby / LexRust /
// LexAsm which use one `SCE_*_WORD` and rely on wordlists
// or state machines to differentiate). To preserve the
// "one visual weight for language keywords" contract that
// the rest of the framework's themes uphold, all 6 dedicated
// Smalltalk keyword slots must be bolded together ŌĆö bolding
// only one would leave `nil` bold but `true` non-bold (or
// vice versa), which is visually incoherent.
const ST_BOLD: &[usize] = &[
    SCE_ST_SELF,
    SCE_ST_SUPER,
    SCE_ST_NIL,
    SCE_ST_BOOL,
    SCE_ST_RETURN,
    SCE_ST_SPEC_SEL,
];

// One-class install (matches LexSmalltalk's single-class
// `smalltalkWordListDesc[]` at `LexSmalltalk.cxx:325-328`).
const ST_THEME: LangTheme = LangTheme {
    keywords: &[(0, SMALLTALK_SPECIAL_SELECTORS)],
    styles: ST_STYLES,
    italic: ST_ITALIC,
    bold: ST_BOLD,
};

// VHDL theme ŌĆö 14 mappings across 16 SCE_VHDL_* slots.
// SCE_VHDL_DEFAULT (0) is left unmapped (paints with the
// default palette, same as every other lexer's `DEFAULT`).
// SCE_VHDL_IDENTIFIER (6) is also unmapped ŌĆö it's an
// intermediate scan-in-progress state per the citation banner
// in `scintilla-sys/src/lib.rs` and never appears at paint
// time in a well-formed source (any identifier that survives
// the classifier's IDENTIFIER-exit branch at
// `LexVHDL.cxx:90-107` without matching one of the 7 wordlist
// classes still paints as IDENTIFIER, so mapping it to
// `StyleSlot::Comment` or similar would over-paint the "user
// wrote something the lexer doesn't recognise" case ŌĆö an
// unstyled default is the right visual for that). SCE_VHDL_USERWORD
// (14) IS mapped to `Keyword2` even though `VHDL_USERWORDS`
// ships empty ŌĆö this reserves the visual slot for when a
// per-project override populates class 6.
//
// **Cross-family palette choices:**
//   - KEYWORD (reserved words) ŌåÆ `Keyword` ŌĆö matches
//     RUST/RB/ST convention.
//   - STDOPERATOR (word-form operators) ŌåÆ `Keyword` ŌĆö same
//     bold-blue as KEYWORD because `and`/`or`/`not`/`xor` read
//     as reserved-word-class tokens to a VHDL author, not as
//     library helpers.
//   - ATTRIBUTE ŌåÆ `Preprocessor` ŌĆö a purple-family accent that
//     matches Ruby's `:symbol` slot and Smalltalk's SYMBOL. VHDL
//     attributes are the closest analogue in this language ŌĆö
//     bare designators accessed via a tick.
//   - STDFUNCTION ŌåÆ `Keyword2` ŌĆö teal / steel-blue to
//     distinguish library helpers from language keywords.
//   - STDPACKAGE ŌåÆ `Macro` ŌĆö a distinct accent for library
//     package names (`ieee`, `std_logic_1164`), matching how
//     `#define` targets get called out in C.
//   - STDTYPE ŌåÆ `Number` ŌĆö a numeric-tinted accent for the
//     type name family (`std_logic`, `integer`). Matches the
//     visual weight readers expect for type-family tokens
//     that are neither operators nor keywords.
//   - USERWORD ŌåÆ `Keyword2` ŌĆö same visual weight as
//     STDFUNCTION, reserving the "identifier the user's
//     project cares about" slot.
//   - OPERATOR (punctuation) ŌåÆ `Operator` ŌĆö standard.
//   - STRING / STRINGEOL ŌåÆ `String` ŌĆö both. STRINGEOL is the
//     unterminated-string error indicator; it still needs a
//     visible colour so the reader sees the runaway string.
//   - NUMBER ŌåÆ `Number` ŌĆö standard.
//   - COMMENT / COMMENTLINEBANG / BLOCK_COMMENT ŌåÆ `Comment`.
const VHDL_STYLES: &[(usize, StyleSlot)] = &[
    // Comment family (line + doc-line + block)
    (SCE_VHDL_COMMENT, StyleSlot::Comment),
    (SCE_VHDL_COMMENTLINEBANG, StyleSlot::Comment),
    (SCE_VHDL_BLOCK_COMMENT, StyleSlot::Comment),
    // Numeric literal
    (SCE_VHDL_NUMBER, StyleSlot::Number),
    // String family (regular + EOL-error)
    (SCE_VHDL_STRING, StyleSlot::String),
    (SCE_VHDL_STRINGEOL, StyleSlot::String),
    // Punctuation operator
    (SCE_VHDL_OPERATOR, StyleSlot::Operator),
    // Reserved words + word-form operators (both bold-keyword)
    (SCE_VHDL_KEYWORD, StyleSlot::Keyword),
    (SCE_VHDL_STDOPERATOR, StyleSlot::Keyword),
    // Predefined attributes (purple accent ŌĆö matches Ruby :sym / Smalltalk #sym)
    (SCE_VHDL_ATTRIBUTE, StyleSlot::Preprocessor),
    // Standard-library callable helpers
    (SCE_VHDL_STDFUNCTION, StyleSlot::Keyword2),
    // Standard-library package names
    (SCE_VHDL_STDPACKAGE, StyleSlot::Macro),
    // Standard-library types
    (SCE_VHDL_STDTYPE, StyleSlot::Number),
    // User words (empty class today; visual slot reserved)
    (SCE_VHDL_USERWORD, StyleSlot::Keyword2),
];

// Italic only on the comment family ŌĆö the universal
// prose-italic convention. All three comment-flavour styles
// (line `--`, doc-line `--!`, block `/* */`) render italic.
const VHDL_ITALIC: &[usize] = &[
    SCE_VHDL_COMMENT,
    SCE_VHDL_COMMENTLINEBANG,
    SCE_VHDL_BLOCK_COMMENT,
];

// Bold on the two "reads-as-a-language-keyword" classes: the
// reserved-word class (`SCE_VHDL_KEYWORD`) and the word-form
// operators (`SCE_VHDL_STDOPERATOR` ŌĆö `and` / `or` / `not` /
// `xor` etc., which the theme paints the SAME visual weight
// as reserved words because they parse as reserved words in
// IEEE-1076 ┬¦7.2). Not bold on ATTRIBUTE, STDFUNCTION,
// STDPACKAGE, STDTYPE, USERWORD ŌĆö those get their identity
// from colour (via distinct StyleSlots) rather than weight,
// matching the "one bold visual for language keywords" rule
// used across the framework.
const VHDL_BOLD: &[usize] = &[SCE_VHDL_KEYWORD, SCE_VHDL_STDOPERATOR];

// Seven-class install matches `VHDLWordLists[]` at
// `LexVHDL.cxx:552-561`. Order matters for the classifier's
// dispatch precedence at `LexVHDL.cxx:93-107` (Keywords wins
// over Operators wins over Attributes ...) ŌĆö this order
// mirrors that. Class 6 (User Words) ships empty by design;
// see `VHDL_USERWORDS` rationale.
const VHDL_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, VHDL_KEYWORDS),
        (1, VHDL_OPERATORS),
        (2, VHDL_ATTRIBUTES),
        (3, VHDL_STDFUNCTIONS),
        (4, VHDL_STDPACKAGES),
        (5, VHDL_STDTYPES),
        (6, VHDL_USERWORDS),
    ],
    styles: VHDL_STYLES,
    italic: VHDL_ITALIC,
    bold: VHDL_BOLD,
};

// `KIXtart` theme ŌĆö 10 mappings across the 12 SCE_KIX_* slots
// (0..=10 + 31). Both `SCE_KIX_DEFAULT` (0) and
// `SCE_KIX_IDENTIFIER` (31) stay unmapped: DEFAULT per the
// framework's universal convention; IDENTIFIER because it's the
// intermediate state for bare identifiers that don't match
// KEYWORD or FUNCTIONS wordlists (i.e., ordinary user-defined
// identifiers) ŌĆö those SHOULD paint as default text so the
// reader isn't visually assaulted by every function name.
//
// **Cross-family palette choices:**
//   - KEYWORD (commands) ŌåÆ `Keyword` ŌĆö bold-blue, matches
//     VHDL/RB/ST convention for reserved-word class.
//   - FUNCTIONS (built-in functions) ŌåÆ `Keyword2` ŌĆö teal, so
//     `KIXtart`'s command-vs-function distinction is visually
//     obvious. Same slot as VHDL's STDFUNCTION.
//   - VAR (`$sigil`) ŌåÆ `Lifetime` ŌĆö matches Rust's `'lt` and
//     Ruby's `SCE_RB_INSTANCE_VAR` / `SCE_RB_CLASS_VAR`
//     conventions for "identifier prefixed by a sigil"
//     (`SCE_RB_GLOBAL` routes to `Macro` in `RB_STYLES`, not
//     `Lifetime` ŌĆö it's not the peer here).
//   - MACRO (`@sigil`) ŌåÆ `Preprocessor` ŌĆö the purple accent
//     matches Ruby's `:symbol` and Smalltalk's `#symbol` (the
//     "designator that follows a sigil" family). Different from
//     VAR so the two sigil families are visually distinct.
//   - STRING1 (double-quoted) + STRING2 (single-quoted) ŌåÆ `String`
//     ŌĆö no double-vs-single quote distinction in the theme (the
//     underlying string semantics are identical in `KIXtart`).
//   - NUMBER ŌåÆ `Number` ŌĆö standard.
//   - OPERATOR ŌåÆ `Operator` ŌĆö standard.
//   - COMMENT (`;`) + COMMENTSTREAM (`/* */`) ŌåÆ `Comment` ŌĆö both.
const KIX_STYLES: &[(usize, StyleSlot)] = &[
    // Comments (line + block)
    (SCE_KIX_COMMENT, StyleSlot::Comment),
    (SCE_KIX_COMMENTSTREAM, StyleSlot::Comment),
    // Strings (double- and single-quoted)
    (SCE_KIX_STRING1, StyleSlot::String),
    (SCE_KIX_STRING2, StyleSlot::String),
    // Numeric literal
    (SCE_KIX_NUMBER, StyleSlot::Number),
    // `$var` sigil-prefixed variable
    (SCE_KIX_VAR, StyleSlot::Lifetime),
    // `@macro` sigil-prefixed macro (whitelist-gated)
    (SCE_KIX_MACRO, StyleSlot::Preprocessor),
    // Commands (bold-keyword)
    (SCE_KIX_KEYWORD, StyleSlot::Keyword),
    // Built-in functions (teal accent)
    (SCE_KIX_FUNCTIONS, StyleSlot::Keyword2),
    // Punctuation-class operator
    (SCE_KIX_OPERATOR, StyleSlot::Operator),
];

// Italic only on the comment families ŌĆö universal prose-italic
// convention. Both `;` line comments and `/* */` block comments
// render italic.
const KIX_ITALIC: &[usize] = &[SCE_KIX_COMMENT, SCE_KIX_COMMENTSTREAM];

// Bold only on the KEYWORD class (`KIXtart` commands read as
// language-keyword-class tokens). FUNCTIONS get their identity
// from the Keyword2 colour accent, not weight ŌĆö matching the
// framework's "one bold visual for language keywords" rule.
const KIX_BOLD: &[usize] = &[SCE_KIX_KEYWORD];

// Three-class install matches LexKix's `keywords` / `keywords2` /
// `keywords3` at `LexKix.cxx:44-46`. Class 3 (`keywords4`) is
// commented out at `:47` ŌĆö never probed ŌĆö so we don't install it.
const KIX_THEME: LangTheme = LangTheme {
    keywords: &[(0, KIX_KEYWORDS), (1, KIX_FUNCTIONS), (2, KIX_MACROS)],
    styles: KIX_STYLES,
    italic: KIX_ITALIC,
    bold: KIX_BOLD,
};

// AutoIt3 theme ŌĆö 15 mappings across 16 SCE_AU3_* slots (0..=15).
// `SCE_AU3_DEFAULT` (0) stays unmapped per the framework's
// universal convention. `SCE_AU3_KEYWORD` (5) is doubly-used:
// (a) the final paint style for reserved words, and (b) the
// intermediate scan state for every identifier that will be
// rewritten by the classifier's wordlist chain ŌĆö so mapping it
// to `StyleSlot::Keyword` correctly paints reserved words
// (rewrites to other classes happen BEFORE paint time via
// `sc.ChangeState`).
//
// **Cross-family palette choices:**
//   - KEYWORD (reserved words: `if`, `for`, `func`, `and`,
//     etc.) ŌåÆ `Keyword` ŌĆö bold-blue, standard.
//   - FUNCTION (built-in AutoIt3 functions) ŌåÆ `Keyword2` ŌĆö teal,
//     so the language-keyword-vs-built-in-function split is
//     visually distinct.
//   - UDF (`_ArrayDisplay`-style Standard UDF Library helpers) ŌåÆ
//     `Keyword2` (same as FUNCTION ŌĆö both are "callable helpers
//     the language provides"). Distinct from user-defined
//     functions which paint as default.
//   - MACRO (`@Error`, `@ScriptDir`, etc.) ŌåÆ `Preprocessor` ŌĆö
//     the purple accent matches Ruby `:symbol`, Smalltalk
//     `#symbol`, KIXtart `@macro` and the "designator that
//     follows a sigil" family.
//   - PREPROCESSOR (`#include`, `#Region`, etc.) ŌåÆ `Macro` ŌĆö
//     matches C's `#define` styling family. Distinct from
//     MACRO because AutoIt3 preprocessor and macro are
//     semantically different (compile-time vs runtime
//     constants), and the visual split reflects that.
//   - VARIABLE (`$name`) ŌåÆ `Lifetime` ŌĆö matches Rust `'lt`,
//     KIXtart `$var`, Ruby `SCE_RB_INSTANCE_VAR` conventions.
//   - SENT (`{ENTER}` / `{F1}` INSIDE strings) ŌåÆ `Preprocessor`
//     ŌĆö matches MACRO's purple accent to signal "this is a
//     named token, not string content." The visual match
//     between MACRO and SENT is intentional: both are
//     structured named tokens with fixed vocabulary that a
//     reader needs to see as distinct from surrounding text.
//   - COMOBJ (`$obj.Method` ŌĆö the `Method` portion) ŌåÆ
//     `Keyword2` (same as FUNCTION) ŌĆö a method call reads as
//     a function invocation.
//   - SPECIAL (empty class, reserved for user extension) ŌåÆ
//     `Keyword2` ŌĆö the visual slot is reserved so a future
//     per-project override that populates the class produces
//     immediate visible highlighting.
//   - EXPAND (empty class, reserved for user extension) ŌåÆ
//     `Keyword` ŌĆö the visual slot is reserved same way.
//   - STRING ŌåÆ `String` ŌĆö standard.
//   - NUMBER ŌåÆ `Number` ŌĆö standard.
//   - OPERATOR ŌåÆ `Operator` ŌĆö standard.
//   - COMMENT (`;`) + COMMENTBLOCK (`#cs ... #ce`) ŌåÆ `Comment`.
const AU3_STYLES: &[(usize, StyleSlot)] = &[
    // Comments (line + block)
    (SCE_AU3_COMMENT, StyleSlot::Comment),
    (SCE_AU3_COMMENTBLOCK, StyleSlot::Comment),
    // Numeric literal
    (SCE_AU3_NUMBER, StyleSlot::Number),
    // Built-in functions (teal)
    (SCE_AU3_FUNCTION, StyleSlot::Keyword2),
    // Reserved words (bold-blue)
    (SCE_AU3_KEYWORD, StyleSlot::Keyword),
    // `@Macro` runtime constants
    (SCE_AU3_MACRO, StyleSlot::Preprocessor),
    // String literal
    (SCE_AU3_STRING, StyleSlot::String),
    // Punctuation operator
    (SCE_AU3_OPERATOR, StyleSlot::Operator),
    // `$var` variables
    (SCE_AU3_VARIABLE, StyleSlot::Lifetime),
    // `{ENTER}` SendKeys inside strings ŌĆö matches MACRO purple
    (SCE_AU3_SENT, StyleSlot::Preprocessor),
    // `#include` / `#Region` etc. ŌĆö `StyleSlot::Macro` (the
    // Rust-macro accent shared with `SCE_RB_GLOBAL` /
    // `SCE_VHDL_STDPACKAGE` etc.). Deliberately DISTINCT from
    // `Preprocessor` (which C's `SCE_C_PREPROCESSOR` uses) so
    // AutoIt3 `#include` paints differently from its `@Error`
    // runtime macros (which route to `Preprocessor`)
    (SCE_AU3_PREPROCESSOR, StyleSlot::Macro),
    // Empty class ŌĆö reserved user-extension slot
    (SCE_AU3_SPECIAL, StyleSlot::Keyword2),
    // Empty class ŌĆö reserved user-extension slot
    (SCE_AU3_EXPAND, StyleSlot::Keyword),
    // `$obj.Method` ŌĆö the `Method` half
    (SCE_AU3_COMOBJ, StyleSlot::Keyword2),
    // Standard UDF Library helpers
    (SCE_AU3_UDF, StyleSlot::Keyword2),
];

// Italic on both comment families ŌĆö universal prose-italic
// convention. Line (`;`) and block (`#cs ... #ce`) comments
// both render italic.
const AU3_ITALIC: &[usize] = &[SCE_AU3_COMMENT, SCE_AU3_COMMENTBLOCK];

// Bold on KEYWORD only. FUNCTION / UDF / COMOBJ share the
// Keyword2 colour accent but not weight, matching the
// framework's "one bold visual for language keywords" rule.
// EXPAND (mapped to Keyword) is intentionally NOT bolded ŌĆö
// the class is empty in the canonical grammar, so bolding it
// would matter only if a user populates the class, in which
// case the palette slot alone is enough visual signal.
const AU3_BOLD: &[usize] = &[SCE_AU3_KEYWORD];

// Eight-class install matches `AU3WordLists[]` at
// `LexAU3.cxx:900-909`. Class ordering matters for the
// classifier's dispatch precedence at `LexAU3.cxx:326-357`:
// keywords ŌåÆ functions ŌåÆ macros ŌåÆ preprocessors ŌåÆ special ŌåÆ
// expand ŌåÆ UDF (SendKeys is class 3 but is probed only from
// the SCE_AU3_SENT state at `:483` inside strings, not from
// the identifier-exit path).
const AU3_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, AU3_KEYWORDS),
        (1, AU3_FUNCTIONS),
        (2, AU3_MACROS),
        (3, AU3_SENDKEYS),
        (4, AU3_PREPROCESSORS),
        (5, AU3_SPECIAL),
        (6, AU3_EXPAND),
        (7, AU3_UDF),
    ],
    styles: AU3_STYLES,
    italic: AU3_ITALIC,
    bold: AU3_BOLD,
};

// Objective Caml theme ŌĆö 14 mappings across the 16 SCE_CAML_* slots
// (0..=15). Both `SCE_CAML_DEFAULT` (0) and `SCE_CAML_IDENTIFIER`
// (1) stay unmapped: DEFAULT per the framework convention;
// IDENTIFIER because it's the paint style for bare user
// identifiers (variables / function names) that survive the
// wordlist chain unmatched ŌĆö those SHOULD paint as default text
// (matching KIXtart's IDENTIFIER-unmapped stance). LexCaml
// exposes IDENTIFIER as a separate SCE constant so a project
// could theme user identifiers distinctly if desired; Code++
// deliberately doesn't take that path.
//
// **Cross-family palette choices:**
//   - KEYWORD (reserved words: `let`, `if`, `match`, etc.) ŌåÆ
//     `Keyword` ŌĆö bold-blue, standard.
//   - KEYWORD2 (Pervasives/Stdlib functions: `print_string`,
//     `List.map`, etc.) ŌåÆ `Keyword2` ŌĆö teal, matches the
//     "language-provided callable helper" role used by AutoIt3
//     FUNCTION and VHDL STDFUNCTION.
//   - KEYWORD3 (type names: `int`, `list`, `option`, `Buffer`)
//     ŌåÆ `Number` ŌĆö the numeric-tinted accent for type-family
//     tokens. Matches VHDL's STDTYPE convention.
//   - TAGNAME (`` `Tag `` polymorphic variant tags) ŌåÆ
//     `Preprocessor` ŌĆö the purple accent matches Ruby `:symbol`,
//     Smalltalk `#symbol`, AutoIt3 `@Macro` and the
//     "designator-follows-sigil" family. `` ` `` is the sigil.
//   - LINENUM (`#123` line-number directives) ŌåÆ `Macro` ŌĆö a
//     distinct accent slot (framework's Rust-macro accent,
//     shared with `SCE_RB_GLOBAL` / `SCE_VHDL_STDPACKAGE` /
//     `SCE_AU3_PREPROCESSOR`). Chosen to visually separate the
//     compile-time `#123` line-marker from the surrounding
//     source without colliding with TAGNAME (which already uses
//     `Preprocessor`).
//   - OPERATOR ŌåÆ `Operator` ŌĆö standard.
//   - NUMBER ŌåÆ `Number` ŌĆö standard.
//   - CHAR (`'c'` char literals) ŌåÆ `String` ŌĆö same slot as
//     STRING, matching every other language's char-literal
//     treatment.
//   - STRING ŌåÆ `String` ŌĆö standard.
//   - WHITE (SML embedded whitespace escape ŌĆö never emitted in
//     Caml mode) ŌåÆ `String` ŌĆö falls back to the surrounding
//     STRING style. Mapped so a stray SML-flavour file that
//     the user opens as `.ml` still renders sensibly.
//   - COMMENT / COMMENT1 / COMMENT2 / COMMENT3 ŌåÆ `Comment` ŌĆö
//     all four nesting-depth styles share the same visual.
//     Nesting depth doesn't affect appearance; it's tracked
//     by the classifier for correct un-nesting only.
const CAML_STYLES: &[(usize, StyleSlot)] = &[
    // Reserved words (bold-blue)
    (SCE_CAML_KEYWORD, StyleSlot::Keyword),
    // Pervasives/Stdlib functions
    (SCE_CAML_KEYWORD2, StyleSlot::Keyword2),
    // Type names (numeric-tinted accent)
    (SCE_CAML_KEYWORD3, StyleSlot::Number),
    // `` `Tag `` polymorphic-variant tags (purple sigil accent)
    (SCE_CAML_TAGNAME, StyleSlot::Preprocessor),
    // `#123` line-number directive
    (SCE_CAML_LINENUM, StyleSlot::Macro),
    // Punctuation operator
    (SCE_CAML_OPERATOR, StyleSlot::Operator),
    // Numeric literal
    (SCE_CAML_NUMBER, StyleSlot::Number),
    // Character literal (`'c'`)
    (SCE_CAML_CHAR, StyleSlot::String),
    // SML whitespace escape (never in Caml mode; mapped
    // defensively so a mis-flagged `.sml` opened as Caml
    // still renders)
    (SCE_CAML_WHITE, StyleSlot::String),
    // String literal (`"..."`)
    (SCE_CAML_STRING, StyleSlot::String),
    // Nested block comments (all four depth-levels share Comment)
    (SCE_CAML_COMMENT, StyleSlot::Comment),
    (SCE_CAML_COMMENT1, StyleSlot::Comment),
    (SCE_CAML_COMMENT2, StyleSlot::Comment),
    (SCE_CAML_COMMENT3, StyleSlot::Comment),
];

// Italic on all four comment-nesting styles ŌĆö universal
// prose-italic convention. Nesting depth doesn't matter; every
// comment layer renders italic.
const CAML_ITALIC: &[usize] = &[
    SCE_CAML_COMMENT,
    SCE_CAML_COMMENT1,
    SCE_CAML_COMMENT2,
    SCE_CAML_COMMENT3,
];

// Bold only on KEYWORD. KEYWORD2 (functions) and KEYWORD3
// (types) share the Keyword2/Number colour accent but not
// weight, matching the framework's "one bold visual for
// language keywords" rule.
const CAML_BOLD: &[usize] = &[SCE_CAML_KEYWORD];

// Three-class install matches `camlWordListDesc[]` at
// `LexCaml.cxx:322-327` ŌĆö class 0 (Keywords), class 1
// (Keywords2 ŌĆö Pervasives/Stdlib functions), class 2
// (Keywords3 ŌĆö type names). Dispatch precedence at
// `LexCaml.cxx:141-146`: class 0 fires first, then class 1,
// then class 2 (with the `_` singleton short-circuit at
// `:141`).
const CAML_THEME: LangTheme = LangTheme {
    keywords: &[(0, CAML_KEYWORDS), (1, CAML_KEYWORDS2), (2, CAML_KEYWORDS3)],
    styles: CAML_STYLES,
    italic: CAML_ITALIC,
    bold: CAML_BOLD,
};

// LexAda emits 11 non-DEFAULT style indices covering the full Ada
// 95/2005/2012 lexical surface. **10 are mapped**; SCE_ADA_IDENTIFIER
// (2) is deliberately left unmapped ŌĆö matches the framework
// convention documented for `CPP_STYLES` at :3836-3837 and the
// explicit rationale for `KIX_STYLES` / `CAML_STYLES` / `PASCAL_STYLES`,
// where bare user-defined identifiers paint at `STYLE_DEFAULT`
// so the reader isn't visually assaulted by every variable /
// subprogram / package / type-name in the buffer. SCE_ADA_DEFAULT
// (0) is also unmapped by construction; every OTHER SCE_ADA_* slot
// gets a distinct visible colour.
//
// Style routing rationale:
//   - WORD (reserved words) ŌåÆ Keyword ŌĆö the language's canonical
//     bold-blue accent. Only ADA_KEYWORDS class is installed
//     (single wordlist per `adaWordListDesc[]`).
//   - IDENTIFIER ŌĆö deliberately UNMAPPED. LexAda sets
//     SCE_ADA_IDENTIFIER as the terminal state for every
//     non-keyword word (`LexAda.cxx:196`); if this were painted,
//     every variable / type / subprogram / package name would
//     tint with a palette accent instead of matching plain text.
//     Every neighbor themed lexer (C, C++, Pascal, VHDL, KIXtart,
//     Caml, AutoIt) omits its `_IDENTIFIER` slot for the same
//     reason. Ada follows suit.
//   - NUMBER ŌåÆ Number. Ada supports decimal (`42` / `3.14`),
//     scientific (`1.0e-3`), and based literals (`16#FF#`,
//     `2#1010#`) via `ColouriseNumber`.
//   - DELIMITER ŌåÆ Operator ŌĆö Ada's `:=`, `=>`, `..`, `**`, `<<`,
//     `>>`, `<=`, `>=`, `/=` all render as consecutive DELIMITER
//     runs since LexAda emits one style-run per punctuation char.
//   - CHARACTER + STRING ŌåÆ String ŌĆö literal quoted content.
//   - CHARACTEREOL + STRINGEOL ŌåÆ String too ŌĆö unterminated
//     literals still get the string colour so the user's eye
//     picks up the run; the illegal-token cue comes from
//     ILLEGAL. Alternative would be to leave them unmapped
//     pending a future `StyleSlot::Error` palette (that's what
//     LexPas, LexHTML SGML, and LexMake do); Ada instead
//     borrows the pattern from VHDL, whose `VHDL_STYLES` (:6250)
//     maps SCE_VHDL_STRINGEOL to `String`. Neither convention is
//     wrong; Ada picks the visible-in-lane choice so the
//     malformed region still reads as string-shaped.
//   - LABEL ŌåÆ Preprocessor ŌĆö `<< label >>` block-label targets
//     for `goto`; the "out-of-band syntax marker" reading fits
//     the Preprocessor slot's visual meaning.
//   - COMMENTLINE ŌåÆ Comment.
//   - ILLEGAL ŌåÆ Macro ŌĆö a distinct visible-error accent for
//     tokens LexAda rejected (bad identifier, bad numeric
//     literal). Reusing Macro because the slot is otherwise
//     Rust-only and Ada doesn't have real macros; borrowing it
//     for a themable syntax-error indicator gives ILLEGAL its
//     own colour without adding a new palette slot.
const ADA_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_ADA_WORD, StyleSlot::Keyword),
    (SCE_ADA_NUMBER, StyleSlot::Number),
    (SCE_ADA_DELIMITER, StyleSlot::Operator),
    (SCE_ADA_CHARACTER, StyleSlot::String),
    (SCE_ADA_CHARACTEREOL, StyleSlot::String),
    (SCE_ADA_STRING, StyleSlot::String),
    (SCE_ADA_STRINGEOL, StyleSlot::String),
    (SCE_ADA_LABEL, StyleSlot::Preprocessor),
    (SCE_ADA_COMMENTLINE, StyleSlot::Comment),
    (SCE_ADA_ILLEGAL, StyleSlot::Macro),
];

// Italic on comments ŌĆö universal prose-italic convention.
const ADA_ITALIC: &[usize] = &[SCE_ADA_COMMENTLINE];

// Bold only on WORD (reserved words). No secondary bold ŌĆö the
// theme uses one bold visual for language keywords, matching the
// framework's convention.
const ADA_BOLD: &[usize] = &[SCE_ADA_WORD];

// Single-class install matches `adaWordListDesc[]` at
// `LexAda.cxx:42-45` ŌĆö class 0 is "Keywords" and adaWordListDesc[1]
// is the NULL sentinel. Only class 0 is populated; no
// `SCI_SETKEYWORDS(1, ...)` needed.
const ADA_THEME: LangTheme = LangTheme {
    keywords: &[(0, ADA_KEYWORDS)],
    styles: ADA_STYLES,
    italic: ADA_ITALIC,
    bold: ADA_BOLD,
};

// LexVerilog emits 19 SCE_V_* slots ŌĆö 13 contiguous (0..=12) plus
// 6 in the extension range (19..=24). **17 are mapped**;
// `SCE_V_DEFAULT` (0) and `SCE_V_IDENTIFIER` (11) stay unmapped
// per the framework convention (bare identifiers paint at
// `STYLE_DEFAULT` alongside the C / C++ / Pascal / VHDL / KIXtart /
// Caml / AutoIt / Ada family). The `SCE_V_USER` (19) slot is
// mapped so that a project that populates class 3 (user tasks /
// identifiers) sees the theme apply; the shipped wordlist is
// empty by default.
//
// **Port-styling states.** SCE_V_INPUT / OUTPUT / INOUT /
// PORT_CONNECT (21..=24) are gated by the
// `lexer.verilog.portstyling` option (default `false` at
// `LexVerilog.cxx:146`). Code++ does not currently plumb
// `SCI_SETPROPERTY`, so those states do not fire in practice
// unless the user manually enables the option via a Scintilla
// property. Mapping them defensively means the theme is already
// consistent for the day port-styling is exposed via a settings
// UI or a per-project override ŌĆö and crucially, the three port
// directions route to the SAME slot (Keyword) they'd land in via
// class 0 wordlist matching when portStyling is OFF. Flipping the
// option therefore produces zero visual difference on the same
// source characters.
//
// Style routing rationale:
//   - COMMENT + COMMENTLINE + COMMENTLINEBANG ŌåÆ Comment.
//     All three comment forms share the italic-green convention;
//     COMMENTLINEBANG (`//!`) is a doc-flag variant that still
//     reads as a comment to the human eye.
//   - COMMENT_WORD ŌåÆ Preprocessor ŌĆö Doxygen-style keywords
//     (`\author`, `\brief`, `\file`) inside any comment (block,
//     line, or line-bang; LexVerilog transitions into COMMENT_WORD
//     from all three comment states). Purple accent draws the eye
//     to the semantic-marker nature of the token.
//   - NUMBER ŌåÆ Number.
//   - WORD (Class 0 ŌĆö module structure, control flow) ŌåÆ
//     Keyword bold blue.
//   - WORD2 (Class 1 ŌĆö types, net-types, gate primitives,
//     drive/charge strengths) ŌåÆ Keyword2 teal. Kept
//     unweighted (not bold) so the primary control-flow
//     keywords still stand out visually.
//   - WORD3 (Class 2 ŌĆö `$`-prefixed system tasks) ŌåÆ Macro.
//     Distinct accent because the `$` sigil already reads as
//     out-of-band and reusing Keyword2 would blur the visual
//     line between "language reserved word" and "runtime
//     library call". Matches how PostScript's SCE_PS_IMMEVAL
//     (the `//name` immediate-evaluate reference at :5772)
//     and Ruby's SCE_RB_GLOBAL borrow the Macro slot for the
//     same "distinct sigil-marked identifier" reading.
//   - USER (Class 3 ŌĆö user-defined tasks / identifiers) ŌåÆ
//     Keyword2. Same lane as WORD2 since the semantic
//     intent is "known library-ish identifier"; the shipped
//     wordlist is empty by default, so this only matters if
//     a project override populates it.
//   - PREPROCESSOR (` `-directives: `` `include ``,
//     `` `define ``, `` `ifdef ``, ŌĆ”) ŌåÆ Preprocessor. The
//     canonical slot for out-of-band syntax markers.
//   - OPERATOR ŌåÆ Operator.
//   - IDENTIFIER ŌĆö deliberately UNMAPPED. Framework convention.
//   - STRING ŌåÆ String.
//   - STRINGEOL ŌåÆ String. Same lane as STRING so the
//     malformed region still reads as string-shaped; matches
//     VHDL_STYLES / ADA_STYLES precedent. LexPas / LexHTML
//     SGML / LexMake take the opposite path (unmapped,
//     pending a future StyleSlot::Error) ŌĆö either convention
//     is defensible.
//   - INPUT / OUTPUT / INOUT ŌåÆ Keyword. Matches the SCE_V_WORD
//     baseline these tokens land in via class 0 wordlist
//     matching when `portStyling` is off (Code++'s default),
//     so toggling the property later doesn't create a large
//     visual jump on identical source characters (bold-blue
//     Keyword either way).
//   - PORT_CONNECT ŌåÆ Keyword2. `.name` in `.name (expr)`
//     module-instantiation binds reads as "known binding
//     identifier" ŌĆö same lane as USER (project-known helper
//     names).
const VERILOG_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_V_COMMENT, StyleSlot::Comment),
    (SCE_V_COMMENTLINE, StyleSlot::Comment),
    (SCE_V_COMMENTLINEBANG, StyleSlot::Comment),
    (SCE_V_COMMENT_WORD, StyleSlot::Preprocessor),
    (SCE_V_NUMBER, StyleSlot::Number),
    (SCE_V_WORD, StyleSlot::Keyword),
    (SCE_V_WORD2, StyleSlot::Keyword2),
    (SCE_V_WORD3, StyleSlot::Macro),
    (SCE_V_USER, StyleSlot::Keyword2),
    (SCE_V_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_V_OPERATOR, StyleSlot::Operator),
    (SCE_V_STRING, StyleSlot::String),
    (SCE_V_STRINGEOL, StyleSlot::String),
    (SCE_V_INPUT, StyleSlot::Keyword),
    (SCE_V_OUTPUT, StyleSlot::Keyword),
    (SCE_V_INOUT, StyleSlot::Keyword),
    (SCE_V_PORT_CONNECT, StyleSlot::Keyword2),
];

// Italic on the three comment style variants and the
// doc-keyword state ŌĆö matching the framework's italic-comment
// convention (see CAML_ITALIC, RUST_ITALIC).
const VERILOG_ITALIC: &[usize] = &[
    SCE_V_COMMENT,
    SCE_V_COMMENTLINE,
    SCE_V_COMMENTLINEBANG,
    SCE_V_COMMENT_WORD,
];

// Bold only on WORD (class 0 primary reserved words). WORD2 /
// WORD3 / USER differentiate via colour, not weight ŌĆö matches
// the framework's "one bold visual for language keywords" rule
// (Caml, VHDL, KIXtart, Ada all follow this).
const VERILOG_BOLD: &[usize] = &[SCE_V_WORD];

// Three wordlist classes installed: class 0 (WORD), class 1
// (WORD2), class 2 (WORD3). Classes 3 (USER), 4 (COMMENT_WORD),
// and 5 (ppDefinitions) intentionally left uninstalled ŌĆö the
// USER slot is empty by design (project-specific override
// mechanism), COMMENT_WORD is a Doxygen-style customisation
// point that Code++ doesn't ship defaults for, and
// ppDefinitions is a lexer-internal macro-expansion table not
// a highlighting class.
const VERILOG_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, VERILOG_KEYWORDS),
        (1, VERILOG_KEYWORDS_2),
        (2, VERILOG_SYSTEM_TASKS),
    ],
    styles: VERILOG_STYLES,
    italic: VERILOG_ITALIC,
    bold: VERILOG_BOLD,
};

// LexMatlab emits 9 `SCE_MATLAB_*` slots (0..=8). **7 are mapped**;
// `SCE_MATLAB_DEFAULT` (0) and `SCE_MATLAB_IDENTIFIER` (7) stay
// unmapped per the framework convention ŌĆö bare variable / function
// names paint at `STYLE_DEFAULT` alongside C / C++ / Pascal / VHDL /
// KIXtart / Caml / AutoIt / Ada / Verilog.
//
// Style routing rationale:
//   - COMMENT ŌåÆ Comment italic green. Covers all three MATLAB
//     comment forms (`%` line, `%{ ... %}` block with nesting,
//     and `...` line-continuation which the classifier promotes
//     to this state).
//   - COMMAND ŌåÆ Preprocessor. `!command` shell-escape syntax at
//     line-start is an out-of-band syntax marker rather than
//     ordinary code ŌĆö same slot the framework uses for
//     `` `include ``-style directives elsewhere.
//   - NUMBER ŌåÆ Number. Also the target for contextual `end`
//     inside indexing (`x(end)`), which is a MATLAB idiom
//     specifically meant to compute like a number.
//   - KEYWORD ŌåÆ Keyword bold blue.
//   - STRING ŌåÆ String. Single-quoted char-array literals.
//   - OPERATOR ŌåÆ Operator.
//   - IDENTIFIER ŌĆö deliberately UNMAPPED. Framework convention.
//   - DOUBLEQUOTESTRING ŌåÆ String. MATLAB R2017a+ `string`-type
//     literals share the string colour lane with the traditional
//     char-array form; the language distinguishes them by TYPE
//     but the user's eye reads both as string content.
const MATLAB_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_MATLAB_COMMENT, StyleSlot::Comment),
    (SCE_MATLAB_COMMAND, StyleSlot::Preprocessor),
    (SCE_MATLAB_NUMBER, StyleSlot::Number),
    (SCE_MATLAB_KEYWORD, StyleSlot::Keyword),
    (SCE_MATLAB_STRING, StyleSlot::String),
    (SCE_MATLAB_OPERATOR, StyleSlot::Operator),
    (SCE_MATLAB_DOUBLEQUOTESTRING, StyleSlot::String),
];

const MATLAB_ITALIC: &[usize] = &[SCE_MATLAB_COMMENT];

const MATLAB_BOLD: &[usize] = &[SCE_MATLAB_KEYWORD];

// Single-class install matches `matlabWordListDesc[]` at
// `LexMatlab.cxx:516-519` ŌĆö class 0 alone, with `[1]` = 0 NULL
// sentinel.
const MATLAB_THEME: LangTheme = LangTheme {
    keywords: &[(0, MATLAB_KEYWORDS)],
    styles: MATLAB_STYLES,
    italic: MATLAB_ITALIC,
    bold: MATLAB_BOLD,
};

// LexHaskell emits 23 `SCE_HA_*` slots (0..=22). **20 are mapped**;
// `SCE_HA_DEFAULT` (0), `SCE_HA_IDENTIFIER` (1), and
// `SCE_HA_IMPORT` (10) stay unmapped. DEFAULT + IDENTIFIER follow
// the framework convention (bare value bindings paint at
// STYLE_DEFAULT). SCE_HA_IMPORT is a legacy state ŌĆö modern
// LexHaskell (since 2013) routes import module names to
// SCE_HA_MODULE instead; the state remains defined but is not
// emitted, so mapping it would add a dead entry to the table.
//
// Style routing rationale:
//   - KEYWORD ŌåÆ Keyword bold blue. Haskell 2010 ┬¦2.4 reserved
//     words.
//   - NUMBER ŌåÆ Number.
//   - STRING + CHARACTER + STRINGEOL ŌåÆ String. All three literal
//     forms share the string colour; STRINGEOL matches the
//     VHDL / Ada / Verilog precedent (visible-in-lane rather
//     than deferring to a future Error slot).
//   - CLASS + INSTANCE ŌåÆ Keyword2. Type-class declaration
//     heads and instance-head class names both read as
//     "known type-family identifier".
//   - MODULE ŌåÆ Preprocessor. Module names in `import` /
//     `module` context are out-of-band syntax markers; same
//     lane as PRAGMA and PREPROCESSOR.
//   - CAPITAL ŌåÆ Keyword2. Capitalized identifiers (data
//     constructors, type names, bare type applications) share
//     the CLASS/INSTANCE lane since they're syntactically
//     equivalent to type-family identifiers in most contexts.
//   - DATA ŌåÆ Keyword2. Data-declaration payload (constructor
//     names inside `data T = A | B | C`).
//   - OPERATOR ŌåÆ Operator.
//   - RESERVED_OPERATOR ŌåÆ Operator. Haskell 2010 ┬¦2.4 reserved
//     operators (`..` / `::` / `=` / `->` / `=>` / `<-` / `|`
//     / `@` / `~` / `\` / `:`) share the Operator lane ŌĆö
//     visually consistent with ordinary operators but reachable
//     through a distinct SCE index if a future palette wants to
//     distinguish them.
//   - COMMENTLINE + COMMENTBLOCK + COMMENTBLOCK2 +
//     COMMENTBLOCK3 ŌåÆ Comment italic. Nesting depth is
//     tracked by the lexer but paints identically at every
//     depth ŌĆö the italic-comment convention is uniform.
//   - PRAGMA ŌåÆ Preprocessor. `{-# LANGUAGE ... #-}` /
//     `{-# INLINE ... #-}` compiler directives.
//   - PREPROCESSOR ŌåÆ Preprocessor. C-preprocessor `#`
//     directives when CPP is being run over the source.
//   - LITERATE_COMMENT + LITERATE_CODEDELIM ŌåÆ mapped
//     defensively for the `.lhs` literate-Haskell case (not
//     emitted by the plain `haskell` lexer, but the SCE
//     slots exist and a future L_LHASKELL wiring would
//     benefit from the theme already covering them).
//     COMMENT lane for LITERATE_COMMENT; Preprocessor lane
//     for LITERATE_CODEDELIM (the `\begin{code}` / `>` code
//     delimiter reads as an out-of-band syntax marker).
const HASKELL_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_HA_KEYWORD, StyleSlot::Keyword),
    (SCE_HA_NUMBER, StyleSlot::Number),
    (SCE_HA_STRING, StyleSlot::String),
    (SCE_HA_CHARACTER, StyleSlot::String),
    (SCE_HA_CLASS, StyleSlot::Keyword2),
    (SCE_HA_MODULE, StyleSlot::Preprocessor),
    (SCE_HA_CAPITAL, StyleSlot::Keyword2),
    (SCE_HA_DATA, StyleSlot::Keyword2),
    (SCE_HA_OPERATOR, StyleSlot::Operator),
    (SCE_HA_INSTANCE, StyleSlot::Keyword2),
    (SCE_HA_COMMENTLINE, StyleSlot::Comment),
    (SCE_HA_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_HA_COMMENTBLOCK2, StyleSlot::Comment),
    (SCE_HA_COMMENTBLOCK3, StyleSlot::Comment),
    (SCE_HA_PRAGMA, StyleSlot::Preprocessor),
    (SCE_HA_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_HA_STRINGEOL, StyleSlot::String),
    (SCE_HA_RESERVED_OPERATOR, StyleSlot::Operator),
    (SCE_HA_LITERATE_COMMENT, StyleSlot::Comment),
    (SCE_HA_LITERATE_CODEDELIM, StyleSlot::Preprocessor),
];

// Italic on every comment variant (5 total: line + block
// depth 1/2/3 + literate).
const HASKELL_ITALIC: &[usize] = &[
    SCE_HA_COMMENTLINE,
    SCE_HA_COMMENTBLOCK,
    SCE_HA_COMMENTBLOCK2,
    SCE_HA_COMMENTBLOCK3,
    SCE_HA_LITERATE_COMMENT,
];

// Bold on KEYWORD only. CLASS / MODULE / CAPITAL / DATA /
// INSTANCE / RESERVED_OPERATOR get their identity from colour,
// not weight ŌĆö matches the framework's "one bold visual for
// language keywords" rule.
const HASKELL_BOLD: &[usize] = &[SCE_HA_KEYWORD];

// Three-class install matches `haskellWordListDesc[]` at
// `LexHaskell.cxx:224-229` ŌĆö class 0 (Keywords), class 1 (FFI),
// class 2 (Reserved operators).
const HASKELL_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, HASKELL_KEYWORDS),
        (1, HASKELL_FFI_KEYWORDS),
        (2, HASKELL_RESERVED_OPERATORS),
    ],
    styles: HASKELL_STYLES,
    italic: HASKELL_ITALIC,
    bold: HASKELL_BOLD,
};

// LexInno emits 13 `SCE_INNO_*` slots (0..=12). **11 are mapped**;
// `SCE_INNO_DEFAULT` (0) and `SCE_INNO_IDENTIFIER` (12) stay
// unmapped per the framework convention (bare tokens paint at
// `STYLE_DEFAULT`).
//
// **Wordlist install: five of six classes.** The `Sections` /
// `Keywords` / `Parameters` / `Preprocessor directives` /
// `Pascal keywords` classes are populated; the `User defined
// keywords` class (5) is left empty as a project-override
// customisation slot ŌĆö the SCE state (`KEYWORD_USER`) is mapped
// defensively so a future per-project wordlist populates it
// without a theme change.
//
// Style routing rationale:
//   - COMMENT + COMMENT_PASCAL ŌåÆ Comment italic. The `;`-line
//     comment used at script level and the Pascal `{...}` /
//     `(*...*)` block comment used inside `[Code]` ŌĆö both read
//     as prose to the human eye.
//   - KEYWORD ŌåÆ Keyword bold blue. `[Setup]`-section directive
//     names (`AppName`, `Compression`, ŌĆ”) ŌĆö matches the
//     "primary language keyword" reading.
//   - KEYWORD_PASCAL ŌåÆ Keyword bold blue. Pascal reserved words
//     inside `[Code]` share the primary-keyword lane since
//     they're the reserved words of the script's embedded
//     Pascal Script dialect ŌĆö same visual role as KEYWORD in
//     the outer script.
//   - PARAMETER ŌåÆ Keyword2 teal. Section-item parameter names
//     (`Source`, `DestDir`, `Flags`, ŌĆ”) ŌĆö secondary structural
//     accent.
//   - KEYWORD_USER ŌåÆ Keyword2. Same lane as PARAMETER since the
//     semantic intent is "known project identifier"; empty
//     wordlist by default.
//   - SECTION ŌåÆ Preprocessor purple. `[SectionName]` headers
//     are structural markers rather than code content ŌĆö
//     matches the "out-of-band syntax marker" reading of the
//     Preprocessor slot.
//   - PREPROC ŌåÆ Preprocessor. `#`-directives (`#define`,
//     `#include`, `#if`, ŌĆ”) ŌĆö canonical preprocessor lane.
//   - INLINE_EXPANSION ŌåÆ Macro. `{code:...}` / `{param:...}`
//     inline preprocessor expansions read as distinct
//     macro-like invocations; Macro slot gives them a themable
//     accent separate from PREPROC.
//   - STRING_DOUBLE + STRING_SINGLE ŌåÆ String. Both string
//     forms share the string lane; Inno syntax accepts either.
//   - IDENTIFIER ŌĆö deliberately UNMAPPED. Framework convention.
const INNO_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_INNO_COMMENT, StyleSlot::Comment),
    (SCE_INNO_KEYWORD, StyleSlot::Keyword),
    (SCE_INNO_PARAMETER, StyleSlot::Keyword2),
    (SCE_INNO_SECTION, StyleSlot::Preprocessor),
    (SCE_INNO_PREPROC, StyleSlot::Preprocessor),
    (SCE_INNO_INLINE_EXPANSION, StyleSlot::Macro),
    (SCE_INNO_COMMENT_PASCAL, StyleSlot::Comment),
    (SCE_INNO_KEYWORD_PASCAL, StyleSlot::Keyword),
    (SCE_INNO_KEYWORD_USER, StyleSlot::Keyword2),
    (SCE_INNO_STRING_DOUBLE, StyleSlot::String),
    (SCE_INNO_STRING_SINGLE, StyleSlot::String),
];

// Italic on the two comment forms.
const INNO_ITALIC: &[usize] = &[SCE_INNO_COMMENT, SCE_INNO_COMMENT_PASCAL];

// Bold on KEYWORD + KEYWORD_PASCAL ŌĆö both fill the "primary
// language keyword" role for their respective contexts (outer
// script vs `[Code]`).
const INNO_BOLD: &[usize] = &[SCE_INNO_KEYWORD, SCE_INNO_KEYWORD_PASCAL];

// Five-class install (classes 0-4). Class 5 (User defined
// keywords) intentionally uninstalled ŌĆö empty customisation
// slot.
const INNO_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, INNO_SECTIONS),
        (1, INNO_KEYWORDS),
        (2, INNO_PARAMETERS),
        (3, INNO_PREPROCESSOR),
        (4, INNO_PASCAL_KEYWORDS),
    ],
    styles: INNO_STYLES,
    italic: INNO_ITALIC,
    bold: INNO_BOLD,
};

// LexCmake emits 15 `SCE_CMAKE_*` slots (0..=14). **14 are
// mapped**; only `SCE_CMAKE_DEFAULT` (0) stays unmapped by
// construction. `SCE_CMAKE_USERDEFINED` (8) is mapped
// defensively even though the shipped wordlist is empty ŌĆö
// a future per-project override that populates class 2 will
// inherit the correct visual without a theme change.
//
// Style routing rationale:
//   - COMMENT ŌåÆ Comment italic. CMake's `#` line comment.
//   - STRINGDQ + STRINGLQ + STRINGRQ ŌåÆ String. Three string
//     forms (double-quote, backtick, single-quote); the LQ
//     and RQ forms are historical but the lexer still emits
//     them.
//   - COMMANDS ŌåÆ Keyword bold. CMake built-in commands
//     (case-insensitive). The primary language accent.
//   - PARAMETERS ŌåÆ Keyword2. Argument keywords / option names
//     (case-sensitive; `PRIVATE`, `PUBLIC`, `REQUIRED`, ŌĆ”) ŌĆö
//     secondary structural accent.
//   - VARIABLE ŌåÆ Preprocessor. `${var}` references are
//     out-of-band syntax markers rather than code content.
//   - USERDEFINED ŌåÆ Keyword2. Same lane as PARAMETERS since
//     the semantic intent is "known project-defined
//     identifier"; empty wordlist by default.
//   - WHILEDEF + FOREACHDEF + IFDEFINEDEF + MACRODEF ŌåÆ
//     Keyword bold. All four are hard-coded flow-control /
//     definition keywords special-cased at LexCmake.cxx:120-133;
//     they fill the same visual role as COMMANDS but through
//     a distinct SCE state so a future palette could
//     differentiate flow keywords from ordinary commands if
//     desired. Bold keeps them at the primary-keyword accent.
//   - STRINGVAR ŌåÆ Preprocessor. Variable interpolation inside
//     a string ŌĆö same "out-of-band marker inside content"
//     reading as VARIABLE.
//   - NUMBER ŌåÆ Number.
const CMAKE_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_CMAKE_COMMENT, StyleSlot::Comment),
    (SCE_CMAKE_STRINGDQ, StyleSlot::String),
    (SCE_CMAKE_STRINGLQ, StyleSlot::String),
    (SCE_CMAKE_STRINGRQ, StyleSlot::String),
    (SCE_CMAKE_COMMANDS, StyleSlot::Keyword),
    (SCE_CMAKE_PARAMETERS, StyleSlot::Keyword2),
    (SCE_CMAKE_VARIABLE, StyleSlot::Preprocessor),
    (SCE_CMAKE_USERDEFINED, StyleSlot::Keyword2),
    (SCE_CMAKE_WHILEDEF, StyleSlot::Keyword),
    (SCE_CMAKE_FOREACHDEF, StyleSlot::Keyword),
    (SCE_CMAKE_IFDEFINEDEF, StyleSlot::Keyword),
    (SCE_CMAKE_MACRODEF, StyleSlot::Keyword),
    (SCE_CMAKE_STRINGVAR, StyleSlot::Preprocessor),
    (SCE_CMAKE_NUMBER, StyleSlot::Number),
];

// Italic on comments only.
const CMAKE_ITALIC: &[usize] = &[SCE_CMAKE_COMMENT];

// Bold on all five keyword-lane states: COMMANDS + the four
// hard-coded flow-control state families. Matches the
// framework's "one bold visual for language keywords" rule
// applied to a lexer that spreads that role across five SCE
// indices.
const CMAKE_BOLD: &[usize] = &[
    SCE_CMAKE_COMMANDS,
    SCE_CMAKE_WHILEDEF,
    SCE_CMAKE_FOREACHDEF,
    SCE_CMAKE_IFDEFINEDEF,
    SCE_CMAKE_MACRODEF,
];

// Three-class install matches `cmakeWordLists[]` at
// `LexCmake.cxx:452-457` ŌĆö class 0 (Commands, case-insensitive),
// class 1 (Parameters, case-sensitive), class 2 (UserDefined,
// case-sensitive, empty by default).
const CMAKE_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, CMAKE_COMMANDS),
        (1, CMAKE_PARAMETERS),
        (2, CMAKE_USERDEFINED),
    ],
    styles: CMAKE_STYLES,
    italic: CMAKE_ITALIC,
    bold: CMAKE_BOLD,
};

// YAML (`L_YAML`) uses Lexilla's `LexYAML.cxx` ŌĆö a
// line-oriented scalar-value lexer. 10 `SCE_YAML_*` slots
// (0..=9); one wordlist class ("Keywords") for the boolean/
// null value tokens. 8 style mappings; `DEFAULT` (0) and
// `ERROR` (8) intentionally unmapped.
//
// **Slot rationale** (per the `LexYAML.cxx` banner in
// `scintilla-sys/src/lib.rs`):
//
//   - COMMENT ŌåÆ Comment. `#`-prefixed line comment.
//   - IDENTIFIER ŌåÆ Keyword2. Mapping-key position ŌĆö the
//     token before the first `:` separator. Framework
//     exception: most IDENTIFIER states follow the "bare
//     identifier ŌåÆ DEFAULT" rule, but YAML's IDENTIFIER is
//     structurally the key of a mapping, not a bare
//     identifier. Precedent: SCE_P_CLASSNAME /
//     SCE_P_DEFNAME / SCE_PL_SUB_PROTOTYPE /
//     SCE_PL_FORMAT_IDENT all route to Keyword2 for the
//     same reason.
//   - KEYWORD ŌåÆ Keyword bold. Boolean/null value tokens
//     (`true`, `False`, `null`, `yes`, etc.). Bold matches
//     the C / Python / Rust primary-keyword archetype.
//   - NUMBER ŌåÆ Number.
//   - REFERENCE ŌåÆ Preprocessor. `&anchor` / `*alias` ŌĆö a
//     structural cross-reference that reads as an out-of-band
//     syntax marker rather than content. Same lane as
//     CMake's `${var}` and the hypertext lexer's HTML
//     entities.
//   - DOCUMENT ŌåÆ Preprocessor bold. `---` / `...` document
//     boundaries. Same "out-of-band structural marker"
//     lane as REFERENCE; bold sets them apart from bare
//     `&`/`*` references while sharing the accent colour.
//   - TEXT ŌåÆ String. Content of folded (`>`) / literal
//     (`|`) block scalars ŌĆö verbatim string data spanning
//     multiple lines.
//   - OPERATOR ŌåÆ Operator. The mapping-separator `:`.
const YAML_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_YAML_COMMENT, StyleSlot::Comment),
    (SCE_YAML_IDENTIFIER, StyleSlot::Keyword2),
    (SCE_YAML_KEYWORD, StyleSlot::Keyword),
    (SCE_YAML_NUMBER, StyleSlot::Number),
    (SCE_YAML_REFERENCE, StyleSlot::Preprocessor),
    (SCE_YAML_DOCUMENT, StyleSlot::Preprocessor),
    (SCE_YAML_TEXT, StyleSlot::String),
    (SCE_YAML_OPERATOR, StyleSlot::Operator),
];

// Italic on `#`-to-EOL comments. Matches universal Code++
// comment-slot convention (Python COMMENTLINE + COMMENTBLOCK,
// Perl COMMENTLINE + POD, Rust COMMENTBLOCK + COMMENTLINE,
// Lua COMMENT + COMMENTLINE + COMMENTDOC, Bash COMMENTLINE).
const YAML_ITALIC: &[usize] = &[SCE_YAML_COMMENT];

// Bold on KEYWORD (matched boolean/null value) and DOCUMENT
// (`---`/`...` markers). KEYWORD gets classic keyword-bold
// treatment matching the C / Python / Perl / Lua precedent;
// DOCUMENT is a structural anchor (document boundary) and
// bolding parallels the Perl `SCE_PL_HERE_DELIM` structural-
// anchor convention.
const YAML_BOLD: &[usize] = &[SCE_YAML_KEYWORD, SCE_YAML_DOCUMENT];

// Single-class install matches `yamlWordListDesc[]` at
// `LexYAML.cxx:33-36` ŌĆö one wordlist ("Keywords") for the
// value-position boolean/null token family.
const YAML_THEME: LangTheme = LangTheme {
    keywords: &[(0, YAML_KEYWORDS)],
    styles: YAML_STYLES,
    italic: YAML_ITALIC,
    bold: YAML_BOLD,
};

// COBOL (`L_COBOL`) uses Lexilla's `LexCOBOL.cxx` ŌĆö the
// column-aware fixed-format-friendly COBOL lexer. 13 slots
// with a **non-contiguous numbering** (SCE_COBOL_WORD2 = 16,
// not 12); 11 style mappings; `DEFAULT` (0) and `IDENTIFIER`
// (11) intentionally unmapped.
//
// **Slot rationale** (per the `LexCOBOL.cxx` banner in
// `scintilla-sys/src/lib.rs`):
//
//   - COMMENT + COMMENTLINE + COMMENTDOC ŌåÆ Comment italic.
//     Three comment forms collapse to one visual (line
//     `*`/`/`, inline `*>`, and doc `**`/`/*`) matching the
//     Lua / Tcl / Perl comment-family collapse precedent.
//     COMMENT (state 1) is legacy ŌĆö the current state
//     machine doesn't emit it ŌĆö but map defensively so a
//     future Lexilla revision that revives it doesn't render
//     un-coloured.
//   - NUMBER ŌåÆ Number. Also catches COBOL level numbers
//     (`01`, `05`, `77`, `88`) intrinsically.
//   - WORD (A) ŌåÆ Keyword bold. Verbs / divisions / sections
//     / control flow ŌĆö the primary structural vocabulary.
//   - STRING + CHARACTER ŌåÆ String. Double-quoted and single-
//     quoted literals collapse to one slot per the C /
//     Perl / Ruby character-vs-string precedent.
//   - WORD3 (C) ŌåÆ Macro. Intrinsic functions (`length`,
//     `upper-case`, `numval`) read as builtins; Macro slot
//     delivers the right visual weight for "known name from
//     the runtime library" without inventing a new slot.
//     Matches how Rust's `println!` uses `SCE_RUST_MACRO`.
//   - PREPROCESSOR ŌåÆ Preprocessor bold. `?` at column 0 ŌĆö
//     rare COBOL preprocessor directive.
//   - OPERATOR ŌåÆ Operator.
//   - WORD2 (B) ŌåÆ Keyword2. PICTURE / VALUE / USAGE / file
//     descriptor clauses + figurative constants ŌĆö the
//     secondary structural vocabulary that colours the
//     DATA and FILE sections.
const COBOL_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_COBOL_COMMENT, StyleSlot::Comment),
    (SCE_COBOL_COMMENTLINE, StyleSlot::Comment),
    (SCE_COBOL_COMMENTDOC, StyleSlot::Comment),
    (SCE_COBOL_NUMBER, StyleSlot::Number),
    (SCE_COBOL_WORD, StyleSlot::Keyword),
    (SCE_COBOL_STRING, StyleSlot::String),
    (SCE_COBOL_CHARACTER, StyleSlot::String),
    (SCE_COBOL_WORD3, StyleSlot::Macro),
    (SCE_COBOL_PREPROCESSOR, StyleSlot::Preprocessor),
    (SCE_COBOL_OPERATOR, StyleSlot::Operator),
    (SCE_COBOL_WORD2, StyleSlot::Keyword2),
];

// Italic on all three comment family states ŌĆö matches
// universal Code++ comment-slot convention (Lua COMMENT +
// COMMENTLINE + COMMENTDOC triple, Tcl COMMENT + COMMENTLINE
// + COMMENT_BOX + BLOCK_COMMENT quad, Perl COMMENTLINE +
// POD family).
const COBOL_ITALIC: &[usize] = &[
    SCE_COBOL_COMMENT,
    SCE_COBOL_COMMENTLINE,
    SCE_COBOL_COMMENTDOC,
];

// Bold on primary keyword (WORD, list A verbs/divisions)
// and preprocessor. WORD gets classic keyword-bold treatment
// matching the C / Rust / Python / Lua precedent. PREPROCESSOR
// carries matching weight as a structural anchor ŌĆö parallels
// `SCE_C_PREPROCESSOR` bold in CPP_BOLD (`#include` / `#define`
// class) though realistic COBOL sees the `?` directive
// vanishingly rarely.
const COBOL_BOLD: &[usize] = &[SCE_COBOL_WORD, SCE_COBOL_PREPROCESSOR];

// Three-class install matches `COBOLWordListDesc[]` at
// `LexCOBOL.cxx:381-386` ŌĆö class 0 (A Keywords), class 1
// (B Keywords ŌåÆ SCE_COBOL_WORD2 = 16), class 2 (Extended
// Keywords ŌåÆ SCE_COBOL_WORD3). Order is canonical; swapping
// classes silently mis-routes highlighting.
const COBOL_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, COBOL_KEYWORDS_A),
        (1, COBOL_KEYWORDS_B),
        (2, COBOL_KEYWORDS_C),
    ],
    styles: COBOL_STYLES,
    italic: COBOL_ITALIC,
    bold: COBOL_BOLD,
};

// Gui4Cli (`L_GUI4CLI`) uses Lexilla's `LexGui4Cli.cxx` ŌĆö
// a niche 1990s Windows GUI-scripting language. **The SCE
// prefix is `SCE_GC_`, not `SCE_GUI4CLI_`** ŌĆö Lexilla's own
// enum spelling, preserved for greppability against the
// vendor tree. 10 slots (0..=9), 9 style mappings; `DEFAULT`
// (0) intentionally unmapped per framework convention.
//
// **Statement-position matching.** `colorFirstWord` at
// `LexGui4Cli.cxx:72-120` fires only for the leading token
// of a statement (post-`\n`/`\r`/`;`). Mid-statement uses
// of the same word stay `SCE_GC_DEFAULT`. This is a lexer
// property ŌĆö not a Code++ concern ŌĆö but noteworthy for
// theme-tuning: given `attr frame sunk` (the vendor sample
// at `AllStyles.gui:18`), only `attr` paints as
// `SCE_GC_ATTRIBUTE`; the `frame` / `sunk` argument tokens
// stay at DEFAULT, even if they happened to appear in one
// of the wordlists. Users expect this; do not "fix" it.
//
// **Slot rationale** (per the `LexGui4Cli.cxx` banner in
// `scintilla-sys/src/lib.rs`):
//
//   - COMMENTLINE + COMMENTBLOCK ŌåÆ Comment italic. Two
//     comment forms (`//` line, `/* ... */` block) collapse
//     to one visual, matching the Lua / Perl comment-family
//     precedent.
//   - GLOBAL (class 0) ŌåÆ Keyword bold. Top-level control
//     declarators (`G4C`, `WINDOW`, `XBUTTON`) ŌĆö the
//     primary structural anchors of a Gui4Cli script.
//   - EVENT (class 1) ŌåÆ Keyword2 bold. `X`-prefixed handler
//     declarators (`XONLOAD`, `XONCLICK`) ŌĆö a distinct
//     structural class from Globals. Bold pairs it with
//     GLOBAL as an equal-weight structural anchor.
//     LexGui4Cli's fold logic at `:271-273` sets header
//     points on both GLOBAL and EVENT lines, reinforcing
//     the "structural sibling" relationship.
//   - ATTRIBUTE (class 2) ŌåÆ Preprocessor. The
//     attribute-clause declarator `ATTR` ŌĆö the sole entry
//     in this class per the vendor `SciTE.properties` (see
//     GUI4CLI_ATTRIBUTES docstring for the statement-
//     position-matching rationale that keeps this list to
//     one token). Out-of-band property marker, same lane
//     as CMake's `${var}` and Rust's `#[attr]`.
//   - CONTROL (class 3) ŌåÆ Keyword. Flow-control words
//     (`IF`, `ELSE`, `ENDIF`, `GOSUB`, `GOTO`) ŌĆö semantic
//     keyword accent, share the primary-keyword slot with
//     GLOBAL.
//   - COMMAND (class 4) ŌåÆ Macro. Built-in verb names
//     (`MSGBOX`, `GUIOPEN`, `SETWINTITLE`) ŌĆö read as
//     "callable from the runtime library" the same way
//     Rust's `println!` reads. Macro slot delivers the
//     right visual weight.
//   - STRING ŌåÆ String. Single- and double-quoted literals
//     collapse to one slot per the C / Perl / COBOL
//     precedent.
//   - OPERATOR ŌåÆ Operator. Arithmetic + relational +
//     statement-terminator `;` + `$` variable sigil + `\`
//     escape.
const GUI4CLI_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_GC_COMMENTLINE, StyleSlot::Comment),
    (SCE_GC_COMMENTBLOCK, StyleSlot::Comment),
    (SCE_GC_GLOBAL, StyleSlot::Keyword),
    (SCE_GC_EVENT, StyleSlot::Keyword2),
    (SCE_GC_ATTRIBUTE, StyleSlot::Preprocessor),
    (SCE_GC_CONTROL, StyleSlot::Keyword),
    (SCE_GC_COMMAND, StyleSlot::Macro),
    (SCE_GC_STRING, StyleSlot::String),
    (SCE_GC_OPERATOR, StyleSlot::Operator),
];

// Italic on both comment forms ŌĆö matches universal Code++
// comment-slot convention (Lua COMMENT + COMMENTLINE +
// COMMENTDOC, Perl COMMENTLINE + POD, Rust COMMENTBLOCK +
// COMMENTLINE).
const GUI4CLI_ITALIC: &[usize] = &[SCE_GC_COMMENTLINE, SCE_GC_COMMENTBLOCK];

// Bold on GLOBAL and EVENT ŌĆö the two structural anchor
// classes that LexGui4Cli's fold logic (:271-273) marks as
// fold-header lines. Sharing bold matches the "structural
// sibling" reading. CONTROL is deliberately non-bold
// (semantic keyword, not structural anchor) matching the
// Lua / Rust precedent where `if` / `else` / `match` are
// bold but the semantic-keyword weight is inherited from
// the slot, not overridden per-state.
const GUI4CLI_BOLD: &[usize] = &[SCE_GC_GLOBAL, SCE_GC_EVENT];

// Five-class install matches `gui4cliWordListDesc[]` at
// `LexGui4Cli.cxx:306-309`. **Order is load-bearing** ŌĆö
// `SCI_SETKEYWORDS` respects wordlist-descriptor order,
// which is Globals(0), Events(1), Attributes(2), Control(3),
// Commands(4). Note the internal probe order at `:105-109`
// is different (Globals ŌåÆ Attributes ŌåÆ Control ŌåÆ Commands ŌåÆ
// Events, Events LAST); test invariant guards against
// cross-list duplicates that would shadow under the probe
// order.
const GUI4CLI_THEME: LangTheme = LangTheme {
    keywords: &[
        (0, GUI4CLI_GLOBALS),
        (1, GUI4CLI_EVENTS),
        (2, GUI4CLI_ATTRIBUTES),
        (3, GUI4CLI_CONTROL),
        (4, GUI4CLI_COMMANDS),
    ],
    styles: GUI4CLI_STYLES,
    italic: GUI4CLI_ITALIC,
    bold: GUI4CLI_BOLD,
};

// D (`L_D`) uses Lexilla's `LexD.cxx` ŌĆö the D programming
// language lexer. 23 slots (0..=22); 20 style mappings;
// `DEFAULT` (0), `WORD3` (8), and `IDENTIFIER` (14)
// intentionally unmapped.
//
// **`WORD3` unmapped is deliberate.** `LexD.cxx:296-307`
// probes wordlists 0/1/3/4/5/6 in the identifier
// classification cascade ŌĆö index 2 is SKIPPED because
// wordlist class 2 is repurposed for
// `SCE_D_COMMENTDOCKEYWORD` (dispatched at `:358` inside
// the doc-comment state). `SCE_D_WORD3` (value 8) is
// therefore DECLARED in the SciLexer.h enum but NEVER
// EMITTED by LexD's state machine. Mapping it would be
// dead code ŌĆö test invariant enforces the exclusion.
//
// **`.di` interface files** ŌĆö the `L_D` LANG_TABLE row
// carries `["d", "di"]` extensions. Both formats use the
// same lexer.
//
// **Slot rationale** (per the `LexD.cxx` banner in
// `scintilla-sys/src/lib.rs`):
//
//   - COMMENT + COMMENTLINE + COMMENTDOC + COMMENTNESTED
//     + COMMENTLINEDOC + COMMENTDOCKEYWORDERROR ŌåÆ Comment
//     italic. Six comment forms collapse to one visual ŌĆö
//     matches the Lua / Tcl / Perl comment-family collapse
//     precedent. COMMENTDOCKEYWORDERROR maps here (not
//     Preprocessor) because a malformed doc tag is
//     visually part of the surrounding doc comment, not a
//     distinct out-of-band marker.
//   - NUMBER ŌåÆ Number. Recognises hex, binary, underscore
//     separators, `e┬▒`/`p┬▒` exponents, and `f`/`F`/`L`/`i`
//     suffixes.
//   - WORD (class 0) ŌåÆ Keyword bold. Primary structural
//     vocabulary ŌĆö control flow, declarations, module
//     system.
//   - STRING + STRINGEOL + CHARACTER + STRINGB + STRINGR
//     ŌåÆ String. Five string flavors (`"..."`, unterminated
//     string, `'c'` character, `` `...` `` backtick
//     wysiwyg, `r"..."`/`x"..."`/`q"..."` raw/hex/delimited)
//     collapse to one slot per the C / Perl / COBOL
//     precedent.
//   - WORD2 (class 1) ŌåÆ Keyword2. Storage classes /
//     purity contracts (`const`, `immutable`, `shared`,
//     `pure`, `nothrow`, etc.). Distinct from primary
//     keywords ŌĆö "how identifiers live" vs "what they are".
//   - TYPEDEF (class 3) ŌåÆ Keyword2. Primitive types +
//     stdlib aliases (`int`, `void`, `string`, `size_t`,
//     etc.). Same visual weight as WORD2 ŌĆö they're both
//     "annotations" on structural code.
//   - WORD5 (class 4) ŌåÆ Keyword2. Special values +
//     compile-time tokens (`true`, `false`, `null`,
//     `__FILE__`, `__LINE__`, etc.). Framework choice:
//     collapse specials into Keyword2 rather than inventing
//     a dedicated slot.
//   - WORD6 (class 5) ŌåÆ Keyword2. Traits / meta
//     (`__traits`, `__vector`, `__parameters`, `__ctfe`).
//     Same lane as specials ŌĆö all `__`-prefixed
//     compile-time surface.
//   - WORD7 (class 6) ŌåÆ Keyword2. Reserved user-extension
//     slot (empty by default; mapped defensively so a
//     project-level Phobos override paints without a theme
//     change).
//   - OPERATOR ŌåÆ Operator. Punctuation + `@` attribute
//     sigil.
//   - COMMENTDOCKEYWORD ŌåÆ Macro. Ddoc `@param`/`@return`
//     etc. inside doc comments ŌĆö read as "known name from
//     the doc-tag vocabulary", same semantic slot as Rust
//     `println!` macro invocations.
const D_STYLES: &[(usize, StyleSlot)] = &[
    (SCE_D_COMMENT, StyleSlot::Comment),
    (SCE_D_COMMENTLINE, StyleSlot::Comment),
    (SCE_D_COMMENTDOC, StyleSlot::Comment),
    (SCE_D_COMMENTNESTED, StyleSlot::Comment),
    (SCE_D_COMMENTLINEDOC, StyleSlot::Comment),
    (SCE_D_COMMENTDOCKEYWORDERROR, StyleSlot::Comment),
    (SCE_D_NUMBER, StyleSlot::Number),
    (SCE_D_WORD, StyleSlot::Keyword),
    (SCE_D_WORD2, StyleSlot::Keyword2),
    (SCE_D_TYPEDEF, StyleSlot::Keyword2),
    (SCE_D_WORD5, StyleSlot::Keyword2),
    (SCE_D_WORD6, StyleSlot::Keyword2),
    (SCE_D_WORD7, StyleSlot::Keyword2),
    (SCE_D_STRING, StyleSlot::String),
    (SCE_D_STRINGEOL, StyleSlot::String),
    (SCE_D_CHARACTER, StyleSlot::String),
    (SCE_D_STRINGB, StyleSlot::String),
    (SCE_D_STRINGR, StyleSlot::String),
    (SCE_D_OPERATOR, StyleSlot::Operator),
    (SCE_D_COMMENTDOCKEYWORD, StyleSlot::Macro),
];

// Italic on all six comment family states ŌĆö matches
// universal Code++ comment-slot convention (COBOL's
// COMMENT + COMMENTLINE + COMMENTDOC triple, Lua's COMMENT
// + COMMENTLINE + COMMENTDOC, Tcl's four-state collapse).
// Also includes COMMENTDOCKEYWORDERROR ŌĆö a malformed doc
// tag is visually a comment, italicised uniformly.
const D_ITALIC: &[usize] = &[
    SCE_D_COMMENT,
    SCE_D_COMMENTLINE,
    SCE_D_COMMENTDOC,
    SCE_D_COMMENTNESTED,
    SCE_D_COMMENTLINEDOC,
    SCE_D_COMMENTDOCKEYWORDERROR,
];

// Bold on primary keyword only. Matches the C / Rust /
// Python / Lua precedent ŌĆö the "one bold class = language
// keywords" rule. Storage-class WORD2 and type-name TYPEDEF
// use Keyword2 weight (not bold) because they're structural
// annotations rather than the primary vocabulary.
const D_BOLD: &[usize] = &[SCE_D_WORD];

// Seven-class install matches `dWordLists[]` at
// `LexD.cxx:104-113` with class 6 (Keywords 7) shipped
