/// Fire every queued NPPN_* notification through `Shell::notify_plugins`,
/// each call wrapped in `PluginCallGuard` (re-entrance guard) and
/// `catch_unwind` (host-internal panics must not unwind across the
/// `extern "system"` `wnd_proc` frame).
///
/// Each notification grabs a fresh `&mut WindowState` borrow, calls
/// `notify_plugins` (which iterates plugins through `&Shell`), then
/// drops the borrow before the next iteration. A plugin's beNotified
/// that `SendMessage(NPPM_*)`s back hits `state_from_hwnd ŌåÆ None`
/// while the guard is set; the inner `wnd_proc` returns 0 and the
/// outer borrow stays sound.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn fire_queued_notifications(hwnd: HWND) {
    // Drain the queue under one borrow, then release before
    // calling into plugin code ŌĆö `take_notifications` only needs
    // `&mut Shell` for the swap, no plugin code runs inside it.
    // SAFETY: caller's contract requires UI-thread invocation;
    // state_from_hwnd's own contract is satisfied there.
    let notifications = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state.shell.take_notifications()
    } else {
        Vec::new()
    };
    if notifications.is_empty() {
        return;
    }
    for notification in notifications {
        // SAFETY: same as above; UI-thread call.
        if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
            // The guard is created INSIDE the catch_unwind closure
            // so that a panic from `PluginCallGuard::enter()` (the
            // nesting-detection assert) is caught here rather than
            // unwinding across the extern "system" wnd_proc frame.
            // The guard's Drop runs when the closure exits (panic
            // or normal return), tightly scoping
            // PLUGIN_CALL_ACTIVE to the plugin call.
            let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                let _guard = PluginCallGuard::enter();
                state.shell.notify_plugins(notification, hwnd.0);
            }));
        }
        // Borrow on `state` ends at the end of each iteration so
        // the next iteration acquires fresh.
    }
}

/// Close the active tab in response to `WM_COMMAND(ID_FILE_CLOSE)`
/// (Ctrl+W accelerator, File ŌåÆ Close menu item, or future
/// right-click ŌåÆ Close). Drives the platform-side cleanup the
/// shell-side `close_active_tab` doesn't know about: removes the
/// item from the tab control, releases the closed document via
/// `SCI_RELEASEDOCUMENT` (drops Scintilla's last refcount on the
/// buffer so memory is freed), and rebinds the view to the new
/// active document if there is one. Closing the last tab leaves
/// the view bound to a fresh empty document until the next
/// `open_file`.
///
/// Notifications (`NPPN_FILECLOSED` + possibly
/// `NPPN_BUFFERACTIVATED`) are queued by the shell-side close;
/// we deliver them via `fire_queued_notifications` after the
/// borrow ends, so plugin `beNotified` callbacks see a fully
/// quiesced state.
///
/// The function body is wrapped in `catch_unwind` so a host-
/// internal panic (allocation failure inside `Vec::push` or
/// `String::clone`, a misbehaving `tracing` subscriber, the
/// `allocate_buffer_id` overflow assert) doesn't unwind across
/// the `extern "system"` `wnd_proc` frame ŌĆö that's UB. Plugin
/// code never runs here, so the wrap is purely a defense
/// against host-internal panics.
///
/// Outcome of one close-active-tab attempt ŌĆö drives the
/// Close-All loop's continue-vs-break decision.
///
///   * `Closed` ŌĆö the active tab was successfully removed.
///   * `NothingToClose` ŌĆö there was no active tab to begin
///     with (workspace was empty), or `state_from_hwnd`
///     returned `None` (re-entrant plugin call active).
///   * `Aborted` ŌĆö the close did not happen because the user
///     dismissed the save-confirm dialog with Cancel, OR
///     because the Save / Save-As path failed (and the
///     error dialog was shown). In a Close-All context this
///     means "stop the loop": closing the next tab is not
///     what the user asked for after they aborted this one.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CloseOutcome {
    Closed,
    NothingToClose,
    Aborted,
}

/// Which subset of tabs the [`close_multiple_documents`] loop
/// should close. Every variant reuses the single-tab close path
/// (dirty-check prompt + Cancel short-circuit), so the user's
/// choices on individual dirty buffers are honoured exactly as
/// they are for `File ŌåÆ Close All`.
// The shared `All` prefix on every variant mirrors the user-facing
// menu labels ("Close All but Active", "Close All to the Left",
// ŌĆ”). Renaming to drop the prefix would only replace one context
// (this enum) with another (a `use CloseMultiKind::*` glob at
// every call site), so silence the pedantic lint.
#[allow(clippy::enum_variant_names)]
#[derive(Copy, Clone, Debug, PartialEq, Eq)]
enum CloseMultiKind {
    /// Every tab except the one that was active when the loop
    /// started. If the active tab is unpinned it stays open;
    /// pinned/unpinned status is irrelevant for this variant.
    AllButActive,
    /// Every tab that is NOT pinned. Pinned tabs stay. The
    /// active tab may or may not survive depending on whether
    /// it's pinned.
    AllButPinned,
    /// Every tab whose current index is < the active tab's
    /// index (i.e. to the left of it in the tab strip).
    AllToLeft,
    /// Every tab whose current index is > the active tab's
    /// index. Everything to the right of the active tab.
    AllToRight,
    /// Every tab that is not dirty (no unsaved changes). Uses
    /// the cached `Tab.dirty` flag which mirrors Scintilla's
    /// `SCI_GETMODIFY` and is maintained by `SCN_SAVEPOINTREACHED`
    /// / `SCN_SAVEPOINTLEFT` ŌĆö so this is O(n) with no
    /// doc-pointer-swap dance. The active tab is closed too if
    /// it happens to be clean.
    AllUnchanged,
}

/// Close every tab that matches the `kind` predicate. Reuses the
/// single-tab close path per iteration so dirty prompts +
/// Cancel-shortcircuits behave identically to Ctrl+W. Bounds
/// the iteration count by the initial tabs length so a
/// misbehaving close path can't hang the app.
///
/// Loop invariant:
///   * Snapshot the active tab id (the "keeper" for the
///     "All but Active" / "All to the Left" / "All to the
///     Right" variants) BEFORE entering the loop, because
///     activating a target tab mid-loop shifts
///     `shell.active_tab` and picking a fresh keeper on every
///     tick would collapse the loop to a no-op (each iteration
///     would try to skip whichever tab we just activated).
///   * Each iteration: pick the next target tab by
///     `pick_next_target(shell, kind, keeper_id)`; if `None`,
///     we're done. Else activate + close.
///   * `handle_close_active_tab_with_outcome` returns
///     `Aborted` on Cancel or `NothingToClose` when
///     `state_from_hwnd` returns `None` (re-entrant plugin
///     call). Either breaks the loop.
///
/// `ensure_one_tab` is called at the end only if the workspace
/// is empty. All five variants can potentially drain the strip
/// (Close All Unchanged if every tab is clean; Close All but
/// Pinned if none are pinned; etc.), and we don't want to leave
/// the user staring at an empty editor.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn close_multiple_documents(hwnd: HWND, kind: CloseMultiKind) {
    // Snapshot the keeper id + initial tab count under one
    // brief borrow, then drop it before the loop ŌĆö each
    // iteration re-acquires the borrow inside its own scope.
    //
    // No active tab ŌåÆ return early instead of falling back to a
    // synthetic id: three of the five variants (AllButActive,
    // AllToLeft, AllToRight) are meaningless without a keeper,
    // and a fallback of `0` would silently protect any tab that
    // happens to have that id from being closed. `refresh_file_menu`
    // greys every entry when `active_tab.is_none()`, but a
    // plugin-forged `WM_COMMAND` bypasses that greying and would
    // reach this helper ŌĆö the early return is the security /
    // correctness gate.
    let (keeper_id, initial_count) = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        let Some(active) = state.shell.active() else {
            return;
        };
        (active.id, state.shell.tabs.len())
    } else {
        return;
    };
    if initial_count == 0 {
        return;
    }
    for _ in 0..initial_count {
        // Pick the next target index under a fresh borrow.
        let next_idx = unsafe { state_from_hwnd(hwnd) }
            .and_then(|state| pick_next_close_target(&state.shell.tabs, kind, keeper_id));
        let Some(idx) = next_idx else {
            break; // No more targets ŌĆö done.
        };
        // Activate the target tab if it isn't already the
        // active one ŌĆö `handle_close_active_tab_inner` reads
        // `SCI_GETMODIFY` off the currently-bound Scintilla
        // document and pops the save prompt for THAT document,
        // so the target must be the bound one before we close.
        let active_now = unsafe { state_from_hwnd(hwnd) }.and_then(|s| s.shell.active_tab);
        if active_now != Some(idx) {
            unsafe { handle_window_menu_click(hwnd, idx) };
        }
        match unsafe { handle_close_active_tab_with_outcome(hwnd) } {
            CloseOutcome::Closed => {}
            // Aborted (Cancel or Save failure) OR NothingToClose
            // (re-entrant plugin call blocking state access):
            // stop the loop. Tabs that have already been closed
            // stay closed; the user committed to those decisions.
            CloseOutcome::Aborted | CloseOutcome::NothingToClose => break,
        }
    }
    // If the loop drained the strip (Close All Unchanged with
    // all-clean tabs; Close All but Pinned with none pinned;
    // ŌĆ”), restore the "always at least one tab" invariant.
    let empty = unsafe { state_from_hwnd(hwnd) }.is_some_and(|s| s.shell.tabs.is_empty());
    if empty {
        unsafe { ensure_one_tab(hwnd) };
    }
    unsafe {
        fire_queued_notifications(hwnd);
    }
}

/// Pick the vector index of the next tab to close for `kind`,
/// or `None` if no candidate remains. `keeper_id` is the tab id
/// that must survive for the "All but Active" / "All to the
/// Left / Right" variants ŌĆö captured once at the loop's start
/// so mid-loop activations don't shift the reference point.
///
/// This is a pure inspector on `Shell`; no mutation, no I/O,
/// no borrow smell. Called once per iteration of the outer
/// close loop.
fn pick_next_close_target(
    tabs: &[codepp_shell::Tab],
    kind: CloseMultiKind,
    keeper_id: i32,
) -> Option<usize> {
    // Never touch a tab whose async load is still in flight.
    // **Data-loss safeguard.** A pending-load tab has no
    // user edits (the user hasn't even seen the file yet);
    // activating it via `handle_window_menu_click` triggers
    // `handle_tab_selchange`'s lazy-populate branch which
    // binds the editor to a freshly-created EMPTY Scintilla
    // document seeded from the empty `tab.text`. Closing that
    // through the standard save-modal path can produce a
    // "Save changes to X.txt?" prompt for a file the user
    // hasn't opened ŌĆö and a Yes click there writes 0 bytes
    // over the real file on disk. Skipping pending-load tabs
    // at target-selection time makes them unreachable by this
    // bulk-close code path, closing the hazard by design ŌĆö
    // same discipline `Shell::save_all` uses at its own
    // iteration site. Users can still close a still-loading
    // tab with Ctrl+W once the load completes.
    let is_closable = |t: &codepp_shell::Tab| t.pending_load.is_none();
    match kind {
        CloseMultiKind::AllButActive => tabs
            .iter()
            .position(|t| t.id != keeper_id && is_closable(t)),
        CloseMultiKind::AllButPinned => tabs.iter().position(|t| !t.pinned && is_closable(t)),
        CloseMultiKind::AllToLeft => {
            // Find the keeper's position; then scan the [0, keeper)
            // prefix for the first closable tab. Returns the
            // absolute index (positions inside a slice starting at
            // 0 are already absolute for the base vector).
            let keeper_pos = tabs.iter().position(|t| t.id == keeper_id)?;
            tabs[..keeper_pos].iter().position(is_closable)
        }
        CloseMultiKind::AllToRight => {
            // Symmetric to AllToLeft on the (keeper, end) suffix.
            // `position` returns a relative index; add `keeper_pos
            // + 1` to convert back to an absolute vector index.
            let keeper_pos = tabs.iter().position(|t| t.id == keeper_id)?;
            tabs[keeper_pos + 1..]
                .iter()
                .position(is_closable)
                .map(|rel| keeper_pos + 1 + rel)
        }
        CloseMultiKind::AllUnchanged => tabs.iter().position(|t| !t.dirty && is_closable(t)),
    }
}

/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_close_active_tab(hwnd: HWND) {
    // Single-tab close discards the outcome ŌĆö Ctrl+W / FileŌåÆClose
    // / future right-click ŌåÆ Close don't need to know whether the
    // user cancelled. Close-All uses the with-outcome variant.
    //
    // SAFETY: caller's UI-thread contract carries.
    let _ = unsafe { handle_close_active_tab_with_outcome(hwnd) };
}

/// Same close-active-tab flow as [`handle_close_active_tab`],
/// but returns the [`CloseOutcome`] so the Close-All loop can
/// stop on `Aborted` instead of re-prompting the same tab on
/// every iteration.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_close_active_tab_with_outcome(hwnd: HWND) -> CloseOutcome {
    // The `catch_unwind` wraps the inner so a host-internal
    // panic (allocation failure, tracing-subscriber misbehaviour,
    // ...) doesn't unwind across the `extern "system"` wnd_proc
    // frame. On a caught panic we report `Aborted` so a
    // Close-All loop stops rather than spinning on a poisoned
    // close path.
    std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        // SAFETY: caller's UI-thread contract carries.
        unsafe { handle_close_active_tab_inner(hwnd) }
    }))
    .unwrap_or(CloseOutcome::Aborted)
}

/// Body of [`handle_close_active_tab_with_outcome`], factored
/// out so the caller can wrap it in a single `catch_unwind`.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_close_active_tab_inner(hwnd: HWND) -> CloseOutcome {
    // Phase 0: dirty-check gate. If the active tab's buffer has
    // unsaved changes, prompt the user with Save / Don't Save /
    // Cancel before any data-model mutation. Cancel aborts the
    // entire close ŌĆö the buffer stays open.
    //
    // Empty-untitled exception: a brand-new untitled tab the user
    // typed-then-erased still reports SCI_GETMODIFY non-zero (the
    // savepoint never moved past the initial empty state), but
    // there's nothing meaningful to save ŌĆö asking "Save 'new 1' ?"
    // for a buffer with zero characters is friction, not safety.
    // The exception is scoped to `!has_path` so titled files are
    // not affected: a "Select All + Delete + close" on a path-bound
    // tab still prompts, letting the user explicitly choose between
    // truncate-and-save and discard.
    //
    // We sample (display name, has_path, dirty, length) under a
    // brief read-only borrow, drop it before the modal pump runs
    // (the borrow can't outlive the modal ŌĆö the Win32 message
    // pump re-enters our wnd_proc, which would alias-UB the
    // `WindowState`), then act on the user's choice.
    //
    // `dirty` OR's the live `SCI_GETMODIFY` bit against the cached
    // `Tab.dirty` from Shell. The two agree for the active tab in
    // normal operation (kept in sync by SCN_SAVEPOINT* notifications),
    // but diverge in the "file removed externally, tab still open"
    // case: Shell flips `Tab.dirty = true` in `apply_file_change`
    // whether the underlying Scintilla doc has been touched or not,
    // so the close-prompt gate here still fires and closing the
    // tab doesn't silently discard the only surviving copy of the
    // buffer text.
    let prelude = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state.shell.active().map(|tab| {
            let name = tab_display_name(tab);
            let has_path = tab.path.is_some();
            let has_pending_load = tab.pending_load.is_some();
            let cached_dirty = tab.dirty;
            let dirty = state.editor.send(SCI_GETMODIFY, 0, 0) != 0 || cached_dirty;
            let length = state.editor.send(SCI_GETLENGTH, 0, 0);
            (name, has_path, has_pending_load, dirty, length)
        })
    } else {
        return CloseOutcome::NothingToClose;
    };
    let Some((display_name, has_path, has_pending_load, dirty, length)) = prelude else {
        return CloseOutcome::NothingToClose;
    };
    // **Data-loss safeguard.** A tab whose async load is still
    // in flight has no user edits ŌĆö the user hasn't even seen
    // the file yet. Any "dirty" state on such a tab's
    // Scintilla document reflects a lazy-populate from an
    // empty `tab.text` (see `handle_tab_selchange`'s
    // lazy-populate branch), not a user modification. Surfacing
    // the "Save changes to X?" modal here would ask the user
    // to sign off on writing an empty buffer over their real
    // file on disk ŌĆö a catastrophic outcome if the click lands
    // on Yes. Treat pending-load tabs as clean unconditionally
    // so the modal never surfaces; the tab is discarded on close
    // exactly as `SaveConfirmResult::No` would have done. Matches
    // the discipline `Shell::save_all` uses on its own iteration
    // path (`pending_load.is_some()` skips the tab there too).
    if dirty && !has_pending_load && (has_path || length > 0) {
        match show_save_confirm_dialog(hwnd, &display_name) {
            SaveConfirmResult::Cancel => return CloseOutcome::Aborted,
            SaveConfirmResult::No => {
                // Proceed to the close without saving. The
                // buffer's edits are discarded with the doc
                // when SCI_RELEASEDOCUMENT runs in Phase 2.
            }
            SaveConfirmResult::Yes => {
                // `has_path` was sampled BEFORE the confirm
                // modal ran. The modal's nested message pump
                // can dispatch WM_APP_WAKE (which drains
                // shell-level deferred work), but no current
                // code path clears an already-set `tab.path`
                // back to `None` ŌĆö the invariant holds. If a
                // future code path could break it,
                // `save_current_to_disk` returns
                // `ShellError::NoActivePath` and the error
                // dialog below surfaces it; the worst case is
                // a confusing "Save failed: no active file
                // path" message, not silent data loss.
                if has_path {
                    // Titled tab ŌĆö save in place. On error,
                    // surface the message and abort the close;
                    // silently dropping the buffer when save
                    // failed is the worst possible outcome.
                    //
                    // `state_from_hwnd` returns `None` when
                    // `PLUGIN_CALL_ACTIVE` is set ŌĆö i.e. a
                    // plugin's `beNotified` is on the stack
                    // and re-entered our wnd_proc. That path is
                    // currently unreachable here (the modal
                    // pump can dispatch plugin notifications,
                    // but the guard is dropped before the
                    // modal returns), but the early return is
                    // the safe behaviour either way: aborting
                    // the close is better than mutating
                    // `WindowState` while a plugin call is
                    // alive.
                    let save_error = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
                        let (shell, mut ui) = state.split();
                        match shell.save_current_to_disk(&mut ui) {
                            Ok(()) => None,
                            Err(e) => Some(e.to_string()),
                        }
                    } else {
                        return CloseOutcome::Aborted;
                    };
                    if let Some(msg) = save_error {
                        show_error_dialog(hwnd, "Save failed", &msg);
                        return CloseOutcome::Aborted;
                    }
                } else {
                    // Untitled tab ŌĆö route through the Save As
                    // dialog. `run_save_as_flow` shows its own
                    // error dialog on failure (so we don't
                    // double-prompt) and updates the tab's path
                    // on success. After it returns, re-read
                    // the dirty bit: if the user cancelled the
                    // GetSaveFileNameW dialog or the save
                    // itself failed, the buffer is still dirty
                    // and we must abort the close.
                    unsafe { run_save_as_flow(hwnd) };
                    let still_dirty = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
                        state.editor.send(SCI_GETMODIFY, 0, 0) != 0
                    } else {
                        return CloseOutcome::Aborted;
                    };
                    if still_dirty {
                        return CloseOutcome::Aborted;
                    }
                }
            }
        }
    }

    // Phase 1: ask the shell to do its half. We hold a brief
    // `&mut WindowState` borrow only for the duration of this
    // call ŌĆö `close_active_tab` is pure data-model work plus an
    // unwatch, no plugin code runs inside it.
    let closed = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state.shell.close_active_tab()
    } else {
        return CloseOutcome::NothingToClose;
    };
    let Some(closed) = closed else {
        return CloseOutcome::NothingToClose;
    };

    // Defense in depth: a refactor that ever produced
    // `closed.scintilla_doc == closed.new_active_doc` (e.g. a
    // future "reload in place" path that reuses the existing
    // doc) would have us release the view's only ref to the
    // doc before the rebind ŌĆö UAF. Catch it as an assert in
    // debug builds; release builds rely on the structural
    // guarantee that `SCI_CREATEDOCUMENT` returns unique pointers.
    if closed.scintilla_doc != 0 && closed.new_active_doc != 0 {
        debug_assert_ne!(
            closed.scintilla_doc, closed.new_active_doc,
            "closed and new-active doc pointers must be distinct"
        );
    }

    // Phase 2: platform cleanup. Re-acquire the borrow; no plugin
    // code runs in this phase either (TCM_*, SCI_* are all
    // synchronous and don't re-enter our wnd_proc).
    if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        // Nuclear-resync the visible strip: delete every item the
        // tab control holds and re-insert from `state.shell.tabs`.
        // This is heavier than a single `TCM_DELETEITEM` for the
        // closed index, but it's the only reliable way to reset
        // the tab control's internal overflow-scroll state ŌĆö see
        // `force_tab_strip_resync`'s doc-comment for the full
        // rationale (the user-reported bug where closing tabs at
        // the left edge of a scrolled strip leaves the visible
        // region empty even though tabs still exist).
        unsafe {
            force_tab_strip_resync(state);
        }

        // Release the closed tab's Scintilla document. The view
        // is still bound to it at this point, so Scintilla's
        // implicit view-ownership keeps the buffer alive until
        // the rebind below; the SCI_RELEASEDOCUMENT here drops
        // our external reference. Skip when the doc was never
        // materialized (background-loaded tab closed before
        // first activation ŌĆö no `SCI_CREATEDOCUMENT` was issued).
        if closed.scintilla_doc != 0 {
            state
                .editor
                .send(SCI_RELEASEDOCUMENT, 0, closed.scintilla_doc);
        }

        // Rebind the view to whatever's now active. Three sub-
        // cases:
        //
        //  1. New active tab has a materialized doc ŌĆö straight
        //     SCI_SETDOCPOINTER. View releases the just-released
        //     `closed.scintilla_doc` (now its final release ŌåÆ
        //     buffer freed) and AddRefs the new doc.
        //  2. New active tab has *no* materialized doc (it was
        //     loaded in the background and never activated).
        //     **Must** lazy-create + populate the doc here, not
        //     defer to a future click: leaving the view bound to
        //     the just-released document would create a use-after-
        //     free window where any keystroke or paint touches a
        //     buffer whose external refcount is zero.
        //  3. No new active tab (closed the last open tab). Bind
        //     the view to a fresh empty placeholder doc so the user
        //     sees an empty editor ŌĆö not the just-closed file's
        //     stale content. Without this, Scintilla's view-implicit
        //     ref keeps the closed doc alive and visible until the
        //     next open's `activate_tab` rebinds the view, which
        //     produces the visible "closed file's text remained on
        //     screen" bug.
        if state.shell.active_tab.is_none() {
            // Refcount lifecycle:
            //   CREATE         ŌåÆ placeholder.refcount = 1 (our ref)
            //   SETDOCPOINTER  ŌåÆ view AddRefs new + Releases whatever
            //                    was previously bound. If we held a
            //                    materialized closed.scintilla_doc it
            //                    was already explicitly RELEASEDOCUMENT'd
            //                    above (refcount 1 ŌåÆ view's implicit
            //                    ref); SETDOCPOINTER's view-Release
            //                    drops that to 0, freeing it.
            //                    placeholder.refcount becomes 2.
            //   RELEASEDOCUMENT ŌåÆ placeholder.refcount = 1, just the
            //                    view's implicit ref. The next
            //                    SETDOCPOINTER (from a future open's
            //                    activate_tab) drops that final ref
            //                    and the placeholder is freed cleanly.
            //
            // Guard against a NULL CREATEDOCUMENT return (Scintilla
            // returns 0 on allocation failure). Using 0 as the lparam
            // for RELEASEDOCUMENT would invoke release-of-null which
            // isn't part of the public ABI contract; guard the whole
            // block so on OOM we leave the view in whatever state
            // Scintilla's own fallback produces ŌĆö same observable
            // behaviour as before this fix and not worse.
            let placeholder = state
                .editor
                .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT);
            if placeholder != 0 {
                state.editor.send(SCI_SETDOCPOINTER, 0, placeholder);
                // Seed the placeholder's empty line 0 so the
                // line-number bar shows "1" instead of blank
                // chrome on the empty editor.
                populate_visible_line_numbers(&state.editor);
                // Deliberately no `enable_change_history` here:
                // the placeholder is bound for one paint cycle,
                // immediately released, and write-protected by
                // the no-active-tab UI state (Ctrl+S, paste, and
                // every other text-mutating command short-circuit
                // when `Shell.active_tab` is `None`). A history
                // tracker on this doc would never observe an
                // edit before the doc is freed.
                state.editor.send(SCI_RELEASEDOCUMENT, 0, placeholder);
            }
            // Refresh chrome to the empty state ŌĆö status bar should
            // reflect the no-buffer state. The title bar gets
            // refreshed unconditionally in Phase 3 below
            // (`update_window_title`), which already handles the
            // `active_tab.is_none()` case by rendering just "Code++".
            let mut win32_ui = Win32Ui {
                status_hwnd: state.status_hwnd,
                tab_hwnd: state.tab_hwnd,
                toolbar_hwnd: state.toolbar_hwnd,
                main_menu: state.main_menu,
                // SAFETY: see the `accel_handle` field doc on
                // `Win32Ui` ŌĆö pointer valid for the life of
                // `WindowState`, dereferenced on the UI thread
                // only.
                accel_handle: &raw mut state.accel_handle,
                plugin_modeless_dialogs: &raw mut state.plugin_modeless_dialogs,
                dock_dialogs: &raw mut state.dock_dialogs,
                udl_registry: &raw const state.shell.udl_registry,
                editor: state.editor,
                docmap_editor: state.docmap_editor,
            };
            <Win32Ui as UiPlatform>::update_status(
                &mut win32_ui,
                codepp_core::lang::L_TEXT,
                &Encoding::default(),
                Eol::default(),
                0,
            );
        }
        if let Some(active_idx) = state.shell.active_tab {
            if closed.new_active_doc != 0 {
                state
                    .editor
                    .send(SCI_SETDOCPOINTER, 0, closed.new_active_doc);
            } else if let Some(text) = state.shell.tabs.get(active_idx).map(|t| t.text.clone()) {
                // Sub-case 2: lazily materialize the doc from the
                // tab's stored text. `tabs.get(active_idx)` rather
                // than `[active_idx]` so a future refactor that
                // could put `active_tab` out of range fails as a
                // missed-rebind no-op rather than a panic across
                // the `extern "system"` wnd_proc frame. Same
                // pattern as `handle_tab_selchange`'s lazy-create
                // branch.
                let new_doc = state
                    .editor
                    .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT);
                state.editor.send(SCI_SETDOCPOINTER, 0, new_doc);
                // Per-doc state ŌĆö every fresh document needs
                // change-history enabled AND tab width re-applied
                // (`SCI_SETTABWIDTH` is per-document; see the
                // `apply_tab_width` doc). The view-side margin
                // already exists from `apply_change_history_margin`
                // at editor creation.
                enable_change_history(&state.editor);
                apply_tab_width(&state.editor);
                let mut bytes = Vec::with_capacity(text.len() + 1);
                bytes.extend_from_slice(text.as_bytes());
                bytes.push(0);
                state.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
                state.editor.send(SCI_EMPTYUNDOBUFFER, 0, 0);
                state.editor.send(SCI_SETSAVEPOINT, 0, 0);
                if let Some(tab) = state.shell.tabs.get_mut(active_idx) {
                    tab.scintilla_doc = new_doc;
                }
            }

            // Sync the visual selection on the tab strip with
            // the new active index.
            unsafe {
                SendMessageW(
                    state.tab_hwnd,
                    TCM_SETCURSEL,
                    Some(WPARAM(active_idx)),
                    Some(LPARAM(0)),
                );
            }

            // Re-apply the new active tab's lexer/theme AND refresh
            // the status bar. Both fields live on the *view* (lexer
            // attachment) and the chrome (status bar text), neither
            // of which the rebind above touches ŌĆö without these
            // calls the user sees the closed tab's colours and
            // status text after the close. The two snapshots happen
            // together so we hold the &Tab borrow once. Pulled out
            // of the borrow scope by Copy: status_hwnd is HWND and
            // editor is EditorHandle, both Copy; the Win32Ui
            // methods only touch self.{editor,status_hwnd}, so the
            // outer &mut state borrow stays sound across the calls.
            let snapshot = state
                .shell
                .tabs
                .get(active_idx)
                .map(|t| (t.lang, t.encoding.clone(), t.eol, t.byte_len));
            if let Some((lang, encoding, eol, byte_len)) = snapshot {
                let mut win32_ui = Win32Ui {
                    status_hwnd: state.status_hwnd,
                    tab_hwnd: state.tab_hwnd,
                    toolbar_hwnd: state.toolbar_hwnd,
                    main_menu: state.main_menu,
                    accel_handle: &raw mut state.accel_handle,
                    plugin_modeless_dialogs: &raw mut state.plugin_modeless_dialogs,
                    dock_dialogs: &raw mut state.dock_dialogs,
                    udl_registry: &raw const state.shell.udl_registry,
                    editor: state.editor,
                    docmap_editor: state.docmap_editor,
                };
                <Win32Ui as UiPlatform>::apply_lang(&mut win32_ui, lang);
                <Win32Ui as UiPlatform>::update_status(
                    &mut win32_ui,
                    lang,
                    &encoding,
                    eol,
                    byte_len,
                );
                // Same SCI_SETDOCPOINTER-doesn't-fire-SCN_UPDATEUI
                // story as `handle_tab_selchange`: refresh toolbar
                // state explicitly so Undo/Redo and view-toggle
                // checks reflect the now-active buffer.
                // SAFETY: `state.toolbar_hwnd` is owned by us;
                // `state.editor` is bound to the active doc.
                unsafe {
                    toolbar::refresh_state(state.toolbar_hwnd, &state.editor);
                }
            }
        }
    }

    // Phase 3: chrome refresh + notification delivery. No state
    // borrow held while plugin code runs.
    unsafe {
        if let Some(state) = state_from_hwnd(hwnd) {
            update_window_title(hwnd, &state.shell);
        }
        fire_queued_notifications(hwnd);
    }
    // Sync the Document Map's miniature view to the surviving
    // active tab. The "no tabs left" path invokes
    // `ensure_one_tab`, which calls `shell.new_untitled(&mut ui)`
    // ŌĆö that trip through `Win32Ui::activate_tab` handles the
    // map sync via the primary path. This explicit call covers
    // the surviving-active-tab close case where the Win32-side
    // rebind above (`SCI_SETDOCPOINTER` on the main view for the
    // new active doc) doesn't go through the trait method.
    // Runs after the notifications block so a re-entrant plugin
    // can't race the sync.
    unsafe {
        sync_docmap_to_active_tab(hwnd);
    }
    CloseOutcome::Closed
}

/// Handle a tab-strip selection change (`TCN_SELCHANGE`). Reads the
/// freshly-selected index off the control, updates
/// `Shell.active_tab`, binds the Scintilla view to that tab's
/// document, and refreshes the status bar so encoding/EOL/size
/// reflect the new tab.
///
/// If the target tab has no document yet (`scintilla_doc == 0`),
/// it's a tab whose load completed while it wasn't active ŌĆö
/// `apply_load_result` populated `tab.text` but skipped the
/// Scintilla document entirely. We materialize the document
/// lazily here: create one, push the tab's stored text, store the
/// pointer back on the tab. Subsequent switches short-circuit.
///
/// Handle `SCN_STYLENEEDED` for a UDL buffer. Called from the
/// `WM_NOTIFY` arm when the active tab's language is inside the
/// UDL dynamic-id range. `target` is the notification's
/// `position` field ŌĆö the byte offset up to which Scintilla
/// wants styling applied.
///
/// If the active tab isn't a UDL (or the registry lookup
/// fails), the function returns without painting ŌĆö Scintilla
/// simply leaves the range at whatever style it currently
/// carries. This is the graceful-degradation shape: a UDL
/// buffer whose registry entry got dropped between
/// `apply_udl_lang` and the notification (impossible today
/// but defensive) renders as plain text instead of crashing.
///
/// **Known m1c-3b-1 limitation** ŌĆö this handler tokenises from
/// a line boundary near `endStyled` without any per-line
/// initial-state carry-over. A multi-line block comment /
/// delimiter span whose opening line falls before the current
/// paint range will mis-style on the first edit inside the
/// span. The fix (tracked follow-up under Phase 4.6 m1c
/// polish): persist per-line initial state via
/// `SCI_SETLINESTATE`, walk back to a line with
/// known-default state before starting the tokenise.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
///
/// **Load-bearing borrow discipline**: `state_from_hwnd` is
/// dropped BEFORE any `editor.send(...)` call. Every
/// `SCI_SETSTYLING` in the paint loop synchronously fires
/// `SCN_MODIFIED(ChangeStyle)` via `Document::SetStyleFor`
/// (`vendor/scintilla/src/Document.cxx:2418-2432` ŌĆö no
/// `modEventMask` override to suppress it), which re-enters
/// `main_wnd_proc`'s `WM_NOTIFY` dispatcher synchronously. If
/// we still held `&WindowState` at that point, the reentrant
/// `SCN_MODIFIED` handler's attempt to re-borrow would violate
/// Rust's aliasing rules. Clone the definition out of the
/// borrow, drop the borrow, then paint.
unsafe fn handle_udl_style_needed(hwnd: HWND, target: usize) {
    let Some(state) = (unsafe { state_from_hwnd(hwnd) }) else {
        return;
    };
    let Some(active_idx) = state.shell.active_tab else {
        return;
    };
    let Some(tab) = state.shell.tabs.get(active_idx) else {
        return;
    };
    let lang_id = tab.lang.as_npp_id();
    if !codepp_udl::is_udl_lang_id(lang_id) {
        return;
    }
    let Some(entry) = state.shell.udl_registry.find_by_lang_type_id(lang_id) else {
        // Registry entry vanished ŌĆö no paint, no crash. Log
        // once so a future contributor can spot this in `-v`
        // output if it ever happens.
        tracing::warn!(
            lang = lang_id,
            "SCN_STYLENEEDED for UDL LangType not in registry; skipping paint"
        );
        return;
    };
    // Cheap `Arc` clone rather than deep-copying the whole
    // definition ŌĆö the whole point of `UdlEntry::compiled` is
    // that this hot path (fires on every keystroke) doesn't
    // rebuild the keyword-class tables. Was
    // `entry.definition.clone()` before the caching layer
    // landed. See `UdlCompiledRules`'s docstring for the
    // DESIGN.md ┬¦8 keystroke-budget rationale.
    let compiled = std::sync::Arc::clone(&entry.compiled);
    let editor = state.editor;
    // Compute line-aligned tokenise range. See
    // `udl_paint::line_aligned_range` for the discipline.
    let (range_start, range_end) = udl_paint::line_aligned_range(&editor, target);
    if range_end <= range_start {
        // Nothing to style (empty range or one that inverted
        // under document-length clamping). Skip cleanly.
        return;
    }
    // **Per-notification paint cap** ŌĆö reviewer-required DoS
    // defence. A plugin or a stray `SCI_COLOURISE(0, -1)` can
    // fire `SCN_STYLENEEDED` with `position` = whole-document,
    // and Scintilla synchronously blocks the UI thread until
    // the handler returns. Cap the per-call paint at 64 KiB
    // (line-aligned). Each `SCI_SETSTYLING` advances Scintilla's
    // `endStyled`, so any bytes past the cap trigger a fresh
    // `SCN_STYLENEEDED` on Scintilla's next paint iteration.
    // The tokeniser is linear-time; 64 KiB is well inside
    // DESIGN.md ┬¦8's keystroke budget.
    const MAX_TOKENISE_RANGE: usize = 64 * 1024;
    let capped_end = range_start
        .saturating_add(MAX_TOKENISE_RANGE)
        .min(range_end);
    // Re-align to end-of-line so a mid-line cap doesn't produce
    // a partial-delimiter tail.
    let capped_line = editor.line_from_position(capped_end);
    let doc_len = editor.send(SCI_GETLENGTH, 0, 0).max(0) as usize;
    let capped_range_end = editor
        .position_from_line(capped_line + 1)
        .unwrap_or(doc_len)
        .min(range_end);
    let range_len = capped_range_end - range_start;
    let Some(bytes) = editor.get_range_bytes(range_start, range_len) else {
        return;
    };
    udl_paint::paint_udl_range(&editor, &compiled, range_start, &bytes);
}

/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_tab_selchange(hwnd: HWND) {
    let Some(state) = (unsafe { state_from_hwnd(hwnd) }) else {
        return;
    };
    // SAFETY: tab_hwnd is a live HWND created in `run`.
    let new_idx = unsafe { SendMessageW(state.tab_hwnd, TCM_GETCURSEL, None, None).0 as isize };
    if new_idx < 0 {
        return;
    }
    let new_idx = new_idx as usize;
    if new_idx >= state.shell.tabs.len() {
        // The control's selection is out of sync with the data
        // model ŌĆö defensive only; should never happen because
        // sync_tab_strip keeps them in lockstep.
        return;
    }
    state.shell.active_tab = Some(new_idx);

    // Snapshot what we need from the tab, then drop the borrow
    // before reaching for `state.editor` (a Copy field) so we can
    // call into Scintilla without a live `&mut Tab` borrow.
    let (mut doc, text_to_populate, encoding, eol, byte_len, lang) = {
        let tab = &state.shell.tabs[new_idx];
        (
            tab.scintilla_doc,
            if tab.scintilla_doc == 0 {
                Some(tab.text.clone())
            } else {
                None
            },
            tab.encoding.clone(),
            tab.eol,
            tab.byte_len,
            tab.lang,
        )
    };

    // Lazily populate the doc on first activation of a background-
    // loaded tab. Create the doc, bind it, push the saved text.
    if let Some(text) = text_to_populate {
        doc = state
            .editor
            .send(SCI_CREATEDOCUMENT, 0, SC_DOCUMENTOPTION_DEFAULT);
        state.editor.send(SCI_SETDOCPOINTER, 0, doc);
        // Per-doc state ŌĆö every fresh document needs change-history
        // enabled AND tab width re-applied (`SCI_SETTABWIDTH` is
        // per-document; see the `apply_tab_width` doc). Margin
        // configuration was applied once at editor creation and
        // lives on the view, so it carries through every doc swap.
        // Critical to call `enable_change_history` BEFORE
        // `SCI_SETTEXT` so the initial text-insert is treated as
        // the document's starting state (not as edits to track).
        enable_change_history(&state.editor);
        apply_tab_width(&state.editor);
        let mut bytes = Vec::with_capacity(text.len() + 1);
        bytes.extend_from_slice(text.as_bytes());
        bytes.push(0);
        state.editor.send(SCI_SETTEXT, 0, bytes.as_ptr() as isize);
        state.editor.send(SCI_EMPTYUNDOBUFFER, 0, 0);
        state.editor.send(SCI_SETSAVEPOINT, 0, 0);
        state.shell.tabs[new_idx].scintilla_doc = doc;
    } else {
        // Doc already exists ŌĆö just rebind the view.
        state.editor.send(SCI_SETDOCPOINTER, 0, doc);
    }

    // Refresh the status bar so encoding/EOL/size match the
    // newly-active tab. Without this, the user sees the old tab's
    // stats until the next `WM_APP_WAKE` drain (which has no
    // reason to fire on a click-only switch).
    let mut win32_ui = Win32Ui {
        status_hwnd: state.status_hwnd,
        tab_hwnd: state.tab_hwnd,
        toolbar_hwnd: state.toolbar_hwnd,
        main_menu: state.main_menu,
        accel_handle: &raw mut state.accel_handle,
        plugin_modeless_dialogs: &raw mut state.plugin_modeless_dialogs,
        dock_dialogs: &raw mut state.dock_dialogs,
        udl_registry: &raw const state.shell.udl_registry,
        editor: state.editor,
        docmap_editor: state.docmap_editor,
    };
    // Re-apply the new tab's lexer/theme. Each tab carries its own
    // LangType; without this call the previous tab's lexer stays
    // bound to the single Scintilla view and colours the new
    // buffer with the wrong rules (or, if the previous tab was
    // L_TEXT, leaves a coloured buffer un-styled).
    <Win32Ui as UiPlatform>::apply_lang(&mut win32_ui, lang);
    <Win32Ui as UiPlatform>::update_status(&mut win32_ui, lang, &encoding, eol, byte_len);

    // Refresh toolbar state for the newly-bound buffer. Same
    // rationale as the status-bar update above: `SCI_SETDOCPOINTER`
    // (the message that bound the new doc to our view) does not
    // fire `SCN_UPDATEUI` per `Editor.cxx::SetDocPointer` ŌĆö only
    // `Redraw()`. Without this explicit refresh the toolbar's
    // Undo/Redo enabled state and view-toggle checks would keep
    // showing the previous tab's state until the user next types
    // or moves the caret. SAFETY: `state.toolbar_hwnd` is the
    // toolbar we own; `state.editor` is bound to the just-
    // attached doc.
    unsafe {
        toolbar::refresh_state(state.toolbar_hwnd, &state.editor);
    }

    // Reflect the new active tab in the window title.
    // SAFETY: caller's UI-thread contract carries to update_window_title.
    unsafe {
        update_window_title(hwnd, &state.shell);
    }

    // Queue NPPN_BUFFERACTIVATED for plugins that track the
    // active buffer. The borrow on `state` is released by NLL at
    // its last use here (the queue method), before
    // `fire_queued_notifications` re-acquires a fresh borrow.
    state.shell.queue_buffer_activated();
    // Repaint the entire tab strip so both the previously-active
    // and newly-active cells redraw with their correct active /
    // inactive styling. The system tab control invalidates only
    // the cells it knows about (the new selection's cell on
    // `TCM_SETCURSEL`), but our owner-draw paint reads
    // `state.shell.active_tab` per cell ŌĆö that membership flips
    // for two cells on every selection change, so without this
    // both the outgoing and incoming styles can lag until an
    // unrelated event (mouse hover, window expose) forces a
    // repaint.
    let tab_hwnd = state.tab_hwnd;
    // SAFETY: tab_hwnd is the live tab control we own; passing
    // None for the rect invalidates the whole client area.
    unsafe {
        let _ = InvalidateRect(Some(tab_hwnd), None, false);
    }
    // SAFETY: caller's UI-thread contract carries.
    unsafe {
        fire_queued_notifications(hwnd);
    }
    // Point the Document Map's miniature view at the newly-
    // active tab's document. Runs regardless of panel
    // visibility ŌĆö a tab switch while the panel is hidden still
    // rebinds so the doc's Scintilla refcount stays coherent
    // (map view's `SCI_SETDOCPOINTER(new)` releases its
    // previous binding, letting the old tab's doc drop to
    // refcount 1 or 0 as appropriate). Also cheap: one
    // direct-call.
    unsafe {
        sync_docmap_to_active_tab(hwnd);
    }
}

/// Sanitize a filename string for display in chrome (tab labels,
/// window titles): strip embedded NULs, CR/LF/TAB, and cap at
/// `TAB_LABEL_MAX_TCHARS - 1` UTF-16 code units. Without this:
///
///   - An embedded U+0000 (legal on some network filesystems,
///     trivially injectable via `NPPM_DOOPEN` from a plugin)
///     truncates `SetWindowTextW`/`SB_SETTEXTW` silently ŌĆö the
///     chrome no longer reflects the real open file, confusing
///     users into acting on the wrong file.
///   - CR/LF/TAB render as glyph noise on tab strips and may
///     produce odd line wrapping in title bars.
///   - Multi-MB paths (legal on some filesystems) produce huge
///     temporary allocations on every chrome refresh.
fn sanitize_filename_for_display(name: &str) -> String {
    let cleaned: String = name
        .chars()
        .filter(|&c| !matches!(c, '\0' | '\r' | '\n' | '\t'))
        .collect();
    // Cap by char count rather than code-unit count for simplicity;
    // the difference is small for chrome strings and stays safely
    // under the wide-buffer cap downstream.
    if cleaned.chars().count() > TAB_LABEL_MAX_TCHARS - 1 {
        cleaned.chars().take(TAB_LABEL_MAX_TCHARS - 1).collect()
    } else {
        cleaned
    }
}

/// Set the main window's title to reflect the currently-active tab:
/// `"<filename> - Code++"` when there's an active path,
/// `"Untitled - Code++"` when the active tab has no path yet,
/// `"Code++"` when no tab is open. Called whenever `Shell.active_tab`
/// changes (tab click, sync after open, plugin-driven switch).
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn update_window_title(hwnd: HWND, shell: &Shell) {
    // Reuse `tab_display_name` so the title reflects the same
    // resolution order the tab label uses (custom_name ŌåÆ path
    // basename ŌåÆ `new N`). Without this the title would still
    // show the on-disk filename or "Untitled" even after a
    // File ŌåÆ Rename..., creating a visual mismatch with the tab.
    let title = match shell.active() {
        Some(tab) => format!("{} - Code++", tab_display_name(tab)),
        None => "Code++".to_string(),
    };
    let wide: Vec<u16> = title.encode_utf16().chain(std::iter::once(0)).collect();
    // SAFETY: hwnd is a valid main-window HWND owned by the caller's
    // thread; `wide` is a null-terminated UTF-16 buffer that lives
    // for the duration of the synchronous SetWindowTextW call.
    unsafe {
        let _ = SetWindowTextW(hwnd, PCWSTR(wide.as_ptr()));
    }
}

/// Bring the Win32 tab strip into sync with `state.shell.tabs`.
/// Inserts a tab item for each new `Shell.tabs[i]` past the count
/// the strip already knows about, using the file's basename (or
/// "Untitled" if the tab has no path yet) as the label. Then
/// snaps the tab control's selection to `state.shell.active_tab`
/// so a click elsewhere or a programmatic switch (`NPPM_SWITCHTOFILE`)
/// is reflected visually.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `state`'s HWNDs.
/// Bring the visible tab strip and window title into sync with
/// `state.shell` after a synchronous Shell mutation that doesn't
/// route through the loader (and so doesn't naturally trigger a
/// `WM_APP_WAKE`). Used by the File menu handlers (New, Open,
/// Reload, Close, Close All, Save As) ŌĆö each one mutates
/// `shell.tabs` or `shell.active_tab` in place and then calls
/// this so the user sees the change immediately rather than
/// after the next message-pump cycle.
///
/// # Safety
///
/// Caller must hold the UI thread's `&mut WindowState` borrow and
/// not be in the middle of a plugin callback (`sync_tab_strip`
/// sends synchronous TCM_* messages but doesn't re-enter `wnd_proc`
/// for them).
/// Run the Save As flow: prompt for a destination path (pre-filled
/// with the active tab's current basename), then route through
/// `Shell::save_buffer_as`. Used by both the explicit FileŌåÆSave As
/// menu path and the FileŌåÆSave fallback when the active tab has no
/// path (an untitled buffer can't Ctrl+S to "the active path"
/// because there isn't one ŌĆö we redirect to Save As instead of
/// surfacing a confusing "no active file path" error).
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn run_save_as_flow(hwnd: HWND) {
    let suggestion = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        state
            .shell
            .active()
            .and_then(|t| t.path.as_ref())
            .and_then(|p| p.file_name())
            .and_then(|s| s.to_str())
            .map(std::string::ToString::to_string)
    } else {
        None
    };
    let new_path = prompt_save_path(hwnd, suggestion.as_deref());
    let save_error: Option<String> = if let Some(p) = new_path {
        if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
            let (shell, mut ui) = state.split();
            let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                shell.save_buffer_as(&mut ui, p)
            }));
            match result {
                Ok(Ok(())) => None,
                Ok(Err(e)) => Some(e.to_string()),
                Err(_) => Some("internal panic during save".to_string()),
            }
        } else {
            None
        }
    } else {
        None
    };
    if let Some(msg) = save_error {
        show_error_dialog(hwnd, "Save As failed", &msg);
    }
    // save_buffer_as updates the tab's path on success ŌĆö refresh
    // the strip so the label switches from "new N" (or the old
    // basename) to the new file's basename.
    unsafe { refresh_tab_chrome(hwnd) };
}

/// Enforce the "always at least one tab" invariant: if `shell.tabs`
/// is empty after a close path (Close, Close All, startup with no
/// session and no CLI path), create a fresh untitled buffer so the
/// user always sees an editor with at least one tab visible.
///
/// Notepad++ has the same invariant ŌĆö closing the last tab pops a
/// "new 1" tab into existence rather than leaving an empty editor
/// chrome with no tab to type into.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn ensure_one_tab(hwnd: HWND) {
    let created = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        if state.shell.tabs.is_empty() {
            let (shell, mut ui) = state.split();
            // catch_unwind: same defensive shape as the menu
            // handlers ŌĆö a panic inside Shell or Win32Ui can't
            // unwind across the wnd_proc's `extern "system"` frame.
            let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                shell.new_untitled(&mut ui);
            }));
            true
        } else {
            false
        }
    } else {
        false
    };
    // Only refresh chrome when we actually created a new tab ŌĆö the
    // close-path callers already ran `sync_tab_strip` once via
    // `handle_close_active_tab_inner`, and the WM_APP_WAKE caller
    // ran it during the drain. A redundant double-refresh is a
    // wasteful TCM_INSERTITEMW + TCM_SETCURSEL pair on every
    // close, observable in traces.
    if created {
        unsafe { refresh_tab_chrome(hwnd) };
    }
}

unsafe fn refresh_tab_chrome(hwnd: HWND) {
    if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        // SAFETY: caller holds the UI-thread invariant. Both
        // helpers are `unsafe fn` because they send Win32 messages
        // and read `state` through a raw pointer dance, but
        // neither re-enters wnd_proc synchronously, so the borrow
        // we hold here is exclusive for their duration.
        unsafe {
            sync_tab_strip(state);
            update_window_title(hwnd, &state.shell);
        }
    }
}

/// Nuclear-option re-sync of the visible tab strip: delete every
/// item the Win32 control holds, reset our `synced_tab_count`, then
/// re-insert all tabs from `state.shell.tabs` via the standard
/// [`sync_tab_strip`] path.
///
/// **Why this exists:** the Win32 tab control's overflow-scroll
/// state (driven by an internal `msctls_updown32` spinner) doesn't
/// reliably clamp on `TCM_DELETEITEM`. After closing tabs that
/// formed the visible region of a horizontally-scrolled strip, the
/// control's scroll-pos can stay pointing past the (now smaller)
/// item list ŌĆö the user sees an empty overflow region even though
/// tabs still exist. `WM_SIZE` to the same dimensions doesn't
/// re-trigger the clamp (the handler short-circuits on no-op size
/// changes), and there's no public message to "scroll active into
/// view". The only documented way to fully reset internal state is
/// to delete all items; on re-insert the control rebuilds its
/// scroll bounds from scratch.
///
/// Cost: one `TCM_DELETEALLITEMS` plus N `TCM_INSERTITEMW` calls.
/// For typical workloads (Ōēż100 tabs) that's a few microseconds per
/// close ŌĆö well below the perceptual threshold and below the
/// per-keystroke budget in DESIGN.md ┬¦8.
///
/// # Safety
///
/// Caller must hold the UI thread's `&mut WindowState` borrow. The
/// `SendMessageW` calls dispatch synchronously into the common-
/// control's `WndProc` and don't re-enter our `wnd_proc`.
unsafe fn force_tab_strip_resync(state: &mut WindowState) {
    // SAFETY: tab_hwnd is a valid HWND created in `run`; both
    // messages take no pointer arguments.
    unsafe {
        SendMessageW(
            state.tab_hwnd,
            TCM_DELETEALLITEMS,
            Some(WPARAM(0)),
            Some(LPARAM(0)),
        );
    }
    state.synced_tab_count = 0;
    unsafe {
        sync_tab_strip(state);
    }
}

unsafe fn sync_tab_strip(state: &mut WindowState) {
    while state.synced_tab_count < state.shell.tabs.len() {
        let idx = state.synced_tab_count;
        let label = tab_label_for(&state.shell.tabs[idx]);
        // TCITEMW.pszText is `*mut u16`; the wide buffer must
        // outlive the SendMessage call. The `label_storage` vec
        // is the buffer, kept alive for the call duration.
        let mut label_storage = label;
        let mut item = TCITEMW {
            mask: windows::Win32::UI::Controls::TCITEMHEADERA_MASK(0x0001), // TCIF_TEXT
            pszText: windows::core::PWSTR(label_storage.as_mut_ptr()),
            ..Default::default()
        };
        // SAFETY: tab_hwnd is a valid HWND (created in `run`); item
        // points to live wide-char storage that lives across the
        // SendMessage call.
        unsafe {
            SendMessageW(
                state.tab_hwnd,
                TCM_INSERTITEMW,
                Some(WPARAM(idx)),
                Some(LPARAM(&raw mut item as isize)),
            );
        }
        state.synced_tab_count += 1;
    }

    // Refresh the labels of tabs already on the strip. Without
    // this, a tab that was inserted while its `path` was still
    // None (synced as "Untitled" right after `open_file`) keeps
    // the placeholder label after `apply_load_result` populates
    // its real path: the insert-only loop above never revisits
    // existing items. TCM_SETITEMW with the same payload shape
    // updates a single TCITEM field in place.
    for idx in 0..state.synced_tab_count {
        // `.get(idx)` rather than `[idx]` so a future refactor
        // that ever lets `synced_tab_count` drift past
        // `shell.tabs.len()` degrades to a missing-update no-op
        // for that one tab rather than panicking across the
        // `extern "system"` wnd_proc frame.
        let Some(tab) = state.shell.tabs.get(idx) else {
            break;
        };
        let label = tab_label_for(tab);
        let mut label_storage = label;
        let mut item = TCITEMW {
            mask: windows::Win32::UI::Controls::TCITEMHEADERA_MASK(0x0001), // TCIF_TEXT
            pszText: windows::core::PWSTR(label_storage.as_mut_ptr()),
            ..Default::default()
        };
        // SAFETY: `state.tab_hwnd` is a live HWND created in
        // `run`; `&mut item` and `label_storage` both stay live
        // for the duration of the synchronous SendMessageW call.
        // TCM_SETITEMW does not re-enter our wnd_proc.
        unsafe {
            SendMessageW(
                state.tab_hwnd,
                TCM_SETITEMW,
                Some(WPARAM(idx)),
                Some(LPARAM(&raw mut item as isize)),
            );
        }
    }

    // Reflect the active tab index on the visual control. Done
    // unconditionally so external switches (NPPM_SWITCHTOFILE,
    // future shortcut routing) keep the tab strip in lockstep.
    if let Some(active_idx) = state.shell.active_tab {
        // SAFETY: tab_hwnd is valid; the result is unused.
        unsafe {
            SendMessageW(
                state.tab_hwnd,
                TCM_SETCURSEL,
                Some(WPARAM(active_idx)),
                Some(LPARAM(0)),
            );
        }
    }
}

/// Build the wide-char tab label for `tab`: the file basename if
/// the tab has a path, else "Untitled". Trailing NUL is appended so
/// the buffer can be passed to `TCITEMW.pszText` directly.
///
/// The output is capped at `TAB_LABEL_MAX_TCHARS - 1` UTF-16 code
/// units (plus the trailing NUL). Without a cap, a path whose
/// `file_name()` is multiple-MB long (legal on some network
/// filesystems) would produce an equally long allocation and a
/// degenerate tab strip. Embedded control characters (`\n`,
/// `\r`, `\t`) are stripped ŌĆö they're legal on some filesystems
/// but render as glyph noise on the tab strip.
const TAB_LABEL_MAX_TCHARS: usize = 260;

/// The user-facing display name for a tab ŌĆö same string the tab
/// strip renders. Three sources, in order:
///   1. Real path ŌåÆ `file_name` basename (the common case).
///   2. No path but `untitled_seq` set ŌåÆ "new N" (created by
///      FileŌåÆNew).
///   3. Fallback "Untitled" (a path with no parseable basename ŌĆö
///      extremely rare in practice, but a safe label for defense
///      in depth).
///
/// Embedded control characters (`\n`, `\r`, `\t`) are stripped ŌĆö
/// they're legal on some filesystems but render as glyph noise.
/// Returned as an owned `String` so callers can format it into
/// other strings (the "Save file '<name>' ?" prompt uses this);
/// [`tab_label_for`] wraps it for the Win32 tab-strip API which
/// needs a NUL-terminated UTF-16 buffer.
fn tab_display_name(tab: &Tab) -> String {
    // Resolution order: user-chosen `custom_name` (set via File ŌåÆ
    // Rename...) wins over both the on-disk filename and the
    // `new N` sequence so the renamed buffer keeps its label
    // through tab switches and session restores. `custom_name` is
    // cleared by `save_buffer_as` once the buffer gains a real
    // path, so a Saved-As-then-renamed flow correctly picks up
    // the on-disk filename.
    let owned = tab
        .custom_name
        .clone()
        .or_else(|| {
            tab.path.as_ref().and_then(|p| {
                p.file_name()
                    .and_then(|s| s.to_str())
                    .map(std::string::ToString::to_string)
            })
        })
        .unwrap_or_else(|| match tab.untitled_seq {
            Some(n) => format!("new {n}"),
            None => "Untitled".to_string(),
        });
    sanitize_filename_for_display(&owned)
}

fn tab_label_for(tab: &Tab) -> Vec<u16> {
    tab_display_name(tab)
        .encode_utf16()
        .chain(std::iter::once(0))
        .collect()
}

/// Bundle of HMENUs the `wnd_proc` and `WindowState` need to keep
/// addressable after `build_main_menu` returns. The bar itself is
/// what `CreateWindowExW` consumes; the four named popups need
/// dynamic refresh on `WM_INITMENUPOPUP` (state-driven check marks
/// or rebuilt-on-open lists). The plugin submenu is exposed
/// separately because the plugin host's `NPPM_GETMENUHANDLE` ABI
/// hands it back as a stable handle, distinct from any other host
/// menu.
struct BuiltMenuBar {
    bar: HMENU,
    plugin_menu: HMENU,
    /// File submenu. Held addressable so `WM_INITMENUPOPUP` can
    /// match against it and refresh the state-driven entries
    /// (currently just `ID_FILE_OPEN_IN_DEFAULT_VIEWER`'s enabled
    /// state, driven by the active tab's on-disk path + extension
    /// association).
    file_menu: HMENU,
    view_menu: HMENU,
    encoding_menu: HMENU,
    language_menu: HMENU,
    window_menu: HMENU,
    /// Popup HMENU for the right-shortcuts `Ō¢╝` dropdown ŌĆö the open-
    /// tabs switcher pinned to the right edge of the menu bar.
    /// Rebuilt on `WM_INITMENUPOPUP` by the same `refresh_window_menu`
    /// helper as the regular Window menu, so its items use the same
    /// `ID_WINDOW_BASE + idx` cmd ids and existing tab-switch
    /// handler.
    right_shortcuts_menu: HMENU,
}

/// Construct the full N++-shaped main menu: File, Edit, Search,
/// View, Encoding, Language, Settings, Tools, Macro, Run, Plugins,
/// Window, ?. Items that already have a real handler attached
/// (Edit's clipboard ops, View's toggles, File's Save/Close/Exit)
/// are enabled; items whose feature lands later in Phase 4+ are
/// inserted as `MF_GRAYED` placeholders so the structure is
/// observable and the cmd ids are reserved.
///
/// # Safety
///
/// `CreateMenu` / `AppendMenuW` are pure heap operations; they
/// don't re-enter our `wnd_proc`. The returned handles are owned by
/// the host process for the window's lifetime.
fn build_main_menu() -> windows::core::Result<BuiltMenuBar> {
    unsafe {
        let bar = CreateMenu()?;

        // ----- File -----
        let file_menu = CreateMenu()?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_NEW as usize,
            w!("&New\tCtrl+N"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_OPEN as usize,
            w!("&Open...\tCtrl+O"),
        )?;
        // "Open Containing Folder Ō¢Ė" submenu. Four entries, all
        // greyed on menu open when the active tab is untitled
        // (state-driven via `refresh_file_menu` on
        // WM_INITMENUPOPUP; MF_BYCOMMAND greying reaches items
        // inside nested submenus, so we don't need to track the
        // submenu HMENU separately). Each entry acts on the
        // parent directory of the active tab's on-disk path.
        let open_containing = CreateMenu()?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_EXPLORER as usize,
            w!("&Explorer"),
        )?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_CMD as usize,
            w!("&cmd"),
        )?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_POWERSHELL as usize,
            w!("&PowerShell"),
        )?;
        AppendMenuW(open_containing, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            open_containing,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_CONTAINING_WORKSPACE as usize,
            w!("Folder as &Workspace"),
        )?;
        AppendMenuW(
            file_menu,
            MF_POPUP,
            open_containing.0 as usize,
            w!("Open &Containing Folder"),
        )?;
        // Enable state is state-driven ŌĆö see [`refresh_file_menu`]
        // fired from `WM_INITMENUPOPUP` for the File menu. Starts
        // greyed because no tab exists at startup; a fresh Ctrl+N
        // or Ctrl+O flips it appropriately on the next popup.
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_OPEN_IN_DEFAULT_VIEWER as usize,
            w!("Open in &Default Viewer"),
        )?;
        // Workspace open-folder. Enabled from m2 onward ŌĆö click
        // pops the folder picker and opens the panel rooted at
        // the chosen folder.
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_OPEN_FOLDER_AS_WORKSPACE as usize,
            w!("Open Folder as &Workspace..."),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_RELOAD as usize,
            w!("&Reload from Disk\tCtrl+R"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE as usize,
            w!("&Save\tCtrl+S"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE_AS as usize,
            w!("Save &As...\tCtrl+Alt+S"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE_ALL as usize,
            w!("Sav&e All\tCtrl+Shift+S"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_RENAME as usize,
            w!("Re&name...\tF2"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_CLOSE as usize,
            w!("&Close\tCtrl+W"),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_CLOSE_ALL as usize,
            w!("Close A&ll\tCtrl+Shift+W"),
        )?;
        // "Close Multiple Documents Ō¢Ė" submenu. Five variants,
        // each closing a specific subset of the open tabs. All
        // reuse the single-tab close path (dirty prompt + Cancel
        // shortcircuit) so a dirty buffer produces the same
        // Save/Don't Save/Cancel dialog as Ctrl+W. Per-entry
        // greying is driven by `refresh_file_menu` on
        // WM_INITMENUPOPUP.
        let close_multi = CreateMenu()?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_BUT_ACTIVE as usize,
            w!("Close All but &Active Document"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_BUT_PINNED as usize,
            w!("Close All but &Pinned Documents"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_TO_LEFT as usize,
            w!("Close All To the &Left"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_TO_RIGHT as usize,
            w!("Close All To the &Right"),
        )?;
        AppendMenuW(
            close_multi,
            MF_STRING | MF_GRAYED,
            ID_FILE_CLOSE_ALL_UNCHANGED as usize,
            w!("Close All &Unchanged"),
        )?;
        AppendMenuW(
            file_menu,
            MF_POPUP,
            close_multi.0 as usize,
            w!("Close &Multiple Documents"),
        )?;
        // Greyed for untitled buffers via `refresh_file_menu` ŌĆö
        // MF_GRAYED here is the startup default (no tab yet
        // exists, so nothing is deletable). Matches Notepad++'s
        // File menu label + behaviour.
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_MOVE_TO_RECYCLE_BIN as usize,
            w!("Move to Recycle &Bin"),
        )?;
        AppendMenuW(file_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Session interchange (Notepad++-shape XML). Enabled at all
        // times ŌĆö Load prompts for a file regardless of what's open,
        // Save works even with zero tabs (writes an empty session).
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_LOAD_SESSION as usize,
            w!("&Load Session..."),
        )?;
        AppendMenuW(
            file_menu,
            MF_STRING,
            ID_FILE_SAVE_SESSION as usize,
            w!("Save Sess&ion..."),
        )?;
        AppendMenuW(file_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Print is greyed by `refresh_file_menu` when there's no
        // active tab or the active tab's document is empty; enabled
        // otherwise. The initial `MF_GRAYED` is a startup safe
        // default (no tab exists at menu-build time).
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_PRINT as usize,
            w!("&Print...\tCtrl+P"),
        )?;
        // Print Preview: same enable / disable discipline as
        // Print (both greyed at menu-build time; enabled by
        // `refresh_file_menu` when a tab is active).
        AppendMenuW(
            file_menu,
            MF_STRING | MF_GRAYED,
            ID_FILE_PRINT_PREVIEW as usize,
            w!("Print Pre&view..."),
        )?;
        AppendMenuW(file_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(file_menu, MF_STRING, ID_FILE_EXIT as usize, w!("E&xit"))?;
        AppendMenuW(bar, MF_POPUP, file_menu.0 as usize, w!("&File"))?;

        // ----- Edit ----- (Scintilla-backed; all enabled.)
        let edit_menu = CreateMenu()?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_UNDO as usize,
            w!("&Undo\tCtrl+Z"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_REDO as usize,
            w!("&Redo\tCtrl+Y"),
        )?;
        AppendMenuW(edit_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_CUT as usize,
            w!("Cu&t\tCtrl+X"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_COPY as usize,
            w!("&Copy\tCtrl+C"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_PASTE as usize,
            w!("&Paste\tCtrl+V"),
        )?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_DELETE as usize,
            w!("&Delete\tDel"),
        )?;
        AppendMenuW(edit_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            edit_menu,
            MF_STRING,
            ID_EDIT_SELECTALL as usize,
            w!("Select &All\tCtrl+A"),
        )?;
        AppendMenuW(bar, MF_POPUP, edit_menu.0 as usize, w!("&Edit"))?;

        // ----- Search ----- (Find/Replace wired in m3b2.)
        let search_menu = CreateMenu()?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FIND as usize,
            w!("&Find...\tCtrl+F"),
        )?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FINDNEXT as usize,
            w!("Find &Next\tF3"),
        )?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FINDPREV as usize,
            w!("Find Pre&vious\tShift+F3"),
        )?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_REPLACE as usize,
            w!("&Replace...\tCtrl+H"),
        )?;
        AppendMenuW(search_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Find in Files ŌĆö m4 step 4a opens the FIF tab in the
        // Find/Replace dialog. Step 4b will wire the Find All
        // button to actually drive `Shell::start_fif`.
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_FINDINFILES as usize,
            w!("Find in Fi&les...\tCtrl+Shift+F"),
        )?;
        AppendMenuW(search_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            search_menu,
            MF_STRING,
            ID_SEARCH_GOTOLINE as usize,
            w!("&Go to...\tCtrl+G"),
        )?;
        AppendMenuW(bar, MF_POPUP, search_menu.0 as usize, w!("&Search"))?;

        // ----- View ----- (toggles refreshed in WM_INITMENUPOPUP.)
        let view_menu = CreateMenu()?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_WORDWRAP as usize,
            w!("&Word Wrap"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_SHOWWS as usize,
            w!("Show White&space"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_SHOWEOL as usize,
            w!("Show End of &Line"),
        )?;
        AppendMenuW(view_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_ZOOMIN as usize,
            w!("Zoom &In\tCtrl++"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_ZOOMOUT as usize,
            w!("Zoom &Out\tCtrl+-"),
        )?;
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_ZOOMRESET as usize,
            w!("&Restore Zoom\tCtrl+0"),
        )?;
        AppendMenuW(view_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        // Toggle ŌĆö check state syncs to `WindowState.workspace_visible`
        // via `refresh_view_menu` (fired from `WM_INITMENUPOPUP`).
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_FOLDER_AS_WORKSPACE as usize,
            w!("&Folder as Workspace"),
        )?;
        // Document Map ŌĆö right-column mirror of the workspace
        // panel. Check state syncs to `WindowState.docmap_visible`
        // via `refresh_view_menu`.
        AppendMenuW(
            view_menu,
            MF_STRING,
            ID_VIEW_DOCMAP as usize,
            w!("&Document Map"),
        )?;
        AppendMenuW(bar, MF_POPUP, view_menu.0 as usize, w!("&View"))?;

        // ----- Encoding ----- (radio refreshed in WM_INITMENUPOPUP;
        // ANSI grayed pending the system-codepage detection path ŌĆö
        // see the WM_COMMAND handler comment for the deferral.)
        let encoding_menu = CreateMenu()?;
        AppendMenuW(
            encoding_menu,
            MF_STRING | MF_GRAYED,
            ID_ENCODING_ANSI as usize,
            w!("&ANSI"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF8 as usize,
            w!("UTF-&8 (no BOM)"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF8_BOM as usize,
            w!("UTF-8 with &BOM"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF16_LE as usize,
            w!("UTF-16 &LE BOM"),
        )?;
        AppendMenuW(
            encoding_menu,
            MF_STRING,
            ID_ENCODING_UTF16_BE as usize,
            w!("UTF-16 B&E BOM"),
        )?;
        AppendMenuW(bar, MF_POPUP, encoding_menu.0 as usize, w!("E&ncoding"))?;

        // ----- Language ----- (built from `core::lang::LANG_TABLE`.
        // cmd id = ID_LANGUAGE_BASE + lang.0. Radio refreshed in
        // WM_INITMENUPOPUP based on the active tab's lang.)
        //
        // Layout (matches Notepad++):
        //   1. "Normal Text" ŌĆö always at top, single entry.
        //   2. Separator.
        //   3. Alphabetical block. Same-first-letter groups of 2+
        //      collapse into a submenu titled by the letter;
        //      single-entry letters stay at the top level.
        //   4. Separator.
        //   5. "User-Defined language" submenu ŌĆö greyed pending the
        //      Phase 5 user-defined-language work.
        let language_menu = build_language_menu()?;
        AppendMenuW(bar, MF_POPUP, language_menu.0 as usize, w!("&Language"))?;

        // ----- Settings -----
        let settings_menu = CreateMenu()?;
        AppendMenuW(
            settings_menu,
            MF_STRING | MF_GRAYED,
            ID_SETTINGS_PREFERENCES as usize,
            w!("&Preferences..."),
        )?;
        AppendMenuW(
            settings_menu,
            MF_STRING,
            ID_SETTINGS_STYLECONFIGURATOR as usize,
            w!("&Style Configurator..."),
        )?;
        AppendMenuW(bar, MF_POPUP, settings_menu.0 as usize, w!("Se&ttings"))?;

        // ----- Tools / Macro / Run ----- (placeholder submenus ŌĆö
        // the menu *items* land alongside the features in later
        // phases; for now the top-level entries reserve the slots
        // and show as empty grayed popups.)
        let tools_menu = CreateMenu()?;
        AppendMenuW(
            tools_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(no tools wired yet)"),
        )?;
        AppendMenuW(bar, MF_POPUP, tools_menu.0 as usize, w!("&Tools"))?;

        let macro_menu = CreateMenu()?;
        AppendMenuW(
            macro_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(macro recording lands later)"),
        )?;
        AppendMenuW(bar, MF_POPUP, macro_menu.0 as usize, w!("&Macro"))?;

        let run_menu = CreateMenu()?;
        AppendMenuW(
            run_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(run-command lands later)"),
        )?;
        AppendMenuW(bar, MF_POPUP, run_menu.0 as usize, w!("R&un"))?;

        // ----- Plugins ----- (populated lazily by `populate_plugin_menu`
        // on first WM_INITMENUPOPUP; the HMENU is alive from now on
        // so plugins that query NPPM_GETMENUHANDLE before the popup
        // get a real handle.)
        let plugin_menu = CreateMenu()?;
        AppendMenuW(bar, MF_POPUP, plugin_menu.0 as usize, w!("&Plugins"))?;

        // ----- Window ----- (rebuilt every WM_INITMENUPOPUP from
        // Shell.tabs; cmd id = ID_WINDOW_BASE + tab idx.)
        let window_menu = CreateMenu()?;
        AppendMenuW(
            window_menu,
            MF_STRING | MF_GRAYED,
            0,
            w!("(no open windows)"),
        )?;
        AppendMenuW(bar, MF_POPUP, window_menu.0 as usize, w!("&Window"))?;

        // ----- ? (Help) -----
        // Order: external links first, then Update (greyed),
        // then About. Two separators split the three logical
        // groups (info-and-community, self-update, app-info).
        // The two greyed entries (`ID_HELP_MANUAL`,
        // `ID_HELP_UPDATE`) are placeholders ŌĆö their command ids
        // are reserved so the menu layout is stable across builds
        // even while the targets aren't wired.
        let help_menu = CreateMenu()?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_HOME as usize,
            w!("Code++ &Home"),
        )?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_PROJECT as usize,
            w!("Code++ &Project Page"),
        )?;
        AppendMenuW(
            help_menu,
            MF_STRING | MF_GRAYED,
            ID_HELP_MANUAL as usize,
            w!("Code++ Online User &Manual"),
        )?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_COMMUNITY as usize,
            w!("Code++ &Community (Forum)"),
        )?;
        AppendMenuW(help_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            help_menu,
            MF_STRING | MF_GRAYED,
            ID_HELP_UPDATE as usize,
            w!("&Update Code++"),
        )?;
        AppendMenuW(help_menu, MF_SEPARATOR, 0, PCWSTR::null())?;
        AppendMenuW(
            help_menu,
            MF_STRING,
            ID_HELP_ABOUT as usize,
            w!("&About Code++\tF1"),
        )?;
        AppendMenuW(bar, MF_POPUP, help_menu.0 as usize, w!("&?"))?;

        // ----- Right shortcuts -----
        // Three single-glyph top-level entries pinned to the right
        // edge of the menu bar: `+` (new untitled), `Ō¢╝` (open-tabs
        // switcher), `X` (close active tab). They form the "right
        // shortcuts" UI group; a future Settings toggle will hide
        // the group as a whole, but for now it's always shown.
        //
        // `+` and `X` reuse `ID_FILE_NEW` / `ID_FILE_CLOSE` so the
        // existing WM_COMMAND handlers light up unchanged. `Ō¢╝` is a
        // popup populated on `WM_INITMENUPOPUP` by the same
        // `refresh_window_menu` helper as the regular Window menu,
        // so the entries use the same `ID_WINDOW_BASE + idx` cmd
        // ids and the same tab-switch handler.
        //
        // Right-justification: `MFT_RIGHTJUSTIFY` on the first of
        // the three items right-aligns it and every subsequent
        // top-level item ŌĆö so the three appear `+ Ō¢╝ X` left-to-right
        // hugging the menu bar's right edge.
        // U+FF0B FULLWIDTH PLUS SIGN ŌĆö drawn at the menu font's full
        // em-square height, so the cross visually matches the `X`
        // letter to its right. ASCII `+` sits at x-height and looks
        // half the size of the neighbouring glyphs.
        AppendMenuW(bar, MF_STRING, ID_FILE_NEW as usize, w!("\u{FF0B}"))?;
        // RAII-wrap the freshly-allocated popup so a `?`-propagated
        // failure on the upcoming attach `AppendMenuW(MF_POPUP)` ŌĆö
        // before Win32 takes ownership ŌĆö frees the orphan instead
        // of leaking a kernel object. The same pattern is used in
        // `build_language_menu`. No construction-time placeholder
        // item is needed: `refresh_window_menu` clears and rebuilds
        // the popup's contents on every `WM_INITMENUPOPUP`.
        let right_shortcuts_guard = MenuGuard::wrap(CreateMenu()?);
        AppendMenuW(
            bar,
            MF_POPUP,
            right_shortcuts_guard.handle().0 as usize,
            w!("\u{25BC}"),
        )?;
        // Attach succeeded ŌĆö defuse the guard so the bar's destroy
        // cascade becomes the sole owner of the popup HMENU.
        let right_shortcuts_menu = right_shortcuts_guard.take();
        AppendMenuW(bar, MF_STRING, ID_FILE_CLOSE as usize, w!("X"))?;

        // Flip the `+` item to right-justified. `GetMenuItemCount`
        // returns the post-append total; the `+` we just appended is
        // at position `count - 3`. A failure here only affects
        // alignment (the three entries still work, they just appear
        // mixed with the left-justified menu items) ŌĆö log and carry
        // on rather than failing the menu build.
        let item_count = GetMenuItemCount(Some(bar));
        if item_count >= 3 {
            let plus_pos = (item_count - 3) as u32;
            let mut mii = MENUITEMINFOW {
                cbSize: std::mem::size_of::<MENUITEMINFOW>() as u32,
                fMask: MIIM_FTYPE,
                fType: MFT_RIGHTJUSTIFY,
                ..Default::default()
            };
            if let Err(e) = SetMenuItemInfoW(bar, plus_pos, true, &raw mut mii) {
                tracing::warn!(error = %e, "SetMenuItemInfoW(MFT_RIGHTJUSTIFY) failed");
            }
        }

        Ok(BuiltMenuBar {
            bar,
            plugin_menu,
            file_menu,
            view_menu,
            encoding_menu,
            language_menu,
            window_menu,
            right_shortcuts_menu,
        })
    }
}

/// Refresh check marks on the View menu so they reflect the live
/// Scintilla state (`SCI_GETWRAPMODE`, `SCI_GETVIEWWS`,
/// `SCI_GETVIEWEOL`). Cheap to call on every `WM_INITMENUPOPUP` ŌĆö
/// three direct-call queries plus three `CheckMenuItem` calls.
///
/// # Safety
///
/// `view_menu` must be a live HMENU (the one built by
/// `build_main_menu`); caller must run on the UI thread.
unsafe fn refresh_view_menu(
    view_menu: HMENU,
    editor: &EditorHandle,
    workspace_visible: bool,
    docmap_visible: bool,
) {
    let wrap_on = editor.send(SCI_GETWRAPMODE, 0, 0) != 0;
    let ws_on = editor.send(SCI_GETVIEWWS, 0, 0) != 0;
    let eol_on = editor.send(SCI_GETVIEWEOL, 0, 0) != 0;
    let mark = |id: u16, on: bool| {
        let flags = MF_BYCOMMAND.0 | if on { MF_CHECKED.0 } else { MF_UNCHECKED.0 };
        // CheckMenuItem returns the previous state on success or
        // -1u32 on failure; we treat both as fire-and-forget ŌĆö a
        // failure here just means the check mark is wrong on this
        // open, never a process-stability issue.
        unsafe {
            let _ = CheckMenuItem(view_menu, u32::from(id), flags);
        }
    };
    mark(ID_VIEW_WORDWRAP, wrap_on);
    mark(ID_VIEW_SHOWWS, ws_on);
    mark(ID_VIEW_SHOWEOL, eol_on);
    // Workspace toggle ŌĆö reads the cached `workspace_visible` bit
    // rather than probing the panel HWND, so the check state
    // stays in lockstep with the layout code that also gates on
    // this bit.
    mark(ID_VIEW_FOLDER_AS_WORKSPACE, workspace_visible);
    // Docmap toggle ŌĆö same cached-bit discipline.
    mark(ID_VIEW_DOCMAP, docmap_visible);
}

/// Radio-mark the menu item matching `lang` in the Language menu.
/// `CheckMenuRadioItem` ensures only one item in the range carries
/// the radio glyph at a time. Phase 4 m1 wires four langs (Normal
/// Text, C, C++, Rust); cmd ids run from `ID_LANGUAGE_BASE` upward.
///
/// # Safety
///
/// `language_menu` must be a live HMENU; caller on the UI thread.
unsafe fn refresh_language_menu(language_menu: HMENU, lang: LangType) {
    // CheckMenuRadioItem(menu, first_id, last_id, check_id, MF_BYCOMMAND).
    // The range is closed [first, last]; we use the full reserved
    // band so future `Lang` additions don't need an off-by-one
    // here. `check_id` outside the range is a no-op which keeps an
    // unrecognised lang from clearing all marks.
    //
    // `lang.as_npp_id()` is whatever i32 the plugin ABI handed us,
    // including i32::MAX from a hostile NPPM_SETBUFFERLANGTYPE.
    // Bound the value before the addition to avoid overflow on the
    // intermediate i32 stage and to keep the resulting target id
    // inside the cmd-id range Win32 will accept.
    let lang_id = lang.as_npp_id();
    // Unified pre-clear: wipe every existing bullet in BOTH the
    // built-in language range AND the UDL item range from every
    // top-level submenu (letter submenus and the "User-Defined
    // language" submenu) and every corresponding parent popup
    // entry. Without this, switching between a built-in language
    // and a UDL leaves the previous side's bullet in place ŌĆö the
    // sweep below only touches the built-in side, and
    // `refresh_udl_radio_mark` only touches the UDL side, so
    // neither reliably clears the other. The clear is idempotent
    // and cheap (one SetMenuItemInfoW per top-level submenu +
    // one inner CheckMenuItem per previously-marked item).
    unsafe { clear_all_language_menu_marks(language_menu) };
    // UDL languages live in a disjoint id space (>= 1024) that
    // maps to `ID_UDL_ITEM_BASE + offset` menu ids, not
    // `ID_LANGUAGE_BASE + id`. Route them through
    // `refresh_udl_radio_mark` so the bullet lands on the correct
    // item inside the "User-Defined language" submenu. Non-UDL
    // out-of-range values (negative or >= ID_LANGUAGE_CAP but not
    // a valid UDL id) fall through to the early return below.
    if codepp_udl::is_udl_lang_id(lang_id) {
        unsafe { set_udl_radio_mark(language_menu, lang_id) };
        return;
    }
    if lang_id < 0 || lang_id as usize >= ID_LANGUAGE_CAP {
        return;
    }
    let target = u32::from(ID_LANGUAGE_BASE) + lang_id as u32;
    // CheckMenuRadioItem only marks items in the menu it's called
    // on. With m6's first-letter submenus the active item may live
    // inside a child popup, so we apply the call to the top-level
    // menu *and* every immediate-child submenu. CheckMenuRadioItem
    // is a no-op on a menu that doesn't contain `target`, so the
    // sweep is harmless on unrelated submenus and idempotent on
    // re-application.
    //
    // **Two-level visibility:** when the active language lives
    // inside a letter submenu (e.g. Perl inside the "P" submenu),
    // `CheckMenuRadioItem` on the submenu marks the language item
    // ŌĆö but the user only sees that bullet after hovering into the
    // submenu. To indicate the active language at the **top level**
    // too, we ALSO set `MFT_RADIOCHECK | MFS_CHECKED` on the parent
    // letter submenu item by position. Letter submenu items have no
    // command id (they carry an HMENU pointer instead), so
    // `CheckMenuRadioItem`'s by-command sweep can't reach them ŌĆö
    // `SetMenuItemInfoW` by position is the only way. Other letter
    // submenus get `MFS_UNCHECKED` so a previously-active letter's
    // mark clears on language switch.
    //
    // The `MIIM_FTYPE | MIIM_STATE` mask only modifies fType / fState;
    // the submenu's HMENU pointer (`hSubMenu` under `MIIM_SUBMENU`)
    // is preserved, so the letter submenu still opens correctly.
    unsafe {
        let _ = CheckMenuRadioItem(
            language_menu,
            u32::from(ID_LANGUAGE_BASE),
            u32::from(ID_LANGUAGE_END),
            target,
            MF_BYCOMMAND.0,
        );
        let count = GetMenuItemCount(Some(language_menu));
        for i in 0..count {
            let sub = GetSubMenu(language_menu, i);
            if sub.is_invalid() {
                continue;
            }
            // Mark items inside the submenu (the inner bullet, visible
            // when the user opens the letter submenu).
            let _ = CheckMenuRadioItem(
                sub,
                u32::from(ID_LANGUAGE_BASE),
                u32::from(ID_LANGUAGE_END),
                target,
                MF_BYCOMMAND.0,
            );
            // Walk the submenu's items by position. Track two things:
            //   * `contains_target` ŌĆö does this submenu contain the
            //     active language? (drives the bullet mark)
            //   * `in_lang_band` ŌĆö does this submenu hold items with
            //     ids inside the `ID_LANGUAGE_BASE..=ID_LANGUAGE_END`
            //     (1500..=1599) range at all? Letter submenus
            //     (A / B / C / ...) yield `true`; the "User-Defined
            //     language" submenu yields `false` because its
            //     entries live in the disjoint 2100..=2102 UDL-
            //     action range and the reserved 2200..=3099 UDL-
            //     item range (Phase 4.6 m2 / m1d) ŌĆö both outside
            //     the language band.
            // The `in_lang_band` discriminator is load-bearing: we
            // ONLY apply `SetMenuItemInfoW` to letter submenus.
            // Touching the UDL submenu would replace the greyed
            // "Define your languageŌĆ”" entry's `MFS_GRAYED` state
            // with `MFS_UNCHECKED` (`MIIM_STATE` overwrites fState
            // wholesale), silently re-enabling the deliberately
            // disabled item.
            let inner_count = GetMenuItemCount(Some(sub));
            let mut contains_target = false;
            let mut in_lang_band = false;
            for j in 0..inner_count {
                let id = GetMenuItemID(sub, j);
                if id == target {
                    contains_target = true;
                    in_lang_band = true;
                    break;
                }
                if id >= u32::from(ID_LANGUAGE_BASE) && id <= u32::from(ID_LANGUAGE_END) {
                    in_lang_band = true;
                    // Don't break ŌĆö still scanning for `target`.
                }
            }
            if !in_lang_band {
                continue;
            }
            // Mark / unmark the parent letter submenu item (top-level
            // entry at position `i`) with MFT_RADIOCHECK + MFS_*.
            let mut mii = MENUITEMINFOW {
                cbSize: u32::try_from(core::mem::size_of::<MENUITEMINFOW>()).unwrap_or(0),
                fMask: MIIM_FTYPE | MIIM_STATE,
                fType: MFT_RADIOCHECK,
                fState: if contains_target {
                    MFS_CHECKED
                } else {
                    MFS_UNCHECKED
                },
                ..Default::default()
            };
            // `i` cast safe ŌĆö GetMenuItemCount returns i32 >= 0 and
            // we're iterating that exact range.
            #[allow(
                clippy::cast_sign_loss,
                reason = "loop bound from GetMenuItemCount is non-negative"
            )]
            let pos = i as u32;
            let _ = SetMenuItemInfoW(language_menu, pos, true, &raw mut mii);
        }
    }
}

/// Clear every existing radio-mark bullet in the Language menu
/// ŌĆö both in the built-in `ID_LANGUAGE_BASE..=ID_LANGUAGE_END`
/// range and the UDL `ID_UDL_ITEM_BASE..=ID_UDL_ITEM_END` range,
/// on every top-level letter submenu AND the "User-Defined
/// language" submenu, AND on the top-level parent popup entries
/// themselves. Called at the top of `refresh_language_menu`
/// before either the built-in or UDL set-mark path applies its
/// own bullet, so switching *between* the two sides doesn't
/// leave a stale bullet behind on the side that just lost focus.
///
/// This is not the same as calling `CheckMenuRadioItem` with an
/// out-of-range target ŌĆö `CheckMenuRadioItem` requires
/// `check_id` to fall within the passed `[first, last]` range or
/// it fails and changes nothing. To clear, we iterate submenu
/// items by position, read each item's cmd id via
/// `GetMenuItemID`, and unmark any that fall into either
/// language range via `CheckMenuItem(sub, id, MF_BYCOMMAND |
/// MF_UNCHECKED)`. Top-level popup entries (which have no cmd
/// id ŌĆö they carry an HMENU pointer instead) are cleared by
/// `SetMenuItemInfoW(MIIM_FTYPE | MIIM_STATE)` with
/// `MFT_RADIOCHECK | MFS_UNCHECKED`.
///
/// # Safety
///
/// `language_menu` must be a live HMENU (top-level Language menu
/// from `build_language_menu`). Caller on the UI thread.
unsafe fn clear_all_language_menu_marks(language_menu: HMENU) {
    unsafe {
        let count = GetMenuItemCount(Some(language_menu));
        if count <= 0 {
            return;
        }
        for i in 0..count {
            let sub = GetSubMenu(language_menu, i);
            if sub.is_invalid() {
                // Direct top-level command item (no child popup):
                //   * "Normal Text" at position 0.
                //   * Any letter with exactly one `LANG_TABLE`
                //     entry (single-run letters aren't wrapped
                //     in a letter submenu).
                //   * Every loaded UDL ŌĆö appended flat at the
                //     bottom of the Language menu by
                //     `append_udls_to_menu` so a UDL click is
                //     one hover-and-click, matching N++'s
                //     layout.
                //
                // Read the cmd id and clear the bullet if it's
                // in either the built-in language range or the
                // UDL item range. Both `refresh_language_menu`'s
                // built-in sweep and `set_udl_radio_mark` set
                // bullets on `language_menu` directly for these
                // ids, so this clear path must handle both
                // ranges to keep cross-boundary switches from
                // leaving a stale bullet behind.
                let id = GetMenuItemID(language_menu, i);
                let in_lang_range =
                    id >= u32::from(ID_LANGUAGE_BASE) && id <= u32::from(ID_LANGUAGE_END);
                let in_udl_range =
                    id >= u32::from(ID_UDL_ITEM_BASE) && id <= u32::from(ID_UDL_ITEM_END);
                if in_lang_range || in_udl_range {
                    let _ = CheckMenuItem(language_menu, id, MF_BYCOMMAND.0 | MF_UNCHECKED.0);
                }
                continue;
            }
            let inner_count = GetMenuItemCount(Some(sub));
            let mut touched = false;
            for j in 0..inner_count {
                let id = GetMenuItemID(sub, j);
                let in_lang_range =
                    id >= u32::from(ID_LANGUAGE_BASE) && id <= u32::from(ID_LANGUAGE_END);
                let in_udl_range =
                    id >= u32::from(ID_UDL_ITEM_BASE) && id <= u32::from(ID_UDL_ITEM_END);
                if in_lang_range || in_udl_range {
                    let _ = CheckMenuItem(sub, id, MF_BYCOMMAND.0 | MF_UNCHECKED.0);
                    touched = true;
                }
            }
            if !touched {
                continue;
            }
            let mut mii = MENUITEMINFOW {
                cbSize: u32::try_from(core::mem::size_of::<MENUITEMINFOW>()).unwrap_or(0),
                fMask: MIIM_FTYPE | MIIM_STATE,
                fType: MFT_RADIOCHECK,
                fState: MFS_UNCHECKED,
                ..Default::default()
            };
            #[allow(
                clippy::cast_sign_loss,
                reason = "loop bound from GetMenuItemCount is non-negative"
            )]
            let pos = i as u32;
            let _ = SetMenuItemInfoW(language_menu, pos, true, &raw mut mii);
        }
    }
}

/// Apply the radio-mark bullet for a UDL language. UDL menu
/// items live as flat top-level entries directly on
/// `language_menu`, with cmd ids in
/// `ID_UDL_ITEM_BASE..=ID_UDL_ITEM_END`, disjoint from the
/// letter-submenus' `ID_LANGUAGE_BASE..=ID_LANGUAGE_END` band.
/// Because the target is a direct child of `language_menu`, one
/// `CheckMenuRadioItem` call on `language_menu` with the UDL id
/// range is sufficient ŌĆö no submenu walk, no companion parent-
/// popup bullet to mirror (there is no popup wrapping UDL
/// entries any more).
///
/// Assumes the caller has already invoked
/// [`clear_all_language_menu_marks`] so no stale bullets remain
/// on either side of the built-in / UDL boundary.
///
/// # Safety
///
/// `language_menu` must be a live HMENU (top-level Language menu
/// from `build_language_menu`). Caller on the UI thread.
unsafe fn set_udl_radio_mark(language_menu: HMENU, lang_id: i32) {
    unsafe {
        // Compute the target cmd id from the lang id ŌĆö inverse
        // of `append_udls_to_menu`'s encoding.
        let offset = lang_id - codepp_udl::UDL_LANG_TYPE_BASE;
        if offset < 0 || offset > i32::from(ID_UDL_ITEM_END - ID_UDL_ITEM_BASE) {
            return;
        }
        // `offset` is bounded in
        // `0..=(ID_UDL_ITEM_END-ID_UDL_ITEM_BASE)` (~900), well
        // inside `u32` range.
        #[allow(clippy::cast_sign_loss, reason = "offset guarded to be non-negative")]
        let target = u32::from(ID_UDL_ITEM_BASE) + offset as u32;
        let _ = CheckMenuRadioItem(
            language_menu,
            u32::from(ID_UDL_ITEM_BASE),
            u32::from(ID_UDL_ITEM_END),
            target,
            MF_BYCOMMAND.0,
        );
    }
}

/// Build the Language menu from `core::lang::LANG_TABLE`. Returns
/// the top-level HMENU, ready to be appended to the menu bar.
///
/// Layout matches Notepad++:
///
///  1. "Normal Text" ŌĆö always at the top, single entry, mapped to
///     `L_TEXT` (cmd id `ID_LANGUAGE_BASE + 0`).
///  2. Separator.
///  3. Alphabetical block of every other `LANG_TABLE` entry. Same-
///     first-letter groups of 2 or more collapse into a submenu
///     titled by the letter; single-entry letters stay at the top
///     level.
///  4. Separator.
///  5. "User-Defined language" submenu (Phase 4.6 m2):
///     - "Define your languageŌĆ”" ŌĆö greyed until the m3 editor
///       modal lands.
///     - "Open User Defined Language folderŌĆ”" ŌĆö opens the OS
///       file explorer at `<config_dir>/userDefineLangs/`,
///       creating the directory first if it doesn't yet exist.
///     - "Notepad++ User Defined Languages Collection" ŌĆö opens
///       [`UDL_COLLECTION_URL`] in the user's default browser.
///  6. The dynamic list of loaded UDLs, appended at the *top
///     level* (below the "User-Defined language" submenu entry,
///     matching N++'s layout ŌĆö one hover-and-click per UDL, not
///     two). That extension happens later in `Win32Ui::run` via
///     `append_udls_to_menu` because the registry isn't
///     populated until `Shell::new` scans
///     `<config_dir>/userDefineLangs/`.
///
/// `LANG_TABLE` is asserted to be alphabetical in `core::lang`'s
/// tests, so the iteration walks adjacent same-letter rows
/// directly without sorting here.
fn build_language_menu() -> Result<HMENU> {
    use codepp_core::lang::LANG_TABLE;

    // Top-level menu, RAII-wrapped: any `?`-propagated failure
    // below destroys the kernel HMENU before the function unwinds,
    // so a partially-built menu never leaks. `take()` defuses the
    // guard right before the successful return.
    let menu = MenuGuard::wrap(unsafe { CreateMenu()? });

    // 1. "Normal Text" at the top. The L_TEXT row sits at index 0
    //    of LANG_TABLE by construction (pinned in
    //    `lang_table_first_entry_is_normal_text`).
    let text_label = wide_terminated("Normal Text");
    unsafe {
        AppendMenuW(
            menu.handle(),
            MF_STRING,
            (i32::from(ID_LANGUAGE_BASE) + LANG_TABLE[0].lang.as_npp_id()) as usize,
            PCWSTR(text_label.as_ptr()),
        )?;
        AppendMenuW(menu.handle(), MF_SEPARATOR, 0, PCWSTR::null())?;
    }

    // 3. Alphabetical block. Walk adjacent same-first-letter rows
    //    and decide submenu vs. top-level by run length.
    let entries = &LANG_TABLE[1..];
    let mut i = 0;
    while i < entries.len() {
        let first_letter = entries[i]
            .menu_label
            .chars()
            .next()
            .map(|c| c.to_ascii_uppercase());
        // Find the run of entries that share `first_letter`.
        let mut j = i + 1;
        while j < entries.len()
            && entries[j]
                .menu_label
                .chars()
                .next()
                .map(|c| c.to_ascii_uppercase())
                == first_letter
        {
            j += 1;
        }
        let run = &entries[i..j];

        if run.len() == 1 {
            // Single entry ŌĆö append directly at top level.
            let label = wide_terminated(run[0].menu_label);
            unsafe {
                AppendMenuW(
                    menu.handle(),
                    MF_STRING,
                    (i32::from(ID_LANGUAGE_BASE) + run[0].lang.as_npp_id()) as usize,
                    PCWSTR(label.as_ptr()),
                )?;
            }
        } else {
            // Multiple entries ŌĆö create a submenu titled by the
            // letter, append each entry to it, then attach the
            // submenu to the top-level menu. Same RAII guard
            // covers a `?`-failure inside the inner loop or on
            // the attach call below.
            let sub = MenuGuard::wrap(unsafe { CreatePopupMenu()? });
            for entry in run {
                let label = wide_terminated(entry.menu_label);
                unsafe {
                    AppendMenuW(
                        sub.handle(),
                        MF_STRING,
                        (i32::from(ID_LANGUAGE_BASE) + entry.lang.as_npp_id()) as usize,
                        PCWSTR(label.as_ptr()),
                    )?;
                }
            }
            let letter = first_letter.map_or_else(|| "?".to_string(), |c| c.to_string());
            let letter_w = wide_terminated(&letter);
            // Attach: ownership of the submenu transfers to `menu`
            // on success. Defuse the submenu guard *only* after
            // the attach call returns Ok ŌĆö a `?` failure here
            // still drops `sub` and frees the orphan.
            let sub_handle = sub.handle();
            unsafe {
                AppendMenuW(
                    menu.handle(),
                    MF_POPUP,
                    sub_handle.0 as usize,
                    PCWSTR(letter_w.as_ptr()),
                )?;
            }
            let _ = sub.take();
        }

        i = j;
    }

    // 4 + 5. User-Defined section (Phase 4.6 m2).
    //
    // Layout follows Notepad++:
    //   Ōö£ŌöĆ Define your languageŌĆ”            (greyed ŌĆö m3 wires the modal)
    //   Ōö£ŌöĆ Open User Defined Language folderŌĆ”
    //   Ōö£ŌöĆ Notepad++ User Defined Languages Collection
    //   Ōö£ŌöĆ ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ (separator, only present once loaded UDLs exist)
    //   ŌööŌöĆ <loaded UDL list>                (m1d populates)
    //
    // The two `OPEN_*` entries are enabled today and route to
    // `ShellExecuteW("open", ...)` in the `WM_COMMAND` handler.
    // The loaded-UDL list is empty until m1b's startup scan lands;
    // the separator that would visually divide the actions from
    // the list is deliberately omitted here (would render as a
    // trailing separator otherwise, which reads as broken layout).
    unsafe {
        AppendMenuW(menu.handle(), MF_SEPARATOR, 0, PCWSTR::null())?;
    }

    let udl_sub = MenuGuard::wrap(unsafe { CreatePopupMenu()? });
    let define_label = wide_terminated("Define your language...");
    unsafe {
        AppendMenuW(
            udl_sub.handle(),
            MF_STRING,
            usize::from(ID_UDL_DEFINE_LANGUAGE),
            PCWSTR(define_label.as_ptr()),
        )?;
    }
    let open_folder_label = wide_terminated("Open User Defined Language folder...");
    unsafe {
        AppendMenuW(
            udl_sub.handle(),
            MF_STRING,
            usize::from(ID_UDL_OPEN_FOLDER),
            PCWSTR(open_folder_label.as_ptr()),
        )?;
    }
    let collection_label = wide_terminated("Notepad++ User Defined Languages Collection");
    unsafe {
        AppendMenuW(
            udl_sub.handle(),
            MF_STRING,
            usize::from(ID_UDL_OPEN_COLLECTION),
            PCWSTR(collection_label.as_ptr()),
        )?;
    }
    let udl_label = wide_terminated("User-Defined language");
    let udl_handle = udl_sub.handle();
    unsafe {
        AppendMenuW(
            menu.handle(),
            MF_POPUP,
            udl_handle.0 as usize,
            PCWSTR(udl_label.as_ptr()),
        )?;
    }
    let _ = udl_sub.take();

    Ok(menu.take())
}

/// Append the loaded UDL entries as flat top-level items on the
/// Language menu, directly below the "User-Defined language"
/// submenu entry. Called from `Win32Ui::run` AFTER `Shell::new`
/// has populated `Shell.udl_registry` (the top-level menu is
/// built with only the built-in languages + the fixed UDL-
/// action submenu during window creation because Shell doesn't
/// exist yet at that point).
///
/// Layout matches Notepad++'s Language menu: the fixed UDL
/// actions ("Define your languageŌĆ”" etc.) live inside the
/// "User-Defined language" submenu; the loaded UDLs themselves
/// appear as flat, top-level `MF_STRING` items at the very
/// bottom of the Language menu, so a click on Language ŌåÆ
/// "Markdown (preinstalled)" is one hover-and-click rather than
/// two.
///
/// Each loaded UDL gets one menu item with command id
/// `ID_UDL_ITEM_BASE + (lang_type_id - UDL_LANG_TYPE_BASE)`.
/// The `WM_COMMAND` dispatcher inverts this: `menu_id -
/// ID_UDL_ITEM_BASE + UDL_LANG_TYPE_BASE = lang_type_id`, then
/// applies the language via `apply_lang(LangType(id))` ŌĆö the
/// same path built-in-lexer menu items already take.
///
/// A separator is inserted before the first UDL entry (only if
/// there's at least one loaded UDL) so the "User-Defined
/// language" submenu entry is visually distinct from the
/// dynamic flat list.
///
/// # Safety
///
/// `language_menu` must be the live top-level HMENU returned by
/// `build_language_menu`, still owned by the top-level menu bar
/// (not detached). Caller runs on the UI thread.
unsafe fn append_udls_to_menu(language_menu: HMENU, registry: &codepp_udl::UdlRegistry) {
    unsafe {
        let entries = registry.entries();
        if entries.is_empty() {
            return;
        }
        // Separator between the "User-Defined language" submenu
        // entry (the last thing `build_language_menu` appended)
        // and the flat loaded-UDL list that follows. Errors
        // from AppendMenuW here are non-critical ŌĆö the menu
        // still functions with the entries appended sans
        // separator, and the failure mode is a Win32
        // out-of-resources which would break far more than this
        // one call.
        let _ = AppendMenuW(language_menu, MF_SEPARATOR, 0, PCWSTR::null());
        for entry in entries {
            let offset = entry.lang_type_id - codepp_udl::UDL_LANG_TYPE_BASE;
            // Bound-check: skip any entry outside the reserved
            // menu range. `MAX_UDL_SCAN_ENTRIES` (1024) is
            // larger than the menu-id range (900 slots between
            // `ID_UDL_ITEM_BASE` and `ID_UDL_ITEM_END`), so a
            // config directory with >900 UDL files can produce
            // entries here that we log-and-drop from the menu
            // ŌĆö the UDL still loads and can be applied via
            // extension detection or plugin API, it just has no
            // Language-menu entry. See DESIGN.md ┬¦7.2 Phase 4.6
            // for the reserved-id-range rationale.
            if offset < 0 || offset > i32::from(ID_UDL_ITEM_END - ID_UDL_ITEM_BASE) {
                tracing::warn!(
                    lang_type_id = entry.lang_type_id,
                    "UDL entry outside ID_UDL_ITEM_BASE..=END range; skipping menu entry"
                );
                continue;
            }
            #[allow(clippy::cast_sign_loss, reason = "offset guarded to be non-negative")]
            let menu_id = usize::from(ID_UDL_ITEM_BASE) + offset as usize;
            let sanitized = sanitize_udl_name_for_menu(&entry.definition.name);
            let label = wide_terminated(&sanitized);
            let _ = AppendMenuW(language_menu, MF_STRING, menu_id, PCWSTR(label.as_ptr()));
        }
    }
}

/// Refresh the loaded UDL registry from disk after the user
/// saves a UDL via the m3 editor. Rebuilds the Language menu's
/// dynamic UDL section so the newly-saved UDL becomes
/// selectable without a restart.
///
/// Contract: called on the UI thread from the main `WndProc`'s
/// `WM_APP_UDL_REFRESH` arm ONLY. Not re-entrant with plugin
/// dispatch ŌĆö the registry mutation must happen inside the
/// `&mut WindowState` borrow so a plugin-thread read never
/// races.
unsafe fn refresh_udl_registry(main_hwnd: HWND) {
    let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
        return;
    };
    let Some(dir) = codepp_platform::user_define_langs_dir() else {
        tracing::warn!("cannot refresh UDL registry: user_define_langs_dir unavailable");
        return;
    };
    // Re-scan from disk. Same call `Shell::new` uses at startup.
    state.shell.udl_registry = codepp_udl::UdlRegistry::scan_dir(&dir);

    // Clear the previously-appended dynamic UDL entries from the
    // Language menu. Walk from the end and delete every trailing
    // item whose command id sits in the UDL range, plus a
    // trailing separator if present. This mirrors what
    // `append_udls_to_menu` inserts:
    //   1. one MFT_SEPARATOR
    //   2. one MF_STRING per loaded UDL, cmd id in
    //      ID_UDL_ITEM_BASE..=ID_UDL_ITEM_END.
    // Removing by-cmd on the strings and by-position on the
    // trailing separator handles both.
    let language_menu = state.language_menu;
    unsafe {
        // First pass: remove every UDL-range command entry.
        // `RemoveMenu(..., MF_BYCOMMAND)` doesn't care about
        // position; iterating until it fails clears them all.
        for id in u32::from(ID_UDL_ITEM_BASE)..=u32::from(ID_UDL_ITEM_END) {
            let _ = RemoveMenu(language_menu, id, MF_BYCOMMAND);
        }
        // Second pass: peel off a trailing separator if present.
        // `GetMenuItemCount` returns -1 on error; treat that as
        // "no menu" and stop.
        let count = GetMenuItemCount(Some(language_menu));
        if count > 0 {
            let last_idx = (count - 1) as u32;
            let mut info = MENUITEMINFOW {
                cbSize: std::mem::size_of::<MENUITEMINFOW>() as u32,
                fMask: MIIM_FTYPE,
                ..Default::default()
            };
            if GetMenuItemInfoW(language_menu, last_idx, true, &raw mut info).is_ok()
                && (info.fType.0 & MFT_SEPARATOR.0) != 0
            {
                let _ = RemoveMenu(language_menu, last_idx, MF_BYPOSITION);
            }
        }
        // Re-append the dynamic UDL entries + their separator.
        append_udls_to_menu(language_menu, &state.shell.udl_registry);
        // Repaint the menu bar so the change is visible.
        let _ = DrawMenuBar(main_hwnd);
    }
}

/// Sanitize a UDL `<UserLang name="...">` attribute for use as
/// a Win32 menu label. Attacker-controlled (UDL XML is authored
/// by third parties ŌĆö the "User-Defined language" submenu even
/// links users to a public GitHub collection to download them),
/// so we treat it exactly like tab-title chrome:
///
/// 1. Strip control characters (`\0`, `\r`, `\n`, `\t`) and cap
///    length via [`sanitize_filename_for_display`]. Without the
///    tab strip, a UDL name containing an embedded `\t` would
///    produce a spoofed right-aligned "shortcut" column in the
///    menu (Win32 uses `\t` as the label/accelerator separator),
///    letting a hostile UDL visually impersonate a menu item
///    with a specific hotkey binding.
/// 2. Escape ampersands as `&&`. Win32 treats a single `&` as
///    the mnemonic-underline marker, so `Save & Continue` would
///    render as `Save _C_ontinue` with `C` underlined. Doubling
///    to `&&` renders a literal ampersand. Without the escape,
///    a UDL name could inject or collide with a mnemonic ŌĆö
///    e.g. `&File Utils` would put a mnemonic on `F`, giving
///    the malicious UDL the same access key as the top-level
///    `&File` menu.
///
/// Returns a new `String`; caller wraps in `wide_terminated`.
fn sanitize_udl_name_for_menu(name: &str) -> String {
    let stripped_and_capped = sanitize_filename_for_display(name);
    let mut escaped = String::with_capacity(stripped_and_capped.len());
    for c in stripped_and_capped.chars() {
        if c == '&' {
            escaped.push_str("&&");
        } else {
            escaped.push(c);
        }
    }
    escaped
}

/// RAII wrapper around an HMENU that calls `DestroyMenu` on drop
/// unless ownership is taken via [`Self::take`]. Used by
/// [`build_language_menu`] so a `?`-propagated failure during
/// menu construction doesn't leak the in-flight kernel object.
///
/// The guard is dropped (and the menu destroyed) on every error
/// path; on success the caller pulls the HMENU out via `take`,
/// which sets the wrapped handle to null and converts the Drop
/// into a no-op.
struct MenuGuard {
    menu: HMENU,
}

impl MenuGuard {
    fn wrap(menu: HMENU) -> Self {
        Self { menu }
    }
    fn handle(&self) -> HMENU {
        self.menu
    }
    /// Defuse the guard, returning the contained HMENU. After
    /// `take`, `Drop` is a no-op ŌĆö the caller has assumed ownership.
    fn take(mut self) -> HMENU {
        let m = self.menu;
        self.menu = HMENU(core::ptr::null_mut());
        m
    }
}

impl Drop for MenuGuard {
    fn drop(&mut self) {
        if !self.menu.is_invalid() {
            // SAFETY: `self.menu` was returned from CreateMenu /
            // CreatePopupMenu and has not been attached to a
            // parent menu (the `take()` defuse runs only after a
            // successful attach). DestroyMenu on an unattached
            // HMENU is the documented release path.
            let _ = unsafe { DestroyMenu(self.menu) };
        }
    }
}

/// Build a UTF-16 `Vec<u16>` with a trailing null. Caller pulls
/// the raw pointer via `.as_ptr()`; the buffer must out-live the
/// `PCWSTR` use. `AppendMenuW` copies the string immediately, so
/// per-call locals are sufficient.
pub(crate) fn wide_terminated(s: &str) -> Vec<u16> {
    s.encode_utf16().chain(std::iter::once(0)).collect()
}

/// Radio-mark the Encoding menu's active item. Encoding values
/// don't yet have a numeric ABI to share with plugins, so the
/// match is on a small inline table ŌĆö extended alongside the
/// `core::encoding` set as new variants land.
///
/// # Safety
///
/// `encoding_menu` must be a live HMENU; caller on the UI thread.
unsafe fn refresh_encoding_menu(encoding_menu: HMENU, encoding: &Encoding) {
    // The Phase 3 status-bar label is the most stable identity we
    // have for an `Encoding`; matching on it avoids exporting more
    // surface from `core::encoding` than the menu actually needs.
    // Anything not in the table leaves no radio mark ŌĆö a
    // user-visible "no encoding selected" cue that an unfamiliar
    // encoding is current.
    let target = match encoding.label() {
        "ANSI" => Some(ID_ENCODING_ANSI),
        "UTF-8" => Some(ID_ENCODING_UTF8),
        "UTF-8 BOM" => Some(ID_ENCODING_UTF8_BOM),
        // The Encoding menu's "UTF-16 LE/BE BOM" items map to
        // `Utf16LeBom` / `Utf16BeBom` (the BOM variants are the
        // canonical save targets ŌĆö the no-BOM variants are
        // detection-only). Both label strings ŌĆö with and without
        // the trailing " BOM" ŌĆö point at the same radio item so
        // a heuristic-detected no-BOM file still highlights the
        // matching menu entry.
        "UTF-16 LE" | "UTF-16 LE BOM" => Some(ID_ENCODING_UTF16_LE),
        "UTF-16 BE" | "UTF-16 BE BOM" => Some(ID_ENCODING_UTF16_BE),
        _ => None,
    };
    if let Some(id) = target {
        unsafe {
            let _ = CheckMenuRadioItem(
                encoding_menu,
                u32::from(ID_ENCODING_ANSI),
                u32::from(ID_ENCODING_UTF16_BE),
                u32::from(id),
                MF_BYCOMMAND.0,
            );
        }
    }
}

/// Rebuild the Window menu from the current tab list. Each tab gets
/// one entry (`<idx>: <filename>`); the active tab is check-marked.
/// Cmd id = `ID_WINDOW_BASE + idx`.
///
/// The submenu is fully torn down and rebuilt on every popup ŌĆö the
/// tab set is small (Ōēż 100 capped by the cmd-id range), so a per-
/// open rebuild is far simpler than tracking deltas.
///
/// # Safety
///
/// `window_menu` must be a live HMENU; caller on the UI thread.
unsafe fn refresh_window_menu(window_menu: HMENU, shell: &Shell) {
    // Clear by deleting every existing item by position. Iterate
    // backward so deletion of item N doesn't shift item N+1 into
    // the just-cleared slot.
    let count = unsafe { GetMenuItemCount(Some(window_menu)) };
    if count > 0 {
        for i in (0..count).rev() {
            unsafe {
                let _ = DeleteMenu(window_menu, i as u32, MF_BYPOSITION);
            }
        }
    }

    if shell.tabs.is_empty() {
        unsafe {
            let _ = AppendMenuW(
                window_menu,
                MF_STRING | MF_GRAYED,
                0,
                w!("(no open windows)"),
            );
        }
        return;
    }

    for (idx, tab) in shell.tabs.iter().enumerate() {
        if idx >= ID_WINDOW_CAP {
            // Cap the visible list at the cmd-id window. The
            // remainder is reachable through tab-strip clicks; the
            // menu just shows the first ID_WINDOW_CAP entries.
            break;
        }
        // Same filename-extraction rule as the tab strip: prefer
        // `path.file_name()`, fall back to "Untitled" for buffers
        // that haven't been saved yet, sanitize for control chars.
        let raw = tab
            .path
            .as_ref()
            .and_then(|p| p.file_name().and_then(|s| s.to_str()))
            .unwrap_or("Untitled");
        let cleaned = sanitize_filename_for_display(raw);
        // Prefix with "<idx+1> " for keyboard-friendly mnemonic
        // (matches N++ which uses 1-based numbering in this menu).
        let display = format!("{} {}", idx + 1, cleaned);
        let display_w: Vec<u16> = display.encode_utf16().chain(std::iter::once(0)).collect();
        let id = (ID_WINDOW_BASE as usize) + idx;
        unsafe {
            let _ = AppendMenuW(window_menu, MF_STRING, id, PCWSTR(display_w.as_ptr()));
        }
    }

    if let Some(active) = shell.active_tab {
        // Defense in depth: only mark the active tab if it's in the
        // visible-cmd-id window. A future `active_tab` outside the
        // 0..ID_WINDOW_CAP range would silently overflow the u32
        // addition; bounded check keeps the target id well-formed.
        if active < ID_WINDOW_CAP {
            let id = u32::from(ID_WINDOW_BASE) + active as u32;
            unsafe {
                let _ = CheckMenuItem(window_menu, id, MF_BYCOMMAND.0 | MF_CHECKED.0);
            }
        }
    }
}

/// Append loaded-plugin `FuncItems` onto the per-plugin submenu after
/// a successful lazy-load round. Each plugin gets its own popup
/// submenu under the top-level "Plugins" entry, with the plugin's
/// own getName output as the label.
///
/// # Safety
///
/// Caller must invoke this on the UI thread that owns `plugin_menu`.
/// `CreateMenu`/`AppendMenuW` do not re-enter our `wnd_proc`.
unsafe fn populate_plugin_menu(plugin_menu: HMENU, shell: &Shell) {
    for (plugin_name, funcs) in shell.loaded_plugin_funcs() {
        // One popup submenu per plugin so users see "Plugins ŌåÆ MyPlugin
        // ŌåÆ Item". Matches Notepad++'s layout.
        // SAFETY: CreateMenu just allocates a new HMENU; no aliasing
        // concerns.
        let submenu = match unsafe { CreateMenu() } {
            Ok(m) => m,
            Err(e) => {
                tracing::warn!(plugin = %plugin_name, error = %e, "CreateMenu failed");
                continue;
            }
        };
        for func in funcs {
            // N++ FuncItem ABI convention: a NULL `_pFunc` marks a menu
            // separator. The item_name for such an entry is a
            // placeholder the plugin does not expect to see rendered
            // (mimeTools, for example, writes a sentinel string there);
            // dispatching MF_STRING with that label is the visible bug.
            if func.p_func.is_none() {
                if let Err(e) = unsafe { AppendMenuW(submenu, MF_SEPARATOR, 0, PCWSTR::null()) } {
                    tracing::warn!(plugin = %plugin_name, error = %e, "AppendMenuW (separator) failed");
                }
                continue;
            }
            // FuncItem.item_name is a fixed-length null-terminated UTF-16
            // array; pass its pointer directly to AppendMenuW.
            let label = PCWSTR(func.item_name.as_ptr());
            // `cmd_id` is i32 (signed) but AppendMenuW expects usize.
            // Plugin cmd_ids are always positive (assigned from
            // PLUGIN_CMD_ID_BASE = 50000), so the cast is value-preserving.
            let id = func.cmd_id as usize;
            // SAFETY: `submenu` is the HMENU we just created; `label`
            // points into a static null-terminated wide string the
            // plugin owns for its lifetime.
            if let Err(e) = unsafe { AppendMenuW(submenu, MF_STRING, id, label) } {
                tracing::warn!(plugin = %plugin_name, error = %e, "AppendMenuW (item) failed");
            }
        }
        // Attach the submenu to the parent "Plugins" popup.
        let plugin_label_w: Vec<u16> = plugin_name
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        // SAFETY: `plugin_menu` is the parent HMENU passed in;
        // `plugin_label_w` is a local wide string that lives for the
        // duration of this call (AppendMenuW copies the label).
        if let Err(e) = unsafe {
            AppendMenuW(
                plugin_menu,
                MF_POPUP,
                submenu.0 as usize,
                PCWSTR(plugin_label_w.as_ptr()),
            )
        } {
            tracing::warn!(plugin = %plugin_name, error = %e, "AppendMenuW (popup) failed");
        }
    }
    // Append the Plugin Manager entry at the bottom of the menu,
    // separated from the per-plugin submenus by a divider ŌĆö
    // matches Notepad++'s layout (per-plugin entries on top, then
    // separator, then "Plugin Admin..."). Always appended, even
    // when no plugins are loaded, so the user can reach the
    // manager to re-enable plugins they previously disabled.
    let _ = unsafe { AppendMenuW(plugin_menu, MF_SEPARATOR, 0, PCWSTR::null()) };
    let _ = unsafe {
        AppendMenuW(
            plugin_menu,
            MF_STRING,
            ID_PLUGINS_ADMIN as usize,
            w!("&Plugin Manager..."),
        )
    };
}

/// Write `text` into status-bar part `part_index`. Centralizes the
/// `SB_SETTEXTW` idiom so the regular status updates (encoding/EOL/size)
/// and the plugin-driven `NPPM_SETSTATUSBAR` overrides share one
/// implementation ŌĆö the only thing that varies is the source string.
/// Trigger a relayout of the main window by posting a `WM_SIZE`
/// to it with its current client rect. Used by every chrome-toggle
/// path (`set_tabbar_hidden`, `set_toolbar_hidden`,
/// `set_menu_hidden`, `set_statusbar_hidden`) so the editor area
/// expands / shrinks to fill the freed / regained band.
///
/// Posts (via `PostMessageW`) rather than sends synchronously: the
/// chrome-toggle messages can be dispatched from inside a plugin's
/// `messageProc`, which is already running under `PluginCallGuard`.
/// A synchronous `SendMessage` would re-enter the main `wnd_proc` on
/// this thread, and `state_from_hwnd` would refuse the re-borrow
/// because the guard is held ŌĆö the layout would silently no-op.
/// Posting queues the size message until after the guard drops,
/// at which point the normal message-pump dequeue can run `WM_SIZE`
/// with full state access.
///
/// `child_hwnd` is any descendant of the main window ŌĆö typically
/// the chrome control we just toggled. The function derives the
/// main window from `GetParent`. The handle is read-only.
///
/// # Safety
///
/// `child_hwnd` must be a valid HWND owned by the same window
/// hierarchy `Win32Ui` was constructed against. UI-thread-only:
/// `GetParent` and `GetClientRect` are not documented as
/// thread-safe with concurrent window-style mutations.
unsafe fn relayout_main_window_via_post(child_hwnd: HWND) {
    // SAFETY: `GetParent` is a cheap UI-thread read with no
    // message pump; the caller's contract guarantees `child_hwnd`
    // is valid.
    unsafe {
        let Ok(parent) = GetParent(child_hwnd) else {
            return;
        };
        let mut rect = RECT::default();
        if GetClientRect(parent, &raw mut rect).is_err() {
            return;
        }
        let w = (rect.right - rect.left).max(0);
        let h = (rect.bottom - rect.top).max(0);
        // WM_SIZE's lparam packs (height << 16 | width). Width
        // and height fit in u16 by the Win32 contract on a single
        // screen; clamp explicitly so a future multi-monitor
        // edge case doesn't produce a garbage lparam.
        let w16 = (w as u32 & 0xFFFF) as isize;
        let h16 = ((h as u32 & 0xFFFF) << 16) as isize;
        // `wparam = 0` synthesizes `SIZE_RESTORED`. The main
        // wnd_proc's WM_SIZE handler ignores wparam today; if it
        // ever branches on the value (e.g. to skip layout on
        // `SIZE_MINIMIZED`), revisit each caller so a chrome
        // toggle doesn't produce a spurious "restored" event.
        let _ = PostMessageW(Some(parent), WM_SIZE, WPARAM(0), LPARAM(h16 | w16));
    }
}

/// Resolve the display label for the Language slot of the
/// status bar. Built-in languages route through
/// `LangType::language_name()` (which walks `core::lang::
/// LANG_TABLE`); dynamically-registered UDLs use the
/// `<UserLang name="...">` string from the parsed
/// [`codepp_udl::UdlDefinition`] in `udl_registry`. Falls back
/// to `"Normal Text"` when the id doesn't resolve in either
/// direction ŌĆö same fallback the pre-Phase-4.6 code used, so a
/// hostile / stale `LangType` produces the same visible label as
/// an actual `L_TEXT` buffer.
///
/// **UDL-name sanitisation.** The UDL branch runs the name
/// through [`sanitize_filename_for_display`] before returning
/// ŌĆö the string comes from third-party XML the user may have
/// downloaded, so control characters (`\0`/`\r`/`\n`/`\t`) that
/// would garble the status bar are stripped and the length is
/// capped so an oversized name can't visually push the adjacent
/// EOL / encoding / caret slots. Consistent with the same
/// discipline the menu-label path already applies via
/// `sanitize_udl_name_for_menu`; the `&`-doubling done there is
/// menu-specific (mnemonic marker) and doesn't apply here since
/// the status bar renders `&` literally.
///
/// Extracted into a free function so the branching can be unit-
/// tested without a live `Win32Ui` or `HWND`. The single caller
/// (`Win32Ui::update_status`) wraps the raw-pointer dereference
/// for the registry itself, matching the safety discipline the
/// rest of the file uses for `udl_registry` access.
fn resolve_lang_label(lang: LangType, udl_registry: &codepp_udl::UdlRegistry) -> String {
    if codepp_udl::is_udl_lang_id(lang.as_npp_id()) {
        udl_registry
            .find_by_lang_type_id(lang.as_npp_id())
            .map_or_else(
                || "Normal Text".to_string(),
                |entry| sanitize_filename_for_display(&entry.definition.name),
            )
    } else {
        lang.language_name().unwrap_or("Normal Text").to_string()
    }
}

fn write_status_part(status_hwnd: HWND, part_index: usize, text: &str) {
    // Strip embedded NUL characters before building the wide buffer.
    // SB_SETTEXTW reads up to the first U+0000 unit; an embedded NUL
    // in plugin-supplied text would silently truncate the visible
    // string mid-glyph. Stripping puts the visible/encoded length in
    // sync so any future multi-part status logic that compares
    // `vec.len()` with what the control consumed stays consistent.
    let cleaned: String;
    let payload = if text.contains('\0') {
        cleaned = text.replace('\0', "");
        cleaned.as_str()
    } else {
        text
    };
    // Null-terminated UTF-16 buffer ŌĆö Vec<u16> over HSTRING so the
    // layout is unambiguous; HSTRING has its own refcounted header.
    let wide: Vec<u16> = payload.encode_utf16().chain(std::iter::once(0)).collect();
    // SB_SETTEXTW = 0x040B (wide variant; 0x0401 is the ANSI
    // SB_SETTEXTA, which the SendMessageW call would mismatch).
    // wparam packs `(part_index | drawing_type << 8)`; drawing type 0
    // gives the default sunken inner edge.
    const SB_SETTEXTW: u32 = 0x040B;
    unsafe {
        SendMessageW(
            status_hwnd,
            SB_SETTEXTW,
            Some(WPARAM(part_index)),
            Some(LPARAM(wide.as_ptr() as isize)),
        );
    }
}

// Status bar part layout. Seven slots, plus the size-grip the
// status-bar control draws on its own at the right edge:
//
//   0: language label         ("Normal Text", "C++", ...)
//   1: spring                  (empty; absorbs window-resize delta)
//   2: length / lines          ("length: 1,819   lines: 116")
//   3: caret position          ("Ln: 104   Col: 9   Pos: 1,539")
//   4: EOL                     ("Windows (CR LF)" / "Unix (LF)" / ...)
//   5: encoding                ("UTF-8")
//   6: INS / OVR               ("INS" / "OVR")
//
// Widths are 96-DPI defaults; the size-grip is system-rendered. A
// future polish item will measure the language label and switch part
// 0 to auto-fit; the fixed width below comfortably fits the longest
// `LANG_TABLE.menu_label` plus padding.
const STATUS_PART_LANG_W: i32 = 220;
// Wide enough for "length: 99,999,999   lines: 999,999" (the
// realistic upper bound at Scintilla's ~2 GiB document ceiling)
// without truncating the line count when six- or seven-digit
// numbers appear. Picked empirically ŌĆö a 6,290-line file with
// 201k bytes already fills ~180 px in the system font. Total
// fixed-right-side parts (length 230 + cursor 220 + EOL 150 +
// encoding 130 + ins/ovr 45) sum to 775 px; combined with the
// `STATUS_PART_LANG_W = 220` minimum on the left, the layout
// collapses on windows narrower than ~995 px client width
// (`setup_status_parts`'s `.max(STATUS_PART_LANG_W)` clamp keeps
// it sound ŌĆö the right-side parts spill off-screen rather than
// crashing).
const STATUS_PART_LENGTH_W: i32 = 230;
const STATUS_PART_CURSOR_W: i32 = 220;
const STATUS_PART_EOL_W: i32 = 150;
// 130px fits the longest non-`Other` `Encoding::label` ŌĆö
// `"UTF-16 LE BOM"` plus the leading two-space pad (~110px at
// 96 DPI in the system font); the extra 20px is breathing room
// for high-DPI rendering and locale label growth.
const STATUS_PART_ENCODING_W: i32 = 130;
const STATUS_PART_INSOVR_W: i32 = 45;

const STATUS_PART_LANG: usize = 0;
#[allow(dead_code)]
const STATUS_PART_SPRING: usize = 1;
const STATUS_PART_LENGTH: usize = 2;
const STATUS_PART_CURSOR: usize = 3;
const STATUS_PART_EOL: usize = 4;
const STATUS_PART_ENCODING: usize = 5;
const STATUS_PART_INSOVR: usize = 6;

const SB_SETPARTS: u32 = 0x0404;

/// Compute right-edge x-coordinates for the 7-part status bar
/// layout and apply them via `SB_SETPARTS`. Called at status-bar
/// creation time and from every `WM_SIZE` so the spring (part 1)
/// absorbs the width delta while every other part keeps its
/// designed width.
///
/// The right edges are cumulative pixel offsets from the
/// status-bar's left edge. The last entry must be `-1` so the
/// final part extends to the control's right edge (which the
/// status bar naturally accounts for the system size-grip in).
fn setup_status_parts(status_hwnd: HWND, client_width: i32) {
    // Sum of fixed-width parts on the right side of the spring.
    let right_total = STATUS_PART_LENGTH_W
        + STATUS_PART_CURSOR_W
        + STATUS_PART_EOL_W
        + STATUS_PART_ENCODING_W
        + STATUS_PART_INSOVR_W;
    // Spring's right edge: window width minus the right-side
    // fixed parts. Clamp to >= STATUS_PART_LANG_W so the spring
    // doesn't collapse below the language slot when the window is
    // narrower than the sum of fixed widths.
    let spring_right = (client_width - right_total).max(STATUS_PART_LANG_W);
    let edges: [i32; 7] = [
        STATUS_PART_LANG_W,
        spring_right,
        spring_right + STATUS_PART_LENGTH_W,
        spring_right + STATUS_PART_LENGTH_W + STATUS_PART_CURSOR_W,
        spring_right + STATUS_PART_LENGTH_W + STATUS_PART_CURSOR_W + STATUS_PART_EOL_W,
        spring_right
            + STATUS_PART_LENGTH_W
            + STATUS_PART_CURSOR_W
            + STATUS_PART_EOL_W
            + STATUS_PART_ENCODING_W,
        // Last part extends to the right edge of the status bar
        // (the control reserves space for the system size-grip
        // automatically).
        -1,
    ];
    unsafe {
        SendMessageW(
            status_hwnd,
            SB_SETPARTS,
            Some(WPARAM(edges.len())),
            Some(LPARAM(edges.as_ptr() as isize)),
        );
    }
}

/// Format an integer with comma thousand-separators (e.g. `1819`
/// ŌåÆ `"1,819"`). Used for the byte-count and caret-position
/// fields in the status bar so a 50k-line file's `Pos: 412,683`
/// stays scannable. Locale-agnostic ŌĆö Code++ doesn't carry a
/// locale layer yet, so the comma matches the most common
/// English-installation convention.
fn format_thousands(n: u64) -> String {
    let s = n.to_string();
    let bytes = s.as_bytes();
    let mut out = String::with_capacity(s.len() + s.len() / 3);
    for (i, b) in bytes.iter().enumerate() {
        if i > 0 && (bytes.len() - i).is_multiple_of(3) {
            out.push(',');
        }
        // `char::from(u8)` is the unambiguous "interpret this byte
        // as a Latin-1 / 7-bit-ASCII codepoint" conversion. The
        // `as char` cast does the same thing but reads as a wider
        // operation than what's actually needed; if a future
        // refactor ever passes non-digit bytes here the explicit
        // form makes the Latin-1 reinterpretation visible.
        out.push(char::from(*b));
    }
    out
}

/// Refresh the Scintilla-driven parts of the status bar (parts 2,
/// 3, 6 ŌĆö length/lines, cursor, INS/OVR). Reads from the editor
/// view directly so the values reflect the live caret state. The
/// shell-driven parts (lang, encoding, EOL) are left untouched
/// here; they're written by [`UiPlatform::update_status`] when
/// the underlying metadata changes.
///
/// Called from:
///  - `Win32Ui::update_status` (full refresh on metadata change)
///  - `main_wnd_proc::WM_NOTIFY/SCN_UPDATEUI` (caret movement)
fn refresh_status_dynamic_parts(status_hwnd: HWND, editor: &EditorHandle) {
    let length = editor.send(SCI_GETLENGTH, 0, 0).max(0) as u64;
    let lines = editor.send(SCI_GETLINECOUNT, 0, 0).max(0) as u64;
    let pos = editor.send(SCI_GETCURRENTPOS, 0, 0).max(0) as u64;
    // SCI_LINEFROMPOSITION returns 0-based line; the status bar
    // shows 1-based per N++ convention.
    let line0 = editor.send(SCI_LINEFROMPOSITION, pos as usize, 0).max(0) as u64;
    // SCI_GETCOLUMN returns 0-based column (virtual-space-aware,
    // tab-expanded); same +1 for display.
    let col0 = editor.send(SCI_GETCOLUMN, pos as usize, 0).max(0) as u64;
    let overtype = editor.send(SCI_GETOVERTYPE, 0, 0) != 0;

    let length_text = format!(
        "  length: {}   lines: {}",
        format_thousands(length),
        format_thousands(lines)
    );
    // Ln / Col are 1-based for display (caret on the first line
    // shows `Ln: 1`); Pos is 0-based (caret at start-of-file
    // shows `Pos: 0`) ŌĆö this matches Notepad++'s status-bar
    // convention exactly. `saturating_add` over plain `+ 1` so
    // the +1 path stays sound even on the unreachable-by-
    // construction edge case where Scintilla returns `u64::MAX`
    // (bytes are bounded at INT_MAX Ōēł 2 GiB by Scintilla's own
    // document model, so overflow is impossible in practice; the
    // explicit saturation makes the intent visible to a reviewer).
    let cursor_text = format!(
        "  Ln: {}   Col: {}   Pos: {}",
        line0.saturating_add(1),
        col0.saturating_add(1),
        format_thousands(pos)
    );
    let insovr_text = if overtype { "  OVR" } else { "  INS" };

    write_status_part(status_hwnd, STATUS_PART_LENGTH, &length_text);
    write_status_part(status_hwnd, STATUS_PART_CURSOR, &cursor_text);
    write_status_part(status_hwnd, STATUS_PART_INSOVR, insovr_text);
}

/// Show a "file changed externally ŌĆö reload?" dialog. Standalone so
/// no `&mut WindowState` borrow is held while the modal pump runs.
fn show_reload_dialog(main_hwnd: HWND, path: &Path) -> bool {
    let prompt = HSTRING::from(format!(
        "{}\n\nThis file changed on disk. Reload from disk and discard any unsaved edits?",
        path.display()
    ));
    let title = w!("Code++: file changed externally");
    let response =
        unsafe { MessageBoxW(Some(main_hwnd), &prompt, title, MB_YESNO | MB_ICONQUESTION) };
    response == IDYES
}

/// Generic Yes/No prompt ŌĆö returns `true` for Yes, `false` for No
/// (or any other dismissal). Modal, so the caller must drop any
/// `&mut WindowState` borrow before calling.
fn show_yes_no_dialog(main_hwnd: HWND, title: &str, message: &str) -> bool {
    let title_w = HSTRING::from(title);
    let msg_w = HSTRING::from(message);
    let response = unsafe {
        MessageBoxW(
            Some(main_hwnd),
            &msg_w,
            &title_w,
            MB_YESNO | MB_ICONQUESTION,
        )
    };
    response == IDYES
}

/// Simple modal OK / Cancel prompt. Returns `true` for OK,
/// `false` for Cancel (or any other dismissal ŌĆö X in the title
/// bar, Esc). Warning icon (matches the "you're about to lose
/// something" tone the OK / Cancel pattern usually indicates ŌĆö
/// used by "Move to Recycle Bin" today, applicable to any
/// destructive-but-recoverable confirmation).
///
/// Modal, so the caller MUST drop any `&mut WindowState` borrow
/// before calling ŌĆö same UB rule as [`show_yes_no_dialog`].
fn show_ok_cancel_dialog(main_hwnd: HWND, title: &str, message: &str) -> bool {
    let title_w = HSTRING::from(title);
    let msg_w = HSTRING::from(message);
    let response = unsafe {
        MessageBoxW(
            Some(main_hwnd),
            &msg_w,
            &title_w,
            MB_OKCANCEL | MB_ICONWARNING,
        )
    };
    response == IDOK
}

/// Format the "Move to Recycle Bin" confirmation dialog's body
/// text. Pure function so the exact wording is unit-testable.
/// Matches the wording the user requested verbatim:
///
/// > The file "C:\path\to\file.rb"
/// > will be moved to your Recycle Bin and this document will
/// > be closed.
/// > Continue?
fn move_to_recycle_bin_prompt_for(path: &Path) -> String {
    format!(
        "The file \"{}\"\nwill be moved to your Recycle Bin and this document will be closed.\nContinue?",
        path.display()
    )
}

/// Outcome of a [`show_save_confirm_dialog`] modal ŌĆö Notepad++'s
/// "Save file 'X' ?" three-way prompt.
///
///   * `Yes` ŌĆö save before proceeding (with the close).
///   * `No` ŌĆö discard changes and proceed.
///   * `Cancel` ŌĆö abort the operation; the buffer stays open.
///
/// Anything other than the three explicit buttons (Esc, Alt-F4 on
/// the dialog, the X in the title bar) maps to `Cancel` ŌĆö that's
/// the safe default: the user did not affirm a destructive action,
/// so we treat the dismissal as "abort." Matches what N++ does.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum SaveConfirmResult {
    Yes,
    No,
    Cancel,
}

/// Map the `MessageBoxW` return value (`MESSAGEBOX_RESULT`) to a
/// [`SaveConfirmResult`]. Centralised so the unit tests can
/// exercise the mapping without spinning up a real Win32 modal.
fn save_confirm_from_message_box(
    response: windows::Win32::UI::WindowsAndMessaging::MESSAGEBOX_RESULT,
) -> SaveConfirmResult {
    if response == IDYES {
        SaveConfirmResult::Yes
    } else if response == IDNO {
        SaveConfirmResult::No
    } else {
        // IDCANCEL, IDABORT, or any unexpected dismissal
        // (Esc, Alt-F4, dialog-X) ŌĆö all map to "abort the
        // close." Safe default; matches Notepad++.
        SaveConfirmResult::Cancel
    }
}

/// Format the "Save file 'NAME' ?" prompt body for
/// [`show_save_confirm_dialog`]. Extracted so the unit-test
/// suite can pin the exact spec wording without spinning up a
/// real Win32 modal ŌĆö the test calls this fn and asserts the
/// returned string against the verbatim spec, which means a
/// stray edit to either the format string or the test trips
/// the assertion.
fn save_confirm_prompt_for(display_name: &str) -> String {
    format!("Save file '{display_name}' ?")
}

/// "Save file 'NAME' ?" three-way confirmation ŌĆö shown when the
/// user closes a tab whose buffer has unsaved changes. Title:
/// `Save`. Question-mark icon (matches `show_yes_no_dialog`'s
/// styling). Buttons: Yes / No / Cancel.
///
/// `display_name` is the tab strip name as rendered by
/// [`tab_display_name`] ŌĆö the same "FILENAME" the user already
/// sees. The single-quote wrapping in the prompt matches N++'s
/// formatting verbatim so muscle-memory carries over.
///
/// Modal: caller MUST drop any `&mut WindowState` borrow before
/// invoking, same UB rule as [`show_yes_no_dialog`].
fn show_save_confirm_dialog(main_hwnd: HWND, display_name: &str) -> SaveConfirmResult {
    let title = w!("Save");
    let prompt = HSTRING::from(save_confirm_prompt_for(display_name));
    let response = unsafe {
        MessageBoxW(
            Some(main_hwnd),
            &prompt,
            title,
            MB_YESNOCANCEL | MB_ICONQUESTION,
        )
    };
    save_confirm_from_message_box(response)
}

/// Show a non-fatal error dialog. Standalone for the same reason as
/// `show_reload_dialog`.
pub(crate) fn show_error_dialog(main_hwnd: HWND, title: &str, message: &str) {
    let title_w = HSTRING::from(title);
    let msg_w = HSTRING::from(message);
    unsafe {
        MessageBoxW(Some(main_hwnd), &msg_w, &title_w, MB_OK | MB_ICONWARNING);
    }
}

/// File-open / file-save filter strings the OS dialog displays in
/// the "Files of type" combo box. Win32 expects pairs of
/// NUL-terminated wide strings (display label, glob) terminated
/// by an extra empty NUL ŌĆö i.e. the trailing `\0\0` below isn't a
/// typo, it's how the API knows the list ended.
///
/// Kept generic `*.*` for now; lexer-specific filters (e.g. `*.rs;
/// *.toml` for Rust projects) would require knowing the active
/// language at dialog-show time, which the Phase 5 cross-platform
/// dialog abstraction can layer in.
fn build_dialog_filter() -> Vec<u16> {
    "All Files (*.*)\0*.*\0Text Files (*.txt)\0*.txt\0\0"
        .encode_utf16()
        .collect()
}

/// Show the standard "Open" dialog and return every path the user
/// selected. Returns an empty `Vec` if the user cancelled. Owner
/// is the main Code++ HWND so the dialog is modal-relative and
/// the user can't hit the file menu twice.
///
/// **Multi-select.** `OFN_ALLOWMULTISELECT` is set so the user
/// can Ctrl+click / Shift+click to open several files in one
/// dialog. With `OFN_EXPLORER`, Windows fills `lpstrFile` with a
/// double-NUL-terminated sequence: for a single selection it's
/// just the full path followed by two NULs; for multiple
/// selections it's the directory, then each filename (basename
/// only), then two NULs. `parse_ofn_multi_select_buffer` handles
/// both shapes and returns absolute `PathBuf`s.
///
/// Buffer size: 32 KiB wide-chars (~ 64 KB). Windows recommends
/// a large buffer for multi-select because the entire selection
/// (directory + every filename + separators) has to fit or the
/// dialog fails with `ERROR_INSUFFICIENT_BUFFER`. `MAX_PATH`
/// (260) would silently truncate on a user picking a dozen files
/// from a deep directory; 32 KiB accommodates hundreds of typical
/// filenames without any practical constraint on the user's
/// selection count.
///
/// The returned `PathBuf`s decode via `from_utf16_lossy` ŌĆö paths
/// containing surrogate halves (extremely rare on real filesystems)
/// degrade to a U+FFFD-substituted path that `std::fs::open` will
/// then refuse, surfacing as an Open error rather than silent
/// corruption.
fn prompt_open_paths(owner: HWND) -> Vec<PathBuf> {
    let filter = build_dialog_filter();
    // 32 KiB wide-chars ŌĆö see the doc comment for why the
    // `MAX_PATH + 1` used by the save-side dialog doesn't work
    // for multi-select.
    const MULTISELECT_BUFFER_CHARS: usize = 32 * 1024;
    let mut buf = vec![0u16; MULTISELECT_BUFFER_CHARS];

    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(buf.as_mut_ptr()),
        nMaxFile: buf.len() as u32,
        nFilterIndex: 1,
        // OFN_NOCHANGEDIR: without it, the dialog silently mutates the
        // process working directory as a side effect of the user
        // navigating around. That would corrupt every later relative
        // path the app resolves (including save_buffer_as's `Path::new(".")`
        // fallback when the chosen file has no parent component).
        //
        // OFN_ALLOWMULTISELECT: Ctrl/Shift-click accumulates a
        // multi-file selection. Requires OFN_EXPLORER for the
        // NUL-separated result format used here; the old
        // space-separated short-name format (without EXPLORER)
        // is unusable ŌĆö filenames with spaces would be silently
        // corrupted.
        Flags: OFN_FILEMUSTEXIST
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_ALLOWMULTISELECT
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };

    // SAFETY: `&mut ofn` is a valid pointer to a fully-initialised
    // `OPENFILENAMEW` struct. `filter` and `buf` outlive the call
    // (both are local Vecs held until function return). The
    // dialog blocks until the user clicks OK or Cancel; on
    // success Windows writes the double-NUL-terminated selection
    // list into `buf`.
    let ok = unsafe { GetOpenFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        // Disambiguate Cancel (returns 0 from CommDlgExtendedError)
        // from a real failure. FNERR_BUFFERTOOSMALL fires when the
        // user's selection wouldn't fit in the 32 KiB buffer above
        // ŌĆö surface it to the user rather than looking like a
        // mis-click cancel. Any other error code is unusual (the
        // OFN struct itself is fully-init) but still warrants a
        // log so the ambient failure is diagnosable.
        let err = unsafe { CommDlgExtendedError() };
        if err == FNERR_BUFFERTOOSMALL {
            show_error_dialog(
                owner,
                "Open ŌĆö too many files",
                "The dialog can't return this many files in one selection. \
                 Please open fewer files at once (or open the folder as a workspace).",
            );
        } else if err.0 != 0 {
            tracing::warn!(
                code = err.0,
                "GetOpenFileNameW failed with a non-cancel error code"
            );
        }
        return Vec::new();
    }
    parse_ofn_multi_select_buffer(&buf)
}

/// Parse the double-NUL-terminated wide-char buffer that
/// `GetOpenFileNameW(OFN_ALLOWMULTISELECT | OFN_EXPLORER)` fills
/// in on success. Two shapes to handle:
///
///   * **Single file selected:** the buffer contains one
///     full path followed by two NULs. Return a one-element
///     `Vec` with that path.
///   * **Multiple files selected:** the buffer contains the
///     directory, then each filename (basename only, no
///     separator prefix), each entry NUL-terminated, and the
///     whole list ends with an additional NUL (so the buffer
///     is double-NUL-terminated). Return one `PathBuf` per
///     filename, each joined onto the directory.
///
/// Disambiguation: if the first NUL-terminated entry is followed
/// by more non-NUL bytes, we're in the multi-file shape. If not,
/// we're in the single-file shape.
///
/// Broken out as a pure function so it can be unit-tested
/// without invoking the actual Win32 dialog.
fn parse_ofn_multi_select_buffer(buf: &[u16]) -> Vec<PathBuf> {
    // Split the wide buffer into NUL-terminated fields. Windows
    // pads the buffer with zeros beyond the double-NUL terminator,
    // so `split(|&c| c == 0)` yields empty strings at the tail;
    // we filter those out.
    let mut fields = buf
        .split(|&c| c == 0)
        .take_while(|slice| !slice.is_empty())
        .map(String::from_utf16_lossy);
    let Some(first) = fields.next() else {
        return Vec::new();
    };
    let rest: Vec<String> = fields.collect();
    if rest.is_empty() {
        // Single-file shape ŌĆö first entry IS the full path.
        return vec![PathBuf::from(first)];
    }
    // Multi-file shape ŌĆö first entry is the directory, remaining
    // are basenames.
    let dir = PathBuf::from(first);
    rest.into_iter()
        .map(|name| {
            let mut p = dir.clone();
            p.push(name);
            p
        })
        .collect()
}

/// Show the standard "Save As" dialog and return the chosen path,
/// or `None` if the user cancelled. `default_name` (if `Some`)
/// pre-fills the file-name edit field ŌĆö used by Save As to suggest
/// the active tab's current basename.
///
/// `OFN_OVERWRITEPROMPT` is set so the OS handles the "file
/// already exists, overwrite?" confirmation ŌĆö saves us
/// reimplementing it. `OFN_PATHMUSTEXIST` rejects nonexistent
/// directories at the dialog level rather than letting the save
/// fail later with a less helpful error.
fn prompt_save_path(owner: HWND, default_name: Option<&str>) -> Option<PathBuf> {
    let filter = build_dialog_filter();
    let mut path = vec![0u16; MAX_PATH as usize + 1];
    if let Some(name) = default_name {
        // Pre-fill the file-name edit field. Truncate to MAX_PATH
        // and NUL-terminate; longer names would trip Windows' own
        // length check. Truncation here is rare (most file names
        // are well under 260 code units) but trace it so a future
        // user report of "Save As suggested a wrong name" is
        // diagnosable from the log.
        let utf16: Vec<u16> = name.encode_utf16().collect();
        let len = utf16.len().min(MAX_PATH as usize);
        if len < utf16.len() {
            tracing::warn!(
                full_len = utf16.len(),
                truncated_to = len,
                "Save As default filename longer than MAX_PATH; truncated",
            );
        }
        path[..len].copy_from_slice(&utf16[..len]);
        path[len] = 0;
    }

    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(path.as_mut_ptr()),
        nMaxFile: path.len() as u32,
        nFilterIndex: 1,
        // See `prompt_open_path` for why OFN_NOCHANGEDIR is mandatory.
        Flags: OFN_OVERWRITEPROMPT
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };

    // SAFETY: same contract as `prompt_open_path` ŌĆö fully-init
    // struct, buffers outlive the call.
    let ok = unsafe { GetSaveFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        return None;
    }

    let nul = path.iter().position(|&u| u == 0).unwrap_or(path.len());
    let s = String::from_utf16_lossy(&path[..nul]);
    if s.is_empty() {
        return None;
    }
    Some(PathBuf::from(s))
}

/// File-type filter for the Load / Save Session dialogs ŌĆö `.xml`
/// first (that's the shape Notepad++ uses for its session files),
/// with an "All Files" fallback so hand-picked non-standard
/// extensions still work. Wire format is the same double-NUL pair
/// list [`build_dialog_filter`] documents.
fn build_session_dialog_filter() -> Vec<u16> {
    "Session Files (*.xml)\0*.xml\0All Files (*.*)\0*.*\0\0"
        .encode_utf16()
        .collect()
}

/// Show the "Open" dialog constrained to `.xml`, single-select.
/// Returns `None` on Cancel or on `CommDlgExtendedError` reporting
/// a non-cancel failure. Ambient dialog behaviour (`OFN_NOCHANGEDIR`,
/// path-must-exist, hide-read-only) matches [`prompt_open_paths`];
/// diverges only in the filter and the single-file result shape.
fn prompt_open_session_xml_path(owner: HWND) -> Option<PathBuf> {
    let filter = build_session_dialog_filter();
    let mut path = vec![0u16; MAX_PATH as usize + 1];
    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(path.as_mut_ptr()),
        nMaxFile: path.len() as u32,
        nFilterIndex: 1,
        Flags: OFN_FILEMUSTEXIST
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };
    // SAFETY: same contract as `prompt_open_paths` ŌĆö fully-initialised
    // OFN, buffers outlive the call, dialog blocks until dismissed.
    let ok = unsafe { GetOpenFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        let err = unsafe { CommDlgExtendedError() };
        if err.0 != 0 {
            tracing::warn!(
                code = err.0,
                "GetOpenFileNameW (session) failed with a non-cancel error code"
            );
        }
        return None;
    }
    let nul = path.iter().position(|&u| u == 0).unwrap_or(path.len());
    let s = String::from_utf16_lossy(&path[..nul]);
    if s.is_empty() {
        return None;
    }
    Some(PathBuf::from(s))
}

/// Show the "Save As" dialog constrained to `.xml`, pre-filled with
/// `session.xml` as the default name. `OFN_OVERWRITEPROMPT` +
/// `OFN_PATHMUSTEXIST` match the discipline the tab-Save-As helper
/// [`prompt_save_path`] uses; only the filter and default-name
/// suggestion differ.
fn prompt_save_session_xml_path(owner: HWND) -> Option<PathBuf> {
    let filter = build_session_dialog_filter();
    let mut path = vec![0u16; MAX_PATH as usize + 1];
    let default_name = "session.xml";
    let utf16: Vec<u16> = default_name.encode_utf16().collect();
    let len = utf16.len().min(MAX_PATH as usize);
    path[..len].copy_from_slice(&utf16[..len]);
    path[len] = 0;

    let mut ofn = OPENFILENAMEW {
        lStructSize: core::mem::size_of::<OPENFILENAMEW>() as u32,
        hwndOwner: owner,
        lpstrFilter: PCWSTR(filter.as_ptr()),
        lpstrFile: PWSTR(path.as_mut_ptr()),
        nMaxFile: path.len() as u32,
        nFilterIndex: 1,
        Flags: OFN_OVERWRITEPROMPT
            | OFN_PATHMUSTEXIST
            | OFN_HIDEREADONLY
            | OFN_EXPLORER
            | OFN_NOCHANGEDIR,
        ..Default::default()
    };
    // SAFETY: same contract as `prompt_save_path` above ŌĆö fully-init
    // OFN struct, filter + path buffers outlive the call.
    let ok = unsafe { GetSaveFileNameW(&raw mut ofn) }.as_bool();
    if !ok {
        return None;
    }
    let nul = path.iter().position(|&u| u == 0).unwrap_or(path.len());
    let s = String::from_utf16_lossy(&path[..nul]);
    if s.is_empty() {
        return None;
    }
    Some(PathBuf::from(s))
}

/// File ŌåÆ Save Session... ŌĆö capture every path-bound open tab and
/// write a Notepad++-shape session XML at a user-picked location.
/// Untitled buffers are skipped (no path to record); the resulting
/// file therefore contains only tabs a fresh N++ (or Code++) instance
/// can reopen from disk. The active tab contributes live caret +
/// scroll positions pulled from Scintilla; the rest carry zeros.
///
/// Dialog and file-write happen with **no** `&mut WindowState` borrow
/// held ŌĆö the OS dialog spins its own message pump that would
/// re-enter `wnd_proc`. Metadata is snapshotted out of state before
/// the dialog opens.
fn handle_save_session(hwnd: HWND) {
    // 1. Snapshot the metadata under a brief borrow. Clone every
    //    field into an owned tuple so the borrow ends before the
    //    dialog opens. Editor reads happen inside the same block
    //    because state.editor and state.shell are disjoint fields
    //    on `&mut WindowState` ŌĆö the borrow checker treats them
    //    independently.
    struct SaveMeta {
        files: Vec<NppFile>,
        active_index: usize,
    }
    let Some(meta) = (unsafe {
        state_from_hwnd(hwnd).map(|state| {
            let active = state.shell.active_tab;
            // Collect path-bound tabs alongside their original
            // vector index. The original index tells us whether
            // the tab is the active one (so we pull live caret /
            // scroll) or a background tab (zeros).
            let path_tabs: Vec<(usize, PathBuf, LangType, bool)> = state
                .shell
                .tabs
                .iter()
                .enumerate()
                .filter_map(|(i, t)| t.path.as_ref().map(|p| (i, p.clone(), t.lang, t.pinned)))
                .collect();
            // active_index against the FILTERED list ŌĆö count
            // path-bound tabs preceding the active one. Zero if
            // no active tab or the active tab is untitled.
            let active_index = active.map_or(0, |ai| {
                state
                    .shell
                    .tabs
                    .iter()
                    .take(ai)
                    .filter(|t| t.path.is_some())
                    .count()
            });
            let files: Vec<NppFile> = path_tabs
                .into_iter()
                .map(|(orig_idx, path, lang, pinned)| {
                    let (start_pos, end_pos, first_visible_line) = if Some(orig_idx) == active {
                        let s = state.editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as u64;
                        let e = state.editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as u64;
                        let fv = state.editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0).max(0) as u32;
                        (s, e, fv)
                    } else {
                        // Non-active tabs: zeros for now. Per-tab
                        // caret persistence across tab switches is
                        // tracked as milestone 6b in DESIGN.md and
                        // has the same "future" shape here ŌĆö same
                        // gap the internal session.xml save path
                        // documents.
                        (0, 0, 0)
                    };
                    NppFile {
                        filename: path,
                        lang: npp_name_for_lang(lang).to_string(),
                        first_visible_line,
                        start_pos,
                        end_pos,
                        tab_pinned: YesNo::from_bool(pinned),
                        encoding: -1,
                        user_read_only: YesNo::No,
                    }
                })
                .collect();
            SaveMeta {
                files,
                active_index,
            }
        })
    }) else {
        return;
    };

    // 2. Prompt for a path. This spins a nested message loop; no
    //    state borrow may be alive when it does.
    let Some(save_path) = prompt_save_session_xml_path(hwnd) else {
        return;
    };

    // 3. Emit the XML. Errors surface via the standard error dialog
    //    ŌĆö the user picked this path and expects a filesystem
    //    outcome, so a silent log wouldn't be right.
    let doc = NppSessionDoc {
        session: NppSession {
            active_view: 0,
            main_view: NppView {
                active_index: meta.active_index,
                files: meta.files,
            },
            // Sub view is always empty on our side (single view) but
            // written for N++ shape parity so an N++ opening the
            // file sees the element it expects.
            sub_view: Some(NppView::default()),
        },
    };
    if let Err(e) = doc.save_to_xml(&save_path) {
        show_error_dialog(
            hwnd,
            "Save Session failed",
            &format!(
                "Could not write the session file:\n\n{}\n\n{}",
                save_path.display(),
                e
            ),
        );
    }
}

/// File ŌåÆ Load Session... ŌĆö pick a Notepad++-shape session XML and
/// open every path-bound `<File>` entry inside it. Per-file metadata
/// (caret position, tab pin state, language override) is applied by
/// pre-populating `shell.session.tabs` with matching entries before
/// each `open_file` call ŌĆö `Shell::apply_load_result` picks the
/// metadata up on load completion via its by-path lookup, the same
/// mechanism the internal startup-restore path uses.
///
/// Already-open paths are handled by `Shell::open_file`'s built-in
/// dedupe: the existing tab activates instead of reloading, so the
/// user's in-progress edits are preserved (Load Session does not
/// force a reset).
fn handle_load_session(hwnd: HWND) {
    // 1. Prompt outside any borrow ŌĆö dialog spins its own pump.
    let Some(load_path) = prompt_open_session_xml_path(hwnd) else {
        return;
    };

    // 2. Read + parse. Errors surface via the standard dialog.
    let doc = match NppSessionDoc::load_from_xml(&load_path) {
        Ok(d) => d,
        Err(e) => {
            show_error_dialog(
                hwnd,
                "Load Session failed",
                &format!(
                    "Could not read the session file:\n\n{}\n\n{}",
                    load_path.display(),
                    e
                ),
            );
            return;
        }
    };

    // Resolve `active_index` to an absolute path *before* filtering
    // ŌĆö the UNC/empty-filename `filter_map` below drops entries,
    // which shifts every downstream index left by one and would
    // silently activate the wrong tab (or none, falling back to the
    // last-file-wins effect of `Shell::open_file`). Anchoring to a
    // path instead of a positional index makes the restore
    // independent of what got filtered / truncated. If the recorded
    // active file is itself a rejected UNC path or a corrupt empty
    // entry, `recorded_active_path` naturally becomes `None` when
    // filtering removes it ŌĆö the later `tabs.iter().position(...)`
    // returns `None` and no override happens, which is the correct
    // fallback ("we can't restore that tab; leave the last-loaded
    // one active").
    let recorded_active_path: Option<PathBuf> = doc
        .session
        .main_view
        .files
        .get(doc.session.main_view.active_index)
        .map(|f| f.filename.clone());

    // Cap the parse-time cost too ŌĆö bound how many `<File>` entries
    // we walk BEFORE the filter runs, not just after it (the
    // filter allocates one `PathBuf` clone per surviving entry, so
    // an attacker-controlled n-way `<File>` list would otherwise
    // eat unbounded CPU + allocations before the post-filter
    // `.take` truncation caught it). Truncated count is logged
    // below.
    let raw_file_count = doc.session.main_view.files.len();
    let mut rejected_unc = 0usize;
    let entries: Vec<(PathBuf, u64, Option<i32>, bool)> = doc
        .session
        .main_view
        .files
        .into_iter()
        .take(MAX_SESSION_TABS)
        .filter_map(|f| {
            // Skip <File> elements with no filename ŌĆö corrupt / hand-
            // authored entries. Also skip entries whose filename is
            // empty (parses cleanly but resolves to `.`).
            if f.filename.as_os_str().is_empty() {
                return None;
            }
            // Reject non-local paths. On Windows, any path starting
            // with `\\` is UNC (`\\server\share\...`) or a device /
            // verbatim namespace (`\\.\...`, `\\?\...`). Feeding a
            // hostile UNC into `std::fs::open` triggers an outbound
            // SMB connection with the current user's NTLM
            // credentials ŌĆö a Responder/ntlmrelayx-style hash
            // capture primitive. A session `.xml` can arrive from a
            // low-trust source (email, chat, "restore my workspace"
            // link), unlike a plugin-driven `NPPM_DOOPEN` where the
            // caller is already in-process trusted code. Reject
            // silently at the parse boundary; count rejections and
            // warn the user once at the end so a legitimate-looking
            // session that happens to reference network shares
            // doesn't disappear without an explanation.
            if is_non_local_windows_path(&f.filename) {
                tracing::warn!(
                    path = ?f.filename,
                    "Load Session: rejected non-local path (UNC / device / verbatim namespace)"
                );
                rejected_unc += 1;
                return None;
            }
            let lang_id = lang_type_from_npp_name(&f.lang).map(|l| l.0);
            Some((f.filename, f.start_pos, lang_id, f.tab_pinned.as_bool()))
        })
        .collect();

    if entries.is_empty() {
        if rejected_unc > 0 {
            show_error_dialog(
                hwnd,
                "Load Session",
                &format!(
                    "This session file contained {rejected_unc} network / UNC path(s), \
                     which Code++ does not open from session files for security reasons.\n\n\
                     No local files were opened."
                ),
            );
        }
        return;
    }

    // Report the truncation from the earlier `.take` ŌĆö `entries`
    // is already capped, but the user (and future post-mortem
    // reader of the log) needs to know how many `<File>` entries
    // were silently dropped. The cap protects the O(n┬▓) find loop
    // below AND the parse-time allocation cost of the filter above.
    let over_cap = raw_file_count.saturating_sub(MAX_SESSION_TABS);
    if over_cap > 0 {
        tracing::warn!(
            cap = MAX_SESSION_TABS,
            dropped = over_cap,
            "Load Session: entries exceed cap; excess dropped",
        );
    }

    // 3. Pre-populate the by-path metadata cache and kick each open.
    //    Re-acquire `state_from_hwnd` on every iteration to match
    //    the discipline `ID_FILE_OPEN` uses ŌĆö a synchronous plugin
    //    hook added to `Shell::open_file` in a future change
    //    (`NPPN_FILEBEFOREOPEN`, DESIGN.md ┬¦7.4) would re-enter
    //    `wnd_proc` and alias the borrow otherwise. Belt and
    //    braces; `open_file` today does not reenter.
    //
    // While iterating we also:
    //
    //   * Apply the pin state via `Shell::set_pinned` on the
    //     just-opened tab. `apply_load_result` only mutates the
    //     `tab.pinned` flag, not the vector position, so without
    //     this call a pinned tab would land at wherever `open_file`
    //     pushed it (end of the vector) and the "pinned before
    //     unpinned" invariant would be broken until the next app
    //     restart, when `normalize_session_pinning` sorts session.xml
    //     back into shape. `set_pinned` is the one path that
    //     relocates the tab into the correct cluster.
    //
    //   * Capture the recorded-active file's stable `tab.id` at
    //     the moment we process its entry. Positional indices
    //     would shift under the `set_pinned` relocations that
    //     happen later in the same loop, and a by-path lookup in
    //     step 4 wouldn't find a still-loading tab (its `tab.path`
    //     stays `None` until `apply_load_result` fires). `tab.id`
    //     is assigned synchronously by `open_file` and never
    //     moves, so it's the only identity that survives both.
    let mut deduped = false;
    let mut recorded_active_target_id: Option<i32> = None;
    for (path, cursor, lang, pinned) in entries {
        let is_recorded_active = recorded_active_path.as_ref() == Some(&path);
        let outcome = unsafe {
            let Some(state) = state_from_hwnd(hwnd) else {
                continue;
            };
            // Merge into shell.session.tabs so apply_load_result's
            // by-path lookup finds our cursor/lang/pinned values
            // when the async load completes. Insert-or-update: if
            // the path already has an entry (e.g. a startup-restore
            // record we haven't consumed yet, or a previous Load
            // Session invocation), overwrite its metadata rather
            // than piling up duplicates.
            let stored = &mut state.shell.session.tabs;
            match stored
                .iter_mut()
                .find(|t| t.path.as_deref() == Some(path.as_path()))
            {
                Some(existing) => {
                    existing.cursor = cursor;
                    existing.lang = lang;
                    existing.pinned = pinned;
                }
                None => stored.push(codepp_core::Tab {
                    path: Some(path.clone()),
                    cursor,
                    lang,
                    pinned,
                    ..codepp_core::Tab::default()
                }),
            }
            let outcome = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                state.shell.open_file(path)
            }))
            .unwrap_or(OpenFileOutcome::Rejected);
            // Post-open reconcile: `open_file` leaves
            // `shell.active_tab` pointing at the affected tab
            // (freshly-pushed or the dedupe target). Capture the
            // stable id BEFORE `set_pinned` potentially relocates,
            // then apply the pin state.
            if !matches!(outcome, OpenFileOutcome::Rejected) {
                if let Some(idx) = state.shell.active_tab {
                    if is_recorded_active {
                        recorded_active_target_id = state.shell.tabs.get(idx).map(|t| t.id);
                    }
                    let _ = state.shell.set_pinned(idx, pinned);
                }
            }
            outcome
        };
        if matches!(outcome, OpenFileOutcome::SwitchedToExisting(_)) {
            deduped = true;
        }
    }

    // 4. Restore the recorded active tab. `Shell::open_file` sets
    //    the just-opened tab as active on every call, so the loop
    //    above ends with the *last* file active ŌĆö override that by
    //    resolving `recorded_active_target_id` (the tab-id captured
    //    inside the loop at the moment the recorded active file
    //    was processed) back to a live index and setting
    //    `shell.active_tab`. When each async load completes,
    //    `apply_load_result` reads `active_tab` and binds the
    //    Scintilla view to the matching doc iff the just-loaded
    //    tab is the active one; making the target active *before*
    //    its load completes is what lets the paint land on the
    //    correct buffer without a second manual rebind. Using
    //    `tab.id` here (not path, not position) so `set_pinned`
    //    relocations from later iterations don't invalidate the
    //    target.
    let mut activated_recorded = false;
    if let Some(target_id) = recorded_active_target_id {
        unsafe {
            if let Some(state) = state_from_hwnd(hwnd) {
                if let Some(idx) = state.shell.tabs.iter().position(|t| t.id == target_id) {
                    if state.shell.active_tab != Some(idx) {
                        state.shell.active_tab = Some(idx);
                        activated_recorded = true;
                    }
                }
            }
        }
    }

    // 5. Sync the tab strip + drain any queued plugin notifications.
    //    Same tail as ID_FILE_OPEN ŌĆö the loader's async completions
    //    will re-sync on WM_APP_WAKE, this handles the sync
    //    "switched to existing tab" case and the manual
    //    active-tab override above.
    // SAFETY: these helpers operate on the wnd_proc's own state via
    // HWND lookup; no aliasing `&mut WindowState` is alive at this
    // point (the last state borrow ended with the `if let` above).
    unsafe {
        refresh_tab_chrome(hwnd);
        if deduped || activated_recorded {
            handle_tab_selchange(hwnd);
        }
        fire_queued_notifications(hwnd);
    }
}

/// File ŌåÆ Print ŌĆö snapshots the active tab's display name plus a copy
/// of the [`EditorHandle`] under a brief `&mut WindowState` borrow,
/// then dispatches to the [`print`] module for the OS print dialog and
/// the two-pass render loop. All GDI + spooler work happens outside
/// the borrow because `PrintDlgW` spins its own message pump that
/// would re-enter `wnd_proc`.
///
/// Idempotent no-op when no tab is open (`refresh_file_menu` greys
/// the menu item in that case, but a plugin-driven `NPPM_MENUCOMMAND`
/// could still fire the id independently ŌĆö the guard here makes the
/// mismatch a silent no-op instead of a panic).
fn handle_print(hwnd: HWND) {
    // Snapshot: display name (basename / new N / custom label) plus a
    // copy of the editor handle. Editor is `Copy` ŌĆö captures the
    // direct-call function pointer once at creation, then every copy
    // dispatches identically. Dropping the state borrow BEFORE the
    // dialog opens is the mandatory pattern (see the load-session
    // handler for the same rationale).
    let (display_name, editor) = unsafe {
        let Some(state) = state_from_hwnd(hwnd) else {
            return;
        };
        let Some(tab) = state.shell.active() else {
            return;
        };
        let name = print::display_name_for(
            tab.path.as_deref(),
            tab.untitled_seq,
            tab.custom_name.as_deref(),
        );
        (name, state.editor)
    };
    print::print_active_document(hwnd, &display_name, editor);
}

/// File ŌåÆ Print Preview ŌĆö snapshot the display name + editor handle
/// under a brief `&mut WindowState` borrow, then dispatch to the
/// [`print_preview`] module. Same borrow-lifetime discipline as
/// `handle_print`: the modal preview pump can re-enter this
/// `wnd_proc`, so no borrow may span it.
fn handle_print_preview(hwnd: HWND) {
    let (display_name, editor) = unsafe {
        let Some(state) = state_from_hwnd(hwnd) else {
            return;
        };
        let Some(tab) = state.shell.active() else {
            return;
        };
        let name = print::display_name_for(
            tab.path.as_deref(),
            tab.untitled_seq,
            tab.custom_name.as_deref(),
        );
        (name, state.editor)
    };
    print_preview::show_print_preview(hwnd, &display_name, editor);
}

// --- About dialog ----------------------------------------------------
//
// Custom modal dialog built on a `WS_POPUP` + `WS_CAPTION` + `WS_SYSMENU`
// window ŌĆö same scaffolding as the Goto / Find-Replace dialogs so the
// modal pump, panic boundary, and themed-paint workaround are reused
// verbatim. Layout mirrors Notepad++'s About box:
//
//   ŌöīŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöÉ
//   Ōöé  [icon]   Code++ v<ver>   (64-bit)                       Ōöé
//   Ōöé           A cross-platform Notepad++ clone ŌĆ”             Ōöé
//   Ōöé                                                          Ōöé
//   Ōöé  [icon]  Home:  https://code-plus-plus.org/              Ōöé
//   Ōöé                                                          Ōöé
//   Ōöé  ŌöīŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ MIT License ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöÉ  Ōöé
//   Ōöé  Ōöé <license body, wrapped in a multi-line STATIC>     Ōöé  Ōöé
//   Ōöé  ŌööŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöś  Ōöé
//   Ōöé                          [ OK ]                          Ōöé
//   ŌööŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöś
//
// The two `[icon]` controls are both clickable (`SS_NOTIFY`) and route
// the click to `ShellExecuteW("open", url, ŌĆ”)` so either the small
// icon or the URL text below opens the home page in the user's
// default browser. Hovering the URL text or the small icon switches
// the cursor to `IDC_HAND` via a `WM_SETCURSOR` hook in
// `about_wnd_proc` ŌĆö the parent override is needed because
// SS_NOTIFY by itself doesn't set a hover cursor.

/// Heap-allocated state for the About dialog. Owned by
/// `show_about_dialog`'s stack frame for the dialog's lifetime; the
/// raw pointer is stashed in the dialog HWND's `GWLP_USERDATA`.
///
/// The bold title `HFONT` is owned by a separate `GdiObjectGuard`
/// because it's only ever read by Win32's message dispatch (via
/// `WM_SETFONT` plumbed through `apply_dialog_font`) and never by
/// our `wnd_proc`, so threading it through state would be noise.
///
/// The chameleon `HICON` *is* tracked here and freed by the
/// `Drop` impl below ŌĆö that makes the icon's lifetime
/// indistinguishable from the state's, eliminating the
/// declaration-order fragility a separate guard would carry (a
/// reorder that puts the guard above the box would silently let
/// `WM_DRAWITEM` read a freed icon between the guard's drop and
/// the box's drop).
struct AboutDialogState {
    /// HWND of the URL link STATIC. The `wnd_proc` compares `wparam`
    /// against this on `WM_SETCURSOR` to switch to `IDC_HAND`, and
    /// against `lparam` on `WM_CTLCOLORSTATIC` to paint the link
    /// text blue.
    link_hwnd: HWND,
    /// HWND of the owner (main editor) window. The IDOK/IDCANCEL
    /// and `WM_CLOSE` handlers re-enable the owner *before*
    /// `DestroyWindow(dlg)` so window activation transfers
    /// naturally back to the editor instead of falling through
    /// z-order to whatever other app happened to be running ŌĆö a
    /// Win32 quirk where destroying a child whose owner is
    /// disabled hands focus to the next-eligible window in the
    /// desktop's activation list.
    owner_hwnd: HWND,
    /// Home URL, owned as a UTF-16 string so `ShellExecuteW` can
    /// take a `PCWSTR` directly. The `HSTRING` keeps the buffer
    /// alive across the call.
    home_url: HSTRING,
    /// Chameleon `HICON` for the owner-draw STATIC. Loaded once
    /// by `show_about_dialog`; the `wnd_proc` reads it on every
    /// `WM_DRAWITEM` for the icon control. Drawn via `DrawIconEx`
    /// with `DI_NORMAL` so the icon's 32bpp alpha channel is
    /// honoured rather than masked to black (the bug that
    /// surfaced the original "icon has a black background"
    /// report). Freed by the `Drop` impl below ŌĆö owning the
    /// handle inside the state ties its lifetime exactly to the
    /// `Box`'s and makes a future reorder safe by construction.
    app_icon: HICON,
    /// HWND of the "MIT License" caption STATIC that sits over
    /// the etched frame's top edge. `WM_CTLCOLORSTATIC` compares
    /// `lparam` against this handle to return `dialog_bg_brush`
    /// (opaque background) for this label only, so the label
    /// paints a solid rectangle over the frame line and visually
    /// breaks it. Every other STATIC still returns `NULL_BRUSH`
    /// (transparent).
    lic_title_hwnd: HWND,
}

impl Drop for AboutDialogState {
    fn drop(&mut self) {
        unsafe {
            if !self.app_icon.is_invalid() {
                let _ = DestroyIcon(self.app_icon);
            }
        }
    }
}

extern "system" fn about_wnd_proc(hwnd: HWND, msg: u32, wparam: WPARAM, lparam: LPARAM) -> LRESULT {
    // Same panic-catch wrapper as the other dialog wnd_procs ŌĆö
    // unwinding across `extern "system"` is UB. On panic fall back
    // to DefWindowProcW which is the natural no-op for unhandled
    // messages.
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_NCCREATE => {
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let state_ptr = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as i32;
                let notif = ((wparam.0 >> 16) & 0xFFFF) as u32;
                if cmd == IDOK.0 || cmd == IDCANCEL.0 {
                    // Re-enable the owner BEFORE destroying the
                    // dialog. If we destroy first, Windows looks
                    // for the next-eligible activation target ŌĆö
                    // the disabled owner is skipped and focus
                    // falls through to whatever else is in
                    // z-order, including other apps. Re-enabling
                    // first means the owner is the natural
                    // activation target when the dialog
                    // disappears. The `OwnerEnableGuard` below
                    // still runs on scope exit; calling
                    // `EnableWindow(true)` on an already-enabled
                    // window is a documented no-op.
                    let state_ptr =
                        GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                    if !state_ptr.is_null() {
                        let _ = EnableWindow((*state_ptr).owner_hwnd, true);
                    }
                    let _ = DestroyWindow(hwnd);
                    LRESULT(0)
                } else if cmd == i32::from(IDC_ABOUT_HOME_LINK) && notif == STN_CLICKED {
                    // URL static was clicked ŌĆö open the home page
                    // in the user's default browser.
                    let state_ptr =
                        GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                    if !state_ptr.is_null() {
                        ShellExecuteW(
                            Some(hwnd),
                            w!("open"),
                            &(*state_ptr).home_url,
                            PCWSTR::null(),
                            PCWSTR::null(),
                            SW_SHOWNORMAL,
                        );
                    }
                    LRESULT(0)
                } else {
                    DefWindowProcW(hwnd, msg, wparam, lparam)
                }
            }
            WM_DRAWITEM => {
                // Owner-draw paint for the chameleon STATIC. We
                // intercept rather than rely on `SS_ICON`'s
                // built-in paint because the SS_ICON path on
                // Win11 strips 32bpp alpha and surfaces
                // transparent pixels as black against the dialog
                // background. Painting the dialog brush first,
                // then `DrawIconEx(DI_NORMAL)`, gives the system
                // a clean backdrop and lets it composite the
                // icon's alpha channel correctly.
                let dis = lparam.0 as *const DRAWITEMSTRUCT;
                if !dis.is_null() {
                    let dis = &*dis;
                    if dis.CtlID == u32::from(IDC_ABOUT_ICON) {
                        // Always return "handled" for our control
                        // id, even if `state_ptr` is unexpectedly
                        // null or the icon failed to load. Windows
                        // does not retry `WM_DRAWITEM` for an
                        // owner-draw STATIC, and falling through
                        // to `DefWindowProcW` would leave the
                        // control area unpainted.
                        let state_ptr =
                            GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                        if !state_ptr.is_null() {
                            FillRect(dis.hDC, &raw const dis.rcItem, dialog_bg_brush());
                            let icon = (*state_ptr).app_icon;
                            if !icon.is_invalid() {
                                let w = dis.rcItem.right - dis.rcItem.left;
                                let h = dis.rcItem.bottom - dis.rcItem.top;
                                let _ = DrawIconEx(
                                    dis.hDC,
                                    dis.rcItem.left,
                                    dis.rcItem.top,
                                    icon,
                                    w,
                                    h,
                                    0,
                                    None,
                                    DI_NORMAL,
                                );
                            }
                        }
                        return LRESULT(1);
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_NCDESTROY => {
                // Defensive: zero `GWLP_USERDATA` so any stray
                // message that races between `DestroyWindow`
                // returning and the modal pump's `IsWindow`
                // break can't deref the dangling state pointer.
                // The `Box<AboutDialogState>` itself is owned by
                // the stack frame in `show_about_dialog` and
                // drops on function return, which always happens
                // *after* `DestroyWindow` synchronously delivers
                // `WM_NCDESTROY` ŌĆö so the pointer is still valid
                // at the moment we zero it.
                SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_SETCURSOR => {
                // wparam carries the HWND of the child currently
                // under the cursor. SS_NOTIFY on its own doesn't
                // change the cursor, so we override here when the
                // child is the URL link.
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                if !state_ptr.is_null() {
                    let child = HWND(wparam.0 as *mut c_void);
                    if child == (*state_ptr).link_hwnd {
                        if let Ok(cursor) = LoadCursorW(None, IDC_HAND) {
                            let _ = SetCursor(Some(cursor));
                        }
                        return LRESULT(1);
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_CLOSE => {
                // Same activation-handoff fix as IDOK/IDCANCEL:
                // the title-bar X reaches us as `WM_CLOSE`, and
                // destroying the dialog while the owner is still
                // disabled would leak focus to whatever sits next
                // in z-order (often another app). Re-enable the
                // owner first so activation returns to the editor.
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                if !state_ptr.is_null() {
                    let _ = EnableWindow((*state_ptr).owner_hwnd, true);
                }
                let _ = DestroyWindow(hwnd);
                LRESULT(0)
            }
            // Same Win11-themed-paint workaround as the Goto and
            // Find/Replace dialogs: the system theme service
            // overrides our class hbrBackground for `WS_POPUP` +
            // `WS_CAPTION` windows. Painting the client rect
            // ourselves and returning 1 keeps the dialog body in
            // our chosen colour.
            WM_ERASEBKGND => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, dialog_bg_brush());
                LRESULT(1)
            }
            WM_CTLCOLORSTATIC => {
                // Most STATICs (title line, home-URL row, license
                // body, etched frame) paint on a transparent
                // background so the dialog fill shows through.
                // Exception: the "MIT License" caption sitting on
                // top of the etched frame's top edge ŌĆö that one
                // needs an opaque `dialog_bg_brush` return so its
                // rect covers the frame line at the caption's
                // position and visually breaks it. Same rect
                // (from the STATIC's own client area) is used as
                // both the text background and the returned
                // brush, keeping the caption's paint fully in
                // its own bounds. Colour the URL STATIC
                // hyperlink-blue (RGB 0,0,238 ŌåÆ COLORREF
                // 0x00EE0000); others keep the system text
                // colour.
                let hdc = HDC(wparam.0 as *mut c_void);
                let target = HWND(lparam.0 as *mut c_void);
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const AboutDialogState;
                if !state_ptr.is_null() && target == (*state_ptr).lic_title_hwnd {
                    let _ = SetBkColor(hdc, COLORREF(DIALOG_BG));
                    return LRESULT(dialog_bg_brush().0 as isize);
                }
                let _ = SetBkMode(hdc, TRANSPARENT);
                if !state_ptr.is_null() && target == (*state_ptr).link_hwnd {
                    let _ = SetTextColor(hdc, COLORREF(0x00EE_0000));
                }
                LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
            }
            WM_CTLCOLORBTN => {
                // No `BS_GROUPBOX` in this dialog anymore (frame
                // is `SS_ETCHEDFRAME` on a STATIC), so the only
                // buttons routing through here are the themed OK
                // push button ŌĆö which paints itself and ignores
                // the brush return. Match the transparent-BkMode
                // + `NULL_BRUSH` pattern the other dialogs use
                // for pushbuttons.
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }));
    match result {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

