/// Architecture suffix shown in the title line ŌĆö `(64-bit)` or
/// `(32-bit)` depending on the target pointer width. Compile-time
/// constant so the formatted string can borrow it without
/// allocating per call.
const ABOUT_ARCH: &str = if cfg!(target_pointer_width = "64") {
    "64-bit"
} else {
    "32-bit"
};

/// Preset colour palette shown in the colour-picker popup ŌĆö
/// 40 swatches in an 8-wide ├Ś 5-tall grid. Same kind of palette
/// Notepad++ uses on its colour buttons. Each tuple is
/// `(R, G, B)`; the grid row-major ordering is:
///
///   Row 0: greyscale ramp (black ŌåÆ white)
///   Rows 1ŌĆō4: hue circle with two saturation / brightness
///     variants per hue
///
/// Hand-picked to give a decent spread without trying to
/// reproduce a colour theory; the "More Colours..." button is
/// the escape hatch for anything not in this set.
const PRESET_COLOURS: &[(u8, u8, u8)] = &[
    // Row 0 ŌĆö greys
    (0x00, 0x00, 0x00),
    (0x33, 0x33, 0x33),
    (0x4D, 0x4D, 0x4D),
    (0x66, 0x66, 0x66),
    (0x80, 0x80, 0x80),
    (0x99, 0x99, 0x99),
    (0xB3, 0xB3, 0xB3),
    (0xFF, 0xFF, 0xFF),
    // Row 1 ŌĆö saturated primaries
    (0x99, 0x00, 0x00),
    (0xCC, 0x00, 0x00),
    (0xCC, 0x66, 0x00),
    (0xFF, 0xCC, 0x00),
    (0x33, 0x99, 0x00),
    (0x00, 0x66, 0x66),
    (0x00, 0x33, 0x99),
    (0x66, 0x00, 0x99),
    // Row 2 ŌĆö bright variants
    (0xFF, 0x00, 0x00),
    (0xFF, 0x66, 0x66),
    (0xFF, 0x99, 0x00),
    (0xFF, 0xFF, 0x00),
    (0x66, 0xCC, 0x00),
    (0x00, 0xCC, 0xCC),
    (0x33, 0x66, 0xFF),
    (0x99, 0x33, 0xFF),
    // Row 3 ŌĆö light tints
    (0xFF, 0x99, 0x99),
    (0xFF, 0xCC, 0xCC),
    (0xFF, 0xCC, 0x99),
    (0xFF, 0xFF, 0x99),
    (0xCC, 0xFF, 0x99),
    (0x99, 0xFF, 0xFF),
    (0x99, 0xCC, 0xFF),
    (0xCC, 0x99, 0xFF),
    // Row 4 ŌĆö neutral / web-safe set
    (0xCC, 0x33, 0x33),
    (0xCC, 0x99, 0x66),
    (0xCC, 0xCC, 0x33),
    (0x99, 0xCC, 0x33),
    (0x33, 0x99, 0x33),
    (0x33, 0xCC, 0x99),
    (0x33, 0x66, 0xCC),
    (0x66, 0x33, 0xCC),
];

/// Layout constants for the colour-picker popup. The swatch
/// grid is `SWATCH_COLS ├Ś SWATCH_ROWS` swatches of
/// `SWATCH_SIZE_PX` each with a `SWATCH_GAP_PX` gap between
/// them, plus a `MORE_BUTTON_H_PX`-tall button at the bottom.
const SWATCH_SIZE_PX: i32 = 22;
const SWATCH_GAP_PX: i32 = 2;
const SWATCH_COLS: i32 = 8;
const SWATCH_ROWS: i32 = 5;
const POPUP_PAD_PX: i32 = 6;
const MORE_BUTTON_H_PX: i32 = 26;
const POPUP_INNER_W_PX: i32 = SWATCH_COLS * SWATCH_SIZE_PX + (SWATCH_COLS - 1) * SWATCH_GAP_PX;
const POPUP_INNER_H_PX: i32 = SWATCH_ROWS * SWATCH_SIZE_PX + (SWATCH_ROWS - 1) * SWATCH_GAP_PX;
const POPUP_CLIENT_W_PX: i32 = POPUP_INNER_W_PX + 2 * POPUP_PAD_PX;
const POPUP_CLIENT_H_PX: i32 = POPUP_INNER_H_PX + 3 * POPUP_PAD_PX + MORE_BUTTON_H_PX;

/// Result of the colour-picker popup ŌĆö `Some(rgb)` if the user
/// clicked a swatch or `ChooseColorW`'d a custom colour; `None`
/// if they dismissed (Esc, click outside, X). Stored on the
/// popup's state and retrieved after the modal pump returns.
#[derive(Clone, Copy)]
enum ColorPickResult {
    /// User picked a colour by clicking a swatch or returning
    /// from `ChooseColorW`.
    Picked((u8, u8, u8)),
    /// User wants to escalate to `ChooseColorW`. The popup
    /// closes itself first; the caller then opens the system
    /// dialog and stores its result.
    MoreColours,
}

/// State passed into the colour-picker popup's `wnd_proc` via
/// CREATESTRUCT.lpCreateParams. Holds the working result ŌĆö
/// initial colour seeding stays on the calling site (the host
/// dialog) and is forwarded to `ChooseColorW` only on the
/// "More Colours..." escalation path.
struct ColorPickerPopupState {
    result: Option<ColorPickResult>,
}

/// Show the colour-picker preset popup just below `(screen_x,
/// screen_y)`, modal to `owner`. Returns `Some(rgb)` if the
/// user picked a colour (either a swatch or via the "More
/// Colours..." escalation to `ChooseColorW`), or `None` on
/// dismissal.
///
/// `initial` is the currently-bound colour for the calling
/// square ŌĆö passed through to `ChooseColorW` so the system
/// dialog opens with that swatch pre-selected; the preset
/// grid itself doesn't highlight it (matches N++'s UX).
fn show_color_picker_popup(
    owner: HWND,
    screen_x: i32,
    screen_y: i32,
    initial: (u8, u8, u8),
) -> Option<(u8, u8, u8)> {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();

    unsafe {
        let instance = GetModuleHandleW(None).ok()?;
        REGISTERED.get_or_init(|| {
            let class = WNDCLASSEXW {
                cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
                style: CS_HREDRAW | CS_VREDRAW,
                lpfnWndProc: Some(color_picker_popup_wnd_proc),
                hInstance: instance.into(),
                hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
                hbrBackground: dialog_bg_brush(),
                lpszClassName: COLOR_PICKER_POPUP_CLASS,
                ..Default::default()
            };
            let _ = RegisterClassExW(&raw const class);
        });

        let mut state = Box::new(ColorPickerPopupState { result: None });
        let state_ptr: *mut ColorPickerPopupState = &raw mut *state;

        let mut window_rect = RECT {
            left: 0,
            top: 0,
            right: POPUP_CLIENT_W_PX,
            bottom: POPUP_CLIENT_H_PX,
        };
        let _ = AdjustWindowRectEx(
            &raw mut window_rect,
            WS_POPUP | WS_BORDER,
            false,
            WS_EX_TOOLWINDOW,
        );
        let popup_w = window_rect.right - window_rect.left;
        let popup_h = window_rect.bottom - window_rect.top;

        let popup = CreateWindowExW(
            WS_EX_TOOLWINDOW,
            COLOR_PICKER_POPUP_CLASS,
            PCWSTR::null(), // no caption shown ŌĆö WS_POPUP has no NC chrome
            WS_POPUP | WS_BORDER,
            screen_x,
            screen_y,
            popup_w,
            popup_h,
            Some(owner),
            None,
            Some(instance.into()),
            Some(state_ptr.cast::<c_void>()),
        )
        .ok()?;
        let _dlg_guard = DlgDestroyGuard(popup);

        // Swatch buttons. Each gets a unique command id in the
        // `IDC_COLOR_POPUP_SWATCH_BASE..` block so WM_COMMAND
        // can route by id without HWND chasing.
        for row in 0..SWATCH_ROWS {
            for col in 0..SWATCH_COLS {
                let idx = (row * SWATCH_COLS + col) as usize;
                let x = POPUP_PAD_PX + col * (SWATCH_SIZE_PX + SWATCH_GAP_PX);
                let y = POPUP_PAD_PX + row * (SWATCH_SIZE_PX + SWATCH_GAP_PX);
                let id = IDC_COLOR_POPUP_SWATCH_BASE + idx as u16;
                let _ = CreateWindowExW(
                    WINDOW_EX_STYLE::default(),
                    w!("BUTTON"),
                    PCWSTR::null(),
                    WS_CHILD | WS_VISIBLE | style_bits(BS_OWNERDRAW),
                    x,
                    y,
                    SWATCH_SIZE_PX,
                    SWATCH_SIZE_PX,
                    Some(popup),
                    Some(HMENU(id as usize as *mut c_void)),
                    Some(instance.into()),
                    None,
                );
            }
        }

        // "More Colours..." button.
        let more_y = POPUP_PAD_PX + POPUP_INNER_H_PX + POPUP_PAD_PX;
        let more = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("More Colours..."),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            POPUP_PAD_PX,
            more_y,
            POPUP_INNER_W_PX,
            MORE_BUTTON_H_PX,
            Some(popup),
            Some(HMENU(IDC_COLOR_POPUP_MORE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);
        apply_dialog_font(more, font);

        let _ = ShowWindow(popup, SW_SHOW);
        let _ = SetFocus(Some(more));

        let mut msg = MSG::default();
        loop {
            if !IsWindow(Some(popup)).as_bool() {
                break;
            }
            let ret = GetMessageW(&raw mut msg, None, 0, 0);
            match ret.0 {
                0 => {
                    let _ = PostMessageW(None, WM_QUIT, msg.wParam, msg.lParam);
                    break;
                }
                -1 => break,
                _ => {
                    // Click outside the popup ŌåÆ dismiss. The
                    // popup doesn't disable its owner (it's not
                    // a true modal ŌĆö same shape as a context
                    // menu), so the user can click back into
                    // the parent dialog without going through
                    // an explicit close.
                    if msg.message == WM_LBUTTONDOWN || msg.message == WM_RBUTTONDOWN {
                        let mut hit_pt = POINT {
                            x: msg.pt.x,
                            y: msg.pt.y,
                        };
                        let mut popup_rect = RECT::default();
                        let _ = GetWindowRect(popup, &raw mut popup_rect);
                        let inside = hit_pt.x >= popup_rect.left
                            && hit_pt.x < popup_rect.right
                            && hit_pt.y >= popup_rect.top
                            && hit_pt.y < popup_rect.bottom;
                        // `hit_pt` shows the GetMessage hot
                        // path uses screen coords already; the
                        // local binding lets us reuse it for a
                        // future "did the click land on a
                        // specific swatch?" follow-up if we
                        // ever need it. Silence the unused-
                        // assignment warning.
                        let _ = &mut hit_pt;
                        if !inside {
                            // Dismiss without picking.
                            let _ = DestroyWindow(popup);
                            break;
                        }
                    }
                    let _ = TranslateMessage(&raw const msg);
                    DispatchMessageW(&raw const msg);
                }
            }
        }

        match state.result.take() {
            Some(ColorPickResult::Picked(rgb)) => Some(rgb),
            Some(ColorPickResult::MoreColours) => pick_color_via_choose_color(owner, initial),
            None => None,
        }
    }
}

/// Window procedure for the colour-picker preset popup.
/// Handles `WM_DRAWITEM` for the swatch buttons (fills them with
/// their `PRESET_COLOURS` entry plus a 1px border) and
/// `WM_COMMAND` for swatch / "More Colours..." clicks.
unsafe extern "system" fn color_picker_popup_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    // Wrap the dispatch in `catch_unwind` so a host-internal
    // panic (allocation failure, indexing slip, tracing
    // misbehaviour, ...) can't unwind across the `extern "system"`
    // wnd_proc frame ŌĆö that's documented UB. On a caught panic
    // we fall back to `DefWindowProcW` so the popup dismisses
    // gracefully rather than corrupting the process. Same
    // pattern every other wnd_proc in this file uses.
    match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        color_picker_popup_wnd_proc_inner(hwnd, msg, wparam, lparam)
    })) {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

unsafe extern "system" fn color_picker_popup_wnd_proc_inner(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    match msg {
        WM_NCCREATE => unsafe {
            let cs = lparam.0 as *const CREATESTRUCTW;
            if !cs.is_null() {
                let state_ptr = (*cs).lpCreateParams as isize;
                SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
            }
            DefWindowProcW(hwnd, msg, wparam, lparam)
        },
        WM_DRAWITEM => unsafe {
            let dis = lparam.0 as *const DRAWITEMSTRUCT;
            if !dis.is_null() {
                let cid = (*dis).CtlID;
                if (u32::from(IDC_COLOR_POPUP_SWATCH_BASE)..).contains(&cid)
                    && cid < (u32::from(IDC_COLOR_POPUP_SWATCH_BASE) + PRESET_COLOURS.len() as u32)
                {
                    let idx = (cid - u32::from(IDC_COLOR_POPUP_SWATCH_BASE)) as usize;
                    let (r, g, b) = PRESET_COLOURS[idx];
                    let rect = (*dis).rcItem;
                    let hdc = (*dis).hDC;
                    let brush = CreateSolidBrush(COLORREF(rgb_to_colorref((r, g, b))));
                    if !brush.is_invalid() {
                        FillRect(hdc, &raw const rect, brush);
                        let _ = DeleteObject(brush.into());
                    }
                    // 1px dark border so light swatches stay
                    // visually distinct from the popup
                    // background.
                    let border = CreatePen(PS_SOLID, 1, COLORREF(0x00_30_30_30));
                    if !border.is_invalid() {
                        let prev = SelectObject(hdc, border.into());
                        let mut last = POINT::default();
                        let _ = MoveToEx(hdc, rect.left, rect.top, Some(&raw mut last));
                        let _ = LineTo(hdc, rect.right - 1, rect.top);
                        let _ = LineTo(hdc, rect.right - 1, rect.bottom - 1);
                        let _ = LineTo(hdc, rect.left, rect.bottom - 1);
                        let _ = LineTo(hdc, rect.left, rect.top);
                        SelectObject(hdc, prev);
                        let _ = DeleteObject(border.into());
                    }
                }
            }
            LRESULT(1)
        },
        WM_COMMAND => unsafe {
            let cid = (wparam.0 & 0xFFFF) as u16;
            let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut ColorPickerPopupState;
            if !state_ptr.is_null() {
                if cid == IDC_COLOR_POPUP_MORE {
                    (*state_ptr).result = Some(ColorPickResult::MoreColours);
                    let _ = DestroyWindow(hwnd);
                } else if (IDC_COLOR_POPUP_SWATCH_BASE..).contains(&cid)
                    && cid < (IDC_COLOR_POPUP_SWATCH_BASE + PRESET_COLOURS.len() as u16)
                {
                    let idx = (cid - IDC_COLOR_POPUP_SWATCH_BASE) as usize;
                    (*state_ptr).result = Some(ColorPickResult::Picked(PRESET_COLOURS[idx]));
                    let _ = DestroyWindow(hwnd);
                }
            }
            LRESULT(0)
        },
        WM_NCDESTROY => unsafe {
            SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
            DefWindowProcW(hwnd, msg, wparam, lparam)
        },
        _ => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

/// Open the Windows `ChooseColorW` common dialog. Returns
/// `Some(rgb)` on OK, `None` on Cancel. `initial` seeds the
/// dialog's initial colour so the user starts from where they
/// were instead of black.
fn pick_color_via_choose_color(owner: HWND, initial: (u8, u8, u8)) -> Option<(u8, u8, u8)> {
    // A 16-entry custom-colour palette is required by Win32 ŌĆö
    // the dialog reads/writes these slots when the user
    // "Adds to Custom Colors". We don't currently persist
    // them, so a fresh white palette every open is the
    // graceful-degradation behaviour.
    let mut custom: [COLORREF; 16] = [COLORREF(0x00_FF_FF_FF); 16];
    let mut cc = CHOOSECOLORW {
        lStructSize: std::mem::size_of::<CHOOSECOLORW>() as u32,
        hwndOwner: owner,
        rgbResult: COLORREF(rgb_to_colorref(initial)),
        lpCustColors: custom.as_mut_ptr(),
        Flags: CC_RGBINIT | CC_FULLOPEN,
        ..Default::default()
    };
    let ok = unsafe { ChooseColorW(&raw mut cc) };
    if !ok.as_bool() {
        return None;
    }
    let cref = cc.rgbResult.0;
    let r = (cref & 0xFF) as u8;
    let g = ((cref >> 8) & 0xFF) as u8;
    let b = ((cref >> 16) & 0xFF) as u8;
    Some((r, g, b))
}

/// Enumerate every distinct font face installed on the system.
/// Returns the names sorted case-insensitively. Skips Windows'
/// "@"-prefixed vertical font duplicates (they're variants of
/// the regular face, not their own face).
fn enumerate_system_fonts() -> Vec<String> {
    use std::collections::BTreeSet;
    let mut fonts: BTreeSet<String> = BTreeSet::new();
    let lf = LOGFONTW {
        lfCharSet: DEFAULT_CHARSET,
        ..Default::default()
    };
    unsafe {
        let dc = GetDC(None);
        if dc.is_invalid() {
            return Vec::new();
        }
        let fonts_ptr: *mut BTreeSet<String> = &raw mut fonts;
        EnumFontFamiliesExW(
            dc,
            &raw const lf,
            Some(font_enum_proc),
            LPARAM(fonts_ptr as isize),
            0,
        );
        ReleaseDC(None, dc);
    }
    fonts.into_iter().collect()
}

/// `EnumFontFamiliesEx` callback ŌĆö extracts the face name from
/// `LOGFONTW.lfFaceName`, skips "@"-prefixed vertical
/// duplicates, and inserts unique names into the
/// caller-supplied `BTreeSet<String>` (so the result is sorted
/// and deduplicated on the way out).
///
/// Wrapped in `catch_unwind` for FFI panic safety ŌĆö the body
/// allocates (`String::from_utf16_lossy`, `BTreeSet::insert`),
/// so an OOM or any other panic must not unwind across the
/// `extern "system"` boundary into GDI's enumeration loop. On
/// a caught panic we return `1` so GDI keeps enumerating; the
/// font that triggered the panic is dropped, the rest of the
/// list still populates.
unsafe extern "system" fn font_enum_proc(
    logfont: *const LOGFONTW,
    _tm: *const TEXTMETRICW,
    _font_type: u32,
    lparam: LPARAM,
) -> i32 {
    std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        if logfont.is_null() || lparam.0 == 0 {
            return 1;
        }
        unsafe {
            let fonts = &mut *(lparam.0 as *mut std::collections::BTreeSet<String>);
            let face = &(*logfont).lfFaceName;
            let len = face.iter().position(|&c| c == 0).unwrap_or(face.len());
            let name = String::from_utf16_lossy(&face[..len]);
            if !name.is_empty() && !name.starts_with('@') {
                fonts.insert(name);
            }
        }
        1
    }))
    .unwrap_or(1)
}

/// Working state for the Style Configurator dialog. Stored
/// inside the dialog's `Box` and reached via `GWLP_USERDATA` from
/// the `wnd_proc`. Carries every control HWND the dispatch
/// touches and the working-copy `Styles` value the user is
/// editing; `result` is set on Save & Close so the modal-pump
/// caller can return it to the host.
struct StyleConfigDialogState {
    owner_hwnd: HWND,
    /// Set to `Some(new)` on Save & Close, left `None` on
    /// Cancel / X / Esc. The driver returns this after the
    /// modal pump.
    result: Option<codepp_core::styles::Styles>,
    /// Live working copy edited by every control mutation. On
    /// Save & Close this becomes `result`.
    working: codepp_core::styles::StyleEntry,
    working_transparency: codepp_core::styles::Transparency,
    /// Control HWNDs. Owned by the dialog window; child
    /// windows are destroyed automatically when the parent
    /// dies, so no explicit cleanup is required.
    fg_button: HWND,
    bg_button: HWND,
    font_combo: HWND,
    size_combo: HWND,
    bold_check: HWND,
    italic_check: HWND,
    underline_check: HWND,
    transparency_check: HWND,
    transparency_slider: HWND,
}

/// Trackbar messages ŌĆö `msctls_trackbar32` doesn't have a
/// dedicated windows-rs newtype the way listview / treeview
/// do, so we use the documented `WM_USER + n` literals.
const WM_USER_TBM: u32 = 0x0400;
const TBM_GETPOS: u32 = WM_USER_TBM;
const TBM_SETPOS: u32 = WM_USER_TBM + 5;
const TBM_SETRANGE: u32 = WM_USER_TBM + 6;
/// `TBS_AUTOTICKS` (1). `TBS_HORZ` is 0 so we just write the
/// auto-ticks bit directly.
const TBS_HORZ_AUTOTICKS: u32 = 0x0001;

/// Menu-click entry point. Snapshots the current styles, opens
/// the modal dialog, and on a non-None return persists via
/// `Shell::set_styles` and re-applies the live editor through
/// `Win32Ui::apply_default_style`. Run on the UI thread.
///
/// # Safety
///
/// `main_hwnd` must be the host's main window on the calling
/// thread; same contract as the rest of the `wnd_proc` dispatch.
unsafe fn handle_style_config_menu(main_hwnd: HWND) {
    // Snapshot under a brief borrow, then drop it before the
    // modal pump runs (the message loop re-enters the wnd_proc).
    let current = match unsafe { state_from_hwnd(main_hwnd) } {
        Some(s) => s.shell.styles.clone(),
        None => return,
    };
    let Some(new_styles) = show_style_config_dialog(main_hwnd, current) else {
        return;
    };
    if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        let (shell, mut ui) = state.split();
        shell.set_styles(new_styles);
        ui.apply_default_style(&shell.styles);
        // `apply_default_style`'s `style_clear_all` propagates
        // the new STYLE_DEFAULT (font, size, fg, bg) to every
        // style index ŌĆö which also wipes the per-style fg
        // colours the active lexer installs (comment-green,
        // keyword-blue, etc.). Without a follow-up `apply_lang`,
        // the user sees a uniformly-coloured buffer until they
        // switch tabs (which re-fires `apply_lang` via the
        // tab-switch dispatch). Re-applying lang here layers
        // the lexer's per-style theme back on top of the new
        // default colour scheme ŌĆö keyword classes survive
        // `style_clear_all` so this only repaints colours, no
        // re-lex work.
        let active_lang = shell.active().map_or(codepp_core::lang::L_TEXT, |t| t.lang);
        ui.apply_lang(active_lang);
    }
}

/// Open the Style Configurator dialog modally over `owner`.
/// Returns `Some(styles)` if the user clicked Save & Close,
/// `None` on Cancel / X / Esc.
fn show_style_config_dialog(
    owner: HWND,
    initial: codepp_core::styles::Styles,
) -> Option<codepp_core::styles::Styles> {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();

    unsafe {
        let instance = GetModuleHandleW(None).ok()?;
        REGISTERED.get_or_init(|| {
            let class = WNDCLASSEXW {
                cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
                style: CS_HREDRAW | CS_VREDRAW,
                lpfnWndProc: Some(style_config_wnd_proc),
                hInstance: instance.into(),
                hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
                hbrBackground: dialog_bg_brush(),
                lpszClassName: STYLE_CONFIG_CLASS,
                ..Default::default()
            };
            let _ = RegisterClassExW(&raw const class);
        });

        let initial_default = initial.effective_default();
        let initial_transparency = initial.effective_transparency();
        let mut state = Box::new(StyleConfigDialogState {
            owner_hwnd: owner,
            result: None,
            working: initial_default.clone(),
            working_transparency: initial_transparency.clone(),
            fg_button: HWND::default(),
            bg_button: HWND::default(),
            font_combo: HWND::default(),
            size_combo: HWND::default(),
            bold_check: HWND::default(),
            italic_check: HWND::default(),
            underline_check: HWND::default(),
            transparency_check: HWND::default(),
            transparency_slider: HWND::default(),
        });
        let state_ptr: *mut StyleConfigDialogState = &raw mut *state;

        // Layout. CLIENT-space; we AdjustWindowRectEx once to
        // get the outer window size for `CreateWindowExW`.
        const CLIENT_W: i32 = 680;
        const CLIENT_H: i32 = 380;

        let mut window_rect = RECT {
            left: 0,
            top: 0,
            right: CLIENT_W,
            bottom: CLIENT_H,
        };
        let _ = AdjustWindowRectEx(
            &raw mut window_rect,
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            false,
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
        );
        let dlg_w = window_rect.right - window_rect.left;
        let dlg_h = window_rect.bottom - window_rect.top;
        let mut owner_rect = RECT::default();
        let _ = GetWindowRect(owner, &raw mut owner_rect);
        let owner_w = owner_rect.right - owner_rect.left;
        let owner_h = owner_rect.bottom - owner_rect.top;
        let dlg_x = owner_rect.left + (owner_w - dlg_w) / 2;
        let dlg_y = owner_rect.top + (owner_h - dlg_h) / 2;

        let dlg = CreateWindowExW(
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
            STYLE_CONFIG_CLASS,
            w!("Style Configurator"),
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            dlg_x,
            dlg_y,
            dlg_w,
            dlg_h,
            Some(owner),
            None,
            Some(instance.into()),
            Some(state_ptr.cast::<c_void>()),
        )
        .ok()?;
        let _dlg_guard = DlgDestroyGuard(dlg);

        let font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);

        // === Top row: Select theme ===
        let theme_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Select theme:"),
            WS_CHILD | WS_VISIBLE,
            20,
            16,
            85,
            18,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let theme_combo = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("COMBOBOX"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WINDOW_STYLE(0x3), // CBS_DROPDOWNLIST
            110,
            14,
            240,
            22,
            Some(dlg),
            Some(HMENU(IDC_STYLE_THEME_COMBO as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let theme_default = HSTRING::from("Default (stylers.xml)");
        SendMessageW(
            theme_combo,
            CB_ADDSTRING,
            Some(WPARAM(0)),
            Some(LPARAM(theme_default.as_ptr() as isize)),
        );
        SendMessageW(
            theme_combo,
            CB_SETCURSEL_MSG,
            Some(WPARAM(0)),
            Some(LPARAM(0)),
        );
        let _ = EnableWindow(theme_combo, false); // greyed ŌĆö out of scope

        // === Left column: Language + Style listbox ===
        let lang_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Language:"),
            WS_CHILD | WS_VISIBLE,
            20,
            54,
            85,
            18,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let lang_combo = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("COMBOBOX"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WINDOW_STYLE(0x3), // CBS_DROPDOWNLIST
            20,
            74,
            200,
            22,
            Some(dlg),
            Some(HMENU(IDC_STYLE_LANG_COMBO as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let global_styles_label = HSTRING::from("Global Styles");
        SendMessageW(
            lang_combo,
            CB_ADDSTRING,
            Some(WPARAM(0)),
            Some(LPARAM(global_styles_label.as_ptr() as isize)),
        );
        SendMessageW(
            lang_combo,
            CB_SETCURSEL_MSG,
            Some(WPARAM(0)),
            Some(LPARAM(0)),
        );
        let _ = EnableWindow(lang_combo, false); // greyed

        let style_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Style:"),
            WS_CHILD | WS_VISIBLE,
            20,
            108,
            85,
            18,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let style_list = CreateWindowExW(
            WS_EX_CLIENTEDGE,
            w!("LISTBOX"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_VSCROLL | WINDOW_STYLE(0x1), // LBS_NOTIFY
            20,
            128,
            200,
            186,
            Some(dlg),
            Some(HMENU(IDC_STYLE_STYLE_LIST as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let default_style_label = HSTRING::from("Default Style");
        SendMessageW(
            style_list,
            LB_ADDSTRING_MSG,
            Some(WPARAM(0)),
            Some(LPARAM(default_style_label.as_ptr() as isize)),
        );
        SendMessageW(
            style_list,
            LB_SETCURSEL_MSG,
            Some(WPARAM(0)),
            Some(LPARAM(0)),
        );

        // === Colour Style group ===
        let colour_group = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Colour Style"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_GROUPBOX),
            240,
            50,
            200,
            130,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fg_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Foreground colour"),
            WS_CHILD | WS_VISIBLE,
            260,
            80,
            140,
            18,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fg_button = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_OWNERDRAW),
            400,
            78,
            30,
            22,
            Some(dlg),
            Some(HMENU(IDC_STYLE_FG_BUTTON as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let bg_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Background colour"),
            WS_CHILD | WS_VISIBLE,
            260,
            124,
            140,
            18,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let bg_button = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_OWNERDRAW),
            400,
            122,
            30,
            22,
            Some(dlg),
            Some(HMENU(IDC_STYLE_BG_BUTTON as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // === Font Style group ===
        let font_group = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Font Style"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_GROUPBOX),
            460,
            50,
            200,
            200,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let font_name_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Font name:"),
            WS_CHILD | WS_VISIBLE,
            478,
            74,
            80,
            18,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let font_combo = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("COMBOBOX"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | WS_VSCROLL | WINDOW_STYLE(0x3), // CBS_DROPDOWNLIST
            478,
            94,
            165,
            200,
            Some(dlg),
            Some(HMENU(IDC_STYLE_FONT_COMBO as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Populate the font dropdown. Enumerate once at dialog
        // open ŌĆö sorted alphabetically. If the configured font
        // isn't in the list (uninstalled since last save), it's
        // appended so the dropdown can still display the user's
        // current choice rather than silently falling back.
        let mut font_names = enumerate_system_fonts();
        if !initial_default.font_name.is_empty()
            && !font_names
                .iter()
                .any(|n| n.eq_ignore_ascii_case(&initial_default.font_name))
        {
            font_names.push(initial_default.font_name.clone());
        }
        let mut configured_idx = None;
        for (idx, name) in font_names.iter().enumerate() {
            let hname = HSTRING::from(name);
            SendMessageW(
                font_combo,
                CB_ADDSTRING,
                Some(WPARAM(0)),
                Some(LPARAM(hname.as_ptr() as isize)),
            );
            if name.eq_ignore_ascii_case(&initial_default.font_name) {
                configured_idx = Some(idx);
            }
        }
        if let Some(idx) = configured_idx {
            SendMessageW(
                font_combo,
                CB_SETCURSEL_MSG,
                Some(WPARAM(idx)),
                Some(LPARAM(0)),
            );
        }

        let font_size_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Font size:"),
            WS_CHILD | WS_VISIBLE,
            478,
            122,
            80,
            18,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let size_combo = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("COMBOBOX"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | WS_VSCROLL | WINDOW_STYLE(0x3), // CBS_DROPDOWNLIST
            478,
            142,
            80,
            200,
            Some(dlg),
            Some(HMENU(IDC_STYLE_SIZE_COMBO as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Sizes 6..=72, configured-or-12 selected.
        let mut configured_size_idx = None;
        for (idx, sz) in (6u16..=72).enumerate() {
            let hsz = HSTRING::from(sz.to_string());
            SendMessageW(
                size_combo,
                CB_ADDSTRING,
                Some(WPARAM(0)),
                Some(LPARAM(hsz.as_ptr() as isize)),
            );
            if sz == initial_default.font_size {
                configured_size_idx = Some(idx);
            }
        }
        if let Some(idx) = configured_size_idx {
            SendMessageW(
                size_combo,
                CB_SETCURSEL_MSG,
                Some(WPARAM(idx)),
                Some(LPARAM(0)),
            );
        }

        let bold_check = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Bold"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            478,
            174,
            120,
            20,
            Some(dlg),
            Some(HMENU(IDC_STYLE_BOLD as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let italic_check = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Italic"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            478,
            196,
            120,
            20,
            Some(dlg),
            Some(HMENU(IDC_STYLE_ITALIC as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let underline_check = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Underline"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            478,
            218,
            120,
            20,
            Some(dlg),
            Some(HMENU(IDC_STYLE_UNDERLINE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        SendMessageW(
            bold_check,
            BM_SETCHECK,
            Some(WPARAM(usize::from(initial_default.bold))),
            Some(LPARAM(0)),
        );
        SendMessageW(
            italic_check,
            BM_SETCHECK,
            Some(WPARAM(usize::from(initial_default.italic))),
            Some(LPARAM(0)),
        );
        SendMessageW(
            underline_check,
            BM_SETCHECK,
            Some(WPARAM(usize::from(initial_default.underline))),
            Some(LPARAM(0)),
        );

        // === Transparency ===
        let transparency_check = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Transparency"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            400,
            325,
            110,
            22,
            Some(dlg),
            Some(HMENU(IDC_STYLE_TRANSPARENCY_CHECK as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        SendMessageW(
            transparency_check,
            BM_SETCHECK,
            Some(WPARAM(usize::from(initial_transparency.enabled))),
            Some(LPARAM(0)),
        );
        let transparency_slider = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("msctls_trackbar32"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | WINDOW_STYLE(TBS_HORZ_AUTOTICKS),
            520,
            323,
            140,
            26,
            Some(dlg),
            Some(HMENU(IDC_STYLE_TRANSPARENCY_SLIDER as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Range 20..=100 matches the model's invariant.
        SendMessageW(
            transparency_slider,
            TBM_SETRANGE,
            Some(WPARAM(1)),
            Some(LPARAM(
                (i64::from(20u32) | (i64::from(100u32) << 16)) as isize,
            )),
        );
        SendMessageW(
            transparency_slider,
            TBM_SETPOS,
            Some(WPARAM(1)),
            Some(LPARAM(initial_transparency.percent as isize)),
        );
        let _ = EnableWindow(transparency_slider, initial_transparency.enabled);

        // === Save & Close / Cancel ===
        let save_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Save && Close"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            20,
            330,
            120,
            28,
            Some(dlg),
            Some(HMENU(IDC_STYLE_SAVE_CLOSE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let cancel_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Cancel"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            150,
            330,
            100,
            28,
            Some(dlg),
            Some(HMENU(IDC_STYLE_CANCEL as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // Apply the dialog font to every child so they pick up
        // the standard system look instead of the OEM bitmap
        // default that Win32 hands new controls.
        for child in [
            theme_label,
            theme_combo,
            lang_label,
            lang_combo,
            style_label,
            style_list,
            colour_group,
            fg_label,
            fg_button,
            bg_label,
            bg_button,
            font_group,
            font_name_label,
            font_combo,
            font_size_label,
            size_combo,
            bold_check,
            italic_check,
            underline_check,
            transparency_check,
            transparency_slider,
            save_btn,
            cancel_btn,
        ] {
            apply_dialog_font(child, font);
        }

        // Stash control HWNDs onto the state so the wnd_proc
        // can read/update them.
        state.fg_button = fg_button;
        state.bg_button = bg_button;
        state.font_combo = font_combo;
        state.size_combo = size_combo;
        state.bold_check = bold_check;
        state.italic_check = italic_check;
        state.underline_check = underline_check;
        state.transparency_check = transparency_check;
        state.transparency_slider = transparency_slider;

        // Disable the owner so the dialog is genuinely modal,
        // then guard the re-enable so a Win32 destruction path
        // never leaves the parent inert.
        let _ = EnableWindow(owner, false);
        let _owner_guard = OwnerEnableGuard(owner);
        let _ = ShowWindow(dlg, SW_SHOW);
        let _ = SetFocus(Some(save_btn));

        let mut msg = MSG::default();
        loop {
            if !IsWindow(Some(dlg)).as_bool() {
                break;
            }
            let ret = GetMessageW(&raw mut msg, None, 0, 0);
            match ret.0 {
                0 => {
                    let _ = PostMessageW(None, WM_QUIT, msg.wParam, msg.lParam);
                    break;
                }
                -1 => break,
                _ => {
                    if !IsDialogMessageW(dlg, &raw const msg).as_bool() {
                        let _ = TranslateMessage(&raw const msg);
                        DispatchMessageW(&raw const msg);
                    }
                }
            }
        }

        state.result.take()
    }
}

/// Listbox messages. The Win32 names are `LB_ADDSTRING` /
/// `LB_SETCURSEL`; values come from the Win32 SDK (not `WM_USER`-
/// based ŌĆö the LB_* range lives in the standard WM_ message
/// allocation around 0x0180). windows-rs doesn't re-export
/// them, so we keep them as local constants.
const LB_ADDSTRING_MSG: u32 = 0x0180;
const LB_SETCURSEL_MSG: u32 = 0x0186;

/// `CB_SETCURSEL` ŌĆö combobox "set current selection" message.
/// Lives in the standard WM_ message range (0x014E); windows-rs
/// doesn't re-export it. Used by the Style Configurator dialog
/// to seed dropdowns with the persisted value on open.
const CB_SETCURSEL_MSG: u32 = 0x014E;

/// Read a combobox's selected text into a Rust `String`.
/// Returns `None` if no selection. Generic for both font and
/// size combos ŌĆö the caller decides how to interpret the text.
unsafe fn combobox_selected_text(combo: HWND) -> Option<String> {
    // Combo-message constants kept local since `windows-rs`
    // doesn't re-export them and they're only used inside this
    // helper. Values verified against the Win32 SDK.
    const CB_GETCURSEL: u32 = 0x0147;
    const CB_GETLBTEXT: u32 = 0x0148;
    const CB_GETLBTEXTLEN: u32 = 0x0149;
    unsafe {
        let sel = SendMessageW(combo, CB_GETCURSEL, Some(WPARAM(0)), Some(LPARAM(0))).0;
        if sel < 0 {
            return None;
        }
        // `CB_GETLBTEXTLEN` returns `CB_ERR` (= -1, signed) on
        // failure. Casting `-1isize` straight to `usize` via
        // `as` would produce `usize::MAX` and trip a multi-
        // exabyte allocation in the `vec![0; len + 1]` below.
        // Range-check first so the error path returns `None`
        // (graceful skip) rather than aborting the process.
        let len_raw = SendMessageW(
            combo,
            CB_GETLBTEXTLEN,
            Some(WPARAM(sel as usize)),
            Some(LPARAM(0)),
        )
        .0;
        if len_raw < 0 {
            return None;
        }
        let len = len_raw as usize;
        if len == 0 {
            return Some(String::new());
        }
        let mut buf: Vec<u16> = vec![0; len + 1];
        SendMessageW(
            combo,
            CB_GETLBTEXT,
            Some(WPARAM(sel as usize)),
            Some(LPARAM(buf.as_mut_ptr() as isize)),
        );
        let written = buf.iter().position(|&c| c == 0).unwrap_or(buf.len());
        Some(String::from_utf16_lossy(&buf[..written]))
    }
}

/// Paint a colour-square button. The `cid` decides whether the
/// fg or bg colour is rendered; the working state carries the
/// RGB values to fill with.
unsafe fn paint_color_square(state: &StyleConfigDialogState, dis: *const DRAWITEMSTRUCT) {
    unsafe {
        let dis_ref = &*dis;
        let cid = dis_ref.CtlID as u16;
        let rgb_hex = if cid == IDC_STYLE_FG_BUTTON {
            &state.working.fg
        } else if cid == IDC_STYLE_BG_BUTTON {
            &state.working.bg
        } else {
            return;
        };
        let rgb = codepp_core::styles::parse_rgb_hex(rgb_hex).unwrap_or((0, 0, 0));
        let cref = COLORREF(rgb_to_colorref(rgb));
        let brush = CreateSolidBrush(cref);
        if !brush.is_invalid() {
            FillRect(dis_ref.hDC, &raw const dis_ref.rcItem, brush);
            let _ = DeleteObject(brush.into());
        }
        // 1px border for legibility (a white BG on a white
        // dialog disappears without it).
        let pen = CreatePen(PS_SOLID, 1, COLORREF(0x00_30_30_30));
        if !pen.is_invalid() {
            let prev = SelectObject(dis_ref.hDC, pen.into());
            let r = dis_ref.rcItem;
            let mut last = POINT::default();
            let _ = MoveToEx(dis_ref.hDC, r.left, r.top, Some(&raw mut last));
            let _ = LineTo(dis_ref.hDC, r.right - 1, r.top);
            let _ = LineTo(dis_ref.hDC, r.right - 1, r.bottom - 1);
            let _ = LineTo(dis_ref.hDC, r.left, r.bottom - 1);
            let _ = LineTo(dis_ref.hDC, r.left, r.top);
            SelectObject(dis_ref.hDC, prev);
            let _ = DeleteObject(pen.into());
        }
    }
}

/// Window procedure for the Style Configurator dialog. Handles
/// the typical create / draw / command / destroy lifecycle plus
/// `WM_HSCROLL` for the transparency slider.
unsafe extern "system" fn style_config_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    // FFI panic safety: same `catch_unwind` wrap every other
    // wnd_proc in this file uses. A panic inside the inner
    // dispatch would otherwise unwind across the
    // `extern "system"` boundary (documented UB).
    match std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        style_config_wnd_proc_inner(hwnd, msg, wparam, lparam)
    })) {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

unsafe extern "system" fn style_config_wnd_proc_inner(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    match msg {
        WM_NCCREATE => unsafe {
            let cs = lparam.0 as *const CREATESTRUCTW;
            if !cs.is_null() {
                let state_ptr = (*cs).lpCreateParams as isize;
                SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
            }
            DefWindowProcW(hwnd, msg, wparam, lparam)
        },
        WM_DRAWITEM => unsafe {
            let dis = lparam.0 as *const DRAWITEMSTRUCT;
            let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const StyleConfigDialogState;
            if !dis.is_null() && !state_ptr.is_null() {
                paint_color_square(&*state_ptr, dis);
            }
            LRESULT(1)
        },
        WM_HSCROLL => unsafe {
            let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut StyleConfigDialogState;
            if !state_ptr.is_null() {
                let slider = (*state_ptr).transparency_slider;
                if lparam.0 as *mut c_void == slider.0 {
                    let pos = SendMessageW(slider, TBM_GETPOS, None, None).0;
                    let clamped = (pos as i32).clamp(20, 100) as u8;
                    (*state_ptr).working_transparency.percent = clamped;
                }
            }
            LRESULT(0)
        },
        WM_COMMAND => unsafe {
            let cid = (wparam.0 & 0xFFFF) as u16;
            let notif = ((wparam.0 >> 16) & 0xFFFF) as u16;
            let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut StyleConfigDialogState;
            if state_ptr.is_null() {
                return LRESULT(0);
            }
            let state = &mut *state_ptr;
            match cid {
                IDC_STYLE_FG_BUTTON | IDC_STYLE_BG_BUTTON if notif == BN_CLICKED as u16 => {
                    // Resolve current colour for ChooseColor seeding.
                    let initial = if cid == IDC_STYLE_FG_BUTTON {
                        codepp_core::styles::parse_rgb_hex(&state.working.fg).unwrap_or((0, 0, 0))
                    } else {
                        codepp_core::styles::parse_rgb_hex(&state.working.bg)
                            .unwrap_or((0xFF, 0xFF, 0xFF))
                    };
                    // Position the popup just below the button.
                    let button_hwnd = if cid == IDC_STYLE_FG_BUTTON {
                        state.fg_button
                    } else {
                        state.bg_button
                    };
                    let mut rect = RECT::default();
                    let _ = GetWindowRect(button_hwnd, &raw mut rect);
                    let picked = show_color_picker_popup(hwnd, rect.left, rect.bottom, initial);
                    if let Some(rgb) = picked {
                        let hex = codepp_core::styles::format_rgb_hex(rgb.0, rgb.1, rgb.2);
                        if cid == IDC_STYLE_FG_BUTTON {
                            state.working.fg = hex;
                        } else {
                            state.working.bg = hex;
                        }
                        // Trigger a repaint of the now-changed
                        // square so the user sees the new colour
                        // immediately.
                        let _ = InvalidateRect(Some(button_hwnd), None, false);
                    }
                }
                IDC_STYLE_BOLD if notif == BN_CLICKED as u16 => {
                    state.working.bold = button_checked(state.bold_check);
                }
                IDC_STYLE_ITALIC if notif == BN_CLICKED as u16 => {
                    state.working.italic = button_checked(state.italic_check);
                }
                IDC_STYLE_UNDERLINE if notif == BN_CLICKED as u16 => {
                    state.working.underline = button_checked(state.underline_check);
                }
                IDC_STYLE_TRANSPARENCY_CHECK if notif == BN_CLICKED as u16 => {
                    let checked = button_checked(state.transparency_check);
                    state.working_transparency.enabled = checked;
                    let _ = EnableWindow(state.transparency_slider, checked);
                }
                // CBN_SELCHANGE = 1.
                IDC_STYLE_FONT_COMBO if notif == 1 => {
                    if let Some(name) = combobox_selected_text(state.font_combo) {
                        state.working.font_name = name;
                    }
                }
                IDC_STYLE_SIZE_COMBO if notif == 1 => {
                    if let Some(Ok(n)) =
                        combobox_selected_text(state.size_combo).map(|s| s.parse::<u16>())
                    {
                        state.working.font_size = n;
                    }
                }
                // The explicit `EnableWindow(owner, true)` calls in
                // these handlers are intentional alongside the
                // outer `OwnerEnableGuard`. The guard fires when
                // the function returns (after the modal pump
                // exits) ŌĆö but Win32 dispatches the next
                // foreground-window decision the moment
                // `DestroyWindow` runs, which is *before* the
                // outer function unwinds. Without the explicit
                // pre-destroy enable, the next window in z-order
                // briefly receives focus before the guard's
                // re-enable fixes it on return. The double
                // `EnableWindow(true)` is idempotent (Win32
                // documents it as a no-op when the state is
                // already enabled) so the redundancy is cheap.
                IDC_STYLE_SAVE_CLOSE => {
                    state.result = Some(codepp_core::styles::Styles {
                        default: Some(state.working.clone()),
                        transparency: Some(state.working_transparency.clone()),
                    });
                    let _ = EnableWindow(state.owner_hwnd, true);
                    let _ = DestroyWindow(hwnd);
                }
                // OR-in `IDCANCEL_U16` so the Esc key closes the
                // dialog too ŌĆö `IsDialogMessageW` in the modal
                // pump above translates Esc into a
                // `WM_COMMAND(IDCANCEL)`, and without this arm the
                // synthesised id (2) doesn't match our custom
                // Cancel-button id (811) and the keystroke gets
                // dropped by the `_ => {}` fall-through. Same
                // pattern the Find/Replace dialog uses
                // (`IDC_FR_CLOSE | IDCANCEL_U16`).
                IDC_STYLE_CANCEL | IDCANCEL_U16 => {
                    state.result = None;
                    let _ = EnableWindow(state.owner_hwnd, true);
                    let _ = DestroyWindow(hwnd);
                }
                _ => {}
            }
            LRESULT(0)
        },
        WM_CLOSE => unsafe {
            let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut StyleConfigDialogState;
            if !state_ptr.is_null() {
                let _ = EnableWindow((*state_ptr).owner_hwnd, true);
            }
            let _ = DestroyWindow(hwnd);
            LRESULT(0)
        },
        WM_NCDESTROY => unsafe {
            SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
            DefWindowProcW(hwnd, msg, wparam, lparam)
        },
        _ => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

/// Handle Language ŌåÆ User-Defined language ŌåÆ "Open User Defined
/// Language folderŌĆ”" ŌĆö creates `<config_dir>/userDefineLangs/`
/// if it doesn't yet exist, then shells out to `ShellExecuteW`
/// which launches the OS default file-explorer (Windows Explorer
/// on Windows) at that path.
///
/// The `create_dir_all` step means this action always succeeds on
/// a fresh install (before m1b's startup scanner has minted the
/// directory itself) ŌĆö a user clicking the menu item expects an
/// open folder, not an error dialog telling them the directory
/// doesn't exist.
///
/// `hwnd` is the owner for `ShellExecuteW`'s error-dialog surface
/// ŌĆö passing the main window keeps any UAC / association-picker
/// prompt visually anchored to Code++.
///
/// **Security note.** The path fed to `ShellExecuteW` is derived
/// from `platform::user_define_langs_dir()`, which joins a fixed
/// `"userDefineLangs"` component to the `APPDATA`-derived
/// `config_dir()`. No user-controlled string participates. The
/// `"open"` verb + directory-path shape is what Windows Explorer
/// uses internally ŌĆö this is not "execute an arbitrary user-named
/// program" surface.
fn open_udl_folder(hwnd: HWND) {
    let Some(dir) = codepp_platform::user_define_langs_dir() else {
        tracing::warn!(
            "no config_dir resolved; skipping open_udl_folder \
             (APPDATA / HOME unset?)"
        );
        return;
    };
    if let Err(e) = std::fs::create_dir_all(&dir) {
        tracing::warn!(
            path = ?dir,
            error = %e,
            "failed to create userDefineLangs directory; \
             ShellExecuteW may still succeed if it exists"
        );
    }
    // Encode the path directly via `OsStr::encode_wide` for
    // lossless UTF-16 round-trip. Going through `to_string_lossy`
    // instead would substitute U+FFFD on any ill-formed surrogate
    // sequence in the OS path ŌĆö safe in practice for our fixed
    // `%APPDATA%\Code++\userDefineLangs` shape but not necessary,
    // and inconsistent with `read_pe_file_version`'s established
    // pattern. Matches the codebase's existing convention for
    // shipping a `Path` into a wide-string API.
    use std::os::windows::ffi::OsStrExt;
    let path_wide: Vec<u16> = dir
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();
    let ret = unsafe {
        ShellExecuteW(
            Some(hwnd),
            w!("open"),
            PCWSTR(path_wide.as_ptr()),
            PCWSTR::null(),
            PCWSTR::null(),
            SW_SHOWNORMAL,
        )
    };
    // `ShellExecuteW` returns a `HINSTANCE`; a value <= 32 is a
    // documented error code (missing association, no `explorer.exe`,
    // etc.). Log the failure so a broken environment is
    // distinguishable from user inattention in `--verbose` diags.
    if (ret.0 as isize) <= 32 {
        tracing::warn!(
            path = ?dir,
            code = ret.0 as isize,
            "ShellExecuteW(open, <udl folder>) failed"
        );
    }
}

/// Open `url` in the user's default browser via
/// `ShellExecuteW("open", ...)`. Shared by every menu handler
/// whose job is "point the OS at this URL" ŌĆö the UDL collection
/// entry and every Help menu external link.
///
/// **Security:** callers pass a compile-time-constant `&'static
/// str`, so the URL is never derived from user input. The
/// documented "open" verb resolves against the registered
/// http/https association and does NOT reach arbitrary command
/// execution, but the constness discipline is what makes that
/// argument bulletproof ŌĆö a mistake at a call site (say, passing
/// a path derived from a text buffer) would be visible in the
/// diff.
///
/// Failure is logged at warn level rather than surfaced to the
/// user ŌĆö a broken browser association is rare, and the
/// alternative (a modal error dialog on every failed click) reads
/// as worse than "the menu did nothing." `HINSTANCE` <= 32 is
/// `ShellExecuteW`'s documented failure signal.
fn open_url_in_browser(hwnd: HWND, url: &'static str) {
    let url_wide = wide_terminated(url);
    // SAFETY: `url_wide` is a stack-owned Vec<u16> that lives
    // across the synchronous `ShellExecuteW` call; `hwnd` is a
    // live top-level window we own on this thread. No pointer
    // is retained past this call.
    let ret = unsafe {
        ShellExecuteW(
            Some(hwnd),
            w!("open"),
            PCWSTR(url_wide.as_ptr()),
            PCWSTR::null(),
            PCWSTR::null(),
            SW_SHOWNORMAL,
        )
    };
    if (ret.0 as isize) <= 32 {
        tracing::warn!(
            url,
            code = ret.0 as isize,
            "ShellExecuteW(open, url) failed"
        );
    }
}

/// Extract the file extension from `path` with the leading dot
/// prefix required by [`AssocQueryStringW`]. Returns `None` for
/// paths with no extension (`README`, `Makefile`) or for
/// extensions that aren't valid UTF-8 (rare in practice on
/// Windows filesystems, but possible via arbitrary byte
/// sequences a plugin could construct).
///
/// Pure ŌĆö no OS interaction. Broken out so the tests can pin
/// the extraction rules without needing a live registry to
/// query.
fn extract_extension_with_dot(path: &Path) -> Option<String> {
    let ext = path.extension()?.to_str()?;
    if ext.is_empty() {
        return None;
    }
    Some(format!(".{ext}"))
}

/// Returns `true` if the current Windows shell has any registered
/// handler for the file extension `ext_with_dot` (e.g. `".txt"`).
///
/// The check is a null-buffer size-probe of [`AssocQueryStringW`]
/// with [`ASSOCSTR_EXECUTABLE`]. Two subtleties worth pinning:
///
/// 1. **`ASSOCF_INIT_IGNOREUNKNOWN` is load-bearing.** Without it,
///    Windows silently falls back to the "Unknown" application
///    for unregistered extensions and returns success anyway. That
///    would light the menu entry for every extension, defeating
///    the greying contract. The `IGNOREUNKNOWN` flag makes
///    unregistered extensions fail with `ERROR_NO_ASSOCIATION`
///    (`0x8007_0483` when wrapped as HRESULT).
///
/// 2. **`S_FALSE` (not `E_POINTER`) is the "size query succeeded"
///    signal.** The Microsoft docs describe the null-buffer
///    contract as "returns the required size" without pinning a
///    specific HRESULT; empirically the `windows` crate surfaces
///    `S_FALSE` (`0x0000_0001`) on Win10/Win11. `hr.is_ok()`
///    covers both `S_OK` and `S_FALSE`, matching either the
///    real-buffer or null-buffer success path.
///
/// Used exclusively by [`refresh_file_menu`] to decide whether
/// `ID_FILE_OPEN_IN_DEFAULT_VIEWER` should be enabled: no
/// association ŌćÆ greyed, matching what a user would see if they
/// clicked and Explorer popped the "How do you want to open this
/// file?" picker instead of opening the file.
fn extension_has_registered_handler(ext_with_dot: &str) -> bool {
    let ext_wide = wide_terminated(ext_with_dot);
    let mut required_size: u32 = 0;
    // SAFETY: `AssocQueryStringW` reads through `ext_wide` (a
    // stack-owned Vec<u16> live across the call), writes to
    // `required_size`, and does nothing with the two null buffer
    // pointers. No wnd_proc re-entry, no cross-thread state.
    let hr = unsafe {
        AssocQueryStringW(
            ASSOCF_INIT_IGNOREUNKNOWN,
            ASSOCSTR_EXECUTABLE,
            PCWSTR(ext_wide.as_ptr()),
            w!("open"),
            None,
            &raw mut required_size,
        )
    };
    hr.is_ok()
}

/// Pass `path` to the OS's registered handler for its extension
/// via `ShellExecuteW("open", ...)`. The verb resolves against
/// the same association tree [`extension_has_registered_handler`]
/// probes, so callers that gate on that helper first can trust
/// the launch to succeed on any healthy machine. Failures still
/// log at `warn` ŌĆö a broken association between the greying
/// refresh and the click (e.g. the user uninstalled the handler
/// mid-session) is rare but not impossible.
///
/// **Security.** Unlike [`open_url_in_browser`], the path here is
/// derived from `Tab.path` (user-controlled) rather than a
/// compile-time constant. The mitigation is that
/// (a) `ShellExecuteW`'s `"open"` verb only invokes the
/// per-extension registered handler, never runs the path as a
/// command, and (b) the path is quoted-then-passed as a single
/// wide-string argument, so a filename containing shell
/// metacharacters cannot inject additional command tokens. Same
/// safety envelope Notepad++ operates under for the equivalent
/// menu entry.
fn open_path_in_default_viewer(hwnd: HWND, path: &Path) {
    use std::os::windows::ffi::OsStrExt;
    let path_wide: Vec<u16> = path
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();
    // SAFETY: `path_wide` lives across the synchronous call; `hwnd`
    // is the main window we own on this thread. No handle is
    // retained past this call.
    let ret = unsafe {
        ShellExecuteW(
            Some(hwnd),
            w!("open"),
            PCWSTR(path_wide.as_ptr()),
            PCWSTR::null(),
            PCWSTR::null(),
            SW_SHOWNORMAL,
        )
    };
    if (ret.0 as isize) <= 32 {
        tracing::warn!(
            path = ?path,
            code = ret.0 as isize,
            "ShellExecuteW(open, <file>) failed"
        );
    }
}

/// Copy `text` to the Windows clipboard as `CF_UNICODETEXT`.
/// Follows the classic Win32 sequence: `OpenClipboard(owner)` ŌåÆ
/// `EmptyClipboard` ŌåÆ `GlobalAlloc(GMEM_MOVEABLE)` ŌåÆ memcpy
/// through `GlobalLock`/`GlobalUnlock` ŌåÆ `SetClipboardData` ŌåÆ
/// `CloseClipboard`.
///
/// Ownership hand-off: on success the clipboard subsystem takes
/// ownership of the `HGLOBAL` and is responsible for freeing it.
/// If `SetClipboardData` fails, we still own the allocation and
/// must free it via `GlobalFree` ŌĆö otherwise the buffer leaks
/// once per failed copy. `EmptyClipboard` frees whatever the
/// previous owner (possibly us on a prior copy) put there, so
/// leaks are bounded to the current attempt's window.
///
/// Errors log at `warn` and drop the copy silently ŌĆö clipboard
/// contention with another app's paste operation is a routine
/// failure mode not worth surfacing to the user.
///
/// # Safety
///
/// `owner` must be a live HWND owned by this thread ŌĆö the
/// clipboard subsystem binds the owning window to the caller's
/// thread for the duration of the open, and passing a foreign
/// HWND races with the owning thread's clipboard state.
unsafe fn copy_text_to_clipboard(owner: HWND, text: &str) {
    use windows::Win32::Foundation::{GlobalFree, HANDLE, HGLOBAL};
    use windows::Win32::System::DataExchange::{
        CloseClipboard, EmptyClipboard, OpenClipboard, SetClipboardData,
    };
    use windows::Win32::System::Memory::{GlobalAlloc, GlobalLock, GlobalUnlock, GMEM_MOVEABLE};

    // Encode as UTF-16 with a trailing NUL. `SetClipboardData`
    // for CF_UNICODETEXT expects a null-terminated wide string;
    // omitting the NUL would let paste consumers read past the
    // buffer end.
    let wide: Vec<u16> = text.encode_utf16().chain(std::iter::once(0)).collect();
    let bytes = wide.len() * 2;

    // SAFETY: no cross-thread state; OpenClipboard binds the
    // clipboard to this thread. Every early-return path either
    // hasn't taken clipboard ownership yet or explicitly calls
    // `CloseClipboard`.
    unsafe {
        if OpenClipboard(Some(owner)).is_err() {
            tracing::warn!("copy_text_to_clipboard: OpenClipboard failed");
            return;
        }
        // EmptyClipboard is best-effort ŌĆö failure just means the
        // previous owner leaks; the copy attempt still proceeds.
        let _ = EmptyClipboard();

        let Ok(hglobal) = GlobalAlloc(GMEM_MOVEABLE, bytes) else {
            let _ = CloseClipboard();
            tracing::warn!(bytes, "copy_text_to_clipboard: GlobalAlloc failed");
            return;
        };
        let hglobal: HGLOBAL = hglobal;
        let dst = GlobalLock(hglobal).cast::<u16>();
        if dst.is_null() {
            let _ = GlobalFree(Some(hglobal));
            let _ = CloseClipboard();
            tracing::warn!("copy_text_to_clipboard: GlobalLock returned null");
            return;
        }
        std::ptr::copy_nonoverlapping(wide.as_ptr(), dst, wide.len());
        // GlobalUnlock's Result is documented as returning an
        // error on the LAST unlock ŌĆö that's the expected path
        // here (lock count goes 1 ŌåÆ 0). Discard it.
        let _ = GlobalUnlock(hglobal);
        let handle = HANDLE(hglobal.0);
        if SetClipboardData(u32::from(CF_UNICODETEXT_U16), Some(handle)).is_err() {
            // SetClipboardData failed ŌåÆ we still own the buffer;
            // free it to avoid a leak. On success ownership
            // transfers to the clipboard subsystem and we MUST
            // NOT free.
            let _ = GlobalFree(Some(hglobal));
            let _ = CloseClipboard();
            tracing::warn!("copy_text_to_clipboard: SetClipboardData failed");
            return;
        }
        let _ = CloseClipboard();
    }
}

/// `CF_UNICODETEXT` clipboard format id. Broken out as a `u16`
/// constant so callers don't need to pull in
/// `windows::Win32::System::Ole::CF_UNICODETEXT` (which is
/// wrapped in a `CLIPBOARD_FORMAT` newtype and only used for
/// this one call). The value is fixed at 13 by the Win32 API
/// and has been since Windows 3.1.
const CF_UNICODETEXT_U16: u16 = 13;

/// Open a Windows Explorer window rooted at `folder`. Uses
/// `ShellExecuteW("open", <folder>, ...)` ŌĆö Windows resolves
/// `open` on a directory to the Explorer shell verb. Failures
/// log at `warn` (same class of soft-fail as
/// [`open_path_in_default_viewer`]).
///
/// **Security.** `folder` is derived from workspace tree text
/// which came from `read_dir` ŌĆö passed as a single wide-string
/// argument to `ShellExecuteW`, never spliced into a command
/// line, so filenames containing shell metacharacters cannot
/// inject additional command tokens.
fn open_explorer_at(hwnd: HWND, folder: &Path) {
    use std::os::windows::ffi::OsStrExt;
    let path_wide: Vec<u16> = folder
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();
    let ret = unsafe {
        ShellExecuteW(
            Some(hwnd),
            w!("open"),
            PCWSTR(path_wide.as_ptr()),
            PCWSTR::null(),
            PCWSTR::null(),
            SW_SHOWNORMAL,
        )
    };
    if (ret.0 as isize) <= 32 {
        tracing::warn!(
            path = ?folder,
            code = ret.0 as isize,
            "ShellExecuteW(open, <folder>) failed"
        );
    }
}

/// Open Explorer at `file`'s parent folder with `file` itself
/// highlighted **and scrolled into view**. Uses the shell's
/// `SHOpenFolderAndSelectItems` COM API ŌĆö the "proper" way to do
/// this on Windows. Notably more reliable than the
/// `explorer.exe /select,"<path>"` command-line variant, which
/// selects the item but does NOT scroll the view when Explorer
/// reuses an existing window showing that folder ŌĆö the item ends
/// up highlighted somewhere off-screen. `SHOpenFolderAndSelectItems`
/// hits the same code path Explorer uses internally when it
/// synthesises "Show in Folder" from its own right-click menus,
/// so the scroll-to-item behaviour is native.
///
/// Implementation:
///   1. Build a NUL-terminated wide-string path.
///   2. `ILCreateFromPathW` ŌåÆ PIDL for the file item.
///   3. `SHOpenFolderAndSelectItems(pidl, None, 0)` ŌĆö per MSDN,
///      when the selection array is empty the `pidlfolder`
///      argument is treated as a fully-qualified item ID list
///      pointing at a single item within a folder, and Explorer
///      opens the item's PARENT folder with that item selected +
///      revealed.
///   4. `ILFree` the PIDL.
///
/// **COM requirement.** `SHOpenFolderAndSelectItems` requires COM
/// to be initialised on the calling thread. The UI thread already
/// has COM in STA mode by the time any menu command can fire,
/// because Scintilla calls `OleInitialize` in its `ScintillaWin`
/// constructor when the editor control is created (see
/// `crates/scintilla-sys/vendor/scintilla/win32/ScintillaWin.cxx`
/// ~line 628), and every menu that reaches this helper lives on
/// the same message-pump thread. No explicit `CoInitializeEx`
/// call is needed ŌĆö attempting a second init would only return
/// `S_FALSE` at best or `RPC_E_CHANGED_MODE` at worst.
///
/// **Security.** Unlike the `/select,"ŌĆ”"` command-line variant,
/// this API takes a PIDL (a binary shell item id list), not a
/// command line ŌĆö so there is no argument-injection surface at
/// all. `ILCreateFromPathW` parses the path itself and produces
/// an opaque structure Explorer consumes directly. Callers may
/// pass any legitimate filesystem path.
///
/// Failures log at `warn` and drop silently ŌĆö the two possible
/// error paths (file no longer exists ŌåÆ `ILCreateFromPathW`
/// returns null; Explorer couldn't be reached ŌåÆ
/// `SHOpenFolderAndSelectItems` returns an HRESULT) both warrant
/// the same soft-fail treatment as
/// [`open_path_in_default_viewer`].
fn open_explorer_selecting(_hwnd: HWND, file: &Path) {
    use std::os::windows::ffi::OsStrExt;
    use windows::Win32::UI::Shell::{ILCreateFromPathW, ILFree, SHOpenFolderAndSelectItems};

    let wide: Vec<u16> = file
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();

    // SAFETY: `wide` is a stack-owned buffer live across the
    // `ILCreateFromPathW` call. UI-thread only.
    // `ILCreateFromPathW` returns null when the path can't be
    // parsed (e.g. missing file); a null PIDL is a soft-fail
    // rather than a crash.
    let pidl = unsafe { ILCreateFromPathW(PCWSTR(wide.as_ptr())) };
    if pidl.is_null() {
        tracing::warn!(
            file = ?file,
            "open_explorer_selecting: ILCreateFromPathW returned null"
        );
        return;
    }
    // SAFETY: `pidl` is a valid ITEMIDLIST from ILCreateFromPathW.
    // `apidl = None` ŌåÆ cidl = 0 ŌåÆ SHOpenFolderAndSelectItems
    // treats `pidl` as the full-item PIDL and selects it in its
    // parent. COM is live on this thread (see doc comment).
    if let Err(e) = unsafe { SHOpenFolderAndSelectItems(pidl, None, 0) } {
        tracing::warn!(
            file = ?file,
            error = ?e,
            "SHOpenFolderAndSelectItems failed"
        );
    }
    // Always free the PIDL we allocated with ILCreateFromPathW ŌĆö
    // SHOpenFolderAndSelectItems does not take ownership.
    unsafe { ILFree(Some(pidl)) };
}

/// Move `path` to the Windows Recycle Bin via
/// `SHFileOperationW(FO_DELETE | FOF_ALLOWUNDO)`. Returns
/// `Ok(())` on a successful move, `Err(String)` with a
/// diagnostic message on failure. This is the exact API path
/// Explorer's own Delete key uses, so the OS Recycle Bin
/// prompts, quota rules, and eventual restore-item metadata
/// behave identically to a user-initiated delete.
///
/// **Confirmation.** We pass `FOF_NOCONFIRMATION` because the
/// caller has already shown its own OK/Cancel prompt with the
/// full file path; layering the shell's generic "Are you sure?"
/// on top would be a friction double-tap.
///
/// **Buffer contract.** `SHFileOperationW`'s `pFrom` is a
/// double-NUL-terminated wide-string list (`"path\0\0"`). We
/// build the buffer as a `Vec<u16>` ending in two NULs and
/// hand a `PCWSTR` pointing at its head.
///
/// **Security.** `path` is derived from `Tab.path` ŌĆö an
/// on-disk file the user opened themselves via FileŌåÆOpen,
/// drag-drop, or session restore. Every entry into
/// `SHFileOperationW` is gated by the caller's OK/Cancel
/// prompt showing the exact absolute path, so the user always
/// sees what they're about to delete.
///
/// **COM precondition.** `SHFileOperationW`'s Recycle Bin
/// path goes through shell/COM machinery. The UI thread
/// already has COM in STA mode by the time any menu command
/// can fire ŌĆö Scintilla's `OleInitialize` (called in
/// `ScintillaWin`'s constructor when the editor control is
/// created) established it, and every menu that reaches this
/// helper lives on the same message-pump thread. Same
/// invariant `open_explorer_selecting` relies on for
/// `SHOpenFolderAndSelectItems`; no explicit `CoInitializeEx`
/// call is needed.
fn move_path_to_recycle_bin(path: &Path) -> std::result::Result<(), String> {
    use std::os::windows::ffi::OsStrExt;
    use windows::Win32::UI::Shell::{
        SHFileOperationW, FOF_ALLOWUNDO, FOF_NOCONFIRMATION, FO_DELETE, SHFILEOPSTRUCTW,
    };

    // Double-NUL terminated wide string. SHFileOperationW's
    // documented contract on `pFrom` ŌĆö a single-file list must
    // still end in two NULs (one terminates the last path, the
    // second terminates the list itself).
    let mut buf: Vec<u16> = path.as_os_str().encode_wide().collect();
    buf.push(0);
    buf.push(0);
    let mut op = SHFILEOPSTRUCTW {
        wFunc: FO_DELETE,
        pFrom: PCWSTR(buf.as_ptr()),
        // `FOF_ALLOWUNDO` is the "Recycle Bin" flag ŌĆö without
        // it, `FO_DELETE` performs an unrecoverable permanent
        // delete. `FOF_NOCONFIRMATION` suppresses the shell's
        // own "Are you sure?" so the caller's prompt is
        // authoritative.
        fFlags: u16::try_from((FOF_ALLOWUNDO | FOF_NOCONFIRMATION).0)
            .expect("FOF flag bits fit in u16"),
        ..Default::default()
    };
    // SAFETY: `buf` outlives the synchronous SHFileOperationW
    // call. `pFrom` points into `buf`; no field of `op` is
    // retained past this call.
    let rc = unsafe { SHFileOperationW(&raw mut op) };
    if rc == 0 && !op.fAnyOperationsAborted.as_bool() {
        Ok(())
    } else {
        Err(format!(
            "SHFileOperationW returned {rc} (aborted={})",
            op.fAnyOperationsAborted.as_bool()
        ))
    }
}

/// Launch `program` (e.g. `"cmd.exe"` or `"powershell.exe"`) with
/// `working_dir` as its current directory. Uses
/// `ShellExecuteW`'s `lpDirectory` parameter ŌĆö the launched
/// process inherits it as CWD, which is exactly the "CMD here"
/// / "PowerShell here" behaviour Explorer implements for its own
/// Shift-right-click menu.
///
/// **Security.** `program` is a compile-time `&'static str`
/// (either "cmd.exe" or "powershell.exe"), never derived from
/// user input. Windows resolves both via `%PATH%` ŌĆö that is the
/// same path Explorer's built-in Shift-right-click uses. If a
/// user has planted a malicious `cmd.exe` earlier in `PATH` than
/// `%SystemRoot%\System32`, they have already lost far more
/// than this menu entry. The `working_dir` is passed via
/// `lpDirectory` (setting CWD, not spliced into a command line),
/// so a hostile pathname cannot inject additional command tokens.
fn shell_launch_in_dir(hwnd: HWND, program: PCWSTR, working_dir: &Path) {
    use std::os::windows::ffi::OsStrExt;
    let dir_wide: Vec<u16> = working_dir
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();
    let ret = unsafe {
        ShellExecuteW(
            Some(hwnd),
            w!("open"),
            program,
            PCWSTR::null(),
            PCWSTR(dir_wide.as_ptr()),
            SW_SHOWNORMAL,
        )
    };
    if (ret.0 as isize) <= 32 {
        tracing::warn!(
            dir = ?working_dir,
            code = ret.0 as isize,
            "ShellExecuteW(open, <program>) failed"
        );
    }
}

/// Resolve the parent directory of the active tab's on-disk path,
/// under a brief `state_from_hwnd` borrow that drops before the
/// caller does anything else. Used by every "Open Containing
/// Folder" submenu arm and any future consumer that wants "the
/// folder containing the file the user is looking at right now."
///
/// Returns `None` iff the tab is untitled (no `path`) OR its
/// path has no parent (drive root / filesystem root). Both cases
/// are also greyed by [`refresh_file_menu`] so a normal menu
/// click never reaches this returning `None`; the `Option` shape
/// only matters when a plugin-forged `WM_COMMAND` bypasses the
/// greying, which stays a silent no-op ŌĆö the greying is a UX
/// gate, not a capability restriction (plugins already run
/// in-process with full authority, DESIGN.md ┬¦6.5).
///
/// # Safety
///
/// `hwnd` must be the main window on the UI thread.
unsafe fn active_parent_dir(hwnd: HWND) -> Option<PathBuf> {
    unsafe { state_from_hwnd(hwnd) }.and_then(|state| {
        state
            .shell
            .active()
            .and_then(|t| t.path.as_deref())
            .and_then(Path::parent)
            .map(Path::to_path_buf)
    })
}

/// Refresh state-driven File menu entries. Currently drives just
/// [`ID_FILE_OPEN_IN_DEFAULT_VIEWER`]'s enabled/greyed state; the
/// rest of the File menu is either statically enabled or gated
/// elsewhere (e.g. Save's WM_INITMENUPOPUP-independent shortcut
/// flow).
///
/// Enable rule (mirrors Notepad++): the entry is enabled iff the
/// active tab has an on-disk path (untitled buffers grey it) AND
/// the extension has a registered OS handler (unregistered
/// extensions grey it). Both checks are cheap ŌĆö a probe-only
/// `AssocQueryStringW` on a menu-open cadence sits well inside
/// the per-frame budget.
///
/// # Safety
///
/// `file_menu` must be a live HMENU (built by
/// [`build_main_menu`], stored on `WindowState`). Caller runs on
/// the UI thread.
unsafe fn refresh_file_menu(file_menu: HMENU, shell: &codepp_shell::Shell) {
    let active_path = shell.active().and_then(|tab| tab.path.as_deref());
    // Open in Default Viewer: enabled iff path exists AND the
    // extension has a registered OS handler.
    let default_viewer_enabled = active_path
        .and_then(extract_extension_with_dot)
        .is_some_and(|ext| extension_has_registered_handler(&ext));
    // Open Containing Folder submenu: enabled iff path exists AND
    // has a parent directory (a path like `C:\`, though not
    // reachable via Save-As on a normal machine, would have no
    // parent). Every entry in the submenu (Explorer / cmd /
    // PowerShell / Folder as Workspace) shares the same enable
    // condition ŌĆö all four operate on the parent directory.
    let open_containing_enabled = active_path.and_then(Path::parent).is_some();

    // Close Multiple Documents: each entry has its own
    // precondition. Baseline is `tabs.len() >= 2` ŌĆö none of the
    // variants make sense with zero or one tab.
    let n = shell.tabs.len();
    let baseline_multi = n >= 2;
    let active_idx = shell.active_tab;
    // "Close All but Active": needs at least one non-active tab
    // to close (i.e. any n >= 2 when an active tab exists).
    let close_but_active_enabled = baseline_multi && active_idx.is_some();
    // "Close All but Pinned": needs at least one non-pinned tab.
    let close_but_pinned_enabled = baseline_multi && shell.tabs.iter().any(|t| !t.pinned);
    // "Close All To the Left": needs active idx > 0 (at least
    // one tab to the left of the active one).
    let close_to_left_enabled = baseline_multi && active_idx.is_some_and(|i| i > 0);
    // "Close All To the Right": needs active idx < n-1.
    let close_to_right_enabled = baseline_multi && active_idx.is_some_and(|i| i + 1 < n);
    // "Close All Unchanged": needs at least one clean tab.
    let close_unchanged_enabled = baseline_multi && shell.tabs.iter().any(|t| !t.dirty);

    // `EnableMenuItem` returns the previous state on success or
    // `-1u32` on failure; both are fire-and-forget for us ŌĆö a
    // failure just means the enable state is wrong on this open,
    // never a stability issue. `MF_BYCOMMAND` searches the entire
    // menu tree rooted at `file_menu`, including nested submenus,
    // so ids that live one level deep (Open Containing Folder,
    // Close Multiple Documents) resolve correctly.
    let apply = |id: u16, enabled: bool| unsafe {
        let flags = MF_BYCOMMAND.0 | if enabled { MF_ENABLED.0 } else { MF_GRAYED.0 };
        let _ = EnableMenuItem(file_menu, u32::from(id), MENU_ITEM_FLAGS(flags));
    };
    apply(ID_FILE_OPEN_IN_DEFAULT_VIEWER, default_viewer_enabled);
    apply(ID_FILE_OPEN_CONTAINING_EXPLORER, open_containing_enabled);
    apply(ID_FILE_OPEN_CONTAINING_CMD, open_containing_enabled);
    apply(ID_FILE_OPEN_CONTAINING_POWERSHELL, open_containing_enabled);
    apply(ID_FILE_OPEN_CONTAINING_WORKSPACE, open_containing_enabled);
    apply(ID_FILE_CLOSE_ALL_BUT_ACTIVE, close_but_active_enabled);
    apply(ID_FILE_CLOSE_ALL_BUT_PINNED, close_but_pinned_enabled);
    apply(ID_FILE_CLOSE_ALL_TO_LEFT, close_to_left_enabled);
    apply(ID_FILE_CLOSE_ALL_TO_RIGHT, close_to_right_enabled);
    apply(ID_FILE_CLOSE_ALL_UNCHANGED, close_unchanged_enabled);
    // Move to Recycle Bin: enabled iff the active tab has an
    // on-disk path (untitled buffers have nothing to move).
    apply(ID_FILE_MOVE_TO_RECYCLE_BIN, active_path.is_some());
    // Print: enabled iff there IS an active tab. We can't cheaply
    // check "document non-empty" from the shell alone (that requires
    // touching Scintilla, which we don't want to do on every menu
    // refresh), so the empty-doc case falls through to the print
    // handler's own fast-path skip.
    apply(ID_FILE_PRINT, shell.active().is_some());
    // Print Preview: same enable condition as Print ŌĆö a modal
    // preview of "no active document" is useless.
    apply(ID_FILE_PRINT_PREVIEW, shell.active().is_some());
}

/// Show the "About Code++" dialog modally. `main_hwnd` is the
/// owner; the dialog disables the owner for the duration of the
/// modal pump and restores it via the existing `OwnerEnableGuard`.
fn show_about_dialog(main_hwnd: HWND) {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();

    unsafe {
        let instance = match GetModuleHandleW(None) {
            Ok(h) => h,
            Err(_) => return,
        };

        REGISTERED.get_or_init(|| {
            let class = WNDCLASSEXW {
                cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
                style: CS_HREDRAW | CS_VREDRAW,
                lpfnWndProc: Some(about_wnd_proc),
                hInstance: instance.into(),
                hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
                hbrBackground: dialog_bg_brush(),
                lpszClassName: ABOUT_CLASS,
                ..Default::default()
            };
            let _ = RegisterClassExW(&raw const class);
        });

        // --- Layout (CLIENT coordinates) --------------------------
        //
        // Tight enough to feel at home next to N++'s About box,
        // wide enough that the license body wraps to ~5 lines.
        const CLIENT_W: i32 = 480;
        const CLIENT_H: i32 = 460;
        const PAD: i32 = 18;

        // Top row: app icon (owner-drawn for alpha-correct paint)
        // + title vertically centered against it.
        const TOP_ICON_SIZE: i32 = 80;
        const TOP_ICON_X: i32 = PAD;
        const TOP_ICON_Y: i32 = PAD;
        const TITLE_X: i32 = TOP_ICON_X + TOP_ICON_SIZE + 16;
        const TITLE_W: i32 = CLIENT_W - TITLE_X - PAD;
        const TITLE_H: i32 = 28;
        // Centre the title vertically against the icon block.
        const TITLE_Y: i32 = TOP_ICON_Y + (TOP_ICON_SIZE - TITLE_H) / 2;

        // Home row: "Home:" label + URL link (no leading icon ŌĆö
        // the chameleon already appears once in the top row).
        const HOME_ROW_Y: i32 = TOP_ICON_Y + TOP_ICON_SIZE + 18;
        const HOME_LABEL_X: i32 = PAD;
        const HOME_LABEL_Y: i32 = HOME_ROW_Y + 4;
        const HOME_LABEL_W: i32 = 48;
        const HOME_LINK_X: i32 = HOME_LABEL_X + HOME_LABEL_W;
        const HOME_LINK_W: i32 = CLIENT_W - HOME_LINK_X - PAD;
        const HOME_ROW_H: i32 = 22;

        // License frame + caption + body. Etched-frame STATIC
        // draws the border rectangle; a separate opaque-fill
        // caption STATIC sits over the top edge so the border
        // line breaks around the "MIT License" text; the
        // multi-line license body STATIC is inset inside the
        // frame. See the block just before the frame `CreateWindowExW`
        // for the design rationale (`BS_GROUPBOX` was replaced
        // after two rounds of unsuccessful title-clear workarounds
        // on Win11).
        const LIC_BOX_Y: i32 = HOME_ROW_Y + HOME_ROW_H + 14;
        const LIC_BOX_X: i32 = PAD;
        const LIC_BOX_W: i32 = CLIENT_W - 2 * PAD;
        const LIC_BOX_H: i32 = 240;
        const LIC_TEXT_X: i32 = LIC_BOX_X + 12;
        const LIC_TEXT_Y: i32 = LIC_BOX_Y + 22;
        const LIC_TEXT_W: i32 = LIC_BOX_W - 24;
        const LIC_TEXT_H: i32 = LIC_BOX_H - 32;

        // OK button at the bottom, centered.
        const OK_W: i32 = 96;
        const OK_H: i32 = 28;
        const OK_X: i32 = (CLIENT_W - OK_W) / 2;
        const OK_Y: i32 = LIC_BOX_Y + LIC_BOX_H + 12;

        // Sanity-check the layout against CLIENT_H at compile time ŌĆö
        // a future tweak that pushes the OK button off the bottom
        // edge fails to build instead of silently clipping the
        // button.
        const _: () = {
            let bottom = OK_Y + OK_H + PAD;
            assert!(bottom <= CLIENT_H, "About-dialog layout overflows CLIENT_H");
        };

        let mut window_rect = RECT {
            left: 0,
            top: 0,
            right: CLIENT_W,
            bottom: CLIENT_H,
        };
        let _ = AdjustWindowRectEx(
            &raw mut window_rect,
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            false,
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
        );
        let dlg_w = window_rect.right - window_rect.left;
        let dlg_h = window_rect.bottom - window_rect.top;

        let mut owner_rect = RECT::default();
        let _ = GetWindowRect(main_hwnd, &raw mut owner_rect);
        let owner_w = owner_rect.right - owner_rect.left;
        let owner_h = owner_rect.bottom - owner_rect.top;
        let dlg_x = owner_rect.left + (owner_w - dlg_w) / 2;
        let dlg_y = owner_rect.top + (owner_h - dlg_h) / 2;

        // Bold title font: ~12pt at 96 DPI. `lfHeight` follows the
        // Win32 convention where a negative value is interpreted as
        // a *character* height in logical units, which matches what
        // a designer expects when picking a "16 px tall" font.
        let mut title_lf = LOGFONTW {
            lfHeight: -16,
            // `FW_BOLD` is a `FONT_WEIGHT(u32)` newtype in
            // windows-rs but `LOGFONTW.lfWeight` is `i32` (signed
            // because the SDK header types it as `LONG`). Extract
            // the inner u32 and cast ŌĆö the value is 700, well
            // inside i32's positive range.
            lfWeight: FW_BOLD.0 as i32,
            ..Default::default()
        };
        // "Segoe UI" is the system UI font on Vista+; falls back
        // gracefully if absent. Truncated copy is fine ŌĆö the array
        // is zero-padded and any tail past the face name is
        // ignored.
        let face = "Segoe UI";
        let utf16: Vec<u16> = face.encode_utf16().collect();
        let n = utf16.len().min(title_lf.lfFaceName.len() - 1);
        title_lf.lfFaceName[..n].copy_from_slice(&utf16[..n]);
        let title_font = CreateFontIndirectW(&raw const title_lf);
        // RAII free for the title font ŌĆö covers every exit path
        // including the child-creation `Err(_) => return` arms below.
        let _title_font_guard = GdiObjectGuard(title_font);
        let default_font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);

        // Pre-format the title string so the heap-allocated
        // `HSTRING` outlives `CreateWindowExW`.
        let title_text = format!("Code++ v{}    ({})", env!("CARGO_PKG_VERSION"), ABOUT_ARCH);
        let title_text_w = HSTRING::from(title_text);
        let home_url = HSTRING::from("https://code-plus-plus.org/");
        let license_w = HSTRING::from(ABOUT_LICENSE_BODY);

        // Load the chameleon icon once for the owner-draw STATIC.
        // 80px request maps to the 64 or 128 px BMP entry inside
        // `code++.ico`; either is 32bpp so `DrawIconEx(DI_NORMAL)`
        // will alpha-composite cleanly. Ownership of the HICON is
        // transferred into `AboutDialogState` immediately below;
        // its `Drop` impl calls `DestroyIcon` on every exit path,
        // including the child-`CreateWindowExW` failure returns.
        let app_icon = LoadImageW(
            Some(instance.into()),
            APP_ICON_RESOURCE,
            IMAGE_ICON,
            TOP_ICON_SIZE,
            TOP_ICON_SIZE,
            LR_DEFAULTCOLOR,
        )
        .map(|h| HICON(h.0))
        .unwrap_or_default();

        // Heap-allocate the dialog state. The wnd_proc reads it via
        // GWLP_USERDATA; the Box stays in this stack frame so the
        // raw pointer remains valid for the dialog's lifetime.
        let mut state = Box::new(AboutDialogState {
            link_hwnd: HWND::default(),
            owner_hwnd: main_hwnd,
            home_url: home_url.clone(),
            app_icon,
            lic_title_hwnd: HWND::default(),
        });
        let state_ptr: *mut AboutDialogState = &raw mut *state;

        let dlg = match CreateWindowExW(
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
            ABOUT_CLASS,
            w!("About Code++"),
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            dlg_x,
            dlg_y,
            dlg_w,
            dlg_h,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            Some(state_ptr.cast::<c_void>()),
        ) {
            Ok(h) => h,
            Err(_) => return,
        };
        let _dlg_guard = DlgDestroyGuard(dlg);

        // Top app-icon STATIC: `SS_OWNERDRAW` so the parent's
        // `WM_DRAWITEM` handler paints the icon via `DrawIconEx`
        // with `DI_NORMAL`. The default `SS_ICON` paint path on
        // Win11 strips 32bpp alpha and surfaces transparent
        // pixels as black, which is what made the chameleon look
        // like it had a black backdrop in the first cut. The
        // owner-draw path composites alpha correctly against the
        // dialog background brush.
        // The HWND is never read again ŌĆö paint and click come
        // through the parent via `WM_DRAWITEM` / `WM_COMMAND` ŌĆö
        // but the binding is required because the early-return
        // path wants a typed `Result`. Underscore-prefixed so
        // clippy doesn't flag it.
        let _icon_top = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | style_bits(SS_OWNERDRAW as i32),
            TOP_ICON_X,
            TOP_ICON_Y,
            TOP_ICON_SIZE,
            TOP_ICON_SIZE,
            Some(dlg),
            Some(HMENU(IDC_ABOUT_ICON as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };

        let title_static = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            &title_text_w,
            WS_CHILD | WS_VISIBLE | style_bits(SS_LEFT as i32),
            TITLE_X,
            TITLE_Y,
            TITLE_W,
            TITLE_H,
            Some(dlg),
            Some(HMENU(IDC_ABOUT_TITLE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };

        let home_label = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Home:"),
            WS_CHILD | WS_VISIBLE | style_bits(SS_LEFT as i32),
            HOME_LABEL_X,
            HOME_LABEL_Y,
            HOME_LABEL_W,
            HOME_ROW_H - 4,
            Some(dlg),
            Some(HMENU(IDC_ABOUT_HOME_LABEL as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };

        // The clickable URL link. SS_NOTIFY makes the static fire
        // STN_CLICKED through WM_COMMAND; the wnd_proc forwards it
        // to ShellExecuteW. WM_CTLCOLORSTATIC paints the text in
        // hyperlink blue.
        let link = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            &home_url,
            WS_CHILD | WS_VISIBLE | style_bits((SS_LEFT | SS_NOTIFY) as i32),
            HOME_LINK_X,
            HOME_LABEL_Y,
            HOME_LINK_W,
            HOME_ROW_H - 4,
            Some(dlg),
            Some(HMENU(IDC_ABOUT_HOME_LINK as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };

        // License box: an etched frame with a separate caption
        // STATIC positioned over the frame's top edge. Split
        // rather than using `BS_GROUPBOX` because the group-box
        // paint routine on Win11 lets the top border line run
        // through the title text regardless of theme state or
        // `WM_CTLCOLORBTN` return ŌĆö verified across the merged
        // (`NULL_BRUSH`), classic (`dialog_bg_brush` +
        // `SetBkColor`), and font-order-swapped variants. The
        // split gives us a frame that draws no title area to
        // interfere with, plus a plain STATIC whose
        // `WM_CTLCOLORSTATIC` returns `dialog_bg_brush` so its
        // painted rect opaquely covers the frame's top edge at
        // the caption's position ŌĆö same visual as a themed
        // group-box title on other platforms, without any of
        // the group-box paint quirks.
        //
        // Caption geometry: the label's vertical centre lands
        // on the frame's top edge (`LIC_BOX_Y`) so the opaque
        // rect breaks the line cleanly. Width is generous
        // enough (`LIC_CAPTION_W`) to seat the label with
        // horizontal padding either side; `SS_CENTER` keeps the
        // text balanced inside that rect.
        const LIC_CAPTION_TEXT_H: i32 = 18;
        const LIC_CAPTION_W: i32 = 96;
        const LIC_CAPTION_X: i32 = LIC_BOX_X + 12;
        const LIC_CAPTION_Y: i32 = LIC_BOX_Y - LIC_CAPTION_TEXT_H / 2;
        let lic_box = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | style_bits(SS_ETCHEDFRAME as i32),
            LIC_BOX_X,
            LIC_BOX_Y,
            LIC_BOX_W,
            LIC_BOX_H,
            Some(dlg),
            Some(HMENU(IDC_ABOUT_LICENSE_GROUP as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };
        let lic_title = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!(" MIT License "),
            WS_CHILD | WS_VISIBLE | style_bits((SS_CENTER | SS_CENTERIMAGE) as i32),
            LIC_CAPTION_X,
            LIC_CAPTION_Y,
            LIC_CAPTION_W,
            LIC_CAPTION_TEXT_H,
            Some(dlg),
            Some(HMENU(IDC_ABOUT_LICENSE_TITLE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };
        let lic_text = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            &license_w,
            WS_CHILD | WS_VISIBLE | style_bits(SS_LEFT as i32),
            LIC_TEXT_X,
            LIC_TEXT_Y,
            LIC_TEXT_W,
            LIC_TEXT_H,
            Some(dlg),
            Some(HMENU(IDC_ABOUT_LICENSE_TEXT as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };

        let ok_btn = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("OK"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            OK_X,
            OK_Y,
            OK_W,
            OK_H,
            Some(dlg),
            Some(HMENU(IDOK.0 as u16 as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };

        // Publish both HWNDs to the wnd_proc before the modal
        // pump kicks off so the very first `WM_SETCURSOR` /
        // `WM_CTLCOLORSTATIC` message can resolve them.
        state.link_hwnd = link;
        state.lic_title_hwnd = lic_title;

        // Apply fonts: bold title font for the title only, default
        // GUI font for everything else. The owner-draw icon
        // STATIC carries no text so it needs no font; the system
        // STATIC class default is used for it implicitly. No
        // `disable_visual_style` call is needed on the etched
        // frame ŌĆö `SetWindowTheme(hwnd, "", "")` targets the
        // "Button" UxTheme class, and `STATIC` is a separate
        // class ("Static") that renders the etched frame
        // correctly under both themed and classic paints. The
        // group-box version of this dialog previously called
        // `disable_visual_style` to work around a BS_GROUPBOX
        // title-clear quirk, but the redesign no longer depends
        // on that path at all.
        apply_dialog_font(title_static, title_font);
        for child in [home_label, link, lic_box, lic_title, lic_text, ok_btn] {
            apply_dialog_font(child, default_font);
        }

        // Disable the owner before SHOW so input cannot reach the
        // main window during the brief moment between window
        // creation and modal pump start; the RAII guard restores
        // the owner on every exit path.
        let _ = EnableWindow(main_hwnd, false);
        let _owner_guard = OwnerEnableGuard(main_hwnd);
        let _ = ShowWindow(dlg, SW_SHOW);
        let _ = SetFocus(Some(ok_btn));

        let mut msg_buf = MSG::default();
        loop {
            if !IsWindow(Some(dlg)).as_bool() {
                break;
            }
            let ret = GetMessageW(&raw mut msg_buf, None, 0, 0);
            match ret.0 {
                0 => {
                    let _ = PostMessageW(None, WM_QUIT, msg_buf.wParam, msg_buf.lParam);
                    break;
                }
                -1 => break,
                _ => {
                    if !IsDialogMessageW(dlg, &raw const msg_buf).as_bool() {
                        let _ = TranslateMessage(&raw const msg_buf);
                        DispatchMessageW(&raw const msg_buf);
                    }
                }
            }
        }

        // Title-font cleanup, owner re-enable, and dialog HWND
        // destroy are all handled by RAII guards (`GdiObjectGuard`,
        // `OwnerEnableGuard`, `DlgDestroyGuard`) on scope exit.
    }
}

// --- Plugin Manager dialog -------------------------------------------
//
// Modal dialog reached via Plugins ŌåÆ Plugin Manager.... Lists every
// discovered plugin (loaded, pending, failed) with a per-row Enabled
// checkbox; toggling the checkbox flips the disabled flag in the
// plugin host and writes the change through to
// `<plugins_config_dir>/disabled.txt`. Disabled plugins skip the
// lazy-load path on the *next* launch ŌĆö currently-loaded plugins
// stay loaded for the rest of the session, matching Notepad++'s
// "restart required" semantics.
//
// Layout follows N++'s Plugin Admin: a single tab control labelled
// "Installed" across the top, a `LVS_REPORT` listview filling the
// body with `LVS_EX_CHECKBOXES + LVS_EX_FULLROWSELECT`, a small
// hint static under the listview, and a Close button bottom-right.
// Future tabs (Updates, Available, Incompatible) slot in alongside
// "Installed" without changing this scaffolding.

const PLUGIN_ADMIN_CLASS: PCWSTR = w!("CodePlusPlusPluginAdminDialog");

const IDC_PLUGIN_ADMIN_TAB: u16 = 700;
const IDC_PLUGIN_ADMIN_LIST: u16 = 701;
const IDC_PLUGIN_ADMIN_HINT: u16 = 702;
const IDC_PLUGIN_ADMIN_CLOSE: u16 = 703;

// Style Configurator dialog (Settings ŌåÆ Style Configurator...).
// Each control gets a stable id in the 800..=899 block so
// WM_COMMAND / WM_DRAWITEM can route by command id without
// HWND chasing. The dialog stores HWNDs on its state for
// repaint / readback, but the command-id route is what the
// wnd_proc dispatch is built around.
const IDC_STYLE_THEME_COMBO: u16 = 800; // greyed out (out of scope today)
const IDC_STYLE_LANG_COMBO: u16 = 801; // greyed out
const IDC_STYLE_STYLE_LIST: u16 = 802;
const IDC_STYLE_FG_BUTTON: u16 = 803;
const IDC_STYLE_BG_BUTTON: u16 = 804;
const IDC_STYLE_FONT_COMBO: u16 = 805;
const IDC_STYLE_SIZE_COMBO: u16 = 806;
const IDC_STYLE_BOLD: u16 = 807;
const IDC_STYLE_ITALIC: u16 = 808;
const IDC_STYLE_UNDERLINE: u16 = 809;
const IDC_STYLE_SAVE_CLOSE: u16 = 810;
const IDC_STYLE_CANCEL: u16 = 811;
const IDC_STYLE_TRANSPARENCY_CHECK: u16 = 812;
const IDC_STYLE_TRANSPARENCY_SLIDER: u16 = 813;
const IDC_COLOR_POPUP_MORE: u16 = 820;
// Swatches in the colour-picker popup occupy ids 830..=869 (40
// preset colours). Click on any of them is a `BN_CLICKED` whose
// command id minus `IDC_COLOR_POPUP_SWATCH_BASE` is the swatch
// index into `PRESET_COLOURS`.
const IDC_COLOR_POPUP_SWATCH_BASE: u16 = 830;

/// `LVM_INSERTITEMW`-side flag value for "checked" in the
/// `LVS_EX_CHECKBOXES` state-image slot. The state-image index
/// occupies bits 12-15 of the item state; index 1 = unchecked,
/// index 2 = checked. `INDEXTOSTATEIMAGEMASK(i)` is just `i << 12`.
const LIST_CHECKED_STATE: u32 = 2 << 12;
const LIST_UNCHECKED_STATE: u32 = 1 << 12;

/// Heap-allocated dialog state. The `wnd_proc` looks it up via
/// `GWLP_USERDATA`; the box is owned by `show_plugin_admin_dialog`'s
/// stack frame for the dialog's lifetime.
struct PluginAdminDialogState {
    /// Snapshot taken at dialog open. Listview rows map 1:1 to this
    /// vec ŌĆö `entries[row].index` is what gets passed back to
    /// `Shell::set_plugin_disabled` on toggle.
    entries: Vec<PluginAdminEntry>,
    /// Owner HWND. The IDOK / `WM_CLOSE` handler re-enables the
    /// owner *before* `DestroyWindow` so window activation
    /// transfers naturally back to the editor (same fix as the
    /// About / Goto dialogs).
    owner_hwnd: HWND,
    /// Listview HWND, captured after creation so the `WM_NOTIFY`
    /// arm can match `nmhdr.hwndFrom` against it.
    list_hwnd: HWND,
}

extern "system" fn plugin_admin_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_NCCREATE => {
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let state_ptr = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as i32;
                if cmd == IDOK.0 || cmd == IDCANCEL.0 || cmd == i32::from(IDC_PLUGIN_ADMIN_CLOSE) {
                    let state_ptr =
                        GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const PluginAdminDialogState;
                    if !state_ptr.is_null() {
                        let _ = EnableWindow((*state_ptr).owner_hwnd, true);
                    }
                    let _ = DestroyWindow(hwnd);
                    LRESULT(0)
                } else {
                    DefWindowProcW(hwnd, msg, wparam, lparam)
                }
            }
            WM_NOTIFY => {
                // Listview check-state change ŌĆö fired once when
                // the user clicks the checkbox in front of a row.
                // Compare the check state in `uOldState` and
                // `uNewState`; if it flipped, push the change
                // through to the shell and persist disabled.txt.
                let nmhdr_ptr = lparam.0 as *const NMHDR;
                if !nmhdr_ptr.is_null() {
                    let nmhdr = &*nmhdr_ptr;
                    let state_ptr =
                        GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut PluginAdminDialogState;
                    if !state_ptr.is_null()
                        && nmhdr.hwndFrom == (*state_ptr).list_hwnd
                        && nmhdr.code == LVN_ITEMCHANGED
                    {
                        let nmlv_ptr = lparam.0 as *const NMLISTVIEW;
                        let nmlv = &*nmlv_ptr;
                        let old_check = nmlv.uOldState & LVIS_STATEIMAGEMASK.0;
                        let new_check = nmlv.uNewState & LVIS_STATEIMAGEMASK.0;
                        // Filter on actual check-state changes ŌĆö
                        // LVN_ITEMCHANGED also fires on selection/
                        // focus changes that we don't care about
                        // here. `old_check == 0` means the
                        // listview hasn't recorded a state-image
                        // value yet (the very first state set);
                        // skipping that prevents our own
                        // populate-time `LVM_SETITEMSTATE` from
                        // looking like a user toggle.
                        if old_check != 0 && old_check != new_check && nmlv.iItem >= 0 {
                            // `iItem >= 0` guard: an LVN_ITEMCHANGED
                            // for a *non-item* event (e.g. group
                            // header click on a future grouped
                            // listview) carries `iItem == -1`. The
                            // wrap-to-`usize::MAX` would still bounds-
                            // check safely on `entries.get_mut`, but
                            // making the intent explicit at the
                            // filter is worth the one extra
                            // comparison.
                            let row = nmlv.iItem as usize;
                            // Explicit reborrow on the entries Vec
                            // ŌĆö rustc 1.95 forbids implicit autorefs
                            // through a raw `*mut`, and going via
                            // `&mut (*state_ptr).entries` makes the
                            // mutability intent clear at the call
                            // site.
                            let entries = &mut (*state_ptr).entries;
                            if let Some(entry) = entries.get_mut(row) {
                                let now_enabled = new_check == LIST_CHECKED_STATE;
                                let new_disabled = !now_enabled;
                                if entry.disabled != new_disabled {
                                    entry.disabled = new_disabled;
                                    // Reach back into the main
                                    // window's state to push the
                                    // change through. We're on the
                                    // UI thread; the dialog blocks
                                    // the owner so no other code
                                    // is touching `Shell` right
                                    // now.
                                    if let Some(parent_state) =
                                        state_from_hwnd((*state_ptr).owner_hwnd)
                                    {
                                        parent_state
                                            .shell
                                            .set_plugin_disabled(entry.index, new_disabled);
                                    }
                                }
                            }
                        }
                    }
                }
                LRESULT(0)
            }
            WM_CLOSE => {
                let state_ptr =
                    GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const PluginAdminDialogState;
                if !state_ptr.is_null() {
                    let _ = EnableWindow((*state_ptr).owner_hwnd, true);
                }
                let _ = DestroyWindow(hwnd);
                LRESULT(0)
            }
            WM_NCDESTROY => {
                // Defensive: zero `GWLP_USERDATA` so any stray
                // message between `DestroyWindow` returning and
                // the modal pump's `IsWindow` break can't deref
                // a dangling pointer (matches the About dialog's
                // pattern).
                SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_ERASEBKGND => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, dialog_bg_brush());
                LRESULT(1)
            }
            WM_CTLCOLORSTATIC | WM_CTLCOLORBTN => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }));
    match result {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

/// Read the PE `VS_FIXEDFILEINFO` resource at `path` and format the
/// file version as `"X.Y.Z.W"` (or `"X.Y.Z"` when revision is 0,
/// `"X.Y"` when both build and revision are 0). Returns `None` for
/// any failure path ŌĆö a DLL without a version resource is the
/// common case for hand-rolled plugins, and the caller falls back
/// to "ŌĆö".
fn read_pe_file_version(path: &Path) -> Option<String> {
    let path_w: Vec<u16> = path
        .as_os_str()
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();
    let path_pcwstr = PCWSTR(path_w.as_ptr());
    // SAFETY: `path_w` is a NUL-terminated UTF-16 string; the
    // pointer is valid for the duration of the call.
    let size = unsafe { GetFileVersionInfoSizeW(path_pcwstr, None) };
    if size == 0 {
        return None;
    }
    // Cap the allocation. `GetFileVersionInfoSizeW` returns the
    // size of the resource block as the DLL's PE header reports
    // it; a maliciously-crafted DLL placed in the plugins
    // directory could specify a multi-MB block to wedge the UI
    // thread into a giant allocation at dialog open. 4 MiB is
    // more than two orders of magnitude above any real-world
    // version block (typical: 1-2 KiB) and well below any
    // memory-pressure threshold.
    const MAX_VERSION_INFO_BYTES: u32 = 4 * 1024 * 1024;
    if size > MAX_VERSION_INFO_BYTES {
        return None;
    }
    let mut buf: Vec<u8> = vec![0; size as usize];
    // SAFETY: `path_w` outlives the call; `buf` has `size` bytes
    // of writable space.
    let ok =
        unsafe { GetFileVersionInfoW(path_pcwstr, None, size, buf.as_mut_ptr().cast::<c_void>()) };
    if ok.is_err() {
        return None;
    }
    let mut info_ptr: *mut c_void = core::ptr::null_mut();
    let mut info_len: u32 = 0;
    let root_query: Vec<u16> = "\\".encode_utf16().chain(std::iter::once(0)).collect();
    // SAFETY: `buf` is alive; `info_ptr`/`info_len` are out-params.
    let ok = unsafe {
        VerQueryValueW(
            buf.as_ptr().cast::<c_void>(),
            PCWSTR(root_query.as_ptr()),
            &raw mut info_ptr,
            &raw mut info_len,
        )
    };
    if !ok.as_bool()
        || info_ptr.is_null()
        || (info_len as usize) < std::mem::size_of::<VS_FIXEDFILEINFO>()
    {
        return None;
    }
    // SAFETY: `info_ptr` points inside `buf`; the pointed-to
    // `VS_FIXEDFILEINFO` is a `#[repr(C)]` POD struct that
    // `VerQueryValueW` filled in.
    let info = unsafe { *(info_ptr as *const VS_FIXEDFILEINFO) };
    // `dwSignature` is the canonical magic 0xFEEF04BD on every
    // valid `VS_FIXEDFILEINFO`. A malformed or zero-padded
    // resource block can pass the byte-length check above with a
    // garbage signature, in which case the version fields are
    // undefined ŌĆö surface as `None` so the UI shows "ŌĆö" rather
    // than an arbitrary number.
    if info.dwSignature != 0xFEEF_04BD {
        return None;
    }
    let major = (info.dwFileVersionMS >> 16) & 0xFFFF;
    let minor = info.dwFileVersionMS & 0xFFFF;
    let build = (info.dwFileVersionLS >> 16) & 0xFFFF;
    let rev = info.dwFileVersionLS & 0xFFFF;
    if rev != 0 {
        Some(format!("{major}.{minor}.{build}.{rev}"))
    } else if build != 0 {
        Some(format!("{major}.{minor}.{build}"))
    } else {
        Some(format!("{major}.{minor}"))
    }
}

/// Show the modal Plugin Manager dialog. Same scaffolding as the
/// other modal dialogs in this file ŌĆö `OwnerEnableGuard` +
/// `DlgDestroyGuard`, panic-catch `wnd_proc`, nested `GetMessageW`
/// pump with `IsDialogMessageW`. `main_hwnd` is the owner;
/// `Shell::installed_plugins` is consulted at open time for the
/// row data, and `Shell::set_plugin_disabled` is called as the
/// user toggles checkboxes.
fn show_plugin_admin_dialog(main_hwnd: HWND) {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();

    unsafe {
        let instance = match GetModuleHandleW(None) {
            Ok(h) => h,
            Err(_) => return,
        };

        REGISTERED.get_or_init(|| {
            let class = WNDCLASSEXW {
                cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
                style: CS_HREDRAW | CS_VREDRAW,
                lpfnWndProc: Some(plugin_admin_wnd_proc),
                hInstance: instance.into(),
                hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
                hbrBackground: dialog_bg_brush(),
                lpszClassName: PLUGIN_ADMIN_CLASS,
                ..Default::default()
            };
            let _ = RegisterClassExW(&raw const class);
        });

        // Snapshot the registry under a brief borrow on the main
        // window's state ŌĆö the `Vec` we get back is owned, so no
        // borrow lasts past this block.
        let entries: Vec<PluginAdminEntry> = if let Some(state) = state_from_hwnd(main_hwnd) {
            state.shell.installed_plugins()
        } else {
            return;
        };

        // --- Layout (CLIENT coordinates) --------------------------
        const CLIENT_W: i32 = 600;
        const CLIENT_H: i32 = 420;
        const PAD: i32 = 14;
        const TAB_Y: i32 = PAD;
        const TAB_H: i32 = 26;
        const LIST_Y: i32 = TAB_Y + TAB_H + 8;
        const LIST_H: i32 = CLIENT_H - LIST_Y - 88;
        const HINT_Y: i32 = LIST_Y + LIST_H + 8;
        const HINT_H: i32 = 32;
        const BTN_W: i32 = 96;
        const BTN_H: i32 = 28;
        const BTN_X: i32 = CLIENT_W - PAD - BTN_W;
        const BTN_Y: i32 = CLIENT_H - PAD - BTN_H;

        let mut window_rect = RECT {
            left: 0,
            top: 0,
            right: CLIENT_W,
            bottom: CLIENT_H,
        };
        let _ = AdjustWindowRectEx(
            &raw mut window_rect,
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            false,
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
        );
        let dlg_w = window_rect.right - window_rect.left;
        let dlg_h = window_rect.bottom - window_rect.top;

        let mut owner_rect = RECT::default();
        let _ = GetWindowRect(main_hwnd, &raw mut owner_rect);
        let owner_w = owner_rect.right - owner_rect.left;
        let owner_h = owner_rect.bottom - owner_rect.top;
        let dlg_x = owner_rect.left + (owner_w - dlg_w) / 2;
        let dlg_y = owner_rect.top + (owner_h - dlg_h) / 2;

        let mut state = Box::new(PluginAdminDialogState {
            entries,
            owner_hwnd: main_hwnd,
            list_hwnd: HWND::default(),
        });
        let state_ptr: *mut PluginAdminDialogState = &raw mut *state;

        let dlg = match CreateWindowExW(
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
            PLUGIN_ADMIN_CLASS,
            w!("Plugin Manager"),
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            dlg_x,
            dlg_y,
            dlg_w,
            dlg_h,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            Some(state_ptr.cast::<c_void>()),
        ) {
            Ok(h) => h,
            Err(_) => return,
        };
        let _dlg_guard = DlgDestroyGuard(dlg);

        // Tab control with a single "Installed" tab. Future tabs
        // (Updates, Available, Incompatible) slot in via additional
        // `TCM_INSERTITEMW` calls; the body shape doesn't change.
        let tab_ctrl = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_TABCONTROL,
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP,
            PAD,
            TAB_Y,
            CLIENT_W - 2 * PAD,
            TAB_H,
            Some(dlg),
            Some(HMENU(IDC_PLUGIN_ADMIN_TAB as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };
        // Add the "Installed" tab.
        let mut installed_label: Vec<u16> = "Installed"
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        let tab_item = TCITEMW {
            mask: TCIF_TEXT,
            pszText: PWSTR(installed_label.as_mut_ptr()),
            ..Default::default()
        };
        SendMessageW(
            tab_ctrl,
            TCM_INSERTITEMW,
            Some(WPARAM(0)),
            Some(LPARAM(&raw const tab_item as isize)),
        );

        // Listview filling the body. `LVS_EX_CHECKBOXES` puts a
        // checkbox before column 0, `LVS_EX_FULLROWSELECT` makes
        // the whole row clickable, `LVS_EX_DOUBLEBUFFER` removes
        // flicker on scroll.
        let list_hwnd = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_LISTVIEWW,
            PCWSTR::null(),
            WS_CHILD
                | WS_VISIBLE
                | WS_TABSTOP
                | style_bits((LVS_REPORT | LVS_SHOWSELALWAYS | LVS_SINGLESEL) as i32),
            PAD,
            LIST_Y,
            CLIENT_W - 2 * PAD,
            LIST_H,
            Some(dlg),
            Some(HMENU(IDC_PLUGIN_ADMIN_LIST as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };
        SendMessageW(
            list_hwnd,
            LVM_SETEXTENDEDLISTVIEWSTYLE,
            Some(WPARAM(0)),
            Some(LPARAM(
                (LVS_EX_CHECKBOXES | LVS_EX_FULLROWSELECT | LVS_EX_DOUBLEBUFFER) as isize,
            )),
        );

        // Two columns: "Plugin" (with implicit checkbox before it
        // via `LVS_EX_CHECKBOXES`) and "Version".
        let columns: [(&str, i32); 2] = [("Plugin", 380), ("Version", 160)];
        for (i, (title, width)) in columns.iter().enumerate() {
            let mut text: Vec<u16> = title.encode_utf16().chain(std::iter::once(0)).collect();
            let col = LVCOLUMNW {
                mask: LVCF_FMT | LVCF_TEXT | LVCF_WIDTH,
                fmt: LVCFMT_LEFT,
                cx: *width,
                pszText: PWSTR(text.as_mut_ptr()),
                ..Default::default()
            };
            SendMessageW(
                list_hwnd,
                LVM_INSERTCOLUMNW,
                Some(WPARAM(i)),
                Some(LPARAM(&raw const col as isize)),
            );
        }

        // Populate one row per plugin. The state-image set
        // (`LVM_SETITEMSTATE` with `LVIF_STATE` + `LIST_CHECKED_STATE`/
        // `LIST_UNCHECKED_STATE`) seeds the checkbox; the LVN_ITEMCHANGED
        // arm filters on `old_check == 0` to suppress reacting to
        // these populate-time sets.
        for (row, entry) in state.entries.iter().enumerate() {
            let mut name_w: Vec<u16> = entry
                .display_label
                .encode_utf16()
                .chain(std::iter::once(0))
                .collect();
            let item = LVITEMW {
                mask: LVIF_TEXT,
                iItem: row as i32,
                iSubItem: 0,
                pszText: PWSTR(name_w.as_mut_ptr()),
                ..Default::default()
            };
            SendMessageW(
                list_hwnd,
                LVM_INSERTITEMW,
                Some(WPARAM(0)),
                Some(LPARAM(&raw const item as isize)),
            );
            // Subitem 1: version. Read once per row; an empty
            // `read_pe_file_version` result renders as an em-dash
            // so the column still reads cleanly.
            let version = read_pe_file_version(&entry.path).unwrap_or_else(|| "ŌĆö".to_string());
            let mut version_w: Vec<u16> =
                version.encode_utf16().chain(std::iter::once(0)).collect();
            let sub = LVITEMW {
                iSubItem: 1,
                pszText: PWSTR(version_w.as_mut_ptr()),
                ..Default::default()
            };
            SendMessageW(
                list_hwnd,
                LVM_SETITEMTEXTW,
                Some(WPARAM(row)),
                Some(LPARAM(&raw const sub as isize)),
            );
            // Seed the checkbox: enabled = !disabled.
            let check_state = if entry.disabled {
                LIST_UNCHECKED_STATE
            } else {
                LIST_CHECKED_STATE
            };
            let state_item = LVITEMW {
                mask: LVIF_STATE,
                state: windows::Win32::UI::Controls::LIST_VIEW_ITEM_STATE_FLAGS(check_state),
                stateMask: LVIS_STATEIMAGEMASK,
                ..Default::default()
            };
            SendMessageW(
                list_hwnd,
                LVM_SETITEMSTATE,
                Some(WPARAM(row)),
                Some(LPARAM(&raw const state_item as isize)),
            );
        }

        // Hint static + Close button.
        let hint = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Tick to enable, untick to disable. Changes take effect on the next launch."),
            WS_CHILD | WS_VISIBLE,
            PAD,
            HINT_Y,
            CLIENT_W - 2 * PAD - BTN_W - 8,
            HINT_H,
            Some(dlg),
            Some(HMENU(IDC_PLUGIN_ADMIN_HINT as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };
        let close_btn = match CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Close"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            BTN_X,
            BTN_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_PLUGIN_ADMIN_CLOSE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        ) {
            Ok(h) => h,
            Err(_) => return,
        };

        // Apply the default GUI font to all text-bearing children.
        let font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);
        for child in [tab_ctrl, list_hwnd, hint, close_btn] {
            apply_dialog_font(child, font);
        }

        // Stash the listview HWND so the WM_NOTIFY arm can match
        // against it.
        state.list_hwnd = list_hwnd;

        // Modal pump.
        let _ = EnableWindow(main_hwnd, false);
        let _owner_guard = OwnerEnableGuard(main_hwnd);
        let _ = ShowWindow(dlg, SW_SHOW);
        let _ = SetFocus(Some(close_btn));

        let mut msg_buf = MSG::default();
        loop {
            if !IsWindow(Some(dlg)).as_bool() {
                break;
            }
            let ret = GetMessageW(&raw mut msg_buf, None, 0, 0);
            match ret.0 {
                0 => {
                    let _ = PostMessageW(None, WM_QUIT, msg_buf.wParam, msg_buf.lParam);
                    break;
                }
                -1 => break,
                _ => {
                    if !IsDialogMessageW(dlg, &raw const msg_buf).as_bool() {
                        let _ = TranslateMessage(&raw const msg_buf);
                        DispatchMessageW(&raw const msg_buf);
                    }
                }
            }
        }
    }
}

// --- "Go to..." modal dialog -----------------------------------------
//
// A small `WS_POPUP` + `WS_CAPTION` + `WS_SYSMENU` window with a
// Line/Offset radio toggle, three labeled boxes ("you are here / want
// to go to / can't go further than"), and OK/Cancel buttons. The
// editable middle box is the only place the user types; the other
// two are read-only edits whose values track the radio state.
//
// The pump is a nested `GetMessageW` loop that runs until the dialog
// HWND is destroyed (via OK/Cancel/X-button); `IsDialogMessageW` in
// the loop handles Tab/Enter/Esc/mnemonic semantics for free because
// the dialog has `WS_EX_CONTROLPARENT` and the controls have
// `WS_TABSTOP`.
//
// While the modal is up the owner is `EnableWindow(false)`'d so the
// user can't reach the main window's menu/accelerators; on destroy
// we re-enable (RAII) and SetFocus back to Scintilla.
//
// Result is plumbed back via a heap-allocated `GotoDialogState`
// whose pointer is stashed in the dialog HWND's `GWLP_USERDATA`.
// The outer caller reads `state.result` after the pump exits.

/// `EM_SETSEL` ŌĆö declared inline because windows-rs splits its
/// edit-control message constants across modules and reaching one
/// just for this single use is more import noise than the literal.
const EM_SETSEL: u32 = 0x00B1;

/// Which axis the dialog's "want to go to" value applies to.
/// Toggled by the radio pair.
#[derive(Clone, Copy, PartialEq, Eq)]
enum GotoMode {
    Line,
    Offset,
}

/// What the user picked. The caller decodes this and dispatches to
/// `SCI_GOTOLINE` or `SCI_GOTOPOS`.
enum GotoTarget {
    /// 1-based line number.
    Line(u32),
    /// 0-based byte offset.
    Offset(u32),
}

/// Heap-allocated dialog state. The `wnd_proc` reads/writes through
/// `GWLP_USERDATA`; the outer `show_goto_dialog` owns the
/// `Box<GotoDialogState>` and reads `result` after the modal pump
/// exits (the dialog window is already destroyed at that point so
/// no `wnd_proc` can race the read).
struct GotoDialogState {
    /// `Some(target)` iff the user clicked OK with valid input.
    /// Stays `None` on Cancel/Esc/X-button close.
    result: Option<GotoTarget>,
    /// Active mode. Mutated by the radio click handler.
    mode: GotoMode,
    /// 1-based current line in the active editor.
    current_line: u32,
    /// 1-based total line count.
    max_line: u32,
    /// 0-based current byte offset of the caret.
    current_offset: u32,
    /// 0-based document length in bytes.
    max_offset: u32,
    /// Control HWNDs, set by `show_goto_dialog` after the children
    /// are created; the `wnd_proc` reads them on radio click and
    /// IDOK to update the readonly boxes and parse the user's
    /// input.
    here_hwnd: HWND,
    target_hwnd: HWND,
    max_hwnd: HWND,
    /// Set to `true` once `show_goto_dialog` has populated the
    /// three control HWNDs above. The `wnd_proc` gates on this so a
    /// `WM_COMMAND` delivered between `WM_NCCREATE` and the end of
    /// child setup (e.g. via `SendMessage` from another thread, or
    /// a plugin synthesizing input) doesn't dereference null HWNDs.
    controls_ready: bool,
}

impl GotoDialogState {
    /// Current-axis "you are here" value.
    fn here_value(&self) -> u32 {
        match self.mode {
            GotoMode::Line => self.current_line,
            GotoMode::Offset => self.current_offset,
        }
    }
    /// Current-axis upper bound. `max_line` is clamped to at least 1
    /// so an empty buffer still presents a useful range.
    fn max_value(&self) -> u32 {
        match self.mode {
            GotoMode::Line => self.max_line.max(1),
            GotoMode::Offset => self.max_offset,
        }
    }
}

extern "system" fn goto_wnd_proc(hwnd: HWND, msg: u32, wparam: WPARAM, lparam: LPARAM) -> LRESULT {
    // The whole body runs under `catch_unwind` so a panic from
    // String::from_utf16_lossy / SetFocus / SendMessageW /
    // SetWindowTextW cannot unwind across this `extern "system"`
    // frame (UB at the FFI boundary). On a panic we fall back to
    // DefWindowProcW which is what every other branch already does
    // for unhandled msgs.
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_NCCREATE => {
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let state_ptr = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as i32;
                let notif = ((wparam.0 >> 16) & 0xFFFF) as u32;
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut GotoDialogState;
                // controls_ready guard: a stray WM_COMMAND between
                // WM_NCCREATE and child-setup completion would
                // otherwise dereference null HWNDs (set/focus on
                // null is silent but SetFocus(null) clears
                // foreground focus, an observable misbehaviour).
                let state = if !state_ptr.is_null() && (*state_ptr).controls_ready {
                    Some(&mut *state_ptr)
                } else {
                    None
                };
                if cmd == IDOK.0 {
                    if let Some(state) = state {
                        if let Some(n) = read_target_value(state.target_hwnd, state.max_value()) {
                            let target = match state.mode {
                                // Clamp Line to >= 1 so a stray "0"
                                // doesn't fall off the bottom of the
                                // 1-based axis.
                                GotoMode::Line => GotoTarget::Line(n.max(1)),
                                GotoMode::Offset => GotoTarget::Offset(n),
                            };
                            state.result = Some(target);
                            let _ = DestroyWindow(hwnd);
                        } else {
                            // Empty / unparseable input: leave the
                            // dialog open with the target field
                            // re-focused and selected so a retry is
                            // a single keystroke.
                            let _ = SetFocus(Some(state.target_hwnd));
                            SendMessageW(
                                state.target_hwnd,
                                EM_SETSEL,
                                Some(WPARAM(0)),
                                Some(LPARAM(-1)),
                            );
                        }
                    }
                    LRESULT(0)
                } else if cmd == IDCANCEL.0 {
                    let _ = DestroyWindow(hwnd);
                    LRESULT(0)
                } else if (cmd == i32::from(IDC_GOTO_RADIO_LINE)
                    || cmd == i32::from(IDC_GOTO_RADIO_OFFSET))
                    && notif == BN_CLICKED
                {
                    if let Some(state) = state {
                        let new_mode = if cmd == i32::from(IDC_GOTO_RADIO_LINE) {
                            GotoMode::Line
                        } else {
                            GotoMode::Offset
                        };
                        if state.mode != new_mode {
                            state.mode = new_mode;
                            populate_axis_boxes(state);
                            let _ = SetFocus(Some(state.target_hwnd));
                            SendMessageW(
                                state.target_hwnd,
                                EM_SETSEL,
                                Some(WPARAM(0)),
                                Some(LPARAM(-1)),
                            );
                        }
                    }
                    LRESULT(0)
                } else {
                    DefWindowProcW(hwnd, msg, wparam, lparam)
                }
            }
            WM_CLOSE => {
                let _ = DestroyWindow(hwnd);
                LRESULT(0)
            }
            // Win11 themed paint silently overrides our class
            // hbrBackground for WS_POPUP | WS_CAPTION dialogs ŌĆö
            // the default WM_ERASEBKGND fills with a themed
            // shade rather than honouring the brush. Painting
            // the client rect ourselves with `dialog_bg_brush`
            // and returning 1 (handled) defeats that override
            // so the dialog renders our chosen colour.
            WM_ERASEBKGND => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, dialog_bg_brush());
                LRESULT(1)
            }
            // STATIC + group-box BTN return NULL_BRUSH so the
            // hbrBackground (now reliably our colour thanks to
            // WM_ERASEBKGND above) shows through.
            WM_CTLCOLORSTATIC | WM_CTLCOLORBTN => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
            }
            WM_CTLCOLOREDIT => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetSysColorBrush(COLOR_WINDOW).0 as isize)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }));
    match result {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

/// Populate the three labeled boxes for the current `state.mode`.
/// Called on initial display and on every radio toggle so the
/// "You are here / want to go to / can't go further than" values
/// reflect the active axis. Pure text update ŌĆö focus and selection
/// are handled by the caller so this can run safely before
/// `ShowWindow`.
unsafe fn populate_axis_boxes(state: &GotoDialogState) {
    unsafe {
        let here = HSTRING::from(state.here_value().to_string());
        let max = HSTRING::from(state.max_value().to_string());
        let _ = SetWindowTextW(state.here_hwnd, &here);
        let _ = SetWindowTextW(state.max_hwnd, &max);
        // Seed the editable target with the current value so the
        // user has a concrete starting point in the active axis.
        let _ = SetWindowTextW(state.target_hwnd, &here);
    }
}

/// Read the editable target box and parse it as a `u32`. Returns
/// `None` only on empty/unparseable input; values above `max` are
/// clamped so the user always lands inside the document. Note that
/// 0 is a valid offset (start of file); the line-vs-offset floor
/// gating happens in the IDOK handler.
unsafe fn read_target_value(edit: HWND, max: u32) -> Option<u32> {
    let mut buf = [0u16; 32];
    let len = unsafe { GetWindowTextW(edit, &mut buf) };
    if len <= 0 {
        return None;
    }
    let text = String::from_utf16_lossy(&buf[..len as usize]);
    let n = text.trim().parse::<u32>().ok()?;
    Some(n.min(max))
}

/// Disable visual styles on `hwnd` so it falls back to classic
/// (Win95-era) painting. Used for `BS_AUTOCHECKBOX`,
/// `BS_AUTORADIOBUTTON`, and `BS_GROUPBOX` whose themed paint
/// produces a slightly-darker rectangle around the control that
/// doesn't match the dialog's `hbrBackground`. Classic-painted
/// buttons honour `WM_CTLCOLORBTN`'s `NULL_BRUSH` return and let
/// the dialog's actual background show through, giving a clean
/// flush look. Visual style on push buttons (Find Next, Close,
/// etc.) is left intact so they keep their rounded Win11 look.
pub(crate) unsafe fn disable_visual_style(hwnd: HWND) {
    unsafe {
        let _ = SetWindowTheme(hwnd, w!(""), w!(""));
    }
}

/// Apply the system default GUI font to a freshly-created child
/// control. Without this Win32 falls back to the bitmap "System"
/// font from the Win95 era, which looks broken on every modern DPI.
pub(crate) unsafe fn apply_dialog_font(child: HWND, font: HFONT) {
    unsafe {
        SendMessageW(
            child,
            WM_SETFONT,
            Some(WPARAM(font.0 as usize)),
            Some(LPARAM(1)),
        );
    }
}

/// Show the modal "Go to..." dialog and return the user's choice,
/// or `None` on Cancel. `current_line` / `max_line` are 1-based;
/// `current_offset` / `max_offset` are 0-based byte counts.
///
/// Must be called from the UI thread that owns `owner`.
fn show_goto_dialog(
    owner: HWND,
    current_line: u32,
    max_line: u32,
    current_offset: u32,
    max_offset: u32,
) -> Option<GotoTarget> {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();

    unsafe {
        let instance = GetModuleHandleW(None).ok()?;

        REGISTERED.get_or_init(|| {
            let class = WNDCLASSEXW {
                cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
                style: CS_HREDRAW | CS_VREDRAW,
                lpfnWndProc: Some(goto_wnd_proc),
                hInstance: instance.into(),
                hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
                // Custom-RGB brush so the dialog background
                // matches the tone Win11 themed checkboxes /
                // radios / push buttons paint as their
                // background. COLOR_3DFACE reads as a touch
                // darker than that on Win11 themed mode and
                // produces a visible mismatch.
                hbrBackground: dialog_bg_brush(),
                lpszClassName: GOTO_CLASS,
                ..Default::default()
            };
            let _ = RegisterClassExW(&raw const class);
        });

        // Heap-allocate the state so the wnd_proc can mutate it
        // and we can read `result` after DestroyWindow. The raw
        // pointer below remains valid for the lifetime of `state`
        // because the local binding is never moved (`state` is
        // the sole owner; the `Box` stays in this stack frame
        // until the function returns).
        let mut state = Box::new(GotoDialogState {
            result: None,
            mode: GotoMode::Line,
            current_line,
            max_line,
            current_offset,
            max_offset,
            here_hwnd: HWND::default(),
            target_hwnd: HWND::default(),
            max_hwnd: HWND::default(),
            controls_ready: false,
        });
        let state_ptr: *mut GotoDialogState = &raw mut *state;

        // Layout is computed in CLIENT coordinates and the actual
        // window size is derived via AdjustWindowRectEx so the
        // border/title bar don't eat into the right padding the way
        // they would if we passed CLIENT_W as the window size.
        // Tightened against Notepad++'s reference proportions:
        // narrower dialog so the buttons sit close to the boxes,
        // shorter so there's only ~14 px of breathing room below
        // the bottom button.
        const CLIENT_W: i32 = 430;
        const CLIENT_H: i32 = 156;
        const X_PAD: i32 = 14;
        const LABEL_X: i32 = X_PAD;
        const LABEL_W: i32 = 155;
        const BOX_X: i32 = 175;
        const BOX_W: i32 = 80;
        const BTN_W: i32 = 130;
        const BTN_X: i32 = CLIENT_W - X_PAD - BTN_W;
        const BOX_H: i32 = 22;
        const LABEL_H: i32 = 20;
        const BTN_H: i32 = 26;
        const RADIO_Y: i32 = 12;
        const ROW1_Y: i32 = 44;
        const ROW2_Y: i32 = 74;
        const ROW3_Y: i32 = 104;

        let mut window_rect = RECT {
            left: 0,
            top: 0,
            right: CLIENT_W,
            bottom: CLIENT_H,
        };
        let _ = AdjustWindowRectEx(
            &raw mut window_rect,
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            false,
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
        );
        let dlg_w = window_rect.right - window_rect.left;
        let dlg_h = window_rect.bottom - window_rect.top;

        let mut owner_rect = RECT::default();
        let _ = GetWindowRect(owner, &raw mut owner_rect);
        let owner_w = owner_rect.right - owner_rect.left;
        let owner_h = owner_rect.bottom - owner_rect.top;
        let dlg_x = owner_rect.left + (owner_w - dlg_w) / 2;
        let dlg_y = owner_rect.top + (owner_h - dlg_h) / 2;

        let dlg = CreateWindowExW(
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
            GOTO_CLASS,
            w!("Go To..."),
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            dlg_x,
            dlg_y,
            dlg_w,
            dlg_h,
            Some(owner),
            None,
            Some(instance.into()),
            Some(state_ptr.cast::<c_void>()),
        )
        .ok()?;
        let _dlg_guard = DlgDestroyGuard(dlg);

        // Radio pair. WS_GROUP on the first scopes the auto-radio
        // group; the second is in the same group so picking one
        // unchecks the other automatically.
        let radio_line = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Line"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | WS_GROUP | style_bits(BS_AUTORADIOBUTTON),
            X_PAD,
            RADIO_Y,
            90,
            BOX_H,
            Some(dlg),
            Some(HMENU(IDC_GOTO_RADIO_LINE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let radio_offset = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Offset"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_AUTORADIOBUTTON),
            X_PAD + 140,
            RADIO_Y,
            90,
            BOX_H,
            Some(dlg),
            Some(HMENU(IDC_GOTO_RADIO_OFFSET as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // Row 1: "You are here:" + readonly box. No button.
        let label_here = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("You are here:"),
            WS_CHILD | WS_VISIBLE,
            LABEL_X,
            ROW1_Y + 2,
            LABEL_W,
            LABEL_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Readonly value: themed EDIT with ES_READONLY + the
        // sunken `WS_EX_CLIENTEDGE` border so the box is visibly
        // framed. Without the extended style the EDIT paints
        // borderless on Windows 11 and merges into the dialog
        // background. The greyish-fill problem stays handled by
        // WM_CTLCOLORSTATIC returning the dialog's COLOR_WINDOW
        // brush ŌĆö readonly EDITs send WM_CTLCOLORSTATIC, not
        // WM_CTLCOLOREDIT.
        let here = CreateWindowExW(
            WS_EX_CLIENTEDGE,
            w!("EDIT"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | style_bits(ES_READONLY | ES_AUTOHSCROLL),
            BOX_X,
            ROW1_Y,
            BOX_W,
            BOX_H,
            Some(dlg),
            Some(HMENU(IDC_GOTO_HERE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // Row 2: "You want to go to:" + editable box + "Go" button
        // (the dialog's IDOK).
        let label_target = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("You want to go to:"),
            WS_CHILD | WS_VISIBLE,
            LABEL_X,
            ROW2_Y + 2,
            LABEL_W,
            LABEL_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let target = CreateWindowExW(
            WS_EX_CLIENTEDGE,
            w!("EDIT"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(ES_NUMBER | ES_AUTOHSCROLL),
            BOX_X,
            ROW2_Y,
            BOX_W,
            BOX_H,
            Some(dlg),
            Some(HMENU(IDC_GOTO_TARGET as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Buttons are 4px taller than the boxes they sit beside,
        // so subtract `(BTN_H - BOX_H) / 2 = 2` from the row Y to
        // center the button vertically against its companion box.
        let ok_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Go"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            BTN_X,
            ROW2_Y - 2,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDOK.0 as u16 as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // Row 3: "You can't go further than:" + readonly box +
        // "I'm going nowhere" button (the dialog's IDCANCEL).
        let label_max = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("You can't go further than:"),
            WS_CHILD | WS_VISIBLE,
            LABEL_X,
            ROW3_Y + 2,
            LABEL_W,
            LABEL_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let max_box = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE,
            BOX_X,
            ROW3_Y + 2,
            BOX_W,
            LABEL_H,
            Some(dlg),
            Some(HMENU(IDC_GOTO_MAX as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let cancel = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("I'm going &nowhere"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            BTN_X,
            ROW3_Y - 2,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDCANCEL.0 as u16 as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        state.here_hwnd = here;
        state.target_hwnd = target;
        state.max_hwnd = max_box;
        // The wnd_proc gates WM_COMMAND on this flag ŌĆö flip it
        // only after the three HWNDs above are populated so a
        // stray pre-show message can't dereference null handles.
        state.controls_ready = true;

        let font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);
        for child in [
            radio_line,
            radio_offset,
            label_here,
            here,
            label_target,
            target,
            label_max,
            max_box,
            ok_btn,
            cancel,
        ] {
            apply_dialog_font(child, font);
        }

        // Initial mode = Line; check the corresponding radio and
        // populate the three boxes BEFORE the dialog is shown so
        // the first frame paints the correct values.
        SendMessageW(
            radio_line,
            BM_SETCHECK,
            Some(WPARAM(BST_CHECKED.0 as usize)),
            Some(LPARAM(0)),
        );
        populate_axis_boxes(&state);

        // Disable owner FIRST, then reveal the dialog and move
        // focus. Doing it in this order means the moment the
        // owner could see "I just lost focus" is also the moment
        // it's disabled, eliminating the brief window where input
        // could still reach the main window.
        let _ = EnableWindow(owner, false);
        let _owner_guard = OwnerEnableGuard(owner);
        let _ = ShowWindow(dlg, SW_SHOW);
        let _ = SetFocus(Some(target));
        SendMessageW(target, EM_SETSEL, Some(WPARAM(0)), Some(LPARAM(-1)));

        let mut msg = MSG::default();
        loop {
            if !IsWindow(Some(dlg)).as_bool() {
                break;
            }
            let ret = GetMessageW(&raw mut msg, None, 0, 0);
            match ret.0 {
                0 => {
                    let _ = PostMessageW(None, WM_QUIT, msg.wParam, msg.lParam);
                    break;
                }
                -1 => break,
                _ => {
                    if !IsDialogMessageW(dlg, &raw const msg).as_bool() {
                        let _ = TranslateMessage(&raw const msg);
                        DispatchMessageW(&raw const msg);
                    }
                }
            }
        }

        state.result.take()
    }
}

// --- Rename dialog ----------------------------------------------------------
//
// Modal text-input dialog used by File ŌåÆ Rename... to set the
// `Tab.custom_name` for an untitled buffer. Path-bound buffers
// route to the Save-As flow instead ŌĆö see the WM_COMMAND handler
// for `ID_FILE_RENAME` in `main_wnd_proc`.

/// State carried through the rename dialog's `wnd_proc` ŌĆö the
/// returned `result` is read after the message pump unwinds and
/// is `Some` only on a confirmed OK with non-empty text.
struct RenameDialogState {
    result: Option<String>,
    edit_hwnd: HWND,
    ok_hwnd: HWND,
    /// Disabled-while-modal owner. Stored on the state so the
    /// `wnd_proc` can `EnableWindow(owner, true)` *before* every
    /// `DestroyWindow` ŌĆö destroying the dialog while the owner is
    /// still disabled lets activation leak to the next window in
    /// z-order (often another app), so this re-enable is what
    /// keeps focus inside our process. Same pattern the About
    /// dialog uses (`AboutDialogState.owner_hwnd`).
    owner_hwnd: HWND,
    controls_ready: bool,
}

/// Re-enable the modal dialog's owner and tear down the dialog
/// window. Centralised so every `DestroyWindow` call site (IDOK
/// commit, IDCANCEL, `WM_CLOSE`) does both halves in the same order
/// ŌĆö re-enable first, then destroy ŌĆö without each branch
/// duplicating the comment + the `EnableWindow` call.
unsafe fn close_rename_dialog(hwnd: HWND, owner_hwnd: HWND) {
    unsafe {
        let _ = EnableWindow(owner_hwnd, true);
        let _ = DestroyWindow(hwnd);
    }
}

extern "system" fn rename_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    // Same `catch_unwind` pattern as `goto_wnd_proc`: a panic
    // crossing the `extern "system"` frame is UB, and
    // `String::from_utf16_lossy` / `SetWindowTextW` / `SetFocus`
    // can all panic on OOM. On panic we fall through to
    // `DefWindowProcW`, which keeps the dialog responsive enough
    // for the user to Cancel out.
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_NCCREATE => {
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let state_ptr = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as i32;
                let notif = ((wparam.0 >> 16) & 0xFFFF) as u32;
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut RenameDialogState;
                let state = if !state_ptr.is_null() && (*state_ptr).controls_ready {
                    Some(&mut *state_ptr)
                } else {
                    None
                };
                if cmd == IDOK.0 {
                    if let Some(state) = state {
                        if let Some(text) = read_rename_value(state.edit_hwnd) {
                            state.result = Some(text);
                            close_rename_dialog(hwnd, state.owner_hwnd);
                        } else {
                            // Empty ŌĆö re-focus the edit so a retry
                            // is one keystroke away. Should be
                            // unreachable because the OK button is
                            // disabled when the edit is empty, but
                            // defensive in case `IsDialogMessageW`
                            // funnels an Enter through some other
                            // path.
                            let _ = SetFocus(Some(state.edit_hwnd));
                        }
                    }
                    LRESULT(0)
                } else if cmd == IDCANCEL.0 {
                    if let Some(state) = state {
                        close_rename_dialog(hwnd, state.owner_hwnd);
                    } else {
                        // No state ŌĆö defensive fallback: best
                        // effort by reading owner via GetWindow.
                        let owner = windows::Win32::UI::WindowsAndMessaging::GetWindow(
                            hwnd,
                            windows::Win32::UI::WindowsAndMessaging::GW_OWNER,
                        )
                        .unwrap_or_default();
                        close_rename_dialog(hwnd, owner);
                    }
                    LRESULT(0)
                } else if cmd == i32::from(IDC_RENAME_EDIT)
                    && notif == windows::Win32::UI::WindowsAndMessaging::EN_CHANGE
                {
                    // Enable / disable the OK button as the edit
                    // gains or loses content. Per the user's
                    // sign-off, an empty rename is rejected ŌĆö OK
                    // stays greyed until a non-whitespace
                    // character is present.
                    if let Some(state) = state {
                        let has_text = read_rename_value(state.edit_hwnd).is_some();
                        let _ = EnableWindow(state.ok_hwnd, has_text);
                    }
                    LRESULT(0)
                } else {
                    DefWindowProcW(hwnd, msg, wparam, lparam)
                }
            }
            WM_CLOSE => {
                // Title-bar X / Alt-F4. Re-enable the owner before
                // destroying so activation returns to it instead
                // of leaking out of the app ŌĆö same fix as the
                // IDOK / IDCANCEL paths above.
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut RenameDialogState;
                let owner = if !state_ptr.is_null() && (*state_ptr).controls_ready {
                    (*state_ptr).owner_hwnd
                } else {
                    windows::Win32::UI::WindowsAndMessaging::GetWindow(
                        hwnd,
                        windows::Win32::UI::WindowsAndMessaging::GW_OWNER,
                    )
                    .unwrap_or_default()
                };
                close_rename_dialog(hwnd, owner);
                LRESULT(0)
            }
            // Same Win11 themed-paint workaround as `goto_wnd_proc`:
            // override `WM_ERASEBKGND` so the dialog body is our
            // `dialog_bg_brush` shade rather than whatever
            // UxTheme paints over the class brush.
            WM_ERASEBKGND => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, dialog_bg_brush());
                LRESULT(1)
            }
            WM_CTLCOLORSTATIC | WM_CTLCOLORBTN => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
            }
            WM_CTLCOLOREDIT => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetSysColorBrush(COLOR_WINDOW).0 as isize)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }));
    match result {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

/// Read the rename edit's text, trim whitespace, and return
/// `None` if the result is empty. The trim matches the
/// "OK is disabled while empty" UX ŌĆö a buffer of pure spaces is
/// treated as empty input rather than as a valid name.
unsafe fn read_rename_value(edit: HWND) -> Option<String> {
    // 256 UTF-16 units is plenty for a tab label ŌĆö well within
    // the `TAB_LABEL_MAX_TCHARS` cap downstream.
    let mut buf = [0u16; 256];
    let len = unsafe { GetWindowTextW(edit, &mut buf) };
    if len <= 0 {
        return None;
    }
    let text = String::from_utf16_lossy(&buf[..len as usize]);
    let trimmed = text.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed.to_string())
    }
}

/// Show the modal Rename dialog with `current_name` pre-filled and
/// selected. Returns the user's new name on OK, or `None` on
/// Cancel / window-close. Must be called from the UI thread that
/// owns `owner`.
fn show_rename_dialog(owner: HWND, current_name: &str) -> Option<String> {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();

    unsafe {
        let instance = GetModuleHandleW(None).ok()?;

        REGISTERED.get_or_init(|| {
            let class = WNDCLASSEXW {
                cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
                style: CS_HREDRAW | CS_VREDRAW,
                lpfnWndProc: Some(rename_wnd_proc),
                hInstance: instance.into(),
                hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
                hbrBackground: dialog_bg_brush(),
                lpszClassName: RENAME_CLASS,
                ..Default::default()
            };
            let _ = RegisterClassExW(&raw const class);
        });

        let mut state = Box::new(RenameDialogState {
            result: None,
            edit_hwnd: HWND::default(),
            ok_hwnd: HWND::default(),
            owner_hwnd: owner,
            controls_ready: false,
        });
        let state_ptr: *mut RenameDialogState = &raw mut *state;

        // Layout: tighter than the Goto dialog because the rename
        // dialog has only three controls (label, edit, two
        // buttons). Same coordinate convention ŌĆö CLIENT
        // dimensions, then `AdjustWindowRectEx` to the window
        // size so the chrome doesn't eat into the right padding.
        const CLIENT_W: i32 = 380;
        const CLIENT_H: i32 = 120;
        const X_PAD: i32 = 14;
        const LABEL_Y: i32 = 12;
        const EDIT_Y: i32 = 36;
        const BTN_Y: i32 = 78;
        const LABEL_W: i32 = CLIENT_W - 2 * X_PAD;
        const LABEL_H: i32 = 18;
        const EDIT_W: i32 = CLIENT_W - 2 * X_PAD;
        const EDIT_H: i32 = 24;
        const BTN_W: i32 = 90;
        const BTN_H: i32 = 26;
        const OK_X: i32 = CLIENT_W - X_PAD - BTN_W * 2 - 8;
        const CANCEL_X: i32 = CLIENT_W - X_PAD - BTN_W;

        let mut window_rect = RECT {
            left: 0,
            top: 0,
            right: CLIENT_W,
            bottom: CLIENT_H,
        };
        let _ = AdjustWindowRectEx(
            &raw mut window_rect,
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            false,
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
        );
        let dlg_w = window_rect.right - window_rect.left;
        let dlg_h = window_rect.bottom - window_rect.top;

        let mut owner_rect = RECT::default();
        let _ = GetWindowRect(owner, &raw mut owner_rect);
        let owner_w = owner_rect.right - owner_rect.left;
        let owner_h = owner_rect.bottom - owner_rect.top;
        let dlg_x = owner_rect.left + (owner_w - dlg_w) / 2;
        let dlg_y = owner_rect.top + (owner_h - dlg_h) / 2;

        let dlg = CreateWindowExW(
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
            RENAME_CLASS,
            w!("Rename"),
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            dlg_x,
            dlg_y,
            dlg_w,
            dlg_h,
            Some(owner),
            None,
            Some(instance.into()),
            Some(state_ptr.cast::<c_void>()),
        )
        .ok()?;
        let _dlg_guard = DlgDestroyGuard(dlg);

        let label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("&New name:"),
            WS_CHILD | WS_VISIBLE,
            X_PAD,
            LABEL_Y,
            LABEL_W,
            LABEL_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let edit = CreateWindowExW(
            WS_EX_CLIENTEDGE,
            w!("EDIT"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(ES_AUTOHSCROLL),
            X_PAD,
            EDIT_Y,
            EDIT_W,
            EDIT_H,
            Some(dlg),
            Some(HMENU(IDC_RENAME_EDIT as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let ok_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&OK"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            OK_X,
            BTN_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDOK.0 as u16 as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let cancel_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Cancel"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            CANCEL_X,
            BTN_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDCANCEL.0 as u16 as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        state.edit_hwnd = edit;
        state.ok_hwnd = ok_btn;
        state.controls_ready = true;

        // Cap the EDIT control's character buffer at the same size
        // `read_rename_value` truncates at (255 + a NUL slot in
        // `GetWindowTextW`'s 256-unit buffer). Without this Win32
        // EDITs default to a 30k / 64k char limit; a long paste
        // would balloon the control's internal buffer for text
        // we'd silently discard at read time. `EM_SETLIMITTEXT`
        // makes the dialog reject keystrokes/pastes past 255
        // up front so the input UX matches what we'll store.
        SendMessageW(
            edit,
            windows::Win32::UI::Controls::EM_SETLIMITTEXT,
            Some(WPARAM(255)),
            Some(LPARAM(0)),
        );

        let font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);
        for child in [label, edit, ok_btn, cancel_btn] {
            apply_dialog_font(child, font);
        }

        // Pre-fill the edit with the current display name and
        // select all so the user's first keystroke replaces it.
        // OK starts disabled iff the prefill is empty (defensive
        // ŌĆö `tab_display_name` always returns a non-empty string,
        // but a future change there shouldn't quietly regress
        // this UX).
        let prefill = HSTRING::from(current_name);
        let _ = SetWindowTextW(edit, &prefill);
        let _ = EnableWindow(ok_btn, !current_name.trim().is_empty());

        let _ = EnableWindow(owner, false);
        let _owner_guard = OwnerEnableGuard(owner);
        let _ = ShowWindow(dlg, SW_SHOW);
        let _ = SetFocus(Some(edit));
        SendMessageW(edit, EM_SETSEL, Some(WPARAM(0)), Some(LPARAM(-1)));

        let mut msg = MSG::default();
        loop {
            if !IsWindow(Some(dlg)).as_bool() {
                break;
            }
            let ret = GetMessageW(&raw mut msg, None, 0, 0);
            match ret.0 {
                0 => {
                    let _ = PostMessageW(None, WM_QUIT, msg.wParam, msg.lParam);
                    break;
                }
                -1 => break,
                _ => {
                    if !IsDialogMessageW(dlg, &raw const msg).as_bool() {
                        let _ = TranslateMessage(&raw const msg);
                        DispatchMessageW(&raw const msg);
                    }
                }
            }
        }

        state.result.take()
    }
}

/// Lift a control-style bitmask (ES_*/BS_*) into the `WINDOW_STYLE`
/// newtype that windows-rs models WS_* flags with. The two are
/// bitwise-compatible by Win32 design, but Rust requires the type
/// match for `|` against `WS_CHILD` etc.
const fn style_bits(bits: i32) -> WINDOW_STYLE {
    WINDOW_STYLE(bits as u32)
}

/// Pack two `i32`s into a Win32 `LPARAM`-shaped `u32`: low word from
/// `lo`, high word from `hi`. Both inputs are clamped to `i16` range
/// (Win32's MAKELONG semantics treat each half as 16-bit). Used by
/// `TCM_SETPADDING` (LOWORD = horizontal padding, HIWORD = vertical
/// padding) and any other Win32 message that follows the same packed-
/// 16-bit convention.
const fn makelong(lo: i32, hi: i32) -> u32 {
    ((lo as u32) & 0xFFFF) | (((hi as u32) & 0xFFFF) << 16)
}

/// COLORREF used by the in-dialog elements that DO route
/// through our paint code (the `BS_GROUPBOX` title clear via
/// `WM_CTLCOLORBTN`, anything else that needs a fill). On
/// Win11 the actual rendered dialog client area is painted
/// by the theme service via DWM/UxTheme ŌĆö outside the
/// `WM_ERASEBKGND` message path entirely ŌĆö so our class
/// `hbrBackground` is silently overridden. Setting this
/// constant to the same shade Win11 paints (`#F9F9F9`)
/// makes the rectangles we DO control blend with the
/// system-painted dialog instead of standing out.
pub(crate) const DIALOG_BG: u32 = 0x00F9_F9F9;
/// COLORREF for the bottom status strip ŌĆö a step darker than
/// the dialog background so it still reads as a distinct band.
const STATUS_BG: u32 = 0x00E8_E8E8;
/// COLORREF for the 1-pixel delimiter strips around the editor
/// (top / bottom / left / right). Mid-gray that reads cleanly
/// against both the white Scintilla content and the lighter
/// status / tab chrome ŌĆö chosen to match the standard Win32
/// "edge" tone (`COLOR_3DSHADOW` adjacent) without the OS-theme
/// drift that comes with using `GetSysColor(COLOR_3DSHADOW)`
/// directly.
const EDITOR_BORDER: u32 = 0x00A0_A0A0;

/// Cached brush for the dialog background (Goto + Find/Replace
/// hbrBackground, plus `WM_CTLCOLORBTN`'s clear brush). Created
/// lazily once on first use; the leaked HBRUSH lives for the
/// app's lifetime, which is fine ŌĆö the alternative is owning
/// the brush in `WindowState` and threading it through every
/// dialog `wnd_proc`.
pub(crate) fn dialog_bg_brush() -> HBRUSH {
    use std::sync::OnceLock;
    static BRUSH: OnceLock<isize> = OnceLock::new();
    let raw = *BRUSH.get_or_init(|| unsafe { CreateSolidBrush(COLORREF(DIALOG_BG)).0 as isize });
    HBRUSH(raw as *mut c_void)
}

/// Cached brush for the 1-pixel delimiter strips around the
/// editor view. Used by `main_wnd_proc::WM_ERASEBKGND` to paint
/// the four-sided border that the [`EDITOR_BORDER_PX`] inset in
/// `layout_children` reveals around the Scintilla view. Same
/// leak-on-purpose lifetime as [`dialog_bg_brush`].
fn editor_border_brush() -> HBRUSH {
    use std::sync::OnceLock;
    static BRUSH: OnceLock<isize> = OnceLock::new();
    let raw =
        *BRUSH.get_or_init(|| unsafe { CreateSolidBrush(COLORREF(EDITOR_BORDER)).0 as isize });
    HBRUSH(raw as *mut c_void)
}

/// Compare a null-terminated wide string at `wide` against the
/// ASCII bytes of `expected`. Returns true iff the wide buffer
/// holds exactly those code units followed by a NUL terminator.
/// Bounded read at `WIDE_COMPARE_CAP` units so a malformed /
/// missing terminator can't run off the end of an arbitrary
/// pointer the OS hands us via `WM_SETTINGCHANGE.lparam`.
///
/// Used for the `WM_SETTINGCHANGE` ŌåÆ `NPPN_DARKMODECHANGED` route:
/// Windows posts the message with `lparam` pointing at a wide
/// setting key (e.g. `"ImmersiveColorSet"`) and we need to
/// match exactly without paying the cost of an allocation per
/// uninteresting setting flip.
///
/// # Safety
///
/// Caller must ensure either:
///   - `wide` is NULL (defensively handled ŌĆö returns false), OR
///   - `wide` is `u16`-aligned AND points at a sequence of
///     `u16` units, terminated by a NUL within
///     `WIDE_COMPARE_CAP` units of the start.
///
/// In particular `wide` must be `u16`-aligned (2-byte
/// alignment) ŌĆö `*wide.add(i)` is an aligned read. The
/// `wnd_proc` call site rejects mis-aligned pointers via
/// `lparam.0 % 2 != 0` before invoking. The OS itself only
/// produces aligned wide strings for `WM_SETTINGCHANGE`, so
/// the alignment guard exists only to harden against an
/// in-process plugin synthesising a misaligned
/// `SendMessage(WM_SETTINGCHANGE)` (DESIGN.md ┬¦6.5: in-process
/// plugin threat model).
const WIDE_COMPARE_CAP: usize = 64;
unsafe fn wide_string_equals(wide: *const u16, expected: &str) -> bool {
    if wide.is_null() {
        return false;
    }
    if !expected.is_ascii() {
        return false;
    }
    let expected_bytes = expected.as_bytes();
    if expected_bytes.len() >= WIDE_COMPARE_CAP {
        return false;
    }
    // SAFETY: caller's contract guarantees `wide` is u16-aligned
    // and the buffer is readable for up to WIDE_COMPARE_CAP
    // units. Loop indices are 0..expected_bytes.len() (< 64),
    // and the post-loop read at `expected_bytes.len()` is
    // also < WIDE_COMPARE_CAP ŌĆö every dereference is in-bounds.
    unsafe {
        for (i, &b) in expected_bytes.iter().enumerate() {
            let c = *wide.add(i);
            if c == 0 || c != u16::from(b) {
                return false;
            }
        }
        // The unit immediately after the expected bytes must
        // be the NUL terminator ŌĆö otherwise the wide string is
        // longer than `expected` and the match is a false
        // positive (e.g. `"ImmersiveColorSetX"` vs the target
        // `"ImmersiveColorSet"`). Index is at most
        // `WIDE_COMPARE_CAP - 1` since the length cap above
        // ensures `expected_bytes.len() < WIDE_COMPARE_CAP`.
        *wide.add(expected_bytes.len()) == 0
    }
}

/// Cached brush for the bottom status strip ŌĆö see
/// [`dialog_bg_brush`] for the lifetime rationale.
fn status_bg_brush() -> HBRUSH {
    use std::sync::OnceLock;
    static BRUSH: OnceLock<isize> = OnceLock::new();
    let raw = *BRUSH.get_or_init(|| unsafe { CreateSolidBrush(COLORREF(STATUS_BG)).0 as isize });
    HBRUSH(raw as *mut c_void)
}

/// RAII guard that re-enables `owner` on drop. `show_goto_dialog`
/// disables the owner before the modal pump and relies on the guard
/// to re-enable it on every exit path ŌĆö including a panic between
/// disable and the pump's natural exit. Without the guard a panic
/// there would soft-lock the main window forever.
pub(crate) struct OwnerEnableGuard(pub(crate) HWND);
impl Drop for OwnerEnableGuard {
    fn drop(&mut self) {
        unsafe {
            let _ = EnableWindow(self.0, true);
        }
    }
}

/// RAII guard that destroys a dialog HWND on drop if it's still
/// alive. Pairs with `OwnerEnableGuard` to make every exit path ŌĆö
/// `?` propagation, panic, `WM_QUIT` mid-pump, or `GetMessageW` error ŌĆö
/// correctly tear down both the dialog window and the disabled-owner
/// state. The `IsWindow` check covers the happy path where the user
/// already clicked OK/Cancel: the dialog is already destroyed and
/// `DestroyWindow` on a dead HWND is a silent error we don't care
/// about, but skipping it keeps the trace log clean.
pub(crate) struct DlgDestroyGuard(pub(crate) HWND);
impl Drop for DlgDestroyGuard {
    fn drop(&mut self) {
        unsafe {
            if IsWindow(Some(self.0)).as_bool() {
                let _ = DestroyWindow(self.0);
            }
        }
    }
}

/// RAII guard that calls `DeleteObject` on a wrapped GDI handle on
/// drop. Used by the About dialog to free its bold title font on
/// every exit path ŌĆö including the child-`CreateWindowExW` failure
/// returns between the dialog HWND being created and the post-pump
/// cleanup, which a manual `DeleteObject` at one site would miss.
/// The handle is `Copy`, so wrapping in the guard does not preclude
/// passing the same `HFONT` to `apply_dialog_font` for the title
/// STATIC.
struct GdiObjectGuard(HFONT);
impl Drop for GdiObjectGuard {
    fn drop(&mut self) {
        unsafe {
            if !self.0.is_invalid() {
                let _ = DeleteObject(self.0.into());
            }
        }
    }
}

// --- Find/Replace modeless dialog ------------------------------------
//
// A `WS_POPUP` + `WS_CAPTION` + `WS_SYSMENU` window with a tab
// control across the top (Find / Replace) and a shared body of
// edit fields, checkboxes, and a Search Mode radio group. Modeless:
// `Close` hides the dialog with ShowWindow(SW_HIDE) so the typed
// query, flag state, and active tab survive between sessions.
// First-time creation is lazy on the first Ctrl+F / Ctrl+H click.
//
// Modeless dialogs require the main message pump to call
// `IsDialogMessageW(dlg, &msg)` BEFORE TranslateAccelerator /
// DispatchMessage so Tab / Enter / Esc / mnemonic handling works.
// The pump in `Win32Ui::run` reads the dialog HWND off WindowState
// for that ŌĆö see `WindowState.find_replace_dlg`.

/// Active tab in the Find/Replace dialog.
#[derive(Clone, Copy, PartialEq, Eq)]
enum FindReplaceTab {
    Find,
    Replace,
    FindInFiles,
}

/// Heap-allocated dialog state. The `wnd_proc` reads/writes through
/// `GWLP_USERDATA`. Lifetime is tied to the dialog window ŌĆö when
/// the dialog is destroyed (on app shutdown), the `wnd_proc`'s
/// `WM_NCDESTROY` drops this Box.
struct FindReplaceState {
    /// HWND of the main host window ŌĆö needed so the `wnd_proc` can
    /// route Find Next / Replace / Replace All into the host's
    /// `Shell` (which lives in `WindowState` on the main HWND).
    main_hwnd: HWND,
    /// Currently active tab.
    tab: FindReplaceTab,
    /// All control HWNDs.
    tab_ctrl: HWND,
    find_label: HWND,
    find_edit: HWND,
    replace_label: HWND,
    replace_edit: HWND,
    backward_cb: HWND,
    whole_word_cb: HWND,
    match_case_cb: HWND,
    wrap_around_cb: HWND,
    mode_group: HWND,
    mode_normal_radio: HWND,
    mode_extended_radio: HWND,
    mode_regex_radio: HWND,
    dot_newline_cb: HWND,
    find_next_btn: HWND,
    count_btn: HWND,
    replace_btn: HWND,
    replace_all_btn: HWND,
    close_btn: HWND,
    in_selection_cb: HWND,
    /// FIF-tab-only controls (m4 step 4a). Layout mirrors N++:
    /// Filters and Directory comboboxes appear in the same column
    /// as Find what / Replace with on the rows below them; the two
    /// new checkboxes sit in a right-side column next to Match
    /// whole word / Match case; the two new buttons share the
    /// right action column with Find Next / Count / Replace.
    fif_filters_label: HWND,
    fif_filters_edit: HWND,
    fif_directory_label: HWND,
    fif_directory_edit: HWND,
    fif_browse_btn: HWND,
    fif_subfolders_cb: HWND,
    fif_hidden_folders_cb: HWND,
    fif_find_all_btn: HWND,
    fif_replace_in_files_btn: HWND,
    /// Bottom-of-dialog STATIC for transient feedback messages
    /// ŌĆö currently used by Count, Replace All, and the
    /// not-found message. The colour switches between blue
    /// (info) and red (error) based on `status_is_error`,
    /// applied in `WM_CTLCOLORSTATIC` when the requesting hwnd
    /// matches this label.
    status_label: HWND,
    /// `true` when the most recent message written to
    /// `status_label` is an error (paint red); `false` for
    /// informational messages (paint blue). Cleared on every
    /// dialog open.
    status_is_error: bool,
    /// Selection range captured the moment "In selection" was
    /// last toggled on. `None` when the box is unchecked. The
    /// `replace_all_in_range` returns an updated `end` after
    /// each Replace All so this stays in sync as text grows.
    in_selection_range: Option<(u64, u64)>,
    /// Set true once all HWNDs above are populated.
    controls_ready: bool,
}

extern "system" fn find_replace_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_NCCREATE => {
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let state_ptr = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, state_ptr);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as u16;
                let notif = ((wparam.0 >> 16) & 0xFFFF) as u32;
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut FindReplaceState;
                if state_ptr.is_null() || !(*state_ptr).controls_ready {
                    return DefWindowProcW(hwnd, msg, wparam, lparam);
                }
                let state = &mut *state_ptr;
                match cmd {
                    IDC_FR_FIND_NEXT => {
                        if notif == BN_CLICKED {
                            handle_find_next(state);
                        }
                        LRESULT(0)
                    }
                    IDC_FR_COUNT => {
                        if notif == BN_CLICKED {
                            handle_count(state);
                        }
                        LRESULT(0)
                    }
                    IDC_FR_REPLACE_BTN => {
                        if notif == BN_CLICKED {
                            handle_replace(state);
                        }
                        LRESULT(0)
                    }
                    IDC_FR_REPLACE_ALL => {
                        if notif == BN_CLICKED {
                            handle_replace_all(state);
                        }
                        LRESULT(0)
                    }
                    IDC_FR_FIF_FIND_ALL => {
                        if notif == BN_CLICKED {
                            handle_fif_find_all(hwnd, state);
                        }
                        LRESULT(0)
                    }
                    IDC_FR_FIF_BROWSE => {
                        if notif == BN_CLICKED {
                            handle_fif_browse(state);
                        }
                        LRESULT(0)
                    }
                    IDC_FR_FIF_REPLACE_IN_FILES => {
                        if notif == BN_CLICKED {
                            handle_fif_replace_in_files(hwnd, state);
                        }
                        LRESULT(0)
                    }
                    // "In selection" toggle: snapshot the editor's
                    // selection bounds when the user checks the
                    // box, clear the snapshot when they uncheck.
                    // Subsequent Find Next / Replace All calls
                    // honor the snapshot regardless of how the
                    // selection has since been mutated.
                    IDC_FR_IN_SELECTION => {
                        if notif == BN_CLICKED {
                            handle_in_selection_toggle(state);
                        }
                        LRESULT(0)
                    }
                    // The Close button AND Esc both land here:
                    // Esc ŌåÆ IsDialogMessageW translates it to a
                    // WM_COMMAND with id=IDCANCEL (=2). Aliasing
                    // the two ids gives us "Esc closes" for free.
                    IDC_FR_CLOSE | IDCANCEL_U16 => {
                        let _ = ShowWindow(hwnd, SW_HIDE);
                        if let Some(window_state) = state_from_hwnd(state.main_hwnd) {
                            let _ = SetFocus(Some(window_state.scintilla_hwnd));
                        }
                        LRESULT(0)
                    }
                    IDC_FR_MODE_REGEX | IDC_FR_MODE_NORMAL | IDC_FR_MODE_EXTENDED => {
                        if notif == BN_CLICKED {
                            // ". matches newline" is only meaningful
                            // in regex mode; grey/ungrey it as the
                            // user toggles the mode radios.
                            let regex_on = button_checked(state.mode_regex_radio);
                            let _ = EnableWindow(state.dot_newline_cb, regex_on);
                        }
                        LRESULT(0)
                    }
                    _ => DefWindowProcW(hwnd, msg, wparam, lparam),
                }
            }
            WM_NOTIFY => {
                let nmhdr = lparam.0 as *const NMHDR;
                if nmhdr.is_null() {
                    return DefWindowProcW(hwnd, msg, wparam, lparam);
                }
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut FindReplaceState;
                if state_ptr.is_null() || !(*state_ptr).controls_ready {
                    return DefWindowProcW(hwnd, msg, wparam, lparam);
                }
                let state = &mut *state_ptr;
                if (*nmhdr).hwndFrom == state.tab_ctrl && (*nmhdr).code == TCN_SELCHANGE {
                    let sel = SendMessageW(state.tab_ctrl, TCM_GETCURSEL, None, None).0;
                    let new_tab = match sel {
                        1 => FindReplaceTab::Replace,
                        2 => FindReplaceTab::FindInFiles,
                        _ => FindReplaceTab::Find,
                    };
                    if state.tab != new_tab {
                        state.tab = new_tab;
                        apply_tab_visibility(state);
                    }
                }
                LRESULT(0)
            }
            // IsDialogMessageW asks the dialog "which button is the
            // default?" via DM_GETDEFID when it sees a VK_RETURN.
            // The standard #32770 dialog class answers this; our
            // custom class has to do it explicitly. The default
            // depends on the active tab ŌĆö Enter on the FIF tab
            // should kick off Find All, not Find Next (which
            // doesn't have a target buffer). Returning the
            // matching id with the DC_HASDEFID magic in the high
            // word gives us "Enter triggers the right button"
            // without a special-case VK_RETURN handler.
            DM_GETDEFID => {
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const FindReplaceState;
                let id = if !state_ptr.is_null()
                    && (*state_ptr).controls_ready
                    && (*state_ptr).tab == FindReplaceTab::FindInFiles
                {
                    IDC_FR_FIF_FIND_ALL
                } else {
                    IDC_FR_FIND_NEXT
                };
                let val = (DC_HASDEFID << 16) | u32::from(id);
                LRESULT(val as isize)
            }
            // Themed STATIC and EDIT controls paint their own
            // background. Without these handlers the dialog shows
            // a slightly-darker grey rectangle behind every label,
            // checkbox, group box, and edit field. Returning the
            // dialog's COLOR_WINDOW brush + transparent text bk
            // mode makes the chrome render against the dialog's
            // own background colour. The status_label gets blue
            // text on top so Replace All's count message stands
            // out against the otherwise black-on-white chrome.
            // Win11 themed paint silently overrides our class
            // hbrBackground for WS_POPUP | WS_CAPTION dialogs ŌĆö
            // painting the client rect ourselves with
            // `dialog_bg_brush` defeats that so the dialog
            // renders our chosen colour, and the STATIC /
            // group-box paths below can rely on the
            // hbrBackground actually being what we set.
            WM_ERASEBKGND => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, dialog_bg_brush());
                LRESULT(1)
            }
            // STATIC controls return NULL_BRUSH so the dialog's
            // painted hbrBackground shows through them ŌĆö the
            // status_label is the exception (it gets an explicit
            // status-bg fill so it reads as a slightly-darker
            // strip with red/blue text for error/info).
            WM_CTLCOLORSTATIC => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                let from = HWND(lparam.0 as *mut c_void);
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *const FindReplaceState;
                if !state_ptr.is_null()
                    && (*state_ptr).controls_ready
                    && (*state_ptr).status_label == from
                {
                    // COLORREF is BGR-packed. RGB(0, 0, 255) =
                    // 0x00FF0000 (blue, info); RGB(220, 0, 0) =
                    // 0x000000DC (red, error).
                    let color = if (*state_ptr).status_is_error {
                        COLORREF(0x0000_00DC)
                    } else {
                        COLORREF(0x00FF_0000)
                    };
                    let _ = SetTextColor(hdc, color);
                    LRESULT(status_bg_brush().0 as isize)
                } else {
                    LRESULT(GetStockObject(NULL_BRUSH).0 as isize)
                }
            }
            // Only the theme-disabled BS_GROUPBOX (the "Search
            // Mode" frame) routes through this ŌĆö themed
            // checkboxes / radios paint themselves and ignore
            // the brush. Returning the dialog brush lets
            // classic groupbox paint clear the title rect so
            // the border line breaks at the title text.
            WM_CTLCOLORBTN => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkColor(hdc, COLORREF(DIALOG_BG));
                LRESULT(dialog_bg_brush().0 as isize)
            }
            // Editable EDITs and combobox dropdown lists keep
            // the standard white interior ŌĆö that's the modern
            // Win11 themed-control look the user expects.
            WM_CTLCOLOREDIT | WM_CTLCOLORLISTBOX => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let _ = SetBkMode(hdc, TRANSPARENT);
                LRESULT(GetSysColorBrush(COLOR_WINDOW).0 as isize)
            }
            WM_CLOSE => {
                // The 'X' on the title bar hides the dialog ŌĆö
                // Close button shares this behaviour via WM_COMMAND.
                let _ = ShowWindow(hwnd, SW_HIDE);
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut FindReplaceState;
                if !state_ptr.is_null() && (*state_ptr).controls_ready {
                    let state = &*state_ptr;
                    if let Some(window_state) = state_from_hwnd(state.main_hwnd) {
                        let _ = SetFocus(Some(window_state.scintilla_hwnd));
                    }
                }
                LRESULT(0)
            }
            WM_NCDESTROY => {
                // Reclaim the heap-allocated state. Only fires on
                // app shutdown ŌĆö the Close button hides, doesn't
                // destroy. Reading via GWLP_USERDATA + Box::from_raw
                // is safe here because no other code path can race
                // a destroyed window's userdata.
                let state_ptr = GetWindowLongPtrW(hwnd, GWLP_USERDATA) as *mut FindReplaceState;
                if !state_ptr.is_null() {
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
                    drop(Box::from_raw(state_ptr));
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }));
    match result {
        Ok(lr) => lr,
        Err(_) => unsafe { DefWindowProcW(hwnd, msg, wparam, lparam) },
    }
}

/// Select every character in a combobox's edit field. Comboboxes
/// don't respond to `EM_SETSEL` directly ŌĆö `CB_SETEDITSEL` is
/// Win32's combobox-specific equivalent. lparam packs (start, end)
/// as two i16 halves; `end = -1` means "end of text", giving the
/// canonical 0xFFFF0000 wire value.
unsafe fn combobox_select_all(combo: HWND) {
    unsafe {
        SendMessageW(
            combo,
            CB_SETEDITSEL,
            None,
            Some(LPARAM(0xFFFF_0000u32 as i32 as isize)),
        );
    }
}

/// Read a button's checked state. Wraps the `BM_GETCHECK` round-trip
/// so callers don't have to repeat the WPARAM/LPARAM dance.
unsafe fn button_checked(btn: HWND) -> bool {
    let r = unsafe { SendMessageW(btn, BM_GETCHECK, None, None).0 };
    r as u32 == BST_CHECKED.0
}

/// Read the current Find/Replace flag state from the checkboxes
/// and Search Mode radios into a `SearchFlags` bitmask.
unsafe fn find_replace_flags(state: &FindReplaceState) -> SearchFlags {
    let mut f = SearchFlags::NONE;
    unsafe {
        if button_checked(state.match_case_cb) {
            f = f.union(SearchFlags::MATCH_CASE);
        }
        if button_checked(state.whole_word_cb) {
            f = f.union(SearchFlags::WHOLE_WORD);
        }
        if button_checked(state.mode_regex_radio) {
            f = f.union(SearchFlags::REGEX);
        }
    }
    f
}

/// Refill a combobox's dropdown list from `items`, in order.
/// `CB_RESETCONTENT` clears any previous entries first so the
/// list reflects the current Shell history exactly. The edit
/// portion of the combobox is left alone ŌĆö only the dropdown
/// changes.
unsafe fn populate_combobox(combo: HWND, items: &[String]) {
    unsafe {
        SendMessageW(combo, CB_RESETCONTENT, None, None);
        for item in items {
            let item_w = HSTRING::from(item.as_str());
            SendMessageW(
                combo,
                CB_ADDSTRING,
                None,
                Some(LPARAM(item_w.as_ptr() as isize)),
            );
        }
    }
}

/// Refresh both Find what / Replace with dropdowns from the
/// shell's stored `find_history`. Called on every dialog open
/// so the dropdowns reflect changes since the last time.
///
/// # Safety
///
/// Caller must not hold any other live `&mut WindowState` borrow
/// at the call site ŌĆö this fn calls `state_from_hwnd` to read
/// the history off the shell, and a second concurrent borrow of
/// the same `WindowState` slot would alias `&mut`. The current
/// callers (`show_find_replace_dialog`, both reuse and create
/// paths) honour this; future callers must too.
unsafe fn refresh_history_dropdowns(state: &FindReplaceState) {
    let Some(window_state) = (unsafe { state_from_hwnd(state.main_hwnd) }) else {
        return;
    };
    unsafe {
        populate_combobox(state.find_edit, &window_state.shell.find_history.finds);
        populate_combobox(
            state.replace_edit,
            &window_state.shell.find_history.replaces,
        );
    }
}

/// If the active editor has a non-empty single-line selection,
/// drop it into the dialog's "Find what" edit (overwriting any
/// previous query) and select-all the field so a typed character
/// replaces it. Multi-line selections are skipped ŌĆö the user
/// almost certainly didn't mean to search for a block of text,
/// and a literal newline in the find box doesn't search well in
/// Normal mode anyway.
unsafe fn prefill_from_selection(state: &FindReplaceState) {
    let Some(window_state) = (unsafe { state_from_hwnd(state.main_hwnd) }) else {
        return;
    };
    let editor = window_state.editor;
    let sel_start = editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as usize;
    let sel_end = editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as usize;
    if sel_end <= sel_start {
        return;
    }
    let len = sel_end - sel_start;
    // Cap the prefill at 1 KiB ŌĆö anyone selecting more than that
    // didn't mean it for the find box.
    if len > 1024 {
        return;
    }
    let mut buf = vec![0u8; len + 1];
    let copied = editor
        .send(SCI_GETSELTEXT, 0, buf.as_mut_ptr() as isize)
        .max(0) as usize;
    let bytes = &buf[..copied.min(len)];
    if bytes.iter().any(|&b| b == b'\n' || b == b'\r') {
        return;
    }
    let text = match std::str::from_utf8(bytes) {
        Ok(s) => s.to_string(),
        Err(_) => return,
    };
    let text_w = HSTRING::from(text);
    unsafe {
        let _ = SetWindowTextW(state.find_edit, &text_w);
        combobox_select_all(state.find_edit);
    }
}

/// Read the visible text of an edit control. Returns an empty
/// string on failure / empty input. Sizes the buffer from the
/// edit's reported length so a multi-KB find query (e.g. a
/// long regex or pasted block) doesn't truncate silently ŌĆö
/// fixed-size buffers here are a real footgun because the user
/// would then run a search against phantom data.
unsafe fn read_edit_text(edit: HWND) -> String {
    let len = unsafe { GetWindowTextLengthW(edit) };
    if len <= 0 {
        return String::new();
    }
    // +1 for the trailing NUL that GetWindowTextW always writes.
    let mut buf = vec![0u16; len as usize + 1];
    let copied = unsafe { GetWindowTextW(edit, &mut buf) } as usize;
    String::from_utf16_lossy(&buf[..copied])
}

/// "Find Next" click handler. Honors the Backward direction
/// checkbox and Wrap around. On a wrap-around miss we now
/// capture the caret beforehand, move it via
/// `SCI_SETEMPTYSELECTION` (which doesn't scroll, unlike
/// `SCI_DOCUMENTSTART`/`END`), retry, and restore on a total
/// miss so the viewport never jumps to position 0. When "In
/// selection" is on we route through `find_*_in_range` against
/// the snapshotted bounds and skip the wrap step.
unsafe fn handle_find_next(state: &mut FindReplaceState) {
    unsafe {
        let query = read_edit_text(state.find_edit);
        if query.is_empty() {
            return;
        }
        let flags = find_replace_flags(state);
        let backward = button_checked(state.backward_cb);
        let wrap = button_checked(state.wrap_around_cb);
        let range = state.in_selection_range;

        // First pass ŌĆö search forward / backward from the caret
        // (or within the snapshotted range).
        let editor;
        let hit;
        let saved_anchor;
        let saved_caret;
        let doc_len;
        {
            let Some(window_state) = state_from_hwnd(state.main_hwnd) else {
                return;
            };
            editor = window_state.editor;
            saved_anchor = editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as usize;
            saved_caret = editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as usize;
            doc_len = editor.send(SCI_GETLENGTH, 0, 0).max(0) as usize;
            let (shell, mut ui) = window_state.split();
            hit = match (range, backward) {
                (Some((s, e)), false) => shell.find_next_in_range(&mut ui, &query, flags, s, e),
                (Some((s, e)), true) => shell.find_prev_in_range(&mut ui, &query, flags, s, e),
                (None, false) => shell.find_next(&mut ui, &query, flags),
                (None, true) => shell.find_prev(&mut ui, &query, flags),
            };
        }
        if hit.is_some() {
            clear_status(state);
            return;
        }

        // Hit the end without finding. With wrap on (and no
        // in-selection range), retry from the opposite end ŌĆö
        // but use SCI_SETEMPTYSELECTION (doesn't scroll) and
        // restore the caret on a total miss so the user's view
        // doesn't jump.
        let wrap_hit = if wrap && range.is_none() {
            let Some(window_state) = state_from_hwnd(state.main_hwnd) else {
                return;
            };
            let (_shell, mut ui) = window_state.split();
            if backward {
                editor.send(SCI_SETEMPTYSELECTION, doc_len, 0);
                ui.search_prev(&query, flags)
            } else {
                editor.send(SCI_SETEMPTYSELECTION, 0, 0);
                ui.search_next(&query, flags)
            }
        } else {
            None
        };
        if wrap_hit.is_some() {
            clear_status(state);
            return;
        }

        // Total miss ŌĆö restore the caret to where the user left
        // it (so the view doesn't snap to position 0) and write
        // the not-found message in red to the status line.
        if wrap && range.is_none() {
            editor.send(SCI_SETSELECTIONSTART, saved_anchor, 0);
            editor.send(SCI_SETSELECTIONEND, saved_caret, 0);
        }
        let scope = if range.is_some() {
            "selection"
        } else {
            "entire file"
        };
        let msg = format!("Find: Can't find the text \"{query}\" in {scope}");
        set_error_status(state, &msg);
    }
}

/// Write `msg` to the status STATIC and flag it as informational
/// (blue). Clears the error flag so a previous red message
/// doesn't leak into a new info display.
unsafe fn set_info_status(state: &mut FindReplaceState, msg: &str) {
    state.status_is_error = false;
    unsafe {
        let _ = SetWindowTextW(state.status_label, &HSTRING::from(msg));
    }
}

/// Same shape as [`set_info_status`] but flags the message as
/// an error so the `WM_CTLCOLORSTATIC` handler paints it red.
unsafe fn set_error_status(state: &mut FindReplaceState, msg: &str) {
    state.status_is_error = true;
    unsafe {
        let _ = SetWindowTextW(state.status_label, &HSTRING::from(msg));
    }
}

/// Clear the status STATIC and reset the colour flag. Called
/// on every successful Find Next / Replace so the previous
/// not-found / Replace All message doesn't linger past its
/// usefulness.
unsafe fn clear_status(state: &mut FindReplaceState) {
    state.status_is_error = false;
    unsafe {
        let _ = SetWindowTextW(state.status_label, w!(""));
    }
}

/// "Count" click handler ŌĆö counts every match in the active
/// buffer (Count is always whole-buffer in N++ even when "In
/// selection" is on; we mirror that) and writes the result to
/// the dialog's blue status line.
unsafe fn handle_count(state: &mut FindReplaceState) {
    unsafe {
        let query = read_edit_text(state.find_edit);
        if query.is_empty() {
            clear_status(state);
            return;
        }
        let flags = find_replace_flags(state);
        let count = {
            let Some(window_state) = state_from_hwnd(state.main_hwnd) else {
                return;
            };
            let (shell, mut ui) = window_state.split();
            shell.count_matches(&mut ui, &query, flags)
        };
        let msg = format!(
            "Count: {} match{} in entire file",
            count,
            if count == 1 { "" } else { "es" },
        );
        set_info_status(state, &msg);
    }
}

/// "In selection" checkbox click handler. On check, snapshot the
/// editor's current selection bounds; on uncheck, clear. When
/// the box is checked but no selection exists, clear the box
/// (visual feedback that there's nothing to confine to).
unsafe fn handle_in_selection_toggle(state: &mut FindReplaceState) {
    unsafe {
        if !button_checked(state.in_selection_cb) {
            state.in_selection_range = None;
            return;
        }
        let Some(window_state) = state_from_hwnd(state.main_hwnd) else {
            return;
        };
        let editor = window_state.editor;
        let s = editor.send(SCI_GETSELECTIONSTART, 0, 0).max(0) as u64;
        let e = editor.send(SCI_GETSELECTIONEND, 0, 0).max(0) as u64;
        if e > s {
            state.in_selection_range = Some((s, e));
        } else {
            // No selection ŌĆö un-check the box so the user sees
            // that "In selection" can't apply right now.
            SendMessageW(
                state.in_selection_cb,
                BM_SETCHECK,
                Some(WPARAM(BST_UNCHECKED.0 as usize)),
                None,
            );
            state.in_selection_range = None;
        }
    }
}

/// "Replace" click handler ŌĆö substitutes the current selection if
/// it matches the query, then advances to the next match.
unsafe fn handle_replace(state: &mut FindReplaceState) {
    unsafe {
        let query = read_edit_text(state.find_edit);
        if query.is_empty() {
            return;
        }
        let replacement = read_edit_text(state.replace_edit);
        let flags = find_replace_flags(state);

        {
            let Some(window_state) = state_from_hwnd(state.main_hwnd) else {
                return;
            };
            let (shell, mut ui) = window_state.split();
            let _ = shell.replace_current(&mut ui, &query, &replacement, flags);
        }
        // Always advance after a Replace click ŌĆö matches the
        // Notepad++ flow where Replace == "swap this match and
        // jump to the next one." The window_state borrow above
        // is dropped at the end of the inner scope; handle_find_next
        // re-acquires its own.
        handle_find_next(state);
    }
}

/// "Replace All" click handler ŌĆö replaces every occurrence in the
/// active buffer (or in the snapshotted "In selection" range) in
/// one undo group, then writes a count message to the status
/// STATIC at the bottom of the dialog (blue, painted by
/// `WM_CTLCOLORSTATIC`). When restricted to a range, the
/// `replace_all_in_range` returns the new end so we can keep
/// `state.in_selection_range` in sync as replacements grow or
/// shrink the affected window.
unsafe fn handle_replace_all(state: &mut FindReplaceState) {
    unsafe {
        let query = read_edit_text(state.find_edit);
        if query.is_empty() {
            return;
        }
        let replacement = read_edit_text(state.replace_edit);
        let flags = find_replace_flags(state);
        let range = state.in_selection_range;

        // Borrow the WindowState only for the operation itself,
        // then release it before mutating `state.in_selection_range`
        // ŌĆö keeps the in-flight WindowState borrow disjoint from
        // the dialog state mutation.
        let (count, refreshed_range) = {
            let Some(window_state) = state_from_hwnd(state.main_hwnd) else {
                return;
            };
            let (shell, mut ui) = window_state.split();
            match range {
                Some((s, e)) => {
                    let (n, new_end) =
                        shell.replace_all_in_range(&mut ui, &query, &replacement, flags, s, e);
                    (n, Some((s, new_end)))
                }
                None => (
                    shell.replace_all(&mut ui, &query, &replacement, flags),
                    None,
                ),
            }
        };
        if refreshed_range.is_some() {
            state.in_selection_range = refreshed_range;
        }
        let scope = if range.is_some() {
            "selection"
        } else {
            "entire file"
        };
        let msg = format!(
            "Replace All: {} occurrence{} {} replaced in {}",
            count,
            if count == 1 { "" } else { "s" },
            if count == 1 { "was" } else { "were" },
            scope,
        );
        set_info_status(state, &msg);
    }
}

/// Set the FIF tab's Directory and Filters comboboxes from a
/// plugin-supplied prefill. Used immediately after the FIF dialog
/// is shown via `NPPM_LAUNCHFINDINFILESDLG`. Empty fields on the
/// prefill are skipped so a partial pre-fill doesn't clobber user
/// state for the absent field.
/// Open (or refocus) the Find/Replace dialog on its
/// Find-in-Files tab and seed the Directory field with `dir`.
/// Shares the same show + prefill machinery the plugin
/// `NPPM_LAUNCHFINDINFILESDLG` path uses ŌĆö [`apply_fif_prefill`]
/// takes a [`codepp_shell::FifLaunchPrefill`], which is
/// constructed inline here for the "directory only" case.
///
/// # Safety
///
/// `main_hwnd` must be the main window on the UI thread. The
/// dialog pump entered by `show_find_replace_dialog` may re-enter
/// `main_wnd_proc`, so callers MUST NOT hold a `&mut WindowState`
/// borrow across the call ŌĆö same discipline every dialog-opening
/// helper uses.
unsafe fn open_fif_at_directory(main_hwnd: HWND, dir: &Path) {
    let existing = unsafe { state_from_hwnd(main_hwnd).and_then(|s| s.find_replace_dlg) };
    let Some(dlg) = show_find_replace_dialog(main_hwnd, existing, FindReplaceTab::FindInFiles)
    else {
        return;
    };
    if let Some(s) = unsafe { state_from_hwnd(main_hwnd) } {
        s.find_replace_dlg = Some(dlg);
    }
    let prefill = codepp_shell::FifLaunchPrefill {
        directory: Some(dir.to_path_buf()),
        filters: None,
    };
    unsafe { apply_fif_prefill(dlg, &prefill) };
}

unsafe fn apply_fif_prefill(dlg: HWND, prefill: &codepp_shell::FifLaunchPrefill) {
    unsafe {
        let state_ptr = GetWindowLongPtrW(dlg, GWLP_USERDATA) as *mut FindReplaceState;
        if state_ptr.is_null() || !(*state_ptr).controls_ready {
            return;
        }
        let state = &*state_ptr;
        if let Some(dir) = &prefill.directory {
            // `to_string_lossy()` makes the lossy decoding explicit;
            // `display().to_string()` is functionally identical but
            // hides the lossy step. The lossy path is unreachable in
            // practice ŌĆö the dispatcher already rejected
            // bad-surrogate inputs in `wide_ptr_to_string`.
            let mut buf: Vec<u16> = dir
                .as_path()
                .to_string_lossy()
                .encode_utf16()
                .chain(std::iter::once(0))
                .collect();
            let _ = SetWindowTextW(state.fif_directory_edit, PCWSTR(buf.as_mut_ptr()));
        }
        if let Some(filters) = &prefill.filters {
            let mut buf: Vec<u16> = filters.encode_utf16().chain(std::iter::once(0)).collect();
            let _ = SetWindowTextW(state.fif_filters_edit, PCWSTR(buf.as_mut_ptr()));
        }
    }
}

/// Frozen snapshot of the FIF tab's input controls. Captured once
/// before any modal pump (e.g. the Replace in Files `MessageBoxW`)
/// and reused for both the confirmation prompt and the orchestrator
/// request ŌĆö guarantees the user runs exactly the search they
/// confirmed, not whatever the controls said after the pump.
struct FifSnapshot {
    query: String,
    directory: String,
    /// Filters text as the user typed it. Whitespace-separated
    /// glob patterns (e.g. `*.cpp *.h`); empty / "*" / "*.*"
    /// means "all files". Parsed into includes by
    /// [`apply_filters_to_walk_opts`] when the request is built.
    filters: String,
    recurse: bool,
    match_case: bool,
    whole_word: bool,
    regex: bool,
    /// User opted into hidden directories via the FIF tab
    /// checkbox. Threaded through to [`FifWalkOpts::walk_hidden_dirs`].
    hidden_folders: bool,
    /// `Some(s)` ŌåÆ Replace in Files (`s` may be empty for "delete
    /// each match"); `None` ŌåÆ plain Find in Files.
    replacement: Option<String>,
}

/// Read every FIF-tab control into a snapshot. Validates the
/// required fields (query + directory) and surfaces an error on
/// the dialog status row. Returns `None` on validation failure or
/// any state-borrow problem.
unsafe fn snapshot_fif_dialog(
    state: &mut FindReplaceState,
    replacement: Option<String>,
) -> Option<FifSnapshot> {
    let query = unsafe { read_edit_text(state.find_edit) };
    if query.is_empty() {
        unsafe { set_error_status(state, "Query is empty") };
        return None;
    }
    let directory = unsafe { read_edit_text(state.fif_directory_edit) };
    if directory.is_empty() {
        unsafe { set_error_status(state, "Directory is empty") };
        return None;
    }
    let filters = unsafe { read_edit_text(state.fif_filters_edit) };
    Some(FifSnapshot {
        query,
        directory,
        filters,
        recurse: unsafe { button_checked(state.fif_subfolders_cb) },
        match_case: unsafe { button_checked(state.match_case_cb) },
        whole_word: unsafe { button_checked(state.whole_word_cb) },
        regex: unsafe { button_checked(state.mode_regex_radio) },
        hidden_folders: unsafe { button_checked(state.fif_hidden_folders_cb) },
        replacement,
    })
}

/// Parse the FIF tab's Filters text into globset patterns and
/// install them on `walk_opts.set_includes`. Empty filters and the
/// "match anything" sentinels (`*`, `*.*`) are no-ops; the walker
/// then searches every file under the root. Tokens are split on
/// whitespace; each token gets `**/` prepended unless it already
/// starts with `**/`, so a user's `*.rs` matches at any depth.
///
/// Returns [`FilterParseError::NegationUnsupported`] if the user
/// typed a `!`-prefixed token. We surface the limit instead of
/// silently dropping the user's intent (deferred to a later polish).
fn apply_filters_to_walk_opts(
    walk_opts: &mut codepp_core::FifWalkOpts,
    filters_text: &str,
) -> std::result::Result<(), FilterParseError> {
    let mut patterns: Vec<String> = Vec::new();
    for tok in filters_text.split_whitespace() {
        if tok == "*" || tok == "*.*" {
            continue;
        }
        if tok.starts_with('!') {
            return Err(FilterParseError::NegationUnsupported);
        }
        let p = if tok.starts_with("**/") {
            tok.to_string()
        } else {
            format!("**/{tok}")
        };
        patterns.push(p);
    }
    if patterns.is_empty() {
        return Ok(());
    }
    let refs: Vec<&str> = patterns.iter().map(String::as_str).collect();
    walk_opts
        .set_includes(&refs)
        .map_err(FilterParseError::Walk)
}

#[derive(Debug)]
enum FilterParseError {
    NegationUnsupported,
    Walk(codepp_core::FifWalkOptsError),
}

impl std::fmt::Display for FilterParseError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            FilterParseError::NegationUnsupported => f.write_str(
                "filters: '!' negation is not yet supported ŌĆö remove the negated tokens",
            ),
            FilterParseError::Walk(e) => write!(f, "{e}"),
        }
    }
}

/// "Find All" click handler on the FIF tab. Snapshots the dialog,
/// kicks off `Shell::start_fif`, and (on success) hides the dialog
/// and shows the modeless progress window.
unsafe fn handle_fif_find_all(dlg: HWND, state: &mut FindReplaceState) {
    let Some(snap) = (unsafe { snapshot_fif_dialog(state, None) }) else {
        return;
    };
    unsafe { start_fif_from_snapshot(dlg, state, snap) };
}

/// "Replace in Files" click handler on the FIF tab. Same flow as
/// Find All but routes a non-`None` replacement string into the
/// shell so each matched file is rewritten in place. Confirms via
/// `MessageBoxW` first because the operation is destructive ŌĆö and
/// snapshots all input controls BEFORE the modal pump so the
/// confirmation text and the actual job parameters cannot diverge
/// (the pump runs the dialog wndproc, which would otherwise let
/// the user edit the controls between Yes-click and orchestrator
/// dispatch).
unsafe fn handle_fif_replace_in_files(dlg: HWND, state: &mut FindReplaceState) {
    let replacement = unsafe { read_edit_text(state.replace_edit) };
    let Some(snap) = (unsafe { snapshot_fif_dialog(state, Some(replacement)) }) else {
        return;
    };
    let recurse_note = if snap.recurse {
        " (and sub-folders)"
    } else {
        ""
    };
    let replacement_for_prompt = snap.replacement.as_deref().unwrap_or("");
    let prompt = format!(
        "Replace every occurrence of\n\n  {}\n\nwith\n\n  {replacement_for_prompt}\n\nin\n\n  {}{recurse_note}\n\nThis modifies files on disk. Continue?",
        snap.query, snap.directory,
    );
    let mut prompt_w: Vec<u16> = prompt.encode_utf16().chain(std::iter::once(0)).collect();
    let mut title_w: Vec<u16> = "Replace in Files"
        .encode_utf16()
        .chain(std::iter::once(0))
        .collect();
    let result = unsafe {
        MessageBoxW(
            Some(state.main_hwnd),
            PCWSTR(prompt_w.as_mut_ptr()),
            PCWSTR(title_w.as_mut_ptr()),
            MB_YESNO | MB_ICONWARNING,
        )
    };
    if result != IDYES {
        return;
    }
    unsafe { start_fif_from_snapshot(dlg, state, snap) };
}

/// Apply the FIF replacement to every open tab whose path falls
/// under `root` and matches the include/exclude filter. Run before
/// the worker starts so the disk-side worker can keep its existing
/// "skip files open in a tab" behaviour: the in-buffer state is the
/// source of truth for an open file (unsaved edits, encoding, etc.),
/// so rewriting it to disk would clobber the user's working copy
/// and trigger the file watcher's "external change" dialog. After
/// this pass, those tabs carry the post-replacement text and the
/// user can save with Ctrl+S ŌĆö same flow as Notepad++.
///
/// Returns `(files_modified, total_replacements)`. `(0, 0)` if no
/// open tab is under `root`, if no match was found in any open
/// tab, or if `FifQuery::compile` fails (the worker will fail with
/// the same error a moment later, surfacing it through the dialog).
unsafe fn apply_fif_in_buffer_replace(
    state: &mut WindowState,
    root: &std::path::Path,
    walk_opts: &codepp_core::FifWalkOpts,
    query_string: &str,
    query_opts: codepp_core::FifQueryOpts,
    replacement: &str,
) -> (usize, usize) {
    let Ok(query) = codepp_core::FifQuery::compile(query_string, query_opts) else {
        return (0, 0);
    };
    let expand_groups = query_opts.regex;

    // Snapshot which tabs are candidates *before* we start sending
    // Scintilla messages. Without this, a SCN_MODIFIED notification
    // produced by SCI_REPLACETARGET could re-enter on this thread
    // and mutate `state.shell.tabs` mid-iteration.
    let candidates: Vec<isize> = state
        .shell
        .tabs
        .iter()
        .filter_map(|tab| {
            let path = tab.path.as_ref()?;
            // Worker pre-filter: under the requested root, then the
            // include/exclude glob set. Mirror the walker's order so
            // tabs match exactly the same set the worker would have.
            if !path.starts_with(root) {
                return None;
            }
            if !walk_opts.path_matches(path) {
                return None;
            }
            // A tab whose document was never materialized has no
            // in-memory buffer to rewrite. Should be impossible in
            // practice (every loaded tab gets activated at least
            // once, which calls SCI_CREATEDOCUMENT), but guard so a
            // future code path that defers materialization doesn't
            // silently corrupt by writing into doc 0.
            if tab.scintilla_doc == 0 {
                return None;
            }
            Some(tab.scintilla_doc)
        })
        .collect();

    if candidates.is_empty() {
        return (0, 0);
    }

    // Save the active doc pointer so we can restore it after the
    // doc-swap dance. Without this the user's active tab silently
    // changes to whichever candidate was visited last.
    let original_doc = state.editor.send(SCI_GETDOCPOINTER, 0, 0);

    // Suppress repaint while we cycle the bound document. Each
    // SCI_SETDOCPOINTER triggers a full editor repaint, which would
    // visibly flash the user's view across every candidate tab.
    // The guard restores redraw + InvalidateRect on Drop, so a panic
    // anywhere in the loop cannot leave the editor permanently
    // frozen. (Same RAII discipline as `PluginCallGuard` below.)
    let _redraw_guard = unsafe { ScintillaRedrawGuard::enter(state.scintilla_hwnd) };

    // SCI_REPLACETARGET fires SCN_MODIFIED via a synchronous
    // SendMessage(parent, WM_NOTIFY, ...). That re-enters
    // `main_wnd_proc` on this same thread, which would call
    // `state_from_hwnd` and materialize a second `&mut WindowState`
    // from the raw GWLP_USERDATA pointer ŌĆö aliased with our outer
    // `state: &mut WindowState`, which is undefined behaviour by
    // Rust's borrow rules. The plugin re-entrancy guard makes
    // `state_from_hwnd` return `None` while held, so the inner
    // wnd_proc handles the SCN_MODIFIED with no host borrow.
    // Drop happens on every exit path including panic, so a panic
    // mid-loop doesn't leave the flag wedged.
    let _call_guard = PluginCallGuard::enter();

    let mut files_modified = 0usize;
    let mut total_replacements = 0usize;

    for doc in &candidates {
        // Bind the candidate document to the single Scintilla view.
        // Direct-call: the function pointer on `editor` was captured
        // from this same view, so it operates on whichever document
        // is currently bound.
        state.editor.send(SCI_SETDOCPOINTER, 0, *doc);

        let old_len = state.editor.send(SCI_GETLENGTH, 0, 0).max(0) as usize;
        if old_len == 0 {
            continue;
        }
        // SCI_GETTEXT writes old_len + 1 bytes (null terminator).
        // Cap the buffer accordingly; the truncation below drops it.
        let cap = old_len + 1;
        let mut buf = vec![0u8; cap];
        let written = state
            .editor
            .send(SCI_GETTEXT, cap, buf.as_mut_ptr() as isize);
        if written <= 0 {
            continue;
        }
        buf.truncate(written as usize);
        // Scintilla's buffer is always UTF-8 in our app
        // (SCI_SETCODEPAGE = SC_CP_UTF8 by default; encoding
        // conversion happens at load/save in `core::file`, not
        // inside the buffer). `from_utf8` is therefore the
        // expected-success path; the lossy fallback is a defensive
        // measure for the rare case where the bytes are actually
        // invalid UTF-8 (e.g. a plugin wrote raw bytes via
        // SCI_INSERTTEXT and didn't translate first).
        let text = match String::from_utf8(buf) {
            Ok(s) => s,
            Err(e) => String::from_utf8_lossy(e.as_bytes()).into_owned(),
        };

        let (new_text, n_replaced) =
            codepp_core::fif::replace_in_text(&query, &text, replacement, expand_groups);

        if n_replaced == 0 {
            continue;
        }

        // Single undo group around the whole-buffer rewrite. Ctrl+Z
        // reverts every replacement at once (matches active-tab
        // Replace All semantics). `old_len` is the BYTE length of
        // the buffer before the rewrite ŌĆö that's what
        // SCI_SETTARGETEND wants (the end offset of the region to
        // replace), distinct from `new_text.len()` (the size of
        // what we're writing in).
        state.editor.send(SCI_BEGINUNDOACTION, 0, 0);
        state.editor.send(SCI_SETTARGETSTART, 0, 0);
        state.editor.send(SCI_SETTARGETEND, old_len, 0);
        // SCI_REPLACETARGET takes wparam = byte length, lparam =
        // pointer; embedded NULs survive (the call is
        // length-prefixed, not null-terminated).
        state.editor.send(
            SCI_REPLACETARGET,
            new_text.len(),
            new_text.as_ptr() as isize,
        );
        state.editor.send(SCI_ENDUNDOACTION, 0, 0);

        files_modified += 1;
        total_replacements += n_replaced;
    }

    // Restore the original document. Redraw is restored when
    // `_redraw_guard` drops at the end of this scope.
    state.editor.send(SCI_SETDOCPOINTER, 0, original_doc);

    (files_modified, total_replacements)
}

/// RAII pair around `WM_SETREDRAW(false)` / `WM_SETREDRAW(true) +
/// InvalidateRect`. Used to suppress flicker during a multi-step
/// editor mutation (FIF in-buffer replace cycles the bound
/// document for each candidate tab). Crucial property: Drop
/// **must** restore redraw on every exit including panic ŌĆö without
/// this discipline a panic mid-loop leaves the Scintilla view
/// permanently frozen, which is unrecoverable for the user.
struct ScintillaRedrawGuard {
    hwnd: HWND,
}

impl ScintillaRedrawGuard {
    /// SAFETY: `hwnd` must reference a live Scintilla view on this
    /// thread. The guard sends two `SendMessageW`s to it; sending
    /// to a destroyed HWND is undefined behaviour.
    unsafe fn enter(hwnd: HWND) -> Self {
        let _ = unsafe { SendMessageW(hwnd, WM_SETREDRAW, Some(WPARAM(0)), Some(LPARAM(0))) };
        Self { hwnd }
    }
}

impl Drop for ScintillaRedrawGuard {
    fn drop(&mut self) {
        // Best-effort restore ŌĆö these calls cannot fail in any
        // recoverable way, and we are deliberately ignoring the
        // results so panic-during-Drop is impossible (which would
        // double-panic the host).
        let _ = unsafe { SendMessageW(self.hwnd, WM_SETREDRAW, Some(WPARAM(1)), Some(LPARAM(0))) };
        let _ = unsafe { InvalidateRect(Some(self.hwnd), None, true) };
    }
}

/// Build a `FifRequest` from the captured snapshot, kick off
/// `Shell::start_fif`, hide the dialog, show the progress window,
/// and reset the dock state so the next set of results lands in a
/// clean listview.
unsafe fn start_fif_from_snapshot(dlg: HWND, state: &mut FindReplaceState, snap: FifSnapshot) {
    let mut walk_opts = codepp_core::FifWalkOpts::default();
    walk_opts.recurse = snap.recurse;
    walk_opts.walk_hidden_dirs = snap.hidden_folders;
    if let Err(e) = apply_filters_to_walk_opts(&mut walk_opts, &snap.filters) {
        unsafe { set_error_status(state, &format!("Find in Files: {e}")) };
        return;
    }

    let query_opts = codepp_core::FifQueryOpts {
        match_case: snap.match_case,
        whole_word: snap.whole_word,
        regex: snap.regex,
    };

    let main_hwnd = state.main_hwnd;
    let root = PathBuf::from(&snap.directory);

    // Replace-in-Files for files the user has open in a tab is
    // applied here, BEFORE the worker starts. The worker continues
    // to skip those paths on disk; the in-buffer pass is the source
    // of truth for an open file. See `apply_fif_in_buffer_replace`
    // for the rationale.
    let in_buffer_counts: Option<(usize, usize)> = snap.replacement.as_ref().and_then(|repl| {
        let win = (unsafe { state_from_hwnd(main_hwnd) })?;
        let counts = unsafe {
            apply_fif_in_buffer_replace(win, &root, &walk_opts, &snap.query, query_opts, repl)
        };
        if counts == (0, 0) {
            None
        } else {
            Some(counts)
        }
    });

    // Snapshot the currently-open tab paths so the orchestrator
    // can skip them in replace mode. Done in the same brief borrow
    // that calls `start_fif` ŌĆö the snapshot is consumed by the
    // worker pool, not retained on the shell.
    let job_raw = {
        let Some(win) = (unsafe { state_from_hwnd(main_hwnd) }) else {
            return;
        };
        let open_tab_paths: Vec<PathBuf> = win
            .shell
            .tabs
            .iter()
            .filter_map(|t| t.path.clone())
            .collect();
        let request = codepp_shell::FifRequest {
            query: snap.query.clone(),
            opts: query_opts,
            root,
            walk: walk_opts,
            replacement: snap.replacement,
            open_tab_paths,
        };
        match win.shell.start_fif(request) {
            Ok(id) => id.raw(),
            Err(e) => {
                // The in-buffer pass already committed replacements
                // to open tabs. Tell the user ŌĆö silent dirty buffers
                // would be confusing and could be saved over real
                // data on Ctrl+S without the user realizing why.
                let suffix = match in_buffer_counts {
                    Some((files, n)) => format!(
                        " ({n} replacement{} already applied to {files} open tab{})",
                        if n == 1 { "" } else { "s" },
                        if files == 1 { "" } else { "s" },
                    ),
                    None => String::new(),
                };
                unsafe { set_error_status(state, &format!("Find in Files: {e}{suffix}")) };
                return;
            }
        }
    };

    unsafe {
        // Hide the Find/Replace dialog while the search runs ŌĆö N++
        // does the same. Refocus is handled by the progress window.
        let _ = ShowWindow(dlg, SW_HIDE);
    }

    let progress = unsafe { show_fif_progress(main_hwnd, &snap.query) };

    // Re-borrow to install the progress HWND and active-job
    // tracking on the main window state. Clear pending caret
    // jumps too so a stale entry from a previous job doesn't
    // misroute the next dblclk on a same-named file.
    if let Some(win) = unsafe { state_from_hwnd(main_hwnd) } {
        win.fif_progress_hwnd = progress;
        win.fif_active_job = Some(job_raw);
        win.fif_pending_results.clear();
        win.fif_listview_index.clear();
        win.fif_pending_jumps.clear();
        win.fif_in_buffer_counts = in_buffer_counts;
        unsafe { fif_listview_clear(win.fif_listview_hwnd) };
    }
}

/// "Browse..." click handler on the FIF tab. Opens a folder picker
/// (`SHBrowseForFolderW`) and writes the chosen path into the
/// directory combobox edit field.
unsafe fn handle_fif_browse(state: &FindReplaceState) {
    use windows::Win32::System::Com::CoTaskMemFree;
    use windows::Win32::UI::Shell::{
        SHBrowseForFolderW, SHGetPathFromIDListW, BFFM_INITIALIZED, BIF_NEWDIALOGSTYLE,
        BIF_RETURNONLYFSDIRS, BROWSEINFOW,
    };

    // Seed the browser with whatever's currently in the directory
    // combobox so the picker opens at the user's last choice.
    let initial = unsafe { read_edit_text(state.fif_directory_edit) };
    let mut initial_w: Vec<u16> = initial.encode_utf16().chain(std::iter::once(0)).collect();

    // Custom callback to set the initial selection on
    // BFFM_INITIALIZED. Hands the picker the seeded path string as
    // an LPARAM. Ignored on first launch when `initial` is empty.
    extern "system" fn browse_cb(hwnd: HWND, msg: u32, _lparam: LPARAM, lp_data: LPARAM) -> i32 {
        if msg == BFFM_INITIALIZED && lp_data.0 != 0 {
            const BFFM_SETSELECTIONW: u32 = 0x466;
            unsafe {
                SendMessageW(hwnd, BFFM_SETSELECTIONW, Some(WPARAM(1)), Some(lp_data));
            }
        }
        0
    }

    let bi = BROWSEINFOW {
        hwndOwner: state.main_hwnd,
        ulFlags: BIF_RETURNONLYFSDIRS | BIF_NEWDIALOGSTYLE,
        lpfn: Some(browse_cb),
        lParam: LPARAM(if initial.is_empty() {
            0
        } else {
            initial_w.as_mut_ptr() as isize
        }),
        ..Default::default()
    };
    let pidl = unsafe { SHBrowseForFolderW(&raw const bi) };
    if pidl.is_null() {
        return;
    }
    let mut path_buf = [0u16; 260]; // MAX_PATH; SHGetPathFromIDListW caps here.
    let ok = unsafe { SHGetPathFromIDListW(pidl, &mut path_buf) };
    unsafe { CoTaskMemFree(Some(pidl as *const _)) };
    if !ok.as_bool() {
        return;
    }
    let null_idx = path_buf
        .iter()
        .position(|&c| c == 0)
        .unwrap_or(path_buf.len());
    let path = String::from_utf16_lossy(&path_buf[..null_idx]);
    let mut path_w: Vec<u16> = path.encode_utf16().chain(std::iter::once(0)).collect();
    unsafe {
        let _ = SetWindowTextW(state.fif_directory_edit, PCWSTR(path_w.as_mut_ptr()));
    }
}

/// Show or hide controls based on the active tab.
///
/// | Control                               | Find | Replace | FIF |
/// |---------------------------------------|------|---------|-----|
/// | find_edit, mode group, match_case,    |  Ō£ō   |    Ō£ō    |  Ō£ō  |
/// |   whole_word, dot_newline, close      |      |         |     |
/// | replace_label/edit                    |  Ō£Ś   |    Ō£ō    |  Ō£ō  |
/// | replace_btn, replace_all_btn          |  Ō£Ś   |    Ō£ō    |  Ō£Ś  |
/// | backward_cb, wrap_around_cb,          |  Ō£ō   |    Ō£ō    |  Ō£Ś  |
/// |   in_selection_cb                     |      |         |     |
/// | find_next_btn, count_btn              |  Ō£ō   |    Ō£ō    |  Ō£Ś  |
/// | fif_filters/directory/browse,         |  Ō£Ś   |    Ō£Ś    |  Ō£ō  |
/// |   sub-folders, hidden folders,        |      |         |     |
/// |   find_all, replace_in_files          |      |         |     |
unsafe fn apply_tab_visibility(state: &FindReplaceState) {
    let is_replace = state.tab == FindReplaceTab::Replace;
    let is_fif = state.tab == FindReplaceTab::FindInFiles;
    let in_buffer = !is_fif;
    let show = |hwnd: HWND, flag: bool| unsafe {
        let _ = ShowWindow(hwnd, if flag { SW_SHOW } else { SW_HIDE });
    };
    // Replace-with row visible on Replace AND FIF (FIF uses
    // the same edit for "Replace in Files").
    show(state.replace_label, is_replace || is_fif);
    show(state.replace_edit, is_replace || is_fif);
    // Replace-action buttons are buffer-only.
    show(state.replace_btn, is_replace);
    show(state.replace_all_btn, is_replace);
    // Buffer-only checkboxes + buttons.
    show(state.backward_cb, in_buffer);
    show(state.wrap_around_cb, in_buffer);
    show(state.in_selection_cb, in_buffer);
    show(state.find_next_btn, in_buffer);
    show(state.count_btn, in_buffer);
    // FIF-only controls.
    show(state.fif_filters_label, is_fif);
    show(state.fif_filters_edit, is_fif);
    show(state.fif_directory_label, is_fif);
    show(state.fif_directory_edit, is_fif);
    show(state.fif_browse_btn, is_fif);
    show(state.fif_subfolders_cb, is_fif);
    show(state.fif_hidden_folders_cb, is_fif);
    show(state.fif_find_all_btn, is_fif);
    show(state.fif_replace_in_files_btn, is_fif);

    // Reposition Whole word + Match case so they line up with the
    // right-column FIF checkboxes (sub-folders / hidden folders).
    // On Find/Replace, Backward sits at the top of the column with
    // Whole word and Match case below it; on FIF, Backward is
    // hidden so Whole word slides up to fill the gap.
    let (whole_word_y, match_case_y) = if is_fif {
        (FR_CHECKBOX_TOP, FR_CHECKBOX_TOP + FR_CHECKBOX_GAP)
    } else {
        (
            FR_CHECKBOX_TOP + FR_CHECKBOX_GAP,
            FR_CHECKBOX_TOP + 2 * FR_CHECKBOX_GAP,
        )
    };
    unsafe {
        let _ = MoveWindow(
            state.whole_word_cb,
            FR_CHECKBOX_X,
            whole_word_y,
            FR_CHECKBOX_W,
            FR_CHECKBOX_H,
            true,
        );
        let _ = MoveWindow(
            state.match_case_cb,
            FR_CHECKBOX_X,
            match_case_y,
            FR_CHECKBOX_W,
            FR_CHECKBOX_H,
            true,
        );
    }
}

/// Lazily create the Find/Replace dialog (the first call creates
/// it; subsequent calls re-show the existing one) and select the
/// requested tab. Returns the dialog HWND so the caller can stash
/// it on `WindowState` for `IsDialogMessageW` integration.
fn show_find_replace_dialog(
    main_hwnd: HWND,
    existing: Option<HWND>,
    initial_tab: FindReplaceTab,
) -> Option<HWND> {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();

    unsafe {
        // Reuse path: the dialog already exists. Just bring it to
        // the foreground, select the right tab, and focus the
        // Find what edit so the user can type immediately.
        if let Some(dlg) = existing {
            if IsWindow(Some(dlg)).as_bool() {
                let state_ptr = GetWindowLongPtrW(dlg, GWLP_USERDATA) as *mut FindReplaceState;
                if !state_ptr.is_null() && (*state_ptr).controls_ready {
                    let state = &mut *state_ptr;
                    state.tab = initial_tab;
                    let idx = match initial_tab {
                        FindReplaceTab::Find => 0,
                        FindReplaceTab::Replace => 1,
                        FindReplaceTab::FindInFiles => 2,
                    };
                    SendMessageW(
                        state.tab_ctrl,
                        TCM_SETCURSEL,
                        Some(WPARAM(idx as usize)),
                        None,
                    );
                    apply_tab_visibility(state);
                    // Wipe any stale Replace All count from the
                    // previous session, prefill the find box from
                    // the current selection, and clear the
                    // In-selection snapshot ŌĆö its bounds may
                    // refer to text the user has since edited
                    // away.
                    clear_status(state);
                    SendMessageW(
                        state.in_selection_cb,
                        BM_SETCHECK,
                        Some(WPARAM(BST_UNCHECKED.0 as usize)),
                        None,
                    );
                    state.in_selection_range = None;
                    refresh_history_dropdowns(state);
                    prefill_from_selection(state);
                    let _ = ShowWindow(dlg, SW_SHOW);
                    let _ = SetFocus(Some(state.find_edit));
                    combobox_select_all(state.find_edit);
                    return Some(dlg);
                }
            }
        }

        // First-time creation.
        let instance = GetModuleHandleW(None).ok()?;
        REGISTERED.get_or_init(|| {
            let class = WNDCLASSEXW {
                cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
                style: CS_HREDRAW | CS_VREDRAW,
                lpfnWndProc: Some(find_replace_wnd_proc),
                hInstance: instance.into(),
                hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
                // See the matching note on the Goto class ŌĆö
                // custom RGB brush keyed to the Win11 themed
                // checkbox tone so the chrome matches.
                hbrBackground: dialog_bg_brush(),
                lpszClassName: FIND_REPLACE_CLASS,
                ..Default::default()
            };
            let _ = RegisterClassExW(&raw const class);
        });

        let mut state = Box::new(FindReplaceState {
            main_hwnd,
            tab: initial_tab,
            tab_ctrl: HWND::default(),
            find_label: HWND::default(),
            find_edit: HWND::default(),
            replace_label: HWND::default(),
            replace_edit: HWND::default(),
            backward_cb: HWND::default(),
            whole_word_cb: HWND::default(),
            match_case_cb: HWND::default(),
            wrap_around_cb: HWND::default(),
            mode_group: HWND::default(),
            mode_normal_radio: HWND::default(),
            mode_extended_radio: HWND::default(),
            mode_regex_radio: HWND::default(),
            dot_newline_cb: HWND::default(),
            find_next_btn: HWND::default(),
            count_btn: HWND::default(),
            replace_btn: HWND::default(),
            replace_all_btn: HWND::default(),
            close_btn: HWND::default(),
            in_selection_cb: HWND::default(),
            fif_filters_label: HWND::default(),
            fif_filters_edit: HWND::default(),
            fif_directory_label: HWND::default(),
            fif_directory_edit: HWND::default(),
            fif_browse_btn: HWND::default(),
            fif_subfolders_cb: HWND::default(),
            fif_hidden_folders_cb: HWND::default(),
            fif_find_all_btn: HWND::default(),
            fif_replace_in_files_btn: HWND::default(),
            status_label: HWND::default(),
            status_is_error: false,
            in_selection_range: None,
            controls_ready: false,
        });
        let state_ptr: *mut FindReplaceState = &raw mut *state;

        // Layout (client coords). Tab control across the top, then
        // a left column with edit fields + checkboxes + Search Mode
        // group, and a right column with the action buttons.
        const CLIENT_W: i32 = 540;
        // Step 4a expands the dialog by 64 px to fit the FIF tab's
        // Filters and Directory rows. Find/Replace tabs see the
        // extra space as empty padding between Replace-with and
        // the checkbox stack ŌĆö acceptable trade vs. resizing the
        // dialog every tab switch.
        const CLIENT_H: i32 = 444;
        const X_PAD: i32 = 14;
        const TAB_TOP: i32 = 8;
        const ROW1_Y: i32 = FR_DLG_ROW1_Y;
        const FIND_LABEL_W: i32 = 90;
        const EDIT_X: i32 = X_PAD + FIND_LABEL_W;
        const EDIT_W: i32 = 240;
        const REPLACE_ROW_Y: i32 = FR_DLG_REPLACE_ROW_Y;
        const FIF_FILTERS_Y: i32 = FR_DLG_FIF_FILTERS_Y;
        const FIF_DIRECTORY_Y: i32 = FR_DLG_FIF_DIRECTORY_Y;
        const FIF_BROWSE_W: i32 = 24;
        const FIF_BROWSE_GAP: i32 = 4;
        const CHECKBOX_X: i32 = FR_CHECKBOX_X;
        const CHECKBOX_W: i32 = FR_CHECKBOX_W;
        const CHECKBOX_H: i32 = FR_CHECKBOX_H;
        const CHECKBOX_TOP: i32 = FR_CHECKBOX_TOP;
        // FIF tab puts two extra checkboxes ("In all sub-folders",
        // "In hidden folders") in the right-hand column at the top
        // of the checkbox stack, beneath the action buttons.
        const FIF_RIGHT_CB_X: i32 = CLIENT_W - X_PAD - CHECKBOX_W;
        // 5 checkboxes in the left column: Backward, Whole word,
        // Match case, Wrap around, In selection.
        const MODE_GROUP_TOP: i32 = CHECKBOX_TOP + 5 * FR_CHECKBOX_GAP + 8;
        const MODE_GROUP_W: i32 = 320;
        // Three rows inside the Search Mode group: Normal,
        // Extended, Regular expression + ". matches newline".
        const MODE_GROUP_H: i32 = 92;
        const BTN_W: i32 = 180;
        const BTN_H: i32 = 26;
        const BTN_X: i32 = CLIENT_W - X_PAD - BTN_W;
        const BTN_GAP: i32 = 6;
        const FIND_NEXT_Y: i32 = ROW1_Y;
        const COUNT_Y: i32 = FIND_NEXT_Y + BTN_H + BTN_GAP;
        const REPLACE_Y: i32 = COUNT_Y + BTN_H + BTN_GAP;
        const REPLACE_ALL_Y: i32 = REPLACE_Y + BTN_H + BTN_GAP;
        // FIF action buttons share the right column. "Find All"
        // overlays "Find Next"; "Replace in Files" overlays
        // "Count" ŌĆö the corresponding Find/Replace buttons hide
        // when the FIF tab is active so there's no visual clash.
        const FIF_FIND_ALL_Y: i32 = FIND_NEXT_Y;
        const FIF_REPLACE_IN_FILES_Y: i32 = COUNT_Y;
        // Status bar runs the full client width along the very
        // bottom of the dialog; the Close button sits one row
        // above it. The status STATIC's slightly-darker fill
        // (COLOR_3DFACE via WM_CTLCOLORSTATIC) makes it read as
        // a distinct status strip.
        const STATUS_H: i32 = 20;
        const STATUS_BOTTOM_PAD: i32 = 4;
        const STATUS_Y: i32 = CLIENT_H - STATUS_H - STATUS_BOTTOM_PAD;
        const STATUS_TO_CLOSE_GAP: i32 = 8;
        const CLOSE_Y: i32 = STATUS_Y - STATUS_TO_CLOSE_GAP - BTN_H;

        let mut window_rect = RECT {
            left: 0,
            top: 0,
            right: CLIENT_W,
            bottom: CLIENT_H,
        };
        let _ = AdjustWindowRectEx(
            &raw mut window_rect,
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            false,
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
        );
        let dlg_w = window_rect.right - window_rect.left;
        let dlg_h = window_rect.bottom - window_rect.top;

        let mut owner_rect = RECT::default();
        let _ = GetWindowRect(main_hwnd, &raw mut owner_rect);
        let owner_w = owner_rect.right - owner_rect.left;
        let owner_h = owner_rect.bottom - owner_rect.top;
        let dlg_x = owner_rect.left + (owner_w - dlg_w) / 2;
        let dlg_y = owner_rect.top + (owner_h - dlg_h) / 2;

        let dlg = CreateWindowExW(
            WS_EX_DLGMODALFRAME | WS_EX_CONTROLPARENT,
            FIND_REPLACE_CLASS,
            w!("Find"),
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            dlg_x,
            dlg_y,
            dlg_w,
            dlg_h,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            Some(state_ptr.cast::<c_void>()),
        )
        .ok()?;
        // If any child creation below `?`-fails, the dialog HWND
        // is destroyed by this guard so we don't leak a live but
        // half-built popup. We `mem::forget` the guard at the end
        // of the function once the dialog is fully assembled.
        let dlg_guard = DlgDestroyGuard(dlg);

        // Tab control (Find | Replace).
        let tab_ctrl = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_TABCONTROL,
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP,
            X_PAD,
            TAB_TOP,
            CLIENT_W - 2 * X_PAD,
            CLIENT_H - TAB_TOP - X_PAD,
            Some(dlg),
            Some(HMENU(IDC_FR_TAB as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Insert three tab items: Find / Replace / Find in Files.
        // The order matters for the TCN_SELCHANGE ŌåÆ enum mapping
        // and for the `idx` returned by `TCM_GETCURSEL`.
        let mut find_label_buf: Vec<u16> =
            "Find".encode_utf16().chain(std::iter::once(0)).collect();
        let mut replace_label_buf: Vec<u16> =
            "Replace".encode_utf16().chain(std::iter::once(0)).collect();
        let mut fif_label_buf: Vec<u16> = "Find in Files"
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        for (idx, label_buf) in [
            &mut find_label_buf,
            &mut replace_label_buf,
            &mut fif_label_buf,
        ]
        .into_iter()
        .enumerate()
        {
            let item = TCITEMW {
                mask: TCIF_TEXT,
                pszText: PWSTR(label_buf.as_mut_ptr()),
                cchTextMax: label_buf.len() as i32,
                ..Default::default()
            };
            SendMessageW(
                tab_ctrl,
                TCM_INSERTITEMW,
                Some(WPARAM(idx)),
                Some(LPARAM(&raw const item as isize)),
            );
        }

        // "Find what:" label + edit (always visible).
        let find_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Find what:"),
            WS_CHILD | WS_VISIBLE,
            X_PAD,
            ROW1_Y + 4,
            FIND_LABEL_W - 4,
            CHECKBOX_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        // "Find what" / "Replace with" are COMBOBOX (CBS_DROPDOWN)
        // controls so the dialog can show recent queries in a
        // dropdown ŌĆö the visible edit field still acts like a
        // plain EDIT (GetWindowTextW / SetWindowTextW work
        // unchanged), and CB_ADDSTRING populates the list. The
        // height parameter to CreateWindowExW for a CBS_DROPDOWN
        // is the total *expanded* height (edit + dropdown);
        // 200 px gives ~8 visible items at the default font.
        const COMBOBOX_EXPANDED_H: i32 = 200;
        let find_edit = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_COMBOBOX,
            PCWSTR::null(),
            WS_CHILD
                | WS_VISIBLE
                | WS_TABSTOP
                | WS_VSCROLL
                | style_bits(CBS_DROPDOWN | CBS_AUTOHSCROLL),
            EDIT_X,
            ROW1_Y,
            EDIT_W,
            COMBOBOX_EXPANDED_H,
            Some(dlg),
            Some(HMENU(IDC_FR_FIND_EDIT as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // "Replace with:" label + combobox (Replace tab only).
        let replace_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Replace with:"),
            WS_CHILD,
            X_PAD,
            REPLACE_ROW_Y + 4,
            FIND_LABEL_W - 4,
            CHECKBOX_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let replace_edit = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_COMBOBOX,
            PCWSTR::null(),
            WS_CHILD | WS_TABSTOP | WS_VSCROLL | style_bits(CBS_DROPDOWN | CBS_AUTOHSCROLL),
            EDIT_X,
            REPLACE_ROW_Y,
            EDIT_W,
            COMBOBOX_EXPANDED_H,
            Some(dlg),
            Some(HMENU(IDC_FR_REPLACE_EDIT as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // Checkboxes.
        let backward_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Backward direction"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            CHECKBOX_X,
            CHECKBOX_TOP,
            CHECKBOX_W,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_BACKWARD as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let whole_word_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Match &whole word only"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            CHECKBOX_X,
            CHECKBOX_TOP + 22,
            CHECKBOX_W,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_WHOLE_WORD as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let match_case_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Match &case"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            CHECKBOX_X,
            CHECKBOX_TOP + 44,
            CHECKBOX_W,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_MATCH_CASE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let wrap_around_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("W&rap around"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            CHECKBOX_X,
            CHECKBOX_TOP + 66,
            CHECKBOX_W,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_WRAP_AROUND as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let in_selection_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("In &selection"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            CHECKBOX_X,
            CHECKBOX_TOP + 88,
            CHECKBOX_W,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_IN_SELECTION as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Wrap is on by default (matches Notepad++).
        SendMessageW(
            wrap_around_cb,
            BM_SETCHECK,
            Some(WPARAM(BST_CHECKED.0 as usize)),
            None,
        );

        // Search Mode group.
        let mode_group = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Search Mode"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_GROUPBOX),
            X_PAD,
            MODE_GROUP_TOP,
            MODE_GROUP_W,
            MODE_GROUP_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Three rows in the group: Normal (row 1), Extended
        // (row 2), Regex + ". matches newline" (row 3 ŌĆö the
        // checkbox sits beside the Regex radio rather than
        // overlapping the Extended row's text).
        let mode_normal_radio = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Normal"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | WS_GROUP | style_bits(BS_AUTORADIOBUTTON),
            X_PAD + 14,
            MODE_GROUP_TOP + 20,
            150,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_MODE_NORMAL as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let mode_extended_radio = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("E&xtended (\\n, \\r, \\t, \\0, \\x...)"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_AUTORADIOBUTTON),
            X_PAD + 14,
            MODE_GROUP_TOP + 42,
            270,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_MODE_EXTENDED as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // Extended mode isn't implemented yet ŌĆö disable so the
        // user knows (and so a click can't put us into a state we
        // don't support).
        let _ = EnableWindow(mode_extended_radio, false);
        let mode_regex_radio = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Re&gular expression"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_AUTORADIOBUTTON),
            X_PAD + 14,
            MODE_GROUP_TOP + 64,
            150,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_MODE_REGEX as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let dot_newline_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!(". &matches newline"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_AUTOCHECKBOX),
            X_PAD + 170,
            MODE_GROUP_TOP + 64,
            140,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_DOT_NEWLINE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let _ = EnableWindow(dot_newline_cb, false);
        // Default Normal mode.
        SendMessageW(
            mode_normal_radio,
            BM_SETCHECK,
            Some(WPARAM(BST_CHECKED.0 as usize)),
            None,
        );

        // Right-column buttons.
        let find_next_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Find Next"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            BTN_X,
            FIND_NEXT_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FR_FIND_NEXT as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let count_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Co&unt"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            BTN_X,
            COUNT_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FR_COUNT as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let replace_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Replace"),
            WS_CHILD | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            BTN_X,
            REPLACE_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FR_REPLACE_BTN as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let replace_all_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Replace &All"),
            WS_CHILD | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            BTN_X,
            REPLACE_ALL_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FR_REPLACE_ALL as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        // FIF tab controls (m4 step 4a). All created hidden ŌĆö the
        // initial `apply_tab_visibility` call after the state's
        // `controls_ready = true` flips on whichever subset matches
        // `initial_tab`. Filters + Directory are COMBOBOX so the
        // dropdown history pattern (m3b2c) can extend naturally
        // when step 4b adds FIF query history.
        let fif_filters_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Filters:"),
            WS_CHILD,
            X_PAD,
            FIF_FILTERS_Y + 4,
            FIND_LABEL_W - 4,
            CHECKBOX_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_filters_edit = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_COMBOBOX,
            PCWSTR::null(),
            WS_CHILD | WS_TABSTOP | WS_VSCROLL | style_bits(CBS_DROPDOWN | CBS_AUTOHSCROLL),
            EDIT_X,
            FIF_FILTERS_Y,
            EDIT_W,
            120,
            Some(dlg),
            Some(HMENU(IDC_FR_FIF_FILTERS as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_directory_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Directory:"),
            WS_CHILD,
            X_PAD,
            FIF_DIRECTORY_Y + 4,
            FIND_LABEL_W - 4,
            CHECKBOX_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_directory_edit = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_COMBOBOX,
            PCWSTR::null(),
            WS_CHILD | WS_TABSTOP | WS_VSCROLL | style_bits(CBS_DROPDOWN | CBS_AUTOHSCROLL),
            EDIT_X,
            FIF_DIRECTORY_Y,
            EDIT_W - FIF_BROWSE_W - FIF_BROWSE_GAP,
            120,
            Some(dlg),
            Some(HMENU(IDC_FR_FIF_DIRECTORY as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_browse_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("..."),
            WS_CHILD | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            EDIT_X + EDIT_W - FIF_BROWSE_W,
            FIF_DIRECTORY_Y,
            FIF_BROWSE_W,
            CHECKBOX_H + 2,
            Some(dlg),
            Some(HMENU(IDC_FR_FIF_BROWSE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_subfolders_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("In all sub-folders"),
            WS_CHILD | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            FIF_RIGHT_CB_X,
            CHECKBOX_TOP,
            CHECKBOX_W,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_FIF_SUBFOLDERS as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_hidden_folders_cb = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("In hidden folders"),
            WS_CHILD | WS_TABSTOP | style_bits(BS_AUTOCHECKBOX),
            FIF_RIGHT_CB_X,
            CHECKBOX_TOP + FR_CHECKBOX_GAP,
            CHECKBOX_W,
            CHECKBOX_H,
            Some(dlg),
            Some(HMENU(IDC_FR_FIF_HIDDEN_FOLDERS as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_find_all_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Find &All"),
            WS_CHILD | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            BTN_X,
            FIF_FIND_ALL_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FR_FIF_FIND_ALL as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let fif_replace_in_files_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("Replace in &Files"),
            WS_CHILD | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            BTN_X,
            FIF_REPLACE_IN_FILES_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FR_FIF_REPLACE_IN_FILES as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        let close_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Close"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_PUSHBUTTON),
            BTN_X,
            CLOSE_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FR_CLOSE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        // Bottom-of-dialog status STATIC for transient feedback
        // (Replace All count, not-found message, etc). Spans
        // the full client width along the bottom of the dialog
        // so the slightly-darker COLOR_3DFACE fill reads as a
        // distinct status strip. Painted blue (info) or red
        // (error) by WM_CTLCOLORSTATIC depending on
        // `state.status_is_error`.
        let status_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE,
            X_PAD,
            STATUS_Y,
            CLIENT_W - 2 * X_PAD,
            STATUS_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        )
        .ok()?;

        // Apply the system GUI font to every child.
        let font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);
        for child in [
            tab_ctrl,
            find_label,
            find_edit,
            replace_label,
            replace_edit,
            backward_cb,
            whole_word_cb,
            match_case_cb,
            wrap_around_cb,
            in_selection_cb,
            mode_group,
            mode_normal_radio,
            mode_extended_radio,
            mode_regex_radio,
            dot_newline_cb,
            find_next_btn,
            count_btn,
            replace_btn,
            replace_all_btn,
            close_btn,
            status_label,
            fif_filters_label,
            fif_filters_edit,
            fif_directory_label,
            fif_directory_edit,
            fif_browse_btn,
            fif_subfolders_cb,
            fif_hidden_folders_cb,
            fif_find_all_btn,
            fif_replace_in_files_btn,
        ] {
            apply_dialog_font(child, font);
        }
        // Disable visual styles ONLY on the BS_GROUPBOX. The
        // themed groupbox paint cuts the border line through
        // the "Search Mode" title; classic paint with the
        // COLOR_3DFACE brush from WM_CTLCOLORBTN clears the
        // title rect cleanly.
        //
        // Checkboxes and radios stay themed: classic-painted
        // BS_AUTOCHECKBOX/BS_AUTORADIOBUTTON don't reliably
        // erase their text region between toggles (DrawText's
        // OPAQUE-bkmode clear isn't enough ŌĆö tightly-drawn
        // glyphs still stack across redraws), and themed
        // paint handles its own redraw correctly.
        disable_visual_style(mode_group);

        state.tab_ctrl = tab_ctrl;
        state.find_label = find_label;
        state.find_edit = find_edit;
        state.replace_label = replace_label;
        state.replace_edit = replace_edit;
        state.backward_cb = backward_cb;
        state.whole_word_cb = whole_word_cb;
        state.match_case_cb = match_case_cb;
        state.wrap_around_cb = wrap_around_cb;
        state.in_selection_cb = in_selection_cb;
        state.mode_group = mode_group;
        state.mode_normal_radio = mode_normal_radio;
        state.mode_extended_radio = mode_extended_radio;
        state.mode_regex_radio = mode_regex_radio;
        state.dot_newline_cb = dot_newline_cb;
        state.find_next_btn = find_next_btn;
        state.count_btn = count_btn;
        state.replace_btn = replace_btn;
        state.replace_all_btn = replace_all_btn;
        state.close_btn = close_btn;
        state.fif_filters_label = fif_filters_label;
        state.fif_filters_edit = fif_filters_edit;
        state.fif_directory_label = fif_directory_label;
        state.fif_directory_edit = fif_directory_edit;
        state.fif_browse_btn = fif_browse_btn;
        state.fif_subfolders_cb = fif_subfolders_cb;
        state.fif_hidden_folders_cb = fif_hidden_folders_cb;
        state.fif_find_all_btn = fif_find_all_btn;
        state.fif_replace_in_files_btn = fif_replace_in_files_btn;
        state.status_label = status_label;

        // Default sub-folders to checked. Most FIF use cases want
        // recursive search (project-wide query); the user can
        // uncheck for a single-folder search before kicking off.
        SendMessageW(
            fif_subfolders_cb,
            BM_SETCHECK,
            Some(WPARAM(BST_CHECKED.0 as usize)),
            None,
        );

        state.controls_ready = true;

        let idx = match initial_tab {
            FindReplaceTab::Find => 0,
            FindReplaceTab::Replace => 1,
            FindReplaceTab::FindInFiles => 2,
        };
        SendMessageW(tab_ctrl, TCM_SETCURSEL, Some(WPARAM(idx as usize)), None);
        apply_tab_visibility(&state);
        refresh_history_dropdowns(&state);
        prefill_from_selection(&state);

        // Drop ownership: the wnd_proc owns the Box from here on
        // and reclaims it on WM_NCDESTROY. The pointer in
        // GWLP_USERDATA was set during WM_NCCREATE. Disarm the
        // dlg_guard for the same reason ŌĆö the dialog is fully
        // built and we want it to outlive this function.
        std::mem::forget(state);
        std::mem::forget(dlg_guard);

        let _ = ShowWindow(dlg, SW_SHOW);
        let _ = SetFocus(Some(find_edit));
        Some(dlg)
    }
}

/// Handle a Language-menu click ŌĆö flip the active tab's lang to the
/// supplied `LangType` id. Routes through the same `set_buffer_lang_type`
/// the plugin ABI uses, so the code path covers re-applying the lexer
/// for the active tab and queueing `NPPN_LANGCHANGED`.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_language_menu_click(hwnd: HWND, lang_id: i32) {
    let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        unsafe { handle_language_menu_click_inner(hwnd, lang_id) };
    }));
}

unsafe fn handle_language_menu_click_inner(hwnd: HWND, lang_id: i32) {
    // Route through `dispatch_plugin_message` with the
    // NPPM_SETBUFFERLANGTYPE wire format so the menu click and a
    // plugin-driven set go through one code path. That code already
    // re-applies the lexer for the active tab and queues
    // NPPN_LANGCHANGED on a real change; mirroring it here means
    // adding/changing language behaviour only happens in one place.
    let buffer_id = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        match state.shell.active() {
            Some(t) => t.id as usize,
            None => return,
        }
    } else {
        return;
    };
    if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        let handles = state.host_handles(hwnd);
        let (shell, mut ui) = state.split();
        // SAFETY: `dispatch_plugin_message` requires a UI-thread
        // call with valid handles for this window. The wnd_proc
        // contract gives us both.
        unsafe {
            let _ = shell.dispatch_plugin_message(
                &mut ui,
                handles,
                codepp_plugin_host::dispatch::NPPM_SETBUFFERLANGTYPE,
                buffer_id,
                lang_id as isize,
            );
        }
    }
    unsafe {
        fire_queued_notifications(hwnd);
    }
}

/// Handle a Window-menu click ŌĆö switch the active tab to `tab_idx`.
/// Routes through the same code path as a tab-strip click so the
/// editor view, status bar, language and window title all update
/// together.
///
/// # Safety
///
/// Caller must invoke from the UI thread that owns `hwnd`.
unsafe fn handle_window_menu_click(hwnd: HWND, tab_idx: usize) {
    let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        unsafe { handle_window_menu_click_inner(hwnd, tab_idx) };
    }));
}

unsafe fn handle_window_menu_click_inner(hwnd: HWND, tab_idx: usize) {
    // TCM_SETCURSEL doesn't generate TCN_SELCHANGE, so we manually
    // invoke the selchange handler after a successful cursor move
    // to do the rest of the work (doc rebind, status, lexer,
    // notification queueing). The selchange call is gated on the
    // cursor move actually happening ŌĆö if `state_from_hwnd` returns
    // None (e.g. PLUGIN_CALL_ACTIVE is set because a plugin's
    // beNotified synthesised this WM_COMMAND), no cursor move
    // occurred and firing selchange anyway would queue a spurious
    // BUFFERACTIVATED on the wrong tab.
    let did_move = if let Some(state) = unsafe { state_from_hwnd(hwnd) } {
        if tab_idx >= state.shell.tabs.len() {
            return;
        }
        unsafe {
            SendMessageW(
                state.tab_hwnd,
                TCM_SETCURSEL,
                Some(WPARAM(tab_idx)),
                Some(LPARAM(0)),
            );
        }
        true
    } else {
        false
    };
    if did_move {
        unsafe {
            handle_tab_selchange(hwnd);
        }
    }
}

// --- Window-geometry persistence -------------------------------------
//
// Cross-launch persistence of the main window's size lives in
// `core::Session.window` (a `WindowGeometry`); on shutdown
// `Shell::save_session` writes the cached value, on startup
// `Shell::saved_window_geometry` returns it. The Win32 plumbing
// below sits between those two points: it reads the saved size at
// app start (clamping against screen + toolbar minimum) and feeds
// every `WM_SIZE` back into the shell so the next save captures
// the user's latest preference.

/// Default outer window dimensions used on a fresh install when
/// session.xml carries no `<window>` element. Wider than the prior
/// `900` so the toolbar's full button strip is visible at standard
/// DPI without the user having to manually widen the window ŌĆö
/// 1280 is the smallest "common laptop" width that comfortably
/// holds every M3 toolbar button + chrome.
const DEFAULT_WINDOW_WIDTH_PX: i32 = 1280;
const DEFAULT_WINDOW_HEIGHT_PX: i32 = 720;

/// Hard floor on the height we'll restore to. A maliciously- or
/// accidentally-tiny saved height (e.g. user dragged the bottom edge
/// to one pixel before closing) would otherwise reopen the window
/// with no usable editor area.
const MIN_WINDOW_HEIGHT_PX: i32 = 400;

/// Hard ceiling on either window dimension. Belt-and-braces against
/// a tampered or corrupted session.xml carrying an `i32::MAX` width
/// or height ŌĆö the screen-clamp normally enforces a tight bound,
/// but on a degenerate monitor query (zero work-area dimensions)
/// the screen clamp is skipped, so an unconditional ceiling is
/// also applied. 32 767 is the historical Win32 GDI coordinate
/// limit and is comfortably larger than any real display.
const MAX_WINDOW_DIMENSION_PX: i32 = 32_767;

/// Work-area rectangle of the monitor closest to `hwnd` (the
/// "screen minus taskbar" rect). Used to clamp the restored window
/// size so a session.xml carrying a width/height larger than the
/// current display doesn't open the window with content off-screen.
unsafe fn nearest_monitor_work_area(hwnd: HWND) -> RECT {
    unsafe {
        let monitor = MonitorFromWindow(hwnd, MONITOR_DEFAULTTONEAREST);
        let mut info = MONITORINFO {
            cbSize: std::mem::size_of::<MONITORINFO>() as u32,
            ..Default::default()
        };
        if GetMonitorInfoW(monitor, &raw mut info).as_bool() {
            info.rcWork
        } else {
            // Fallback when the monitor query fails (extremely rare ŌĆö
            // would require a yanked display while the call was in
            // flight). 1920├Ś1040 = 1080p minus a typical 40-pixel
            // taskbar, so the screen-clamp on the saved geometry
            // doesn't accidentally collapse the window during this
            // edge case.
            const FALLBACK_WORK_W: i32 = 1920;
            const FALLBACK_WORK_H: i32 = 1040;
            RECT {
                left: 0,
                top: 0,
                right: FALLBACK_WORK_W,
                bottom: FALLBACK_WORK_H,
            }
        }
    }
}

/// Outer-width floor below which the toolbar would clip its
/// rightmost buttons. `toolbar::natural_min_width_px` returns the
/// inner-strip width; we add the non-client frame chrome via
/// `AdjustWindowRectEx` (matching the main window's style + menu)
/// so the result is comparable to the outer width that
/// `SetWindowPos` and the saved geometry both use.
unsafe fn toolbar_min_outer_width(toolbar_hwnd: HWND) -> i32 {
    unsafe {
        let inner = toolbar::natural_min_width_px(toolbar_hwnd);
        if inner <= 0 {
            // Toolbar not yet laid out (TB_GETMAXSIZE returned 0) ŌĆö
            // fall back to the default width so we don't accidentally
            // collapse the window during early init.
            return DEFAULT_WINDOW_WIDTH_PX;
        }
        let mut frame = RECT {
            left: 0,
            top: 0,
            right: inner,
            bottom: 0,
        };
        // `AdjustWindowRectEx(rect, style, has_menu, ex_style)`
        // expands `rect` from a desired client area to the outer
        // window rect that produces it ŌĆö same style flags the main
        // window was created with, `bMenu = true` because the main
        // window has a menu bar. On failure (invalid style flags or
        // a future API change) the rect is left untouched, which
        // would silently understate the floor by the non-client
        // chrome ŌĆö fall through to the safe default instead.
        if AdjustWindowRectEx(
            &raw mut frame,
            WS_OVERLAPPEDWINDOW,
            true,
            WINDOW_EX_STYLE::default(),
        )
        .is_err()
        {
            return DEFAULT_WINDOW_WIDTH_PX;
        }
        frame.right - frame.left
    }
}

/// Apply the saved window geometry ŌĆö or a sensible default when no
/// session.xml is present ŌĆö to `main_hwnd`. Sets the *restored*
/// (non-maximized) outer rectangle via `SetWindowPos(SWP_NOMOVE)`
/// and returns the `ShowWindow` command the caller should use:
/// `SW_SHOWMAXIMIZED` if the saved state was maximized, otherwise
/// `SW_SHOW`.
///
/// Layered constraints, applied in order:
///   1. **Saved width/height** from `session.xml` if present,
///      otherwise the [`DEFAULT_WINDOW_WIDTH_PX`] /
///      [`DEFAULT_WINDOW_HEIGHT_PX`] defaults.
///   2. **Toolbar minimum**: width is `max`'d against
///      `toolbar_min_outer_width` so the user never launches into
///      a state where rightmost toolbar buttons are clipped ŌĆö the
///      bug this whole change is meant to address.
///   3. **Hard height floor** so a tampered-or-accidentally-tiny
///      saved height can't reopen the window at one-pixel-tall.
///   4. **Screen clamp** against the current monitor's work area
///      so a saved geometry from a larger display doesn't push
///      content off-screen.
unsafe fn apply_initial_window_size(
    main_hwnd: HWND,
    toolbar_hwnd: HWND,
    saved: Option<WindowGeometry>,
) -> SHOW_WINDOW_CMD {
    unsafe {
        let toolbar_floor = toolbar_min_outer_width(toolbar_hwnd);
        let work = nearest_monitor_work_area(main_hwnd);
        let work_w = (work.right - work.left).max(0);
        let work_h = (work.bottom - work.top).max(0);

        let (mut width, mut height, maximized) = match saved {
            Some(g) => (
                g.width.unwrap_or(DEFAULT_WINDOW_WIDTH_PX),
                g.height.unwrap_or(DEFAULT_WINDOW_HEIGHT_PX),
                g.maximized,
            ),
            None => (DEFAULT_WINDOW_WIDTH_PX, DEFAULT_WINDOW_HEIGHT_PX, false),
        };

        // Toolbar floor takes precedence over the saved width.
        width = width.max(toolbar_floor);
        // Hard height floor.
        height = height.max(MIN_WINDOW_HEIGHT_PX);
        // Hard ceiling ŌĆö applied unconditionally so a degenerate
        // monitor query (which skips the screen clamp below) can't
        // forward an `i32::MAX` saved value straight to
        // `SetWindowPos`. The Win32 GDI coordinate limit is 32 767;
        // anything larger has no use and risks integer issues
        // downstream.
        width = width.min(MAX_WINDOW_DIMENSION_PX);
        height = height.min(MAX_WINDOW_DIMENSION_PX);
        // Screen clamp ŌĆö only when the work area is non-degenerate.
        if work_w > 0 {
            width = width.min(work_w);
        }
        if work_h > 0 {
            height = height.min(work_h);
        }

        // SWP_NOMOVE keeps whatever position `CreateWindowExW(...,
        // CW_USEDEFAULT, CW_USEDEFAULT, ...)` chose; SWP_NOZORDER
        // leaves the z-order alone (no need to re-stack a window
        // that hasn't been shown yet). The result is suppressed
        // because the HWND was just created by the surrounding
        // `run()` and is guaranteed live ŌĆö the only realistic
        // failure (an invalid flag combination) is a coding bug,
        // not a recoverable runtime condition.
        let _ = SetWindowPos(
            main_hwnd,
            None,
            0,
            0,
            width,
            height,
            SWP_NOMOVE | SWP_NOZORDER,
        );

        if maximized {
            SW_SHOWMAXIMIZED
        } else {
            SW_SHOW
        }
    }
}

/// Update the shell's cached window geometry from a `WM_SIZE`
/// observation. Called from the main `wnd_proc`'s `WM_SIZE` arm so
/// the next `save_session` writes through whatever the user last
/// set. `wparam_size_state` is the raw `wparam` from the message.
///
/// Behaviour by state:
///   - **Restored**: capture the current outer rect and stamp it
///     into width/height; clear the maximized flag.
///   - **Maximized**: leave width/height alone (preserves the
///     un-maximize-back-to-this fallback) and set the maximized
///     flag.
///   - **Minimized / sibling-window maximize transitions**
///     (`SIZE_MAXSHOW`/`SIZE_MAXHIDE`): ignored. Persisting
///     minimized would surprise the user on next launch, and the
///     `MAXSHOW`/`MAXHIDE` codes report on *another* window and
///     carry no useful size for ours.
fn track_window_geometry(hwnd: HWND, shell: &mut Shell, wparam_size_state: u32) {
    // Numeric values of `SIZE_*` from `winuser.h`. windows-rs hides
    // these behind a feature gate that's not currently enabled in
    // our dependency manifest; the values are stable SDK ABI.
    const SIZE_RESTORED: u32 = 0;
    const SIZE_MAXIMIZED: u32 = 2;

    // Match exhaustively on the two states we care about and bail
    // on everything else. Folding the dispatch into one match
    // keeps an unrecognised state from accidentally landing in a
    // path that re-writes the cache with stale values.
    let (maximized, capture_size) = match wparam_size_state {
        SIZE_RESTORED => (false, true),
        SIZE_MAXIMIZED => (true, false),
        _ => return,
    };

    let mut geom = shell.saved_window_geometry().unwrap_or_default();
    geom.maximized = maximized;
    if capture_size {
        let mut outer = RECT::default();
        // SAFETY: hwnd is the main window currently dispatching
        // WM_SIZE. GetWindowRect on a live HWND is sound; on
        // failure we leave width/height unchanged (the prior
        // saved values stay).
        if unsafe { GetWindowRect(hwnd, &raw mut outer) }.is_ok() {
            geom.width = Some(outer.right - outer.left);
            geom.height = Some(outer.bottom - outer.top);
        }
    }
    shell.set_window_geometry(geom);
}

/// Run the Code++ Win32 event loop. Blocks until the user exits.
///
/// Decode a Win32 `ACCEL` entry into the plugin-visible
/// `ShortcutKey` shape. The `fVirt` byte packs the modifier
/// flags (`FCONTROL` / `FSHIFT` / `FALT`) plus `FVIRTKEY`; the
/// modifier bits map 1:1 to N++'s `ShortcutKey.is_*` fields.
/// `ACCEL.key` is the virtual-key code as `u16`; `ShortcutKey`
/// declares the field as `u8`, so we truncate ŌĆö virtual-key
/// codes fit in a byte (the entire `VK_*` namespace is below
/// 0xFF).
fn decode_accel_to_shortcut_key(a: &ACCEL) -> codepp_plugin_host::ShortcutKey {
    let bits = a.fVirt.0;
    if a.key > 0xFF {
        // Today's `VK_*` namespace tops out at 0xFE, so this
        // branch is unreachable. The warn-log is for the
        // hypothetical future-Microsoft-expansion case ŌĆö
        // without it the `as u8` truncation below would
        // silently drop the high byte and a plugin would read
        // a wrong `ShortcutKey.key` with no diagnostic.
        tracing::warn!(
            cmd = a.cmd,
            key = a.key,
            "ACCEL.key exceeds u8 range; ShortcutKey.key truncates to low byte"
        );
    }
    codepp_plugin_host::ShortcutKey {
        is_ctrl: u8::from((bits & FCONTROL.0) != 0),
        is_alt: u8::from((bits & FALT.0) != 0),
        is_shift: u8::from((bits & FSHIFT.0) != 0),
        key: a.key as u8,
    }
}

/// Build the host's default accelerator table ŌĆö the keyboard
/// shortcuts the message pump consults via `TranslateAcceleratorW`.
/// Single source of truth for both the initial `HACCEL` creation
/// and `Win32Ui::shortcut_for_cmd_id`'s live introspection: the
/// `WM_KEYDOWN` path consults this table via the live HACCEL on
/// `WindowState`, and `NPPM_GETSHORTCUTBYCMDID` reads from the
/// same handle through `CopyAcceleratorTableW`. When
/// `NPPM_REMOVESHORTCUTBYCMDID` removes a binding the recreate
/// path filters this set and rebuilds; subsequent calls observe
/// the updated set automatically.
///
/// The covered set is exactly the commands Scintilla doesn't
/// already bind natively (Ctrl+X / C / V / Z / Y / A live
/// inside Scintilla's own keyboard table ŌĆö duplicating them as
/// host-level accelerators caused a "Ctrl+V sometimes doesn't
/// paste" bug we traced and removed). See the message-pump
/// commentary in `run()` for the full rationale.
fn build_default_accel_table() -> Vec<ACCEL> {
    let ctrl = ACCEL_VIRT_FLAGS(FCONTROL.0 | FVIRTKEY.0);
    let ctrl_shift = ACCEL_VIRT_FLAGS(FCONTROL.0 | FSHIFT.0 | FVIRTKEY.0);
    let ctrl_alt = ACCEL_VIRT_FLAGS(FCONTROL.0 | FALT.0 | FVIRTKEY.0);
    vec![
        // File ŌĆö the Save family follows Notepad++'s conventions:
        //   Ctrl+S       ŌåÆ Save (active buffer)
        //   Ctrl+Alt+S   ŌåÆ Save As (opens dialog for active buffer)
        //   Ctrl+Shift+S ŌåÆ Save All (every dirty buffer at once)
        // Ctrl+R ŌåÆ Reload (from disk). Ctrl+W / Ctrl+Shift+W ŌåÆ
        // Close / Close All. None of these keys are bound in
        // Scintilla's native keyboard table (which owns Ctrl+X/C/
        // V/Z/Y/A ŌĆö see the comment above about the "Ctrl+V
        // sometimes doesn't paste" bug), so there's no
        // contention with the editor.
        //
        // **AltGr caveat.** On non-US keyboard layouts (German,
        // French, etc.) AltGr is delivered as Ctrl+Alt combined,
        // so AltGr+S ŌĆö normally a printable character on those
        // layouts ŌĆö will fire the Save As accelerator instead.
        // This is an accepted trade-off Notepad++ shares (its
        // default Save As binding is also Ctrl+Alt+S) and is
        // consistent with how a user of the two apps side by
        // side would expect the shortcut to behave.
        ACCEL {
            fVirt: ctrl,
            key: VK_N.0,
            cmd: ID_FILE_NEW,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_O.0,
            cmd: ID_FILE_OPEN,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_R.0,
            cmd: ID_FILE_RELOAD,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_S.0,
            cmd: ID_FILE_SAVE,
        },
        ACCEL {
            fVirt: ctrl_alt,
            key: VK_S.0,
            cmd: ID_FILE_SAVE_AS,
        },
        ACCEL {
            fVirt: ctrl_shift,
            key: VK_S.0,
            cmd: ID_FILE_SAVE_ALL,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_W.0,
            cmd: ID_FILE_CLOSE,
        },
        // Print ŌĆö standard Ctrl+P across every OS-native app that
        // ever printed anything. Scintilla doesn't bind Ctrl+P, so
        // there's no editor-side contention.
        ACCEL {
            fVirt: ctrl,
            key: VK_P.0,
            cmd: ID_FILE_PRINT,
        },
        ACCEL {
            fVirt: ctrl_shift,
            key: VK_W.0,
            cmd: ID_FILE_CLOSE_ALL,
        },
        // Search
        ACCEL {
            fVirt: ctrl,
            key: VK_F.0,
            cmd: ID_SEARCH_FIND,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_H.0,
            cmd: ID_SEARCH_REPLACE,
        },
        ACCEL {
            fVirt: ctrl_shift,
            key: VK_F.0,
            cmd: ID_SEARCH_FINDINFILES,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_G.0,
            cmd: ID_SEARCH_GOTOLINE,
        },
        // Find Next / Find Previous repeat shortcuts.
        ACCEL {
            fVirt: ACCEL_VIRT_FLAGS(FVIRTKEY.0),
            key: VK_F3.0,
            cmd: ID_SEARCH_FINDNEXT,
        },
        ACCEL {
            fVirt: ACCEL_VIRT_FLAGS(FSHIFT.0 | FVIRTKEY.0),
            key: VK_F3.0,
            cmd: ID_SEARCH_FINDPREV,
        },
        // View
        ACCEL {
            fVirt: ctrl,
            key: VK_OEM_PLUS.0,
            cmd: ID_VIEW_ZOOMIN,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_OEM_MINUS.0,
            cmd: ID_VIEW_ZOOMOUT,
        },
        ACCEL {
            fVirt: ctrl,
            key: VK_0.0,
            cmd: ID_VIEW_ZOOMRESET,
        },
        // Help ŌĆö F1 opens the About dialog. Plain virtual key
        // (no modifier bits) so any F1 press from the main
        // window dispatches `ID_HELP_ABOUT`. Scintilla doesn't
        // bind F1 natively so there's no contention with the
        // editor's keyboard table.
        ACCEL {
            fVirt: ACCEL_VIRT_FLAGS(FVIRTKEY.0),
            key: VK_F1.0,
            cmd: ID_HELP_ABOUT,
        },
        // File ŌåÆ Rename... ŌĆö F2 is the conventional rename
        // shortcut across Windows shells, IDEs, and Notepad++.
        // Plain virtual key, no modifier bits, matching F1's
        // contract. Scintilla doesn't bind F2 either, so there's
        // no contention with the editor.
        ACCEL {
            fVirt: ACCEL_VIRT_FLAGS(FVIRTKEY.0),
            key: VK_F2.0,
            cmd: ID_FILE_RENAME,
        },
    ]
}

/// `initial_path` (if `Some`) is queued for opening immediately after
/// the window is shown ŌĆö same code path as drag-and-drop and as
/// session-restore. Used for Phase 2 demo verification and for
/// `codepp.exe <path>` from the shell.
pub fn run(initial_path: Option<PathBuf>) -> Result<()> {
    unsafe {
        let instance = GetModuleHandleW(None)?;

        // Common controls ŌĆö status bar (BAR), tab strip (TAB),
        // listview (LISTVIEW) for the FIF results dock, and
        // treeview (TREEVIEW) for the workspace panel body.
        let icc = INITCOMMONCONTROLSEX {
            dwSize: std::mem::size_of::<INITCOMMONCONTROLSEX>() as u32,
            dwICC: ICC_BAR_CLASSES
                | ICC_TAB_CLASSES
                | ICC_LISTVIEW_CLASSES
                | ICC_TREEVIEW_CLASSES
                | ICC_PROGRESS_CLASS,
        };
        InitCommonControlsEx(&raw const icc).ok()?;

        // Register Scintilla's window classes.
        if Scintilla_RegisterClasses(instance.0) == 0 {
            return Err(windows::core::Error::from_thread());
        }

        // Load the application icon ŌĆö the same multi-resolution
        // `assets/code++.ico` that `crates/app/build.rs` embedded as
        // resource id `1` in the `.exe`. `LoadIconW` picks the
        // platform's preferred large size (typically 32x32) for the
        // title bar; `LoadImageW` with explicit `(16, 16)` requests
        // the small-icon variant for Alt+Tab and the Task Manager.
        // Both paths fall back to a null `HICON` on failure, which
        // makes Win32 use `IDI_APPLICATION` (the generic Windows
        // icon) ŌĆö graceful degradation if the resource ever fails
        // to load. `APP_ICON_RESOURCE` lives at module scope ŌĆö
        // see its definition for the `MAKEINTRESOURCEW` rationale.
        let icon_large = LoadIconW(Some(instance.into()), APP_ICON_RESOURCE).unwrap_or_default();
        let icon_small = LoadImageW(
            Some(instance.into()),
            APP_ICON_RESOURCE,
            IMAGE_ICON,
            16,
            16,
            LR_DEFAULTCOLOR,
        )
        .map(|h| HICON(h.0))
        .unwrap_or_default();

        // Register our main-window class.
        let main_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(main_wnd_proc),
            hInstance: instance.into(),
            hIcon: icon_large,
            hIconSm: icon_small,
            hCursor: LoadCursorW(None, IDC_ARROW)?,
            hbrBackground: HBRUSH((COLOR_WINDOW.0 + 1) as usize as *mut c_void),
            lpszClassName: MAIN_CLASS,
            ..Default::default()
        };
        if RegisterClassExW(&raw const main_class) == 0 {
            return Err(windows::core::Error::from_thread());
        }

        // Full N++-shaped menu bar. `build_main_menu` returns the
        // bar plus the HMENUs of submenus we need later for dynamic
        // refresh (encoding/lang radios, View toggles) or for plugin
        // ABI exposure (the per-plugin submenu).
        let menus = build_main_menu()?;
        let menubar = menus.bar;
        let plugin_menu = menus.plugin_menu;

        // Create the main window without children first; we attach
        // them after the Shell is built and stashed in GWLP_USERDATA.
        let main_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            MAIN_CLASS,
            w!("Code++"),
            WS_OVERLAPPEDWINDOW,
            CW_USEDEFAULT,
            CW_USEDEFAULT,
            900,
            600,
            None,
            Some(menubar),
            Some(instance.into()),
            None,
        )?;

        // Status bar ŌĆö auto-anchored to the bottom by the SB_RESIZE
        // pattern (parent WM_SIZE forwards to the status bar so it
        // stretches to fill width).
        let status_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            STATUSBAR_CLASS,
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        // A freshly-created status bar has zero parts. SB_SETTEXTW on a
        // non-existent part silently no-ops (returns success without
        // storing anything), which produces an empty status bar at
        // runtime. Apply the 7-part layout right away so writes from
        // the first `update_status` land in the right slots; WM_SIZE
        // re-applies it on every window resize so the spring (part 1)
        // tracks the current width.
        {
            let mut client = RECT::default();
            let initial_width = if GetClientRect(main_hwnd, &raw mut client).is_ok() {
                client.right
            } else {
                // Fallback: the window-creation `CreateWindowExW`
                // path uses CW_USEDEFAULT for the initial size, so
                // GetClientRect should succeed; the 800px fallback
                // exists only to keep `setup_status_parts` from
                // computing nonsense edges if the call ever fails.
                800
            };
            setup_status_parts(status_hwnd, initial_width);
        }
        // Subclass the status bar so right-clicks on the language
        // part (leftmost) pop a context menu mirroring the menu
        // bar's Language submenu. See `status_bar_subclass_proc`.
        // `SetWindowSubclass` returns BOOL ŌĆö failure is extremely
        // unlikely (only OOM at subclass-chain allocation time) and
        // the only consequence is that the context menu doesn't
        // appear; the status bar otherwise functions normally.
        let _ = SetWindowSubclass(
            status_hwnd,
            Some(status_bar_subclass_proc),
            STATUS_BAR_SUBCLASS_ID,
            0,
        );

        // Toolbar ŌĆö sits below the menu bar, above the tab strip.
        // Buttons are bound to existing menu IDs so click ŌåÆ
        // WM_COMMAND reuses the menu's handlers (see `mod toolbar`
        // for the full layout). Created here, sized via WM_SIZE
        // through `layout_children`.
        let toolbar_handles = toolbar::create_toolbar(main_hwnd, instance)?;
        let toolbar_hwnd = toolbar_handles.hwnd;
        let toolbar_image_list = toolbar_handles.image_list;
        let toolbar_bitmap_px = toolbar_handles.bitmap_px;

        // Tab control ŌĆö sits below the toolbar, above Scintilla.
        // One TCITEMW per `Shell.tabs[i]` is inserted lazily by
        // `sync_tab_strip` after the first drain delivers a load
        // result. WM_NOTIFY (TCN_SELCHANGE) wires click ŌåÆ tab
        // switch via SCI_SETDOCPOINTER.
        let tab_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_TABCONTROL,
            PCWSTR::null(),
            // `TCS_OWNERDRAWFIXED` makes the parent receive
            // `WM_DRAWITEM` per tab cell so we paint each item
            // ourselves: background + save icon + label + close-X.
            // This is the only path on Win10/11 that reliably
            // shows custom icons + per-tab hover state inside a
            // themed tab control ŌĆö UxTheme intercepts
            // `NM_CUSTOMDRAW` for the system tab strip but leaves
            // `WM_DRAWITEM` alone.
            WS_CHILD | WS_VISIBLE | style_bits(TCS_OWNERDRAWFIXED as i32),
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;

        // Reserve horizontal room either side of the tab text for
        // the save icon (left) and the close-X (right).
        // `TCM_SETPADDING` adds the wparam padding either side of
        // the system-calculated text width. The vertical padding
        // bumps the tab height a touch so the 16-px icon doesn't
        // crowd the top/bottom borders.
        SendMessageW(
            tab_hwnd,
            TCM_SETPADDING,
            Some(WPARAM(0)),
            Some(LPARAM(
                makelong(TAB_TEXT_PADDING_X_PX, TAB_TEXT_PADDING_Y_PX) as isize,
            )),
        );

        // Subclass the tab control so left-button mouse messages
        // can drive drag-to-reorder, hover state for the close-X,
        // and click-to-close-tab. `tab_subclass_proc` removes
        // itself from the subclass chain on `WM_NCDESTROY` so the
        // subclass storage doesn't leak when the window dies.
        // `SetWindowSubclass` returns BOOL ŌĆö failure is extremely
        // rare (out-of-memory only) and would just mean drag
        // doesn't work; fall through silently in that case rather
        // than blocking startup.
        let _ = SetWindowSubclass(tab_hwnd, Some(tab_subclass_proc), TAB_SUBCLASS_ID, 0);

        // Scintilla child ŌĆö sized via WM_SIZE relative to the status bar.
        let scintilla_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            SCINTILLA_CLASS,
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;

        // FIF dock + splitter ŌĆö both hidden at startup. The dock is a
        // bare WS_CHILD container; step 4 will populate it with a
        // SysListView32 and a small status row. WS_CLIPCHILDREN keeps
        // future child-control redraws from flickering through the
        // dock's own paint.
        register_fif_classes();
        let fif_dock_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            FIF_DOCK_CLASS,
            PCWSTR::null(),
            WS_CHILD | WS_CLIPCHILDREN,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let fif_splitter_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            FIF_SPLITTER_CLASS,
            PCWSTR::null(),
            WS_CHILD,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;

        // Workspace panel + splitter ŌĆö both hidden at startup, both
        // eagerly created so `layout_children` always has valid
        // HWNDs to reason about (mirrors the FIF pattern above).
        // The panel body (header + action bar + tree) is populated
        // in m2/m3; m1 just registers the classes and holds the
        // container.
        register_workspace_classes();
        let workspace_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WORKSPACE_PANEL_CLASS,
            PCWSTR::null(),
            WS_CHILD | WS_CLIPCHILDREN,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let workspace_splitter_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WORKSPACE_SPLITTER_CLASS,
            PCWSTR::null(),
            WS_CHILD,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;

        // Workspace in-panel children: header title STATIC + close-├Ś
        // button, and three action-row buttons. All are children of
        // `workspace_hwnd`, so their visibility is transitively
        // gated by the panel's own visibility (the panel starts
        // hidden). Positioned by `workspace_panel_wnd_proc`'s
        // `WM_SIZE` handler on every panel-size change.
        //
        // Frame created FIRST so z-order (later-created siblings
        // paint above earlier) puts it behind the label + close.
        // Same z-order technique the About dialog uses for its
        // "MIT License" etched frame.
        let workspace_header_frame = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | style_bits(SS_ETCHEDFRAME as i32),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let workspace_header_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Folder as Workspace"),
            WS_CHILD | WS_VISIBLE | style_bits(SS_CENTERIMAGE as i32),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let workspace_close_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            // Multiplication-sign U+2715 ŌĆö same close-glyph pattern
            // as the FIF dock's ├Ś button. Reads as "close" at small
            // sizes without a custom-drawn button.
            w!("\u{2715}"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_PUSHBUTTON),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            Some(HMENU(IDC_WORKSPACE_CLOSE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )?;
        // Action buttons. Unicode glyphs (ŌŖ×/ŌŖ¤/ŌŚÄ) are placeholders
        // for the m3-polish icon set ŌĆö good enough visual affordance
        // for m2 verify (each is distinct at 22 px) without adding
        // PNG assets to the tree.
        let workspace_action_unfold = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("\u{229E}"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_PUSHBUTTON),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            Some(HMENU(IDC_WORKSPACE_UNFOLD as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )?;
        let workspace_action_fold = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("\u{229F}"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_PUSHBUTTON),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            Some(HMENU(IDC_WORKSPACE_FOLD as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )?;
        let workspace_action_locate = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("\u{25CE}"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_PUSHBUTTON),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            Some(HMENU(IDC_WORKSPACE_LOCATE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )?;
        // TreeView filling the workspace panel body. Populated
        // lazily via `TVN_ITEMEXPANDINGW` ŌĆö see [`populate_workspace_root`]
        // and [`insert_tree_folder_children`]. Styles:
        //   * TVS_HASBUTTONS ŌĆö [+]/[-] chevrons.
        //   * TVS_HASLINES + TVS_LINESATROOT ŌĆö hierarchy lines
        //     from root down (matches Explorer's tree pane).
        //   * TVS_SHOWSELALWAYS ŌĆö selection stays visible when
        //     the tree loses focus (so a double-click in the
        //     editor doesn't visually clear the tree selection).
        let workspace_tree_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_TREEVIEWW,
            PCWSTR::null(),
            WS_CHILD
                | WS_VISIBLE
                | WS_TABSTOP
                | style_bits(
                    (TVS_HASBUTTONS | TVS_HASLINES | TVS_LINESATROOT | TVS_SHOWSELALWAYS) as i32,
                ),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        // Wire the system image list once at creation so every
        // subsequent `TVITEMW::iImage` refers to a system-icon
        // index (matches Explorer's icons). The `SHGFI_SYSICONINDEX`
        // return value IS the `HIMAGELIST`; the dummy call with an
        // empty path gives us the handle. Empty string (not NULL)
        // ŌĆö behaviour with a null `pszPath` here is undocumented,
        // and the guard `if sys_himl != 0` below covers the failure
        // path either way, but the empty-string form is what the
        // MSDN example uses.
        let mut sfi = SHFILEINFOW::default();
        let sys_himl = SHGetFileInfoW(
            w!(""),
            windows::Win32::Storage::FileSystem::FILE_ATTRIBUTE_NORMAL,
            Some(&raw mut sfi),
            std::mem::size_of::<SHFILEINFOW>() as u32,
            SHGFI_SYSICONINDEX | SHGFI_SMALLICON | SHGFI_USEFILEATTRIBUTES,
        ) as isize;
        if sys_himl != 0 {
            SendMessageW(
                workspace_tree_hwnd,
                TVM_SETIMAGELIST,
                Some(WPARAM(TVSIL_NORMAL as usize)),
                Some(LPARAM(sys_himl)),
            );
        }
        // "Unfold All" overlay controls ŌĆö a marquee progress bar
        // and a "Expanding folders: N" STATIC. Both start hidden;
        // they take the tree's place during the async walk so the
        // per-tick tree repaint isn't visible (tree paints only
        // once, at the end, showing the final expanded state).
        let workspace_unfold_progress = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("msctls_progress32"),
            PCWSTR::null(),
            WS_CHILD | style_bits(PBS_MARQUEE as i32),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let workspace_unfold_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | style_bits((SS_CENTER | SS_CENTERIMAGE) as i32),
            0,
            0,
            0,
            0,
            Some(workspace_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;

        // Document Map panel + splitter. Symmetric with the
        // workspace panel above but positioned at the right edge
        // by `layout_children`. Both start hidden; toggled by
        // the View ŌåÆ Document Map menu, the docmap toolbar
        // button, or session restore.
        register_docmap_classes();
        let docmap_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            DOCMAP_PANEL_CLASS,
            PCWSTR::null(),
            WS_CHILD | WS_CLIPCHILDREN,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let docmap_splitter_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            DOCMAP_SPLITTER_CLASS,
            PCWSTR::null(),
            WS_CHILD,
            0,
            0,
            0,
            0,
            Some(main_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        // In-panel header chrome for the docmap. Frame FIRST for
        // the same z-order rationale as the workspace header
        // (later siblings paint above earlier siblings, so the
        // etched frame sits behind the label + close-├Ś).
        let docmap_header_frame = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE | style_bits(SS_ETCHEDFRAME as i32),
            0,
            0,
            0,
            0,
            Some(docmap_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let docmap_header_label = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("Document Map"),
            WS_CHILD | WS_VISIBLE | style_bits(SS_CENTERIMAGE as i32),
            0,
            0,
            0,
            0,
            Some(docmap_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let docmap_close_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("\u{2715}"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_PUSHBUTTON),
            0,
            0,
            0,
            0,
            Some(docmap_hwnd),
            Some(HMENU(IDC_DOCMAP_CLOSE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )?;
        // Miniature Scintilla view inside the docmap panel body.
        // Bound to the active tab's document via
        // `SCI_SETDOCPOINTER` ŌĆö the two views share the same
        // `Document`, so text stays in sync without any
        // duplication. Read-only + no caret + no scrollbars + no
        // margins + heavy zoom-out give the "aerial view" look
        // Notepad++'s Document Map ships with.
        let docmap_scintilla_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            SCINTILLA_CLASS,
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE,
            0,
            0,
            0,
            0,
            Some(docmap_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        // Direct-call pointers for the map view. Same shape as
        // the main-editor path above ŌĆö a null return from either
        // `SCI_GETDIRECTFUNCTION` or `SCI_GETDIRECTPOINTER` is
        // fatal: the map view can't operate without them and the
        // codebase's editor abstraction requires the pair.
        let docmap_direct_fn_lr =
            SendMessageW(docmap_scintilla_hwnd, SCI_GETDIRECTFUNCTION, None, None);
        let docmap_direct_ptr_lr =
            SendMessageW(docmap_scintilla_hwnd, SCI_GETDIRECTPOINTER, None, None);
        if docmap_direct_fn_lr.0 == 0 || docmap_direct_ptr_lr.0 == 0 {
            return Err(windows::core::Error::new(
                E_FAIL,
                "docmap Scintilla returned null SCI_GETDIRECTFUNCTION/SCI_GETDIRECTPOINTER",
            ));
        }
        let docmap_direct_fn: ScintillaDirectFunction = std::mem::transmute(docmap_direct_fn_lr.0);
        let docmap_direct_ptr = docmap_direct_ptr_lr.0 as *mut c_void;
        let docmap_editor =
            EditorHandle::new(docmap_scintilla_hwnd.0, docmap_direct_fn, docmap_direct_ptr);
        // One-time map-view configuration. All of these are
        // Scintilla view-level settings (per-`ViewStyle`) that
        // survive doc-pointer swaps, so we set them once at
        // creation and every subsequent `SCI_SETDOCPOINTER`
        // rebind (see [`sync_docmap_to_active_tab`]) inherits
        // them unchanged.
        //
        // Read-only blocks user-initiated edits through the
        // shared document ŌĆö a keystroke while the map has focus
        // would otherwise mutate the buffer the main editor is
        // also bound to. Invisible caret hides the blinking
        // insertion point since there's nothing to insert at.
        // Both scrollbars stay hidden ŌĆö the map is a
        // fixed-height overview, not a scrollable pane. Every
        // margin (line-number, symbol, fold) collapses to zero
        // so the miniature view uses its full width for content.
        // Zoom `-10` shrinks the font to the smallest legible
        // block-shape that still hints at text density ŌĆö matches
        // N++'s default map font size.
        docmap_editor.send(SCI_SETREADONLY, 1, 0);
        docmap_editor.send(SCI_SETCARETSTYLE, CARETSTYLE_INVISIBLE, 0);
        docmap_editor.send(SCI_SETHSCROLLBAR, 0, 0);
        docmap_editor.send(SCI_SETVSCROLLBAR, 0, 0);
        docmap_editor.send(SCI_SETMARGINWIDTHN, 0, 0);
        docmap_editor.send(SCI_SETMARGINWIDTHN, 1, 0);
        docmap_editor.send(SCI_SETMARGINWIDTHN, 2, 0);
        docmap_editor.send(SCI_SETZOOM, -10_isize as usize, 0);
        // Viewport highlight paint is done by our own WM_PAINT
        // subclass proc ŌĆö see [`docmap_scintilla_subclass_proc`].
        // Scintilla's built-in indicators are range-based
        // (per-subline paint at glyph resolution), which at the
        // map view's zoom of -10 makes every line ~2-3 px tall.
        // A per-line box outline covers the entire line at that
        // scale, producing the "everything's orange" result the
        // earlier iterations landed on. Custom GDI drawing of a
        // SINGLE rectangle across the full highlight range ŌĆö
        // top of the first visible line to bottom of the last ŌĆö
        // is the only way to get the clean bounding-box look
        // Notepad++'s Document Map paints (which uses the same
        // custom-overlay technique).
        // Subclass the map's Scintilla so mouse events reach us
        // BEFORE Scintilla's own handler (which would start a
        // text-selection drag on the read-only view ŌĆö pointless
        // and would interfere with the map's own scroll-drag
        // gesture). Same failure mode as
        // `SetWindowSubclass(tab_hwnd, ...)` above: BOOL return,
        // near-impossible failure at OOM, degrades to
        // no-drag-to-scroll if it fails but no crash. Removed
        // implicitly at Scintilla control destruction ŌĆö no
        // teardown hook needed.
        let _ = SetWindowSubclass(
            docmap_scintilla_hwnd,
            Some(docmap_scintilla_subclass_proc),
            DOCMAP_SCINTILLA_SUBCLASS_ID,
            0,
        );

        // Header chrome inside the dock ŌĆö a status STATIC on the
        // left for "X matches in Y files" and a close-X button on
        // the right. Both are visible from creation; the dock's
        // own visibility gates them.
        let fif_dock_status = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR::null(),
            WS_CHILD | WS_VISIBLE,
            0,
            0,
            0,
            0,
            Some(fif_dock_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        let fif_dock_close = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            // Multiplication-sign U+2715 reads as a close glyph at
            // small sizes without needing a custom-drawn button or
            // an icon resource.
            w!("\u{2715}"),
            WS_CHILD | WS_VISIBLE | style_bits(BS_PUSHBUTTON),
            0,
            0,
            0,
            0,
            Some(fif_dock_hwnd),
            Some(HMENU(IDC_FIF_DOCK_CLOSE as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )?;

        // Listview inside the dock (m4 step 4b). Visible from
        // creation so the dock's first show flashes results
        // immediately rather than after a separate paint cycle.
        // The dock itself stays hidden (WS_CHILD only); this child
        // is only visible when the dock is.
        let fif_listview_hwnd = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            WC_LISTVIEWW,
            PCWSTR::null(),
            WS_CHILD
                | WS_VISIBLE
                | WS_TABSTOP
                | style_bits((LVS_REPORT | LVS_SHOWSELALWAYS | LVS_SINGLESEL) as i32),
            0,
            0,
            0,
            0,
            Some(fif_dock_hwnd),
            None,
            Some(instance.into()),
            None,
        )?;
        // Full-row select + double-buffering for smooth scroll.
        SendMessageW(
            fif_listview_hwnd,
            LVM_SETEXTENDEDLISTVIEWSTYLE,
            Some(WPARAM(0)),
            Some(LPARAM(
                (LVS_EX_FULLROWSELECT | LVS_EX_DOUBLEBUFFER) as isize,
            )),
        );
        // Insert the three columns. Widths chosen for a 900-px
        // initial main-window width (default `CreateWindowExW` size
        // in `run`); the user can resize each header independently
        // post-search.
        for (i, (title, width)) in [("File", 360_i32), ("Line", 70_i32), ("Match", 480_i32)]
            .iter()
            .enumerate()
        {
            let mut text: Vec<u16> = title.encode_utf16().chain(std::iter::once(0)).collect();
            let col = LVCOLUMNW {
                mask: LVCF_FMT | LVCF_TEXT | LVCF_WIDTH,
                fmt: LVCFMT_LEFT,
                cx: *width,
                pszText: PWSTR(text.as_mut_ptr()),
                cchTextMax: text.len() as i32,
                ..Default::default()
            };
            SendMessageW(
                fif_listview_hwnd,
                LVM_INSERTCOLUMNW,
                Some(WPARAM(i)),
                Some(LPARAM(&raw const col as isize)),
            );
        }

        // Capture the direct-call pair.
        let direct_fn_lr = SendMessageW(scintilla_hwnd, SCI_GETDIRECTFUNCTION, None, None);
        let direct_ptr_lr = SendMessageW(scintilla_hwnd, SCI_GETDIRECTPOINTER, None, None);
        if direct_fn_lr.0 == 0 || direct_ptr_lr.0 == 0 {
            return Err(windows::core::Error::new(
                E_FAIL,
                "Scintilla returned null SCI_GETDIRECTFUNCTION/SCI_GETDIRECTPOINTER",
            ));
        }
        let direct_fn: ScintillaDirectFunction = std::mem::transmute(direct_fn_lr.0);
        let direct_ptr = direct_ptr_lr.0 as *mut c_void;
        let editor = EditorHandle::new(scintilla_hwnd.0, direct_fn, direct_ptr);

        // Horizontal scroll: by default Scintilla seeds scrollWidth
        // at 2000 px and never shrinks it, so the user can scroll
        // far past the end of any visible line into empty space.
        // Width tracking (SCI_SETSCROLLWIDTHTRACKING(1)) tells
        // Scintilla to recompute scrollWidth as the longest visible
        // line, with `SCI_SETSCROLLWIDTH(1)` seeding the starting
        // value at 1 px so the first paint doesn't carry the 2000
        // default forward. Together: horizontal scrollbar only
        // appears when content actually overflows, and scrolling
        // stops at the real end of the longest line.
        editor.send(SCI_SETSCROLLWIDTH, 1, 0);
        editor.send(SCI_SETSCROLLWIDTHTRACKING, 1, 0);

        // Line-number margin: configure once here so it appears on
        // the first paint, then `apply_default_styles` (called on
        // every language switch) re-applies `STYLE_LINENUMBER`
        // colours that `SCI_STYLECLEARALL` clobbers. The margin's
        // width is a fixed `LINE_NUMBER_MARGIN_PX` and doesn't
        // change between calls.
        apply_line_number_margin(&editor);

        // Caret-line highlight: paints the line containing the
        // caret in `BG_CARET_LINE`. Lives on view state, not on
        // a style index, so one call here is enough ŌĆö survives
        // `SCI_STYLECLEARALL` and the per-language re-styling
        // that `apply_default_styles` triggers.
        apply_caret_line_highlight(&editor);

        // Change-history strip: configure the dedicated narrow
        // margin (type/width/mask + the `SC_MARKNUM_HISTORY_MODIFIED`
        // marker's symbol + colour). Margin settings live on the
        // view, so this single call covers every tab. The
        // per-document enable below covers the implicit doc the
        // Scintilla control creates at construction; subsequent
        // documents minted via `SCI_CREATEDOCUMENT` get the same
        // treatment at their respective creation sites.
        apply_change_history_margin(&editor);
        enable_change_history(&editor);

        // Brace-match visual: initialise STYLE_BRACELIGHT (34) and
        // STYLE_BRACEBAD (35) with the N++ red/dark-red palette. The
        // SCN_UPDATEUI handler then paints the caret's bracket + its
        // mate (or the caret's bracket alone when unmatched) as the
        // cursor moves.
        apply_brace_styles(&editor);

        // Indent-guide visual: initialise STYLE_INDENTGUIDE (37) with
        // N++'s light-grey (`#BEBEBE`) so the vertical dotted guide
        // lines are readable when the user toggles them on via the
        // toolbar. STYLE_INDENTGUIDE lives in the 32-39 predefined
        // range that `SCI_STYLECLEARALL` resets, so this must also
        // fire from the tail of `apply_default_styles` ŌĆö same
        // re-application pattern as line-number and brace styles.
        apply_indent_guide_style(&editor);

        // Tab-width + implicit indent-level width for the indent-
        // guide algorithm on the initial implicit document. Per-
        // document Scintilla state (see `apply_tab_width` doc), so
        // subsequent `SCI_CREATEDOCUMENT` sites in `activate_tab`
        // and elsewhere each repeat this call. Defaults to 4 to
        // match modern-language convention; without it Scintilla
        // uses 8, which mis-draws guides on 4-space-indented code.
        apply_tab_width(&editor);

        // EOL mode for the initial implicit document. Per-document
        // Scintilla state (see `apply_eol_mode` doc). Subsequent
        // tab activations pass their authoritative eol through
        // `update_status`, which re-applies via `apply_eol_mode`.
        // Without this initial call the implicit doc holds
        // Scintilla's built-in CRLF default on Windows before the
        // first real tab loads ŌĆö visible only if the user typed
        // into the pre-first-tab implicit doc, but harmless to
        // pin defensively.
        apply_eol_mode(&editor, Eol::default());

        // Fold margin GEOMETRY: allocate margin index 2, install the
        // box-style markers, set colours, enable automatic click-
        // toggle and auto-expand-on-edit. Must run AFTER
        // `apply_change_history_margin` ŌĆö that function's defensive
        // `set_margin_mask(1..=3, 0)` loop would otherwise wipe our
        // mask right back to zero. The fold *classifier* property
        // (`fold=1`) is issued per-language in `apply_lang` because
        // it lives on the lexer instance, which doesn't exist yet
        // here and gets replaced with a fresh instance on every
        // `SCI_SETILEXER`.
        apply_fold_margin(&editor);

        // Wake closure: PostMessage ourselves WM_APP_WAKE.
        // PostMessage is thread-safe ŌĆö it just enqueues a message for
        // the target window's thread, which is what we want.
        let main_hwnd_value = main_hwnd.0 as usize;
        let wake = Arc::new(move || {
            // SAFETY: HWND is just a handle ŌĆö PostMessageW only
            // enqueues a message for the target window's thread,
            // doesn't dereference. The window may have been destroyed
            // by the time wake fires; PostMessage returns FALSE in
            // that case and we ignore it. The enclosing run() body is
            // already wrapped in an unsafe block, so the closure
            // doesn't need its own.
            let _ = PostMessageW(
                Some(HWND(main_hwnd_value as *mut c_void)),
                WM_APP_WAKE,
                WPARAM(0),
                LPARAM(0),
            );
        }) as Arc<dyn Fn() + Send + Sync>;

        let mut shell = Shell::new(wake)
            .map_err(|e| windows::core::Error::new(E_FAIL, format!("shell init: {e}")))?;

        // Plugin discovery: enumerate `*.dll` candidates in the user's
        // plugins directory. **No DLL is mapped here** (DESIGN.md
        // ┬¦6.4 mandates lazy load); each candidate stays in the
        // `Pending` state until first menu touch. A non-existent
        // plugins directory is the first-run case and is not an
        // error ŌĆö `discover_plugins` returns 0 silently.
        if let Some(dir) = codepp_platform::plugins_dir() {
            match shell.discover_plugins(&dir) {
                Ok(count) => {
                    tracing::info!(plugins_dir = ?dir, count = count, "plugin candidates discovered");
                }
                Err(e) => {
                    tracing::warn!(plugins_dir = ?dir, error = %e, "plugin discovery failed");
                }
            }
        }

        // Build the initial accelerator table. Lives on
        // WindowState (rather than a `run()`-local) so plugin-
        // driven mutations (`NPPM_REMOVESHORTCUTBYCMDID`) can
        // replace the handle. The pump reads the slot fresh on
        // every iteration so a recreate inside a NPPM dispatch
        // takes effect on the very next keystroke.
        let initial_accels = build_default_accel_table();
        let initial_accel_handle: HACCEL = CreateAcceleratorTableW(&initial_accels)?;

        // Load the tab-strip save icons (blue = clean, red = dirty)
        // into 32bpp premultiplied DIB sections. Both bitmaps stay
        // alive on `WindowState` for the life of the window and are
        // freed in `WM_DESTROY`. A failure here would mean broken
        // tab paint ŌĆö `is_invalid()` on a returned HBITMAP gates
        // every paint site, so a partial failure shows blank icons
        // rather than crashing.
        let tab_bitmap_px = pick_tab_bitmap_size();
        // `pick_tab_bitmap_size` unconditionally returns HIDPI for
        // the taller [`TAB_HEIGHT_PX`] cell; the LO branch is kept
        // dormant behind the function so a future per-monitor-DPI
        // scaler can restore it without churning this call site.
        let (tab_save_blue_png, tab_save_red_png) = (PNG_TAB_SAVE_HIDPI, PNG_TAB_SAVE_DIRTY_HIDPI);
        let tab_save_blue_hbm = match toolbar::png_to_hbitmap(tab_save_blue_png) {
            Ok(h) => h,
            Err(e) => {
                tracing::warn!(error = %e, "tab-save (clean) icon decode failed; tab strip will paint without it");
                HBITMAP(core::ptr::null_mut())
            }
        };
        let tab_save_red_hbm = match toolbar::png_to_hbitmap(tab_save_red_png) {
            Ok(h) => h,
            Err(e) => {
                tracing::warn!(error = %e, "tab-save (dirty) icon decode failed; tab strip will paint without it");
                HBITMAP(core::ptr::null_mut())
            }
        };

        // Heap-allocate the WindowState. We resolve and queue the
        // initial-open path while we still own the box (i.e.
        // BEFORE installing it in `GWLP_USERDATA`), so there's
        // never a moment when both a Rust `&mut` reference into
        // the state and the raw pointer in `GWLP_USERDATA` are
        // simultaneously live. `state_from_hwnd` returns `None`
        // until the slot is filled at the bottom of this block.
        let mut state = Box::new(WindowState {
            scintilla_hwnd,
            status_hwnd,
            toolbar_hwnd,
            toolbar_image_list,
            toolbar_bitmap_px,
            tab_hwnd,
            synced_tab_count: 0,
            main_menu: menubar,
            plugin_menu,
            plugins_menu_initialized: false,
            file_menu: menus.file_menu,
            view_menu: menus.view_menu,
            encoding_menu: menus.encoding_menu,
            language_menu: menus.language_menu,
            window_menu: menus.window_menu,
            right_shortcuts_menu: menus.right_shortcuts_menu,
            find_replace_dlg: None,
            udl_editor_dlg: None,
            plugin_modeless_dialogs: Vec::new(),
            dock_dialogs: Vec::new(),
            fif_dock_hwnd,
            fif_listview_hwnd,
            fif_dock_status,
            fif_dock_close,
            fif_splitter_hwnd,
            fif_dock_visible: false,
            fif_dock_height: DEFAULT_DOCK_HEIGHT_PX,
            fif_splitter_drag: None,
            workspace_hwnd,
            workspace_splitter_hwnd,
            workspace_visible: false,
            workspace_width: DEFAULT_WORKSPACE_WIDTH_PX,
            workspace_splitter_drag: None,
            workspace_root: None,
            workspace_header_frame,
            workspace_header_label,
            workspace_close_hwnd,
            workspace_action_unfold,
            workspace_action_fold,
            workspace_action_locate,
            workspace_tree_hwnd,
            workspace_unfold_pending: Vec::new(),
            workspace_unfold_count: 0,
            workspace_unfold_progress,
            workspace_unfold_label,
            workspace_ctx_target: None,
            docmap_hwnd,
            docmap_splitter_hwnd,
            docmap_visible: false,
            docmap_width: DEFAULT_DOCMAP_WIDTH_PX,
            docmap_splitter_drag: None,
            docmap_scroll_drag: None,
            docmap_header_frame,
            docmap_header_label,
            docmap_close_hwnd,
            docmap_scintilla_hwnd,
            docmap_editor,
            fif_progress_hwnd: None,
            fif_active_job: None,
            fif_pending_results: Vec::new(),
            fif_listview_index: Vec::new(),
            fif_pending_jumps: Vec::new(),
            fif_in_buffer_counts: None,
            tab_drag: None,
            tab_save_blue_hbm,
            tab_save_red_hbm,
            tab_bitmap_px,
            tab_hover_idx: None,
            tab_hover_close_x: false,
            tab_mouse_tracking: false,
            tab_close_armed: None,
            tab_hover_pin: false,
            tab_pin_armed: None,
            editor,
            shell,
            accel_handle: initial_accel_handle,
        });

        // Resolve the initial files:
        //   1. Explicit CLI argument wins (manual override / test path).
        //      Single file ŌåÆ single open.
        //   2. Otherwise, restore *every* tab from session.xml in its
        //      stored order, then override `active_tab` to the
        //      session's recorded active index. Without the override
        //      `open_file` would always end with the last-pushed tab
        //      active, regardless of which one the user had focused
        //      before shutdown.
        if let Some(path) = initial_path {
            state.shell.open_file(path);
        } else {
            // Load every restorable tab from session.xml and dispatch
            // per variant: saved files are queued for async open via
            // the loader (same path as user-initiated open); untitled
            // buffers are recreated synchronously with their backup
            // text already in place. Iterating entries in session
            // order keeps the user's tab arrangement intact (saved
            // files interleaved with untitled buffers).
            let entries = state.shell.load_session_entries();
            for entry in entries {
                match entry {
                    SessionRestoreEntry::OpenFile(p) => {
                        state.shell.open_file(p);
                    }
                    SessionRestoreEntry::UntitledFromBackup {
                        untitled_seq,
                        text,
                        cursor,
                        encoding,
                        eol,
                        backup_modified_externally,
                        custom_name,
                        lang,
                        pinned,
                    } => {
                        // `restore_untitled_with_text` needs a
                        // `&mut UiPlatform` to allocate the Scintilla
                        // doc and seed it with the backup text.
                        // Split off a fresh `Win32Ui` view here
                        // exactly the way the wnd_proc dispatch
                        // does ŌĆö avoids holding both a `&mut Shell`
                        // and a parallel `&mut WindowState` borrow.
                        let (shell, mut ui) = state.split();
                        shell.restore_untitled_with_text(
                            &mut ui,
                            untitled_seq,
                            text,
                            cursor,
                            encoding,
                            eol,
                            backup_modified_externally,
                            custom_name,
                            lang,
                            pinned,
                        );
                    }
                    SessionRestoreEntry::DirtyFromBackup {
                        path,
                        text,
                        cursor,
                        encoding,
                        eol,
                        disk_changed_externally,
                        backup_modified_externally,
                        lang,
                        pinned,
                    } => {
                        // Same shape as the Untitled branch: split
                        // off a UiPlatform handle, seed the new
                        // tab with the backup text, leave the
                        // buffer dirty so the user sees the
                        // unsaved-edits glyph. The two flags
                        // route independent warnings through
                        // `Shell.deferred_dialogs` ŌåÆ
                        // `Shell::drain` on the next pump
                        // iteration: `disk_changed_externally`
                        // triggers a reload prompt; the new
                        // `backup_modified_externally` triggers
                        // an Error dialog when the recovery file
                        // itself was edited.
                        let (shell, mut ui) = state.split();
                        shell.restore_dirty_with_text(
                            &mut ui,
                            path,
                            text,
                            cursor,
                            encoding,
                            eol,
                            disk_changed_externally,
                            backup_modified_externally,
                            lang,
                            pinned,
                        );
                    }
                }
            }
            if let Some(idx) = state.shell.session_active_index() {
                if idx < state.shell.tabs.len() {
                    state.shell.active_tab = Some(idx);
                } else {
                    // Saved active index points outside the
                    // restored tab range ŌĆö happens if a tab
                    // failed to push (e.g. `loader.open` returned
                    // None for a path, or a backup file failed
                    // to read) or if session.xml was tampered.
                    // Fall back to the most-recently-pushed tab
                    // and surface the rejection so the user has
                    // a breadcrumb if their previously-active
                    // buffer isn't the one focused.
                    tracing::warn!(
                        session_active = idx,
                        restored = state.shell.tabs.len(),
                        "session.xml active index out of range; using last-restored tab",
                    );
                }
            }
        }

        // Snapshot the FIF layout defaults from the live state so
        // the initial `layout_children` call below has a single
        // source of truth ŌĆö if the WindowState initializer ever
        // changes, the layout call follows automatically.
        let initial_dock_visible = state.fif_dock_visible;
        let initial_dock_height = state.fif_dock_height;

        // Apply the saved window geometry (or defaults) before
        // installing GWLP_USERDATA + showing. `apply_initial_window_size`
        // walks the saved-or-default ŌåÆ toolbar-floor ŌåÆ screen-clamp
        // chain and decides whether to show normally or maximized.
        // Doing this *before* the GWLP_USERDATA install means the
        // resulting `WM_SIZE` finds an empty `state_from_hwnd` and
        // skips layout ŌĆö matches the existing "explicit
        // layout_children after ShowWindow" pattern.
        let saved_geom = state.shell.saved_window_geometry();
        let show_cmd = apply_initial_window_size(main_hwnd, toolbar_hwnd, saved_geom);
        // Seed the shell's runtime cache from the saved geometry so
        // that `WM_SIZE` (which runs `track_window_geometry`) doesn't
        // wipe a perfectly-good saved value if the user closes the
        // app without resizing.
        if let Some(g) = saved_geom {
            state.shell.set_window_geometry(g);
        }

        // Apply persisted view toggles (indent guide, word wrap,
        // show-whitespace, show-EOL). Every one of these settings
        // lives on Scintilla's `ViewStyle` (per-view, not per-
        // document; verified in Editor.cxx ŌĆö `vs.viewIndentationGuides`
        // / `vs.SetWrapState` / `vs.viewWhitespace` / `vs.viewEOL`),
        // so one application at cold start covers the whole session ŌĆö
        // new tabs / doc-pointer swaps don't reset any of them. Runs
        // after `Shell::new` (so `saved_view_settings` is populated
        // from the loaded session.xml) and before window show, so the
        // very first paint already reflects the user's choices instead
        // of Scintilla's built-in off defaults.
        //
        // Wrap and whitespace both accept multi-value enums
        // (`SC_WRAP_NONE` / `SC_WRAP_WORD` / `SC_WRAP_CHAR` /
        // `SC_WRAP_WHITESPACE` on the wrap side; `SCWS_INVISIBLE` /
        // `SCWS_VISIBLEALWAYS` / `SCWS_VISIBLEAFTERINDENT` /
        // `SCWS_VISIBLEONLYININDENT` on the whitespace side), but
        // Code++'s user surface only exposes on/off, so the persisted
        // bool round-trips as {0, 1} ŌĆö matches the semantics of every
        // ID_VIEW_* toggle handler below.
        let saved_view = state.shell.saved_view_settings();
        state.editor.send(
            SCI_SETINDENTATIONGUIDES,
            if saved_view.indent_guide {
                SC_IV_LOOKBOTH
            } else {
                SC_IV_NONE
            },
            0,
        );
        state
            .editor
            .send(SCI_SETWRAPMODE, usize::from(saved_view.word_wrap), 0);
        state
            .editor
            .send(SCI_SETVIEWWS, usize::from(saved_view.show_whitespace), 0);
        state
            .editor
            .send(SCI_SETVIEWEOL, usize::from(saved_view.show_eol), 0);

        // Seed STYLE_DEFAULT from styles.xml (font face, size,
        // bold / italic / underline, fg, bg) and apply transparency
        // *after* session restore has populated tabs but *before*
        // the GWLP_USERDATA install + window show. This way the
        // very first paint already reflects the user's configured
        // appearance ŌĆö without it, a saved Consolas / dark-grey-on-
        // light-grey config would briefly flash as Scintilla's
        // built-in defaults before settling.
        //
        // `apply_default_style`'s `style_clear_all` propagates
        // STYLE_DEFAULT to every style index, which also wipes
        // any per-style fg colours an earlier synchronous
        // `apply_lang` installed (via
        // `restore_dirty_with_text` for DirtyFromBackup tabs or
        // `restore_untitled_with_text` for UntitledFromBackup
        // tabs ŌĆö both call `apply_lang` synchronously during
        // session restore). Re-apply lang for the active tab so
        // the lexer's theme layers back on top of the new
        // default. For OpenFile tabs the later async load
        // completion will call `apply_lang` again ŌĆö harmless
        // redundancy, no visible flicker since we haven't
        // shown the window yet.
        {
            let (shell, mut ui) = state.split();
            ui.apply_default_style(&shell.styles);
            let active_lang = shell.active().map_or(codepp_core::lang::L_TEXT, |t| t.lang);
            ui.apply_lang(active_lang);
        }

        // Append the loaded UDL entries as flat top-level items
        // at the bottom of the Language menu (right below the
        // "User-Defined language" submenu entry, matching N++'s
        // layout so a click on a loaded UDL is one hover-and-
        // click rather than two). `build_language_menu` built
        // the top-level menu structure and the fixed-action
        // submenu during window construction (Shell didn't
        // exist yet ŌĆö the UDL registry is populated by
        // `Shell::new`'s scan of `<config_dir>/userDefineLangs/`
        // which just ran above). Append now on the UI thread,
        // before the window is shown, so the very first user
        // drop-down of the Language menu already shows every
        // loaded UDL. Cheap: one `AppendMenuW` per entry,
        // registry capped at [`MAX_UDL_SCAN_ENTRIES`].
        //
        // SAFETY: `state.language_menu` is the live top-level
        // Language HMENU returned by `build_language_menu` and
        // still owned by the top-level menu bar (installed via
        // `SetMenu` on the main HWND above); the call runs on
        // the UI thread that just created it. Enclosing block
        // is already unsafe.
        append_udls_to_menu(state.language_menu, &state.shell.udl_registry);

        // Box now finalized. Install the raw pointer in GWLP_USERDATA;
        // the Box is reclaimed in WM_DESTROY.
        let state_ptr = Box::into_raw(state);
        SetWindowLongPtrW(main_hwnd, GWLP_USERDATA, state_ptr as isize);

        // Wake the message pump so any deferred dialogs queued
        // during session restore (currently only the
        // external-edit reload prompt for `DirtyFromBackup` tabs
        // whose disk file changed during the recovery window)
        // surface on the first WM_APP_WAKE iteration. Without
        // this, a session that restored only untitled and
        // dirty-from-backup tabs would have no async loader
        // event to trigger a drain, and the deferred prompt
        // would sit in the queue until the user did something
        // that fired one.
        let _ = PostMessageW(Some(main_hwnd), WM_APP_WAKE, WPARAM(0), LPARAM(0));

        // Drag-drop: tell Windows our window accepts files.
        DragAcceptFiles(main_hwnd, true);

        // Periodic auto-save timer. Fires `WM_TIMER` every
        // `AUTOSAVE_INTERVAL_MS` on the main window's message queue;
        // the wnd_proc's `WM_TIMER` arm dispatches a full
        // `Shell::save_session` so unsaved buffers and dirty saved-
        // file edits are persisted continuously, not only on clean
        // shutdown. `WM_DESTROY` calls `KillTimer` to release the
        // timer slot before the window goes away. A `0` return from
        // `SetTimer` means failure (out of timer handles ŌĆö extremely
        // rare); we log and carry on, since the shutdown save is
        // still in place as a fallback.
        if SetTimer(
            Some(main_hwnd),
            AUTOSAVE_TIMER_ID,
            AUTOSAVE_INTERVAL_MS,
            None,
        ) == 0
        {
            tracing::warn!("SetTimer for auto-save failed; relying on shutdown save only");
        }

        // Show + size + focus.
        let _ = ShowWindow(main_hwnd, show_cmd);
        let mut rect = RECT::default();
        GetClientRect(main_hwnd, &raw mut rect)?;
        layout_children(
            toolbar_hwnd,
            toolbar::toolbar_height_px(toolbar_bitmap_px),
            tab_hwnd,
            scintilla_hwnd,
            status_hwnd,
            fif_splitter_hwnd,
            fif_dock_hwnd,
            initial_dock_visible,
            initial_dock_height,
            // Tab strip is visible by default ŌĆö the only path that
            // hides it is `NPPM_HIDETABBAR`, which can't fire
            // before `WM_APP_WAKE`.
            false,
            WorkspaceLayout {
                panel: workspace_hwnd,
                splitter: workspace_splitter_hwnd,
                visible: false,
                width: DEFAULT_WORKSPACE_WIDTH_PX,
            },
            DocMapLayout {
                panel: docmap_hwnd,
                splitter: docmap_splitter_hwnd,
                visible: false,
                width: DEFAULT_DOCMAP_WIDTH_PX,
            },
            rect.right,
            rect.bottom,
        );
        // Cold-start restore: if the previous session had the
        // workspace panel open, pop it back up at the same root
        // and width. Runs AFTER the initial layout so
        // `show_workspace_panel`'s own layout call correctly
        // undoes the hardcoded `visible: false` above; both
        // layouts happen before the message pump starts, so
        // the user sees the final (with-panel) state on the
        // first paint, not a flash of editor-full-width then
        // panel-slides-in.
        apply_saved_workspace(main_hwnd);
        apply_saved_docmap(main_hwnd);
        // Seed the map view with the active tab's document so
        // the miniature view isn't blank on first paint. Runs
        // regardless of `docmap_visible` ŌĆö the panel might be
        // hidden but toggling it on later shouldn't require a
        // fresh sync (though `show_docmap_panel` re-syncs
        // defensively either way; the redundant call is cheap).
        sync_docmap_to_active_tab(main_hwnd);
        let _ = SetFocus(Some(scintilla_hwnd));

        // Initial toolbar-state sync. Without this the first paint
        // shows Undo/Redo enabled (TBSTATE_ENABLED is the default
        // for non-greyed M2 buttons), but the empty buffer can
        // neither undo nor redo ŌĆö flip them to the correct greyed
        // state up front. SCN_UPDATEUI will keep them in sync from
        // the next user action onwards.
        toolbar::refresh_state(toolbar_hwnd, &editor);

        // First-run / empty-session fallback: if neither a CLI path
        // nor a stored session populated any tabs, pop a fresh
        // untitled buffer so the user lands on a typable editor
        // instead of an empty chrome. The "always at least one tab"
        // invariant matches Notepad++'s behaviour and what the
        // close paths enforce. Done AFTER `SetWindowLongPtrW` above
        // so `state_from_hwnd` (used by `ensure_one_tab` ŌåÆ
        // `refresh_tab_chrome`) resolves to the freshly-installed
        // pointer; before this point the GWLP_USERDATA is still
        // zero and the helper would no-op.
        ensure_one_tab(main_hwnd);

        // Accelerator table. We route through `TranslateAcceleratorW`
        // rather than handling `WM_KEYDOWN` in the wnd_proc because
        // Scintilla owns keyboard focus while the user types, so a
        // parent-side WM_KEYDOWN never fires for editor keystrokes.
        // The accelerator table is queried before
        // `TranslateMessage`/`DispatchMessageW`, posting a WM_COMMAND
        // to the main window without depending on focus.
        //
        // **Scintilla-native shortcuts are deliberately absent.**
        // Scintilla's own keyboard table already binds Ctrl+X / C /
        // V / Z / Y / A to its built-in cut/copy/paste/undo/redo/
        // selectall implementations. If we register them as
        // accelerators, TranslateAcceleratorW intercepts the
        // keypress before Scintilla sees it and hands the work back
        // through a WM_COMMAND round-trip ŌĆö same end result on the
        // happy path, but it's a duplicate code path that surfaces
        // odd glitches under heavy keyboard activity (the
        // user-observed "Ctrl+V sometimes doesn't paste, second
        // attempt works" was traced to this duplication). The menu
        // items still display the shortcut hint (`\tCtrl+X`) and
        // mouse clicks on them fire WM_COMMAND ŌåÆ editor.send(SCI_*),
        // so menu and keyboard each have a single, well-defined
        // path that doesn't fight with the other.
        //
        // The table covers only the commands Scintilla doesn't
        // already bind natively:
        //   - File: New (Ctrl+N), Open (Ctrl+O), Save (Ctrl+S),
        //     Save As (Ctrl+Shift+S), Close (Ctrl+W).
        //   - Search: Find / Replace / Find-in-Files / Goto Line.
        //   - View: Zoom In / Zoom Out / Restore Zoom.
        //
        // The pump reads `state.accel_handle` fresh on every
        // iteration so plugin-driven mutations
        // (`NPPM_REMOVESHORTCUTBYCMDID` and friends) take effect
        // on the very next keystroke. The handle stored on
        // `WindowState` is the one updated when the table is
        // rebuilt; this initial creation seeds it.

        // Standard message loop with accelerator translation.
        // The Find/Replace dialog is modeless, so its messages must
        // pass through `IsDialogMessageW` BEFORE the accelerator
        // table ŌĆö otherwise Tab / Enter / Esc / mnemonic handling
        // inside the dialog would be intercepted by the main
        // window's accelerators (Ctrl+F especially) and never reach
        // the dialog's controls.
        let mut msg = MSG::default();
        loop {
            let ret = GetMessageW(&raw mut msg, None, 0, 0);
            match ret.0 {
                0 => break,
                -1 => return Err(windows::core::Error::from_thread()),
                _ => {
                    // Extract the dialog HWND as a Copy value and
                    // drop the WindowState borrow BEFORE calling
                    // IsDialogMessageW. IsDialogMessageW dispatches
                    // synchronously into the dialog's wnd_proc,
                    // which can re-enter `state_from_hwnd(main_hwnd)`
                    // (e.g. Replace All routing through Shell). If
                    // the outer borrow were still alive at that
                    // point we'd produce two `&mut WindowState`
                    // referring to the same slot ŌĆö aliasing UB.
                    // Pull the dialog handle AND the live HACCEL
                    // out of `WindowState` in the same `&mut`
                    // borrow scope, then drop the borrow before
                    // any synchronous re-entry. Reading the
                    // accel_handle fresh each iteration is what
                    // makes plugin-driven mutations
                    // (`NPPM_REMOVESHORTCUTBYCMDID`) take effect
                    // on the next keystroke without restarting
                    // the message loop ŌĆö the handle on
                    // `WindowState` is the one the recreate path
                    // updates.
                    // Pull the dialog handles, the live HACCEL,
                    // AND a snapshot of the plugin-registered
                    // modeless dialogs out of `WindowState` in
                    // the same `&mut` borrow scope, then drop
                    // the borrow before any synchronous re-entry.
                    // The Vec is `clone()`-d (cheap ŌĆö typically
                    // 0..2 entries) so the iteration below holds
                    // no borrow on `WindowState`; an
                    // `IsDialogMessageW` call that re-enters
                    // wnd_proc and triggers a NPPM dispatch is
                    // free to mutate `plugin_modeless_dialogs`
                    // without aliasing the local snapshot.
                    let (dlg_handle, udl_editor_handle, haccel, plugin_dlgs): (
                        Option<HWND>,
                        Option<HWND>,
                        HACCEL,
                        Vec<HWND>,
                    ) = state_from_hwnd(main_hwnd).map_or(
                        (None, None, HACCEL::default(), Vec::new()),
                        |s| {
                            (
                                s.find_replace_dlg,
                                s.udl_editor_dlg,
                                s.accel_handle,
                                s.plugin_modeless_dialogs.clone(),
                            )
                        },
                    );
                    let mut handled = false;
                    if let Some(dlg) = dlg_handle {
                        if IsWindow(Some(dlg)).as_bool()
                            && IsDialogMessageW(dlg, &raw const msg).as_bool()
                        {
                            handled = true;
                        }
                    }
                    // UDL editor modeless dialog (Phase 4.6 m3b).
                    // Route Tab / Enter / mnemonic keystrokes so
                    // the modal keyboard-nav behaves like every
                    // other modeless dialog we own.
                    if !handled {
                        if let Some(dlg) = udl_editor_handle {
                            if IsWindow(Some(dlg)).as_bool()
                                && IsDialogMessageW(dlg, &raw const msg).as_bool()
                            {
                                handled = true;
                            }
                        }
                    }
                    // Plugin-registered modeless dialogs after
                    // the host's Find/Replace dialog so a plugin
                    // can't shadow the host's keyboard handling
                    // by registering a wrapper HWND. Each dialog
                    // is checked for `IsWindow` before
                    // `IsDialogMessageW` because plugins might
                    // forget to REMOVE before destroying ŌĆö the
                    // guard turns a freed-handle race into a
                    // clean miss instead of a UB read.
                    //
                    // Track which dialogs are dead so we can
                    // evict them from `plugin_modeless_dialogs`
                    // after iteration. Without eviction, a
                    // misbehaving plugin that ADDs without
                    // REMOVE causes the Vec to grow without
                    // bound ŌĆö each leaked HWND adds one extra
                    // `IsWindow` call per keystroke. The
                    // eviction is best-effort: a recycled
                    // handle that `IsWindow` reports as alive
                    // (a known Win32 hazard the upstream contract
                    // also inherits) stays in the Vec.
                    let mut dead_indices: Vec<usize> = Vec::new();
                    if handled {
                        // Even on the host-Find/Replace-handled
                        // path, run the dead-handle scan so a
                        // single iteration where the host dialog
                        // consumed the message still cleans up
                        // any orphans the plugin Vec accumulated.
                        for (idx, dlg) in plugin_dlgs.iter().enumerate() {
                            if !IsWindow(Some(*dlg)).as_bool() {
                                dead_indices.push(idx);
                            }
                        }
                    } else {
                        for (idx, dlg) in plugin_dlgs.iter().enumerate() {
                            if !IsWindow(Some(*dlg)).as_bool() {
                                dead_indices.push(idx);
                                continue;
                            }
                            if IsDialogMessageW(*dlg, &raw const msg).as_bool() {
                                handled = true;
                                break;
                            }
                        }
                    }
                    if !dead_indices.is_empty() {
                        if let Some(state) = state_from_hwnd(main_hwnd) {
                            // Evict by HWND value (the indices
                            // are local to `plugin_dlgs`, but the
                            // live Vec on `state` may have been
                            // mutated by a re-entrant
                            // NPPM_MODELESSDIALOG dispatch
                            // between the snapshot and now).
                            let dead_hwnds: Vec<HWND> =
                                dead_indices.iter().map(|i| plugin_dlgs[*i]).collect();
                            state
                                .plugin_modeless_dialogs
                                .retain(|h| !dead_hwnds.iter().any(|d| d.0 == h.0));
                        }
                    }
                    if !handled && TranslateAcceleratorW(main_hwnd, haccel, &raw const msg) == 0 {
                        let _ = TranslateMessage(&raw const msg);
                        DispatchMessageW(&raw const msg);
                    }
                }
            }
        }
        Ok(())
    }
}

/// Layout children: tab strip across the top, status bar at the
/// bottom, Scintilla fills the remainder.
///
/// SAFETY: caller must hold valid HWNDs for the four windows.
/// Authoritative clamp for the FIF dock height. Single source of
/// truth shared by `layout_children` (which applies the clamp to
/// the persisted height on every layout) and `splitter_wnd_proc`
/// (which applies it on every drag-move). When `layout_children`
/// goes DPI-aware, this helper is the only spot that needs the
/// `TAB_HEIGHT_PX` / `STATUS_HEIGHT_PX` substitutions ŌĆö the drag
/// handler picks up the change for free.
fn clamp_dock_height(client_height: i32, toolbar_height: i32, requested: i32) -> i32 {
    let mid = (client_height - toolbar_height - TAB_HEIGHT_PX - STATUS_HEIGHT_PX).max(0);
    let usable = mid.saturating_sub(SPLITTER_HEIGHT_PX);
    // `(usable - MIN_SCINTILLA_HEIGHT_PX).max(MIN_DOCK_HEIGHT_PX)`
    // collapses to `MIN_DOCK_HEIGHT_PX` on a window crushed below
    // the splitter's minimums ŌĆö `clamp(MIN, MIN)` then renders the
    // dock at exactly `MIN_DOCK_HEIGHT_PX` rather than panicking
    // on a low > high range.
    let upper = (usable - MIN_SCINTILLA_HEIGHT_PX).max(MIN_DOCK_HEIGHT_PX);
    requested.clamp(MIN_DOCK_HEIGHT_PX, upper)
}

/// Workspace-panel layout inputs bundled into a small owned
/// struct so [`layout_children`] doesn't push past clippy's
/// too-many-arguments cap. All four fields together describe
/// "how much of the client area does the left-column workspace
/// take, and which HWNDs do we position for it."
///
/// Fully populated at every call site ŌĆö the `visible: false`
/// path leaves the panel + splitter alone (they stay wherever a
/// previous `MoveWindow` left them; `ShowWindow(SW_HIDE)` toggles
/// visibility orthogonally).
#[derive(Copy, Clone)]
struct WorkspaceLayout {
    panel: HWND,
    splitter: HWND,
    visible: bool,
    width: i32,
}

/// "How much of the client area does the right-column Document
/// Map take, and which HWNDs do we position for it." Mirror of
/// [`WorkspaceLayout`] on the opposite edge.
#[derive(Copy, Clone)]
struct DocMapLayout {
    panel: HWND,
    splitter: HWND,
    visible: bool,
    width: i32,
}

#[allow(clippy::too_many_arguments)]
unsafe fn layout_children(
    toolbar: HWND,
    toolbar_height: i32,
    tabs: HWND,
    scintilla: HWND,
    status: HWND,
    splitter: HWND,
    dock: HWND,
    dock_visible: bool,
    dock_height: i32,
    tab_hidden: bool,
    workspace: WorkspaceLayout,
    docmap: DocMapLayout,
    width: i32,
    height: i32,
) {
    // Module-level `TAB_HEIGHT_PX` / `STATUS_HEIGHT_PX` carry the
    // 96-DPI defaults. `SB_GETBORDERS` / `TCM_GETITEMRECT` could
    // measure these precisely; the constants become measured
    // values once `layout_children` goes DPI-aware (Phase 4 polish
    // item).
    //
    // When the tab strip is hidden (NPPM_HIDETABBAR), it claims
    // zero height and the Scintilla view starts at y=0 ŌĆö the same
    // visual result Notepad++ produces when its own tab strip is
    // hidden. The `MoveWindow` call below still runs and keeps
    // the (already invisible via ShowWindow(SW_HIDE)) tab control
    // at full width with height=0 ŌĆö a zero-height window costs
    // nothing to keep around, and the visibility toggle stays
    // orthogonal to the layout.
    let tab_height = if tab_hidden { 0 } else { TAB_HEIGHT_PX };
    let status_height = STATUS_HEIGHT_PX;
    // Workspace column takes the left band of the mid-region
    // (between toolbar-bottom and status-bar-top). Clamped to
    // `MIN_WORKSPACE_WIDTH_PX..=(width - MIN_SCINTILLA_WIDTH_PX
    //  - WORKSPACE_SPLITTER_WIDTH_PX)` so a window-resize-down
    // that pushes past the splitter's minimums is corrected
    // here ŌĆö same idempotence rule as [`clamp_dock_height`] does
    // for the vertical splitter. When the panel is hidden the
    // column collapses to zero width and the layout math is
    // identical to the pre-workspace behaviour.
    let (workspace_col_width, editor_x_shift) = if workspace.visible {
        let clamped = clamp_workspace_width(width, workspace.width);
        (clamped, clamped + WORKSPACE_SPLITTER_WIDTH_PX)
    } else {
        (0, 0)
    };
    // Symmetric right-side accounting for the Document Map
    // panel. `docmap_col_width` is the pixel column the panel
    // eats off the right edge; `editor_x_shrink_right` is what
    // every horizontal-width calc below subtracts to keep the
    // editor / tabs / FIF dock from underlapping the map, and
    // includes the splitter band alongside the panel body so a
    // hover over the seam gets the resize cursor.
    // `clamp_docmap_width` is the same authority
    // [`apply_saved_docmap`] and the splitter drag consult, so a
    // window-resize-down that pushes past the docmap's ceiling
    // is corrected here and the layout stays idempotent (mirror
    // of `clamp_workspace_width` on the left column).
    let (docmap_col_width, editor_x_shrink_right) = if docmap.visible {
        let clamped = clamp_docmap_width(width, docmap.width);
        (clamped, clamped + DOCMAP_SPLITTER_WIDTH_PX)
    } else {
        (0, 0)
    };
    unsafe {
        // Toolbar at the very top (y=0), full width ŌĆö the workspace
        // panel starts *below* the toolbar so users can still see
        // the whole toolbar regardless of workspace state.
        let _ = MoveWindow(toolbar, 0, 0, width, toolbar_height, true);
        // Tab strip: sits above the editor, shifted right by the
        // workspace column so the workspace panel spans from just
        // below the toolbar to just above the status bar, AND
        // shrunk on the right by the docmap column so the map
        // panel spans the same vertical band on the opposite
        // edge.
        let tabs_w = (width - editor_x_shift - editor_x_shrink_right).max(0);
        let _ = MoveWindow(
            tabs,
            editor_x_shift,
            toolbar_height,
            tabs_w,
            tab_height,
            true,
        );
        let _ = MoveWindow(
            status,
            0,
            height - status_height,
            width,
            status_height,
            true,
        );
        // Workspace panel: fills the left column from toolbar-bottom
        // to status-bar-top. Splitter sits flush to its right edge.
        // Both hidden ŌåÆ `ShowWindow(SW_HIDE)` was called at panel
        // close; we still MoveWindow them so their off-screen
        // position doesn't matter if a future SW_SHOW fires.
        let ws_top = toolbar_height;
        let ws_height = (height - status_height - toolbar_height).max(0);
        if workspace.visible {
            let _ = MoveWindow(
                workspace.panel,
                0,
                ws_top,
                workspace_col_width,
                ws_height,
                true,
            );
            let _ = MoveWindow(
                workspace.splitter,
                workspace_col_width,
                ws_top,
                WORKSPACE_SPLITTER_WIDTH_PX,
                ws_height,
                true,
            );
        }
        // Docmap panel + splitter: right-column mirror of the
        // workspace pair. Splitter sits flush to the panel's
        // LEFT edge (opposite of the workspace splitter's right
        // edge). Hidden ŌåÆ skip both `MoveWindow` calls;
        // `ShowWindow(SW_HIDE)` was called at panel close.
        if docmap.visible {
            let docmap_x = (width - docmap_col_width).max(0);
            let splitter_x = (docmap_x - DOCMAP_SPLITTER_WIDTH_PX).max(0);
            let _ = MoveWindow(
                docmap.splitter,
                splitter_x,
                ws_top,
                DOCMAP_SPLITTER_WIDTH_PX,
                ws_height,
                true,
            );
            let _ = MoveWindow(
                docmap.panel,
                docmap_x,
                ws_top,
                docmap_col_width,
                ws_height,
                true,
            );
        }

        let scintilla_top = toolbar_height + tab_height;
        let mid_height = (height - status_height - tab_height - toolbar_height).max(0);

        // Inset the Scintilla view by `EDITOR_BORDER_PX` on every
        // side of its allocated cell. The parent's
        // `WM_ERASEBKGND` paints the revealed strips with
        // `editor_border_brush`, producing a four-sided delimiter
        // around the edit area on every layout pass.
        //
        // The splitter and FIF dock keep their full window-width
        // ŌĆö the splitter is itself a visual band between the
        // Scintilla view and the dock, so a border there would
        // double up with no gain. Insetting just the editor
        // proper means the visible gray frame ends at the
        // splitter (when the dock is open) or at the status bar
        // (when the dock is closed), which is the natural
        // "around the actual edit area" reading of the request.
        //
        // The editor's x-origin shifts right by `editor_x_shift`
        // (workspace column + splitter width) when the workspace
        // is shown; this keeps the editor column snug against the
        // workspace splitter without a second inset.
        let editor_x = editor_x_shift + EDITOR_BORDER_PX;
        let editor_w =
            (width - editor_x_shift - editor_x_shrink_right - 2 * EDITOR_BORDER_PX).max(0);
        let editor_y = scintilla_top + EDITOR_BORDER_PX;
        let fif_dock_x = editor_x_shift;
        let fif_dock_w = (width - editor_x_shift - editor_x_shrink_right).max(0);

        if dock_visible {
            // Authoritative clamp ŌĆö re-applies the same rule the
            // splitter drag uses, so a window-resize-down that
            // pushes past the persisted dock height is corrected
            // here and the layout stays idempotent.
            let dock_h = clamp_dock_height(height, toolbar_height, dock_height);
            let usable = mid_height.saturating_sub(SPLITTER_HEIGHT_PX);
            let scintilla_height = (usable - dock_h).max(MIN_SCINTILLA_HEIGHT_PX);
            let splitter_top = scintilla_top + scintilla_height;
            let dock_top = splitter_top + SPLITTER_HEIGHT_PX;
            let actual_dock_height = (mid_height - scintilla_height - SPLITTER_HEIGHT_PX).max(0);
            // Editor: top + left + right insets only ŌĆö the
            // splitter sits flush below it as the bottom delimiter.
            // The `- EDITOR_BORDER_PX` matches the `editor_y +=
            // EDITOR_BORDER_PX` shift above so the bottom edge
            // lands exactly at `scintilla_top + scintilla_height`
            // (i.e. flush against the splitter); without this
            // subtraction the editor would overlap the splitter
            // top by `EDITOR_BORDER_PX` pixels.
            let editor_h = (scintilla_height - EDITOR_BORDER_PX).max(0);
            let _ = MoveWindow(scintilla, editor_x, editor_y, editor_w, editor_h, true);
            let _ = MoveWindow(
                splitter,
                fif_dock_x,
                splitter_top,
                fif_dock_w,
                SPLITTER_HEIGHT_PX,
                true,
            );
            // The dock's own WM_SIZE handler positions its
            // children (status STATIC, close-X button, listview)
            // ŌĆö see `fif_dock_wnd_proc`.
            let _ = MoveWindow(
                dock,
                fif_dock_x,
                dock_top,
                fif_dock_w,
                actual_dock_height,
                true,
            );
        } else {
            // Splitter and dock are hidden ŌĆö leave them where they
            // are; ShowWindow toggles their visibility separately.
            // Editor: full inset on all four sides.
            let editor_h = (mid_height - 2 * EDITOR_BORDER_PX).max(0);
            let _ = MoveWindow(scintilla, editor_x, editor_y, editor_w, editor_h, true);
        }
    }
}

/// Clamp a requested workspace-panel width to
/// `[MIN_WORKSPACE_WIDTH_PX, upper]` where `upper` leaves room
/// for the editor's minimum plus the splitter. Analogous to
/// [`clamp_dock_height`] on the vertical axis ŌĆö a
/// window-resize-down that pushes past the horizontal splitter's
/// minimums lands here and the layout stays idempotent. Also
/// the single source of truth for the eventual splitter drag
/// (lands in m2), so a change to the minimums flows through
/// both call sites.
fn clamp_workspace_width(client_width: i32, requested: i32) -> i32 {
    let usable = client_width.saturating_sub(WORKSPACE_SPLITTER_WIDTH_PX);
    // Same `.max(MIN_WORKSPACE_WIDTH_PX)` pattern as
    // `clamp_dock_height` ŌĆö `clamp(MIN, MIN)` collapses to
    // exactly `MIN_WORKSPACE_WIDTH_PX` on a window crushed below
    // the splitter's minimums, rather than panicking on low > high.
    let upper = (usable - MIN_SCINTILLA_WIDTH_PX).max(MIN_WORKSPACE_WIDTH_PX);
    requested.clamp(MIN_WORKSPACE_WIDTH_PX, upper)
}

/// Clamp a requested docmap-panel width to
/// `[MIN_DOCMAP_WIDTH_PX, upper]` where `upper` leaves room for
/// the editor's minimum AND the docmap splitter's own 4-px band.
/// Same shape as [`clamp_workspace_width`], applied on every
/// layout pass so a persisted
/// [`codepp_core::session::DocMapSession::width`] value that was
/// saved on a wider display ŌĆö or hand-edited / crash-corrupted to
/// something wild ŌĆö can never drive `MoveWindow` with a
/// nonsensical dimension. Also enforces the invariant on cold
/// start via [`apply_saved_docmap`] and on splitter drag.
///
/// Does NOT subtract the workspace column's width. When both
/// panels are visible on a very narrow window the editor's
/// `.max(0)` guard still catches a would-be negative width
/// safely ŌĆö worst case is the editor visually squeezes to zero
/// with the two panels butting up against each other, not a
/// crash or an overlap. Coordinating the two panels'
/// simultaneous clamps against a shared editor floor is tracked
/// as a Phase 5 polish item.
fn clamp_docmap_width(client_width: i32, requested: i32) -> i32 {
    let usable = client_width.saturating_sub(DOCMAP_SPLITTER_WIDTH_PX);
    let upper = (usable - MIN_SCINTILLA_WIDTH_PX).max(MIN_DOCMAP_WIDTH_PX);
    requested.clamp(MIN_DOCMAP_WIDTH_PX, upper)
}

/// Register the FIF dock and splitter window classes. Idempotent ŌĆö
/// `RegisterClassExW` returns 0 with `ERROR_CLASS_ALREADY_EXISTS` on
/// repeat calls, which we ignore. Safe to call from `run()` before
/// `CreateWindowExW` references the class names.
unsafe fn register_fif_classes() {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();
    REGISTERED.get_or_init(|| unsafe {
        let instance = GetModuleHandleW(None).unwrap_or_default();
        // Dock: empty container, default arrow cursor, system 3D
        // face for the background so it visually delineates from
        // Scintilla above and the status bar below. The wndproc is
        // a one-line forwarder rather than `DefWindowProcW`
        // directly, because windows-rs declares `DefWindowProcW`
        // as `unsafe fn` rather than the `extern "system"`
        // signature `WNDCLASSEXW.lpfnWndProc` requires.
        let dock_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(fif_dock_wnd_proc),
            hInstance: instance.into(),
            hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: FIF_DOCK_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const dock_class);

        // Splitter: thin band that owns the resize cursor and the
        // mouse-capture drag protocol. Its background brush
        // matches the dock so the seam between them is invisible
        // until the user hovers (cursor change) ŌĆö same visual
        // affordance N++ uses.
        let splitter_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(splitter_wnd_proc),
            hInstance: instance.into(),
            // The cursor is also forced via WM_SETCURSOR so it
            // changes the moment the splitter is hovered, not
            // only after the first mouse-down. This `hCursor`
            // value is the fallback Windows uses if WM_SETCURSOR
            // isn't handled.
            hCursor: LoadCursorW(None, IDC_SIZENS).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: FIF_SPLITTER_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const splitter_class);

        // FIF progress dialog: modeless top-level window shown
        // while a search is running. Standard arrow cursor; system
        // 3D face for the background; small cap-only window styled
        // by `show_fif_progress`.
        let progress_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(fif_progress_wnd_proc),
            hInstance: instance.into(),
            hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: FIF_PROGRESS_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const progress_class);
    });
}

/// Register the workspace panel and its splitter window classes.
/// Idempotent via `OnceLock` (same pattern as
/// [`register_fif_classes`]).
///
/// # Safety
///
/// `RegisterClassExW` is pure Win32 registration; the only invariant
/// is that the `wnd_proc` pointers we hand it (`workspace_panel_wnd_proc`,
/// `workspace_splitter_wnd_proc`) live for the app's lifetime ŌĆö which
/// is trivially true for `extern "system" fn` items.
unsafe fn register_workspace_classes() {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();
    REGISTERED.get_or_init(|| unsafe {
        let instance = GetModuleHandleW(None).unwrap_or_default();
        // Panel container. Empty background painted with the shared
        // dialog-chrome brush (`dialog_bg_brush`) so the panel
        // visually reads as one continuous surface with the tab
        // strip; the header + action bar paint their own chrome on
        // top in m2. Default arrow cursor everywhere except the
        // splitter.
        let panel_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(workspace_panel_wnd_proc),
            hInstance: instance.into(),
            hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: WORKSPACE_PANEL_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const panel_class);

        // Splitter: vertical band with the horizontal-drag cursor
        // (`IDC_SIZEWE`). Background matches the panel so the seam
        // is invisible until hover reveals the cursor change ŌĆö
        // parity with the FIF splitter's affordance model.
        let splitter_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(workspace_splitter_wnd_proc),
            hInstance: instance.into(),
            hCursor: LoadCursorW(None, IDC_SIZEWE).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: WORKSPACE_SPLITTER_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const splitter_class);
    });
}

/// Register the Document Map panel + splitter window classes.
/// Idempotent via `OnceLock`, same shape as
/// [`register_workspace_classes`].
///
/// # Safety
///
/// `RegisterClassExW` invariants: the `wnd_proc` pointers we hand
/// it (`docmap_panel_wnd_proc`, `docmap_splitter_wnd_proc`) are
/// `extern "system" fn` items that live for the app's lifetime.
unsafe fn register_docmap_classes() {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();
    REGISTERED.get_or_init(|| unsafe {
        let instance = GetModuleHandleW(None).unwrap_or_default();
        let panel_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(docmap_panel_wnd_proc),
            hInstance: instance.into(),
            hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: DOCMAP_PANEL_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const panel_class);

        let splitter_class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(docmap_splitter_wnd_proc),
            hInstance: instance.into(),
            hCursor: LoadCursorW(None, IDC_SIZEWE).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: DOCMAP_SPLITTER_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const splitter_class);
    });
}

/// `Wnd_proc` for the workspace panel container. Handles:
///
///   * `WM_SIZE`: lay out the header (title + close-├Ś) and
///     action-row (three narrow buttons on the right). Body
///     (tree) space is reserved but left empty in m2 ŌĆö m3 fills
///     it with `SysTreeView32`.
///   * `WM_COMMAND`: consume the close-├Ś button and route to
///     [`hide_workspace_panel`]. Action-row clicks bubble up
///     to `main_wnd_proc` for the m3 handlers to consume.
///   * `WM_CTLCOLORSTATIC`: paint the header label's background
///     with the shared chrome brush so it visually merges into
///     the panel ŌĆö same technique as [`fif_dock_wnd_proc`].
///
/// # Safety
///
/// Standard `extern "system"` `wnd_proc` invariants ŌĆö must not
/// unwind across the FFI boundary. All bodies are `unsafe {}` at
/// the FFI point of contact and route through `state_from_hwnd`
/// under `PluginCallGuard` for parent-state access.
extern "system" fn workspace_panel_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_SIZE => {
                let width = (lparam.0 & 0xFFFF) as i32;
                let height = ((lparam.0 >> 16) & 0xFFFF) as i32;
                // Snapshot the five child HWNDs under a brief borrow,
                // drop it, then call `layout_workspace_panel_children`
                // with the snapshot. `MoveWindow(..., true)` can post
                // repaint notifications that re-enter our wnd_proc,
                // which would then reach for `state_from_hwnd` again
                // and produce two overlapping `&mut WindowState` ŌĆö
                // aliasing UB under Rust's `noalias` optimizer even
                // before behavioural bugs appear. Same discipline as
                // `fif_dock_wnd_proc`'s `WM_SIZE`.
                let hwnds = state_from_hwnd(GetParent(hwnd).unwrap_or_default()).map(|state| {
                    (
                        state.workspace_header_frame,
                        state.workspace_header_label,
                        state.workspace_close_hwnd,
                        state.workspace_action_unfold,
                        state.workspace_action_fold,
                        state.workspace_action_locate,
                        state.workspace_tree_hwnd,
                        state.workspace_unfold_progress,
                        state.workspace_unfold_label,
                    )
                });
                if let Some((
                    header_frame,
                    header_label,
                    close,
                    unfold,
                    fold,
                    locate,
                    tree,
                    unfold_progress,
                    unfold_label,
                )) = hwnds
                {
                    layout_workspace_panel_children(
                        WorkspacePanelChildren {
                            header_frame,
                            header_label,
                            close,
                            unfold,
                            fold,
                            locate,
                            tree,
                            unfold_progress,
                            unfold_label,
                        },
                        width,
                        height,
                    );
                }
                LRESULT(0)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as u16;
                let parent = GetParent(hwnd).unwrap_or_default();
                if cmd == IDC_WORKSPACE_CLOSE {
                    if !parent.0.is_null() {
                        hide_workspace_panel(parent);
                    }
                    return LRESULT(0);
                }
                // Unfold / Fold / Locate: `DefWindowProcW` does NOT
                // forward WM_COMMAND to the grandparent (main window)
                // ŌĆö Windows sends it only to the control's direct
                // parent, which is us. Explicitly re-send to
                // `main_wnd_proc` so m3's handlers there can consume
                // it. Same idiom `fif_dock_wnd_proc` uses for its
                // WM_NOTIFY bubble-up.
                if !parent.0.is_null() {
                    SendMessageW(parent, msg, Some(wparam), Some(lparam));
                }
                LRESULT(0)
            }
            WM_NOTIFY => {
                // TreeView notifications: lazy expand + double-click.
                // `lparam` is `NMHDR*` ŌĆö the header is enough to
                // dispatch on notification code. Only two codes
                // matter for m3:
                //   * `TVN_ITEMEXPANDINGW`: lazy `read_dir` when
                //     a folder is being expanded for the first time.
                //   * `NM_DBLCLK`: open file in the editor.
                //
                // Everything else falls through to `DefWindowProcW`
                // so TreeView's default expand/collapse animation
                // and keyboard handling still run.
                //
                // SAFETY: `lparam` points to a `NMHDR` (or a wider
                // notification struct that starts with `NMHDR` ŌĆö
                // guaranteed by the Windows notification ABI).
                let nmhdr = &*(lparam.0 as *const NMHDR);
                let workspace_hwnd_here = hwnd;
                let parent = GetParent(hwnd).unwrap_or_default();
                if nmhdr.code == TVN_ITEMEXPANDINGW {
                    // `TVN_ITEMEXPANDINGW` uses `NMTREEVIEWW`. The
                    // `action` field tells us expand vs collapse.
                    let ntv = &*(lparam.0 as *const NMTREEVIEWW);
                    // Only populate on expand; collapse leaves the
                    // real children in place so re-expand is instant.
                    if ntv.action == TVE_EXPAND {
                        let root = state_from_hwnd(parent).and_then(|s| s.workspace_root.clone());
                        if let (Some(state), Some(root)) = (state_from_hwnd(parent), root) {
                            let tree = state.workspace_tree_hwnd;
                            // Snapshot the tree HWND then drop the
                            // borrow before calling the populate
                            // helper ŌĆö it issues `TVM_*` sends that
                            // could re-enter through a plugin
                            // subclass one day. Same discipline as
                            // the other snapshot-then-drop sites.
                            let _ = state;
                            handle_tree_item_expanding(tree, ntv.itemNew.hItem, &root);
                        }
                    }
                    // Return 0 = allow the expand/collapse to proceed.
                    // Non-zero would suppress it (which we never want).
                    return LRESULT(0);
                }
                if nmhdr.code == NM_DBLCLK {
                    // Which control was double-clicked? Only the tree
                    // matters ŌĆö action buttons don't fire NM_DBLCLK
                    // (they use `BN_CLICKED` inside `WM_COMMAND`).
                    let tree_hwnd = state_from_hwnd(parent).map(|s| s.workspace_tree_hwnd);
                    if let Some(tree) = tree_hwnd {
                        if nmhdr.hwndFrom == tree {
                            handle_tree_double_click(parent, tree);
                            return LRESULT(0);
                        }
                    }
                }
                if nmhdr.code == NM_RCLICK {
                    // Right-click on the tree ŌåÆ show the per-node
                    // context menu (Remove / Copy path / Find in
                    // Files / Explorer here / etc.). Only fires for
                    // the tree control ŌĆö action buttons don't
                    // produce NM_RCLICK. Buffered lookup +
                    // `state_from_hwnd` re-entry pattern matches
                    // the NM_DBLCLK branch above.
                    let tree_hwnd = state_from_hwnd(parent).map(|s| s.workspace_tree_hwnd);
                    if let Some(tree) = tree_hwnd {
                        if nmhdr.hwndFrom == tree {
                            show_workspace_tree_context_menu(parent, tree);
                            return LRESULT(0);
                        }
                    }
                }
                // Fall through ŌĆö let default handling run for every
                // other notification.
                let _ = workspace_hwnd_here;
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_CTLCOLORSTATIC => LRESULT(dialog_bg_brush().0 as isize),
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// Snapshot of the workspace panel's six child HWNDs. Owned by
/// value so [`layout_workspace_panel_children`] doesn't need to
/// hold a `&mut WindowState` borrow while it issues `MoveWindow`
/// calls that could re-enter our `wnd_proc` via child repaint
/// notifications. Mirrors the snapshot-then-drop discipline the
/// FIF dock uses.
#[derive(Copy, Clone)]
struct WorkspacePanelChildren {
    /// Etched-frame STATIC that visually groups the header row.
    /// Painted first (via z-order) so `header_label` + `close`
    /// sit on top.
    header_frame: HWND,
    header_label: HWND,
    close: HWND,
    unfold: HWND,
    fold: HWND,
    locate: HWND,
    /// `SysTreeView32` filling the panel body below the action row.
    tree: HWND,
    /// Marquee progress bar overlay shown during "Unfold All".
    /// Positioned inside the tree body area, centred vertically.
    unfold_progress: HWND,
    /// Status STATIC directly below the progress bar. Shows
    /// "Expanding folders: N" during the walk.
    unfold_label: HWND,
}

/// Lay out the workspace panel's five children within its client
/// rect. Called from the panel's `WM_SIZE` handler (which
/// snapshots the child HWNDs before invoking) and from
/// [`show_workspace_panel`] via the same `WM_SIZE` cascade fired
/// by `MoveWindow` on the panel.
///
/// Row structure (top-to-bottom):
///
///   * Header (`WORKSPACE_HEADER_HEIGHT_PX`): title label left,
///     close-├Ś button pinned to the right edge.
///   * Action row (`WORKSPACE_ACTION_HEIGHT_PX`): three narrow
///     buttons on the right (unfold / fold / locate).
///   * Body: everything below ŌĆö reserved for the m3 tree view.
///
/// A negative or zero client dimension is treated as "panel
/// isn't laid out yet"; all `MoveWindow` calls run through
/// `.max(0)` clamps so a zero-height row collapses cleanly rather
/// than panicking.
///
/// # Safety
///
/// Every HWND in `children` must be live (created in `run()`,
/// destroyed only at panel/window teardown). Runs on the UI
/// thread; no cross-thread invariants.
unsafe fn layout_workspace_panel_children(
    children: WorkspacePanelChildren,
    width: i32,
    height: i32,
) {
    let inset = WORKSPACE_INSET_PX;
    let inner_left = inset;
    let inner_right = (width - inset).max(inner_left);
    let inner_width = (inner_right - inner_left).max(0);

    // Header row ŌĆö etched frame encloses title + close-├Ś as a
    // visually-grouped box. Frame spans the full header row;
    // label and close inset inside so they don't overpaint the
    // frame's border.
    let header_y = inset;
    let frame_pad = WORKSPACE_HEADER_FRAME_INSET_PX;
    let content_left = inner_left + frame_pad;
    let content_right = (inner_right - frame_pad).max(content_left);
    let close_w = WORKSPACE_CLOSE_BUTTON_WIDTH_PX;
    let close_x = (content_right - close_w).max(content_left);
    let label_w = (close_x - content_left).max(0);
    let inner_h = (WORKSPACE_HEADER_HEIGHT_PX - 2 * frame_pad).max(0);
    unsafe {
        let _ = MoveWindow(
            children.header_frame,
            inner_left,
            header_y,
            inner_width,
            WORKSPACE_HEADER_HEIGHT_PX,
            true,
        );
        let _ = MoveWindow(
            children.header_label,
            content_left,
            header_y + frame_pad,
            label_w,
            inner_h,
            true,
        );
        let _ = MoveWindow(
            children.close,
            close_x,
            header_y + frame_pad,
            close_w,
            inner_h,
            true,
        );
    }

    // Action row ŌĆö three buttons pinned to the right edge.
    let action_y = header_y + WORKSPACE_HEADER_HEIGHT_PX;
    let btn_w = WORKSPACE_ACTION_BUTTON_WIDTH_PX;
    let locate_x = (inner_right - btn_w).max(inner_left);
    let fold_x = (locate_x - btn_w).max(inner_left);
    let unfold_x = (fold_x - btn_w).max(inner_left);
    unsafe {
        let _ = MoveWindow(
            children.unfold,
            unfold_x,
            action_y,
            btn_w,
            WORKSPACE_ACTION_HEIGHT_PX,
            true,
        );
        let _ = MoveWindow(
            children.fold,
            fold_x,
            action_y,
            btn_w,
            WORKSPACE_ACTION_HEIGHT_PX,
            true,
        );
        let _ = MoveWindow(
            children.locate,
            locate_x,
            action_y,
            btn_w,
            WORKSPACE_ACTION_HEIGHT_PX,
            true,
        );
    }
    // Body region ŌĆö the `SysTreeView32` fills it during normal
    // use; a marquee progress bar + counter STATIC take its
    // place while "Unfold All" is running. All three are
    // positioned unconditionally; visibility is toggled by
    // `ShowWindow(SW_SHOW/HIDE)` in `start_workspace_unfold_all`
    // / on completion. Placing them at their target positions
    // even when hidden means the reveal on completion is
    // instant ŌĆö no first-paint layout jitter.
    let body_top = action_y + WORKSPACE_ACTION_HEIGHT_PX;
    let body_bottom = (height - inset).max(body_top);
    let body_h = (body_bottom - body_top).max(0);
    unsafe {
        let _ = MoveWindow(
            children.tree,
            inner_left,
            body_top,
            inner_width,
            body_h,
            true,
        );
        // Progress bar + label centered vertically within the
        // body region. Progress bar spans the full inner width;
        // label sits directly below with a small gap. If body
        // is too short to fit both, they just clip ŌĆö the reveal
        // on completion swaps back to the tree anyway.
        let overlay_h = WORKSPACE_UNFOLD_PROGRESS_HEIGHT_PX
            + WORKSPACE_UNFOLD_PROGRESS_GAP_PX
            + WORKSPACE_UNFOLD_LABEL_HEIGHT_PX;
        let overlay_top = body_top + ((body_h - overlay_h) / 2).max(0);
        let _ = MoveWindow(
            children.unfold_progress,
            inner_left,
            overlay_top,
            inner_width,
            WORKSPACE_UNFOLD_PROGRESS_HEIGHT_PX,
            true,
        );
        let _ = MoveWindow(
            children.unfold_label,
            inner_left,
            overlay_top + WORKSPACE_UNFOLD_PROGRESS_HEIGHT_PX + WORKSPACE_UNFOLD_PROGRESS_GAP_PX,
            inner_width,
            WORKSPACE_UNFOLD_LABEL_HEIGHT_PX,
            true,
        );
    }
}

/// Snapshot of the Document Map panel's chrome + body children:
/// header frame, title label, close-├Ś button, and the miniature
/// Scintilla view that fills the body. Same snapshot-then-drop
/// discipline as [`WorkspacePanelChildren`].
#[derive(Copy, Clone)]
struct DocMapPanelChildren {
    header_frame: HWND,
    header_label: HWND,
    close: HWND,
    /// Second Scintilla control filling the panel body ŌĆö bound
    /// via `SCI_SETDOCPOINTER` to the active tab's document.
    scintilla: HWND,
}

/// Lay out the docmap panel's chrome + body children within its
/// client rect. Header row at the top (etched frame + title +
/// close-├Ś); the Scintilla miniature view fills the rest of the
/// panel below the header, using the panel's full inner width.
///
/// # Safety
///
/// Every HWND in `children` must be live (created in [`run`],
/// destroyed only at window teardown). UI-thread only.
unsafe fn layout_docmap_panel_children(children: DocMapPanelChildren, width: i32, height: i32) {
    let inset = DOCMAP_INSET_PX;
    let inner_left = inset;
    let inner_right = (width - inset).max(inner_left);
    let inner_width = (inner_right - inner_left).max(0);
    let header_y = inset;
    let frame_pad = DOCMAP_HEADER_FRAME_INSET_PX;
    let content_left = inner_left + frame_pad;
    let content_right = (inner_right - frame_pad).max(content_left);
    let close_w = DOCMAP_CLOSE_BUTTON_WIDTH_PX;
    let close_x = (content_right - close_w).max(content_left);
    let label_w = (close_x - content_left).max(0);
    let inner_h = (DOCMAP_HEADER_HEIGHT_PX - 2 * frame_pad).max(0);
    unsafe {
        let _ = MoveWindow(
            children.header_frame,
            inner_left,
            header_y,
            inner_width,
            DOCMAP_HEADER_HEIGHT_PX,
            true,
        );
        let _ = MoveWindow(
            children.header_label,
            content_left,
            header_y + frame_pad,
            label_w,
            inner_h,
            true,
        );
        let _ = MoveWindow(
            children.close,
            close_x,
            header_y + frame_pad,
            close_w,
            inner_h,
            true,
        );
    }
    // Body ŌĆö miniature Scintilla view fills the panel below the
    // header, using the full inner width. A negative body_h
    // (panel narrower than the header) clamps to zero via `.max`
    // ŌĆö the `MoveWindow` no-ops on a zero-dim window rather
    // than panicking.
    let body_top = header_y + DOCMAP_HEADER_HEIGHT_PX;
    let body_bottom = (height - inset).max(body_top);
    let body_h = (body_bottom - body_top).max(0);
    unsafe {
        let _ = MoveWindow(
            children.scintilla,
            inner_left,
            body_top,
            inner_width,
            body_h,
            true,
        );
    }
}

/// `Wnd_proc` for the Document Map panel container. Handles:
///
///   * `WM_SIZE`: lay out the header chrome (frame + title +
///     close-├Ś) plus the miniature Scintilla view that fills
///     the body.
///   * `WM_COMMAND`: consume the close-├Ś button and route to
///     [`hide_docmap_panel`].
///
/// # Safety
///
/// Standard `extern "system"` `wnd_proc` invariants ŌĆö must not
/// unwind across the FFI boundary. All Win32 API calls are
/// wrapped in `unsafe`; parent-state access goes through
/// `state_from_hwnd` under `PluginCallGuard`.
extern "system" fn docmap_panel_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_SIZE => {
                let width = (lparam.0 & 0xFFFF) as i32;
                let height = ((lparam.0 >> 16) & 0xFFFF) as i32;
                // Snapshot the four child HWNDs under a brief
                // borrow, drop it, then call the layout helper.
                // Same aliasing-safety rationale as
                // `workspace_panel_wnd_proc`'s WM_SIZE.
                let hwnds = state_from_hwnd(GetParent(hwnd).unwrap_or_default()).map(|state| {
                    (
                        state.docmap_header_frame,
                        state.docmap_header_label,
                        state.docmap_close_hwnd,
                        state.docmap_scintilla_hwnd,
                    )
                });
                if let Some((header_frame, header_label, close, scintilla)) = hwnds {
                    layout_docmap_panel_children(
                        DocMapPanelChildren {
                            header_frame,
                            header_label,
                            close,
                            scintilla,
                        },
                        width,
                        height,
                    );
                }
                LRESULT(0)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as u16;
                if cmd == IDC_DOCMAP_CLOSE {
                    let parent = GetParent(hwnd).unwrap_or_default();
                    if !parent.0.is_null() {
                        hide_docmap_panel(parent);
                    }
                    return LRESULT(0);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_CTLCOLORSTATIC => {
                // Paint the header label's background with the
                // shared chrome brush so it merges into the
                // panel ŌĆö same technique the workspace panel's
                // header uses (via `fif_dock_wnd_proc`'s
                // WM_CTLCOLORSTATIC handler pattern; keeping
                // both panels visually consistent).
                let hdc = wparam.0 as *mut c_void;
                SetBkMode(HDC(hdc), TRANSPARENT);
                LRESULT(dialog_bg_brush().0 as isize)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// `Wnd_proc` for the workspace splitter ŌĆö horizontal-axis
/// mirror of [`splitter_wnd_proc`]. Captures drag state on
/// `WM_LBUTTONDOWN`, applies the new workspace width on each
/// `WM_MOUSEMOVE`, releases on `WM_LBUTTONUP`. Reads/writes the
/// parent `WindowState` via `state_from_hwnd(GetParent(...))` so
/// all drag state lives in one place.
///
/// # Safety
///
/// Standard `extern "system"` `wnd_proc` invariants ŌĆö must not
/// unwind across the FFI boundary. All bodies wrap Win32 API
/// calls in `unsafe {}`; parent-state access goes through
/// `state_from_hwnd` under `PluginCallGuard`.
extern "system" fn workspace_splitter_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_SETCURSOR => {
                if let Ok(cursor) = LoadCursorW(None, IDC_SIZEWE) {
                    let _ = SetCursor(Some(cursor));
                }
                LRESULT(1)
            }
            WM_LBUTTONDOWN => {
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    let mut pt = POINT::default();
                    if GetCursorPos(&raw mut pt).is_ok() {
                        state.workspace_splitter_drag = Some(WorkspaceSplitterDrag {
                            start_screen_x: pt.x,
                            width_at_start: state.workspace_width,
                        });
                        let _ = SetCapture(hwnd);
                    }
                }
                LRESULT(0)
            }
            WM_MOUSEMOVE => {
                let parent = GetParent(hwnd).unwrap_or_default();
                // Same snapshot-then-drop-borrow pattern as the FIF
                // splitter to avoid re-entering `&mut WindowState`
                // via `MoveWindow ŌåÆ WM_SIZE ŌåÆ workspace_panel_wnd_proc`
                // on the panel's own children.
                let snap = if let Some(state) = state_from_hwnd(parent) {
                    state.workspace_splitter_drag.map(|drag| {
                        (
                            drag,
                            state.workspace_width,
                            state.toolbar_hwnd,
                            state.toolbar_bitmap_px,
                            state.tab_hwnd,
                            state.scintilla_hwnd,
                            state.status_hwnd,
                            state.fif_splitter_hwnd,
                            state.fif_dock_hwnd,
                            state.fif_dock_visible,
                            state.fif_dock_height,
                            WorkspaceLayout {
                                panel: state.workspace_hwnd,
                                splitter: state.workspace_splitter_hwnd,
                                visible: state.workspace_visible,
                                width: state.workspace_width,
                            },
                            DocMapLayout {
                                panel: state.docmap_hwnd,
                                splitter: state.docmap_splitter_hwnd,
                                visible: state.docmap_visible,
                                width: state.docmap_width,
                            },
                        )
                    })
                } else {
                    None
                };
                let Some((
                    drag,
                    current_width,
                    toolbar_hwnd,
                    toolbar_bitmap_px,
                    tabs,
                    scintilla,
                    status,
                    fif_splitter,
                    fif_dock,
                    fif_dock_visible,
                    fif_dock_height,
                    mut workspace,
                    docmap,
                )) = snap
                else {
                    return LRESULT(0);
                };
                let mut pt = POINT::default();
                if GetCursorPos(&raw mut pt).is_err() {
                    return LRESULT(0);
                }
                let mut rect = RECT::default();
                if GetClientRect(parent, &raw mut rect).is_err() {
                    return LRESULT(0);
                }
                // Dragging right grows the panel; dragging left
                // shrinks it. `clamp_workspace_width` is the same
                // authority `layout_children` consults, so the value
                // we write back into state matches what gets rendered.
                let proposed = drag.width_at_start + (pt.x - drag.start_screen_x);
                let new_width = clamp_workspace_width(rect.right, proposed);
                if new_width == current_width {
                    return LRESULT(0);
                }
                if let Some(state) = state_from_hwnd(parent) {
                    state.workspace_width = new_width;
                }
                workspace.width = new_width;
                let tab_hidden = !IsWindowVisible(tabs).as_bool();
                // Suppress Scintilla's WM_PAINT storm during the
                // drag's `MoveWindow` burst. Without this, every
                // pixel of drag fires WM_SIZE on Scintilla, which
                // invalidates and repaints the entire editor ŌĆö
                // visible as heavy flicker on wider windows.
                //
                // [`ScintillaRedrawGuard`] handles the SETREDRAW
                // pair as RAII: enter() suppresses paints,
                // Drop restores + `InvalidateRect`s in one shot.
                // Using the guard rather than a manual bracket
                // guarantees redraw is restored even if a future
                // edit to `layout_children` introduces a panic
                // path ŌĆö a stuck-frozen Scintilla view would be
                // unrecoverable for the user.
                //
                // Scoped block so the guard's Drop runs BEFORE the
                // explicit `UpdateWindow` below ŌĆö we want the
                // guard's InvalidateRect to have marked the region
                // dirty by the time UpdateWindow forces a paint.
                {
                    let _redraw = ScintillaRedrawGuard::enter(scintilla);
                    layout_children(
                        toolbar_hwnd,
                        toolbar::toolbar_height_px(toolbar_bitmap_px),
                        tabs,
                        scintilla,
                        status,
                        fif_splitter,
                        fif_dock,
                        fif_dock_visible,
                        fif_dock_height,
                        tab_hidden,
                        workspace,
                        docmap,
                        rect.right,
                        rect.bottom,
                    );
                }
                let _ = UpdateWindow(scintilla);
                LRESULT(0)
            }
            WM_LBUTTONUP => {
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    state.workspace_splitter_drag = None;
                }
                let _ = ReleaseCapture();
                LRESULT(0)
            }
            WM_CAPTURECHANGED => {
                // Defensive: some UI operation stole capture mid-drag
                // (e.g. Alt+Tab). Clear drag state so the next
                // WM_MOUSEMOVE without a fresh WM_LBUTTONDOWN
                // doesn't resize the panel to whatever the cursor
                // happens to be over.
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    state.workspace_splitter_drag = None;
                }
                LRESULT(0)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// `Wnd_proc` for the Document Map splitter ŌĆö right-column mirror
/// of [`workspace_splitter_wnd_proc`]. Sign convention flips:
/// dragging LEFT grows the panel because the panel sits at the
/// right edge and the splitter to its left.
///
/// # Safety
///
/// Standard `extern "system"` `wnd_proc` invariants ŌĆö must not
/// unwind across the FFI boundary. All bodies wrap Win32 API
/// calls in `unsafe {}`; parent-state access goes through
/// `state_from_hwnd` under `PluginCallGuard`.
extern "system" fn docmap_splitter_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_SETCURSOR => {
                if let Ok(cursor) = LoadCursorW(None, IDC_SIZEWE) {
                    let _ = SetCursor(Some(cursor));
                }
                LRESULT(1)
            }
            WM_LBUTTONDOWN => {
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    let mut pt = POINT::default();
                    if GetCursorPos(&raw mut pt).is_ok() {
                        state.docmap_splitter_drag = Some(DocMapSplitterDrag {
                            start_screen_x: pt.x,
                            width_at_start: state.docmap_width,
                        });
                        let _ = SetCapture(hwnd);
                    }
                }
                LRESULT(0)
            }
            WM_MOUSEMOVE => {
                let parent = GetParent(hwnd).unwrap_or_default();
                let snap = if let Some(state) = state_from_hwnd(parent) {
                    state.docmap_splitter_drag.map(|drag| {
                        (
                            drag,
                            state.docmap_width,
                            state.toolbar_hwnd,
                            state.toolbar_bitmap_px,
                            state.tab_hwnd,
                            state.scintilla_hwnd,
                            state.status_hwnd,
                            state.fif_splitter_hwnd,
                            state.fif_dock_hwnd,
                            state.fif_dock_visible,
                            state.fif_dock_height,
                            WorkspaceLayout {
                                panel: state.workspace_hwnd,
                                splitter: state.workspace_splitter_hwnd,
                                visible: state.workspace_visible,
                                width: state.workspace_width,
                            },
                            DocMapLayout {
                                panel: state.docmap_hwnd,
                                splitter: state.docmap_splitter_hwnd,
                                visible: state.docmap_visible,
                                width: state.docmap_width,
                            },
                            state.editor,
                            state.docmap_editor,
                        )
                    })
                } else {
                    None
                };
                let Some((
                    drag,
                    current_width,
                    toolbar_hwnd,
                    toolbar_bitmap_px,
                    tabs,
                    scintilla,
                    status,
                    fif_splitter,
                    fif_dock,
                    fif_dock_visible,
                    fif_dock_height,
                    workspace,
                    mut docmap,
                    main_editor,
                    docmap_editor,
                )) = snap
                else {
                    return LRESULT(0);
                };
                let mut pt = POINT::default();
                if GetCursorPos(&raw mut pt).is_err() {
                    return LRESULT(0);
                }
                let mut rect = RECT::default();
                if GetClientRect(parent, &raw mut rect).is_err() {
                    return LRESULT(0);
                }
                // Sign flip vs the workspace splitter: dragging
                // LEFT grows the docmap (subtract the delta).
                let proposed = drag.width_at_start - (pt.x - drag.start_screen_x);
                let new_width = clamp_docmap_width(rect.right, proposed);
                if new_width == current_width {
                    return LRESULT(0);
                }
                if let Some(state) = state_from_hwnd(parent) {
                    state.docmap_width = new_width;
                }
                docmap.width = new_width;
                let tab_hidden = !IsWindowVisible(tabs).as_bool();
                // Same anti-flicker discipline as the workspace
                // splitter ŌĆö Scintilla's WM_PAINT burst during
                // rapid MoveWindow is bracketed by
                // `ScintillaRedrawGuard`.
                {
                    let _redraw = ScintillaRedrawGuard::enter(scintilla);
                    layout_children(
                        toolbar_hwnd,
                        toolbar::toolbar_height_px(toolbar_bitmap_px),
                        tabs,
                        scintilla,
                        status,
                        fif_splitter,
                        fif_dock,
                        fif_dock_visible,
                        fif_dock_height,
                        tab_hidden,
                        workspace,
                        docmap,
                        rect.right,
                        rect.bottom,
                    );
                }
                let _ = UpdateWindow(scintilla);
                // Panel width change alters the miniature
                // view's lines-on-screen ŌĆö the highlight-center
                // math would drift otherwise. Update pulls both
                // handles by value, no reentrant `state_from_hwnd`.
                update_docmap_viewport_indicator(main_editor, docmap_editor);
                LRESULT(0)
            }
            WM_LBUTTONUP => {
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    state.docmap_splitter_drag = None;
                }
                let _ = ReleaseCapture();
                LRESULT(0)
            }
            WM_CAPTURECHANGED => {
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    state.docmap_splitter_drag = None;
                }
                LRESULT(0)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// Scroll the main editor so the given document-line index is
/// centered vertically in the main viewport. Called on every
/// mouse-down / mouse-move inside the map view's scroll-drag
/// gesture. Uses [`SCI_VISIBLEFROMDOCLINE`] to convert the
/// doc-line into visible-line space (identity when folding is
/// off) so [`SCI_LINESCROLL`] moves the right amount.
///
/// # Safety
///
/// Both handles must be live; caller runs on the UI thread.
unsafe fn scroll_main_to_doc_line(main_editor: EditorHandle, target_doc_line: isize) {
    let target_visible = main_editor.send(SCI_VISIBLEFROMDOCLINE, target_doc_line as usize, 0);
    let main_lines_on_screen = main_editor.send(SCI_LINESONSCREEN, 0, 0);
    let current_first_visible = main_editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0);
    let desired_first_visible = (target_visible - main_lines_on_screen / 2).max(0);
    let delta = desired_first_visible - current_first_visible;
    if delta != 0 {
        main_editor.send(SCI_LINESCROLL, 0, delta);
    }
}

/// Subclass proc for the Document Map's Scintilla control.
/// Hijacks mouse events so a click / drag on the miniature view
/// scrolls the MAIN editor to the corresponding line (rather
/// than letting Scintilla start a text-selection drag on the
/// read-only view). Every other message forwards to
/// `DefSubclassProc` so Scintilla's own paint / keyboard /
/// notification handling continues unchanged.
///
/// Drag-state is stored on `WindowState.docmap_scroll_drag`,
/// reached by walking TWO levels of parenthood from the map's
/// Scintilla HWND: its direct parent is the docmap panel HWND
/// (which owns no state), whose parent is the main window
/// (where `state` is installed via `GWLP_USERDATA`). Same
/// discipline the workspace/docmap splitters use, except those
/// splitters are direct children of the main window so their
/// walk is only one hop.
///
/// # Safety
///
/// Standard subclass-proc invariants ŌĆö must not unwind across
/// FFI. All bodies wrap Win32/state access in `unsafe`.
unsafe extern "system" fn docmap_scintilla_subclass_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
    _uidsubclass: usize,
    _dwrefdata: usize,
) -> LRESULT {
    unsafe {
        // Walk `map_scintilla ŌåÆ docmap_panel ŌåÆ main_hwnd`. The
        // panel HWND doesn't have `WindowState` installed on
        // `GWLP_USERDATA`; state lives on the main window.
        let panel = GetParent(hwnd).unwrap_or_default();
        let main = GetParent(panel).unwrap_or_default();
        match msg {
            WM_LBUTTONDOWN => {
                if let Some(state) = state_from_hwnd(main) {
                    state.docmap_scroll_drag = Some(DocMapScrollDrag { _priv: () });
                }
                let _ = SetCapture(hwnd);
                // Do the initial scroll immediately so a plain
                // click (no drag) still moves the view.
                let x = (lparam.0 & 0xFFFF) as i16 as i32;
                let y = ((lparam.0 >> 16) & 0xFFFF) as i16 as i32;
                let (main_editor, docmap_editor) = if let Some(state) = state_from_hwnd(main) {
                    (state.editor, state.docmap_editor)
                } else {
                    return LRESULT(0);
                };
                let pos = docmap_editor.send(SCI_POSITIONFROMPOINTCLOSE, x as usize, y as isize);
                if pos >= 0 {
                    let doc_line = docmap_editor.send(SCI_LINEFROMPOSITION, pos as usize, 0);
                    scroll_main_to_doc_line(main_editor, doc_line);
                }
                // Consume the event so Scintilla doesn't start a
                // text-selection drag on the read-only view.
                LRESULT(0)
            }
            WM_MOUSEMOVE => {
                let dragging = if let Some(state) = state_from_hwnd(main) {
                    state.docmap_scroll_drag.is_some()
                } else {
                    false
                };
                if !dragging {
                    return DefSubclassProc(hwnd, msg, wparam, lparam);
                }
                let x = (lparam.0 & 0xFFFF) as i16 as i32;
                let y = ((lparam.0 >> 16) & 0xFFFF) as i16 as i32;
                let (main_editor, docmap_editor) = if let Some(state) = state_from_hwnd(main) {
                    (state.editor, state.docmap_editor)
                } else {
                    return LRESULT(0);
                };
                let pos = docmap_editor.send(SCI_POSITIONFROMPOINTCLOSE, x as usize, y as isize);
                if pos >= 0 {
                    let doc_line = docmap_editor.send(SCI_LINEFROMPOSITION, pos as usize, 0);
                    scroll_main_to_doc_line(main_editor, doc_line);
                }
                LRESULT(0)
            }
            WM_LBUTTONUP => {
                if let Some(state) = state_from_hwnd(main) {
                    state.docmap_scroll_drag = None;
                }
                let _ = ReleaseCapture();
                LRESULT(0)
            }
            WM_CAPTURECHANGED => {
                // Defensive: some UI operation stole capture
                // mid-drag (e.g. Alt+Tab). Clear drag state so a
                // stray WM_MOUSEMOVE without a fresh
                // WM_LBUTTONDOWN doesn't scroll the main editor.
                if let Some(state) = state_from_hwnd(main) {
                    state.docmap_scroll_drag = None;
                }
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            WM_MOUSEWHEEL => {
                // Wheel-scroll on the map view scrolls the MAIN
                // editor rather than the map (the map is a
                // fixed-viewport overview; the main editor is
                // the surface the user actually navigates).
                // Forward the message directly to the main
                // editor's Scintilla control ŌĆö it handles wheel
                // scrolling natively.
                let main_scintilla = if let Some(state) = state_from_hwnd(main) {
                    state.scintilla_hwnd
                } else {
                    return LRESULT(0);
                };
                let _ = SendMessageW(main_scintilla, WM_MOUSEWHEEL, Some(wparam), Some(lparam));
                // Consume so Scintilla's own wnd_proc doesn't
                // scroll the map view ŌĆö the map should stay
                // pinned by `update_docmap_viewport_indicator`'s
                // centering logic, not respond to wheel input
                // directly.
                LRESULT(0)
            }
            WM_PAINT => {
                // Double-buffered paint: render Scintilla's
                // miniature text AND our translucent-orange
                // overlay into an off-screen bitmap, then blit
                // both to the screen in one shot. Without this,
                // scrolling produces visible flicker because the
                // sequence "Scintilla's buffer ŌåÆ screen ŌåÆ our
                // overlay ŌåÆ screen" leaves a one-frame window
                // during which the screen shows Scintilla's
                // fresh text WITHOUT the overlay on top of it.
                //
                // Scintilla is asked to paint into our memory DC
                // via `WM_PRINTCLIENT` (the documented
                // control-paints-into-caller-DC message; every
                // major Win32 control including Scintilla
                // supports it). The overlay is then drawn on
                // the same memory DC, and the whole thing is
                // BitBlt'd to the paint DC returned by
                // `BeginPaint` ŌĆö one screen write per frame,
                // no intermediate flash.
                let mut ps = PAINTSTRUCT::default();
                let dst_dc = BeginPaint(hwnd, &raw mut ps);
                if !dst_dc.is_invalid() {
                    let mut client = RECT::default();
                    if GetClientRect(hwnd, &raw mut client).is_ok() {
                        let width = client.right - client.left;
                        let height = client.bottom - client.top;
                        if width > 0 && height > 0 {
                            let mem_dc = CreateCompatibleDC(Some(dst_dc));
                            let mem_bmp = CreateCompatibleBitmap(dst_dc, width, height);
                            if !mem_dc.is_invalid() && !mem_bmp.is_invalid() {
                                let prev_bmp = SelectObject(mem_dc, HGDIOBJ(mem_bmp.0));
                                // Ask Scintilla to render its
                                // content into `mem_dc`. Sending
                                // via SendMessageW re-enters our
                                // own subclass proc; the `_ =>`
                                // arm forwards to DefSubclassProc
                                // which reaches Scintilla's own
                                // wnd_proc.
                                let _ = SendMessageW(
                                    hwnd,
                                    WM_PRINTCLIENT,
                                    Some(WPARAM(mem_dc.0 as usize)),
                                    Some(LPARAM((PRF_CLIENT | PRF_ERASEBKGND) as isize)),
                                );
                                paint_docmap_viewport_overlay(mem_dc, client, main);
                                let _ = BitBlt(
                                    dst_dc,
                                    0,
                                    0,
                                    width,
                                    height,
                                    Some(mem_dc),
                                    0,
                                    0,
                                    SRCCOPY,
                                );
                                SelectObject(mem_dc, prev_bmp);
                            }
                            if !mem_bmp.is_invalid() {
                                let _ = DeleteObject(HGDIOBJ(mem_bmp.0));
                            }
                            if !mem_dc.is_invalid() {
                                let _ = DeleteDC(mem_dc);
                            }
                        }
                    }
                    let _ = EndPaint(hwnd, &raw const ps);
                }
                LRESULT(0)
            }
            WM_ERASEBKGND => {
                // Skip background erase entirely ŌĆö the buffered
                // WM_PAINT above fills every pixel of the client
                // area with Scintilla's rendered content, so any
                // background erase is redundant work AND a source
                // of tearing (background fill ŌåÆ paint ŌåÆ visible
                // flash of background between the two).
                LRESULT(1)
            }
            _ => DefSubclassProc(hwnd, msg, wparam, lparam),
        }
    }
}

/// Paint the translucent orange viewport-highlight rectangle onto
/// the caller's device context. Called from the map Scintilla's
/// `WM_PAINT` subclass ŌĆö the DC is a memory DC into which
/// Scintilla has already painted its miniature text (via
/// `WM_PRINTCLIENT`), so this overlay lands on top of the text
/// inside the same off-screen buffer. That buffer is then blit'd
/// to the screen in one shot, eliminating the paint-flicker that
/// separate on-screen overlay drawing would produce.
///
/// `dst_hdc` ŌĆö target device context (memory DC in the buffered
/// paint path).
/// `client_rect` ŌĆö client rect of the map view; the overlay
/// spans full width, its vertical extent is computed from the
/// main editor's visible range.
/// `main_hwnd` ŌĆö the main window, needed for `state_from_hwnd`
/// to reach both editor handles.
///
/// No-op when the state pointer isn't installed, the viewport
/// is empty, or Scintilla returns degenerate coordinates.
///
/// # Safety
///
/// Runs on the UI thread inside `WM_PAINT` dispatch. Uses only
/// GDI calls; the caller owns the DC lifecycle.
unsafe fn paint_docmap_viewport_overlay(dst_hdc: HDC, client_rect: RECT, main_hwnd: HWND) {
    unsafe {
        let (main_editor, docmap_editor) = if let Some(state) = state_from_hwnd(main_hwnd) {
            (state.editor, state.docmap_editor)
        } else {
            return;
        };
        // Recompute the visible-line range on the main editor.
        // Same discipline as `update_docmap_viewport_indicator`
        // ŌĆö read fresh values so a mid-frame scroll on the main
        // editor still positions the overlay correctly.
        let first_visible = main_editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0);
        let lines_on_screen = main_editor.send(SCI_LINESONSCREEN, 0, 0);
        let line_count = main_editor.send(SCI_GETLINECOUNT, 0, 0).max(0);
        if first_visible < 0 || lines_on_screen <= 0 || line_count == 0 {
            return;
        }
        let last_visible_exclusive = first_visible + lines_on_screen;
        let first_doc_line = main_editor.send(SCI_DOCLINEFROMVISIBLE, first_visible as usize, 0);
        let last_doc_line_raw =
            main_editor.send(SCI_DOCLINEFROMVISIBLE, last_visible_exclusive as usize, 0);
        let last_doc_line_exclusive = last_doc_line_raw.min(line_count);
        if first_doc_line < 0 || last_doc_line_exclusive <= first_doc_line {
            return;
        }
        let first_pos = docmap_editor.send(SCI_POSITIONFROMLINE, first_doc_line as usize, 0);
        let last_pos =
            docmap_editor.send(SCI_POSITIONFROMLINE, last_doc_line_exclusive as usize, 0);
        if first_pos < 0 || last_pos < 0 {
            return;
        }
        let top_y = docmap_editor.send(SCI_POINTYFROMPOSITION, 0, first_pos);
        let bottom_y = docmap_editor.send(SCI_POINTYFROMPOSITION, 0, last_pos);
        let top_y_i32 = i32::try_from(top_y).unwrap_or(0);
        let mut bottom_y_i32 = i32::try_from(bottom_y).unwrap_or(0);
        if bottom_y_i32 <= top_y_i32 {
            let line_h = docmap_editor.send(SCI_TEXTHEIGHT, first_doc_line as usize, 0);
            bottom_y_i32 = top_y_i32 + i32::try_from(line_h).unwrap_or(0);
        }
        let rect_w = (client_rect.right - client_rect.left).max(0);
        let rect_h = (bottom_y_i32 - top_y_i32).max(0);
        if rect_w <= 0 || rect_h <= 0 {
            return;
        }
        // Fill (translucent orange) via `AlphaBlend` from a 1x1
        // solid-orange memory bitmap. `AlphaBlend` stretches the
        // 1x1 source to the target rect and uniformly blends
        // through `SourceConstantAlpha` ŌĆö perfect for a flat
        // translucent wash over the miniature text underneath.
        let hdc_mem = CreateCompatibleDC(Some(dst_hdc));
        if hdc_mem.is_invalid() {
            return;
        }
        let hbm = CreateCompatibleBitmap(dst_hdc, 1, 1);
        if !hbm.is_invalid() {
            let prev_bm = SelectObject(hdc_mem, HGDIOBJ(hbm.0));
            let fill_brush = CreateSolidBrush(COLORREF(DOCMAP_VIEWPORT_COLOR));
            if !fill_brush.is_invalid() {
                let fill_rect = RECT {
                    left: 0,
                    top: 0,
                    right: 1,
                    bottom: 1,
                };
                FillRect(hdc_mem, &raw const fill_rect, fill_brush);
                let _ = DeleteObject(HGDIOBJ(fill_brush.0));
            }
            let blend = BLENDFUNCTION {
                BlendOp: AC_SRC_OVER as u8,
                BlendFlags: 0,
                SourceConstantAlpha: DOCMAP_VIEWPORT_FILL_ALPHA,
                AlphaFormat: 0,
            };
            let _ = AlphaBlend(
                dst_hdc,
                client_rect.left,
                top_y_i32,
                rect_w,
                rect_h,
                hdc_mem,
                0,
                0,
                1,
                1,
                blend,
            );
            SelectObject(hdc_mem, prev_bm);
            let _ = DeleteObject(HGDIOBJ(hbm.0));
        }
        let _ = DeleteDC(hdc_mem);
    }
}

/// Hard cap on registered dock-dialog count. A misbehaving plugin
/// that calls `NPPM_DMMREGASDCKDLG` in a loop with fresh HWNDs
/// would otherwise allocate an unbounded number of frames (each a
/// GDI / USER object ŌĆö Win32's per-process default cap is around
/// 10000). 64 is well above any reasonable plugin's needs (`NppExec`,
/// `NppFTP`, etc. each register one) while leaving room for power
/// users running many docked plugins simultaneously.
const DOCK_DIALOG_REGISTRATION_CAP: usize = 64;

/// Default floating-frame dimensions when the plugin's
/// `rc_float` is empty or adversarial. Width ├Ś height in pixels.
const DOCK_FRAME_DEFAULT_W: i32 = 480;
const DOCK_FRAME_DEFAULT_H: i32 = 360;
/// Default top-left corner. Fixed (not monitor-relative) ŌĆö Phase
/// 5 docking manager adds DPI / multi-monitor awareness.
const DOCK_FRAME_DEFAULT_X: i32 = 200;
const DOCK_FRAME_DEFAULT_Y: i32 = 200;

/// Compute the floating dock frame's initial (x, y, width, height).
/// If the plugin's `tTbData.rc_float` is well-formed (right > left,
/// bottom > top, AND the resulting dimensions fit in i32 without
/// overflow AND are positive), use it verbatim ŌĆö that's the
/// position the plugin remembered from its last session. Otherwise
/// fall back to a centred, modestly-sized panel so the user sees
/// the dialog somewhere reasonable on first registration.
///
/// `saturating_sub` guards against an adversarial `rc_float`:
/// e.g. `left = i32::MIN, right = i32::MAX` would otherwise
/// overflow on the `right - left` subtraction (debug panic, release
/// silent wrap). Saturation produces `i32::MAX` which is then
/// rejected by the `<= 0` post-check (well ŌĆö `i32::MAX > 0`, but
/// `CreateWindowExW` would silently clamp the window to monitor
/// bounds). The subsequent dimension-positivity check is the real
/// guard.
fn compute_dock_frame_position(rc_float: &codepp_plugin_host::TbRect) -> (i32, i32, i32, i32) {
    if rc_float.right > rc_float.left && rc_float.bottom > rc_float.top {
        let w = rc_float.right.saturating_sub(rc_float.left);
        let h = rc_float.bottom.saturating_sub(rc_float.top);
        if w > 0 && h > 0 {
            return (rc_float.left, rc_float.top, w, h);
        }
    }
    (
        DOCK_FRAME_DEFAULT_X,
        DOCK_FRAME_DEFAULT_Y,
        DOCK_FRAME_DEFAULT_W,
        DOCK_FRAME_DEFAULT_H,
    )
}

/// Register the dock-frame window class. Idempotent via `OnceLock` ŌĆö
/// safe to call from `register_dock_dialog` immediately before each
/// frame's `CreateWindowExW`. The class wndproc is
/// `dock_frame_wnd_proc` which handles `WM_SIZE` (resize the
/// plugin's `h_client` to fill the client area) and `WM_CLOSE`
/// (hide the frame instead of destroying ŌĆö the registration
/// outlives a close-button click).
unsafe fn register_dock_frame_class() {
    use std::sync::OnceLock;
    static REGISTERED: OnceLock<()> = OnceLock::new();
    REGISTERED.get_or_init(|| unsafe {
        let instance = GetModuleHandleW(None).unwrap_or_default();
        let class = WNDCLASSEXW {
            cbSize: std::mem::size_of::<WNDCLASSEXW>() as u32,
            style: CS_HREDRAW | CS_VREDRAW,
            lpfnWndProc: Some(dock_frame_wnd_proc),
            hInstance: instance.into(),
            hCursor: LoadCursorW(None, IDC_ARROW).unwrap_or_default(),
            hbrBackground: dialog_bg_brush(),
            lpszClassName: DOCK_FRAME_CLASS,
            ..Default::default()
        };
        let _ = RegisterClassExW(&raw const class);
    });
}

/// `Wnd_proc` for the host-owned floating frame that wraps a
/// plugin's docking dialog (registered via `NPPM_DMMREGASDCKDLG`).
/// The plugin's `h_client` HWND is stashed in the frame's
/// `GWLP_USERDATA` at `WM_NCCREATE` so `WM_SIZE` can resize it to
/// fill the client area without going through the `WindowState`
/// registry.
///
/// `WM_CLOSE` hides the frame rather than destroying it ŌĆö the
/// registration survives, and a subsequent `NPPM_DMMSHOW` re-shows.
/// The frame is destroyed by Win32 when the main window dies (the
/// frames are owned by the main HWND).
extern "system" fn dock_frame_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_NCCREATE => {
                // CREATESTRUCTW.lpCreateParams carries the plugin's
                // h_client HWND (passed via the lpParam arg of
                // CreateWindowExW). Stash it so WM_SIZE can find
                // it without a Vec lookup.
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let h_client_raw = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, h_client_raw);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_SIZE => {
                let h_client_raw = GetWindowLongPtrW(hwnd, GWLP_USERDATA);
                if h_client_raw != 0 {
                    let h_client = HWND(h_client_raw as *mut c_void);
                    // Defensive: the plugin may have destroyed
                    // h_client without unregistering. `IsWindow`
                    // catches that without a Vec lookup.
                    if IsWindow(Some(h_client)).as_bool() {
                        let mut rc = RECT::default();
                        if GetClientRect(hwnd, &raw mut rc).is_ok() {
                            let _ = MoveWindow(h_client, 0, 0, rc.right, rc.bottom, true);
                        }
                    }
                }
                LRESULT(0)
            }
            WM_CLOSE => {
                // Hide instead of destroy. Phase 5 polish item:
                // synthesise a `DMN_CLOSE` notification so the
                // plugin can update its Show/Hide menu state in
                // sync with the visual change. Today plugins
                // discover the hide via the next NPPM-driven
                // refresh or the user re-clicking the menu item.
                let _ = ShowWindow(hwnd, SW_HIDE);
                LRESULT(0)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// Resolve the progress window's owner HWND from `GWLP_USERDATA`
/// (stashed at `WM_NCCREATE`) and call `Shell::cancel_fif` through
/// it. Used by both Cancel-button clicks and the title-bar X.
unsafe fn cancel_via_owner(progress: HWND) {
    let owner_raw = unsafe { GetWindowLongPtrW(progress, GWLP_USERDATA) };
    if owner_raw == 0 {
        return;
    }
    let owner = HWND(owner_raw as *mut c_void);
    if let Some(state) = unsafe { state_from_hwnd(owner) } {
        state.shell.cancel_fif();
    }
}

/// `Wnd_proc` for the FIF progress dialog. Owns nothing ŌĆö Cancel
/// clicks route to `Shell::cancel_fif` via the parent's
/// `WindowState`, and the window is destroyed by the search-
/// completion drain in `main_wnd_proc`.
extern "system" fn fif_progress_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as u16;
                if cmd == IDC_FIF_PROGRESS_CANCEL || cmd == IDCANCEL_U16 {
                    cancel_via_owner(hwnd);
                    // The terminal `FifEvent::Cancelled` will
                    // destroy this window; no need to do it here.
                    return LRESULT(0);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_CLOSE => {
                // System-menu close (the title-bar X). Route
                // through Shell::cancel_fif so the terminal event
                // arrives and `finalize_fif_job` clears
                // `fif_progress_hwnd`. Skipping this would let
                // `DefWindowProcW` destroy the window directly,
                // leaving a stale HWND in `WindowState` that
                // `finalize_fif_job` would later double-destroy.
                cancel_via_owner(hwnd);
                LRESULT(0)
            }
            WM_NCCREATE => {
                let cs = lparam.0 as *const CREATESTRUCTW;
                if !cs.is_null() {
                    let owner_ptr = (*cs).lpCreateParams as isize;
                    SetWindowLongPtrW(hwnd, GWLP_USERDATA, owner_ptr);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_ERASEBKGND => {
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, dialog_bg_brush());
                LRESULT(1)
            }
            WM_CTLCOLORSTATIC => LRESULT(dialog_bg_brush().0 as isize),
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// Construct and show the FIF progress dialog. `owner` is the main
/// window ŌĆö its `WindowState` is reachable via `GWLP_USERDATA`, and
/// the Cancel button forwards through it to `Shell::cancel_fif`.
unsafe fn show_fif_progress(owner: HWND, query: &str) -> Option<HWND> {
    unsafe {
        let instance = GetModuleHandleW(None).ok()?;
        const W: i32 = 460;
        const H: i32 = 140;
        let mut owner_rect = RECT::default();
        let _ = GetWindowRect(owner, &raw mut owner_rect);
        let owner_w = owner_rect.right - owner_rect.left;
        let owner_h = owner_rect.bottom - owner_rect.top;
        let x = owner_rect.left + (owner_w - W) / 2;
        let y = owner_rect.top + (owner_h - H) / 2;

        let mut title_buf: Vec<u16> = "Find in Files"
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        let dlg = CreateWindowExW(
            WS_EX_DLGMODALFRAME,
            FIF_PROGRESS_CLASS,
            PCWSTR(title_buf.as_mut_ptr()),
            WS_POPUP | WS_CAPTION | WS_SYSMENU,
            x,
            y,
            W,
            H,
            Some(owner),
            None,
            Some(instance.into()),
            Some(owner.0),
        )
        .ok()?;

        // First-row label: query text. Second-row label: current
        // file path. Third-row label: stats (X hits in Y files).
        // Cancel button at the bottom-right.
        const PAD: i32 = 12;
        const ROW_H: i32 = 18;
        const QUERY_Y: i32 = 12;
        const PATH_Y: i32 = QUERY_Y + ROW_H + 6;
        const STATS_Y: i32 = PATH_Y + ROW_H + 6;
        const BTN_W: i32 = 80;
        const BTN_H: i32 = 26;
        const BTN_X: i32 = W - PAD - BTN_W - 8; // 8 for client/non-client gap
        const BTN_Y: i32 = H - PAD - BTN_H - 24;

        let mut query_buf: Vec<u16> = format!("Searching for: {query}")
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        let _ = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            PCWSTR(query_buf.as_mut_ptr()),
            WS_CHILD | WS_VISIBLE,
            PAD,
            QUERY_Y,
            W - 2 * PAD,
            ROW_H,
            Some(dlg),
            None,
            Some(instance.into()),
            None,
        );
        let path_static = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("StartingŌĆ”"),
            WS_CHILD | WS_VISIBLE,
            PAD,
            PATH_Y,
            W - 2 * PAD,
            ROW_H,
            Some(dlg),
            Some(HMENU(IDC_FIF_PROGRESS_PATH as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let stats_static = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("STATIC"),
            w!("0 hits in 0 files"),
            WS_CHILD | WS_VISIBLE,
            PAD,
            STATS_Y,
            W - 2 * PAD - BTN_W - 8,
            ROW_H,
            Some(dlg),
            Some(HMENU(IDC_FIF_PROGRESS_STATS as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;
        let cancel_btn = CreateWindowExW(
            WINDOW_EX_STYLE::default(),
            w!("BUTTON"),
            w!("&Cancel"),
            WS_CHILD | WS_VISIBLE | WS_TABSTOP | style_bits(BS_DEFPUSHBUTTON),
            BTN_X,
            BTN_Y,
            BTN_W,
            BTN_H,
            Some(dlg),
            Some(HMENU(IDC_FIF_PROGRESS_CANCEL as usize as *mut c_void)),
            Some(instance.into()),
            None,
        )
        .ok()?;

        let font = HFONT(GetStockObject(DEFAULT_GUI_FONT).0);
        for child in [path_static, stats_static, cancel_btn] {
            apply_dialog_font(child, font);
        }

        let _ = ShowWindow(dlg, SW_SHOW);
        Some(dlg)
    }
}

/// Update the "current path" label on the progress dialog.
unsafe fn fif_progress_set_path(progress: HWND, path: &Path) {
    // Truncation is char-based, not byte-based: a slice at
    // `display.len() - 79` panics if that byte falls inside a
    // multi-byte UTF-8 sequence (any non-ASCII tail in the path ŌĆö
    // CJK / Cyrillic / accented Latin / emoji directory names are
    // common). `char_indices().rev().nth(78)` finds the byte
    // offset 79 chars back from the end.
    const MAX_DISPLAY_CHARS: usize = 80;
    let display = path.to_string_lossy();
    let truncated = if display.chars().count() > MAX_DISPLAY_CHARS {
        let start = display
            .char_indices()
            .rev()
            .nth(MAX_DISPLAY_CHARS - 2)
            .map_or(0, |(i, _)| i);
        format!("ŌĆ”{}", &display[start..])
    } else {
        display.into_owned()
    };
    let mut buf: Vec<u16> = truncated.encode_utf16().chain(std::iter::once(0)).collect();
    unsafe {
        if let Ok(child) = GetDlgItem(Some(progress), i32::from(IDC_FIF_PROGRESS_PATH)) {
            let _ = SetWindowTextW(child, PCWSTR(buf.as_mut_ptr()));
        }
    }
}

/// Update the "X hits in Y files" label on the progress dialog.
unsafe fn fif_progress_set_stats(progress: HWND, hits: usize, files: usize) {
    let s = format!(
        "{hits} hit{} in {files} file{}",
        if hits == 1 { "" } else { "s" },
        if files == 1 { "" } else { "s" },
    );
    let mut buf: Vec<u16> = s.encode_utf16().chain(std::iter::once(0)).collect();
    unsafe {
        if let Ok(child) = GetDlgItem(Some(progress), i32::from(IDC_FIF_PROGRESS_STATS)) {
            let _ = SetWindowTextW(child, PCWSTR(buf.as_mut_ptr()));
        }
    }
}

/// Tear down the progress dialog. Called from the search-completion
/// drain in `main_wnd_proc::WM_APP_WAKE`.
unsafe fn close_fif_progress(progress: HWND) {
    unsafe {
        let _ = DestroyWindow(progress);
    }
}

/// Clear the FIF results listview and reset the row index. Called
/// at the start of each search.
unsafe fn fif_listview_clear(listview: HWND) {
    unsafe {
        SendMessageW(listview, LVM_DELETEALLITEMS, None, None);
    }
}

/// Append one row to the FIF results listview. Returns the
/// just-inserted row index, or -1 on failure.
unsafe fn fif_listview_append(
    listview: HWND,
    file_display: &str,
    line_no: u32,
    match_text: &str,
) -> i32 {
    unsafe {
        let mut file_buf: Vec<u16> = file_display
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        let item_count = SendMessageW(listview, LVM_GETITEMCOUNT, None, None).0 as i32;
        let item = LVITEMW {
            mask: LVIF_TEXT,
            iItem: item_count,
            iSubItem: 0,
            pszText: PWSTR(file_buf.as_mut_ptr()),
            cchTextMax: file_buf.len() as i32,
            ..Default::default()
        };
        let new_idx = SendMessageW(
            listview,
            LVM_INSERTITEMW,
            Some(WPARAM(0)),
            Some(LPARAM(&raw const item as isize)),
        )
        .0 as i32;
        if new_idx < 0 {
            return -1;
        }
        let mut line_buf: Vec<u16> = format!("{line_no}")
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        let line_item = LVITEMW {
            mask: LVIF_TEXT,
            iItem: new_idx,
            iSubItem: 1,
            pszText: PWSTR(line_buf.as_mut_ptr()),
            cchTextMax: line_buf.len() as i32,
            ..Default::default()
        };
        SendMessageW(
            listview,
            LVM_SETITEMTEXTW,
            Some(WPARAM(new_idx as usize)),
            Some(LPARAM(&raw const line_item as isize)),
        );
        let mut match_buf: Vec<u16> = match_text
            .encode_utf16()
            .chain(std::iter::once(0))
            .collect();
        let match_item = LVITEMW {
            mask: LVIF_TEXT,
            iItem: new_idx,
            iSubItem: 2,
            pszText: PWSTR(match_buf.as_mut_ptr()),
            cchTextMax: match_buf.len() as i32,
            ..Default::default()
        };
        SendMessageW(
            listview,
            LVM_SETITEMTEXTW,
            Some(WPARAM(new_idx as usize)),
            Some(LPARAM(&raw const match_item as isize)),
        );
        new_idx
    }
}

/// Drain queued FIF events from the shell and route them to the
/// progress window (during search) or the dock listview (on
/// search completion). Called from `WM_APP_WAKE` after the
/// loader/file-watcher drains. Filters by `fif_active_job` so
/// stale events from a preempted job land harmlessly.
unsafe fn drain_fif_events(main_hwnd: HWND) {
    let (events, active_job) = {
        let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
            return;
        };
        (state.shell.take_fif_events(), state.fif_active_job)
    };
    if events.is_empty() {
        return;
    }
    let Some(active_job) = active_job else {
        return;
    };

    let mut last_path: Option<PathBuf> = None;
    let mut new_files = 0usize;
    let mut new_hits = 0usize;
    let mut terminal: Option<codepp_shell::FifEvent> = None;

    for event in events {
        match event {
            codepp_shell::FifEvent::FileMatches { job, path, outcome } => {
                if job.raw() != active_job {
                    continue; // stale, from a preempted job
                }
                new_files += 1;
                new_hits += outcome.matches.len();
                last_path = Some(path.clone());
                if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
                    state.fif_pending_results.push(FifPendingFile {
                        path,
                        matches: outcome.matches,
                        truncated: outcome.truncated,
                    });
                }
            }
            term @ (codepp_shell::FifEvent::Done { .. }
            | codepp_shell::FifEvent::Cancelled { .. }) => {
                let job_id = match &term {
                    codepp_shell::FifEvent::Done { job, .. } => job.raw(),
                    codepp_shell::FifEvent::Cancelled { job, .. } => job.raw(),
                    _ => unreachable!(),
                };
                if job_id == active_job {
                    terminal = Some(term);
                }
            }
        }
    }

    // Update progress window with the latest path + cumulative
    // counts. Done before the terminal event handling so the user
    // sees a final number tick on the way to "complete".
    if new_files > 0 || new_hits > 0 {
        let snap = unsafe { state_from_hwnd(main_hwnd) }
            .map(|s| (s.fif_progress_hwnd, total_pending_stats(s)));
        if let Some((Some(progress), (total_hits, total_files))) = snap {
            unsafe { fif_progress_set_stats(progress, total_hits, total_files) };
            if let Some(p) = &last_path {
                unsafe { fif_progress_set_path(progress, p) };
            }
        }
    }

    if let Some(term) = terminal {
        unsafe { finalize_fif_job(main_hwnd, term) };
    }
}

/// Sum the per-file pending results into `(hits, files)` counters
/// for the progress window's running total.
fn total_pending_stats(state: &WindowState) -> (usize, usize) {
    let files = state.fif_pending_results.len();
    let hits: usize = state
        .fif_pending_results
        .iter()
        .map(|f| f.matches.len())
        .sum();
    (hits, files)
}

/// Handle the terminal `FifEvent::Done` / `Cancelled`. Closes the
/// progress window, populates the listview from buffered results,
/// shows the dock if any matches were found, and clears the
/// active-job tracking.
unsafe fn finalize_fif_job(main_hwnd: HWND, terminal: codepp_shell::FifEvent) {
    // Drain progress HWND + pending results out of state in one
    // brief borrow; populate the listview AFTER the borrow ends so
    // `LVM_INSERTITEMW` syncs cannot re-enter.
    let (progress_hwnd, pending, listview, dialog, in_buffer_counts) = {
        let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
            return;
        };
        let progress = state.fif_progress_hwnd.take();
        let pending = std::mem::take(&mut state.fif_pending_results);
        state.fif_active_job = None;
        // Take the in-buffer tally even on cancel: the in-buffer
        // pass already ran (synchronously, before `start_fif`), so
        // those edits are real and need to show in the status. The
        // alternative ŌĆö silently dropping them ŌĆö would leave the
        // user wondering why their open tabs are dirty.
        let in_buffer = state.fif_in_buffer_counts.take();
        (
            progress,
            pending,
            state.fif_listview_hwnd,
            state.find_replace_dlg,
            in_buffer,
        )
    };

    if let Some(p) = progress_hwnd {
        unsafe { close_fif_progress(p) };
    }

    let (cancelled, mut files_modified, files_skipped_open, mut total_replacements) =
        match &terminal {
            codepp_shell::FifEvent::Done { stats, .. } => (
                false,
                stats.files_modified,
                stats.files_skipped_open,
                stats.total_replacements,
            ),
            codepp_shell::FifEvent::Cancelled { .. } => (true, 0, 0, 0),
            _ => return,
        };

    // Fold the in-buffer pass's tally into the worker's stats. The
    // worker's `files_skipped_open` already counts these tabs (it
    // skipped them on disk), so subtract the in-buffer files from
    // it to keep the total honest: "skipped" should mean "still
    // unaddressed", not "covered by in-buffer".
    let (in_buffer_files, in_buffer_replacements) = in_buffer_counts.unwrap_or((0, 0));
    files_modified += in_buffer_files;
    total_replacements += in_buffer_replacements;
    let files_skipped_open = files_skipped_open.saturating_sub(in_buffer_files);

    // Populate listview + index. We rebuild `fif_listview_index`
    // here so the `NM_DBLCLK` handler can map row ŌåÆ location.
    let mut new_index: Vec<FifListviewRow> = Vec::with_capacity(64);
    let total_hits: usize = pending.iter().map(|f| f.matches.len()).sum();
    unsafe { fif_listview_clear(listview) };
    for file in &pending {
        let display = file.path.to_string_lossy();
        let suffix = if file.truncated { " (truncated)" } else { "" };
        let display_with = if suffix.is_empty() {
            display.into_owned()
        } else {
            format!("{display}{suffix}")
        };
        for m in &file.matches {
            let row =
                unsafe { fif_listview_append(listview, &display_with, m.line_no, &m.line_text) };
            if row >= 0 {
                new_index.push(FifListviewRow {
                    path: file.path.clone(),
                    line_no: m.line_no,
                    col_start: m.col_start,
                    col_end: m.col_end,
                });
            }
        }
    }
    let any_results = !new_index.is_empty();
    let status_hwnd_for_text = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.fif_listview_index = new_index;
        Some(state.fif_dock_status)
    } else {
        None
    };
    if let Some(status) = status_hwnd_for_text {
        let prefix = if cancelled { "Cancelled ŌĆö " } else { "" };
        let skip_suffix = if files_skipped_open > 0 {
            format!(
                " (skipped {files_skipped_open} open file{})",
                if files_skipped_open == 1 { "" } else { "s" },
            )
        } else {
            String::new()
        };
        let s = if files_modified == 0 && files_skipped_open > 0 {
            // All matching files were open in tabs ŌĆö nothing was
            // written. Distinct wording from "Replaced 0 in 0
            // files" so it doesn't read as "search ran and found
            // nothing".
            format!(
                "{prefix}No files replaced ŌĆö all {files_skipped_open} matching file{} {} open in a tab",
                if files_skipped_open == 1 { "" } else { "s" },
                if files_skipped_open == 1 { "is" } else { "are" },
            )
        } else if files_modified > 0 || files_skipped_open > 0 {
            // Use the worker's authoritative replace count rather
            // than `total_hits` ŌĆö the search side caps per-file at
            // `MAX_MATCHES_PER_FILE` for display, but the replace
            // ran uncapped, so reporting the search count would
            // undercount on dense matches.
            format!(
                "{prefix}Replaced {total_replacements} occurrence{} in {files_modified} file{}{skip_suffix}",
                if total_replacements == 1 { "" } else { "s" },
                if files_modified == 1 { "" } else { "s" },
            )
        } else {
            format!(
                "{prefix}{total_hits} match{} in {} file{}",
                if total_hits == 1 { "" } else { "es" },
                pending.len(),
                if pending.len() == 1 { "" } else { "s" },
            )
        };
        let mut buf: Vec<u16> = s.encode_utf16().chain(std::iter::once(0)).collect();
        unsafe {
            let _ = SetWindowTextW(status, PCWSTR(buf.as_mut_ptr()));
        }
    }

    // Reveal the dock if we have something to show. On a
    // cancelled-with-zero-results we leave the dock as-is so the
    // user isn't surprised by a sudden empty pane.
    if any_results {
        unsafe { show_fif_dock(main_hwnd) };
    } else if cancelled {
        // No-op: keep prior dock state.
    } else {
        // Done with zero results: surface a status message on the
        // Find/Replace dialog if it's still around. Quietest
        // signal that doesn't demand a modal dialog.
        if let Some(dlg) = dialog {
            let mut buf: Vec<u16> = "Find in Files: no results"
                .encode_utf16()
                .chain(std::iter::once(0))
                .collect();
            unsafe {
                let _ = SetWindowTextW(dlg, PCWSTR(buf.as_mut_ptr()));
            }
        }
    }
}

/// Open the file referenced by the listview row the user just
/// double-clicked, then position the caret at the matched line +
/// column once the load completes (queued via Shell's normal load
/// path; the post-load focus shift is handled by the existing
/// load drain).
unsafe fn handle_fif_listview_dblclk(main_hwnd: HWND, row: usize) {
    // Look up the row in the index, queue an open through the
    // Shell's normal load path, and stash the (line, col) so the
    // next `WM_APP_WAKE` drain can apply the caret jump once the
    // file's text is in Scintilla. open_file is async so we can't
    // jump synchronously here ŌĆö the buffer would still be empty.
    let row_data = {
        let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
            return;
        };
        state.fif_listview_index.get(row).cloned()
    };
    let Some(row) = row_data else {
        return;
    };
    let deduped = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.fif_pending_jumps.push(row.clone());
        matches!(
            state.shell.open_file(row.path),
            OpenFileOutcome::SwitchedToExisting(_) | OpenFileOutcome::AlreadyActive
        )
    } else {
        false
    };
    // If the FIF target was already open (either as the active tab
    // or a background tab), no async load will fire ŌĆö the WM_APP_WAKE
    // drain that normally handles caret placement never wakes. Do
    // the tab-strip resync + view rebind synchronously so the user
    // lands on the matched line right away. `apply_pending_fif_jumps`
    // is idempotent (it only jumps when the active tab's path
    // matches a queued entry), so it's safe to call here even if
    // the load already applied the jump.
    if deduped {
        // SAFETY: caller (`main_wnd_proc`) owns the UI-thread borrow
        // and is not inside a plugin callback; each unsafe fn below
        // sends synchronous Win32 messages and doesn't re-enter our
        // wnd_proc.
        unsafe {
            refresh_tab_chrome(main_hwnd);
            handle_tab_selchange(main_hwnd);
            apply_pending_fif_jumps(main_hwnd);
        }
    }
}

/// Walk `fif_pending_jumps`; for each entry whose path matches a
/// fully-loaded tab in the shell, apply a Scintilla `SCI_GOTOLINE`
/// + `SCI_GOTOPOS` to land the caret at the matched (line, col).
///
/// Applied entries are removed; unmatched ones stay queued for a
/// later drain ŌĆö the load may still be in flight.
unsafe fn apply_pending_fif_jumps(main_hwnd: HWND) {
    let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
        return;
    };
    if state.fif_pending_jumps.is_empty() {
        return;
    }
    // Snapshot the active tab's path + load state. If the active
    // tab isn't loaded yet, there's nothing to apply this round.
    let Some(active) = state.shell.active() else {
        return;
    };
    let Some(active_path) = active.path.clone() else {
        return;
    };
    if active.pending_load.is_some() {
        return;
    }
    let editor = state.editor;
    let mut applied_any = false;
    state.fif_pending_jumps.retain(|jump| {
        if jump.path != active_path {
            return true; // not yet ŌĆö keep for next drain
        }
        // SCI_GOTOLINE puts the caret at column 0 of (line - 1)
        // and brings the line into view. We then read the
        // line-start position via SCI_GETCURRENTPOS and select
        // the matched span via SCI_SETSEL ŌĆö the selection
        // highlights the match and Scintilla's built-in
        // EnsureCaretVisible scrolls horizontally so a long
        // line's match isn't clipped by the right edge.
        let line_zero_based = jump.line_no.saturating_sub(1) as codepp_scintilla_sys::uptr_t;
        editor.send(codepp_scintilla_sys::SCI_GOTOLINE, line_zero_based, 0);
        let line_start = editor.send(codepp_scintilla_sys::SCI_GETCURRENTPOS, 0, 0);
        let start_pos =
            (line_start as i64 + i64::from(jump.col_start)).max(0) as codepp_scintilla_sys::uptr_t;
        let end_pos =
            (line_start as i64 + i64::from(jump.col_end)).max(0) as codepp_scintilla_sys::sptr_t;
        editor.send(codepp_scintilla_sys::SCI_SETSEL, start_pos, end_pos);
        applied_any = true;
        false // remove this entry
    });
    // Unconditional vertical re-centre. `SCI_SETSEL` already
    // scrolled the matched line on-screen at the nearest edge ŌĆö
    // for the dock case, that edge is just above the dock's
    // header, which leaves the match looking pinned to the
    // bottom. `center_caret` (vs `_if_offscreen`) ignores the
    // already-on-screen short-circuit and re-scrolls so the
    // matched line lands in the middle of the editor's reduced
    // height.
    if applied_any {
        center_caret(&editor);
    }
}

/// Show the FIF dock and resize Scintilla around it. Idempotent.
unsafe fn show_fif_dock(main_hwnd: HWND) {
    let snapshot = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        if state.fif_dock_visible {
            return;
        }
        state.fif_dock_visible = true;
        Some((
            state.toolbar_hwnd,
            state.toolbar_bitmap_px,
            state.tab_hwnd,
            state.scintilla_hwnd,
            state.status_hwnd,
            state.fif_splitter_hwnd,
            state.fif_dock_hwnd,
            state.fif_dock_height,
            WorkspaceLayout {
                panel: state.workspace_hwnd,
                splitter: state.workspace_splitter_hwnd,
                visible: state.workspace_visible,
                width: state.workspace_width,
            },
            DocMapLayout {
                panel: state.docmap_hwnd,
                splitter: state.docmap_splitter_hwnd,
                visible: state.docmap_visible,
                width: state.docmap_width,
            },
        ))
    } else {
        None
    };
    let Some((
        toolbar_hwnd,
        toolbar_bitmap_px,
        tabs,
        scintilla,
        status,
        splitter,
        dock,
        dock_height,
        workspace,
        docmap,
    )) = snapshot
    else {
        return;
    };
    unsafe {
        let _ = ShowWindow(splitter, SW_SHOW);
        let _ = ShowWindow(dock, SW_SHOW);
        let mut rect = RECT::default();
        if GetClientRect(main_hwnd, &raw mut rect).is_ok() {
            // Read current tab-strip visibility ŌĆö `IsWindowVisible`
            // is the source of truth (toggled by `NPPM_HIDETABBAR`).
            let tab_hidden = !IsWindowVisible(tabs).as_bool();
            layout_children(
                toolbar_hwnd,
                toolbar::toolbar_height_px(toolbar_bitmap_px),
                tabs,
                scintilla,
                status,
                splitter,
                dock,
                true,
                dock_height,
                tab_hidden,
                workspace,
                docmap,
                rect.right,
                rect.bottom,
            );
        }
    }
}

/// Hide the FIF dock and resize Scintilla to reclaim its space.
/// Idempotent. Listview contents are preserved across show/hide
/// cycles ŌĆö the user can re-trigger via the next search.
unsafe fn hide_fif_dock(main_hwnd: HWND) {
    let snapshot = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        if !state.fif_dock_visible {
            return;
        }
        state.fif_dock_visible = false;
        Some((
            state.toolbar_hwnd,
            state.toolbar_bitmap_px,
            state.tab_hwnd,
            state.scintilla_hwnd,
            state.status_hwnd,
            state.fif_splitter_hwnd,
            state.fif_dock_hwnd,
            state.fif_dock_height,
            WorkspaceLayout {
                panel: state.workspace_hwnd,
                splitter: state.workspace_splitter_hwnd,
                visible: state.workspace_visible,
                width: state.workspace_width,
            },
            DocMapLayout {
                panel: state.docmap_hwnd,
                splitter: state.docmap_splitter_hwnd,
                visible: state.docmap_visible,
                width: state.docmap_width,
            },
        ))
    } else {
        None
    };
    let Some((
        toolbar_hwnd,
        toolbar_bitmap_px,
        tabs,
        scintilla,
        status,
        splitter,
        dock,
        dock_height,
        workspace,
        docmap,
    )) = snapshot
    else {
        return;
    };
    unsafe {
        let _ = ShowWindow(splitter, SW_HIDE);
        let _ = ShowWindow(dock, SW_HIDE);
        let mut rect = RECT::default();
        if GetClientRect(main_hwnd, &raw mut rect).is_ok() {
            let tab_hidden = !IsWindowVisible(tabs).as_bool();
            layout_children(
                toolbar_hwnd,
                toolbar::toolbar_height_px(toolbar_bitmap_px),
                tabs,
                scintilla,
                status,
                splitter,
                dock,
                false,
                dock_height,
                tab_hidden,
                workspace,
                docmap,
                rect.right,
                rect.bottom,
            );
        }
    }
}

/// Prompt the user for a folder via `SHBrowseForFolderW` and
/// return the chosen path. `None` on cancel or any failure ŌĆö the
/// caller should treat a `None` as "user backed out."
///
/// `initial` is the folder the picker opens on. Passing the
/// current workspace root gives the user a natural "change my
/// mind" flow (the picker starts where they last chose).
///
/// Uses the older `SHBrowseForFolderW` for symmetry with
/// [`handle_fif_browse`]; a Vista+ `IFileOpenDialog` migration is
/// a shared cleanup for both call sites, tracked as a future
/// polish item.
///
/// # Safety
///
/// UI thread only. `owner` should be a live top-level HWND to
/// anchor the dialog against; the picker spins its own message
/// loop, so the caller must ensure no `&mut WindowState` borrow
/// is live when this returns (the picker can re-enter our
/// `wnd_proc` during its pump).
unsafe fn prompt_pick_workspace_folder(owner: HWND, initial: Option<&Path>) -> Option<PathBuf> {
    use std::os::windows::ffi::OsStrExt;
    use windows::Win32::System::Com::CoTaskMemFree;
    use windows::Win32::UI::Shell::{
        SHBrowseForFolderW, SHGetPathFromIDListW, BFFM_INITIALIZED, BIF_NEWDIALOGSTYLE,
        BIF_RETURNONLYFSDIRS, BROWSEINFOW,
    };

    // Seed the picker with the caller's initial path so the user
    // opens exactly where they last were. Encoded as a wide-string
    // via `OsStr::encode_wide` ŌĆö lossless round-trip for any real
    // filesystem path.
    let mut initial_w: Vec<u16> = initial
        .map(|p| {
            p.as_os_str()
                .encode_wide()
                .chain(std::iter::once(0))
                .collect()
        })
        .unwrap_or_default();

    extern "system" fn browse_cb(hwnd: HWND, msg: u32, _lparam: LPARAM, lp_data: LPARAM) -> i32 {
        if msg == BFFM_INITIALIZED && lp_data.0 != 0 {
            const BFFM_SETSELECTIONW: u32 = 0x467;
            unsafe {
                SendMessageW(hwnd, BFFM_SETSELECTIONW, Some(WPARAM(1)), Some(lp_data));
            }
        }
        0
    }

    let bi = BROWSEINFOW {
        hwndOwner: owner,
        ulFlags: BIF_RETURNONLYFSDIRS | BIF_NEWDIALOGSTYLE,
        lpfn: Some(browse_cb),
        lParam: LPARAM(if initial_w.is_empty() {
            0
        } else {
            initial_w.as_mut_ptr() as isize
        }),
        ..Default::default()
    };
    let pidl = unsafe { SHBrowseForFolderW(&raw const bi) };
    if pidl.is_null() {
        return None;
    }
    let mut path_buf = [0u16; 260];
    let ok = unsafe { SHGetPathFromIDListW(pidl, &mut path_buf) };
    unsafe { CoTaskMemFree(Some(pidl as *const _)) };
    if !ok.as_bool() {
        return None;
    }
    let null_idx = path_buf
        .iter()
        .position(|&c| c == 0)
        .unwrap_or(path_buf.len());
    // `OsString::from_wide` is lossless ŌĆö it preserves every
    // UTF-16 code unit including unpaired surrogates. Using
    // `String::from_utf16_lossy` here would substitute U+FFFD on
    // any bad surrogate, and m3's `read_dir` on the resulting
    // `PathBuf` would silently resolve to a different directory
    // (an attacker-plantable junction with a name differing only
    // in the corrupted code point). NTFS permits filenames with
    // unpaired surrogates, so this isn't purely hypothetical.
    use std::os::windows::ffi::OsStringExt;
    let os = std::ffi::OsString::from_wide(&path_buf[..null_idx]);
    Some(PathBuf::from(os))
}

// ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
// Workspace tree ŌĆö lazy directory population.
//
// The tree is populated one folder at a time via
// `TVN_ITEMEXPANDINGW`. Each folder node uses `lParam` as a
// state machine:
//   * `WORKSPACE_ITEM_FILE  = 0` ŌĆö file (leaf).
//   * `WORKSPACE_ITEM_UNPOP = 1` ŌĆö folder, not yet populated
//     (has a placeholder child so the [+] chevron appears).
//   * `WORKSPACE_ITEM_POP   = 2` ŌĆö folder, populated (real
//     children ŌĆö either subfolders + files, or nothing if the
//     folder was empty).
// The `TVN_ITEMEXPANDINGW` handler reads the state, populates
// on `UNPOP`, transitions to `POP`. Subsequent expands are
// no-ops on the state flip.

/// Item lParam sentinel: leaf file. No children.
const WORKSPACE_ITEM_FILE: isize = 0;
/// Item lParam sentinel: folder with a placeholder child, not
/// yet read from disk. Populated on first `TVN_ITEMEXPANDING`.
const WORKSPACE_ITEM_UNPOP: isize = 1;
/// Item lParam sentinel: folder whose real children are loaded.
const WORKSPACE_ITEM_POP: isize = 2;

/// Classification of the workspace tree node that was
/// right-clicked. Determines which items appear in the popup
/// (Remove is root-only; Copy file name / Open / Run by system
/// are file-only) and how "Explorer/CMD/PowerShell here" resolves
/// the working directory (folder ŌåÆ the folder itself; file ŌåÆ the
/// parent directory).
#[derive(Copy, Clone, Debug, PartialEq, Eq)]
enum WorkspaceCtxKind {
    Root,
    Folder,
    File,
}

/// Payload captured on right-click and consumed by the `WM_COMMAND`
/// arm of the chosen menu item. Stored on
/// [`WindowState::workspace_ctx_target`].
#[derive(Clone, Debug)]
struct WorkspaceCtxTarget {
    path: PathBuf,
    kind: WorkspaceCtxKind,
}

/// Ask the OS for the system-icon-list index of a filesystem
/// entry. `SHGFI_USEFILEATTRIBUTES` makes `SHGetFileInfoW` skip
/// any actual disk access ŌĆö it derives the icon from the passed
/// attribute bits alone. Fast, so cheap to call per-item during
/// populate.
///
/// # Safety
///
/// `name_wide` must be a null-terminated wide string. UI-thread
/// only (the system image list is one per process; concurrent
/// access is fine but keeps the pattern consistent with the
/// rest of the file).
unsafe fn sys_icon_index_for(name_wide: &[u16], is_dir: bool) -> i32 {
    use windows::Win32::Storage::FileSystem::{FILE_ATTRIBUTE_DIRECTORY, FILE_ATTRIBUTE_NORMAL};
    let attribs = if is_dir {
        FILE_ATTRIBUTE_DIRECTORY
    } else {
        FILE_ATTRIBUTE_NORMAL
    };
    let mut sfi = SHFILEINFOW::default();
    unsafe {
        SHGetFileInfoW(
            PCWSTR(name_wide.as_ptr()),
            attribs,
            Some(&raw mut sfi),
            std::mem::size_of::<SHFILEINFOW>() as u32,
            SHGFI_SYSICONINDEX | SHGFI_SMALLICON | SHGFI_USEFILEATTRIBUTES,
        );
    }
    sfi.iIcon
}

/// Insert one item under `parent` in `tree`. Returns the new
/// item's handle, or a null handle on failure (caller should
/// treat as "insert dropped").
///
/// `has_placeholder`: if true AND `is_dir`, the caller is
/// responsible for inserting a placeholder child so the [+]
/// chevron appears; the item's `lParam` is set to
/// `WORKSPACE_ITEM_UNPOP`. If false, `lParam` becomes
/// `WORKSPACE_ITEM_FILE` (for files) or `WORKSPACE_ITEM_POP`
/// (for folders whose children are being inserted right now).
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND. UI-thread only.
unsafe fn tree_insert_item(
    tree: HWND,
    parent: HTREEITEM,
    name: &str,
    is_dir: bool,
    has_placeholder: bool,
) -> HTREEITEM {
    let name_wide: Vec<u16> = name.encode_utf16().chain(std::iter::once(0)).collect();
    let icon = unsafe { sys_icon_index_for(&name_wide, is_dir) };
    let lparam_val = if !is_dir {
        WORKSPACE_ITEM_FILE
    } else if has_placeholder {
        WORKSPACE_ITEM_UNPOP
    } else {
        WORKSPACE_ITEM_POP
    };
    // `TVIF_CHILDREN` + `cChildren = 0` on an item is a
    // load-bearing HINT to TreeView: "this item has no
    // children, don't render a chevron." That hint sticks even
    // if we later insert real children under it ŌĆö the chevron
    // stays hidden and the user can't expand.
    //
    // So we only include TVIF_CHILDREN when we want to hint the
    // *presence* of children ahead of actually inserting them ŌĆö
    // the placeholder-folder case (`is_dir && has_placeholder`),
    // where the chevron must appear before the real `read_dir`
    // runs on expand. For everything else (root, populated
    // folder, file), omit the mask bit and let TreeView infer
    // the chevron from actual child count.
    let mask_bits = TVIF_TEXT
        | TVIF_IMAGE
        | TVIF_SELECTEDIMAGE
        | TVIF_PARAM
        | if is_dir && has_placeholder {
            TVIF_CHILDREN
        } else {
            windows::Win32::UI::Controls::TVITEM_MASK(0)
        };
    let item = TVITEMW {
        mask: mask_bits,
        pszText: windows::core::PWSTR(name_wide.as_ptr().cast_mut()),
        cchTextMax: name_wide.len() as i32,
        iImage: icon,
        iSelectedImage: icon,
        cChildren: windows::Win32::UI::Controls::TVITEMEXW_CHILDREN(i32::from(
            is_dir && has_placeholder,
        )),
        lParam: LPARAM(lparam_val),
        ..Default::default()
    };
    let insert = TVINSERTSTRUCTW {
        hParent: parent,
        hInsertAfter: TVI_LAST,
        Anonymous: windows::Win32::UI::Controls::TVINSERTSTRUCTW_0 { item },
    };
    let result = unsafe {
        SendMessageW(
            tree,
            TVM_INSERTITEMW,
            Some(WPARAM(0)),
            Some(LPARAM(&raw const insert as isize)),
        )
    };
    HTREEITEM(result.0)
}

/// Insert a hidden "placeholder" child under `parent` so its
/// `[+]` chevron shows without us having to `read_dir` yet.
/// The placeholder itself is invisible in practice ŌĆö the
/// user only sees it in the flash between clicking `[+]` and
/// the real children arriving via `TVN_ITEMEXPANDINGW`.
///
/// # Safety
///
/// Same as [`tree_insert_item`].
unsafe fn tree_insert_placeholder(tree: HWND, parent: HTREEITEM) {
    // Empty-string placeholder. `TVIF_PARAM` marker so we can
    // recognise & delete it on the first real populate.
    let name_wide: [u16; 1] = [0];
    let item = TVITEMW {
        mask: TVIF_TEXT | TVIF_PARAM,
        pszText: windows::core::PWSTR(name_wide.as_ptr().cast_mut()),
        cchTextMax: 0,
        // Sentinel `-1` so we can distinguish the placeholder
        // from every real item (file=0, unpop=1, pop=2).
        lParam: LPARAM(-1),
        ..Default::default()
    };
    let insert = TVINSERTSTRUCTW {
        hParent: parent,
        hInsertAfter: TVI_LAST,
        Anonymous: windows::Win32::UI::Controls::TVINSERTSTRUCTW_0 { item },
    };
    unsafe {
        SendMessageW(
            tree,
            TVM_INSERTITEMW,
            Some(WPARAM(0)),
            Some(LPARAM(&raw const insert as isize)),
        );
    }
}

/// `read_dir(dir)` and insert its entries as children of
/// `parent`. Folders come first alphabetically, then files
/// alphabetically ŌĆö matches Explorer's ordering. Each subfolder
/// gets a placeholder so the `[+]` chevron shows without us
/// recursing here (that's the "lazy" part ŌĆö recursion happens
/// per-folder on user expand).
///
/// Errors from `read_dir` are logged and treated as "empty
/// directory" ŌĆö the folder shows as expanded with no children.
///
/// # Safety
///
/// Same as [`tree_insert_item`].
unsafe fn insert_tree_folder_children(tree: HWND, parent: HTREEITEM, dir: &Path) {
    let mut folders: Vec<String> = Vec::new();
    let mut files: Vec<String> = Vec::new();
    match std::fs::read_dir(dir) {
        Ok(entries) => {
            for entry in entries.flatten() {
                let name = entry.file_name().to_string_lossy().into_owned();
                // `file_type()` is fast (uses cached dir-entry metadata
                // on Windows); no extra `stat` call.
                let is_dir = entry.file_type().is_ok_and(|ft| ft.is_dir());
                if is_dir {
                    folders.push(name);
                } else {
                    files.push(name);
                }
            }
        }
        Err(e) => {
            tracing::warn!(dir = ?dir, error = %e, "workspace read_dir failed; showing empty folder");
            return;
        }
    }
    // Case-insensitive sort ŌĆö Explorer's behaviour on Windows.
    // Rust's default `sort()` is case-sensitive; the closure
    // below folds case for comparison without allocating extra.
    folders.sort_by_key(|s| s.to_lowercase());
    files.sort_by_key(|s| s.to_lowercase());
    for name in &folders {
        let node = unsafe { tree_insert_item(tree, parent, name, true, true) };
        if node.0 != 0 {
            unsafe { tree_insert_placeholder(tree, node) };
        }
    }
    for name in &files {
        unsafe { tree_insert_item(tree, parent, name, false, false) };
    }
}

/// Wipe every item in the tree via `TVM_DELETEITEM(TVI_ROOT)`.
/// Called before re-populating (e.g. on `File ŌåÆ Open Folder
/// as Workspace...` re-root).
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND.
unsafe fn tree_clear_all(tree: HWND) {
    unsafe {
        SendMessageW(
            tree,
            TVM_DELETEITEM,
            Some(WPARAM(0)),
            Some(LPARAM(TVI_ROOT.0)),
        );
    }
}

/// Populate the tree with the workspace root as the top node
/// and its direct children as the second level. Subfolders get
/// placeholders so `[+]` chevrons show without any deeper
/// `read_dir` calls ŌĆö subsequent expands populate one folder
/// at a time via [`insert_tree_folder_children`].
///
/// The root node is inserted expanded (`TVM_EXPAND(TVE_EXPAND)`)
/// so the user sees the top level immediately without an extra
/// click.
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND. UI-thread only.
unsafe fn populate_workspace_root(tree: HWND, root: &Path) {
    unsafe { tree_clear_all(tree) };
    let root_name = root.file_name().map_or_else(
        || root.to_string_lossy().into_owned(),
        |s| s.to_string_lossy().into_owned(),
    );
    // `TVI_ROOT` is the documented sentinel for "insert as a
    // top-level item." `HTREEITEM::default()` (i.e. NULL) happens
    // to work as a synonym on current Windows but isn't part of
    // the documented contract ŌĆö use the explicit sentinel.
    let root_node = unsafe { tree_insert_item(tree, TVI_ROOT, &root_name, true, false) };
    if root_node.0 == 0 {
        return;
    }
    unsafe { insert_tree_folder_children(tree, root_node, root) };
    // Auto-expand the root so the user sees the first level
    // without clicking. Second- and deeper-level expands remain
    // lazy per [`TVN_ITEMEXPANDINGW`].
    unsafe {
        SendMessageW(
            tree,
            TVM_EXPAND,
            Some(WPARAM(TVE_EXPAND.0 as usize)),
            Some(LPARAM(root_node.0)),
        );
    }
}

/// Read the text of a tree item into an owned `String`. Used
/// by [`tree_item_full_path`] to reconstruct a filesystem path
/// by walking from an item up to the root.
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND, `item` a live
/// item in it.
unsafe fn tree_item_text(tree: HWND, item: HTREEITEM) -> String {
    // MAX_PATH is enough for one path component; components
    // longer than that are exceptionally rare (Windows'
    // NAME_MAX per-component is 255 typically).
    let mut buf = [0u16; 260];
    let mut item_out = TVITEMW {
        mask: TVIF_TEXT,
        hItem: item,
        pszText: windows::core::PWSTR(buf.as_mut_ptr()),
        cchTextMax: buf.len() as i32,
        ..Default::default()
    };
    unsafe {
        SendMessageW(
            tree,
            TVM_GETITEMW,
            Some(WPARAM(0)),
            Some(LPARAM(&raw mut item_out as isize)),
        );
    }
    let null_idx = buf.iter().position(|&c| c == 0).unwrap_or(buf.len());
    use std::os::windows::ffi::OsStringExt;
    std::ffi::OsString::from_wide(&buf[..null_idx])
        .to_string_lossy()
        .into_owned()
}

/// Reconstruct the full filesystem path of `item` by walking
/// from it up to the root, collecting each item's text as a
/// path component, and joining onto `workspace_root`. The
/// topmost item (the root node) is skipped ŌĆö its text is
/// `workspace_root`'s basename, which is already implicit in
/// `workspace_root` itself.
///
/// # Safety
///
/// Same as [`tree_item_text`].
unsafe fn tree_item_full_path(tree: HWND, item: HTREEITEM, workspace_root: &Path) -> PathBuf {
    let mut components: Vec<String> = Vec::new();
    let mut cur = item;
    // Walk up: for each item, if it has a parent, keep its text;
    // when we hit the root (parent == null), stop.
    loop {
        let parent = unsafe {
            SendMessageW(
                tree,
                TVM_GETNEXTITEM,
                Some(WPARAM(TVGN_PARENT as usize)),
                Some(LPARAM(cur.0)),
            )
        };
        if parent.0 == 0 {
            // `cur` is the root node ŌĆö its text (workspace_root
            // basename) is NOT a path component to append; the
            // components collected so far are already relative
            // to workspace_root.
            break;
        }
        components.push(unsafe { tree_item_text(tree, cur) });
        cur = HTREEITEM(parent.0);
    }
    components.reverse();
    let mut path = workspace_root.to_path_buf();
    for c in components {
        path.push(c);
    }
    path
}

/// Read a tree item's `lParam` (our state sentinel: file /
/// folder-unpopulated / folder-populated / placeholder).
///
/// # Safety
///
/// Same as [`tree_item_text`].
unsafe fn tree_item_lparam(tree: HWND, item: HTREEITEM) -> isize {
    let mut item_out = TVITEMW {
        mask: TVIF_PARAM,
        hItem: item,
        ..Default::default()
    };
    unsafe {
        SendMessageW(
            tree,
            TVM_GETITEMW,
            Some(WPARAM(0)),
            Some(LPARAM(&raw mut item_out as isize)),
        );
    }
    item_out.lParam.0
}

/// Write a tree item's `lParam`. Paired with
/// [`tree_item_lparam`] to transition folders from
/// `WORKSPACE_ITEM_UNPOP` ŌåÆ `WORKSPACE_ITEM_POP` after the
/// first lazy populate.
///
/// # Safety
///
/// Same as [`tree_item_text`].
unsafe fn tree_set_item_lparam(tree: HWND, item: HTREEITEM, lparam: isize) {
    let item_set = TVITEMW {
        mask: TVIF_PARAM,
        hItem: item,
        lParam: LPARAM(lparam),
        ..Default::default()
    };
    unsafe {
        SendMessageW(
            tree,
            TVM_SETITEMW,
            Some(WPARAM(0)),
            Some(LPARAM(&raw const item_set as isize)),
        );
    }
}

/// Remove every child of `parent`. Used to strip the placeholder
/// off an `UNPOP` folder before inserting real children.
///
/// # Safety
///
/// Same as [`tree_item_text`].
unsafe fn tree_delete_all_children(tree: HWND, parent: HTREEITEM) {
    loop {
        let child = unsafe {
            SendMessageW(
                tree,
                TVM_GETNEXTITEM,
                Some(WPARAM(TVGN_CHILD as usize)),
                Some(LPARAM(parent.0)),
            )
        };
        if child.0 == 0 {
            break;
        }
        unsafe {
            SendMessageW(tree, TVM_DELETEITEM, Some(WPARAM(0)), Some(LPARAM(child.0)));
        }
    }
}

/// Handle `TVN_ITEMEXPANDINGW`: if the item is an unpopulated
/// folder (`WORKSPACE_ITEM_UNPOP`), delete its placeholder,
/// `read_dir` its path, insert real children, and flip its
/// state to `WORKSPACE_ITEM_POP`. Any other state is a no-op ŌĆö
/// already-populated folders don't re-read on subsequent
/// expands.
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND on the UI thread.
/// `workspace_root` must match the tree's current population
/// (it's what path reconstruction joins against).
unsafe fn handle_tree_item_expanding(tree: HWND, item: HTREEITEM, workspace_root: &Path) {
    let state = unsafe { tree_item_lparam(tree, item) };
    if state != WORKSPACE_ITEM_UNPOP {
        return;
    }
    let path = unsafe { tree_item_full_path(tree, item, workspace_root) };
    unsafe { tree_delete_all_children(tree, item) };
    unsafe { insert_tree_folder_children(tree, item, &path) };
    unsafe { tree_set_item_lparam(tree, item, WORKSPACE_ITEM_POP) };
}

/// Handle `NM_DBLCLK` on the tree: if a file item is selected,
/// route it to `Shell::open_file`. Folder items are ignored ŌĆö
/// `TreeView`'s default `NM_DBLCLK` handling toggles their expand
/// state, which is the desired behaviour.
///
/// # Safety
///
/// `main_hwnd` must be the main window. `tree` a live tree HWND.
unsafe fn handle_tree_double_click(main_hwnd: HWND, tree: HWND) {
    // Which item is under the cursor / selected? On a double-click,
    // TreeView has already updated the selection to the clicked
    // item, so `TVGN_CARET` gives the right answer.
    let selected = unsafe {
        SendMessageW(
            tree,
            TVM_GETNEXTITEM,
            Some(WPARAM(TVGN_CARET as usize)),
            Some(LPARAM(0)),
        )
    };
    let item = HTREEITEM(selected.0);
    if item.0 == 0 {
        return;
    }
    let state = unsafe { tree_item_lparam(tree, item) };
    if state != WORKSPACE_ITEM_FILE {
        // Folder ŌĆö let TreeView's own double-click-to-expand
        // handling run. We return WITHOUT consuming, so the
        // default proc will toggle expand.
        return;
    }
    // Reconstruct the file path against the current workspace
    // root and open it.
    let root = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_root.clone()
    } else {
        None
    };
    let Some(root) = root else {
        return;
    };
    let path = unsafe { tree_item_full_path(tree, item, &root) };
    // Defense in depth: `tree_item_full_path` joins each tree
    // item's displayed text (which came from `read_dir`) onto
    // `workspace_root` via `PathBuf::push`. On a well-behaved
    // Windows filesystem, `read_dir` never returns entries with
    // path separators or absolute-path syntax ŌĆö so the joined
    // path stays under `workspace_root`. But `PathBuf::push`
    // with an absolute component REPLACES the accumulated
    // path, so a hostile network filesystem / third-party
    // driver that returned e.g. a name starting with `\` could
    // in principle escape. Verify before handing to
    // `Shell::open_file`; a mismatch is a bug in the FS or the
    // tree state, not something to silently paper over.
    if !path.starts_with(&root) {
        tracing::warn!(
            path = ?path,
            root = ?root,
            "workspace tree: reconstructed path escaped root; refusing to open"
        );
        return;
    }
    // Drop the state borrow completely, then call open_file on
    // a fresh borrow ŌĆö `Shell::open_file` mutates and we do NOT
    // want a re-entrant borrow via any load-progress wakeup.
    if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        let _ = state.shell.open_file(path);
    }
    // `open_file` queues a load; the tab strip / editor update
    // when the load completes (WM_APP_WAKE drain). No further
    // action needed here.
    unsafe {
        crate::fire_queued_notifications(main_hwnd);
        refresh_tab_chrome(main_hwnd);
    }
}

/// Get the first child of `item` in the tree, or a null handle
/// if there are none. Wrapper around `TVM_GETNEXTITEM(TVGN_CHILD)`.
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND.
unsafe fn tree_first_child(tree: HWND, item: HTREEITEM) -> HTREEITEM {
    let r = unsafe {
        SendMessageW(
            tree,
            TVM_GETNEXTITEM,
            Some(WPARAM(TVGN_CHILD as usize)),
            Some(LPARAM(item.0)),
        )
    };
    HTREEITEM(r.0)
}

/// Get the next sibling of `item` ŌĆö the item that follows it at
/// the same level. Null handle if `item` is the last sibling.
///
/// # Safety
///
/// Same as [`tree_first_child`].
unsafe fn tree_next_sibling(tree: HWND, item: HTREEITEM) -> HTREEITEM {
    let r = unsafe {
        SendMessageW(
            tree,
            TVM_GETNEXTITEM,
            Some(WPARAM(TVGN_NEXT as usize)),
            Some(LPARAM(item.0)),
        )
    };
    HTREEITEM(r.0)
}

/// `TVM_EXPAND(action, item)` shorthand. `action` is one of
/// `TVE_EXPAND` / `TVE_COLLAPSE`.
///
/// # Safety
///
/// Same as [`tree_first_child`].
unsafe fn tree_expand(tree: HWND, item: HTREEITEM, action: u32) {
    unsafe {
        SendMessageW(
            tree,
            TVM_EXPAND,
            Some(WPARAM(action as usize)),
            Some(LPARAM(item.0)),
        );
    }
}

/// Depth-first walk of the tree from `item`, invoking `visit` on
/// every descendant (in visit-parent-first order). Callers use
/// this to implement Unfold All / Fold All / Locate ŌĆö each of
/// which mutates state via `visit` (expanding, collapsing, or
/// searching). Iterative to avoid stack blowup on deep trees.
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND. `visit` is called
/// on the UI thread; nothing forbids it from re-entering
/// `TreeView` APIs but the caller should ensure it doesn't delete
/// `item` mid-walk.
unsafe fn tree_walk_descendants<F: FnMut(HWND, HTREEITEM)>(
    tree: HWND,
    item: HTREEITEM,
    visit: &mut F,
) {
    // Stack of items to process. We push a subtree root, then
    // pop-visit-push-children.
    let mut stack: Vec<HTREEITEM> = vec![item];
    while let Some(node) = stack.pop() {
        visit(tree, node);
        // Push children in reverse so the leftmost child is
        // processed next (visually first).
        let mut children: Vec<HTREEITEM> = Vec::new();
        let mut child = unsafe { tree_first_child(tree, node) };
        while child.0 != 0 {
            children.push(child);
            child = unsafe { tree_next_sibling(tree, child) };
        }
        for c in children.into_iter().rev() {
            stack.push(c);
        }
    }
}

/// Write a fresh "Expanding folders: N" caption into the
/// counter label. Called on every tick so the user sees
/// progress climb.
///
/// # Safety
///
/// `label` must be a live STATIC HWND on the UI thread.
unsafe fn update_workspace_unfold_label(label: HWND, count: usize) {
    let text = format!("Expanding folders: {count}");
    let wide: Vec<u16> = text.encode_utf16().chain(std::iter::once(0)).collect();
    unsafe {
        let _ = SetWindowTextW(label, PCWSTR(wide.as_ptr()));
    }
}

/// Kick off the async "Unfold All" walk. Hides the tree, shows
/// the marquee progress + counter overlay, seeds the pending
/// queue with the root, starts the `WM_TIMER` that ticks the
/// state machine. Idempotent: a second click while a walk is
/// already in progress is a no-op.
///
/// **Why the overlay?** Each per-tick tree expand fires
/// notifications that dirty the tree; without hiding it, the
/// user sees rows blip in for every one of the hundreds/thousands
/// of folders being walked ŌĆö flicker that undermines the whole
/// point of "responsive UI." Hiding + overlay eliminates the
/// mid-walk paints; the tree only paints once, at the end,
/// showing the final expanded state.
///
/// **Why marquee, not %?** Total folder count isn't known
/// upfront (that's what the walk is for). The queue-based
/// discovery means "% done" would fluctuate misleadingly as new
/// UNPOP folders are discovered and enqueued. A marquee
/// animation + growing count is honest ("something's happening,
/// N so far").
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn start_workspace_unfold_all(main_hwnd: HWND) {
    let snapshot = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        (
            state.workspace_tree_hwnd,
            state.workspace_unfold_progress,
            state.workspace_unfold_label,
            !state.workspace_unfold_pending.is_empty(),
        )
    } else {
        return;
    };
    let (tree, progress, label, already_running) = snapshot;
    if already_running {
        // A walk is already in progress; ignore the extra click
        // rather than spawning a second timer that would race the
        // first one's queue mutations.
        return;
    }
    let root = unsafe {
        SendMessageW(
            tree,
            TVM_GETNEXTITEM,
            Some(WPARAM(TVGN_ROOT as usize)),
            Some(LPARAM(0)),
        )
    };
    let root_item = HTREEITEM(root.0);
    if root_item.0 == 0 {
        return;
    }
    if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_unfold_pending.push(root_item);
        state.workspace_unfold_count = 0;
    }
    unsafe {
        // Swap the tree for the overlay: hide tree, show
        // progress + label, kick off the marquee animation.
        let _ = ShowWindow(tree, SW_HIDE);
        update_workspace_unfold_label(label, 0);
        let _ = ShowWindow(progress, SW_SHOW);
        let _ = ShowWindow(label, SW_SHOW);
        // 30 ms marquee-step interval ŌĆö smooth animation without
        // burning CPU.
        SendMessageW(progress, PBM_SETMARQUEE, Some(WPARAM(1)), Some(LPARAM(30)));
        // 15 ms timer ŌĆö matches Windows' clock granularity so we
        // process a batch as often as the system will wake us.
        // With `WORKSPACE_UNFOLD_BATCH_SIZE = 20`, that's ~1300
        // folders/sec ŌĆö a 5000-folder workspace unfolds in ~4 s.
        SetTimer(Some(main_hwnd), WORKSPACE_UNFOLD_TIMER_ID, 15, None);
    }
}

/// Process a batch of folders from the "Unfold All" pending
/// queue. Called from the `WM_TIMER(WORKSPACE_UNFOLD_TIMER_ID)`
/// arm of `main_wnd_proc`. Returns `true` if more work remains,
/// `false` if the queue is empty (caller kills the timer +
/// triggers the completion path).
///
/// Batch size is [`WORKSPACE_UNFOLD_BATCH_SIZE`] ŌĆö we can be
/// aggressive here because the tree is hidden during the walk,
/// so per-batch tree paints aren't visible. The message pump
/// still runs between ticks, so paint / mouse / keys flow
/// normally.
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn tick_workspace_unfold(main_hwnd: HWND) -> bool {
    let tree = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_tree_hwnd
    } else {
        return false;
    };
    let mut processed_this_tick = 0usize;
    for _ in 0..WORKSPACE_UNFOLD_BATCH_SIZE {
        let node = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
            state.workspace_unfold_pending.pop()
        } else {
            break;
        };
        let Some(node) = node else { break };
        // Expand this folder ŌĆö fires `TVN_ITEMEXPANDING`
        // synchronously, which populates its children on the
        // first expand (state machine `UNPOP ŌåÆ POP`). Idempotent
        // on already-populated folders.
        unsafe { tree_expand(tree, node, TVE_EXPAND.0) };
        // Discover this folder's subfolder children and enqueue
        // them for later ticks. Stack semantics (`Vec::push`) ŌåÆ
        // DFS: we dive into one branch before moving to siblings.
        let mut child = unsafe { tree_first_child(tree, node) };
        while child.0 != 0 {
            let child_state = unsafe { tree_item_lparam(tree, child) };
            if child_state == WORKSPACE_ITEM_UNPOP || child_state == WORKSPACE_ITEM_POP {
                if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
                    state.workspace_unfold_pending.push(child);
                }
            }
            child = unsafe { tree_next_sibling(tree, child) };
        }
        processed_this_tick += 1;
    }
    // Update the counter label at the end of the batch (one
    // paint per tick, not per folder).
    let (count, label, has_more) = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_unfold_count += processed_this_tick;
        (
            state.workspace_unfold_count,
            state.workspace_unfold_label,
            !state.workspace_unfold_pending.is_empty(),
        )
    } else {
        return false;
    };
    unsafe { update_workspace_unfold_label(label, count) };
    has_more
}

/// Completion path for the async "Unfold All" walk: stop the
/// marquee, hide the overlay, show the tree, and force a single
/// clean repaint so the user sees the final expanded state.
/// Called from the `WM_TIMER` arm when
/// [`tick_workspace_unfold`] returns `false`.
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn finish_workspace_unfold(main_hwnd: HWND) {
    let (tree, progress, label) = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        (
            state.workspace_tree_hwnd,
            state.workspace_unfold_progress,
            state.workspace_unfold_label,
        )
    } else {
        return;
    };
    unsafe {
        // Stop the animation before hiding ŌĆö a marquee that's
        // still animating while its window is hidden wastes a
        // tiny amount of CPU on the marquee thread until the
        // next `PBM_SETMARQUEE(0)`.
        SendMessageW(progress, PBM_SETMARQUEE, Some(WPARAM(0)), Some(LPARAM(0)));
        let _ = ShowWindow(progress, SW_HIDE);
        let _ = ShowWindow(label, SW_HIDE);
        let _ = ShowWindow(tree, SW_SHOW);
        // Force one fresh paint of the fully-expanded tree.
        let _ = InvalidateRect(Some(tree), None, true);
        let _ = UpdateWindow(tree);
    }
}

/// Cancel an in-flight "Unfold All" walk. Called by `Fold All`
/// (so its `TVE_COLLAPSE` walk isn't racing the unfold) and by
/// `hide_workspace_panel` / `WM_DESTROY` (so a timer tick can't
/// fire on stale tree state after the panel is gone).
///
/// Symmetric with [`start_workspace_unfold_all`] ŌĆö restores
/// the tree/overlay visibility to its pre-unfold state.
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn cancel_workspace_unfold(main_hwnd: HWND) {
    let running = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        let running = !state.workspace_unfold_pending.is_empty();
        state.workspace_unfold_pending.clear();
        state.workspace_unfold_count = 0;
        running
    } else {
        return;
    };
    unsafe {
        let _ = KillTimer(Some(main_hwnd), WORKSPACE_UNFOLD_TIMER_ID);
    }
    if running {
        // Restore the panel to its pre-unfold visual state.
        unsafe { finish_workspace_unfold(main_hwnd) };
    }
}

/// Recursively collapse every folder in the tree. No I/O
/// happens ŌĆö just `TVM_EXPAND(TVE_COLLAPSE)` on each folder.
///
/// # Safety
///
/// Same as [`tree_unfold_all`].
unsafe fn tree_fold_all(tree: HWND) {
    let root = unsafe {
        SendMessageW(
            tree,
            TVM_GETNEXTITEM,
            Some(WPARAM(TVGN_ROOT as usize)),
            Some(LPARAM(0)),
        )
    };
    let root_item = HTREEITEM(root.0);
    if root_item.0 == 0 {
        return;
    }
    unsafe {
        SendMessageW(tree, WM_SETREDRAW, Some(WPARAM(0)), Some(LPARAM(0)));
        tree_walk_descendants(tree, root_item, &mut |t, node| {
            // Only need to touch folders; files have no expand state.
            let state = tree_item_lparam(t, node);
            if state == WORKSPACE_ITEM_UNPOP || state == WORKSPACE_ITEM_POP {
                tree_expand(t, node, TVE_COLLAPSE.0);
            }
        });
        SendMessageW(tree, WM_SETREDRAW, Some(WPARAM(1)), Some(LPARAM(0)));
        let _ = InvalidateRect(Some(tree), None, true);
        let _ = UpdateWindow(tree);
    }
}

/// Case-insensitive analogue of `Path::strip_prefix`. Returns
/// `Some(rest)` where `rest` is `target`'s components after
/// `prefix`, or `None` if `target` doesn't start with `prefix`
/// under case-insensitive comparison.
///
/// Windows filesystems (NTFS/FAT/exFAT) are case-insensitive at
/// the file-lookup layer, and Explorer displays whichever case
/// the on-disk metadata uses. Two paths that resolve to the same
/// file can therefore differ in case at any component ŌĆö most
/// commonly the drive letter ŌĆö so a case-sensitive `strip_prefix`
/// gives false negatives on identical files.
///
/// Comparison is `to_lowercase()`-based; imperfect Unicode case
/// folding is acceptable here because the fall-through only
/// affects the "Locate Current File" no-op case (worse than
/// perfect: locate silently does nothing on some non-ASCII
/// paths; better than the alternative: false-positive resolve to
/// the wrong file, which would corrupt user state).
fn strip_prefix_case_insensitive(target: &Path, prefix: &Path) -> Option<PathBuf> {
    let mut t_iter = target.components();
    let mut p_iter = prefix.components();
    loop {
        match (t_iter.next(), p_iter.next()) {
            (None, None) => {
                // Both exhausted ŌĆö target == prefix. The relative
                // remainder is empty.
                return Some(PathBuf::new());
            }
            (Some(first_extra), None) => {
                // Prefix exhausted while target has more ŌĆö the
                // remaining components form the relative path.
                // `first_extra` was consumed by the pattern match
                // and must be re-included; naive `t_iter.collect()`
                // silently drops it.
                let mut rel = PathBuf::from(first_extra.as_os_str());
                for c in t_iter {
                    rel.push(c);
                }
                return Some(rel);
            }
            (None, Some(_)) => return None,
            (Some(tc), Some(pc)) => {
                let ts = tc.as_os_str().to_string_lossy().to_lowercase();
                let ps = pc.as_os_str().to_string_lossy().to_lowercase();
                if ts != ps {
                    return None;
                }
            }
        }
    }
}

/// Reveal `target` in the tree by walking down from the root
/// one path component at a time, expanding each ancestor
/// folder along the way (triggering lazy population via
/// `TVN_ITEMEXPANDINGW`), and finally selecting + scrolling to
/// the leaf.
///
/// If `target` is not under `workspace_root`, returns silently
/// (matches N++'s no-feedback behaviour for the same case). If
/// any intermediate component is missing from disk (renamed
/// between panel open and now), the walk stops at the last
/// existing ancestor and selects that.
///
/// # Safety
///
/// `tree` must be a live `SysTreeView32` HWND.
unsafe fn tree_locate_path(tree: HWND, target: &Path, workspace_root: &Path) {
    // Only meaningful if `target` is under the workspace root.
    // Case-insensitive strip ŌĆö Windows filesystems are
    // case-insensitive, and `Path::strip_prefix` is case-sensitive
    // by default. Without this, drive-letter case differences
    // (`c:\foo` vs `C:\foo`) or a user opening a file via
    // drag-and-drop where the path's case differs from the
    // folder-picker's canonicalisation would make Locate a silent
    // no-op even though the file is genuinely inside the
    // workspace.
    let Some(rel) = strip_prefix_case_insensitive(target, workspace_root) else {
        return;
    };
    let root = unsafe {
        SendMessageW(
            tree,
            TVM_GETNEXTITEM,
            Some(WPARAM(TVGN_ROOT as usize)),
            Some(LPARAM(0)),
        )
    };
    let mut cur = HTREEITEM(root.0);
    if cur.0 == 0 {
        return;
    }
    // Walk `rel`'s components one at a time. For each component,
    // ensure `cur` is expanded (this fires TVN_ITEMEXPANDING ŌåÆ
    // lazy `read_dir` if needed), then scan `cur`'s children for
    // a matching name.
    for comp in rel.components() {
        // `Component::as_os_str()` for `Normal(name)` is the name
        // itself. Prefix / root / current-dir components should
        // never appear in a relative path, but skip defensively.
        let comp_name = comp.as_os_str();
        if comp_name.is_empty() {
            continue;
        }
        let comp_name_str = comp_name.to_string_lossy();
        // Expand cur (idempotent) ŌĆö triggers lazy populate if
        // it's still UNPOP.
        unsafe { tree_expand(tree, cur, TVE_EXPAND.0) };
        // Scan children for the component.
        let mut found = HTREEITEM(0);
        let mut child = unsafe { tree_first_child(tree, cur) };
        while child.0 != 0 {
            let name = unsafe { tree_item_text(tree, child) };
            // Case-insensitive compare ŌĆö Windows paths are case-
            // insensitive on NTFS/FAT, and Explorer displays the
            // filesystem's canonical case. Using `eq_ignore_ascii_case`
            // is faithful to the FS behaviour for ASCII; for non-
            // ASCII, fall back to `to_lowercase` (imperfect but
            // "good enough" ŌĆö Unicode case folding is complex and
            // Explorer itself has quirks).
            if name.eq_ignore_ascii_case(&comp_name_str)
                || name.to_lowercase() == comp_name_str.to_lowercase()
            {
                found = child;
                break;
            }
            child = unsafe { tree_next_sibling(tree, child) };
        }
        if found.0 == 0 {
            // Component missing from tree ŌĆö stop at last existing
            // ancestor. Select `cur` so the user at least sees
            // the closest match.
            break;
        }
        cur = found;
    }
    // Select the final match and scroll it into view.
    unsafe {
        SendMessageW(
            tree,
            TVM_SELECTITEM,
            Some(WPARAM(TVGN_CARET as usize)),
            Some(LPARAM(cur.0)),
        );
        SendMessageW(
            tree,
            TVM_ENSUREVISIBLE,
            Some(WPARAM(0)),
            Some(LPARAM(cur.0)),
        );
    }
}

/// `View ŌåÆ Locate Current File` ŌĆö reveal the active tab's path in
/// the workspace tree. Snapshots the active path + workspace root
/// under a brief borrow so the tree walk runs without holding
/// `&mut WindowState`.
///
/// # Safety
///
/// `main_hwnd` must be a live main window HWND. UI thread only.
unsafe fn locate_current_file_in_workspace(main_hwnd: HWND) {
    let (tree, root, active_path) = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        (
            state.workspace_tree_hwnd,
            state.workspace_root.clone(),
            state.shell.active().and_then(|t| t.path.clone()),
        )
    } else {
        return;
    };
    let (Some(root), Some(active)) = (root, active_path) else {
        return;
    };
    unsafe { tree_locate_path(tree, &active, &root) };
}

/// Right-click context menu for the workspace tree. Called from
/// the panel's `WM_NOTIFY` on `NM_RCLICK`.
///
/// Flow:
///   1. `GetCursorPos` ŌåÆ hit-test the tree via `TVM_HITTEST` to
///      identify the clicked item.
///   2. Read its `lParam` sentinel and parent pointer to classify
///      the target as root / non-root folder / file.
///   3. Select the item (`TreeView` doesn't do this on right-click
///      by default) so the popup targets a visually-highlighted
///      row.
///   4. Reconstruct the item's full filesystem path via
///      [`tree_item_full_path`], stash it + kind on
///      [`WindowState::workspace_ctx_target`].
///   5. Build the appropriate popup menu (see [`WorkspaceCtxKind`]
///      for the per-kind shape).
///   6. `TrackPopupMenu(TPM_RETURNCMD)` ŌåÆ the chosen id is
///      `PostMessageW`'d to the main window as a `WM_COMMAND`
///      so the existing `main_wnd_proc` dispatch picks it up on
///      a clean tick with no `TrackPopupMenu` modal pump still
///      on the stack.
///
/// Reconstructed paths defence-in-depth check against
/// [`Path::starts_with(workspace_root)`] before being stashed,
/// mirroring [`handle_tree_double_click`]'s defence against a
/// hostile filesystem returning components with path separators.
///
/// # Safety
///
/// `main_hwnd` must be the main window. `tree` must be the
/// workspace tree's live `SysTreeView32` HWND. UI thread only.
unsafe fn show_workspace_tree_context_menu(main_hwnd: HWND, tree: HWND) {
    // 1. Cursor ŌåÆ tree client coords ŌåÆ hit-test.
    let mut cursor = POINT::default();
    if unsafe { GetCursorPos(&raw mut cursor) }.is_err() {
        return;
    }
    let mut client_pt = cursor;
    if !unsafe { ScreenToClient(tree, &raw mut client_pt) }.as_bool() {
        return;
    }
    let mut ht = TVHITTESTINFO {
        pt: client_pt,
        flags: TVHITTESTINFO_FLAGS::default(),
        hItem: HTREEITEM(0),
    };
    unsafe {
        SendMessageW(
            tree,
            TVM_HITTEST,
            Some(WPARAM(0)),
            Some(LPARAM(&raw mut ht as isize)),
        );
    }
    // Only accept clicks that landed on an item's icon / label /
    // state-icon / to-the-right-of-label area. `TVHT_ONITEM` is
    // already the aggregate icon+label+state-icon mask (70), so
    // ORing it with `TVHT_ONITEMRIGHT` covers everything a real
    // item click can produce. A click on the [+] chevron
    // (`TVHT_ONITEMBUTTON`), the indent guides
    // (`TVHT_ONITEMINDENT`), the whitespace above/below any item
    // (`TVHT_ABOVE` / `TVHT_BELOW` / `TVHT_NOWHERE`), or the
    // resize gutter (`TVHT_TOLEFT`) all fall through with no
    // menu ŌĆö matching what File Explorer does when you
    // right-click empty space in the folder tree.
    let on_item = ht.flags & (TVHT_ONITEM | TVHT_ONITEMRIGHT);
    if on_item.0 == 0 || ht.hItem.0 == 0 {
        return;
    }
    let item = ht.hItem;

    // 2. Classify: root vs folder vs file.
    let state_sentinel = unsafe { tree_item_lparam(tree, item) };
    let parent = unsafe {
        SendMessageW(
            tree,
            TVM_GETNEXTITEM,
            Some(WPARAM(TVGN_PARENT as usize)),
            Some(LPARAM(item.0)),
        )
    };
    let is_root = parent.0 == 0;
    let kind = if state_sentinel == WORKSPACE_ITEM_FILE {
        WorkspaceCtxKind::File
    } else if is_root {
        WorkspaceCtxKind::Root
    } else {
        WorkspaceCtxKind::Folder
    };

    // 3. Select the clicked item so the highlight matches the
    //    popup. Match File Explorer + N++'s behaviour ŌĆö silent
    //    right-click that doesn't change selection is jarring.
    unsafe {
        SendMessageW(
            tree,
            TVM_SELECTITEM,
            Some(WPARAM(TVGN_CARET as usize)),
            Some(LPARAM(item.0)),
        );
    }

    // 4. Reconstruct + validate path, stash on WindowState.
    let root = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_root.clone()
    } else {
        return;
    };
    let Some(root) = root else {
        return;
    };
    let path = unsafe { tree_item_full_path(tree, item, &root) };
    // Same defence as `handle_tree_double_click`: a hostile
    // filesystem returning a component with an absolute-path
    // prefix could escape workspace_root via `PathBuf::push`. All
    // context menu actions dispatch on this path (opening files,
    // spawning shells, showing FIF), so escape here would be far
    // worse than escape in the double-click path.
    if !path.starts_with(&root) {
        tracing::warn!(
            path = ?path,
            root = ?root,
            "workspace tree ctx menu: reconstructed path escaped root; refusing to show menu"
        );
        return;
    }
    if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_ctx_target = Some(WorkspaceCtxTarget {
            path: path.clone(),
            kind,
        });
    }

    // 5. Build the popup. Menu shape depends on `kind`:
    //   * Root:   Remove | -- | Copy path | Find in Files... | -- |
    //             Explorer here | CMD here | PowerShell here
    //   * Folder: Copy path | Find in Files... | -- |
    //             Explorer here | CMD here | PowerShell here
    //   * File:   Open | -- | Copy path | Copy file name |
    //             Run by system | -- |
    //             Explorer here | CMD here | PowerShell here
    let Ok(menu) = (unsafe { CreatePopupMenu() }) else {
        return;
    };
    let append = |flags: MENU_ITEM_FLAGS, id: u16, text: PCWSTR| unsafe {
        let _ = AppendMenuW(menu, flags, id as usize, text);
    };
    let sep = || MF_SEPARATOR;
    match kind {
        WorkspaceCtxKind::Root => {
            append(MF_STRING, ID_WORKSPACE_CTX_REMOVE, w!("Remove"));
            append(sep(), 0, PCWSTR::null());
            append(MF_STRING, ID_WORKSPACE_CTX_COPY_PATH, w!("Copy path"));
            append(
                MF_STRING,
                ID_WORKSPACE_CTX_FIND_IN_FILES,
                w!("Find in Files..."),
            );
            append(sep(), 0, PCWSTR::null());
            append(MF_STRING, ID_WORKSPACE_CTX_EXPLORER, w!("Explorer here"));
            append(MF_STRING, ID_WORKSPACE_CTX_CMD, w!("CMD here"));
            append(
                MF_STRING,
                ID_WORKSPACE_CTX_POWERSHELL,
                w!("PowerShell here"),
            );
        }
        WorkspaceCtxKind::Folder => {
            append(MF_STRING, ID_WORKSPACE_CTX_COPY_PATH, w!("Copy path"));
            append(
                MF_STRING,
                ID_WORKSPACE_CTX_FIND_IN_FILES,
                w!("Find in Files..."),
            );
            append(sep(), 0, PCWSTR::null());
            append(MF_STRING, ID_WORKSPACE_CTX_EXPLORER, w!("Explorer here"));
            append(MF_STRING, ID_WORKSPACE_CTX_CMD, w!("CMD here"));
            append(
                MF_STRING,
                ID_WORKSPACE_CTX_POWERSHELL,
                w!("PowerShell here"),
            );
        }
        WorkspaceCtxKind::File => {
            append(MF_STRING, ID_WORKSPACE_CTX_OPEN_FILE, w!("Open"));
            append(sep(), 0, PCWSTR::null());
            append(MF_STRING, ID_WORKSPACE_CTX_COPY_PATH, w!("Copy path"));
            append(
                MF_STRING,
                ID_WORKSPACE_CTX_COPY_FILE_NAME,
                w!("Copy file name"),
            );
            // "Run by system" mirrors File ŌåÆ Open in Default Viewer:
            // only enabled when the extension has a registered
            // handler. Grey it (rather than omit) so the layout
            // stays predictable across files.
            let run_flags = MF_STRING
                | if extract_extension_with_dot(&path)
                    .is_some_and(|ext| extension_has_registered_handler(&ext))
                {
                    MF_ENABLED
                } else {
                    MF_GRAYED
                };
            append(
                run_flags,
                ID_WORKSPACE_CTX_RUN_BY_SYSTEM,
                w!("Run by system"),
            );
            append(sep(), 0, PCWSTR::null());
            append(MF_STRING, ID_WORKSPACE_CTX_EXPLORER, w!("Explorer here"));
            append(MF_STRING, ID_WORKSPACE_CTX_CMD, w!("CMD here"));
            append(
                MF_STRING,
                ID_WORKSPACE_CTX_POWERSHELL,
                w!("PowerShell here"),
            );
        }
    }

    // 6. Show the popup at the cursor's *screen* coords. TrackPopupMenu
    //    with TPM_RETURNCMD enters a modal pump ŌĆö no WindowState
    //    borrow may be alive across it, so the stash above was our
    //    last touch of state before this call. TPM_RIGHTBUTTON lets
    //    the right button dismiss/select (default is left only).
    let cmd = unsafe {
        TrackPopupMenu(
            menu,
            TPM_LEFTALIGN | TPM_RETURNCMD | TPM_RIGHTBUTTON,
            cursor.x,
            cursor.y,
            Some(0),
            main_hwnd,
            None,
        )
    };
    // `CreatePopupMenu` returned an HMENU we now own; free it
    // before we return regardless of whether the user picked
    // something. TrackPopupMenu does NOT take ownership.
    unsafe {
        let _ = DestroyMenu(menu);
    }
    if cmd.0 == 0 {
        // User dismissed the popup without picking. Drop the
        // stash so the next click starts fresh.
        if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
            state.workspace_ctx_target = None;
        }
        return;
    }
    // Post as WM_COMMAND to the main window ŌĆö mirrors what the
    // language status menu does. Dispatch happens on a clean tick
    // with no popup pump on the stack.
    let _ = unsafe {
        PostMessageW(
            Some(main_hwnd),
            WM_COMMAND,
            WPARAM(cmd.0 as usize),
            LPARAM(0),
        )
    };
}

/// "Remove" from the root-folder context menu. Clears the tree
/// and drops the stashed workspace root so the next session save
/// won't restore it. The panel itself stays visible with an
/// empty tree ŌĆö matches the user-facing spec ("the workspace is
/// empty"). Cancels any in-flight Unfold All so its ticks don't
/// try to walk the just-deleted tree.
///
/// # Safety
///
/// `main_hwnd` must be a live main window on the UI thread.
unsafe fn remove_workspace_root(main_hwnd: HWND) {
    unsafe { cancel_workspace_unfold(main_hwnd) };
    let tree = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_root = None;
        state.workspace_tree_hwnd
    } else {
        return;
    };
    unsafe { tree_clear_all(tree) };
    // Persist the cleared state so quitting Code++ now doesn't
    // resurrect the removed root on the next launch ŌĆö matches
    // the "session persistence" fix landed with m4.
    unsafe { sync_workspace_state_to_shell(main_hwnd) };
}

/// Show the workspace panel rooted at `root`. Idempotent on the
/// visibility flag; overwrites `workspace_root` on every call so
/// `File ŌåÆ Open Folder as Workspace...` can re-root an already-
/// open panel without the user having to close it first.
///
/// The initial layout re-runs `layout_children` under a snapshot
/// borrow (same pattern as `show_fif_dock`) so `MoveWindow` ŌåÆ
/// `WM_SIZE` on the panel doesn't re-enter a live
/// `&mut WindowState`.
///
/// # Safety
///
/// `main_hwnd` must be a live main window HWND. UI thread only.
unsafe fn show_workspace_panel(main_hwnd: HWND, root: PathBuf) {
    // The header title stays fixed at "Folder as Workspace" (the
    // text seeded on control creation). Earlier iterations
    // overwrote it with the root basename here, but that was
    // never the intended design ŌĆö the header is a label for the
    // panel itself, not for the currently-loaded folder. The
    // root folder's name is already visible as the top tree node.
    let snapshot = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.workspace_root = Some(root.clone());
        state.workspace_visible = true;
        Some((
            state.toolbar_hwnd,
            state.toolbar_bitmap_px,
            state.tab_hwnd,
            state.scintilla_hwnd,
            state.status_hwnd,
            state.fif_splitter_hwnd,
            state.fif_dock_hwnd,
            state.fif_dock_visible,
            state.fif_dock_height,
            state.workspace_tree_hwnd,
            WorkspaceLayout {
                panel: state.workspace_hwnd,
                splitter: state.workspace_splitter_hwnd,
                visible: true,
                width: state.workspace_width,
            },
            DocMapLayout {
                panel: state.docmap_hwnd,
                splitter: state.docmap_splitter_hwnd,
                visible: state.docmap_visible,
                width: state.docmap_width,
            },
        ))
    } else {
        None
    };
    let Some((
        toolbar_hwnd,
        toolbar_bitmap_px,
        tabs,
        scintilla,
        status,
        fif_splitter,
        fif_dock,
        fif_dock_visible,
        fif_dock_height,
        tree,
        workspace,
        docmap,
    )) = snapshot
    else {
        return;
    };
    unsafe {
        // Clear + repopulate the tree. Only the root + its
        // direct children hit disk here (one `read_dir`);
        // subfolders defer to `TVN_ITEMEXPANDING`.
        populate_workspace_root(tree, &root);
        let _ = ShowWindow(workspace.panel, SW_SHOW);
        let _ = ShowWindow(workspace.splitter, SW_SHOW);
        let mut rect = RECT::default();
        if GetClientRect(main_hwnd, &raw mut rect).is_ok() {
            let tab_hidden = !IsWindowVisible(tabs).as_bool();
            layout_children(
                toolbar_hwnd,
                toolbar::toolbar_height_px(toolbar_bitmap_px),
                tabs,
                scintilla,
                status,
                fif_splitter,
                fif_dock,
                fif_dock_visible,
                fif_dock_height,
                tab_hidden,
                workspace,
                docmap,
                rect.right,
                rect.bottom,
            );
        }
    }
}

/// Hide the workspace panel, reclaiming the horizontal space for
/// the editor. Idempotent. `workspace_root` is deliberately
/// preserved so the next `View ŌåÆ Folder as Workspace` toggle
/// re-opens with the same root without asking again ŌĆö matches
/// N++'s behaviour.
///
/// # Safety
///
/// Same invariants as [`show_workspace_panel`].
unsafe fn hide_workspace_panel(main_hwnd: HWND) {
    // Kill any in-flight "Unfold All" walk BEFORE we tear the
    // panel state down ŌĆö the timer would otherwise keep firing
    // and reach into a tree HWND whose parent's visibility just
    // flipped underneath it.
    unsafe { cancel_workspace_unfold(main_hwnd) };
    let snapshot = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        if !state.workspace_visible {
            return;
        }
        state.workspace_visible = false;
        Some((
            state.toolbar_hwnd,
            state.toolbar_bitmap_px,
            state.tab_hwnd,
            state.scintilla_hwnd,
            state.status_hwnd,
            state.fif_splitter_hwnd,
            state.fif_dock_hwnd,
            state.fif_dock_visible,
            state.fif_dock_height,
            WorkspaceLayout {
                panel: state.workspace_hwnd,
                splitter: state.workspace_splitter_hwnd,
                visible: false,
                width: state.workspace_width,
            },
            DocMapLayout {
                panel: state.docmap_hwnd,
                splitter: state.docmap_splitter_hwnd,
                visible: state.docmap_visible,
                width: state.docmap_width,
            },
        ))
    } else {
        None
    };
    let Some((
        toolbar_hwnd,
        toolbar_bitmap_px,
        tabs,
        scintilla,
        status,
        fif_splitter,
        fif_dock,
        fif_dock_visible,
        fif_dock_height,
        workspace,
        docmap,
    )) = snapshot
    else {
        return;
    };
    unsafe {
        let _ = ShowWindow(workspace.panel, SW_HIDE);
        let _ = ShowWindow(workspace.splitter, SW_HIDE);
        let mut rect = RECT::default();
        if GetClientRect(main_hwnd, &raw mut rect).is_ok() {
            let tab_hidden = !IsWindowVisible(tabs).as_bool();
            layout_children(
                toolbar_hwnd,
                toolbar::toolbar_height_px(toolbar_bitmap_px),
                tabs,
                scintilla,
                status,
                fif_splitter,
                fif_dock,
                fif_dock_visible,
                fif_dock_height,
                tab_hidden,
                workspace,
                docmap,
                rect.right,
                rect.bottom,
            );
        }
    }
}

/// Top-level entry for `File ŌåÆ Open Folder as Workspace...` ŌĆö pop
/// the folder picker under a fresh (no `&mut WindowState`) borrow,
/// then hand the chosen path to [`show_workspace_panel`]. Idempotent:
/// user cancel is a no-op; a fresh pick while the panel is open
/// re-roots it in place.
///
/// # Safety
///
/// Same invariants as [`show_workspace_panel`].
unsafe fn open_workspace_folder_flow(main_hwnd: HWND) {
    // Read the current root (if any) under a brief borrow so the
    // picker seeds where the user last was. Drop the borrow before
    // calling the picker ŌĆö the picker spins its own message pump
    // and would re-enter our wnd_proc.
    let initial: Option<PathBuf> =
        unsafe { state_from_hwnd(main_hwnd).and_then(|state| state.workspace_root.clone()) };
    let picked = unsafe { prompt_pick_workspace_folder(main_hwnd, initial.as_deref()) };
    if let Some(root) = picked {
        unsafe { show_workspace_panel(main_hwnd, root) };
    }
}

/// Top-level entry for `View ŌåÆ Folder as Workspace` (menu toggle).
/// Three branches:
///
///   * Panel visible ŌåÆ hide.
///   * Panel hidden, `workspace_root` set ŌåÆ show at the stored
///     root (no picker; user already made that choice).
///   * Panel hidden, no root yet ŌåÆ route to
///     [`open_workspace_folder_flow`] so the user picks a
///     folder in the same click.
///
/// Matches N++'s View-menu toggle behaviour for the same feature.
///
/// # Safety
///
/// Same invariants as [`show_workspace_panel`].
unsafe fn toggle_workspace_panel(main_hwnd: HWND) {
    let (visible, root) = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        (state.workspace_visible, state.workspace_root.clone())
    } else {
        return;
    };
    if visible {
        unsafe { hide_workspace_panel(main_hwnd) };
    } else if let Some(r) = root {
        unsafe { show_workspace_panel(main_hwnd, r) };
    } else {
        unsafe { open_workspace_folder_flow(main_hwnd) };
    }
}

/// Snapshot the current workspace panel state into
/// `Shell.session.workspace` so the next `save_session` writes
/// it through to disk. Called immediately before every
/// `save_session` invocation (the periodic autosave tick + the
/// `WM_DESTROY` shutdown save) so a clean shutdown or a
/// mid-session autosave both capture the latest state.
///
/// If the user has never opened a workspace this session
/// (`workspace_root` is `None`), we deliberately preserve any
/// pre-existing `WorkspaceSession` on the Shell rather than
/// overwriting with `None`. That way a user who launched into a
/// restored workspace, then closed the app without touching
/// the panel, still gets the same restore next launch. The
/// panel-close X and `View ŌåÆ Folder as Workspace` toggle both
/// leave `workspace_root` populated for exactly this reason
/// (matches N++'s behaviour).
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn sync_workspace_state_to_shell(main_hwnd: HWND) {
    let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
        return;
    };
    let Some(root) = state.workspace_root.clone() else {
        // No root has ever been set this session ŌĆö leave any
        // previously-loaded `WorkspaceSession` alone (see doc).
        return;
    };
    state
        .shell
        .set_workspace_session(Some(codepp_core::session::WorkspaceSession {
            root: Some(root),
            visible: state.workspace_visible,
            width: Some(state.workspace_width),
        }));
}

/// Cold-start restore: read `Shell.saved_workspace_session()`
/// and apply it. If the session had a workspace with `visible ==
/// true`, this pops the panel open at the saved root and
/// applies the saved width. If `visible == false` but a root is
/// present, we seed `state.workspace_root` + `state.workspace_width`
/// so a later `View ŌåÆ Folder as Workspace` opens at the
/// remembered root without needing to prompt again.
///
/// Called once from `run()` after `SetWindowLongPtrW(GWLP_USERDATA)`
/// installs the state pointer + the initial `layout_children`
/// call. Placing it after the initial layout means the first
/// paint already reflects the restored panel state ŌĆö no visible
/// "editor first, then panel slides in" flash.
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn apply_saved_workspace(main_hwnd: HWND) {
    let saved = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.shell.saved_workspace_session()
    } else {
        return;
    };
    let Some(ws) = saved else {
        return;
    };
    let Some(root) = ws.root else {
        return;
    };
    // Seed the width first so the panel opens at the persisted
    // size rather than snapping to the default and then resizing.
    if let Some(width) = ws.width {
        if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
            state.workspace_width = width;
        }
    }
    if ws.visible {
        // `show_workspace_panel` handles the state seeding
        // (`workspace_root`, `workspace_visible`), tree populate,
        // `ShowWindow`, and layout re-run. One call restores
        // everything.
        unsafe { show_workspace_panel(main_hwnd, root) };
    } else if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        // Not visible ŌĆö remember the root so the next `View ŌåÆ
        // Folder as Workspace` opens at it without prompting.
        state.workspace_root = Some(root);
    }
}

/// Show the Document Map panel. Idempotent on the visibility
/// flag. Symmetric with [`show_workspace_panel`] minus the
/// tree/root plumbing (docmap doesn't bind to a resource ŌĆö it
/// mirrors whatever buffer is active).
///
/// # Safety
///
/// `main_hwnd` must be a live main window HWND. UI thread only.
unsafe fn show_docmap_panel(main_hwnd: HWND) {
    let snapshot = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        if state.docmap_visible {
            return;
        }
        state.docmap_visible = true;
        Some((
            state.toolbar_hwnd,
            state.toolbar_bitmap_px,
            state.tab_hwnd,
            state.scintilla_hwnd,
            state.status_hwnd,
            state.fif_splitter_hwnd,
            state.fif_dock_hwnd,
            state.fif_dock_visible,
            state.fif_dock_height,
            WorkspaceLayout {
                panel: state.workspace_hwnd,
                splitter: state.workspace_splitter_hwnd,
                visible: state.workspace_visible,
                width: state.workspace_width,
            },
            DocMapLayout {
                panel: state.docmap_hwnd,
                splitter: state.docmap_splitter_hwnd,
                visible: true,
                width: state.docmap_width,
            },
        ))
    } else {
        None
    };
    let Some((
        toolbar_hwnd,
        toolbar_bitmap_px,
        tabs,
        scintilla,
        status,
        fif_splitter,
        fif_dock,
        fif_dock_visible,
        fif_dock_height,
        workspace,
        docmap,
    )) = snapshot
    else {
        return;
    };
    unsafe {
        let _ = ShowWindow(docmap.panel, SW_SHOW);
        let _ = ShowWindow(docmap.splitter, SW_SHOW);
        let mut rect = RECT::default();
        if GetClientRect(main_hwnd, &raw mut rect).is_ok() {
            let tab_hidden = !IsWindowVisible(tabs).as_bool();
            layout_children(
                toolbar_hwnd,
                toolbar::toolbar_height_px(toolbar_bitmap_px),
                tabs,
                scintilla,
                status,
                fif_splitter,
                fif_dock,
                fif_dock_visible,
                fif_dock_height,
                tab_hidden,
                workspace,
                docmap,
                rect.right,
                rect.bottom,
            );
        }
        // Sync the toolbar's Document Map button check state to
        // the new visibility. `refresh_state` doesn't touch this
        // bit (docmap visibility isn't a Scintilla-derived state),
        // so we push it explicitly here.
        toolbar::set_button_checked(toolbar_hwnd, ID_VIEW_DOCMAP, true);
        // Defensive re-sync of the map view's bound doc ŌĆö cold
        // start already seeded it, but a panel toggle after a
        // tab activation that happened while the panel was
        // hidden needs this to catch up. `sync_docmap_to_active_tab`
        // trails an `update_docmap_viewport_indicator` call
        // internally, so the reveal paints the highlight at the
        // main editor's current viewport in the same frame.
        sync_docmap_to_active_tab(main_hwnd);
    }
}

/// Hide the Document Map panel, reclaiming the horizontal space
/// for the editor. Idempotent. Mirror of [`hide_workspace_panel`].
///
/// # Safety
///
/// Same invariants as [`show_docmap_panel`].
unsafe fn hide_docmap_panel(main_hwnd: HWND) {
    let snapshot = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        if !state.docmap_visible {
            return;
        }
        state.docmap_visible = false;
        Some((
            state.toolbar_hwnd,
            state.toolbar_bitmap_px,
            state.tab_hwnd,
            state.scintilla_hwnd,
            state.status_hwnd,
            state.fif_splitter_hwnd,
            state.fif_dock_hwnd,
            state.fif_dock_visible,
            state.fif_dock_height,
            WorkspaceLayout {
                panel: state.workspace_hwnd,
                splitter: state.workspace_splitter_hwnd,
                visible: state.workspace_visible,
                width: state.workspace_width,
            },
            DocMapLayout {
                panel: state.docmap_hwnd,
                splitter: state.docmap_splitter_hwnd,
                visible: false,
                width: state.docmap_width,
            },
        ))
    } else {
        None
    };
    let Some((
        toolbar_hwnd,
        toolbar_bitmap_px,
        tabs,
        scintilla,
        status,
        fif_splitter,
        fif_dock,
        fif_dock_visible,
        fif_dock_height,
        workspace,
        docmap,
    )) = snapshot
    else {
        return;
    };
    unsafe {
        let _ = ShowWindow(docmap.panel, SW_HIDE);
        let _ = ShowWindow(docmap.splitter, SW_HIDE);
        let mut rect = RECT::default();
        if GetClientRect(main_hwnd, &raw mut rect).is_ok() {
            let tab_hidden = !IsWindowVisible(tabs).as_bool();
            layout_children(
                toolbar_hwnd,
                toolbar::toolbar_height_px(toolbar_bitmap_px),
                tabs,
                scintilla,
                status,
                fif_splitter,
                fif_dock,
                fif_dock_visible,
                fif_dock_height,
                tab_hidden,
                workspace,
                docmap,
                rect.right,
                rect.bottom,
            );
        }
        toolbar::set_button_checked(toolbar_hwnd, ID_VIEW_DOCMAP, false);
    }
}

/// Toggle the Document Map panel. Convenience wrapper around
/// [`show_docmap_panel`] / [`hide_docmap_panel`] driven by the
/// View ŌåÆ Document Map menu, the docmap toolbar button, and the
/// header's close-├Ś (via [`IDC_DOCMAP_CLOSE`]).
///
/// # Safety
///
/// Same invariants as the show/hide helpers.
unsafe fn toggle_docmap_panel(main_hwnd: HWND) {
    let visible = unsafe { state_from_hwnd(main_hwnd) }.is_some_and(|s| s.docmap_visible);
    if visible {
        unsafe { hide_docmap_panel(main_hwnd) };
    } else {
        unsafe { show_docmap_panel(main_hwnd) };
    }
}

/// Defensive re-sync of the map view's Scintilla binding to the
/// active tab's document. The **primary** sync path is
/// [`Win32Ui::activate_tab`], which rebinds the map view in
/// lockstep with the main view ŌĆö that covers every Shell-driven
/// activation (FileŌåÆOpen, FileŌåÆNew, session restore, plugin
/// `NPPM_SWITCHTOFILE`, `ensure_one_tab`). This helper is called
/// from the Win32-side tab-switch / tab-close paths that mutate
/// the main view's binding without going through the trait
/// method: `handle_tab_selchange`, `handle_close_active_tab_inner`,
/// `show_docmap_panel` (belt-and-braces after a hidden-panel
/// tab switch), and the cold-start seed. Same-doc redundant
/// rebinds are Scintilla no-ops so the double coverage is safe.
///
/// Cheap: one `SCI_SETDOCPOINTER` direct-call. Scintilla's
/// ref-counting makes the shared binding safe ŌĆö the doc's
/// refcount stays non-zero as long as either view (main editor
/// or map) references it, so tab-close's `SCI_RELEASEDOCUMENT`
/// doesn't free out from under the map.
///
/// A zero doc pointer (nothing to bind, e.g. a pending-load tab
/// whose lazy doc hasn't been minted yet) short-circuits ŌĆö the
/// map view keeps its previous binding, which is harmless (the
/// user just sees stale content until the load finishes and the
/// next selchange fires).
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn sync_docmap_to_active_tab(main_hwnd: HWND) {
    let (main_editor, docmap_editor, doc) =
        if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
            let doc = state.shell.active().map_or(0, |t| t.scintilla_doc);
            (state.editor, state.docmap_editor, doc)
        } else {
            return;
        };
    if doc == 0 {
        return;
    }
    docmap_editor.send(SCI_SETDOCPOINTER, 0, doc);
    // Rebinding the doc changes the map's line-count and
    // per-line pixel positions, so the auto-center scroll
    // computed at the previous tab's dimensions is stale.
    // Kick a fresh update so the map view scrolls to keep the
    // main editor's viewport centered, and invalidate the map
    // so the WM_PAINT subclass redraws the overlay rectangle
    // against the newly-bound content. Handles pulled from the
    // borrow above so no second `state_from_hwnd` is needed.
    unsafe {
        update_docmap_viewport_indicator(main_editor, docmap_editor);
    }
}

/// Recompute + repaint the docmap viewport-highlight indicator so
/// it covers exactly the line range currently visible in the main
/// editor. Called on every event that shifts either endpoint:
///
///   * Scroll (`SCN_UPDATEUI` with `SC_UPDATE_V_SCROLL`).
///   * Tab activation ([`Win32Ui::activate_tab`] +
///     [`sync_docmap_to_active_tab`]).
///   * Panel show ([`show_docmap_panel`], to seed the initial
///     paint).
///   * Main-editor resize (changes `SCI_LINESONSCREEN` so the
///     bottom edge of the range moves) ŌĆö hooked via the parent
///     window's `WM_SIZE` handler.
///
/// Also scrolls the map view so the highlighted range is
/// centered vertically in the miniature ŌĆö a very long buffer
/// won't fit into the panel at any zoom, and without this the
/// user would scroll the main editor down and see the map's
/// highlight disappear off the bottom of the panel.
///
/// Cheap: three direct-call reads on the main editor
/// (`SCI_GETFIRSTVISIBLELINE`, `SCI_LINESONSCREEN`,
/// `SCI_GETLINECOUNT`), one `SCI_POSITIONFROMLINE` per endpoint,
/// two indicator writes on the map, one scroll adjustment. Well
/// under the keystroke budget in DESIGN.md ┬¦8.
///
/// # Aliasing safety
///
/// Takes the two `EditorHandle`s by value (they are `Copy`)
/// rather than re-deriving them from an `HWND` via
/// `state_from_hwnd`. This matters: several call sites already
/// hold a live `&mut WindowState` (or a `&mut Shell` reborrowed
/// from one via `WindowState::split`) at the moment this helper
/// runs. A second `state_from_hwnd` reach-back from inside would
/// materialise an overlapping `&mut WindowState` ŌĆö aliasing UB
/// under Rust's `noalias` optimizer even before behavioural bugs
/// appear. Same discipline as the pre-existing `Win32Ui` fields
/// (`accel_handle`, `dock_dialogs`, `udl_registry`).
///
/// # Safety
///
/// Both handles must be live ŌĆö created in [`run`], destroyed only
/// at window teardown. UI thread only.
unsafe fn update_docmap_viewport_indicator(main_editor: EditorHandle, docmap_editor: EditorHandle) {
    // Main-editor viewport bounds. `SCI_GETFIRSTVISIBLELINE`
    // returns a VISIBLE-line index (post-folding / post-
    // wrapping) which is what the user sees but NOT what
    // `SCI_POSITIONFROMLINE` accepts ŌĆö it takes a DOCUMENT-line
    // index. Convert via `SCI_DOCLINEFROMVISIBLE` (identity when
    // no folding is active). Same conversion for the exclusive
    // upper endpoint.
    let first_visible = main_editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0);
    let lines_on_screen = main_editor.send(SCI_LINESONSCREEN, 0, 0);
    let line_count = main_editor.send(SCI_GETLINECOUNT, 0, 0).max(0);
    if first_visible < 0 || lines_on_screen <= 0 || line_count == 0 {
        // Empty buffer or pre-first-`WM_SIZE`. Invalidate the
        // map view so its `WM_PAINT` subclass runs and clears
        // any leftover overlay from a previous tab.
        let map_hwnd = HWND(docmap_editor.hwnd());
        unsafe {
            let _ = InvalidateRect(Some(map_hwnd), None, false);
        }
        return;
    }
    let last_visible_exclusive = first_visible + lines_on_screen;
    let first_doc_line = main_editor.send(SCI_DOCLINEFROMVISIBLE, first_visible as usize, 0);
    let last_doc_line_raw =
        main_editor.send(SCI_DOCLINEFROMVISIBLE, last_visible_exclusive as usize, 0);
    let last_doc_line_exclusive = last_doc_line_raw.min(line_count);
    if first_doc_line < 0 || last_doc_line_exclusive < first_doc_line {
        return;
    }
    // Center the highlighted range in the map's viewport so it
    // stays visible when the user scrolls the main editor
    // beyond the map's own lines-on-screen. Compute the target
    // first-visible-line for the map: put the highlight's
    // vertical center at the map's vertical center. Uses
    // document-line indices on both sides so folding doesn't
    // cause a jump.
    let map_lines_on_screen = docmap_editor.send(SCI_LINESONSCREEN, 0, 0);
    let highlight_span = last_doc_line_exclusive - first_doc_line;
    let target_map_first = (first_doc_line + highlight_span / 2 - map_lines_on_screen / 2).max(0);
    let map_current_first = docmap_editor.send(SCI_GETFIRSTVISIBLELINE, 0, 0);
    let delta = target_map_first - map_current_first;
    if delta != 0 {
        docmap_editor.send(SCI_LINESCROLL, 0, delta);
    }
    // Kick a repaint so the WM_PAINT subclass draws the fresh
    // overlay rectangle. Scintilla's own paint may or may not
    // re-fire depending on whether the doc-pointer / scroll
    // moved; a manual invalidation guarantees the overlay tracks.
    let map_hwnd = HWND(docmap_editor.hwnd());
    unsafe {
        let _ = InvalidateRect(Some(map_hwnd), None, false);
    }
}

/// Push the current docmap panel state into the shell so the next
/// `save_session` writes it through to disk. Same discipline as
/// [`sync_workspace_state_to_shell`]. Called from the periodic
/// autosave and shutdown paths.
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn sync_docmap_state_to_shell(main_hwnd: HWND) {
    let Some(state) = (unsafe { state_from_hwnd(main_hwnd) }) else {
        return;
    };
    state
        .shell
        .set_docmap_session(Some(codepp_core::session::DocMapSession {
            visible: state.docmap_visible,
            width: Some(state.docmap_width),
        }));
}

/// Cold-start restore: read `Shell.saved_docmap_session()` and
/// apply it. Mirrors [`apply_saved_workspace`] on the right column.
///
/// # Safety
///
/// `main_hwnd` must be the main window HWND. UI thread only.
unsafe fn apply_saved_docmap(main_hwnd: HWND) {
    let saved = if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
        state.shell.saved_docmap_session()
    } else {
        return;
    };
    let Some(dm) = saved else {
        return;
    };
    // Seed the width first so the panel opens at the persisted
    // size rather than snapping to the default. Clamp against
    // the current client width so a saved value from a wider
    // display (or a hand-edited / crash-corrupted session.xml)
    // can never drive `MoveWindow` with a nonsensical dimension
    // ŌĆö belt-and-braces alongside the same clamp
    // `layout_children` applies on every pass.
    if let Some(width) = dm.width {
        let mut rect = RECT::default();
        let client_width =
            if unsafe { GetClientRect(main_hwnd, &raw mut rect) }.is_ok() && rect.right > 0 {
                rect.right
            } else {
                // Pre-first-`WM_SIZE` fallback (window not yet
                // sized). The layout pass that fires after
                // `show_docmap_panel` will re-clamp against the
                // real client width; the initial-default
                // ceiling here just keeps the seeded value
                // sane for that first call.
                DEFAULT_DOCMAP_WIDTH_PX + MIN_SCINTILLA_WIDTH_PX
            };
        let clamped = clamp_docmap_width(client_width, width);
        if let Some(state) = unsafe { state_from_hwnd(main_hwnd) } {
            state.docmap_width = clamped;
        }
    }
    if dm.visible {
        unsafe { show_docmap_panel(main_hwnd) };
    }
}

/// `Wnd_proc` for the FIF dock container. Owns the layout of its
/// own children (status STATIC, close-X button, listview) on
/// `WM_SIZE`, forwards `WM_NOTIFY` from the listview up to
/// `main_wnd_proc` (so `NM_DBLCLK` reaches the file-open routing),
/// and handles its own close-X button click.
extern "system" fn fif_dock_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_SIZE => {
                let width = (lparam.0 & 0xFFFF) as i32;
                let height = ((lparam.0 >> 16) & 0xFFFF) as i32;
                let parent = GetParent(hwnd).unwrap_or_default();
                let snap = state_from_hwnd(parent)
                    .map(|s| (s.fif_dock_status, s.fif_dock_close, s.fif_listview_hwnd));
                if let Some((status, close, listview)) = snap {
                    // Header band: status fills (0 .. close_x);
                    // close button is right-aligned. Listview
                    // takes everything below the header.
                    let close_x = (width - FIF_DOCK_CLOSE_W).max(0);
                    let _ = MoveWindow(
                        status,
                        4,
                        2,
                        (close_x - 8).max(0),
                        FIF_DOCK_HEADER_H - 4,
                        true,
                    );
                    let _ = MoveWindow(
                        close,
                        close_x,
                        1,
                        FIF_DOCK_CLOSE_W,
                        FIF_DOCK_HEADER_H - 2,
                        true,
                    );
                    let listview_h = (height - FIF_DOCK_HEADER_H).max(0);
                    let _ = MoveWindow(listview, 0, FIF_DOCK_HEADER_H, width, listview_h, true);
                }
                LRESULT(0)
            }
            WM_NOTIFY => {
                // Forward to main_hwnd so the listview's NM_DBLCLK
                // (and any future NM_RCLICK / LVN_*) reaches the
                // routing handler in `main_wnd_proc::WM_NOTIFY`.
                // DefWindowProcW does NOT forward WM_NOTIFY by
                // default; the dock has to do it explicitly.
                let parent = GetParent(hwnd).unwrap_or_default();
                if !parent.0.is_null() {
                    return SendMessageW(parent, msg, Some(wparam), Some(lparam));
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_COMMAND => {
                let cmd = (wparam.0 & 0xFFFF) as u16;
                if cmd == IDC_FIF_DOCK_CLOSE {
                    let parent = GetParent(hwnd).unwrap_or_default();
                    if !parent.0.is_null() {
                        hide_fif_dock(parent);
                    }
                    return LRESULT(0);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_CTLCOLORSTATIC => LRESULT(dialog_bg_brush().0 as isize),
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// `Wnd_proc` for the FIF splitter handle. Stays small ŌĆö captures
/// drag state on `WM_LBUTTONDOWN`, applies the new dock height on
/// each `WM_MOUSEMOVE`, releases on `WM_LBUTTONUP`. Reads/writes
/// the parent `WindowState` via `state_from_hwnd(GetParent(...))`
/// so all drag state lives in one place.
extern "system" fn splitter_wnd_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
) -> LRESULT {
    unsafe {
        match msg {
            WM_SETCURSOR => {
                if let Ok(cursor) = LoadCursorW(None, IDC_SIZENS) {
                    let _ = SetCursor(Some(cursor));
                }
                // Returning non-zero stops Windows from forwarding
                // WM_SETCURSOR to the parent (which would clobber
                // our cursor with the parent's class arrow).
                LRESULT(1)
            }
            WM_LBUTTONDOWN => {
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    let mut pt = POINT::default();
                    if GetCursorPos(&raw mut pt).is_ok() {
                        state.fif_splitter_drag = Some(SplitterDrag {
                            start_screen_y: pt.y,
                            dock_height_at_start: state.fif_dock_height,
                        });
                        let _ = SetCapture(hwnd);
                    }
                }
                LRESULT(0)
            }
            WM_MOUSEMOVE => {
                let parent = GetParent(hwnd).unwrap_or_default();
                // Snapshot drag state + HWNDs while holding a brief
                // borrow; the borrow ends with the `if let` so the
                // `layout_children` call below cannot re-enter a
                // live `&mut WindowState` via `MoveWindow` ŌåÆ
                // `WM_SIZE` on a child whose wndproc later wants to
                // touch the parent state. Mirrors the pattern in
                // `toggle_fif_dock`.
                let snap = if let Some(state) = state_from_hwnd(parent) {
                    state.fif_splitter_drag.map(|drag| {
                        (
                            drag,
                            state.fif_dock_height,
                            state.toolbar_hwnd,
                            state.toolbar_bitmap_px,
                            state.tab_hwnd,
                            state.scintilla_hwnd,
                            state.status_hwnd,
                            state.fif_splitter_hwnd,
                            state.fif_dock_hwnd,
                            state.fif_dock_visible,
                            WorkspaceLayout {
                                panel: state.workspace_hwnd,
                                splitter: state.workspace_splitter_hwnd,
                                visible: state.workspace_visible,
                                width: state.workspace_width,
                            },
                            DocMapLayout {
                                panel: state.docmap_hwnd,
                                splitter: state.docmap_splitter_hwnd,
                                visible: state.docmap_visible,
                                width: state.docmap_width,
                            },
                        )
                    })
                } else {
                    None
                };
                let Some((
                    drag,
                    current_height,
                    toolbar_hwnd,
                    toolbar_bitmap_px,
                    tabs,
                    scintilla,
                    status,
                    splitter,
                    dock,
                    dock_visible,
                    workspace,
                    docmap,
                )) = snap
                else {
                    return LRESULT(0);
                };
                let toolbar_height = toolbar::toolbar_height_px(toolbar_bitmap_px);
                let mut pt = POINT::default();
                if GetCursorPos(&raw mut pt).is_err() {
                    return LRESULT(0);
                }
                let mut rect = RECT::default();
                if GetClientRect(parent, &raw mut rect).is_err() {
                    return LRESULT(0);
                }
                // Dragging up grows the dock; dragging down shrinks
                // it. `clamp_dock_height` is the same authority
                // `layout_children` consults, so the value we write
                // back into state matches what gets rendered.
                let proposed = drag.dock_height_at_start + (drag.start_screen_y - pt.y);
                let new_height = clamp_dock_height(rect.bottom, toolbar_height, proposed);
                if new_height == current_height {
                    return LRESULT(0);
                }
                // Brief write-back. Borrow ends at the closing
                // `}` so layout_children below has no live
                // `&mut WindowState` to alias.
                if let Some(state) = state_from_hwnd(parent) {
                    state.fif_dock_height = new_height;
                }
                let tab_hidden = !IsWindowVisible(tabs).as_bool();
                // Same anti-flicker discipline as the workspace
                // splitter's drag ŌĆö bracket the layout burst with
                // `ScintillaRedrawGuard` so Scintilla batches all
                // WM_SIZE-driven repaints into one after the guard
                // drops. Without this the vertical drag flickers
                // the editor content, most visibly on wide/tall
                // windows.
                {
                    let _redraw = ScintillaRedrawGuard::enter(scintilla);
                    layout_children(
                        toolbar_hwnd,
                        toolbar_height,
                        tabs,
                        scintilla,
                        status,
                        splitter,
                        dock,
                        dock_visible,
                        new_height,
                        tab_hidden,
                        workspace,
                        docmap,
                        rect.right,
                        rect.bottom,
                    );
                }
                let _ = UpdateWindow(scintilla);
                LRESULT(0)
            }
            WM_LBUTTONUP => {
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    state.fif_splitter_drag = None;
                }
                // `ReleaseCapture` on a window that doesn't hold
                // capture is a documented no-op, so the call is
                // unconditionally safe here. No `GetCapture()`
                // guard needed.
                let _ = ReleaseCapture();
                LRESULT(0)
            }
            WM_CAPTURECHANGED => {
                // Capture stolen by another window (alt-tab,
                // task-switcher, parent destruction). Without this
                // handler the user could alt-tab mid-drag, return,
                // and have the next mouse-move outside-the-button
                // resize the dock ŌĆö exactly the bug Windows
                // documents `WM_CAPTURECHANGED` to prevent.
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    state.fif_splitter_drag = None;
                }
                LRESULT(0)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// `comctl32` subclass procedure installed on the Win32 tab control.
/// Intercepts left-button mouse messages so the user can drag a tab
/// to a new position; everything else (right-click, paint, theme,
/// `TCN_SELCHANGE` notification routing, ŌĆ”) falls through to the
/// system tab control via `DefSubclassProc` so default behaviour is
/// preserved verbatim.
///
/// State lives on `WindowState.tab_drag` (the parent's `GWLP_USERDATA`),
/// reached via `state_from_hwnd(GetParent(hwnd))`. Same pattern as
/// `splitter_wnd_proc` ŌĆö keeps the subclass function thin and lets
/// the rest of the codebase reach drag state without a new global.
///
/// Reorder model: as the cursor moves into a different tab cell,
/// the dragged tab "bubbles" toward it via `Shell::move_tab` one
/// neighbour-swap at a time. With ~60 fps `WM_MOUSEMOVE` delivery
/// the user sees smooth tab reordering even when crossing several
/// neighbours quickly. `Shell::save_session` writes the current tab
/// order, so the new arrangement persists across launches without
/// any extra plumbing.
///
/// `WM_NCDESTROY` removes the subclass via `RemoveWindowSubclass`
/// to avoid the comctl32 documentation's "leaving a subclass on a
/// dying window leaks the per-subclass storage" footgun.
extern "system" fn tab_subclass_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
    _id_subclass: usize,
    _ref_data: usize,
) -> LRESULT {
    // Same panic-catch pattern as the dialog wnd_procs in this
    // file: unwinding across an `extern "system"` frame is UB.
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_LBUTTONDOWN => {
                let x = i32::from((lparam.0 & 0xFFFF) as i16);
                let y = i32::from(((lparam.0 >> 16) & 0xFFFF) as i16);
                let parent = GetParent(hwnd).unwrap_or_default();
                // Close-X click takes priority over drag detection.
                // If the press lands on a tab's X, arm the close
                // (committed on the matching WM_LBUTTONUP only if
                // the cursor is still on the same X ŌĆö Win32 button
                // convention) and let DefSubclassProc activate the
                // clicked tab via the usual `TCN_SELCHANGE` path so
                // the queued `ID_FILE_CLOSE` operates on the right
                // buffer when it fires.
                let close_hit = tab_close_x_hit_test(hwnd, x, y);
                if let Some(idx) = close_hit {
                    if let Some(state) = state_from_hwnd(parent) {
                        state.tab_close_armed = Some(idx);
                        // Clear any drag the previous click might
                        // have left armed. Belt-and-braces ŌĆö drag
                        // is only set when the press is over a tab
                        // body (handled below), but a bug in that
                        // path would otherwise stick.
                        state.tab_drag = None;
                    }
                    let _ = SetCapture(hwnd);
                    return DefSubclassProc(hwnd, msg, wparam, lparam);
                }
                // Pin-toggle click. Same click-fires-on-matching-
                // release convention as close-X: arm now on
                // `WM_LBUTTONDOWN`, commit on `WM_LBUTTONUP` iff
                // the release lands on the same pin, cancel on
                // `WM_CAPTURECHANGED`. Intercepts before drag-
                // detect so clicking the pin doesn't also start a
                // tab reorder. Forwarded to `DefSubclassProc` so
                // the underlying click still activates the tab ŌĆö
                // matches the close-X path.
                let pin_hit = tab_pin_hit_test(hwnd, x, y);
                if let Some(idx) = pin_hit {
                    if let Some(state) = state_from_hwnd(parent) {
                        state.tab_pin_armed = Some(idx);
                        state.tab_drag = None;
                    }
                    let _ = SetCapture(hwnd);
                    return DefSubclassProc(hwnd, msg, wparam, lparam);
                }
                let hit = tab_hit_test(hwnd, x, y);
                if let Some(state) = state_from_hwnd(parent) {
                    if let Some(idx) = hit {
                        // Skip drag arming on pinned tabs ŌĆö the
                        // shell would reject every `move_tab` call
                        // via the invariant guard anyway (pinned
                        // tabs are fixed in place, that's the
                        // point), but arming and then no-op-ing
                        // through the WM_MOUSEMOVE loop is
                        // wasted work per mouse frame. The click
                        // still falls through to
                        // `DefSubclassProc` so the tab activates
                        // normally.
                        let is_pinned = state.shell.tabs.get(idx).is_some_and(|t| t.pinned);
                        if !is_pinned {
                            state.tab_drag = Some(TabDrag {
                                source_idx: idx,
                                start_x: x,
                                threshold_passed: false,
                            });
                            let _ = SetCapture(hwnd);
                        }
                    }
                }
                // Forward to the system tab control so the click
                // still fires `TCN_SELCHANGE` and selects the
                // grabbed tab ŌĆö that's the right UX (clicking a
                // tab activates it, dragging then reorders the
                // already-active tab).
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            WM_MOUSEMOVE => {
                // WM_MOUSEMOVE fires constantly while the cursor is
                // over the tab strip, with or without a button held.
                // We use it for two things: drag-to-reorder (when
                // `tab_drag` is set) and hover state for the close-X
                // glyphs (always tracked so the X reveals on inactive
                // tabs while the cursor is over them).
                let x = i32::from((lparam.0 & 0xFFFF) as i16);
                let y = i32::from(((lparam.0 >> 16) & 0xFFFF) as i16);
                let parent = GetParent(hwnd).unwrap_or_default();
                let hit = tab_hit_test(hwnd, x, y);
                let close_hit = tab_close_x_hit_test(hwnd, x, y).is_some();
                let pin_hit = tab_pin_hit_test(hwnd, x, y).is_some();
                // Hover-state update + TrackMouseEvent arming. Done
                // outside the drag branch so plain hover (no button
                // held) updates the visible X / pin glyphs
                // immediately.
                if let Some(state) = state_from_hwnd(parent) {
                    let prev_idx = state.tab_hover_idx;
                    let prev_on_x = state.tab_hover_close_x;
                    let prev_on_pin = state.tab_hover_pin;
                    state.tab_hover_idx = hit;
                    state.tab_hover_close_x = close_hit;
                    state.tab_hover_pin = pin_hit;
                    if !state.tab_mouse_tracking {
                        let mut tme = TRACKMOUSEEVENT {
                            cbSize: core::mem::size_of::<TRACKMOUSEEVENT>() as u32,
                            dwFlags: TME_LEAVE,
                            hwndTrack: hwnd,
                            dwHoverTime: 0,
                        };
                        // SAFETY: `tme` is a stack binding alive
                        // across the synchronous TrackMouseEvent
                        // call; the call writes nothing back and
                        // arms a one-shot WM_MOUSELEAVE.
                        let _ = TrackMouseEvent(&raw mut tme);
                        state.tab_mouse_tracking = true;
                    }
                    // Repaint affected cells on transitions. We
                    // invalidate two indices (old + new) to cover
                    // moves between adjacent tabs; for a same-tab
                    // sub-region change (X or pin), the old==new
                    // path collapses to one InvalidateRect.
                    if prev_idx != hit || prev_on_x != close_hit || prev_on_pin != pin_hit {
                        if let Some(prev) = prev_idx {
                            invalidate_tab(hwnd, prev);
                        }
                        if let Some(now) = hit {
                            invalidate_tab(hwnd, now);
                        }
                    }
                }
                if let Some(state) = state_from_hwnd(parent) {
                    if let Some(mut drag) = state.tab_drag {
                        // Defensive: another input path could
                        // shrink `tabs` mid-drag (e.g., a Ctrl+W
                        // close ŌĆö keyboard messages aren't gated
                        // by mouse capture, so they keep flowing
                        // to the main window). If our recorded
                        // source index no longer points at a
                        // live tab, abandon the drag rather than
                        // burning O(N) `move_tab` no-ops on
                        // every subsequent mousemove.
                        if drag.source_idx >= state.shell.tabs.len() {
                            state.tab_drag = None;
                            return DefSubclassProc(hwnd, msg, wparam, lparam);
                        }
                        // Promote click ŌåÆ drag once the user has
                        // crossed the move threshold. Sticky once
                        // set ŌĆö wiggling back over the source
                        // tab still allows further reordering.
                        if !drag.threshold_passed
                            && (x - drag.start_x).abs() >= TAB_DRAG_THRESHOLD_PX
                        {
                            drag.threshold_passed = true;
                        }
                        if drag.threshold_passed {
                            if let Some(target_idx) = hit {
                                // Bubble the dragged tab toward the
                                // cursor one neighbour at a time ŌĆö
                                // each iteration calls `move_tab`
                                // (which adjusts `active_tab` for
                                // us) and re-syncs the visible tab
                                // strip. With high-frequency
                                // mousemove delivery this still
                                // reads as a smooth animation,
                                // even when the cursor jumps
                                // several cells at once.
                                let max_steps = state.shell.tabs.len();
                                let mut steps = 0;
                                while drag.source_idx != target_idx && steps < max_steps {
                                    let next = if drag.source_idx < target_idx {
                                        drag.source_idx + 1
                                    } else {
                                        drag.source_idx - 1
                                    };
                                    if state.shell.move_tab(drag.source_idx, next) {
                                        drag.source_idx = next;
                                    } else {
                                        break;
                                    }
                                    steps += 1;
                                }
                                if steps > 0 {
                                    force_tab_strip_resync(state);
                                }
                            }
                        }
                        state.tab_drag = Some(drag);
                    }
                }
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            WM_LBUTTONUP => {
                let x = i32::from((lparam.0 & 0xFFFF) as i16);
                let y = i32::from(((lparam.0 >> 16) & 0xFFFF) as i16);
                let parent = GetParent(hwnd).unwrap_or_default();
                // Commit the close-X arm if the release lands on the
                // same X the press did ŌĆö Win32 button convention
                // ("click and drag away to cancel"). The arm clears
                // unconditionally so a release outside the X (or on
                // a different tab's X) just dismisses without firing.
                let release_close_hit = tab_close_x_hit_test(hwnd, x, y);
                let release_pin_hit = tab_pin_hit_test(hwnd, x, y);
                let (close_armed, pin_armed) = if let Some(state) = state_from_hwnd(parent) {
                    let c = state.tab_close_armed.take();
                    let p = state.tab_pin_armed.take();
                    state.tab_drag = None;
                    (c, p)
                } else {
                    (None, None)
                };
                let _ = ReleaseCapture();
                if let Some(armed_idx) = close_armed {
                    if release_close_hit == Some(armed_idx) {
                        // Activate the clicked tab if it wasn't
                        // already, then post the close. The
                        // activation runs synchronously via
                        // `TCM_SETCURSEL` + a synthesised
                        // `TCN_SELCHANGE`; the close runs after
                        // we return so any per-tab close prompt
                        // appears against the just-activated
                        // buffer.
                        let cur = SendMessageW(hwnd, TCM_GETCURSEL, None, None).0 as i32;
                        if cur != armed_idx as i32 {
                            SendMessageW(
                                hwnd,
                                TCM_SETCURSEL,
                                Some(WPARAM(armed_idx)),
                                Some(LPARAM(0)),
                            );
                            // TCM_SETCURSEL doesn't fire
                            // TCN_SELCHANGE ŌĆö synthesise it so
                            // `handle_tab_selchange` runs the
                            // SCI_SETDOCPOINTER swap and the
                            // close path operates on the right
                            // buffer.
                            handle_tab_selchange(parent);
                        }
                        let _ = PostMessageW(
                            Some(parent),
                            WM_COMMAND,
                            WPARAM(ID_FILE_CLOSE as usize),
                            LPARAM(0),
                        );
                    }
                }
                // Pin arm commits on same-pin release, mirroring
                // the close-X convention. `Shell::set_pinned` does
                // the flag flip + boundary move + active-index
                // adjustment + `NPPN_DOCORDERCHANGED` in one call.
                // Force a full tab-strip resync after so the
                // system tab control's TCITEM order reflects the
                // reordered `Shell.tabs` ŌĆö otherwise the moved
                // pinned tab keeps its old visual position until
                // the next TCM_INSERTITEM / DELETEITEM.
                //
                // `TCM_SETCURSEL`/`TCM_DELETEALLITEMS`/`TCM_INSERTITEMW`
                // do not fire `TCN_SELCHANGE` (documented Win32
                // behaviour), so the synchronous resync from
                // inside a mouse handler cannot re-enter our
                // `wnd_proc` and double-borrow `&mut WindowState`
                // ŌĆö same rationale the drag-reorder path relies
                // on.
                if let Some(armed_idx) = pin_armed {
                    if release_pin_hit == Some(armed_idx) {
                        if let Some(state) = state_from_hwnd(parent) {
                            let want = !state.shell.tabs.get(armed_idx).is_some_and(|t| t.pinned);
                            if state.shell.set_pinned(armed_idx, want) {
                                force_tab_strip_resync(state);
                                // Refresh hover state against the
                                // NEW tab order ŌĆö the cursor
                                // hasn't moved but a different
                                // logical tab now sits under it,
                                // so `tab_hover_idx` /
                                // `tab_hover_pin` etc. are stale.
                                // Without this, the next paint
                                // renders hover-darkened glyphs
                                // on whichever tab happens to
                                // land at the stale index until
                                // the user's next physical mouse
                                // move corrects it.
                                refresh_tab_hover_from_cursor(state, hwnd);
                            }
                        }
                    }
                }
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            WM_MOUSELEAVE => {
                // Cursor left the tab strip: clear hover state,
                // disarm the leave tracker (Win32 fires once per
                // arm), and repaint the previously-hovered cell so
                // its close-X / pin returns to non-hover colour.
                let parent = GetParent(hwnd).unwrap_or_default();
                if let Some(state) = state_from_hwnd(parent) {
                    let prev = state.tab_hover_idx;
                    state.tab_hover_idx = None;
                    state.tab_hover_close_x = false;
                    state.tab_hover_pin = false;
                    state.tab_mouse_tracking = false;
                    if let Some(idx) = prev {
                        invalidate_tab(hwnd, idx);
                    }
                }
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            WM_CAPTURECHANGED => {
                // Same rationale as `splitter_wnd_proc`: if capture
                // is taken away mid-drag (alt-tab, parent destroy,
                // ŌĆ”), drop the drag state so the next mouse-move
                // doesn't reorder tabs without a held button. Same
                // logic for the close-X / pin arms: capture loss =
                // cancel.
                //
                // Hover state piggy-backs on the same teardown:
                // without this, an Alt-Tab while the cursor sits over
                // a tab leaves the previously-hovered cell painted
                // with its hover-shaded background and visible close-X
                // / pin until the cursor next moves over the strip.
                let parent = GetParent(hwnd).unwrap_or_default();
                let prev_hover = if let Some(state) = state_from_hwnd(parent) {
                    state.tab_drag = None;
                    state.tab_close_armed = None;
                    state.tab_pin_armed = None;
                    let prev = state.tab_hover_idx;
                    state.tab_hover_idx = None;
                    state.tab_hover_close_x = false;
                    state.tab_hover_pin = false;
                    state.tab_mouse_tracking = false;
                    prev
                } else {
                    None
                };
                if let Some(idx) = prev_hover {
                    invalidate_tab(hwnd, idx);
                }
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            WM_NCDESTROY => {
                // Match comctl32's documented "remove on destroy"
                // requirement so the subclass storage doesn't
                // outlive the HWND.
                let _ = windows::Win32::UI::Shell::RemoveWindowSubclass(
                    hwnd,
                    Some(tab_subclass_proc),
                    TAB_SUBCLASS_ID,
                );
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            _ => DefSubclassProc(hwnd, msg, wparam, lparam),
        }
    }));
    match result {
        Ok(lr) => lr,
        // Same fallback as the other wnd_procs in this file:
        // forward to the system handler on panic so the message
        // still produces a sensible default.
        Err(_) => unsafe { DefSubclassProc(hwnd, msg, wparam, lparam) },
    }
}

/// Subclass id passed to `SetWindowSubclass` / `RemoveWindowSubclass`.
/// Only one subclass is installed on the tab control today, so the
/// value is arbitrary ŌĆö the constant just gives it a name.
const TAB_SUBCLASS_ID: usize = 1;

/// Subclass id for the Document Map's Scintilla control ŌĆö used to
/// hijack mouse events (`WM_LBUTTONDOWN`/`MOUSEMOVE`/`LBUTTONUP`)
/// so a click / drag on the miniature view scrolls the MAIN
/// editor to the corresponding line. Same subclass mechanism the
/// tab strip uses ([`TAB_SUBCLASS_ID`]). Numerically distinct
/// from other `*_SUBCLASS_ID` constants in this file ŌĆö the
/// `uIdSubclass` `SetWindowSubclass` parameter is scoped
/// per-HWND, so a collision would be inert, but keeping the
/// values unique across the file avoids confusing future readers
/// who assume a global namespace.
const DOCMAP_SCINTILLA_SUBCLASS_ID: usize = 3;

/// Subclass id for the status-bar control. Each subclassed control
/// needs its own id in the parent's subclass-chain bookkeeping ŌĆö the
/// values are arbitrary but must be distinct across all
/// `SetWindowSubclass` callers on a given HWND.
const STATUS_BAR_SUBCLASS_ID: usize = 2;

/// Status-bar message: query the bounding rectangle of a part (the
/// status bar is divided into N parts by `setup_status_parts`). The
/// `windows` crate doesn't re-export `SB_GETRECT` in the
/// `UI::Controls` module today; same pattern as the locally-defined
/// `SB_SETTEXTW` inside `update_status` ŌĆö the numeric value is from
/// `commctrl.h` and is part of the stable Win32 ABI.
const SB_GETRECT: u32 = 0x040A;

/// Subclass procedure for the status bar. Intercepts right-clicks
/// on the leftmost (language) part and pops a context menu showing
/// the same content as the main menu bar's Language submenu. All
/// other messages pass through to `DefSubclassProc` unchanged.
///
/// Reuses the existing `state.language_menu` HMENU directly ŌĆö the
/// same HMENU is attached to the menu bar as a submenu and can be
/// passed to `TrackPopupMenu` without copying. Radio checkmarks
/// (which mark the currently-detected language) are kept in sync
/// by the shared `refresh_language_menu` call path; the popup
/// inherits the current state automatically.
///
/// Same `catch_unwind` guard as `tab_subclass_proc` ŌĆö unwinding
/// across an `extern "system"` frame is UB.
extern "system" fn status_bar_subclass_proc(
    hwnd: HWND,
    msg: u32,
    wparam: WPARAM,
    lparam: LPARAM,
    _id_subclass: usize,
    _ref_data: usize,
) -> LRESULT {
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| unsafe {
        match msg {
            WM_RBUTTONUP => {
                // Extract client-relative x / y from the packed lparam.
                // Same low-/high-word pattern as `tab_subclass_proc`
                // and every other Win32 mouse handler in the file.
                let x = i32::from((lparam.0 & 0xFFFF) as i16);
                let y = i32::from(((lparam.0 >> 16) & 0xFFFF) as i16);
                if status_bar_x_is_in_lang_part(hwnd, x) {
                    show_language_status_context_menu(hwnd, x, y);
                    return LRESULT(0);
                }
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            WM_NCDESTROY => {
                // Match comctl32's documented "remove on destroy"
                // requirement so the subclass storage doesn't
                // outlive the HWND. Same pattern as
                // `tab_subclass_proc`.
                let _ = windows::Win32::UI::Shell::RemoveWindowSubclass(
                    hwnd,
                    Some(status_bar_subclass_proc),
                    STATUS_BAR_SUBCLASS_ID,
                );
                DefSubclassProc(hwnd, msg, wparam, lparam)
            }
            _ => DefSubclassProc(hwnd, msg, wparam, lparam),
        }
    }));
    // Panic fallback forwards to `DefSubclassProc` rather than
    // returning 0 ŌĆö matches `tab_subclass_proc`'s shape and produces
    // a sensible system default for any message a future maintainer
    // adds custom handling for.
    result.unwrap_or_else(|_| unsafe { DefSubclassProc(hwnd, msg, wparam, lparam) })
}

/// True iff `client_x` (status-bar client coordinates) lands inside
/// the language part. The 7-part layout is rebuilt by
/// `setup_status_parts` on every `WM_SIZE`, but the language part is
/// always part 0 ŌĆö so the rect query is stable across window
/// resizes without needing to plumb the current layout through.
unsafe fn status_bar_x_is_in_lang_part(status_hwnd: HWND, client_x: i32) -> bool {
    let mut rect = RECT::default();
    let ok = unsafe {
        SendMessageW(
            status_hwnd,
            SB_GETRECT,
            Some(WPARAM(STATUS_PART_LANG)),
            Some(LPARAM(&raw mut rect as isize)),
        )
    };
    if ok.0 == 0 {
        return false;
    }
    client_x >= rect.left && client_x < rect.right
}

/// Pop a context menu showing the Language menu's contents at the
/// given status-bar client coordinates. `TPM_BOTTOMALIGN` opens the
/// menu upward from the click point so it doesn't extend below the
/// screen edge (the status bar is at the bottom of the window).
/// `TPM_RETURNCMD` makes `TrackPopupMenu` return the selected
/// command id instead of posting it; we then `PostMessageW` it to
/// the main window so the existing `WM_COMMAND` dispatch path
/// (`handle_language_menu_click`) handles it identically to a click
/// on the real menu-bar Language item.
unsafe fn show_language_status_context_menu(status_hwnd: HWND, client_x: i32, client_y: i32) {
    let parent = match unsafe { GetParent(status_hwnd) } {
        Ok(p) => p,
        Err(_) => return,
    };
    let Some(state) = (unsafe { state_from_hwnd(parent) }) else {
        return;
    };
    let menu = state.language_menu;
    if menu.0.is_null() {
        return;
    }
    // Refresh the radio-bullet on the active language's menu item
    // BEFORE the popup is shown. `WM_INITMENUPOPUP` does fire for
    // `TrackPopupMenu` and the existing handler in `main_wnd_proc`
    // re-applies the radio mark ŌĆö but doing it here too is cheap
    // (one `CheckMenuRadioItem` + a loop over a handful of
    // submenus) and ensures the bullet is correct even if a future
    // `TPM_NONOTIFY`-style flag suppresses the init path. Same
    // borrow lifetime as `state` ŌĆö drops on the next line.
    if let Some(active) = state.shell.active() {
        unsafe { refresh_language_menu(menu, active.lang) };
    }
    // `state` borrow ends here (NLL): `menu` is a `Copy` HMENU, no
    // further field access. `TrackPopupMenu` below enters a modal
    // message loop that re-dispatches into `main_wnd_proc`, which
    // calls `state_from_hwnd(parent)` again; with this borrow
    // already dropped there's no aliased `&mut WindowState`.
    let _ = state;
    let mut pt = POINT {
        x: client_x,
        y: client_y,
    };
    if !unsafe { ClientToScreen(status_hwnd, &raw mut pt) }.as_bool() {
        return;
    }
    // TPM_BOTTOMALIGN ŌĆö menu's bottom edge at `pt.y` ŌåÆ opens upward.
    // TPM_LEFTALIGN  ŌĆö left edge at `pt.x`.
    // TPM_RETURNCMD  ŌĆö return id instead of auto-posting WM_COMMAND.
    // TPM_RIGHTBUTTON ŌĆö right-click selects items (default is left).
    // Deliberately NOT TPM_NONOTIFY ŌĆö that flag's behaviour on
    // `WM_INITMENUPOPUP` is ambiguous across Windows versions, and
    // letting init notifications through means our existing
    // `WM_INITMENUPOPUP` handler can refresh the menu (the explicit
    // refresh above is belt-and-braces).
    let cmd = unsafe {
        TrackPopupMenu(
            menu,
            TPM_BOTTOMALIGN | TPM_LEFTALIGN | TPM_RETURNCMD | TPM_RIGHTBUTTON,
            pt.x,
            pt.y,
            Some(0),
            parent,
            None,
        )
    };
    if cmd.0 != 0 {
        // Same WM_COMMAND shape the menu bar produces ŌĆö `wparam` low
        // word = command id, high word = notification code (0 for
        // menu items), `lparam` = 0 for menu sources. Routed through
        // the existing ID_LANGUAGE_BASE dispatch in `main_wnd_proc`.
        let _ =
            unsafe { PostMessageW(Some(parent), WM_COMMAND, WPARAM(cmd.0 as usize), LPARAM(0)) };
    }
}

// --- Tab strip owner-draw paint ---------------------------------------------
//
// `TCS_OWNERDRAWFIXED` makes the parent receive `WM_DRAWITEM` per tab
// cell. We paint everything ourselves: background fill, the dirty/clean
// floppy icon (left), the tab text (centre), and the close-X (right).
// This is the only path on Win10/11 that reliably renders custom icons +
// hover state inside tab cells ŌĆö UxTheme paints over `NM_CUSTOMDRAW`
// callbacks for tabs and steals the cell, but it does not intercept
// `WM_DRAWITEM`.

/// Tab-strip icon edge length at standard DPI (kept dormant ŌĆö see
/// [`pick_tab_bitmap_size`]). Half the toolbar's 24-px choice
/// because the strip is too short for a 24-px icon at the old
/// [`TAB_HEIGHT_PX`] of 22; unused today because the taller 30-px
/// strip pairs with the HIDPI icon on every DPI tier so a single
/// 32-px source bitmap covers both LO and HIDPI paths.
#[allow(dead_code)]
const TAB_BITMAP_PX_LO: i32 = 16;
/// Tab-strip icon **source** edge length in pixels ŌĆö the size of the
/// PNG asset decoded into `WindowState.tab_save_*_hbm`. Named
/// `HIDPI` for historical reasons (LO / HIDPI selection lived in
/// [`pick_tab_bitmap_size`]); today the function returns this value
/// unconditionally so the higher-resolution source is used on every
/// DPI tier. The **displayed** icon size is
/// [`TAB_ICON_DISPLAY_PX`], which is smaller ŌĆö the source bitmap
/// is downscaled at blit time via `AlphaBlend`'s built-in stretch
/// so the icon fits inside the [`TAB_HEIGHT_PX`] cell with
/// breathing room and clears the [`TAB_ACTIVE_INDICATOR`] strip.
const TAB_BITMAP_PX_HIDPI: i32 = 32;

/// Tab-strip icon **display** edge length. Decoupled from the
/// source bitmap size ([`TAB_BITMAP_PX_HIDPI`]) so we can render a
/// crisp downscale of the 32-px asset at whatever size actually
/// fits the 30-px tab cell without clipping. 20 px leaves 5 px of
/// vertical breathing room top+bottom around a 30-px cell centred
/// vertically (30 ŌłÆ 20 = 10 ŌåÆ 5 px each side). The icon's top rows
/// sit inside the top edge of the
/// [`TAB_ACTIVE_INDICATOR_HEIGHT_PX_HIDPI`] orange strip on active
/// tabs; the icon paints after the strip via `AlphaBlend`, so its
/// opaque pixels overwrite the strip within the icon's ~20-px-wide
/// left column while the strip stays fully visible across the rest
/// of the tab width ŌĆö see [`tab_save_icon_rect`] for the alignment
/// rationale (icon centre matches the text centre). `AlphaBlend`
/// does bilinear-ish stretch on downscale; 32ŌåÆ20 is a clean-enough
/// ratio (~63%) that the glyph stays legible.
const TAB_ICON_DISPLAY_PX: i32 = 20;

/// Pixel inset from the tab cell's left edge to the save icon, and
/// from the tab cell's right edge to the close-X glyph. Generous
/// enough that the icons don't crowd the cell border on either side.
const TAB_PAD_X_PX: i32 = 6;
/// Pixel gap between the save icon and the start of the tab text.
const TAB_ICON_TEXT_GAP_PX: i32 = 4;
/// Pixel gap between the tab text and the close-X glyph.
const TAB_TEXT_CLOSEX_GAP_PX: i32 = 4;
/// Edge length of the close-X clickable area inside a tab cell.
/// 12 px is roughly the size of the toolbar close-X glyph and reads
/// at every supported DPI without dominating the tab cell.
const TAB_CLOSEX_SIZE_PX: i32 = 12;
/// Edge length of the pin-toggle clickable area, sat immediately
/// left of the close-X. Matches [`TAB_CLOSEX_SIZE_PX`] so the two
/// affordances read as a paired row.
const TAB_PIN_SIZE_PX: i32 = 12;
/// Pixel padding to feed `TCM_SETPADDING` so the tab control reserves
/// room either side of the tab text for the save icon (left) and
/// close-X + pin (right). Left-side reservation must accommodate
/// `TAB_PAD_X_PX` (6) + [`TAB_ICON_DISPLAY_PX`] (20) +
/// `TAB_ICON_TEXT_GAP_PX` (4) = 30 px. Right-side must fit
/// `TAB_PAD_X_PX` (6) + `TAB_CLOSEX_SIZE_PX` (12) +
/// `TAB_TEXT_CLOSEX_GAP_PX` (4) + [`TAB_PIN_SIZE_PX`] (12) +
/// `TAB_TEXT_CLOSEX_GAP_PX` (4) = 38 px. `TCM_SETPADDING` takes a
/// single value applied to both sides, so use the larger ŌĆö the
/// left picks up 8 extra cushion px, which reads as slightly more
/// breathing room around the save icon rather than a layout bug.
/// No DPI awareness in `TCM_SETPADDING` itself, so this is a
/// single value applied across DPI tiers.
const TAB_TEXT_PADDING_X_PX: i32 = 38;
/// Vertical padding fed to `TCM_SETPADDING` alongside [`TAB_TEXT_PADDING_X_PX`].
/// Sized against [`TAB_HEIGHT_PX`] (30) so the auto-computed cell
/// (`text_height` Ōēł 15 + 2 * `padding_y` + control overhead) fills
/// the strip end-to-end without a bare band on top. 7 empirically
/// lands the cell at ~30 px at 96 DPI with the default GUI font ŌĆö
/// the tab control's per-padding-unit contribution to cell height
/// is ~1.9 px, so `padding_y = 7` yields cell Ōēł 15 + 14 + overhead Ōēł
/// 30, matching the target strip height.
const TAB_TEXT_PADDING_Y_PX: i32 = 7;

/// `SourceConstantAlpha` (0..255) `AlphaBlend` applies when blitting an
/// inactive tab's save icon. 128 Ōēł 50% opacity ŌĆö readable but visibly
/// dimmer than the active tab's full-opacity icon.
const TAB_INACTIVE_ICON_ALPHA: u8 = 128;

/// Tab cell background colour when the tab is active. White, matching
/// the editor body so the active tab reads as a continuous extension
/// of the document area below it.
const TAB_BG_ACTIVE: u32 = 0x00_FF_FF_FF;
/// Tab cell background for inactive tabs. A slight dark grey
/// (~RGB 208,208,208) that puts the inactive cells "in shade"
/// against the near-white active tab and light toolbar chrome ŌĆö the
/// look users asked for on Win10/11 light mode. Old value 0xF0F0F0
/// (near-white) was too close to the surrounding chrome to read as
/// inactive at a glance. The save icon within inherits the shaded
/// look via `TAB_INACTIVE_ICON_ALPHA`'s 50% blend against this
/// darker backdrop ŌĆö no separate icon colour is needed.
const TAB_BG_INACTIVE: u32 = 0x00_D0_D0_D0;
/// Same as [`TAB_BG_INACTIVE`] but slightly brighter, used while the
/// cursor hovers over an inactive tab. RGB ~220,220,220 ŌĆö a small
/// step lift that still keeps the cell visibly "in shade" relative
/// to the active tab.
const TAB_BG_INACTIVE_HOVER: u32 = 0x00_DC_DC_DC;
/// Foreground (text) colour for the active tab's label.
const TAB_FG_ACTIVE: u32 = 0x00_00_00_00;
/// Foreground for inactive tabs ŌĆö medium grey so they read as
/// secondary without becoming illegible.
const TAB_FG_INACTIVE: u32 = 0x00_60_60_60;

/// Orange strip painted along the top edge of the active tab as a
/// "this is the focused buffer" indicator. RGB(255,167,38) ŌĆö the
/// Material `orange 400` shade. Lighter than the toolbar palette's
/// `ORANGE` (`orange 600`, used for the paste icon) so the strip
/// reads as an accent rather than competing with the chrome. The
/// system tab control paints a hairline themed outline on top of
/// the cell after `WM_DRAWITEM` returns, eating ~1 px from the top
/// of the strip; the paint path unconditionally uses
/// [`TAB_ACTIVE_INDICATOR_HEIGHT_PX_HIDPI`] (8 px painted) so the
/// visible portion is ~7 px ŌĆö reads as a bold accent band rather
/// than a thin hairline. COLORREF is BGR.
const TAB_ACTIVE_INDICATOR: u32 = 0x00_26_A7_FF;
/// Pixel height of the active-tab indicator strip at standard DPI
/// (kept dormant ŌĆö see [`pick_tab_bitmap_size`]). 6 px painted Ōēł
/// 5 px visible after the system's themed-outline overdraw; would
/// read as a strong accent at 96 DPI. Unused today because the
/// tab-strip paint path unconditionally uses
/// [`TAB_ACTIVE_INDICATOR_HEIGHT_PX_HIDPI`] alongside the always-
/// HIDPI icon source; a future per-monitor DPI scaler slotting into
/// [`pick_tab_bitmap_size`] can rewire the paint site to pick
/// between these two values.
#[allow(dead_code)]
const TAB_ACTIVE_INDICATOR_HEIGHT_PX_LO: i32 = 6;
/// `HiDPI` counterpart ŌĆö reduced from the initial value of 9 to 8
/// px so the strip pairs cleanly with the 20-px icon inside a
/// 30-px cell (a taller strip started eating perceptible space
/// off the icon's ~5-px top breathing room). Same
/// overlap-then-overwrite scheme as the LO tier (see
/// [`tab_save_icon_rect`]): the icon's top rows sit inside the
/// strip's reserved zone, but the icon's `AlphaBlend` runs after
/// the strip fill so the icon column paints cleanly on top and the
/// strip stays visible across the rest of the tab.
const TAB_ACTIVE_INDICATOR_HEIGHT_PX_HIDPI: i32 = 8;

/// Background fill for the close-X box on the active tab in its
/// resting state ŌĆö a deep red. COLORREF (BBGGRR) for RGB(183,28,28),
/// the `red 900` Material-like shade. The white X glyph is drawn on
/// top so the box reads as a familiar "close" affordance at a glance.
const TAB_CLOSEX_BOX_DARK: u32 = 0x00_1C_1C_B7;
/// Background fill for the close-X box when the cursor sits directly
/// over the box, on any tab (active or inactive). RGB(229,57,53) ŌĆö
/// the same `red 600` shade the toolbar palette uses, picked for
/// visual continuity with the rest of the chrome.
const TAB_CLOSEX_BOX_LIGHT: u32 = 0x00_35_39_E5;
/// Greyed-out box fill used on inactive tabs the cursor is hovering
/// but not specifically over the X glyph. RGB(136,136,136).
const TAB_CLOSEX_BOX_GREY: u32 = 0x00_88_88_88;
/// Stroke colour of the X glyph drawn inside every close-box
/// regardless of active/inactive/hover state. White (RGB 255,255,255).
const TAB_CLOSEX_GLYPH: u32 = 0x00_FF_FF_FF;

/// Fill colour for the pin glyph in its **pinned** state. Material
/// blue 500 (RGB 33,150,243), stored as BGR for `COLORREF`. A
/// deliberately different hue family from the orange
/// [`TAB_ACTIVE_INDICATOR`] strip (Material orange 400) so a tab
/// that is both pinned AND active shows both accents without them
/// competing chromatically ŌĆö orange band across the top, blue
/// glyph on the right, complementary hues that read as distinct
/// signals rather than a single confused colour.
const TAB_PIN_FILL_PINNED: u32 = 0x00_F3_96_21;
/// Outline colour for the pin glyph in its **unpinned** state.
/// Neutral medium grey (RGB 128,128,128), BGR. Since every tab
/// defaults to unpinned, this glyph paints on every cell out of
/// the box; a saturated hue (an earlier iteration used Material
/// red 700) reads as "warning" applied to the whole strip. Grey
/// keeps the affordance visible without shouting, and reserves
/// the accent hue ([`TAB_PIN_FILL_PINNED`]) for the pinned state
/// where visual weight is the correct signal.
const TAB_PIN_OUTLINE_UNPINNED: u32 = 0x00_80_80_80;

/// Compile-time-embedded PNG bytes for the tab-strip save icons. The
/// LO / HIDPI pairs are 16-px / 32-px renders of the same SVG sources
/// generated by `tools/codepp-icons/generate.py`. Decoded once at
/// `WindowState` construction via `toolbar::png_to_hbitmap` and stored
/// as `HBITMAP`s on `WindowState` for the life of the window. LO
/// variants are kept dormant behind [`pick_tab_bitmap_size`] for a
/// future per-monitor DPI scaler; today only the HIDPI pair is
/// actually decoded.
#[allow(dead_code)]
const PNG_TAB_SAVE_LO: &[u8] = include_bytes!("../../../assets/icons/tab-save.png");
const PNG_TAB_SAVE_HIDPI: &[u8] = include_bytes!("../../../assets/icons/tab-save@2x.png");
#[allow(dead_code)]
const PNG_TAB_SAVE_DIRTY_LO: &[u8] = include_bytes!("../../../assets/icons/tab-save-dirty.png");
const PNG_TAB_SAVE_DIRTY_HIDPI: &[u8] =
    include_bytes!("../../../assets/icons/tab-save-dirty@2x.png");

/// Pick the tab-strip icon **source** bitmap edge length.
///
/// Historically DPI-driven ŌĆö LO on sub-144-DPI systems, HIDPI at
/// or above `toolbar::HIDPI_DPI_THRESHOLD` (144 DPI, i.e. Windows'
/// 150 % scaling tier) ŌĆö but now that the tab strip is
/// [`TAB_HEIGHT_PX`] (30) tall ŌĆö up from the 22-px Win32 default ŌĆö
/// the 16-px LO source read as tiny inside the taller cell. Users asked for a
/// save icon that scales up in proportion to the taller tab
/// height, so we always return HIDPI regardless of monitor DPI and
/// downscale to [`TAB_ICON_DISPLAY_PX`] (20) at blit time via
/// `AlphaBlend`'s built-in stretch. The 32-px source is the SVG's
/// native @2x render, so decoding it is cheap and stretching down
/// to 20 px gives a crisper glyph than upscaling the 16-px LO
/// source would. Kept as a function (rather than inlining the
/// constant) so a future DPI-aware scaler ŌĆö say, per-monitor DPI
/// with two extra asset tiers ŌĆö can slot back in without churning
/// the call sites.
fn pick_tab_bitmap_size() -> i32 {
    TAB_BITMAP_PX_HIDPI
}

/// Compute the screen-space rect of the close-X clickable area within
/// a tab cell whose item rect is `item_rect`. The X sits flush-right
/// inside the cell, vertically centred.
///
/// Pure function so the hit-test path (`tab_close_x_hit_test`) and the
/// paint path (`paint_tab_item`) both compute the same rect from the
/// same input ŌĆö drift between them would mean clicks land in the wrong
/// place relative to the painted glyph.
fn tab_close_x_rect(item_rect: RECT) -> RECT {
    let cy = i32::midpoint(item_rect.top, item_rect.bottom);
    let half = TAB_CLOSEX_SIZE_PX / 2;
    let right = item_rect.right - TAB_PAD_X_PX;
    let left = right - TAB_CLOSEX_SIZE_PX;
    RECT {
        left,
        top: cy - half,
        right,
        bottom: cy - half + TAB_CLOSEX_SIZE_PX,
    }
}

/// Compute the screen-space rect of the pin-toggle clickable area
/// within a tab cell. The pin sits immediately left of the close-X
/// with [`TAB_TEXT_CLOSEX_GAP_PX`] between them (reusing the same
/// gap constant that separates the text label from the close-X ŌĆö
/// visually the two right-hand affordances read as a paired row
/// with equal breathing room).
///
/// Pure function so the hit-test path ([`tab_pin_hit_test`],
/// added in p3) and the paint path ([`paint_tab_item`]) both
/// derive the same rect from the same input ŌĆö drift between them
/// would mean clicks land in the wrong place relative to the
/// painted glyph.
fn tab_pin_rect(item_rect: RECT) -> RECT {
    let cy = i32::midpoint(item_rect.top, item_rect.bottom);
    let half = TAB_PIN_SIZE_PX / 2;
    let right = tab_close_x_rect(item_rect).left - TAB_TEXT_CLOSEX_GAP_PX;
    let left = right - TAB_PIN_SIZE_PX;
    RECT {
        left,
        top: cy - half,
        right,
        bottom: cy - half + TAB_PIN_SIZE_PX,
    }
}

/// Polygon vertices for the pinned-state pin glyph (upright
/// thumbtack), expressed in a 12├Ś12 canvas anchored at (0, 0).
/// Shape: a horizontal head bar at the top, a vertical shaft
/// below, and a triangular point at the bottom ŌĆö the classic
/// thumbtack silhouette that reads correctly at 12 px.
/// Traversed clockwise starting from the top-left of the head.
///
/// The paint path translates each vertex by
/// `(pin_rect.left, pin_rect.top)` before feeding them to
/// `Polygon`, so this table is a pure design artefact ŌĆö changing
/// the shape is a table edit, not a rework of the paint code.
const TAB_PIN_POLYGON_PINNED: &[(i32, i32)] = &[
    (3, 2),  // head, top-left
    (9, 2),  // head, top-right
    (9, 4),  // head, bottom-right
    (7, 4),  // step inward to shaft
    (7, 8),  // shaft, right side
    (6, 11), // tip
    (5, 8),  // shaft, left side
    (5, 4),  // step inward to head
    (3, 4),  // head, bottom-left
];

/// Polygon vertices for the unpinned-state pin glyph ŌĆö the same
/// thumbtack silhouette rotated 45┬░ counter-clockwise (visually:
/// head at the upper edge tilted lower-left ŌåÆ upper-right, tip
/// at the lower-right corner). Rotation is baked in at design
/// time so runtime paint is a single translate + `Polygon`.
///
/// Vertices were derived from [`TAB_PIN_POLYGON_PINNED`] by the
/// screen-space 45┬░ CCW rotation formula:
/// `new = (round(6 + 0.707┬Ędx + 0.707┬Ędy), round(6 ŌłÆ 0.707┬Ędx + 0.707┬Ędy))`
/// with `(dx, dy) = (x ŌłÆ 6, y ŌłÆ 6)`. Rounded to the nearest
/// integer for pixel alignment. Same clockwise traversal order
/// as the unrotated shape.
const TAB_PIN_POLYGON_UNPINNED: &[(i32, i32)] = &[
    (1, 5),
    (5, 1),
    (7, 2),
    (5, 4),
    (8, 7),
    (10, 10),
    (7, 8),
    (4, 5),
    (2, 7),
];

/// Darken a `COLORREF` (BGR-encoded 32-bit value) by `delta` per
/// channel, saturating at 0. Used by the pin-glyph paint path to
/// tint the hover state without a second colour constant per state
/// ŌĆö a `40`-per-channel drop reads as "same colour, slightly
/// darker" across every base hue we use, matching the visual
/// convention the close-X's `BOX_DARK` ŌåÆ `BOX_LIGHT` hover swap
/// establishes.
///
/// Pure function, unit-testable, and cheap enough (three
/// saturating subtracts) that it's called every paint frame
/// without measurable cost.
///
/// `COLORREF` on Windows is documented `0x00BBGGRR` ŌĆö the low
/// byte is **Red**, not Blue, despite the name. Channel names
/// here match actual bit position (not the "BGR" spelling) so
/// a future generalization that adjusts channels non-uniformly
/// can trust the labels.
fn darken_colorref(bgr: u32, delta: u8) -> u32 {
    let r = (bgr & 0xFF) as u8;
    let g = ((bgr >> 8) & 0xFF) as u8;
    let b = ((bgr >> 16) & 0xFF) as u8;
    let r2 = r.saturating_sub(delta);
    let g2 = g.saturating_sub(delta);
    let b2 = b.saturating_sub(delta);
    (u32::from(b2) << 16) | (u32::from(g2) << 8) | u32::from(r2)
}

/// Compute the rect inside a tab cell where the save icon is painted.
/// The icon sits flush-left, vertically centred on the cell midpoint
/// ŌĆö the same midpoint `DrawTextW`'s `DT_VCENTER` uses for the tab
/// label ŌĆö so the icon's vertical centre lines up with the text's.
/// On active tabs this puts the top of the icon slightly inside the
/// [`TAB_ACTIVE_INDICATOR_HEIGHT_PX_HIDPI`] orange strip's reserved
/// zone; the icon's `AlphaBlend` paints after the strip, so the
/// icon's opaque pixels overwrite the strip in its own ~20-px-wide
/// column while the strip stays fully visible across the rest of
/// the tab width. Keeping icon/text aligned reads better than
/// biasing the icon downward to fully clear the strip. `bitmap_px`
/// is the edge length of the displayed icon (see
/// [`TAB_ICON_DISPLAY_PX`]).
fn tab_save_icon_rect(item_rect: RECT, bitmap_px: i32) -> RECT {
    let cy = i32::midpoint(item_rect.top, item_rect.bottom);
    let half = bitmap_px / 2;
    let left = item_rect.left + TAB_PAD_X_PX;
    RECT {
        left,
        top: cy - half,
        right: left + bitmap_px,
        bottom: cy - half + bitmap_px,
    }
}

/// Hit-test the close-X glyphs of every visible tab. Returns the
/// index of the tab whose close-X rect contains `(x, y)`, or `None`
/// otherwise. Called from `tab_subclass_proc::WM_LBUTTONDOWN` so a
/// click on the X intercepts before drag-detect / activation.
unsafe fn tab_close_x_hit_test(tab_hwnd: HWND, x: i32, y: i32) -> Option<usize> {
    // Walk every tab item ŌĆö tab counts are small (typical session has
    // < 20 open buffers) so a linear scan is faster than the alternative
    // of caching rects on every paint and invalidating them on every
    // move/insert/delete.
    let n = unsafe {
        SendMessageW(
            tab_hwnd,
            windows::Win32::UI::Controls::TCM_GETITEMCOUNT,
            None,
            None,
        )
        .0 as i32
    };
    if n <= 0 {
        return None;
    }
    for i in 0..n {
        let mut rc = RECT::default();
        let ok = unsafe {
            SendMessageW(
                tab_hwnd,
                TCM_GETITEMRECT,
                Some(WPARAM(i as usize)),
                Some(LPARAM(&raw mut rc as isize)),
            )
        };
        if ok.0 == 0 {
            continue;
        }
        let close_rc = tab_close_x_rect(rc);
        if x >= close_rc.left && x < close_rc.right && y >= close_rc.top && y < close_rc.bottom {
            return Some(i as usize);
        }
    }
    None
}

/// Hit-test the pin-toggle glyphs of every visible tab. Returns
/// the index of the tab whose pin rect contains `(x, y)`, or
/// `None` otherwise. Called from `tab_subclass_proc::WM_LBUTTONDOWN`
/// so a click on the pin intercepts before drag-detect / tab
/// activation, and from `WM_MOUSEMOVE` so the hover state
/// [`WindowState::tab_hover_pin`] tracks accurately.
///
/// Structurally identical to [`tab_close_x_hit_test`] ŌĆö same
/// linear scan (tab counts are small), same `TCM_GETITEMRECT`
/// per item, only the rect helper differs. Kept as a separate
/// function rather than parameterising over "which rect" so
/// each hit-test path reads flat at every call site.
unsafe fn tab_pin_hit_test(tab_hwnd: HWND, x: i32, y: i32) -> Option<usize> {
    let n = unsafe {
        SendMessageW(
            tab_hwnd,
            windows::Win32::UI::Controls::TCM_GETITEMCOUNT,
            None,
            None,
        )
        .0 as i32
    };
    if n <= 0 {
        return None;
    }
    for i in 0..n {
        let mut rc = RECT::default();
        let ok = unsafe {
            SendMessageW(
                tab_hwnd,
                TCM_GETITEMRECT,
                Some(WPARAM(i as usize)),
                Some(LPARAM(&raw mut rc as isize)),
            )
        };
        if ok.0 == 0 {
            continue;
        }
        let pin_rc = tab_pin_rect(rc);
        if x >= pin_rc.left && x < pin_rc.right && y >= pin_rc.top && y < pin_rc.bottom {
            return Some(i as usize);
        }
    }
    None
}

/// Owner-draw paint for one tab cell. Called from the parent's
/// `WM_DRAWITEM` handler after dispatching on `dis.CtlType == ODT_TAB`.
///
/// Painting order: background fill ŌåÆ save icon (with `AlphaBlend` if
/// inactive) ŌåÆ tab text ŌåÆ close-X. Each piece is computed from the
/// shared rect helpers above so click hit-testing stays in lockstep.
unsafe fn paint_tab_item(state: &mut WindowState, dis: &DRAWITEMSTRUCT) {
    let idx = dis.itemID as usize;
    let active = matches!(state.shell.active_tab, Some(a) if a == idx);
    let hovered = matches!(state.tab_hover_idx, Some(h) if h == idx);
    // Read the dirty bit off the cached `Tab.dirty` field rather
    // than off Scintilla's live `SCI_GETMODIFY`. Live read only
    // works for whichever tab the editor is currently bound to;
    // for inactive tabs the bound doc is the active tab's, not
    // this one. The cache is kept in sync via SCN_SAVEPOINT*
    // notifications (see the WM_NOTIFY arm in `main_wnd_proc`)
    // and by `handle_tab_selchange` snapshotting the outgoing
    // tab's modify state before the doc-pointer swap.
    //
    // Untitled buffers follow the same rule as titled ones:
    // clean on creation (blue glyph), red the moment the user
    // types. Matches Notepad++'s semantic ŌĆö a fresh `new 1` tab
    // is not "dirty" just because it lacks a path; only user
    // edits count. Aligns Code++ with N++'s tab strip so muscle
    // memory carries across.
    let dirty = idx < state.shell.tabs.len() && state.shell.tabs[idx].dirty;

    // Background fill: pick the right shade for active / inactive
    // (with a subtle bump for inactive-hovered).
    let bg_color = if active {
        TAB_BG_ACTIVE
    } else if hovered {
        TAB_BG_INACTIVE_HOVER
    } else {
        TAB_BG_INACTIVE
    };
    // SAFETY: `dis.hDC` is supplied by Windows for this message and
    // valid for the duration of the WM_DRAWITEM dispatch. The brush
    // we create here is selected for FillRect and immediately
    // deleted; no other thread can observe the GDI objects we're
    // touching since we're on the UI thread. `CreateSolidBrush`
    // returning null under GDI exhaustion is the only failure mode
    // ŌĆö we skip the FillRect in that case (DeleteObject(NULL) is a
    // documented safe no-op, but we still gate to keep the intent
    // explicit). A skipped fill leaves the tab cell with whatever
    // the system painted before WM_DRAWITEM fired; not pretty, but
    // it avoids passing a null HBRUSH to FillRect, which is UB.
    unsafe {
        let bg_brush = CreateSolidBrush(COLORREF(bg_color));
        if !bg_brush.is_invalid() {
            FillRect(dis.hDC, &raw const dis.rcItem, bg_brush);
            let _ = DeleteObject(bg_brush.into());
        }
    }

    // Active-tab indicator: an orange strip along the top edge of
    // the active cell. See `TAB_ACTIVE_INDICATOR_HEIGHT_PX_HIDPI`
    // for the painted-vs-visible-px rationale (the system tab
    // control's themed-outline overdraw eats ~1 px from the top).
    // Painted after the background fill (so the strip sits on top
    // of any system theme paint) and BEFORE the icon: the icon's
    // ~3-px overlap with the strip is intentionally overwritten by
    // the icon's `AlphaBlend` inside the ~20-px icon column so the
    // icon centre stays aligned with the text centre ŌĆö see the
    // paint block below and [`tab_save_icon_rect`]. Inactive tabs
    // get nothing ŌĆö the strip is the visual cue that says "this
    // is the focused buffer".
    if active {
        // `state.tab_bitmap_px` is always `TAB_BITMAP_PX_HIDPI`
        // today ([`pick_tab_bitmap_size`] always returns HIDPI), so
        // the strip height is HIDPI unconditionally. Kept as a
        // direct read of the HIDPI constant rather than a per-DPI
        // branch to match the treatment of the sibling LO assets;
        // a future per-monitor DPI scaler can reintroduce the
        // branch here alongside [`pick_tab_bitmap_size`]'s scaler.
        let strip_h = TAB_ACTIVE_INDICATOR_HEIGHT_PX_HIDPI;
        let strip_rc = RECT {
            left: dis.rcItem.left,
            top: dis.rcItem.top,
            right: dis.rcItem.right,
            bottom: dis.rcItem.top + strip_h,
        };
        // SAFETY: same WM_DRAWITEM lifetime contract as the bg
        // brush above; null-handle guard mirrored from there.
        unsafe {
            let strip_brush = CreateSolidBrush(COLORREF(TAB_ACTIVE_INDICATOR));
            if !strip_brush.is_invalid() {
                FillRect(dis.hDC, &raw const strip_rc, strip_brush);
                let _ = DeleteObject(strip_brush.into());
            }
        }
    }

    // Save icon (left). Pick blue for clean buffers, red for dirty.
    // `AlphaBlend` with `SourceConstantAlpha = 128` dims inactive
    // tabs to ~50% opacity ŌĆö one bitmap per state instead of four.
    let icon_hbm = if dirty {
        state.tab_save_red_hbm
    } else {
        state.tab_save_blue_hbm
    };
    if !icon_hbm.is_invalid() {
        // Display size ([`TAB_ICON_DISPLAY_PX`], 20 px) is decoupled
        // from the source bitmap size (`state.tab_bitmap_px`, 32 px)
        // so the icon fits inside the 30-px cell with 5 px of
        // breathing room top+bottom. The icon overlaps the top of
        // the orange indicator strip on active tabs by ~3 px inside
        // its own ~20-px-wide column; the icon paints AFTER the
        // strip (see the strip block above) so its opaque pixels
        // overwrite that overlap and the strip stays fully visible
        // across the rest of the tab width ŌĆö that alignment reads
        // cleaner than biasing the icon downward would (icon and
        // text centres stay on the same horizontal line).
        // `AlphaBlend` stretches the 32-px source down to the 20-px
        // dest during the blit; no separate resize step required.
        let icon_rc = tab_save_icon_rect(dis.rcItem, TAB_ICON_DISPLAY_PX);
        let icon_w = icon_rc.right - icon_rc.left;
        let icon_h = icon_rc.bottom - icon_rc.top;
        let alpha = if active { 255 } else { TAB_INACTIVE_ICON_ALPHA };
        // SAFETY: CreateCompatibleDC for a hwnd-supplied HDC, and
        // SelectObject the source HBITMAP into it. The mem DC and
        // the HBITMAP we own; the AlphaBlend pixel format requires
        // the source to be a 32bpp DIB section with premultiplied
        // BGRA ŌĆö which is exactly what `toolbar::png_to_hbitmap`
        // produces for our two `tab-save*.png` assets. Mem DC is
        // deleted at the end of the block; the HBITMAP stays alive
        // on `WindowState` for the next paint.
        unsafe {
            let mem_dc = CreateCompatibleDC(Some(dis.hDC));
            if !mem_dc.is_invalid() {
                let prev = SelectObject(mem_dc, HGDIOBJ(icon_hbm.0));
                let blend = BLENDFUNCTION {
                    BlendOp: AC_SRC_OVER as u8,
                    BlendFlags: 0,
                    SourceConstantAlpha: alpha,
                    AlphaFormat: AC_SRC_ALPHA as u8,
                };
                let _ = AlphaBlend(
                    dis.hDC,
                    icon_rc.left,
                    icon_rc.top,
                    icon_w,
                    icon_h,
                    mem_dc,
                    0,
                    0,
                    state.tab_bitmap_px,
                    state.tab_bitmap_px,
                    blend,
                );
                let _ = SelectObject(mem_dc, prev);
                let _ = DeleteDC(mem_dc);
            }
        }
    }

    // Tab text. Reserve a strip between the save icon and the pin
    // for the label; let `DT_END_ELLIPSIS` clip long names with "ŌĆ”".
    // The pin sits between the label and the close-X (see
    // [`tab_pin_rect`]), so the label's right edge is derived from
    // the pin's left edge, not the close-X's ŌĆö the close-X path
    // reads `pin_rect.left - TAB_TEXT_CLOSEX_GAP_PX` transitively.
    if idx < state.shell.tabs.len() {
        let text_left =
            tab_save_icon_rect(dis.rcItem, TAB_ICON_DISPLAY_PX).right + TAB_ICON_TEXT_GAP_PX;
        let text_right = tab_pin_rect(dis.rcItem).left - TAB_TEXT_CLOSEX_GAP_PX;
        if text_right > text_left {
            let mut text_rc = RECT {
                left: text_left,
                top: dis.rcItem.top,
                right: text_right,
                bottom: dis.rcItem.bottom,
            };
            let label = tab_display_name(&state.shell.tabs[idx]);
            let mut wide: Vec<u16> = label.encode_utf16().collect();
            let fg = if active {
                TAB_FG_ACTIVE
            } else {
                TAB_FG_INACTIVE
            };
            // SAFETY: `dis.hDC` is the WM_DRAWITEM-supplied DC; the
            // wide buffer outlives the call (lives in the parent
            // stack frame).
            unsafe {
                SetBkMode(dis.hDC, TRANSPARENT);
                let _ = SetTextColor(dis.hDC, COLORREF(fg));
                DrawTextW(
                    dis.hDC,
                    wide.as_mut_slice(),
                    &raw mut text_rc,
                    DT_VCENTER | DT_SINGLELINE | DT_NOPREFIX | DT_END_ELLIPSIS,
                );
            }
        }
    }

    // Close-X. Visibility rules:
    //   - active tab: always shown.
    //   - inactive tab: shown only while the cursor hovers over the
    //     same tab cell (at which point the box is grey by default
    //     and red when the cursor is specifically over it).
    //
    // Render a filled colour box with a white X drawn over the top ŌĆö
    // a familiar "close" affordance on every modern tab strip.
    // Plain coloured strokes alone (an earlier iteration) read as
    // ambient text rather than as a clickable button.
    let show_x = active || hovered;
    if show_x {
        let on_x = hovered && state.tab_hover_close_x;
        let box_color = if on_x {
            TAB_CLOSEX_BOX_LIGHT
        } else if active {
            TAB_CLOSEX_BOX_DARK
        } else {
            TAB_CLOSEX_BOX_GREY
        };
        let close_rc = tab_close_x_rect(dis.rcItem);
        // Stroke thickness: 2 px. Was per-DPI (1 at 96, 2 at HIDPI)
        // when the tab strip pulled two source-bitmap tiers, but
        // now that [`pick_tab_bitmap_size`] returns HIDPI on every
        // tier the 2-px stroke is what actually ships everywhere;
        // a per-monitor DPI scaler can reintroduce the branch here
        // alongside [`pick_tab_bitmap_size`]'s scaler. Inset by 3
        // px so the X doesn't touch the box edges and reads as a
        // glyph rather than as noise.
        let pen_width = 2;
        let inset = 3;
        // SAFETY: brush + pen are created locally and released at
        // the end of the block. The DC and rect are valid for the
        // duration of the WM_DRAWITEM dispatch; FillRect is the
        // standard idiom for a flat-coloured rectangle. Each
        // `Create*` is gated on `!is_invalid()` ŌĆö `CreateSolidBrush`
        // / `CreatePen` can return null under GDI exhaustion, and
        // passing a null `HBRUSH` to `FillRect` or `HGDIOBJ(null)` to
        // `SelectObject` is documented UB on Win32.
        unsafe {
            let bg_brush = CreateSolidBrush(COLORREF(box_color));
            if !bg_brush.is_invalid() {
                FillRect(dis.hDC, &raw const close_rc, bg_brush);
                let _ = DeleteObject(bg_brush.into());
            }

            let pen = CreatePen(PS_SOLID, pen_width, COLORREF(TAB_CLOSEX_GLYPH));
            if !pen.is_invalid() {
                let prev = SelectObject(dis.hDC, HGDIOBJ(pen.0));
                let mut prev_pt = POINT { x: 0, y: 0 };
                let _ = MoveToEx(
                    dis.hDC,
                    close_rc.left + inset,
                    close_rc.top + inset,
                    Some(&raw mut prev_pt),
                );
                let _ = LineTo(dis.hDC, close_rc.right - inset, close_rc.bottom - inset);
                let _ = MoveToEx(
                    dis.hDC,
                    close_rc.right - inset,
                    close_rc.top + inset,
                    Some(&raw mut prev_pt),
                );
                let _ = LineTo(dis.hDC, close_rc.left + inset, close_rc.bottom - inset);
                let _ = SelectObject(dis.hDC, prev);
                let _ = DeleteObject(HGDIOBJ(pen.0));
            }
        }
    }

    // Pin toggle. Always visible on every tab so users can tell
    // pinned from unpinned at a glance without hovering ŌĆö the pin
    // state is permanent metadata, not a transient affordance.
    // Two shapes, picked from the compile-time polygon tables:
    //   - Pinned:   [`TAB_PIN_POLYGON_PINNED`]  ŌĆö filled blue
    //     thumbtack sitting upright.
    //   - Unpinned: [`TAB_PIN_POLYGON_UNPINNED`] ŌĆö grey outline of
    //     the same thumbtack rotated 45┬░ CCW.
    // Hover state (cursor over the pin's own rect) darkens the
    // colour by ~40 to signal clickability without changing the
    // shape ŌĆö same convention the close-X uses via its BOX_DARK
    // ŌåÆ BOX_LIGHT transition.
    // The 12├Ś12 canvas the tables were designed in is translated
    // into the pin rect at paint time via `pin_rc.left/top`.
    if idx < state.shell.tabs.len() {
        let is_pinned = state.shell.tabs[idx].pinned;
        let on_pin = hovered && state.tab_hover_pin;
        let pin_rc = tab_pin_rect(dis.rcItem);
        let template = if is_pinned {
            TAB_PIN_POLYGON_PINNED
        } else {
            TAB_PIN_POLYGON_UNPINNED
        };
        // Build the translated vertex buffer on the stack. The
        // polygon tables are `Ōēż 12` entries so a small `Vec` here
        // is cheap and keeps the paint code obvious; heap
        // allocation is one tiny alloc/free per tab per paint,
        // negligible compared to the `AlphaBlend` above.
        let points: Vec<POINT> = template
            .iter()
            .map(|(dx, dy)| POINT {
                x: pin_rc.left + dx,
                y: pin_rc.top + dy,
            })
            .collect();
        // SAFETY: `points.as_ptr()` outlives the synchronous
        // `Polygon` call (borrowed from the local `Vec`). GDI
        // objects created here (pen and, for the pinned case, the
        // fill brush) are selected ŌåÆ drawn ŌåÆ deselected ŌåÆ deleted
        // inside the block. `NULL_BRUSH` is a stock object and
        // must NOT be `DeleteObject`'d ŌĆö we hold it only through
        // `SelectObject` and restore the previous brush before
        // returning. Each `Create*` is null-guarded because GDI
        // exhaustion returns null; a null pen/brush passed to
        // `SelectObject` is documented UB. `Polygon` with a
        // `NULL_BRUSH` draws only the outline (no fill) ŌĆö which
        // is exactly the unpinned appearance we want.
        unsafe {
            let base_color = if is_pinned {
                TAB_PIN_FILL_PINNED
            } else {
                TAB_PIN_OUTLINE_UNPINNED
            };
            let pen_color = if on_pin {
                darken_colorref(base_color, 40)
            } else {
                base_color
            };
            let pen = CreatePen(PS_SOLID, 1, COLORREF(pen_color));
            if !pen.is_invalid() {
                let prev_pen = SelectObject(dis.hDC, HGDIOBJ(pen.0));
                // Fill vs outline selection via the brush.
                let brush = if is_pinned {
                    // Fill colour follows the pen so hover state
                    // uses the darkened variant (`pen_color`) ŌĆö
                    // otherwise the outline would darken while
                    // the fill stayed light and the two would
                    // read as mismatched.
                    CreateSolidBrush(COLORREF(pen_color))
                } else {
                    // Stock NULL_BRUSH ŌĆö `HBRUSH` wrapper over
                    // the stock handle. Not deletable.
                    HBRUSH(GetStockObject(NULL_BRUSH).0)
                };
                if !brush.is_invalid() {
                    let prev_brush = SelectObject(dis.hDC, HGDIOBJ(brush.0));
                    let _ = Polygon(dis.hDC, &points);
                    let _ = SelectObject(dis.hDC, prev_brush);
                    if is_pinned {
                        // Only the pinned path owns the brush;
                        // NULL_BRUSH belongs to GDI's stock table.
                        let _ = DeleteObject(brush.into());
                    }
                }
                let _ = SelectObject(dis.hDC, prev_pen);
                let _ = DeleteObject(HGDIOBJ(pen.0));
            }
        }
    }
}

/// Re-run the tab-strip hit-tests against the current cursor
/// position and update `WindowState::tab_hover_*` fields
/// accordingly, then invalidate the affected cells.
///
/// Called from the pin-commit path after `force_tab_strip_resync`
/// reorders the tab strip: the cursor hasn't moved, but a
/// different logical tab now sits under it. Without this refresh
/// the stale `tab_hover_idx` would drive the next `WM_DRAWITEM`
/// to render hover-darkened glyphs on whichever tab landed at
/// the old index, until the user's next `WM_MOUSEMOVE` corrected
/// the tracker naturally.
///
/// `GetCursorPos` returns screen coords; `ScreenToClient(tab_hwnd)`
/// converts to the same coordinate space the hit-tests expect.
/// A failure in either call leaves the state unchanged ŌĆö a
/// stale-glyph frame is a better failure mode than an
/// inconsistent update.
unsafe fn refresh_tab_hover_from_cursor(state: &mut WindowState, tab_hwnd: HWND) {
    let mut pt = POINT::default();
    // SAFETY: `pt` is a stack binding alive across both
    // synchronous calls; neither retains the pointer.
    let ok = unsafe { GetCursorPos(&raw mut pt).is_ok() };
    if !ok {
        return;
    }
    let converted = unsafe { ScreenToClient(tab_hwnd, &raw mut pt).as_bool() };
    if !converted {
        return;
    }
    let hit = unsafe { tab_hit_test(tab_hwnd, pt.x, pt.y) };
    let close_hit = unsafe { tab_close_x_hit_test(tab_hwnd, pt.x, pt.y).is_some() };
    let pin_hit = unsafe { tab_pin_hit_test(tab_hwnd, pt.x, pt.y).is_some() };
    let prev_idx = state.tab_hover_idx;
    let prev_on_x = state.tab_hover_close_x;
    let prev_on_pin = state.tab_hover_pin;
    state.tab_hover_idx = hit;
    state.tab_hover_close_x = close_hit;
    state.tab_hover_pin = pin_hit;
    if prev_idx != hit || prev_on_x != close_hit || prev_on_pin != pin_hit {
        if let Some(prev) = prev_idx {
            unsafe { invalidate_tab(tab_hwnd, prev) };
        }
        if let Some(now) = hit {
            unsafe { invalidate_tab(tab_hwnd, now) };
        }
    }
}

/// Invalidate one tab cell so the next `WM_PAINT` cycle re-fires
/// `WM_DRAWITEM` for it. Called from hover-state transitions and from
/// the dirty-bit hook so the icon/X repaints don't wait for an
/// incidental refresh.
unsafe fn invalidate_tab(tab_hwnd: HWND, idx: usize) {
    let mut rc = RECT::default();
    // SAFETY: `tab_hwnd` is our owned tab control HWND on this thread;
    // `rc` is a stack binding alive across the synchronous SendMessage.
    let ok = unsafe {
        SendMessageW(
            tab_hwnd,
            TCM_GETITEMRECT,
            Some(WPARAM(idx)),
            Some(LPARAM(&raw mut rc as isize)),
        )
    };
    if ok.0 != 0 {
        // SAFETY: rc was filled by TCM_GETITEMRECT; tab_hwnd is live.
        let _ = unsafe { InvalidateRect(Some(tab_hwnd), Some(&raw const rc), false) };
    }
}

/// Hit-test the tab control: return the index of the tab at client
/// coords `(x, y)`, or `None` if the cursor isn't over a tab cell.
/// `TCM_HITTEST`'s `TCHT_NOWHERE` flag covers the gap between the
/// last tab and the right edge ŌĆö we don't need to inspect the flags
/// since a returned `idx == -1` already means "miss".
unsafe fn tab_hit_test(tab_hwnd: HWND, x: i32, y: i32) -> Option<usize> {
    let mut info = TCHITTESTINFO {
        pt: POINT { x, y },
        ..Default::default()
    };
    // SAFETY: `info` is a stack binding that lives across the
    // synchronous `SendMessageW`; the raw pointer is valid for
    // the duration of the call. Inner `unsafe { }` block is
    // mandated by the project's `unsafe-op-in-unsafe-fn` lint
    // (see DEVELOPMENT.md / CLAUDE.md gate).
    let result = unsafe {
        SendMessageW(
            tab_hwnd,
            TCM_HITTEST,
            None,
            Some(LPARAM(&raw mut info as isize)),
        )
    };
    let idx = result.0 as i32;
    if idx >= 0 {
        Some(idx as usize)
    } else {
        None
    }
}

extern "system" fn main_wnd_proc(hwnd: HWND, msg: u32, wparam: WPARAM, lparam: LPARAM) -> LRESULT {
    unsafe {
        match msg {
            WM_NCCREATE => {
                // GWLP_USERDATA is set by run() AFTER CreateWindowExW
                // returns, since the state needs the HWND. So there's
                // no CREATESTRUCT.lpCreateParams to harvest here.
                // Fall through to default processing.
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_APP_WAKE => {
                // Drain the shell's task queues. Drain returns any
                // pending modal dialogs; we MUST show them only AFTER
                // the &mut WindowState borrow is dropped, otherwise
                // MessageBoxW's nested message pump can re-enter
                // wnd_proc and produce aliasing UB.
                let pending: Vec<PendingDialog> = {
                    if let Some(state) = state_from_hwnd(hwnd) {
                        let (shell, mut ui) = state.split();
                        shell.drain(&mut ui)
                    } else {
                        Vec::new()
                    }
                };
                // No state borrow held below this point.
                for dialog in pending {
                    match dialog {
                        PendingDialog::ConfirmReload(path) => {
                            let yes = show_reload_dialog(hwnd, &path);
                            if yes {
                                if let Some(state) = state_from_hwnd(hwnd) {
                                    state.shell.confirm_reload(path);
                                }
                            }
                        }
                        PendingDialog::Error { title, message } => {
                            show_error_dialog(hwnd, &title, &message);
                        }
                    }
                }
                // Fire any NPPN_* notifications queued by the drain
                // (NPPN_FILEOPENED on a successful load). Done AFTER
                // dialogs so a plugin that might block in beNotified
                // doesn't delay the user-visible reload prompt.
                fire_queued_notifications(hwnd);
                // Bring the tab strip into sync after any new tabs
                // were pushed during the drain. Done after the
                // dialog/notification cycle so the user sees the
                // new tab appear at the same moment they get the
                // open's "load complete" feedback. The window
                // title is refreshed alongside so the title bar
                // reflects whichever tab the drain just activated.
                if let Some(state) = state_from_hwnd(hwnd) {
                    sync_tab_strip(state);
                    update_window_title(hwnd, &state.shell);
                    // Repaint every cell so any `Tab.dirty` flips
                    // that happened during drain (e.g. Shell
                    // marking a tab dirty from `FileChange::Removed`)
                    // recolour the save icon on the visible strip.
                    // `sync_tab_strip` only triggers cell paints via
                    // `TCM_INSERTITEMW` / `TCM_SETITEMW` when the
                    // label changes; a dirty-only change touches no
                    // label and would otherwise stay hidden until an
                    // unrelated repaint. Whole-strip invalidation is
                    // cheap (~one paint per tab per drain).
                    let _ = InvalidateRect(Some(state.tab_hwnd), None, false);
                }
                // Defense in depth for the "always at least one tab"
                // invariant: a load failure on a fresh tab removes
                // the tab in `apply_load_result`, which can leave the
                // workspace empty. Pop a fallback untitled buffer so
                // the user lands on something typable instead of an
                // empty editor chrome.
                ensure_one_tab(hwnd);
                // Drain any FIF events the orchestrator delivered
                // since last wake. Must happen AFTER the load /
                // change drains above so a click on a FIF result
                // that opens a file in a new tab ŌĆö see step 4b's
                // NM_DBLCLK handler ŌĆö doesn't race a still-loading
                // tab from this same wake.
                drain_fif_events(hwnd);
                // Apply any caret jumps queued by FIF dblclk now
                // that the just-completed loads have populated
                // their target tabs. Done after `drain_fif_events`
                // so a search-completion that reveals the dock
                // doesn't compete with a same-wake jump.
                apply_pending_fif_jumps(hwnd);
                LRESULT(0)
            }
            // UDL editor saved a UDL ŌĆö re-scan the registry from
            // disk so the newly-saved (or updated) UDL becomes
            // selectable from the Language menu without a
            // restart. Same-thread PostMessage from the editor's
            // Save handler, so no aliasing concern.
            udl_editor::WM_APP_UDL_REFRESH => {
                refresh_udl_registry(hwnd);
                LRESULT(0)
            }
            // UDL editor dialog was destroyed. Clear the tracking
            // slot so the reuse fast-path doesn't try to
            // re-activate a dead HWND.
            udl_editor::WM_APP_UDL_CLOSED => {
                if let Some(state) = state_from_hwnd(hwnd) {
                    let closed = HWND(lparam.0 as *mut c_void);
                    if state.udl_editor_dlg == Some(closed) {
                        state.udl_editor_dlg = None;
                    }
                }
                LRESULT(0)
            }
            WM_DROPFILES => {
                let mut deduped = false;
                if let Some(state) = state_from_hwnd(hwnd) {
                    let hdrop = HDROP(wparam.0 as *mut c_void);
                    deduped = handle_dropped_files(state, hdrop);
                    DragFinish(hdrop);
                }
                // If the last drop targeted an already-open file
                // (e.g. dragging the same file twice), the shell
                // flipped `active_tab` without kicking off a load
                // ŌĆö see the ID_FILE_OPEN dedupe comment. Fire the
                // selchange manually so the editor swaps to the
                // just-activated buffer's Scintilla doc.
                if deduped {
                    refresh_tab_chrome(hwnd);
                    handle_tab_selchange(hwnd);
                }
                LRESULT(0)
            }
            WM_COMMAND => {
                let cmd_u16 = (wparam.0 & 0xFFFF) as u16;
                let cmd_i32 = i32::from(cmd_u16);
                match cmd_u16 {
                    ID_FILE_SAVE => {
                        // Save inside the borrow; if it fails, capture
                        // the error message and show the dialog AFTER
                        // the borrow is dropped (same UB rule as
                        // WM_APP_WAKE).
                        //
                        // The save call is wrapped in catch_unwind so
                        // a host-internal panic ŌĆö e.g. a `Vec::push`
                        // OOM in the notification queue, or a
                        // tracing-subscriber misbehaviour ŌĆö doesn't
                        // unwind across the `extern "system"`
                        // wnd_proc frame (UB at the FFI boundary).
                        // Three save outcomes:
                        //   * Ok ŌĆö written; nothing to surface.
                        //   * Err(NoActivePath) ŌĆö the active tab is
                        //     untitled. Redirect to Save As so
                        //     Ctrl+S on an untitled buffer DTRTs
                        //     instead of throwing a confusing
                        //     "no active file path" error.
                        //   * Other Err ŌĆö surface in the error
                        //     dialog (read-only file, permission
                        //     issue, encoding failure, etc.).
                        enum SaveOutcome {
                            Ok,
                            RedirectSaveAs,
                            Failed(String),
                        }
                        let outcome = if let Some(state) = state_from_hwnd(hwnd) {
                            let (shell, mut ui) = state.split();
                            let result =
                                std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                                    shell.save_current_to_disk(&mut ui)
                                }));
                            match result {
                                Ok(Ok(())) => SaveOutcome::Ok,
                                Ok(Err(codepp_shell::ShellError::NoActivePath)) => {
                                    SaveOutcome::RedirectSaveAs
                                }
                                Ok(Err(e)) => SaveOutcome::Failed(e.to_string()),
                                Err(_) => {
                                    SaveOutcome::Failed("internal panic during save".to_string())
                                }
                            }
                        } else {
                            SaveOutcome::Ok
                        };
                        match outcome {
                            SaveOutcome::Ok => {}
                            SaveOutcome::RedirectSaveAs => run_save_as_flow(hwnd),
                            SaveOutcome::Failed(msg) => {
                                show_error_dialog(hwnd, "Save failed", &msg);
                            }
                        }
                        // On a successful save, save_current_to_disk
                        // queues NPPN_FILESAVED and clears the dirty
                        // glyph via `UiPlatform::mark_saved`; on
                        // failure both are no-ops.
                        fire_queued_notifications(hwnd);
                    }
                    ID_FILE_NEW => {
                        // FileŌåÆNew: synchronous untitled-buffer
                        // creation. No I/O, so no need to defer
                        // until after the borrow drops; the
                        // BUFFERACTIVATED notification queues and
                        // gets fired below.
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let (shell, mut ui) = state.split();
                            let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                                shell.new_untitled(&mut ui);
                            }));
                        }
                        // The new tab won't appear on the strip
                        // without an explicit sync ŌĆö `new_untitled`
                        // is synchronous, doesn't go through the
                        // loader, so no WM_APP_WAKE is queued.
                        refresh_tab_chrome(hwnd);
                        fire_queued_notifications(hwnd);
                    }
                    ID_FILE_OPEN => {
                        // Show the OS dialog *outside* the &mut state
                        // borrow ŌĆö it spins its own message loop that
                        // can re-enter our wnd_proc, and any active
                        // borrow at that point would alias-UB.
                        //
                        // Multi-select: `prompt_open_paths` returns
                        // every file the user picked. Empty Vec on
                        // Cancel. Each path funnels through
                        // `Shell::open_file` in the same shape the
                        // single-path handler used ŌĆö the shell
                        // dedupes already-open paths and pushes fresh
                        // tabs for the rest. `deduped` tracks whether
                        // ANY of the opens landed on an existing tab
                        // so the final `handle_tab_selchange` fires
                        // once at the end and rebinds the view to
                        // whichever tab ended up active.
                        let paths = prompt_open_paths(hwnd);
                        let mut deduped = false;
                        for p in paths {
                            let outcome = if let Some(state) = state_from_hwnd(hwnd) {
                                std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                                    state.shell.open_file(p)
                                }))
                                .unwrap_or(OpenFileOutcome::Rejected)
                            } else {
                                OpenFileOutcome::Rejected
                            };
                            if matches!(outcome, OpenFileOutcome::SwitchedToExisting(_)) {
                                deduped = true;
                            }
                        }
                        // If `open_file` switched to an existing tab
                        // (the de-dupe branch) there's no async load
                        // to wake on, so the tab strip's TCM_SETCURSEL
                        // won't update without an explicit refresh.
                        // Idempotent in the load-actually-kicked-off
                        // case (the WM_APP_WAKE drain runs sync_tab_strip
                        // again when the load completes).
                        refresh_tab_chrome(hwnd);
                        // Dedupe branch: the shell flipped
                        // `active_tab` but no load will wake to
                        // run `handle_tab_selchange` ŌĆö and
                        // `sync_tab_strip`'s `TCM_SETCURSEL`
                        // doesn't generate `TCN_SELCHANGE`, so the
                        // view stays bound to the previous buffer's
                        // Scintilla document. Fire the selchange
                        // handler manually so the editor swaps to
                        // the just-activated tab's doc pointer.
                        if deduped {
                            handle_tab_selchange(hwnd);
                        }
                        fire_queued_notifications(hwnd);
                    }
                    ID_FILE_SAVE_SESSION => {
                        handle_save_session(hwnd);
                    }
                    ID_FILE_LOAD_SESSION => {
                        handle_load_session(hwnd);
                    }
                    ID_FILE_PRINT => {
                        handle_print(hwnd);
                    }
                    ID_FILE_PRINT_PREVIEW => {
                        handle_print_preview(hwnd);
                    }
                    ID_FILE_OPEN_IN_DEFAULT_VIEWER => {
                        // Snapshot the active tab's path under a brief
                        // borrow, then drop it before `ShellExecuteW`:
                        // the shelled-out process is asynchronous but
                        // the call itself can enter modal dialogs
                        // (UAC prompt, association picker) whose
                        // pump would re-enter our wnd_proc.
                        //
                        // The menu item is greyed by
                        // `refresh_file_menu` for untitled buffers /
                        // unregistered extensions, so a click always
                        // reaches this arm with a path that is
                        // eligible on the machine ŌĆö the `path.is_some()`
                        // guard is UX-only (not a security boundary):
                        // it protects against a plugin-driven
                        // `NPPM_MENUCOMMAND` firing the id
                        // independently of menu greying and hitting
                        // `open_path_in_default_viewer` with a
                        // no-path tab, which would silently no-op
                        // and pop nothing at all. Plugins already
                        // run in-process with full authority
                        // (DESIGN.md ┬¦6.5), so they could call
                        // `ShellExecuteW` directly on any path
                        // regardless ŌĆö the gate isn't a
                        // capability restriction.
                        let path: Option<PathBuf> = state_from_hwnd(hwnd)
                            .and_then(|state| state.shell.active().and_then(|t| t.path.clone()));
                        if let Some(p) = path {
                            open_path_in_default_viewer(hwnd, &p);
                        }
                    }
                    ID_FILE_OPEN_FOLDER_AS_WORKSPACE => {
                        // Pop the folder picker on a fresh borrow
                        // (the picker spins its own message pump),
                        // then hand the chosen path to the panel
                        // show flow. Cancel is a silent no-op.
                        open_workspace_folder_flow(hwnd);
                    }
                    // File ŌåÆ Open Containing Folder submenu. Each
                    // arm resolves the active tab's parent
                    // directory via [`active_parent_dir`] ŌĆö a
                    // shared helper that centralises the borrow
                    // + dropdown pattern (`state_from_hwnd` ŌåÆ
                    // `active().path.parent()` ŌåÆ `PathBuf`) and
                    // documents the "greying is UX-only, not a
                    // capability gate" contract so a future
                    // reader doesn't strip the `Option` guard as
                    // redundant. Entries are greyed by
                    // `refresh_file_menu` when the tab is
                    // untitled or its path has no parent; the
                    // `Option` guard here is what makes a
                    // plugin-forged `WM_COMMAND` bypass a silent
                    // no-op rather than a panic.
                    ID_FILE_OPEN_CONTAINING_EXPLORER => {
                        // Prefer `/select,` so Explorer highlights
                        // the active file and scrolls it into view
                        // rather than just opening at the parent
                        // folder ŌĆö matches "Show in Folder" UX
                        // across the ecosystem (Notepad++, VS
                        // Code, browsers). Gated on the same
                        // parent-exists predicate as
                        // `active_parent_dir` (Explorer's `/select`
                        // needs a real parent to open at, which
                        // rules out drive-root paths); we resolve
                        // the file path itself here rather than
                        // reusing `active_parent_dir` so `/select`
                        // has the addressable child to highlight.
                        let file = state_from_hwnd(hwnd).and_then(|state| {
                            state
                                .shell
                                .active()
                                .and_then(|t| t.path.as_deref())
                                .filter(|p| p.parent().is_some())
                                .map(Path::to_path_buf)
                        });
                        if let Some(f) = file {
                            open_explorer_selecting(hwnd, &f);
                        }
                    }
                    ID_FILE_OPEN_CONTAINING_CMD => {
                        if let Some(d) = active_parent_dir(hwnd) {
                            shell_launch_in_dir(hwnd, w!("cmd.exe"), &d);
                        }
                    }
                    ID_FILE_OPEN_CONTAINING_POWERSHELL => {
                        if let Some(d) = active_parent_dir(hwnd) {
                            shell_launch_in_dir(hwnd, w!("powershell.exe"), &d);
                        }
                    }
                    ID_FILE_OPEN_CONTAINING_WORKSPACE => {
                        // "Folder as Workspace" on the parent dir.
                        // Reuses the same `show_workspace_panel`
                        // entry point the folder picker uses ŌĆö
                        // idempotent on the visibility flag, and
                        // re-roots in place if the panel is
                        // already open at a different folder.
                        // Matches the "open folder as workspace"
                        // menu entry's UX (no picker step needed
                        // because we already know the folder).
                        if let Some(d) = active_parent_dir(hwnd) {
                            show_workspace_panel(hwnd, d);
                        }
                    }
                    ID_VIEW_FOLDER_AS_WORKSPACE => {
                        // Three-branch toggle:
                        //   * visible ŌåÆ hide
                        //   * hidden + root set ŌåÆ show at stored root
                        //   * hidden + no root ŌåÆ route to picker flow
                        // See [`toggle_workspace_panel`] for the full
                        // decision matrix. Matches N++'s View-menu
                        // toggle for the same feature.
                        toggle_workspace_panel(hwnd);
                    }
                    ID_VIEW_DOCMAP => {
                        // Simple two-branch toggle (no picker step ŌĆö
                        // the docmap always mirrors the active
                        // buffer). [`toggle_docmap_panel`] handles
                        // the layout re-run + toolbar-check sync.
                        toggle_docmap_panel(hwnd);
                    }
                    IDC_WORKSPACE_UNFOLD => {
                        // Workspace panel: start the async
                        // "Unfold All" walk. See
                        // [`start_workspace_unfold_all`] and
                        // [`tick_workspace_unfold`] ŌĆö the walk runs
                        // one folder per `WM_TIMER` tick so the UI
                        // stays responsive on large workspaces. A
                        // second click while a walk is already in
                        // progress is a no-op.
                        start_workspace_unfold_all(hwnd);
                    }
                    IDC_WORKSPACE_FOLD => {
                        // Workspace panel: collapse every folder in
                        // the tree. Purely a UI operation ŌĆö no I/O.
                        // Cancel any in-flight unfold walk first so
                        // its ticks don't fight our collapse.
                        cancel_workspace_unfold(hwnd);
                        let tree = state_from_hwnd(hwnd).map(|s| s.workspace_tree_hwnd);
                        if let Some(t) = tree {
                            tree_fold_all(t);
                        }
                    }
                    IDC_WORKSPACE_LOCATE => {
                        // Workspace panel: reveal the active tab's
                        // file in the tree by walking down from the
                        // root one path component at a time,
                        // expanding each ancestor (triggers lazy
                        // populate), then selecting the leaf. No-op
                        // if there's no active tab, no workspace
                        // root, or the file isn't under the root.
                        locate_current_file_in_workspace(hwnd);
                    }
                    // Workspace tree right-click context menu arms.
                    // The stashed target on `WindowState.workspace_ctx_target`
                    // was populated by `show_workspace_tree_context_menu`
                    // just before `TrackPopupMenu`; every arm takes it out
                    // (drops the stash) and then acts. If the take
                    // returns `None` ŌĆö e.g. a keyboard-triggered
                    // WM_COMMAND on one of these ids that skipped the
                    // right-click flow ŌĆö the arm is a silent no-op
                    // (these ids have no menu bar entry, so the only
                    // reachable path is the context menu).
                    ID_WORKSPACE_CTX_REMOVE => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            if target.kind == WorkspaceCtxKind::Root {
                                remove_workspace_root(hwnd);
                            }
                        }
                    }
                    ID_WORKSPACE_CTX_COPY_PATH => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            let text = target.path.to_string_lossy().into_owned();
                            copy_text_to_clipboard(hwnd, &text);
                        }
                    }
                    ID_WORKSPACE_CTX_COPY_FILE_NAME => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            let name = target
                                .path
                                .file_name()
                                .map(|s| s.to_string_lossy().into_owned())
                                .unwrap_or_default();
                            if !name.is_empty() {
                                copy_text_to_clipboard(hwnd, &name);
                            }
                        }
                    }
                    ID_WORKSPACE_CTX_FIND_IN_FILES => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            // For folders/root, use the target path as
                            // the FIF directory. For a file ŌĆö not
                            // reachable today (the file-kind menu has
                            // no "Find in Files" entry), but if a
                            // future menu adds it, use the parent.
                            let dir = match target.kind {
                                WorkspaceCtxKind::File => {
                                    target.path.parent().map(Path::to_path_buf)
                                }
                                _ => Some(target.path.clone()),
                            };
                            if let Some(d) = dir {
                                open_fif_at_directory(hwnd, &d);
                            }
                        }
                    }
                    ID_WORKSPACE_CTX_OPEN_FILE => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            if target.kind == WorkspaceCtxKind::File {
                                if let Some(state) = state_from_hwnd(hwnd) {
                                    let _ = state.shell.open_file(target.path);
                                }
                                fire_queued_notifications(hwnd);
                                refresh_tab_chrome(hwnd);
                            }
                        }
                    }
                    ID_WORKSPACE_CTX_RUN_BY_SYSTEM => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            if target.kind == WorkspaceCtxKind::File {
                                open_path_in_default_viewer(hwnd, &target.path);
                            }
                        }
                    }
                    ID_WORKSPACE_CTX_EXPLORER => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            // File ŌåÆ open at parent WITH the file
                            //   highlighted (Explorer's
                            //   `/select,"..."` ŌĆö same UX as
                            //   Windows Explorer's own
                            //   Shift-right-click ŌåÆ "Open file
                            //   location", VS Code's "Reveal in
                            //   File Explorer", etc.).
                            // Folder / root ŌåÆ open at that folder
                            //   itself (no file to select).
                            match target.kind {
                                WorkspaceCtxKind::File => {
                                    open_explorer_selecting(hwnd, &target.path);
                                }
                                _ => {
                                    open_explorer_at(hwnd, &target.path);
                                }
                            }
                        }
                    }
                    ID_WORKSPACE_CTX_CMD => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            let workdir = match target.kind {
                                WorkspaceCtxKind::File => {
                                    target.path.parent().map(Path::to_path_buf)
                                }
                                _ => Some(target.path.clone()),
                            };
                            if let Some(d) = workdir {
                                shell_launch_in_dir(hwnd, w!("cmd.exe"), &d);
                            }
                        }
                    }
                    ID_WORKSPACE_CTX_POWERSHELL => {
                        let taken =
                            state_from_hwnd(hwnd).and_then(|s| s.workspace_ctx_target.take());
                        if let Some(target) = taken {
                            let workdir = match target.kind {
                                WorkspaceCtxKind::File => {
                                    target.path.parent().map(Path::to_path_buf)
                                }
                                _ => Some(target.path.clone()),
                            };
                            if let Some(d) = workdir {
                                shell_launch_in_dir(hwnd, w!("powershell.exe"), &d);
                            }
                        }
                    }
                    ID_FILE_SAVE_AS => {
                        run_save_as_flow(hwnd);
                        // save_buffer_as clears the dirty glyph via
                        // UiPlatform::mark_saved on success and
                        // run_save_as_flow refreshes the tab strip.
                        fire_queued_notifications(hwnd);
                    }
                    ID_FILE_RENAME => {
                        // Two-branch behaviour:
                        //   - untitled buffer (no path): show the
                        //     modal Rename dialog and update
                        //     `Tab.custom_name` on confirm.
                        //   - path-bound buffer: route to Save-As,
                        //     letting the user pick a new on-disk
                        //     location (matches Notepad++'s
                        //     FileŌåÆRename semantics for saved files).
                        //
                        // The dialog opens its own message pump,
                        // so any `&mut WindowState` borrow MUST be
                        // dropped before `show_rename_dialog` is
                        // called ŌĆö re-entrant `state_from_hwnd`
                        // during the dialog would alias. We also
                        // capture the buffer id (not just the
                        // index) so the post-dialog write hits the
                        // right tab even if a `WM_APP_WAKE` mid-
                        // pump shifted the tabs vector underneath
                        // us ŌĆö buffer ids are stable across closes
                        // and reorders (assigned once at creation,
                        // never reused within a session).
                        enum RenameAction {
                            None,
                            ShowDialog {
                                current_name: String,
                                buffer_id: i32,
                            },
                            RouteToSaveAs,
                        }
                        let action = if let Some(state) = state_from_hwnd(hwnd) {
                            match state.shell.active_tab {
                                Some(idx) if idx < state.shell.tabs.len() => {
                                    let tab = &state.shell.tabs[idx];
                                    if tab.path.is_some() {
                                        RenameAction::RouteToSaveAs
                                    } else {
                                        RenameAction::ShowDialog {
                                            current_name: tab_display_name(tab),
                                            buffer_id: tab.id,
                                        }
                                    }
                                }
                                _ => RenameAction::None,
                            }
                        } else {
                            RenameAction::None
                        };
                        match action {
                            RenameAction::None => {}
                            RenameAction::RouteToSaveAs => {
                                run_save_as_flow(hwnd);
                                fire_queued_notifications(hwnd);
                            }
                            RenameAction::ShowDialog {
                                current_name,
                                buffer_id,
                            } => {
                                if let Some(new_name) = show_rename_dialog(hwnd, &current_name) {
                                    if let Some(state) = state_from_hwnd(hwnd) {
                                        if let Some(tab) =
                                            state.shell.tabs.iter_mut().find(|t| t.id == buffer_id)
                                        {
                                            tab.custom_name = Some(new_name);
                                        }
                                    }
                                    refresh_tab_chrome(hwnd);
                                    if let Some(state) = state_from_hwnd(hwnd) {
                                        update_window_title(hwnd, &state.shell);
                                    }
                                }
                            }
                        }
                    }
                    ID_FILE_SAVE_ALL => {
                        // Iterate every titled tab, save each, then
                        // restore the original active. Errors are
                        // collected per-tab; if any fired, surface
                        // a summary in a single error dialog after
                        // the borrow ends.
                        let errors: Vec<(i32, codepp_shell::ShellError)> =
                            if let Some(state) = state_from_hwnd(hwnd) {
                                let (shell, mut ui) = state.split();
                                let result =
                                    std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                                        shell.save_all(&mut ui)
                                    }));
                                // Each successful per-tab save already
                                // cleared its dirty glyph via
                                // `UiPlatform::mark_saved` inside
                                // `save_current_to_disk` ŌĆö no batch-
                                // level save-point fold needed (and
                                // the old one was wrong: it left
                                // successfully-saved tabs dirty
                                // whenever any sibling failed). On
                                // a wholesale catch_unwind catch we
                                // just report no errors and let the
                                // higher-level panic handler log it.
                                result.unwrap_or_default()
                            } else {
                                Vec::new()
                            };
                        if !errors.is_empty() {
                            let summary = errors
                                .iter()
                                .map(|(id, e)| format!("buffer {id}: {e}"))
                                .collect::<Vec<_>>()
                                .join("\n");
                            show_error_dialog(hwnd, "Save All ŌĆö some files failed", &summary);
                        }
                        // Save All flips the active tab during the
                        // loop and restores it; the tab strip
                        // selection needs to follow.
                        refresh_tab_chrome(hwnd);
                        fire_queued_notifications(hwnd);
                    }
                    ID_FILE_CLOSE_ALL => {
                        // Loop the single-tab close path until no
                        // tabs remain ŌĆö each iteration does one
                        // shell-side close + UI rebind /
                        // SCI_RELEASEDOCUMENT, exactly as a
                        // user-driven Ctrl+W does. The single-tab
                        // path now includes the
                        // Save/Don't Save/Cancel modal for dirty
                        // buffers, so Close All naturally inherits
                        // per-tab prompting: dirty tabs get the
                        // dialog, clean ones close silently.
                        //
                        // Two important details vs. the previous
                        // close-all-and-discard implementation:
                        //
                        //   1. The loop honours the
                        //      `CloseOutcome::Aborted` signal ŌĆö a
                        //      User-Cancel (or a Save / Save-As
                        //      failure with the error already
                        //      shown) breaks the loop instead of
                        //      re-prompting the same tab on the
                        //      next iteration. Tabs that have
                        //      already been closed in earlier
                        //      iterations stay closed; the user
                        //      committed to those decisions.
                        //
                        //   2. `ensure_one_tab` only runs if the
                        //      loop actually emptied the
                        //      workspace. If the user aborted
                        //      partway through, we leave the
                        //      remaining tabs alone ŌĆö pushing a
                        //      fresh "new 1" placeholder when
                        //      tabs already exist would be
                        //      surprising.
                        //
                        // The loop bound is `tabs.len()` rather
                        // than `while !is_empty()` so a
                        // misbehaving close path that fails to
                        // remove a tab can't spin forever ŌĆö
                        // surface as a stuck tab, not a hang.
                        let initial = if let Some(state) = state_from_hwnd(hwnd) {
                            state.shell.tabs.len()
                        } else {
                            0
                        };
                        let mut ran_to_completion = true;
                        for _ in 0..initial {
                            let still_open =
                                state_from_hwnd(hwnd).is_some_and(|s| !s.shell.tabs.is_empty());
                            if !still_open {
                                break;
                            }
                            match handle_close_active_tab_with_outcome(hwnd) {
                                CloseOutcome::Closed => {}
                                CloseOutcome::NothingToClose => {
                                    // The `still_open` guard
                                    // above already filters the
                                    // empty-workspace case, so
                                    // hitting `NothingToClose`
                                    // mid-loop means
                                    // `state_from_hwnd` returned
                                    // `None` ŌĆö a re-entrant
                                    // plugin call is on the
                                    // stack and we can't safely
                                    // mutate state. Tabs remain;
                                    // suppress `ensure_one_tab`
                                    // so we don't push a
                                    // placeholder onto a
                                    // non-empty strip.
                                    ran_to_completion = false;
                                    break;
                                }
                                CloseOutcome::Aborted => {
                                    ran_to_completion = false;
                                    break;
                                }
                            }
                        }
                        if ran_to_completion {
                            // Workspace is empty ŌĆö restore the
                            // "always at least one tab" invariant
                            // with a fresh untitled buffer so the
                            // user sees a visible tab to type into
                            // instead of an empty editor chrome.
                            ensure_one_tab(hwnd);
                        }
                        fire_queued_notifications(hwnd);
                    }
                    // File ŌåÆ Close Multiple Documents submenu. All
                    // five arms funnel through `close_multiple_documents`
                    // which handles the loop, the mid-loop
                    // activation-then-close dance, the abort
                    // short-circuits, and the `ensure_one_tab` +
                    // notification drain at the end. Per-entry
                    // greying by `refresh_file_menu` means a
                    // normal click never reaches an arm with no
                    // targets (baseline_multi = `tabs.len() >= 2`
                    // plus the variant's own precondition); a
                    // plugin-forged WM_COMMAND that skips the
                    // greying reaches a helper that's already
                    // a no-op when `pick_next_close_target`
                    // returns None on the first iteration.
                    ID_FILE_CLOSE_ALL_BUT_ACTIVE => {
                        close_multiple_documents(hwnd, CloseMultiKind::AllButActive);
                    }
                    ID_FILE_CLOSE_ALL_BUT_PINNED => {
                        close_multiple_documents(hwnd, CloseMultiKind::AllButPinned);
                    }
                    ID_FILE_CLOSE_ALL_TO_LEFT => {
                        close_multiple_documents(hwnd, CloseMultiKind::AllToLeft);
                    }
                    ID_FILE_CLOSE_ALL_TO_RIGHT => {
                        close_multiple_documents(hwnd, CloseMultiKind::AllToRight);
                    }
                    ID_FILE_CLOSE_ALL_UNCHANGED => {
                        close_multiple_documents(hwnd, CloseMultiKind::AllUnchanged);
                    }
                    ID_FILE_MOVE_TO_RECYCLE_BIN => {
                        // Flow:
                        //   1. Snapshot the active tab's path (drop
                        //      the borrow immediately ŌĆö the confirm
                        //      dialog spins its own message pump).
                        //   2. Show OK / Cancel with the exact
                        //      path in the body. Cancel ŌåÆ done.
                        //   3. Force the buffer's savepoint so the
                        //      close path skips the "Save changes?"
                        //      modal. Deleting a file is an "I'm
                        //      done" action; prompting to save
                        //      first is nonsensical here.
                        //   4. Close the active tab via the normal
                        //      path (Scintilla doc release +
                        //      rebind + tab strip resync). If
                        //      close is aborted for any other
                        //      reason (re-entrant plugin call,
                        //      panic caught by the outcome
                        //      wrapper), skip the deletion.
                        //   5. Move the file to the Recycle Bin.
                        //      Log an error dialog on
                        //      SHFileOperationW failure ŌĆö the
                        //      buffer is already gone at this
                        //      point so we can't undo the close,
                        //      but the file is still on disk.
                        //
                        // The menu entry is greyed for untitled
                        // buffers by `refresh_file_menu`, so a
                        // click always reaches this arm with a
                        // path ŌĆö the `path.is_some()` guard is
                        // UX-only, not a security boundary. Same
                        // rationale documented on
                        // `ID_FILE_OPEN_IN_DEFAULT_VIEWER`.
                        let path: Option<PathBuf> = state_from_hwnd(hwnd)
                            .and_then(|state| state.shell.active().and_then(|t| t.path.clone()));
                        let Some(path) = path else {
                            return LRESULT(0);
                        };
                        let prompt = move_to_recycle_bin_prompt_for(&path);
                        let confirmed = show_ok_cancel_dialog(hwnd, "Delete file", &prompt);
                        if !confirmed {
                            return LRESULT(0);
                        }
                        // Force the buffer to clean state so the
                        // save-prompt in
                        // `handle_close_active_tab_inner` doesn't
                        // fire ŌĆö the whole point of this action
                        // is that the file (and its edits) are
                        // being discarded. The inner close path
                        // reads dirty via `SCI_GETMODIFY` (a
                        // direct-call query on the bound doc, not
                        // the cached `Tab.dirty` field or a
                        // notification-driven flag), so
                        // `SCI_SETSAVEPOINT` here suppresses the
                        // prompt synchronously and deterministically.
                        if let Some(state) = state_from_hwnd(hwnd) {
                            state.editor.send(SCI_SETSAVEPOINT, 0, 0);
                        }
                        // Close BEFORE delete for two reasons:
                        //   1. `shell.close_active_tab` (called
                        //      inside `handle_close_active_tab_inner`)
                        //      unwatches the path, so the
                        //      subsequent SHFileOperationW doesn't
                        //      race the file-watcher and pop its
                        //      own "reload? file deleted?" prompt
                        //      on top of this flow.
                        //   2. If the delete fails, the file is
                        //      left on disk intact ŌĆö the user can
                        //      still recover their data by
                        //      reopening it. The buffer is gone
                        //      but that's the intended
                        //      dischargeable state anyway.
                        let outcome = handle_close_active_tab_with_outcome(hwnd);
                        if !matches!(outcome, CloseOutcome::Closed) {
                            // Close didn't happen (e.g. re-entrant
                            // plugin call blocked state access).
                            // Bail without touching the file so
                            // the user's buffer/file stay in sync.
                            return LRESULT(0);
                        }
                        // Preserve the "always at least one tab"
                        // invariant if this was the last tab.
                        // Matches every other close call site
                        // that can drain the strip.
                        ensure_one_tab(hwnd);
                        if let Err(e) = move_path_to_recycle_bin(&path) {
                            tracing::warn!(
                                path = ?path,
                                error = %e,
                                "SHFileOperationW(FO_DELETE|FOF_ALLOWUNDO) failed"
                            );
                            show_error_dialog(
                                hwnd,
                                "Delete failed",
                                &format!(
                                    "The file could not be moved to the Recycle Bin.\n\n{}\n\n{}",
                                    path.display(),
                                    e
                                ),
                            );
                        }
                        fire_queued_notifications(hwnd);
                    }
                    ID_FILE_RELOAD => {
                        // Reload from disk. Two checks before we
                        // touch anything:
                        //   1. Active tab has a path. Without one
                        //      (untitled buffer) there's nothing to
                        //      reload; skip both prompt and call so
                        //      the user doesn't see a Yes/No dialog
                        //      that silently no-ops on Yes.
                        //   2. The buffer is dirty. If Scintilla's
                        //      modified flag AND the cached
                        //      `Tab.dirty` are both clear, reload
                        //      is idempotent and the prompt is
                        //      just noise ŌĆö skip it. The OR mirrors
                        //      the close-tab gate: `Tab.dirty` can
                        //      be true while `SCI_GETMODIFY` is
                        //      false when the file was deleted
                        //      externally (Shell flips `Tab.dirty`
                        //      from `apply_file_change::Removed`
                        //      without touching the Scintilla doc),
                        //      and in that case the reload would
                        //      still discard state the user might
                        //      want to preserve ŌĆö either the
                        //      pre-delete buffer text itself, or,
                        //      if the file was recreated with new
                        //      content and the user said No to the
                        //      Confirm Reload dialog, the stale
                        //      version they were keeping.
                        let (has_path, dirty) = if let Some(state) = state_from_hwnd(hwnd) {
                            let (has_path, cached_dirty) = state
                                .shell
                                .active()
                                .map_or((false, false), |t| (t.path.is_some(), t.dirty));
                            let dirty = state.editor.send(SCI_GETMODIFY, 0, 0) != 0 || cached_dirty;
                            (has_path, dirty)
                        } else {
                            (false, false)
                        };
                        if has_path {
                            let proceed = if dirty {
                                show_yes_no_dialog(
                                    hwnd,
                                    "Reload from Disk",
                                    "Discard unsaved changes and reload from disk?",
                                )
                            } else {
                                true
                            };
                            if proceed {
                                if let Some(state) = state_from_hwnd(hwnd) {
                                    let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(
                                        || {
                                            state.shell.reload_active();
                                        },
                                    ));
                                }
                            }
                        }
                        fire_queued_notifications(hwnd);
                    }
                    ID_FILE_CLOSE => {
                        handle_close_active_tab(hwnd);
                        // The "always at least one tab" invariant:
                        // closing the last tab pops a fresh untitled
                        // buffer so the user always sees an editor
                        // with a visible tab to type into.
                        ensure_one_tab(hwnd);
                    }
                    ID_FILE_EXIT => {
                        let _ = DestroyWindow(hwnd);
                    }
                    // Edit menu ŌĆö every entry is a single Scintilla
                    // direct-call. `editor` is `Copy`, so we pull a
                    // local copy out of the brief `&mut state` borrow
                    // and the borrow ends before the SCI call. Plugin
                    // re-entrance isn't a concern (Scintilla direct
                    // calls don't go through any wnd_proc).
                    ID_EDIT_UNDO | ID_EDIT_REDO | ID_EDIT_CUT | ID_EDIT_COPY | ID_EDIT_PASTE
                    | ID_EDIT_DELETE | ID_EDIT_SELECTALL => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let editor = state.editor;
                            let sci_msg = match cmd_u16 {
                                ID_EDIT_UNDO => SCI_UNDO,
                                ID_EDIT_REDO => SCI_REDO,
                                ID_EDIT_CUT => SCI_CUT,
                                ID_EDIT_COPY => SCI_COPY,
                                ID_EDIT_PASTE => SCI_PASTE,
                                ID_EDIT_DELETE => SCI_CLEAR,
                                ID_EDIT_SELECTALL => SCI_SELECTALL,
                                _ => unreachable!(),
                            };
                            editor.send(sci_msg, 0, 0);
                        }
                    }
                    // View toggles ŌĆö flip the corresponding Scintilla
                    // setting; the next WM_INITMENUPOPUP refreshes
                    // the check mark from the now-updated state.
                    ID_VIEW_WORDWRAP => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let editor = state.editor;
                            let toolbar_hwnd = state.toolbar_hwnd;
                            let on = editor.send(SCI_GETWRAPMODE, 0, 0) != 0;
                            editor.send(SCI_SETWRAPMODE, usize::from(!on), 0);
                            // Persist the new state ŌĆö same read-modify-
                            // write shape as the indent-guide toggle so
                            // a future sibling toggle can't clobber the
                            // other flags on the struct.
                            let mut view = state.shell.saved_view_settings();
                            view.word_wrap = !on;
                            state.shell.set_view_settings(view);
                            // SCI_SETWRAPMODE doesn't fire SCN_UPDATEUI,
                            // so push the new check state onto the
                            // toolbar explicitly.
                            toolbar::refresh_state(toolbar_hwnd, &editor);
                        }
                    }
                    ID_VIEW_SHOWWS => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let editor = state.editor;
                            let toolbar_hwnd = state.toolbar_hwnd;
                            let on = editor.send(SCI_GETVIEWWS, 0, 0) != 0;
                            // SCWS_INVISIBLE = 0, SCWS_VISIBLEALWAYS = 1.
                            editor.send(SCI_SETVIEWWS, usize::from(!on), 0);
                            let mut view = state.shell.saved_view_settings();
                            view.show_whitespace = !on;
                            state.shell.set_view_settings(view);
                            toolbar::refresh_state(toolbar_hwnd, &editor);
                        }
                    }
                    ID_VIEW_SHOWEOL => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let editor = state.editor;
                            let toolbar_hwnd = state.toolbar_hwnd;
                            let on = editor.send(SCI_GETVIEWEOL, 0, 0) != 0;
                            editor.send(SCI_SETVIEWEOL, usize::from(!on), 0);
                            let mut view = state.shell.saved_view_settings();
                            view.show_eol = !on;
                            state.shell.set_view_settings(view);
                            toolbar::refresh_state(toolbar_hwnd, &editor);
                        }
                    }
                    // Toolbar-only "Show All Chars" ŌĆö flips both
                    // whitespace and EOL visibility together. The
                    // button stays checked only when *both* are on
                    // (a user who toggled just one via the View
                    // submenu is in a "split" state and the
                    // combined indicator reads off, matching the
                    // mode it represents).
                    ID_VIEW_SHOW_ALL_CHARS => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let editor = state.editor;
                            let toolbar_hwnd = state.toolbar_hwnd;
                            let ws_on = editor.send(SCI_GETVIEWWS, 0, 0) != 0;
                            let eol_on = editor.send(SCI_GETVIEWEOL, 0, 0) != 0;
                            // Click pivots on the combined state:
                            // both on ŌåÆ both off; otherwise ŌåÆ both on.
                            // That makes the click semantics agree
                            // with the button's check indicator.
                            let new_on = !(ws_on && eol_on);
                            let target = usize::from(new_on);
                            editor.send(SCI_SETVIEWWS, target, 0);
                            editor.send(SCI_SETVIEWEOL, target, 0);
                            // Persist both underlying flags. The
                            // composite button reads them back on
                            // next launch via `refresh_state`'s
                            // `ws_on && eol_on` gate ŌĆö same
                            // in-session semantic, restored across
                            // launches.
                            let mut view = state.shell.saved_view_settings();
                            view.show_whitespace = new_on;
                            view.show_eol = new_on;
                            state.shell.set_view_settings(view);
                            toolbar::refresh_state(toolbar_hwnd, &editor);
                        }
                    }
                    // Toolbar-only "Show Indent Guide" ŌĆö toggles
                    // between SC_IV_NONE and SC_IV_LOOKBOTH (the
                    // "guides through whitespace" mode that's most
                    // useful for indented code; matches what
                    // Notepad++ enables).
                    ID_VIEW_SHOW_INDENT_GUIDE => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let editor = state.editor;
                            let toolbar_hwnd = state.toolbar_hwnd;
                            let mode = editor.send(SCI_GETINDENTATIONGUIDES, 0, 0) as usize;
                            let target = if mode == SC_IV_NONE {
                                SC_IV_LOOKBOTH
                            } else {
                                SC_IV_NONE
                            };
                            editor.send(SCI_SETINDENTATIONGUIDES, target, 0);
                            // Persist the new state on Shell so the
                            // next `save_session` (autosave / shutdown)
                            // writes it through to `session.xml` and
                            // the next launch cold-starts with the
                            // same choice. Read-modify-write so a
                            // future sibling toggle on `ViewSettings`
                            // doesn't get clobbered here.
                            let mut view = state.shell.saved_view_settings();
                            view.indent_guide = target == SC_IV_LOOKBOTH;
                            state.shell.set_view_settings(view);
                            toolbar::refresh_state(toolbar_hwnd, &editor);
                        }
                    }
                    ID_VIEW_ZOOMIN => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            state.editor.send(SCI_ZOOMIN, 0, 0);
                        }
                    }
                    ID_VIEW_ZOOMOUT => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            state.editor.send(SCI_ZOOMOUT, 0, 0);
                        }
                    }
                    ID_VIEW_ZOOMRESET => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            state.editor.send(SCI_SETZOOM, 0, 0);
                        }
                    }
                    // Encoding menu (m5): "Convert to ..." items.
                    // Code++'s Scintilla view always holds UTF-8
                    // internally ŌĆö the conversion is purely a
                    // metadata flip on `tab.encoding`. The next
                    // Save re-encodes through the chosen variant;
                    // the round-trip back to UTF-8 on reopen is
                    // bytes-correct for every codepoint
                    // representable in both encodings (which is
                    // every text for the four UTF variants).
                    //
                    // ANSI is grayed today: it would need
                    // GetACP-driven system-codepage detection plus
                    // a save-time error path for unrepresentable
                    // characters. Tracked as a follow-up.
                    ID_ENCODING_UTF8 | ID_ENCODING_UTF8_BOM | ID_ENCODING_UTF16_LE
                    | ID_ENCODING_UTF16_BE => {
                        let target = match cmd_u16 {
                            ID_ENCODING_UTF8 => Encoding::Utf8,
                            ID_ENCODING_UTF8_BOM => Encoding::Utf8Bom,
                            ID_ENCODING_UTF16_LE => Encoding::Utf16LeBom,
                            ID_ENCODING_UTF16_BE => Encoding::Utf16BeBom,
                            _ => unreachable!("outer match guarantees one of the four"),
                        };
                        if let Some(state) = state_from_hwnd(hwnd) {
                            if state.shell.set_buffer_encoding(target) {
                                // Refresh the status bar so the
                                // encoding label reflects the
                                // change immediately. byte_len is
                                // the on-disk byte count ŌĆö kept
                                // from the tab snapshot since the
                                // in-memory text didn't change.
                                let snapshot = state
                                    .shell
                                    .active()
                                    .map(|t| (t.lang, t.encoding.clone(), t.eol, t.byte_len));
                                if let Some((lang, encoding, eol, byte_len)) = snapshot {
                                    let mut win32_ui = Win32Ui {
                                        status_hwnd: state.status_hwnd,
                                        tab_hwnd: state.tab_hwnd,
                                        toolbar_hwnd: state.toolbar_hwnd,
                                        main_menu: state.main_menu,
                                        accel_handle: &raw mut state.accel_handle,
                                        plugin_modeless_dialogs: &raw mut state
                                            .plugin_modeless_dialogs,
                                        dock_dialogs: &raw mut state.dock_dialogs,
                                        udl_registry: &raw const state.shell.udl_registry,
                                        editor: state.editor,
                                        docmap_editor: state.docmap_editor,
                                    };
                                    <Win32Ui as UiPlatform>::update_status(
                                        &mut win32_ui,
                                        lang,
                                        &encoding,
                                        eol,
                                        byte_len,
                                    );
                                }
                            }
                        }
                    }
                    // Help ŌåÆ About: simple MessageBox with version
                    // info. Modal pump runs after the borrow drops.
                    ID_HELP_ABOUT => {
                        show_about_dialog(hwnd);
                    }
                    // Language ŌåÆ User-Defined language ŌåÆ Open UDL
                    // folder (Phase 4.6 m2). Creates
                    // `<config_dir>/userDefineLangs/` if missing,
                    // then launches the OS file explorer at that
                    // path via `ShellExecuteW("open", ...)`.
                    ID_UDL_OPEN_FOLDER => {
                        open_udl_folder(hwnd);
                    }
                    // Language ŌåÆ User-Defined language ŌåÆ Define
                    // your languageŌĆ” (Phase 4.6 m3b). Opens the
                    // modeless UDL editor. Reuses an already-open
                    // instance if present; otherwise creates a
                    // fresh one starting from the "New UDL"
                    // defaults. The returned HWND is stashed on
                    // `WindowState.udl_editor_dlg` so the main
                    // pump can route `IsDialogMessageW` to it.
                    ID_UDL_DEFINE_LANGUAGE => {
                        let existing = state_from_hwnd(hwnd).and_then(|s| s.udl_editor_dlg);
                        if let Some(dlg) = udl_editor::show_udl_editor(
                            hwnd,
                            existing,
                            udl_editor::UdlEditorMode::New,
                        ) {
                            if let Some(s) = state_from_hwnd(hwnd) {
                                s.udl_editor_dlg = Some(dlg);
                            }
                        }
                    }
                    // Language ŌåÆ User-Defined language ŌåÆ Notepad++
                    // UDL Collection (Phase 4.6 m2). Opens
                    // `UDL_COLLECTION_URL` in the user's default
                    // browser. Compile-time-fixed URL, no user
                    // string ever reaches `ShellExecuteW`.
                    ID_UDL_OPEN_COLLECTION => {
                        open_url_in_browser(hwnd, UDL_COLLECTION_URL);
                    }
                    // Help ŌåÆ Code++ Home / Project Page /
                    // Community. Same shared browser helper as the
                    // UDL Collection entry above; each URL is a
                    // compile-time constant so no user-controlled
                    // string ever reaches `ShellExecuteW`.
                    ID_HELP_HOME => {
                        open_url_in_browser(hwnd, HELP_HOME_URL);
                    }
                    ID_HELP_PROJECT => {
                        open_url_in_browser(hwnd, HELP_PROJECT_URL);
                    }
                    ID_HELP_COMMUNITY => {
                        open_url_in_browser(hwnd, HELP_COMMUNITY_URL);
                    }
                    // Settings ŌåÆ Style Configurator. Opens the
                    // modal style editor. On Save & Close the
                    // returned `Styles` is persisted via
                    // `Shell::set_styles` and applied to the live
                    // Scintilla view through `apply_default_style`
                    // (the same path the startup seeder uses).
                    ID_SETTINGS_STYLECONFIGURATOR => {
                        handle_style_config_menu(hwnd);
                    }
                    // Plugins ŌåÆ Plugin Manager. Modal dialog listing
                    // every discovered plugin with a per-row Enabled
                    // checkbox; toggling persists to
                    // `<plugins_config_dir>/disabled.txt`. Same
                    // borrow-then-drop pattern as the About dialog
                    // ŌĆö `show_plugin_admin_dialog` only takes
                    // `main_hwnd`, runs its own modal pump, and
                    // re-acquires `state_from_hwnd` for the toggle
                    // hooks under fresh borrows.
                    ID_PLUGINS_ADMIN => {
                        show_plugin_admin_dialog(hwnd);
                    }
                    // Go to... (m3b1). Pull the caret's line + offset
                    // and the document's line count + length off the
                    // editor so the dialog can populate both axes
                    // independently. After the user picks, dispatch
                    // to SCI_GOTOLINE (zero-based line) or SCI_GOTOPOS
                    // (zero-based byte offset) per the result variant
                    // and re-focus Scintilla so the user can type
                    // immediately.
                    ID_SEARCH_GOTOLINE => {
                        let seed = if let Some(state) = state_from_hwnd(hwnd) {
                            let editor = state.editor;
                            let pos = editor.send(SCI_GETCURRENTPOS, 0, 0).max(0) as u32;
                            let cur_line =
                                editor.send(SCI_LINEFROMPOSITION, pos as usize, 0).max(0) as u32;
                            let total_lines = editor.send(SCI_GETLINECOUNT, 0, 0).max(0) as u32;
                            let length = editor.send(SCI_GETLENGTH, 0, 0).max(0) as u32;
                            Some((
                                cur_line.saturating_add(1).max(1),
                                total_lines.max(1),
                                pos,
                                length,
                                state.scintilla_hwnd,
                            ))
                        } else {
                            None
                        };
                        if let Some((cur_line, max_line, cur_offset, max_offset, scintilla_hwnd)) =
                            seed
                        {
                            if let Some(target) =
                                show_goto_dialog(hwnd, cur_line, max_line, cur_offset, max_offset)
                            {
                                if let Some(state) = state_from_hwnd(hwnd) {
                                    match target {
                                        GotoTarget::Line(n) => {
                                            state.editor.send(
                                                SCI_GOTOLINE,
                                                n.saturating_sub(1) as usize,
                                                0,
                                            );
                                        }
                                        GotoTarget::Offset(p) => {
                                            state.editor.send(SCI_GOTOPOS, p as usize, 0);
                                        }
                                    }
                                }
                            }
                            let _ = SetFocus(Some(scintilla_hwnd));
                        }
                    }
                    // Find / Replace ŌĆö open the modeless dialog and
                    // select the appropriate tab. The dialog is
                    // lazily created on first invocation and reused
                    // (via ShowWindow(SW_HIDE) on Close) afterwards
                    // so the typed query and flag state survive
                    // across open/close cycles.
                    ID_SEARCH_FIND | ID_SEARCH_REPLACE | ID_SEARCH_FINDINFILES => {
                        let initial_tab = match cmd_u16 {
                            ID_SEARCH_REPLACE => FindReplaceTab::Replace,
                            ID_SEARCH_FINDINFILES => FindReplaceTab::FindInFiles,
                            _ => FindReplaceTab::Find,
                        };
                        let existing = state_from_hwnd(hwnd).and_then(|s| s.find_replace_dlg);
                        if let Some(dlg) = show_find_replace_dialog(hwnd, existing, initial_tab) {
                            if let Some(state) = state_from_hwnd(hwnd) {
                                state.find_replace_dlg = Some(dlg);
                            }
                        }
                    }
                    // F3 / Shift+F3 ŌĆö repeat the last search using
                    // the query/flags Shell::find_next stored on the
                    // most recent dialog interaction.
                    ID_SEARCH_FINDNEXT => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let (shell, mut ui) = state.split();
                            let _ = shell.find_next_repeat(&mut ui);
                        }
                    }
                    ID_SEARCH_FINDPREV => {
                        if let Some(state) = state_from_hwnd(hwnd) {
                            let (shell, mut ui) = state.split();
                            let _ = shell.find_prev_repeat(&mut ui);
                        }
                    }
                    _ => {
                        // Dynamic-range commands (Language menu,
                        // Window menu). These reach the `_` arm
                        // because their cmd ids carry a parameter
                        // value (lang-id or tab-idx) rather than a
                        // single fixed constant.
                        if (ID_LANGUAGE_BASE..=ID_LANGUAGE_END).contains(&cmd_u16) {
                            let lang_id = i32::from(cmd_u16 - ID_LANGUAGE_BASE);
                            handle_language_menu_click(hwnd, lang_id);
                            return LRESULT(0);
                        }
                        if (ID_UDL_ITEM_BASE..=ID_UDL_ITEM_END).contains(&cmd_u16) {
                            // Loaded-UDL menu item. `append_udls_to_menu`
                            // encodes the entry as
                            // `menu_id = ID_UDL_ITEM_BASE + (lang_type_id -
                            // UDL_LANG_TYPE_BASE)`. Invert here and route
                            // through the same `handle_language_menu_click`
                            // path built-in-lexer menu items take ŌĆö that
                            // dispatches `NPPM_SETBUFFERLANGTYPE`, which
                            // updates the tab's `lang`, re-runs
                            // `apply_lang` (which reads `udl_registry`
                            // for UDL ids), queues `NPPN_LANGCHANGED`,
                            // and refreshes the status bar. One code
                            // path, three sources (menu click, plugin
                            // set, file-open by extension).
                            let offset = i32::from(cmd_u16 - ID_UDL_ITEM_BASE);
                            let lang_type_id = codepp_udl::UDL_LANG_TYPE_BASE + offset;
                            handle_language_menu_click(hwnd, lang_type_id);
                            return LRESULT(0);
                        }
                        if (ID_WINDOW_BASE..=ID_WINDOW_END).contains(&cmd_u16) {
                            let tab_idx = (cmd_u16 - ID_WINDOW_BASE) as usize;
                            handle_window_menu_click(hwnd, tab_idx);
                            return LRESULT(0);
                        }
                        // Plugin menu-command dispatch. Plugin cmd-ids
                        // start at PLUGIN_CMD_ID_BASE (50000) ŌĆö well
                        // above any host built-in. Look up the
                        // callback through the borrow, **then drop
                        // the borrow before invoking**: a plugin's
                        // PluginCmd is allowed to SendMessage(NPPM_*)
                        // back into our wnd_proc, which would
                        // re-enter and materialize a second
                        // &mut WindowState from the same raw pointer
                        // (aliasing UB). Splitting into a lookup
                        // phase and an invoke phase keeps the
                        // re-entrant call sound.
                        if cmd_i32 >= PLUGIN_CMD_ID_BASE {
                            let p_func = if let Some(state) = state_from_hwnd(hwnd) {
                                state.shell.lookup_plugin_command(cmd_i32)
                            } else {
                                None
                            };
                            // Borrow on `state` ends here.
                            if let Some(f) = p_func {
                                // SAFETY: `f` is the C ABI fn ptr the
                                // plugin handed us in FuncItem.p_func.
                                // The plugin's DLL stays loaded for as
                                // long as Shell holds it; the pointer
                                // is valid. catch_unwind so a Rust-
                                // authored plugin's panic doesn't
                                // unwind across the C ABI. The
                                // PluginCallGuard arms the re-entrance
                                // flag in case the plugin
                                // SendMessages NPPM_* back; defense
                                // in depth even though NLL has
                                // already dropped the lookup borrow.
                                // Guard inside the catch_unwind
                                // closure so nested-guard assert is
                                // caught here. Same pattern as
                                // `fire_queued_notifications`.
                                let _ =
                                    std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                                        let _guard = PluginCallGuard::enter();
                                        f();
                                    }));
                            }
                        }
                    }
                }
                LRESULT(0)
            }
            WM_INITMENUPOPUP => {
                // First-touch plugin load. wparam carries the HMENU
                // of the popup about to be shown; lparam packs (item
                // index, is_window_menu_flag). We compare the HMENU
                // against our `plugin_menu` and, if it matches and we
                // haven't yet loaded, load every Pending plugin and
                // append their FuncItems as menu entries.
                //
                // The lookup phase holds `state`; the load phase has
                // to drop the borrow first because plugin `setInfo`
                // can synchronously SendMessage(NPPM_*) back into
                // wnd_proc (re-entrance). We therefore: (1) decide
                // whether work is needed under the borrow, (2) drop
                // the borrow, (3) reacquire and run the load, (4)
                // populate the menu under a fresh borrow.
                let popup_hmenu_value = wparam.0;
                let needs_init = if let Some(state) = state_from_hwnd(hwnd) {
                    !state.plugins_menu_initialized
                        && popup_hmenu_value == state.plugin_menu.0 as usize
                } else {
                    false
                };
                if needs_init {
                    // Build NppData under a brief borrow.
                    let npp_data = if let Some(state) = state_from_hwnd(hwnd) {
                        NppData {
                            npp_handle: hwnd.0,
                            scintilla_main_handle: state.scintilla_hwnd.0,
                            scintilla_second_handle: core::ptr::null_mut(),
                        }
                    } else {
                        // Should be unreachable given the needs_init
                        // path above, but stay defensive.
                        return LRESULT(0);
                    };
                    // Mark the menu as initialized **before** running
                    // any plugin code so a nested WM_INITMENUPOPUP
                    // (from any path that re-enters wnd_proc during
                    // load) sees `needs_init == false` and skips
                    // re-running the load. We pay the cost of a
                    // possibly-empty submenu in the rare error case
                    // where load fails entirely ŌĆö preferable to
                    // double-loading the same plugin.
                    if let Some(state) = state_from_hwnd(hwnd) {
                        state.plugins_menu_initialized = true;
                    }
                    // Trigger lazy load. The PluginCallGuard arms the
                    // PLUGIN_CALL_ACTIVE flag for the duration of the
                    // call so any re-entrant `state_from_hwnd` from a
                    // plugin's `setInfo` returns None ŌĆö preventing
                    // the second `&mut WindowState` materialization
                    // that would otherwise alias with our outer
                    // borrow. The guard's Drop clears the flag even
                    // on panic.
                    //
                    // The whole call is wrapped in `catch_unwind` so
                    // a host-internal panic (allocation failure,
                    // tracing-subscriber misbehaviour) doesn't
                    // unwind across the `extern "system"` wnd_proc
                    // frame ŌĆö that's UB. Plugin entry-points are
                    // already individually `catch_unwind`-wrapped
                    // inside `load_inner`; this outer guard catches
                    // panics in our own bookkeeping.
                    if let Some(state) = state_from_hwnd(hwnd) {
                        // Guard inside the catch_unwind closure so
                        // its assert (nested-guard detection) is
                        // caught here rather than unwinding across
                        // extern "system". Same pattern as
                        // `fire_queued_notifications`.
                        let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                            let _guard = PluginCallGuard::enter();
                            state.shell.ensure_plugins_loaded(npp_data);
                        }));
                    }
                    // Populate the menu from loaded plugins. We rebuild
                    // the FuncItem list inside a borrow, then call
                    // AppendMenuW for each entry; AppendMenuW does
                    // not re-enter our wnd_proc, so the borrow can
                    // span the population.
                    if let Some(state) = state_from_hwnd(hwnd) {
                        populate_plugin_menu(state.plugin_menu, &state.shell);
                        // Force the menu bar to redraw so the user
                        // sees the populated submenu on this very
                        // open (without a redraw, the items only
                        // appear after the popup re-displays).
                        let _ = DrawMenuBar(hwnd);
                    }
                }
                // Refresh dynamic state on the four state-driven
                // submenus (View toggles, Encoding/Language radios,
                // Window list). Each refresh is read-only against
                // `state` apart from the rebuild on `window_menu`,
                // which only mutates the menu HMENU ŌĆö not anything
                // a re-entrant call could observe through `state`.
                // None of these helpers re-enter our wnd_proc.
                if let Some(state) = state_from_hwnd(hwnd) {
                    if popup_hmenu_value == state.file_menu.0 as usize {
                        refresh_file_menu(state.file_menu, &state.shell);
                    } else if popup_hmenu_value == state.view_menu.0 as usize {
                        refresh_view_menu(
                            state.view_menu,
                            &state.editor,
                            state.workspace_visible,
                            state.docmap_visible,
                        );
                    } else if popup_hmenu_value == state.encoding_menu.0 as usize {
                        if let Some(active) = state.shell.active() {
                            refresh_encoding_menu(state.encoding_menu, &active.encoding);
                        }
                    } else if popup_hmenu_value == state.language_menu.0 as usize {
                        if let Some(active) = state.shell.active() {
                            refresh_language_menu(state.language_menu, active.lang);
                        }
                    } else if popup_hmenu_value == state.window_menu.0 as usize {
                        refresh_window_menu(state.window_menu, &state.shell);
                    } else if popup_hmenu_value == state.right_shortcuts_menu.0 as usize {
                        // Right-edge `Ō¢╝` open-tabs switcher. Same
                        // content shape as the Window menu ŌĆö reuse
                        // the helper so the entry list, cmd ids, and
                        // active-tab check mark stay in sync.
                        refresh_window_menu(state.right_shortcuts_menu, &state.shell);
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_SIZE => {
                let width = (lparam.0 & 0xFFFF) as i32;
                let height = ((lparam.0 >> 16) & 0xFFFF) as i32;
                let editors = if let Some(state) = state_from_hwnd(hwnd) {
                    let tab_hidden = !IsWindowVisible(state.tab_hwnd).as_bool();
                    let toolbar_height = toolbar::toolbar_height_px(state.toolbar_bitmap_px);
                    let workspace = WorkspaceLayout {
                        panel: state.workspace_hwnd,
                        splitter: state.workspace_splitter_hwnd,
                        visible: state.workspace_visible,
                        width: state.workspace_width,
                    };
                    let docmap = DocMapLayout {
                        panel: state.docmap_hwnd,
                        splitter: state.docmap_splitter_hwnd,
                        visible: state.docmap_visible,
                        width: state.docmap_width,
                    };
                    layout_children(
                        state.toolbar_hwnd,
                        toolbar_height,
                        state.tab_hwnd,
                        state.scintilla_hwnd,
                        state.status_hwnd,
                        state.fif_splitter_hwnd,
                        state.fif_dock_hwnd,
                        state.fif_dock_visible,
                        state.fif_dock_height,
                        tab_hidden,
                        workspace,
                        docmap,
                        width,
                        height,
                    );
                    // Re-apply the 7-part layout so the spring
                    // (part 1) absorbs the width delta. The fixed
                    // right-side parts keep their designed widths;
                    // text written by `update_status` /
                    // `refresh_status_dynamic_parts` lands in the
                    // same slots regardless of window width.
                    setup_status_parts(state.status_hwnd, width);
                    // Persist the latest geometry into the shell's
                    // session cache so the next clean shutdown
                    // writes the size the user actually wants.
                    track_window_geometry(hwnd, &mut state.shell, wparam.0 as u32);
                    Some((state.editor, state.docmap_editor))
                } else {
                    None
                };
                // A main-window resize changes the main editor's
                // `SCI_LINESONSCREEN`, which shifts the bottom
                // edge of the visible range. Scintilla doesn't
                // fire `SCN_UPDATEUI(SC_UPDATE_V_SCROLL)` for a
                // resize that doesn't move first-visible-line
                // (only for scroll gestures), so we push the
                // update ourselves. Both editor handles snapshot
                // out of the `state_from_hwnd` scope above so no
                // second borrow materialises here.
                if let Some((main_editor, docmap_editor)) = editors {
                    update_docmap_viewport_indicator(main_editor, docmap_editor);
                }
                LRESULT(0)
            }
            WM_SETFOCUS => {
                if let Some(state) = state_from_hwnd(hwnd) {
                    let _ = SetFocus(Some(state.scintilla_hwnd));
                }
                LRESULT(0)
            }
            WM_SETTINGCHANGE => {
                // Windows posts WM_SETTINGCHANGE on system-wide
                // setting changes. The dark/light theme flip is
                // identified by `lparam` pointing at the wide
                // string "ImmersiveColorSet" ŌĆö match that and
                // re-broadcast as NPPN_DARKMODECHANGED so plugins
                // that paint their own chrome can re-read the
                // system colour state. Other settings (fonts,
                // accessibility, regional) reach DefWindowProcW
                // unchanged.
                //
                // `lparam` may be NULL ŌĆö a generic "something
                // changed" broadcast that does not name a
                // specific setting key. The wide-string compare
                // below returns false on NULL, so we naturally
                // skip those. (The main window is registered
                // via `RegisterClassExW`, so Windows always
                // delivers the wide-string flavour ŌĆö no ANSI /
                // cross-encoding case to worry about.)
                //
                // The `lparam.0 % 2 != 0` guard rejects
                // misaligned pointers up front ŌĆö the OS itself
                // always hands us `u16`-aligned strings, but an
                // in-process plugin doing
                // `SendMessage(WM_SETTINGCHANGE, 0, &one_byte)`
                // could otherwise feed `wide_string_equals` a
                // misaligned pointer and trigger UB on the
                // first aligned read. Cheap defense-in-depth.
                let lp = lparam.0;
                // SAFETY: enclosing `main_wnd_proc` body is one
                // big `unsafe { match ŌĆ” }` (windows-rs API
                // surface). `wide_string_equals` is `unsafe fn`
                // for u16-alignment + bounded-read contract;
                // the `lp % 2 == 0` guard above satisfies the
                // alignment side of the contract, the
                // `WIDE_COMPARE_CAP = 64` cap inside the helper
                // satisfies the bounded-read side.
                if lp != 0
                    && lp % 2 == 0
                    && wide_string_equals(lp as *const u16, "ImmersiveColorSet")
                {
                    if let Some(state) = state_from_hwnd(hwnd) {
                        let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                            let _guard = PluginCallGuard::enter();
                            state
                                .shell
                                .notify_plugins(Notification::DarkModeChanged, hwnd.0);
                        }));
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_TIMER => {
                // Auto-save tick. `wparam` carries the timer id we
                // passed to `SetTimer` ŌĆö gate on it so an unrelated
                // common-control timer (e.g., a third-party plugin
                // that started its own timer on this HWND) doesn't
                // accidentally trigger a save pass. `state.split()`
                // mirrors the wnd_proc's standard "fresh UiPlatform
                // view" pattern; `catch_unwind` matches `WM_DESTROY`
                // so a panic in shell bookkeeping can't unwind
                // across the `extern "system"` frame.
                if wparam.0 == WORKSPACE_UNFOLD_TIMER_ID {
                    // Async "Unfold All" tick ŌĆö process a batch of
                    // folders, then decide whether to keep the timer
                    // alive. On completion, `finish_workspace_unfold`
                    // stops the marquee, hides the overlay, shows
                    // the tree, and forces one clean repaint.
                    let more = tick_workspace_unfold(hwnd);
                    if !more {
                        let _ = KillTimer(Some(hwnd), WORKSPACE_UNFOLD_TIMER_ID);
                        finish_workspace_unfold(hwnd);
                    }
                    return LRESULT(0);
                }
                if wparam.0 == AUTOSAVE_TIMER_ID {
                    if let Some(state) = state_from_hwnd(hwnd) {
                        // Freeze the editor's WM_PAINT delivery
                        // around the save pass. `save_session`
                        // walks every tab and round-trips through
                        // `SCI_SETDOCPOINTER` for non-active dirty
                        // tabs; each swap pair invalidates the
                        // editor and (without this freeze) Scintilla
                        // paints the intermediate state ŌĆö a
                        // visible-and-irritating flicker every 7
                        // seconds. `WM_SETREDRAW(false)` queues
                        // invalidations without painting; the
                        // matching `(true)` re-enables painting,
                        // and an explicit `InvalidateRect` forces
                        // ONE clean repaint of the final
                        // (active-doc, restored-view) state.
                        let scintilla_hwnd = state.scintilla_hwnd;
                        let _ = SendMessageW(
                            scintilla_hwnd,
                            WM_SETREDRAW,
                            Some(WPARAM(0)),
                            Some(LPARAM(0)),
                        );
                        // Capture the workspace panel state
                        // (root / visible / width) into the shell's
                        // session cache BEFORE `save_session` runs
                        // so cold-start restore next launch sees the
                        // latest state. Same discipline for the
                        // right-side Document Map panel.
                        sync_workspace_state_to_shell(hwnd);
                        sync_docmap_state_to_shell(hwnd);
                        let (shell, mut ui) = state.split();
                        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                            shell.save_session(&mut ui)
                        }));
                        let _ = SendMessageW(
                            scintilla_hwnd,
                            WM_SETREDRAW,
                            Some(WPARAM(1)),
                            Some(LPARAM(0)),
                        );
                        // Force a single fresh paint of the
                        // restored-view state. Without this the
                        // editor stays visually frozen until the
                        // next user-driven invalidation.
                        let _ = InvalidateRect(Some(scintilla_hwnd), None, false);
                        match result {
                            Ok(Ok(())) => {}
                            Ok(Err(e)) => {
                                tracing::warn!(error = %e, "auto-save failed");
                            }
                            Err(_) => {
                                tracing::warn!("auto-save panicked");
                            }
                        }
                    }
                    return LRESULT(0);
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_ERASEBKGND => {
                // Paint the entire client area with the editor-
                // border colour. Child windows (tabs, Scintilla,
                // status, splitter, dock) draw their own
                // backgrounds on top of this in the subsequent
                // WM_PAINT pass; the only places the gray brush
                // remains visible are the EDITOR_BORDER_PX strips
                // around the Scintilla view that `layout_children`
                // deliberately leaves uncovered. This produces the
                // four-sided delimiter the user requested without
                // introducing a separate WM_PAINT handler ŌĆö the
                // erase pass is enough because all chrome is
                // child-window-rendered.
                //
                // Returning 1 (TRUE) signals "background already
                // erased" so DefWindowProcW doesn't re-erase with
                // the class brush.
                let hdc = HDC(wparam.0 as *mut c_void);
                let mut rect = RECT::default();
                let _ = GetClientRect(hwnd, &raw mut rect);
                FillRect(hdc, &raw const rect, editor_border_brush());
                LRESULT(1)
            }
            WM_DESTROY => {
                // Persist the session before tearing down. Pull live
                // text/cursor through the editor while it still
                // exists ŌĆö once we PostQuitMessage the message pump
                // unwinds and the Scintilla window is destroyed.
                //
                // Kill the auto-save timer first so a tick can't
                // race the shutdown save (or arrive after the box
                // is reclaimed below). Same reasoning for the
                // workspace-unfold timer ŌĆö a mid-shutdown tick
                // reaching into a torn-down tree HWND is UB.
                let _ = KillTimer(Some(hwnd), AUTOSAVE_TIMER_ID);
                let _ = KillTimer(Some(hwnd), WORKSPACE_UNFOLD_TIMER_ID);
                // Fire NPPN_BEFORESHUTDOWN before any host-side
                // teardown. Plugins use this hook to save their
                // own state alongside the host's session save.
                // Code++'s queue-deferred delivery model means a
                // plugin response cannot veto shutdown (the
                // upstream contract allows that, but the queue
                // is one-way), so this is informational only.
                //
                // Dispatched synchronously (via `notify_plugins`,
                // not `fire_queued_notifications`) so a plugin's
                // `beNotified(BEFORESHUTDOWN)` handler can still
                // call back into NPPM messages that need live
                // session data ŌĆö `Shell.tabs`, the
                // file-watcher state, the editor handle. Any
                // notifications a plugin queues from inside its
                // BEFORESHUTDOWN handler land in
                // `pending_notifications` and get drained by the
                // `fire_queued_notifications` call further down.
                if let Some(state) = state_from_hwnd(hwnd) {
                    let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                        let _guard = PluginCallGuard::enter();
                        state
                            .shell
                            .notify_plugins(Notification::BeforeShutdown, hwnd.0);
                    }));
                }
                // Capture workspace + docmap panel state into the
                // shell's session cache BEFORE the shutdown save
                // runs ŌĆö same rationale as the autosave path above.
                sync_workspace_state_to_shell(hwnd);
                sync_docmap_state_to_shell(hwnd);
                if let Some(state) = state_from_hwnd(hwnd) {
                    let (shell, mut ui) = state.split();
                    // catch_unwind for the same reason as
                    // ID_FILE_SAVE: a panic in shell bookkeeping must
                    // not unwind across the extern "system" wnd_proc
                    // frame during teardown.
                    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                        shell.save_session(&mut ui)
                    }));
                    match result {
                        Ok(Ok(())) => {}
                        Ok(Err(e)) => tracing::warn!(error = %e, "session save failed"),
                        Err(_) => tracing::warn!("session save panicked"),
                    }
                }

                // Drain any leftover NPPN_FILEOPENED/NPPN_FILESAVED
                // notifications that were queued since the last
                // WM_APP_WAKE drain ŌĆö a file-open completing right
                // before the user closes the app would otherwise be
                // silently dropped, breaking plugins that audit-log
                // file activity. Safe to call here: no borrow is
                // held, and `fire_queued_notifications` arms its
                // own PluginCallGuard around each plugin call.
                fire_queued_notifications(hwnd);

                // Fire NPPN_SHUTDOWN to every loaded plugin while the
                // WindowState (and the PluginHost it owns) still
                // exists. The PluginCallGuard prevents a plugin's
                // beNotified from materializing a second
                // &mut WindowState via re-entrant SendMessage; the
                // catch_unwind keeps a host-internal panic from
                // unwinding across the extern "system" wnd_proc.
                if let Some(state) = state_from_hwnd(hwnd) {
                    // Guard inside the catch_unwind closure so the
                    // nested-guard assert (if it ever fired) is
                    // caught here. Same pattern as
                    // `fire_queued_notifications`.
                    let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                        let _guard = PluginCallGuard::enter();
                        state.shell.notify_plugins(Notification::Shutdown, hwnd.0);
                    }));
                }

                // Free the toolbar's image list. The OS would
                // reclaim it at process exit anyway, but explicit
                // teardown matches the project's "leak nothing on
                // graceful shutdown" pattern.
                //
                // ORDER-SENSITIVE: this block must run before the
                // `Box::from_raw` reclaim immediately below ŌĆö both
                // read `state` through `GWLP_USERDATA`, and the Box
                // reclaim is what makes subsequent `state_from_hwnd`
                // calls return `None`. Reordering the two would
                // leak the imagelist on shutdown.
                //
                // Detach the imagelist from the toolbar *before*
                // destroying it ŌĆö `NPPN_SHUTDOWN` fires immediately
                // above, and a plugin's handler is allowed to call
                // `RedrawWindow` / `UpdateWindow` on top-level UI
                // (not banned by the ABI). With the imagelist
                // detached first, even a worst-case re-paint hits
                // the empty-imagelist path inside the toolbar
                // proc and renders blank cells instead of
                // dereferencing a freed HIMAGELIST.
                if let Some(state) = state_from_hwnd(hwnd) {
                    use windows::Win32::UI::Controls::TB_SETIMAGELIST;
                    SendMessageW(
                        state.toolbar_hwnd,
                        TB_SETIMAGELIST,
                        Some(WPARAM(0)),
                        Some(LPARAM(0)),
                    );
                    let _ = windows::Win32::UI::Controls::ImageList_Destroy(Some(
                        state.toolbar_image_list,
                    ));
                    // Free the two tab-strip save icons. Same
                    // "OS would reclaim at process exit, but the
                    // project's leak-nothing pattern wants explicit
                    // teardown" rationale as the toolbar imagelist
                    // above. `is_invalid()` skips the call when
                    // the icon failed to decode at startup.
                    if !state.tab_save_blue_hbm.is_invalid() {
                        let _ = DeleteObject(state.tab_save_blue_hbm.into());
                    }
                    if !state.tab_save_red_hbm.is_invalid() {
                        let _ = DeleteObject(state.tab_save_red_hbm.into());
                    }
                }

                // Free the accelerator table. Same "OS would
                // reclaim it at process exit anyway, but explicit
                // teardown matches the project's leak-nothing
                // pattern" rationale as the imagelist above. The
                // message pump already exited (we're in the
                // wnd_proc reachable only after `GetMessageW`
                // returns 0 from `WM_QUIT`), so no
                // `TranslateAcceleratorW` call can race the
                // destroy.
                if let Some(state) = state_from_hwnd(hwnd) {
                    let h = state.accel_handle;
                    if !h.is_invalid() {
                        let _ = DestroyAcceleratorTable(h);
                        // Zero the slot so a buggy late call
                        // path (e.g. a stray `Win32Ui` that
                        // somehow outlived `WindowState`) reads
                        // an invalid handle and cleanly
                        // short-circuits rather than passing a
                        // freed HACCEL to a Win32 API.
                        state.accel_handle = HACCEL::default();
                    }
                }

                // Reclaim the WindowState box. After this point, any
                // re-entrant wnd_proc gets `None` from
                // `state_from_hwnd` (GWLP_USERDATA == 0), so any late
                // plugin SendMessage during teardown is safely
                // dispatched as DefWindowProcW.
                let raw = SetWindowLongPtrW(hwnd, GWLP_USERDATA, 0);
                if raw != 0 {
                    let _ = Box::from_raw(raw as *mut WindowState);
                }
                PostQuitMessage(0);
                LRESULT(0)
            }
            // Plugin host inbound dispatch. Plugins call
            // `SendMessage(npp_hwnd, NPPM_*, ŌĆ”)`; the dispatcher
            // (`plugin_host::dispatch_nppm`) handles every v1 message
            // and returns `Some(LRESULT)`. Out-of-range messages
            // return `None` and we fall through to the default
            // handler.
            //
            // The range guard here matches the dispatcher's two
            // ranges: NPPMSG..NPPMSG+200 for the mainline NPPM_*
            // family, and RUNCOMMAND_USER..+100 for the handful of
            // host-environment queries (`NPPM_GETNPPDIRECTORY`,
            // `NPPM_GETNPPFULLFILEPATH`). Pre-filtering at the
            // wnd_proc layer keeps `dispatch_plugin_message` (and
            // the `state_from_hwnd` traversal it requires) off the
            // hot path for every non-plugin WM_USER message.
            m if (NPPMSG..NPPMSG + NPPMSG_RANGE).contains(&m)
                || (RUNCOMMAND_USER..RUNCOMMAND_USER + RUNCOMMAND_RANGE).contains(&m) =>
            {
                if let Some(state) = state_from_hwnd(hwnd) {
                    // Snapshot the active tab before dispatch so
                    // we can detect plugin-driven flips
                    // (`NPPM_SWITCHTOFILE`, `NPPM_DOOPEN` on a
                    // background-loaded path, `NPPM_ACTIVATEDOC`,
                    // `NPPM_LOADSESSION`, ŌĆ”). These paths mutate
                    // `Shell.active_tab` directly and don't return
                    // an `OpenFileOutcome`, so the interactive
                    // path's return-value hook doesn't reach them.
                    // Without a rebind here the Scintilla view
                    // stays bound to the *previous* tab's document
                    // ŌĆö a subsequent Ctrl+S would read the stale
                    // buffer's text and write it to the *new*
                    // active tab's path, silently corrupting an
                    // unrelated file on disk.
                    let pre_active = state.shell.active_tab;
                    let handles = state.host_handles(hwnd);
                    let (shell, mut ui) = state.split();
                    // SAFETY: `(msg, wparam, lparam)` are forwarded
                    // verbatim from a real Win32 wnd_proc dispatch;
                    // `handles` describes the same window. The
                    // plugin sending the message is bound by the
                    // documented NPPM_* ABI in the compat headers.
                    // No nested `unsafe` block needed ŌĆö the entire
                    // wnd_proc body runs inside one already.
                    let routed =
                        shell.dispatch_plugin_message(&mut ui, handles, m, wparam.0, lparam.0);
                    // After the dispatch borrow ends, drain any
                    // FIF-launch prefill the plugin queued via
                    // NPPM_LAUNCHFINDINFILESDLG and open the dialog
                    // with the directory / filters pre-filled.
                    //
                    // **PLUGIN_CALL_ACTIVE invariant:** if a plugin
                    // re-entered this arm from inside its own
                    // `beNotified` (PluginCallGuard active), the
                    // outer `state_from_hwnd` above would have
                    // returned `None` and we'd never reach here ŌĆö
                    // so a re-entrant `NPPM_LAUNCHFINDINFILESDLG`
                    // never reaches the dispatcher and never
                    // writes a stale prefill. The drain below
                    // therefore only sees prefills produced from a
                    // non-re-entrant plugin call, and consumes
                    // them on the same wnd_proc tick.
                    //
                    // The dialog HWND is stashed on `WindowState`
                    // BEFORE `apply_fif_prefill` so any
                    // CBN_EDITCHANGE the SetWindowTextW writes
                    // might surface (the dialog wndproc handles
                    // those, not main_wnd_proc, but defence in
                    // depth) sees the up-to-date dialog handle
                    // rather than a stale `None`.
                    let prefill =
                        state_from_hwnd(hwnd).and_then(|s| s.shell.take_fif_launch_prefill());
                    if let Some(prefill) = prefill {
                        let existing = state_from_hwnd(hwnd).and_then(|s| s.find_replace_dlg);
                        if let Some(dlg) =
                            show_find_replace_dialog(hwnd, existing, FindReplaceTab::FindInFiles)
                        {
                            if let Some(s) = state_from_hwnd(hwnd) {
                                s.find_replace_dlg = Some(dlg);
                            }
                            apply_fif_prefill(dlg, &prefill);
                        }
                    }
                    // Detect plugin-driven active-tab flips and
                    // synchronously rebind the view. Fire on any
                    // net active-tab change whose target isn't
                    // still loading ŌĆö for a still-loading tab,
                    // `apply_load_result` will do the rebind on
                    // the WM_APP_WAKE drain instead.
                    //
                    // Do **not** gate on `scintilla_doc != 0`:
                    // background-loaded tabs (session restore /
                    // NPPM_LOADSESSION opening multiple files at
                    // once) finish with `scintilla_doc == 0`
                    // whenever they weren't the active tab at
                    // load-completion time ŌĆö nothing will re-fire
                    // the load, so waiting on WM_APP_WAKE would
                    // leave them permanently unrebound.
                    // `handle_tab_selchange` already lazily
                    // materialises the document from `tab.text`
                    // in that case (see its `text_to_populate`
                    // branch); the interactive paths above
                    // (ID_FILE_OPEN / WM_DROPFILES / FIF dblclk)
                    // deliberately fire it without any doc-pointer
                    // check for the same reason. Without this,
                    // an NPPM_SWITCHTOFILE / NPPM_ACTIVATEDOC /
                    // NPPM_DOOPEN dedupe onto such a background
                    // tab leaves `Shell.active_tab` and the
                    // visible Scintilla document out of sync,
                    // and the next Ctrl+S silently writes the
                    // still-bound previous buffer's text to the
                    // new active tab's path.
                    let needs_rebind = state_from_hwnd(hwnd)
                        .and_then(|s| {
                            let new_active = s.shell.active_tab?;
                            if Some(new_active) == pre_active {
                                return None;
                            }
                            let tab = s.shell.tabs.get(new_active)?;
                            if tab.pending_load.is_some() {
                                return None;
                            }
                            Some(())
                        })
                        .is_some();
                    if needs_rebind {
                        refresh_tab_chrome(hwnd);
                        handle_tab_selchange(hwnd);
                    }
                    match routed {
                        Some(lr) => LRESULT(lr),
                        None => DefWindowProcW(hwnd, msg, wparam, lparam),
                    }
                } else {
                    // No state yet (early WM_NCCREATE territory); fall
                    // through to default. Plugins shouldn't be
                    // sending NPPM_* this early ŌĆö they receive
                    // `npp_hwnd` from `setInfo`, which only runs
                    // once the WindowState exists.
                    DefWindowProcW(hwnd, msg, wparam, lparam)
                }
            }
            WM_NOTIFY => {
                // lParam points to an NMHDR; for tab-control
                // notifications it points to the start of a tab-
                // specific struct whose first field is NMHDR. We
                // only act on TCN_SELCHANGE for our own tab control;
                // other WM_NOTIFY senders fall through to default.
                let nmhdr_ptr = lparam.0 as *const NMHDR;
                if !nmhdr_ptr.is_null() {
                    // SAFETY (covered by the wnd_proc's outer
                    // `unsafe` block): Win32 hands us a valid NMHDR
                    // pointer for the duration of the dispatch. We
                    // read by value into a local; nothing escapes.
                    let nmhdr = *nmhdr_ptr;
                    // Toolbar background custom-draw. The default
                    // `ToolbarWindow32` UxTheme paints a system-
                    // grey backdrop that reads as visually heavy
                    // against Code++'s light chrome ŌĆö users on
                    // Win10/11 light mode consistently describe it
                    // as "9x-era." UxTheme routes its background
                    // paint through NM_CUSTOMDRAW / CDDS_PREPAINT
                    // to the parent BEFORE it paints the buttons,
                    // so filling `nmcd.rc` here with our own
                    // chrome brush lands under the button paint ŌĆö
                    // the themed hover / pressed / disabled glyphs
                    // continue to draw correctly on top.
                    //
                    // Return `CDRF_NOTIFYITEMDRAW` (not
                    // `CDRF_SKIPDEFAULT`) so the toolbar still
                    // hands each button back to UxTheme for its
                    // normal themed paint ŌĆö skipping default would
                    // strip the theme entirely, losing hover
                    // states, and force us into full owner-draw
                    // (tracked as Phase 5 option (c) in DESIGN.md
                    // ┬¦7.4). Item stages currently pass through
                    // via `CDRF_DODEFAULT` ŌĆö no per-button
                    // overrides today.
                    //
                    // Colour source is `dialog_bg_brush()`
                    // (`DIALOG_BG = 0xF9F9F9`), the same brush the
                    // Find/Replace and Goto dialogs use, so all of
                    // Code++'s chrome bars converge on a single
                    // near-white shade. Matches the perceptual
                    // "menu bar + status bar look" that motivated
                    // this change without picking up the specific
                    // system-colour drift that `COLOR_MENUBAR` /
                    // `COLOR_3DFACE` show across theme variants.
                    if nmhdr.code == NM_CUSTOMDRAW {
                        let owns_source = if let Some(state) = state_from_hwnd(hwnd) {
                            nmhdr.hwndFrom == state.toolbar_hwnd
                        } else {
                            false
                        };
                        if owns_source {
                            // SAFETY: outer wnd_proc `unsafe`
                            // block; `lparam` is a valid pointer
                            // to an `NMCUSTOMDRAW`-prefixed struct
                            // (the toolbar sends `NMTBCUSTOMDRAW`,
                            // whose first field is `NMCUSTOMDRAW`)
                            // for the dispatch's duration. Read
                            // by shared reference ŌĆö no mutation.
                            let nmcd = &*(lparam.0 as *const NMCUSTOMDRAW);
                            if nmcd.dwDrawStage == CDDS_PREPAINT {
                                FillRect(nmcd.hdc, &raw const nmcd.rc, dialog_bg_brush());
                                return LRESULT(CDRF_NOTIFYITEMDRAW as isize);
                            }
                            return LRESULT(CDRF_DODEFAULT as isize);
                        }
                    }
                    if nmhdr.code == TCN_SELCHANGE {
                        // Filter on the source HWND so a future
                        // sibling tab control doesn't accidentally
                        // drive our state machine.
                        let owns_source = if let Some(state) = state_from_hwnd(hwnd) {
                            nmhdr.hwndFrom == state.tab_hwnd
                        } else {
                            false
                        };
                        if owns_source {
                            handle_tab_selchange(hwnd);
                        }
                    } else if nmhdr.code == SCN_STYLENEEDED {
                        // Container-lexer styling request (Phase
                        // 4.6 m1c-3b-1). Fires when Scintilla
                        // needs styling for a range and no
                        // Lexilla lexer is attached (we put the
                        // view in container mode via
                        // `clear_lexer` inside `apply_udl_lang`).
                        // Read the target end position from the
                        // SCNotification, look up the active
                        // UDL, and paint the line-aligned range.
                        //
                        // Only handle notifications from OUR
                        // Scintilla view ŌĆö plugin-created
                        // Scintilla controls (via
                        // NPPM_CREATESCINTILLAHANDLE) would
                        // also route through this WM_NOTIFY
                        // handler, but their styling is the
                        // plugin's own concern.
                        //
                        // SAFETY (outer `unsafe`): Win32 hands
                        // us a valid `SCNotification` pointer;
                        // we read `position` by value into a
                        // local.
                        let owns_source = if let Some(state) = state_from_hwnd(hwnd) {
                            nmhdr.hwndFrom == state.scintilla_hwnd
                        } else {
                            false
                        };
                        if owns_source {
                            let sci = &*(lparam.0 as *const SCNotification);
                            let target = sci.position.max(0) as usize;
                            handle_udl_style_needed(hwnd, target);
                        }
                    } else if nmhdr.code == SCN_MODIFIED {
                        // Scintilla's tracking-mode horizontal
                        // scrollWidth is high-water-mark ŌĆö it grows
                        // when a wider line appears but never
                        // shrinks when long lines are deleted, so
                        // the scrollbar stays after the long line
                        // is gone. SCI_SETSCROLLWIDTH(1) resets
                        // `lineWidthMaxSeen`; the next paint
                        // recomputes from the current visible
                        // content. Filter to text-changing
                        // modifications only (insert / delete) ŌĆö
                        // style and fold notifications don't
                        // affect line widths.
                        //
                        // SAFETY (outer `unsafe`): Win32 hands us a
                        // pointer to a Scintilla `SCNotification`
                        // valid for the dispatch; nmhdr is just its
                        // first field. We read modification_type
                        // by value into a local; nothing escapes.
                        let owns_source = if let Some(state) = state_from_hwnd(hwnd) {
                            nmhdr.hwndFrom == state.scintilla_hwnd
                        } else {
                            false
                        };
                        if owns_source {
                            let sci = &*(lparam.0 as *const SCNotification);
                            let modtype = sci.modification_type;
                            let lines_added = sci.lines_added;
                            if (modtype & (SC_MOD_INSERTTEXT | SC_MOD_DELETETEXT)) != 0 {
                                if let Some(state) = state_from_hwnd(hwnd) {
                                    state.editor.send(SCI_SETSCROLLWIDTH, 1, 0);
                                    // Line-number margin: when line
                                    // count changed, repopulate the
                                    // *visible* window with the
                                    // current digit-width. We don't
                                    // walk the whole affected suffix
                                    // ŌĆö that would be O(N) for a
                                    // bulk text load (e.g. opening
                                    // a 100k-line file fires one
                                    // SCN_MODIFIED with linesAdded
                                    // ~= 100k). The off-screen
                                    // suffix gets populated lazily
                                    // by the `SCN_UPDATEUI`
                                    // vertical-scroll hook just
                                    // before those lines enter the
                                    // viewport.
                                    if lines_added != 0 {
                                        populate_visible_line_numbers(&state.editor);
                                    }
                                    // Length / lines refresh on
                                    // every text-modifying edit.
                                    // The SCN_UPDATEUI arm below
                                    // also refreshes, and a
                                    // typical edit fires both
                                    // (SCN_MODIFIED then
                                    // SCN_UPDATEUI) ŌĆö but this
                                    // arm covers scripted edits
                                    // (e.g. plugin paste, FIF
                                    // in-buffer replace) that
                                    // don't move the caret and
                                    // therefore don't trigger
                                    // SCN_UPDATEUI. The double-
                                    // fire is cheap (a handful
                                    // of direct-call reads + 3
                                    // SB_SETTEXTW writes) and
                                    // keeps length/lines in sync
                                    // unconditionally.
                                    refresh_status_dynamic_parts(state.status_hwnd, &state.editor);
                                    // SCN_MODIFIED implies the undo
                                    // stack changed (every edit
                                    // pushes onto it; every
                                    // discardable edit pops).
                                    // Refresh Undo/Redo enabled
                                    // state on every text-changing
                                    // modification ŌĆö covers both
                                    // user keystrokes (which also
                                    // fire SCN_UPDATEUI; the double
                                    // call is cheap, ~10 ┬Ąs each)
                                    // and scripted edits (plugin
                                    // paste, FIF in-buffer replace)
                                    // that don't trigger the
                                    // SCN_UPDATEUI path.
                                    toolbar::refresh_state(state.toolbar_hwnd, &state.editor);
                                }
                            }
                        }
                    } else if nmhdr.code == SCN_SAVEPOINTREACHED || nmhdr.code == SCN_SAVEPOINTLEFT
                    {
                        // Scintilla emits these whenever the bound
                        // document's modify state flips between
                        // "matches last saved" (REACHED) and "has
                        // unsaved edits" (LEFT). Our tab-strip paint
                        // reads `Tab.dirty` rather than calling
                        // `SCI_GETMODIFY` per cell (the live read
                        // requires an expensive doc-pointer-swap
                        // dance for any non-active tab), so this is
                        // the canonical hook that keeps the cache
                        // in sync. Filter on `hwndFrom` so a
                        // plugin-owned Scintilla can't write into
                        // our active tab's dirty bit.
                        let dirty = nmhdr.code == SCN_SAVEPOINTLEFT;
                        let (active, tab_hwnd) = if let Some(state) = state_from_hwnd(hwnd) {
                            if nmhdr.hwndFrom == state.scintilla_hwnd {
                                (state.shell.active_tab, state.tab_hwnd)
                            } else {
                                (None, state.tab_hwnd)
                            }
                        } else {
                            (None, HWND::default())
                        };
                        if let Some(idx) = active {
                            if let Some(state) = state_from_hwnd(hwnd) {
                                if idx < state.shell.tabs.len() {
                                    state.shell.tabs[idx].dirty = dirty;
                                }
                            }
                            invalidate_tab(tab_hwnd, idx);
                        }
                    } else if nmhdr.code == SCN_UPDATEUI {
                        // SCN_UPDATEUI fires on caret movement,
                        // selection change, scrolling, and most
                        // other UI-relevant Scintilla state
                        // shifts. Scoping the source filter to
                        // our Scintilla view keeps a future
                        // sibling editor (Phase 5 split-view)
                        // from cross-talking into our status
                        // bar. The dynamic parts are cheap (a
                        // handful of direct-call queries plus
                        // three SB_SETTEXTW writes), well below
                        // the per-keystroke budget in
                        // DESIGN.md ┬¦8.
                        let owns_source = if let Some(state) = state_from_hwnd(hwnd) {
                            nmhdr.hwndFrom == state.scintilla_hwnd
                        } else {
                            false
                        };
                        if owns_source {
                            // Read the `updated` flags out of the
                            // notification before any
                            // `state_from_hwnd` re-borrow ŌĆö same
                            // pattern as the SCN_MODIFIED arm.
                            let sci = &*(lparam.0 as *const SCNotification);
                            let updated = sci.updated;
                            if let Some(state) = state_from_hwnd(hwnd) {
                                refresh_status_dynamic_parts(state.status_hwnd, &state.editor);
                                // Sync the toolbar's dynamic state
                                // (Undo/Redo enabled, view-toggle
                                // checks). SCN_UPDATEUI fires after
                                // every Scintilla state change the
                                // user can drive ŌĆö typing, undo,
                                // tab switch, view-toggle setter
                                // ŌĆö so this single call covers all
                                // of those without per-event hooks.
                                toolbar::refresh_state(state.toolbar_hwnd, &state.editor);
                                // Vertical scroll moved the visible
                                // window. Lazily populate any newly-
                                // visible line numbers ŌĆö covers the
                                // off-screen suffix that the
                                // SCN_MODIFIED arm intentionally
                                // skipped to avoid the O(N) bulk-
                                // load stall. Filter on
                                // `SC_UPDATE_V_SCROLL` so the broad
                                // SCN_UPDATEUI firehose (caret
                                // movement, selection change) doesn't
                                // re-do this work on every keystroke.
                                if (updated & SC_UPDATE_V_SCROLL) != 0 {
                                    populate_visible_line_numbers(&state.editor);
                                    // Move the Document Map's
                                    // viewport highlight to match
                                    // the new visible-line range in
                                    // the main editor. Handles
                                    // pulled from the outer `state`
                                    // borrow so the update helper
                                    // doesn't re-derive them via
                                    // `state_from_hwnd` ŌĆö that
                                    // would materialise an
                                    // overlapping `&mut WindowState`
                                    // (aliasing UB) since `state` is
                                    // still live for the
                                    // `update_brace_highlight` call
                                    // below.
                                    update_docmap_viewport_indicator(
                                        state.editor,
                                        state.docmap_editor,
                                    );
                                }
                                // Brace-match highlight ŌĆö repaint
                                // whenever the selection moved OR the
                                // document content changed (typing past
                                // a highlighted pair leaves stale
                                // highlight otherwise). Ignore pure-
                                // scroll updates; the caret position
                                // hasn't changed then.
                                if (updated & (SC_UPDATE_SELECTION | SC_UPDATE_CONTENT)) != 0 {
                                    update_brace_highlight(&state.editor);
                                }
                            }
                        }
                    } else if nmhdr.code == NM_DBLCLK {
                        // Source-filter on the FIF listview so we
                        // don't poach double-clicks meant for the
                        // tab strip or any future listview.
                        let owns_listview = if let Some(state) = state_from_hwnd(hwnd) {
                            nmhdr.hwndFrom == state.fif_listview_hwnd
                        } else {
                            false
                        };
                        if owns_listview {
                            let nmia = &*(lparam.0 as *const NMITEMACTIVATE);
                            let row = nmia.iItem;
                            if row >= 0 {
                                handle_fif_listview_dblclk(hwnd, row as usize);
                            }
                        }
                    } else if nmhdr.code == windows::Win32::UI::Controls::TBN_GETINFOTIPW {
                        // Toolbar wants a tooltip for the hovered
                        // button. Filter on the source HWND so the
                        // FIF listview / a future sibling toolbar
                        // doesn't drive our button-tooltip table by
                        // accident. SAFETY (covered by the wnd_proc
                        // outer unsafe): toolbar guarantees lparam
                        // points at a valid `NMTBGETINFOTIPW` whose
                        // `pszText` buffer is writable for
                        // `cchTextMax` UTF-16 units.
                        let owns_source = if let Some(state) = state_from_hwnd(hwnd) {
                            nmhdr.hwndFrom == state.toolbar_hwnd
                        } else {
                            false
                        };
                        if owns_source {
                            toolbar::fill_info_tip(
                                lparam.0 as *mut windows::Win32::UI::Controls::NMTBGETINFOTIPW,
                            );
                        }
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            WM_DRAWITEM => {
                // Owner-draw paint dispatch. The tab control is the
                // only owner-draw control parented under the main
                // window; filter on `CtlType == ODT_TAB` so a future
                // owner-draw button or list doesn't crosstalk.
                //
                // Wrap `paint_tab_item` in `catch_unwind` so a panic
                // (e.g. an OOM in `encode_utf16().collect()` for a
                // tab label, or a future GDI-binding panic on a
                // malformed handle) does not unwind across the
                // `extern "system"` frame ŌĆö that's UB at the FFI
                // boundary, mirroring the catch_unwind treatment in
                // `tab_subclass_proc` and the dialog wnd-procs.
                // On panic we fall through to `DefWindowProcW` so
                // the system supplies a default fill, and `state` is
                // `None` for the same fall-through reason (PluginCallGuard
                // active, or pre-init).
                let dis_ptr = lparam.0 as *const DRAWITEMSTRUCT;
                if !dis_ptr.is_null() {
                    let dis = &*dis_ptr;
                    if dis.CtlType == ODT_TAB {
                        let painted = if let Some(state) = state_from_hwnd(hwnd) {
                            std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                                paint_tab_item(state, dis);
                            }))
                            .is_ok()
                        } else {
                            false
                        };
                        if painted {
                            return LRESULT(1);
                        }
                    }
                }
                DefWindowProcW(hwnd, msg, wparam, lparam)
            }
            _ => DefWindowProcW(hwnd, msg, wparam, lparam),
        }
    }
}

/// Set while a plugin entry-point call is in flight from this UI
/// thread. The flag protects [`state_from_hwnd`] against Win32's
/// re-entrant `SendMessage`: a plugin's `setInfo` (or any synchronous
/// plugin callback) can `SendMessage(npp_handle, NPPM_*, ...)` back
/// into our `wnd_proc` on the same call stack. Without the flag, the
/// re-entrant `wnd_proc` would materialize a second `&mut WindowState`
/// from the same raw pointer while the outer borrow was still live ŌĆö
/// aliasing UB. With the flag, the inner `state_from_hwnd` returns
/// `None` and the inner `wnd_proc` handles the message with no host
/// state (the dispatcher returns 0, which plugins read as "feature
/// unavailable" ŌĆö same fallback Notepad++ produces when its own
/// state is mid-mutation).
///
/// Win32 dispatches messages serially on the owning thread, so a
/// process-wide static is sufficient ŌĆö there's no second thread that
/// could reasonably observe a different value.
static PLUGIN_CALL_ACTIVE: AtomicBool = AtomicBool::new(false);

/// Shadow of Scintilla's font-quality state. Scintilla's public
/// message set lacks a `SCI_GETFONTQUALITY` peer, so the previous
/// value `NPPM_SETSMOOTHFONT` reports has to be tracked here.
/// Single-view Code++ has one editor and the chrome runs on the UI
/// thread, so a process-wide atomic is sufficient ŌĆö same model as
/// `PLUGIN_CALL_ACTIVE`. Default `true` matches Scintilla's
/// `SC_EFF_QUALITY_DEFAULT` start state, which on modern Windows
/// resolves to LCD-optimised / `ClearType` ŌĆö the same pixel
/// rendering the user sees before any plugin call runs. A plugin
/// that calls `NPPM_SETSMOOTHFONT(TRUE)` on a fresh launch
/// therefore reads back the correct previous-state TRUE rather
/// than a misleading FALSE.
static SMOOTH_FONT_STATE: AtomicBool = AtomicBool::new(true);

/// RAII guard that flips [`PLUGIN_CALL_ACTIVE`] on for the duration
/// of a plugin call. Drop unconditionally clears the flag, including
/// on panic ŌĆö so a Rust-authored plugin that panics doesn't leave
/// the host wedged with a permanently-set guard.
struct PluginCallGuard;

impl PluginCallGuard {
    fn enter() -> Self {
        // Reject nested guards. The current call sites never nest
        // (each is a leaf of the wnd_proc that holds no borrow
        // above it), but a future change that adds a second `enter`
        // while one is already armed would silently get a guard
        // whose Drop clears the flag too early ŌĆö re-opening the
        // aliasing window for any plugin code still on the stack.
        //
        // Hard `assert!` (not `debug_assert!`) so release builds
        // catch it too. Every call site invokes `enter()` from
        // inside a `catch_unwind` closure, so the panic is caught
        // there rather than crossing the `extern "system"` boundary.
        assert!(
            !PLUGIN_CALL_ACTIVE.load(Ordering::Acquire),
            "PluginCallGuard nested ŌĆö Drop ordering would clear the flag too early"
        );
        PLUGIN_CALL_ACTIVE.store(true, Ordering::Release);
        Self
    }
}

impl Drop for PluginCallGuard {
    fn drop(&mut self) {
        PLUGIN_CALL_ACTIVE.store(false, Ordering::Release);
    }
}

/// SAFETY: the returned reference borrows from the `Box<WindowState>`
/// stashed in `GWLP_USERDATA`. `wnd_proc` invocations are serialized
/// per-window (Win32 dispatches one at a time on the owning thread),
/// so concurrent mutable aliasing across messages cannot occur ŌĆö but
/// see [`PLUGIN_CALL_ACTIVE`] for re-entrant `SendMessage` from inside
/// plugin code, which IS a path that can produce nested `wnd_proc`
/// calls on the same stack. The flag check refuses the inner
/// borrow when one is already in flight.
unsafe fn state_from_hwnd<'a>(hwnd: HWND) -> Option<&'a mut WindowState> {
    if PLUGIN_CALL_ACTIVE.load(Ordering::Acquire) {
        // Re-entered while a plugin callback is on the stack.
        // Returning None here is what makes the outer borrow safe:
        // the inner wnd_proc never materializes a second
        // &mut WindowState from the raw pointer.
        return None;
    }
    let raw = unsafe { GetWindowLongPtrW(hwnd, GWLP_USERDATA) };
    if raw == 0 {
        None
    } else {
        Some(unsafe { &mut *(raw as *mut WindowState) })
    }
}

/// Maximum plausible path length in TCHARs. Windows long paths can
/// theoretically reach ~32767, but anything longer than that from
/// `DragQueryFileW` is implausible and likely a malformed HDROP. We
/// reject rather than risk an overflow when computing `needed + 1`.
const MAX_PATH_TCHARS: u32 = 32_767;

/// Returns `true` when **any** drop in the batch hit
/// [`OpenFileOutcome::SwitchedToExisting`], i.e. the file was already
/// open in some tab. The `WM_DROPFILES` caller uses that signal to fire
/// a synchronous view rebind ŌĆö see the `ID_FILE_OPEN` dedupe comment
/// for why the tab-strip resync alone isn't sufficient.
///
/// Accumulated with `|=` across the loop rather than tracked as the
/// last-seen result: the shell's `open_file` promotes each opened tab
/// to active in turn, so a mid-loop dedupe flip to a background tab
/// followed by a load-enqueue on a fresh path would leave `active_tab`
/// pointing at the fresh tab (rebound by the load's `WM_APP_WAKE`
/// drain ŌĆö OK). But a mid-loop dedupe followed by `Rejected` (only
/// reachable at the `MAX_OPEN_TABS` cap) would leave `active_tab`
/// pointing at the deduped-to tab with no rebind ŌĆö so we must react
/// if any iteration returned `SwitchedToExisting`.
///
/// SAFETY: `hdrop` must be a valid HDROP handed to us by `WM_DROPFILES`.
unsafe fn handle_dropped_files(state: &mut WindowState, hdrop: HDROP) -> bool {
    // DragQueryFileW with iFile=0xFFFFFFFF returns the count.
    let count = unsafe { DragQueryFileW(hdrop, 0xFFFF_FFFF, None) };
    let mut any_deduped = false;
    for i in 0..count {
        // First call: required-buffer size (TCHARs, exclusive of null).
        let needed = unsafe { DragQueryFileW(hdrop, i, None) };
        if needed == 0 || needed > MAX_PATH_TCHARS {
            // 0 means "no path here" (defensive), and >32767 is the
            // overflow guard: `needed + 1` on a u32 close to MAX would
            // wrap to 0 and we'd allocate an empty buffer, then write
            // OOB on the second DragQueryFileW.
            continue;
        }
        let mut buf = vec![0u16; needed as usize + 1];
        let copied = unsafe { DragQueryFileW(hdrop, i, Some(&mut buf)) } as usize;
        if copied == 0 {
            continue;
        }
        // `copied` excludes the trailing null.
        buf.truncate(copied);
        let path = PathBuf::from(String::from_utf16_lossy(&buf));
        let outcome = state.shell.open_file(path);
        any_deduped |= matches!(outcome, OpenFileOutcome::SwitchedToExisting(_));
    }
    any_deduped
}

#[cfg(test)]
mod colour_helpers_tests {
    use super::darken_colorref;

    /// A typical case: mid-range BGR channels each drop by the
    /// requested delta, no saturation.
    #[test]
    fn darken_middle_range() {
        // BGR 0x80_A0_C0 ŌåÆ each channel down by 0x20 ŌåÆ
        // 0x60_80_A0. Confirms channel independence.
        assert_eq!(darken_colorref(0x00_80_A0_C0, 0x20), 0x00_60_80_A0);
    }

    /// A channel already below `delta` saturates to zero rather
    /// than wrapping around ŌĆö hover state should darken to black,
    /// never explode into a bright colour.
    #[test]
    fn darken_saturates_at_zero() {
        // Blue channel 0x10, delta 0x30 ŌåÆ 0 (saturating). Others
        // (0x40, 0x80) also drop by 0x30 ŌåÆ 0x10, 0x50.
        assert_eq!(darken_colorref(0x00_80_40_10, 0x30), 0x00_50_10_00);
    }

    /// A zero delta is a no-op ŌĆö safety net for a future call
    /// site that forwards a possibly-zero user setting.
    #[test]
    fn darken_zero_delta_is_no_op() {
        assert_eq!(darken_colorref(0x00_11_22_33, 0), 0x00_11_22_33);
    }
}

#[cfg(test)]
mod idm_mapping_tests {
    use super::{
        is_plugin_cmd_id, map_npp_idm_to_local, IDM_EDIT_COPY, IDM_EDIT_CUT, IDM_EDIT_DELETE,
        IDM_EDIT_PASTE, IDM_EDIT_REDO, IDM_EDIT_SELECTALL, IDM_EDIT_UNDO, IDM_FILE_CLOSE,
        IDM_FILE_CLOSEALL, IDM_FILE_EXIT, IDM_FILE_NEW, IDM_FILE_OPEN, IDM_FILE_PRINT,
        IDM_FILE_RELOAD, IDM_FILE_RENAME, IDM_FILE_SAVE, IDM_FILE_SAVEALL, IDM_FILE_SAVEAS,
        IDM_FORMAT_ANSI, IDM_FORMAT_AS_UTF_8, IDM_FORMAT_UTF_16BE, IDM_FORMAT_UTF_16LE,
        IDM_FORMAT_UTF_8, IDM_SEARCH_FIND, IDM_SEARCH_FINDINFILES, IDM_SEARCH_FINDNEXT,
        IDM_SEARCH_GOTOLINE, IDM_SEARCH_REPLACE, IDM_VIEW_WRAP, IDM_VIEW_ZOOMIN, IDM_VIEW_ZOOMOUT,
        IDM_VIEW_ZOOMRESTORE, ID_EDIT_COPY, ID_EDIT_CUT, ID_EDIT_DELETE, ID_EDIT_PASTE,
        ID_EDIT_REDO, ID_EDIT_SELECTALL, ID_EDIT_UNDO, ID_ENCODING_ANSI, ID_ENCODING_UTF16_BE,
        ID_ENCODING_UTF16_LE, ID_ENCODING_UTF8, ID_ENCODING_UTF8_BOM, ID_FILE_CLOSE,
        ID_FILE_CLOSE_ALL, ID_FILE_EXIT, ID_FILE_NEW, ID_FILE_OPEN, ID_FILE_PRINT, ID_FILE_RELOAD,
        ID_FILE_RENAME, ID_FILE_SAVE, ID_FILE_SAVE_ALL, ID_FILE_SAVE_AS, ID_SEARCH_FIND,
        ID_SEARCH_FINDINFILES, ID_SEARCH_FINDNEXT, ID_SEARCH_GOTOLINE, ID_SEARCH_REPLACE,
        ID_VIEW_WORDWRAP, ID_VIEW_ZOOMIN, ID_VIEW_ZOOMOUT, ID_VIEW_ZOOMRESET,
        PLUGIN_ALLOC_CMD_LIMIT, PLUGIN_CMD_ID_BASE,
    };

    /// The N++ ABI numeric constants must match `menuCmdID.h` exactly ŌĆö
    /// a divergence would silently drop the dispatch (plugins ship a
    /// specific number on the wire; the mapping table has to match it).
    #[test]
    fn idm_base_values_match_npp_abi() {
        // File section: IDM_BASE(40000) + 1000 + slot.
        assert_eq!(IDM_FILE_NEW, 41001);
        assert_eq!(IDM_FILE_OPEN, 41002);
        assert_eq!(IDM_FILE_SAVE, 41006);
        assert_eq!(IDM_FILE_EXIT, 41011);
        // Edit section: IDM_BASE + 2000 + slot.
        assert_eq!(IDM_EDIT_CUT, 42001);
        assert_eq!(IDM_EDIT_UNDO, 42003);
        // Search section: IDM_BASE + 3000 + slot.
        assert_eq!(IDM_SEARCH_FIND, 43001);
        assert_eq!(IDM_SEARCH_FINDINFILES, 43009);
        // View section: IDM_BASE + 4000 + slot.
        assert_eq!(IDM_VIEW_WRAP, 44007);
        // Format (encoding) section: IDM_BASE + 5000 + slot.
        assert_eq!(IDM_FORMAT_ANSI, 45001);
        assert_eq!(IDM_FORMAT_UTF_8, 45002);
    }

    /// Every entry in the File / Edit / Search / View / Format
    /// sections we care about maps to the equivalent Code++ `ID_*`
    /// that runs the same action. If a mapping regresses, this
    /// test surfaces it before the plugin ABI does.
    #[test]
    fn every_wired_idm_maps_to_expected_local_id() {
        // File.
        assert_eq!(map_npp_idm_to_local(IDM_FILE_NEW), Some(ID_FILE_NEW));
        assert_eq!(map_npp_idm_to_local(IDM_FILE_OPEN), Some(ID_FILE_OPEN));
        assert_eq!(map_npp_idm_to_local(IDM_FILE_CLOSE), Some(ID_FILE_CLOSE));
        assert_eq!(
            map_npp_idm_to_local(IDM_FILE_CLOSEALL),
            Some(ID_FILE_CLOSE_ALL)
        );
        assert_eq!(map_npp_idm_to_local(IDM_FILE_SAVE), Some(ID_FILE_SAVE));
        assert_eq!(
            map_npp_idm_to_local(IDM_FILE_SAVEALL),
            Some(ID_FILE_SAVE_ALL)
        );
        assert_eq!(map_npp_idm_to_local(IDM_FILE_SAVEAS), Some(ID_FILE_SAVE_AS));
        assert_eq!(map_npp_idm_to_local(IDM_FILE_PRINT), Some(ID_FILE_PRINT));
        assert_eq!(map_npp_idm_to_local(IDM_FILE_EXIT), Some(ID_FILE_EXIT));
        assert_eq!(map_npp_idm_to_local(IDM_FILE_RELOAD), Some(ID_FILE_RELOAD));
        assert_eq!(map_npp_idm_to_local(IDM_FILE_RENAME), Some(ID_FILE_RENAME));
        // Edit.
        assert_eq!(map_npp_idm_to_local(IDM_EDIT_CUT), Some(ID_EDIT_CUT));
        assert_eq!(map_npp_idm_to_local(IDM_EDIT_COPY), Some(ID_EDIT_COPY));
        assert_eq!(map_npp_idm_to_local(IDM_EDIT_UNDO), Some(ID_EDIT_UNDO));
        assert_eq!(map_npp_idm_to_local(IDM_EDIT_REDO), Some(ID_EDIT_REDO));
        assert_eq!(map_npp_idm_to_local(IDM_EDIT_PASTE), Some(ID_EDIT_PASTE));
        assert_eq!(map_npp_idm_to_local(IDM_EDIT_DELETE), Some(ID_EDIT_DELETE));
        assert_eq!(
            map_npp_idm_to_local(IDM_EDIT_SELECTALL),
            Some(ID_EDIT_SELECTALL)
        );
        // Search.
        assert_eq!(map_npp_idm_to_local(IDM_SEARCH_FIND), Some(ID_SEARCH_FIND));
        assert_eq!(
            map_npp_idm_to_local(IDM_SEARCH_FINDNEXT),
            Some(ID_SEARCH_FINDNEXT)
        );
        assert_eq!(
            map_npp_idm_to_local(IDM_SEARCH_REPLACE),
            Some(ID_SEARCH_REPLACE)
        );
        assert_eq!(
            map_npp_idm_to_local(IDM_SEARCH_GOTOLINE),
            Some(ID_SEARCH_GOTOLINE)
        );
        assert_eq!(
            map_npp_idm_to_local(IDM_SEARCH_FINDINFILES),
            Some(ID_SEARCH_FINDINFILES)
        );
        // View.
        assert_eq!(map_npp_idm_to_local(IDM_VIEW_ZOOMIN), Some(ID_VIEW_ZOOMIN));
        assert_eq!(
            map_npp_idm_to_local(IDM_VIEW_ZOOMOUT),
            Some(ID_VIEW_ZOOMOUT)
        );
        // IDM_VIEW_ZOOMRESTORE has an intentional name difference
        // from ID_VIEW_ZOOMRESET ŌĆö verify the cross-name mapping.
        assert_eq!(
            map_npp_idm_to_local(IDM_VIEW_ZOOMRESTORE),
            Some(ID_VIEW_ZOOMRESET)
        );
        assert_eq!(map_npp_idm_to_local(IDM_VIEW_WRAP), Some(ID_VIEW_WORDWRAP));
        // Format / encoding ŌĆö the AS_UTF_8 ŌåÆ UTF8_BOM mapping is
        // the load-bearing cross-name pairing here.
        assert_eq!(
            map_npp_idm_to_local(IDM_FORMAT_ANSI),
            Some(ID_ENCODING_ANSI)
        );
        assert_eq!(
            map_npp_idm_to_local(IDM_FORMAT_UTF_8),
            Some(ID_ENCODING_UTF8)
        );
        assert_eq!(
            map_npp_idm_to_local(IDM_FORMAT_AS_UTF_8),
            Some(ID_ENCODING_UTF8_BOM)
        );
        assert_eq!(
            map_npp_idm_to_local(IDM_FORMAT_UTF_16LE),
            Some(ID_ENCODING_UTF16_LE)
        );
        assert_eq!(
            map_npp_idm_to_local(IDM_FORMAT_UTF_16BE),
            Some(ID_ENCODING_UTF16_BE)
        );
    }

    /// Unmapped IDM_* values (Notepad++ features Code++ doesn't
    /// implement yet ŌĆö session save/load, macro record, etc.) must
    /// return `None` so the caller can log-and-drop instead of
    /// falling through into an unrelated Code++ command.
    #[test]
    fn unmapped_idm_returns_none() {
        // Random unmapped IDM_* ŌĆö the SETTING / TOOLS / MACRO / RUN
        // section bases from menuCmdID.h have no mapped children.
        assert_eq!(map_npp_idm_to_local(46000), None); // IDM_SETTING
        assert_eq!(map_npp_idm_to_local(47000), None); // IDM_TOOLS
        assert_eq!(map_npp_idm_to_local(48000), None); // IDM_MACRO
        assert_eq!(map_npp_idm_to_local(49000), None); // IDM_RUN
                                                       // Middle of the IDM_FILE range that's not a wired command
                                                       // (IDM_FILE_LOADSESSION == 41012).
        assert_eq!(map_npp_idm_to_local(41012), None);
        // Plugin-cmd space is intentionally NOT in the mapping ŌĆö
        // the dispatcher passes those through untouched.
        assert_eq!(map_npp_idm_to_local(PLUGIN_CMD_ID_BASE), None);
        assert_eq!(map_npp_idm_to_local(PLUGIN_CMD_ID_BASE + 100), None);
        // Negative / zero ŌĆö plugin bug or garbage; must be dropped.
        assert_eq!(map_npp_idm_to_local(0), None);
        assert_eq!(map_npp_idm_to_local(-1), None);
    }

    /// `is_plugin_cmd_id` accepts every id in the plugin-owned
    /// range [`PLUGIN_CMD_ID_BASE`, `PLUGIN_ALLOC_CMD_LIMIT`] and
    /// rejects everything else. The upper bound matters: without it,
    /// a plugin sending an id past the alloc-pool ceiling would
    /// truncate through `WM_COMMAND`'s low-16-bit key in
    /// `main_wnd_proc` and alias onto a small built-in `ID_*` value
    /// (e.g. `ID_FILE_SAVE = 1000`), silently triggering the wrong
    /// action. Failing closed here keeps buggy plugins from firing
    /// unrelated host commands.
    #[test]
    fn plugin_cmd_id_range_bounds_are_closed() {
        // Below the range ŌĆö built-in IDM_* section, garbage, negative.
        assert!(!is_plugin_cmd_id(0));
        assert!(!is_plugin_cmd_id(-1));
        assert!(!is_plugin_cmd_id(PLUGIN_CMD_ID_BASE - 1));
        // Inside the range ŌĆö FuncItem base and alloc pool both count.
        assert!(is_plugin_cmd_id(PLUGIN_CMD_ID_BASE));
        assert!(is_plugin_cmd_id(PLUGIN_CMD_ID_BASE + 100));
        assert!(is_plugin_cmd_id(PLUGIN_ALLOC_CMD_LIMIT));
        // Above the range ŌĆö the WM_COMMAND truncation collision zone.
        // A hypothetical `PLUGIN_ALLOC_CMD_LIMIT + 1` (65_501) with
        // its low 16 bits (65_501 & 0xFFFF = 65_501) is above u16::MAX
        // and would truncate; larger values are the real collision
        // (e.g. 66536 & 0xFFFF = 1000, aliasing ID_FILE_SAVE).
        assert!(!is_plugin_cmd_id(PLUGIN_ALLOC_CMD_LIMIT + 1));
        assert!(!is_plugin_cmd_id(65_536 + i32::from(super::ID_FILE_SAVE)));
        assert!(!is_plugin_cmd_id(i32::MAX));
    }

    /// The plugin-cmd threshold must sit above every `IDM_*` section
    /// base so plugin-allocated ids can't accidentally collide with
    /// a mapping-table entry. Highest `IDM_*` section base in
    /// `menuCmdID.h` is `IDM_RUN` (49000); `PLUGIN_CMD_ID_BASE` is
    /// `50_000` so the two ranges stay disjoint with a comfortable
    /// buffer. Enforced at compile time ŌĆö a bump of
    /// `PLUGIN_CMD_ID_BASE` that violated this would fail to
    /// compile. The upper bound is also asserted here so a shrink
    /// of the alloc pool below the range floor is caught early.
    const _: () = assert!(PLUGIN_CMD_ID_BASE > 49_999);
    const _: () = assert!(PLUGIN_ALLOC_CMD_LIMIT >= PLUGIN_CMD_ID_BASE);
}

#[cfg(test)]
mod file_menu_extension_tests {
    use super::extract_extension_with_dot;
    use std::path::PathBuf;

    /// A typical case: the extractor prepends the required dot,
    /// yielding the exact form `AssocQueryStringW` expects.
    #[test]
    fn common_extension_is_returned_with_leading_dot() {
        assert_eq!(
            extract_extension_with_dot(&PathBuf::from(r"C:\src\lib.rs")),
            Some(".rs".to_string())
        );
        assert_eq!(
            extract_extension_with_dot(&PathBuf::from("notes.txt")),
            Some(".txt".to_string())
        );
    }

    /// Files with no extension (README, Makefile) have no
    /// association to probe ŌĆö the menu item must grey. Returning
    /// `None` from the extractor is the mechanism.
    #[test]
    fn no_extension_returns_none() {
        assert_eq!(
            extract_extension_with_dot(&PathBuf::from(r"C:\project\README")),
            None
        );
        assert_eq!(extract_extension_with_dot(&PathBuf::from("Makefile")), None);
    }

    /// Dot-files (`.gitignore`, `.env`) ŌĆö `Path::extension`
    /// returns `None` for these on both Unix and Windows, so the
    /// extractor mirrors that. Consistent with N++ behaviour:
    /// dot-files grey the entry until the user gives them a real
    /// extension.
    #[test]
    fn dot_files_have_no_extension() {
        assert_eq!(
            extract_extension_with_dot(&PathBuf::from(".gitignore")),
            None
        );
        assert_eq!(
            extract_extension_with_dot(&PathBuf::from(r"C:\src\.env")),
            None
        );
    }

    /// Multi-dot files (`archive.tar.gz`) ŌĆö `Path::extension`
    /// returns only the trailing segment. That matches what a
    /// user pastes into the shell association picker, so
    /// probing on `.gz` is the correct behaviour (there's no
    /// per-`.tar.gz` handler in the registry).
    #[test]
    fn multi_dot_returns_final_segment_only() {
        assert_eq!(
            extract_extension_with_dot(&PathBuf::from(r"C:\dl\archive.tar.gz")),
            Some(".gz".to_string())
        );
    }

    /// Trailing-dot filenames (`weird.`) ŌĆö `Path::extension`
    /// returns `Some("")` on some platforms. The extractor
    /// filters empty extensions to avoid probing `"."`, which
    /// would return spurious hits from mis-configured
    /// associations.
    #[test]
    fn trailing_dot_returns_none() {
        assert_eq!(extract_extension_with_dot(&PathBuf::from("weird.")), None);
    }

    /// Case is preserved verbatim ŌĆö Windows filesystems are
    /// case-insensitive, and `AssocQueryStringW` normalises
    /// internally, so `.TXT` and `.txt` reach the same handler.
    /// Round-tripping the on-disk casing here is cheaper than a
    /// `to_lowercase()` allocation on every menu open.
    #[test]
    fn case_is_preserved() {
        assert_eq!(
            extract_extension_with_dot(&PathBuf::from("README.MD")),
            Some(".MD".to_string())
        );
    }

    /// Live probe against the Windows shell registry. `.exe` is
    /// guaranteed to have a registered handler on every Windows
    /// installation (Windows Explorer double-clicks it); a
    /// deliberately nonsense extension must fail to distinguish
    /// itself from the generic "Unknown" fallback (that's what
    /// [`ASSOCF_INIT_IGNOREUNKNOWN`] guarantees). Pins the correct
    /// combination of flag + HRESULT check ŌĆö a regression on
    /// either (dropping the flag, matching the wrong success
    /// code) would fail exactly this test.
    ///
    /// Runs only on Windows because the underlying
    /// `AssocQueryStringW` symbol is Windows-only. On Linux/macOS
    /// the whole `ui_win32` crate isn't built into the app anyway,
    /// but its cfg-gates keep the test suite green on those CI
    /// runners.
    #[cfg(target_os = "windows")]
    #[test]
    fn extension_check_distinguishes_registered_from_missing() {
        use super::extension_has_registered_handler;
        assert!(
            extension_has_registered_handler(".exe"),
            ".exe must resolve to the OS's registered handler on every Windows install"
        );
        assert!(
            !extension_has_registered_handler(".zzzznotreal-codepp-testonly"),
            "unregistered extension must fail ŌĆö otherwise the greying logic \
             never fires and the menu entry is permanently enabled"
        );
    }
}

#[cfg(test)]
mod strip_prefix_case_insensitive_tests {
    use super::strip_prefix_case_insensitive;
    use std::path::{Path, PathBuf};

    /// Common case: target and prefix share components, target has
    /// more. The relative remainder must include EVERY component of
    /// target that isn't in prefix ŌĆö regression against the bug
    /// where the `(_, None)` match arm consumed the first extra
    /// component in the pattern but dropped it in the `t_iter.collect()`
    /// that followed, yielding a `PathBuf` missing its topmost segment.
    #[test]
    fn returns_all_target_components_past_prefix() {
        let target = Path::new(r"C:\Users\Max\Projects\code-plus-plus\crates\ui_win32\src\lib.rs");
        let prefix = Path::new(r"C:\Users\Max\Projects\code-plus-plus");
        let rel = strip_prefix_case_insensitive(target, prefix).expect("should match");
        assert_eq!(rel, PathBuf::from(r"crates\ui_win32\src\lib.rs"));
    }

    /// Drive-letter case difference. Windows filesystems are
    /// case-insensitive; a `c:` vs `C:` mismatch must not defeat
    /// the strip. Std's `Path::strip_prefix` is case-SENSITIVE and
    /// would return `None` here ŌĆö this is the reason
    /// `strip_prefix_case_insensitive` exists.
    #[test]
    fn drive_letter_case_mismatch_is_tolerated() {
        let target = Path::new(r"c:\users\max\projects\code-plus-plus\readme.md");
        let prefix = Path::new(r"C:\Users\Max\Projects\code-plus-plus");
        let rel = strip_prefix_case_insensitive(target, prefix).expect("should match");
        assert_eq!(rel, PathBuf::from("readme.md"));
    }

    /// Component case difference deeper in the path ŌĆö also
    /// tolerated.
    #[test]
    fn interior_component_case_mismatch_is_tolerated() {
        let target = Path::new(r"C:\Users\MAX\projects\Code-Plus-Plus\src");
        let prefix = Path::new(r"C:\users\Max\PROJECTS\code-plus-plus");
        let rel = strip_prefix_case_insensitive(target, prefix).expect("should match");
        assert_eq!(rel, PathBuf::from("src"));
    }

    /// Target and prefix identical: relative remainder is empty.
    #[test]
    fn identical_paths_yield_empty_rel() {
        let target = Path::new(r"C:\Users\Max\code");
        let prefix = Path::new(r"C:\Users\Max\code");
        let rel = strip_prefix_case_insensitive(target, prefix).expect("should match");
        assert_eq!(rel, PathBuf::new());
    }

    /// Target diverges from prefix mid-path: no match.
    #[test]
    fn diverging_paths_return_none() {
        let target = Path::new(r"C:\Users\Max\OtherProject\file.rs");
        let prefix = Path::new(r"C:\Users\Max\code-plus-plus");
        assert_eq!(strip_prefix_case_insensitive(target, prefix), None);
    }

    /// Target shorter than prefix: no match.
    #[test]
    fn target_shorter_than_prefix_returns_none() {
        let target = Path::new(r"C:\Users\Max");
        let prefix = Path::new(r"C:\Users\Max\code-plus-plus");
        assert_eq!(strip_prefix_case_insensitive(target, prefix), None);
    }

    /// Single-component past prefix ŌĆö the most stripped-down form
    /// of the regressed bug. Must return that one component.
    #[test]
    fn single_extra_component_survives() {
        let target = Path::new(r"C:\workspace\just-one-more");
        let prefix = Path::new(r"C:\workspace");
        let rel = strip_prefix_case_insensitive(target, prefix).expect("should match");
        assert_eq!(rel, PathBuf::from("just-one-more"));
    }
}

#[cfg(test)]
mod fif_filter_tests {
    use super::{apply_filters_to_walk_opts, FilterParseError};
    use codepp_core::FifWalkOpts;
    use std::path::Path;

    fn included(opts: &FifWalkOpts, rel: &str) -> bool {
        opts.path_matches(Path::new(rel))
    }

    #[test]
    fn empty_and_match_all_sentinels_install_no_includes() {
        for input in ["", "   ", "*", "*.*", "* *.*"] {
            let mut opts = FifWalkOpts::default();
            apply_filters_to_walk_opts(&mut opts, input).expect("ok");
            // No includes installed ŌåÆ every non-excluded file is searched.
            assert!(included(&opts, "src/foo.rs"), "input {input:?}");
            assert!(included(&opts, "src/foo.h"), "input {input:?}");
        }
    }

    #[test]
    fn bare_extension_glob_matches_at_any_depth() {
        let mut opts = FifWalkOpts::default();
        apply_filters_to_walk_opts(&mut opts, "*.rs").expect("ok");
        assert!(included(&opts, "src/foo.rs"));
        assert!(included(&opts, "deep/nested/dir/foo.rs"));
        assert!(!included(&opts, "src/foo.h"));
    }

    #[test]
    fn multiple_tokens_union_as_includes() {
        let mut opts = FifWalkOpts::default();
        apply_filters_to_walk_opts(&mut opts, "*.cpp *.h").expect("ok");
        assert!(included(&opts, "src/foo.cpp"));
        assert!(included(&opts, "src/foo.h"));
        assert!(!included(&opts, "src/foo.rs"));
    }

    #[test]
    fn already_double_star_prefixed_is_passed_through() {
        let mut opts = FifWalkOpts::default();
        apply_filters_to_walk_opts(&mut opts, "**/src/*.rs").expect("ok");
        assert!(included(&opts, "src/foo.rs"));
        assert!(included(&opts, "deep/src/foo.rs"));
        assert!(!included(&opts, "lib/foo.rs"));
    }

    #[test]
    fn negation_token_is_rejected() {
        let mut opts = FifWalkOpts::default();
        let err = apply_filters_to_walk_opts(&mut opts, "*.rs !*.test.rs").unwrap_err();
        assert!(matches!(err, FilterParseError::NegationUnsupported));
    }
}

#[cfg(test)]
mod line_number_format_tests {
    use super::line_number_width;

    #[test]
    fn width_grows_at_decimal_boundaries() {
        // Single-digit floor: even 0 / 1 lines need width 1 so an
        // empty-buffer placeholder shows "1" instead of nothing.
        assert_eq!(line_number_width(0), 1);
        assert_eq!(line_number_width(1), 1);
        assert_eq!(line_number_width(9), 1);
        // 9 ŌåÆ 10 boundary: width jumps to 2 so "10" fits.
        assert_eq!(line_number_width(10), 2);
        assert_eq!(line_number_width(99), 2);
        // 99 ŌåÆ 100 boundary: the user's reported case.
        assert_eq!(line_number_width(100), 3);
        assert_eq!(line_number_width(999), 3);
        assert_eq!(line_number_width(1_000), 4);
        assert_eq!(line_number_width(99_999), 5);
        assert_eq!(line_number_width(100_000), 6);
    }

    #[test]
    fn formatted_line_numbers_share_a_rightmost_column() {
        // Mirror of the user's reference case: in a 100-line file
        // (width = 3), `1`, `99`, and `100` should all render with
        // the rightmost digit at the same column when prefixed
        // with the 1-char left pad. Verifying via direct format!
        // call rather than going through Scintilla.
        let width = line_number_width(100);
        assert_eq!(format!(" {:>width$}", 1, width = width), "   1");
        assert_eq!(format!(" {:>width$}", 99, width = width), "  99");
        assert_eq!(format!(" {:>width$}", 100, width = width), " 100");
    }
}

#[cfg(test)]
mod status_bar_format_tests {
    use super::format_thousands;

    #[test]
    fn small_numbers_pass_through_unchanged() {
        assert_eq!(format_thousands(0), "0");
        assert_eq!(format_thousands(7), "7");
        assert_eq!(format_thousands(99), "99");
        assert_eq!(format_thousands(999), "999");
    }

    #[test]
    fn thousand_separators_at_every_third_digit_from_the_right() {
        assert_eq!(format_thousands(1_000), "1,000");
        assert_eq!(format_thousands(1_234), "1,234");
        assert_eq!(format_thousands(12_345), "12,345");
        assert_eq!(format_thousands(123_456), "123,456");
        assert_eq!(format_thousands(1_234_567), "1,234,567");
        assert_eq!(format_thousands(1_000_000_000), "1,000,000,000");
    }

    #[test]
    fn large_u64_values_format_correctly() {
        // ~2 GiB ŌĆö Scintilla's document-size ceiling. The actual
        // upper bound `format_thousands` could see in production.
        assert_eq!(format_thousands(2_147_483_647), "2,147,483,647");
    }
}

#[cfg(test)]
mod wide_string_equals_tests {
    use super::wide_string_equals;

    fn make_wide(s: &str) -> Vec<u16> {
        let mut v: Vec<u16> = s.encode_utf16().collect();
        v.push(0);
        v
    }

    #[test]
    fn null_pointer_returns_false() {
        // SAFETY: NULL is the documented input ŌĆö the function
        // is defensively NULL-safe and short-circuits.
        assert!(!unsafe { wide_string_equals(core::ptr::null(), "anything") });
    }

    #[test]
    fn exact_match_is_true() {
        let w = make_wide("ImmersiveColorSet");
        // SAFETY: `w` is a properly-aligned, NUL-terminated
        // Vec<u16> living for the duration of the call.
        assert!(unsafe { wide_string_equals(w.as_ptr(), "ImmersiveColorSet") });
    }

    #[test]
    fn longer_wide_string_is_false() {
        // Defensive: "ImmersiveColorSetX" must not match
        // "ImmersiveColorSet" ŌĆö the post-prefix NUL check rejects.
        let w = make_wide("ImmersiveColorSetX");
        assert!(!unsafe { wide_string_equals(w.as_ptr(), "ImmersiveColorSet") });
    }

    #[test]
    fn shorter_wide_string_is_false() {
        // Wide string is a strict prefix of the expected ŌĆö the
        // mid-loop NUL check rejects.
        let w = make_wide("Immersive");
        assert!(!unsafe { wide_string_equals(w.as_ptr(), "ImmersiveColorSet") });
    }

    #[test]
    fn different_string_is_false() {
        let w = make_wide("Environment");
        assert!(!unsafe { wide_string_equals(w.as_ptr(), "ImmersiveColorSet") });
    }

    #[test]
    fn empty_wide_against_empty_expected_is_true() {
        // An empty wide string (just the NUL) matches an empty
        // expected ŌĆö the post-prefix check passes immediately.
        let w = make_wide("");
        assert!(unsafe { wide_string_equals(w.as_ptr(), "") });
    }

    #[test]
    fn non_ascii_expected_is_false() {
        // The compare path only handles ASCII expected strings ŌĆö
        // a multi-byte UTF-8 expected character would compare
        // byte-by-byte against u16 code units which is wrong.
        // The fn returns false up front to avoid the trap.
        let w = make_wide("r├®sum├®");
        assert!(!unsafe { wide_string_equals(w.as_ptr(), "r├®sum├®") });
    }
}

#[cfg(test)]
mod tab_display_name_tests {
    use super::{move_to_recycle_bin_prompt_for, save_confirm_prompt_for, tab_display_name};
    use codepp_shell::Tab;
    use std::path::PathBuf;

    #[test]
    fn titled_tab_returns_basename() {
        let tab = Tab {
            path: Some(PathBuf::from("C:/Users/foo/notes.txt")),
            ..Tab::default()
        };
        assert_eq!(tab_display_name(&tab), "notes.txt");
    }

    #[test]
    fn untitled_tab_with_seq_returns_new_n() {
        let tab = Tab {
            path: None,
            untitled_seq: Some(3),
            ..Tab::default()
        };
        assert_eq!(tab_display_name(&tab), "new 3");
    }

    #[test]
    fn untitled_tab_without_seq_returns_untitled_fallback() {
        // Defensive case ŌĆö a path-less tab with no sequence
        // shouldn't normally exist, but the display name must
        // still be a sensible label.
        let tab = Tab {
            path: None,
            untitled_seq: None,
            ..Tab::default()
        };
        assert_eq!(tab_display_name(&tab), "Untitled");
    }

    #[test]
    fn custom_name_overrides_untitled_seq() {
        // File ŌåÆ Rename... on `new 3` produces a tab with
        // `untitled_seq = Some(3)` AND `custom_name = Some(...)`.
        // The display label must be the user-chosen name, not
        // the sequence number ŌĆö that's the entire point of the
        // feature.
        let tab = Tab {
            path: None,
            untitled_seq: Some(3),
            custom_name: Some("scratchpad".to_string()),
            ..Tab::default()
        };
        assert_eq!(tab_display_name(&tab), "scratchpad");
    }

    #[test]
    fn custom_name_overrides_path_basename() {
        // Defensive priority test: even if a tab has both a path
        // and a `custom_name` (which shouldn't normally happen
        // because `save_buffer_as` clears `custom_name`), the
        // custom name still wins so the tab strip honours the
        // documented priority order. Catches a regression where
        // the `or_else` arms in `tab_display_name` get reordered.
        let tab = Tab {
            path: Some(PathBuf::from("/tmp/notes.txt")),
            custom_name: Some("renamed".to_string()),
            ..Tab::default()
        };
        assert_eq!(tab_display_name(&tab), "renamed");
    }

    #[test]
    fn control_chars_in_basename_are_stripped() {
        // `sanitize_filename_for_display` removes control
        // characters before the dialog format inserts the
        // name into the prompt ŌĆö without that, a filename
        // with `\n` would inject newlines into the message
        // box.
        let tab = Tab {
            path: Some(PathBuf::from("with\nlinefeed.txt")),
            ..Tab::default()
        };
        let name = tab_display_name(&tab);
        assert!(!name.contains('\n'), "got {name:?}");
    }

    #[test]
    fn move_to_recycle_bin_prompt_matches_spec() {
        // The user-facing wording must match the spec verbatim.
        // Pin the exact string so a stray edit to either the
        // format literal or this assertion trips the test.
        let out =
            move_to_recycle_bin_prompt_for(std::path::Path::new(r"C:\Users\Max\Downloads\test.rb"));
        assert_eq!(
            out,
            "The file \"C:\\Users\\Max\\Downloads\\test.rb\"\n\
             will be moved to your Recycle Bin and this document will be closed.\n\
             Continue?"
        );
    }

    #[test]
    fn move_to_recycle_bin_prompt_handles_spaces_in_path() {
        // A common Windows case: spaces in the path shouldn't
        // require quoting or escaping in the display ŌĆö they're
        // just rendered inside the outer quotes. Guards against
        // a future format-string edit that adds its own
        // shell-style quoting.
        let out = move_to_recycle_bin_prompt_for(std::path::Path::new(
            r"C:\Users\Max\Downloads\example - Copy.rb",
        ));
        assert!(out.contains(r#""C:\Users\Max\Downloads\example - Copy.rb""#));
    }

    #[test]
    fn save_confirm_prompt_format_matches_spec() {
        // The dialog text the user sees when closing a dirty
        // tab ŌĆö verbatim spec: "Save file 'NAME' ?". Calls the
        // production helper directly so a stray edit to either
        // the format string or this assertion trips the test.
        assert_eq!(
            save_confirm_prompt_for("notes.txt"),
            "Save file 'notes.txt' ?"
        );
    }

    #[test]
    fn save_confirm_prompt_uses_untitled_name_verbatim() {
        // Untitled tabs feed their "new N" name straight into
        // the dialog ŌĆö no special-casing in the prompt.
        assert_eq!(save_confirm_prompt_for("new 3"), "Save file 'new 3' ?");
    }
}

#[cfg(test)]
mod ofn_multi_select_parser_tests {
    //! Unit tests for `parse_ofn_multi_select_buffer` ŌĆö the
    //! parser that decodes the double-NUL-terminated wide-char
    //! buffer `GetOpenFileNameW(OFN_ALLOWMULTISELECT | OFN_EXPLORER)`
    //! writes on success. Confirms both single-file and
    //! multi-file result shapes are recognised and joined
    //! correctly, and that the trailing NUL padding Windows
    //! leaves in the buffer doesn't leak into the output.

    use super::parse_ofn_multi_select_buffer;
    use std::path::PathBuf;

    /// Build a double-NUL-terminated wide-char buffer from a list
    /// of fields, then pad with more NULs to simulate the
    /// zero-initialised tail of a 32 KiB Vec that Windows only
    /// wrote a prefix of.
    fn wide_buf(fields: &[&str], pad_zeros: usize) -> Vec<u16> {
        let mut out: Vec<u16> = Vec::new();
        for f in fields {
            out.extend(f.encode_utf16());
            out.push(0);
        }
        // Final terminating NUL (making it double-NUL).
        out.push(0);
        out.extend(std::iter::repeat_n(0u16, pad_zeros));
        out
    }

    #[test]
    fn single_file_returns_one_full_path() {
        // Single-file shape: full path, NUL, NUL, [padding].
        let buf = wide_buf(&[r"C:\Users\foo\notes.txt"], 100);
        let out = parse_ofn_multi_select_buffer(&buf);
        assert_eq!(out, vec![PathBuf::from(r"C:\Users\foo\notes.txt")]);
    }

    #[test]
    fn multi_file_joins_each_name_onto_the_directory() {
        // Multi-file shape: directory, NUL, name1, NUL, name2,
        // NUL, name3, NUL, NUL.
        let buf = wide_buf(&[r"C:\Users\foo", "a.txt", "b.txt", "c.txt"], 50);
        let out = parse_ofn_multi_select_buffer(&buf);
        assert_eq!(
            out,
            vec![
                PathBuf::from(r"C:\Users\foo\a.txt"),
                PathBuf::from(r"C:\Users\foo\b.txt"),
                PathBuf::from(r"C:\Users\foo\c.txt"),
            ]
        );
    }

    #[test]
    fn empty_buffer_yields_no_paths() {
        // Simulates the buffer state after Cancel (nothing
        // written) ŌĆö every byte NUL.
        let buf = vec![0u16; 64];
        let out = parse_ofn_multi_select_buffer(&buf);
        assert!(out.is_empty());
    }

    #[test]
    fn trailing_padding_does_not_produce_ghost_entries() {
        // Even 10 KiB of trailing zeros must not manifest as
        // empty-string PathBufs in the result. The `take_while
        // !slice.is_empty()` stop condition guards this.
        let buf = wide_buf(&[r"C:\dir", "one.txt"], 10 * 1024);
        let out = parse_ofn_multi_select_buffer(&buf);
        assert_eq!(out, vec![PathBuf::from(r"C:\dir\one.txt")]);
    }

    #[test]
    fn unicode_paths_round_trip_through_utf16() {
        // Non-ASCII in both directory and filename ŌĆö verifies
        // `String::from_utf16_lossy` doesn't corrupt the
        // characters and that `PathBuf::push` joins correctly.
        let buf = wide_buf(&[r"C:\ą¤ąŠą╗čīąĘąŠą▓ą░čéąĄą╗ąĖ", "ąĘą░ą╝ąĄčéą║ąĖ.txt", "µŚźµ£¼Ķ¬×.md"], 30);
        let out = parse_ofn_multi_select_buffer(&buf);
        assert_eq!(
            out,
            vec![
                PathBuf::from(r"C:\ą¤ąŠą╗čīąĘąŠą▓ą░čéąĄą╗ąĖ\ąĘą░ą╝ąĄčéą║ąĖ.txt"),
                PathBuf::from(r"C:\ą¤ąŠą╗čīąĘąŠą▓ą░čéąĄą╗ąĖ\µŚźµ£¼Ķ¬×.md"),
            ]
        );
    }

    #[test]
    fn single_file_with_spaces_returns_full_path() {
        // Spaces are legal filesystem characters; verify they
        // don't accidentally trigger the multi-file
        // disambiguation (the OFN_EXPLORER protocol is
        // NUL-separated, not space-separated ŌĆö this test pins
        // that guarantee).
        let buf = wide_buf(&[r"C:\Program Files\My App\notes v2.txt"], 20);
        let out = parse_ofn_multi_select_buffer(&buf);
        assert_eq!(
            out,
            vec![PathBuf::from(r"C:\Program Files\My App\notes v2.txt")]
        );
    }
}

#[cfg(test)]
mod close_multi_target_tests {
    //! Unit tests for `pick_next_close_target` ŌĆö the pure
    //! inspector that drives `close_multiple_documents`. Focus
    //! is on the data-loss-preventing `pending_load` filter:
    //! a still-loading tab must never be chosen as a close
    //! target under any variant, because activating it via
    //! `handle_window_menu_click` would populate the editor
    //! with an empty document from the empty `tab.text` and
    //! open the door to a "Save changes to X?" prompt that
    //! writes 0 bytes over the real file on Yes.

    use super::{pick_next_close_target, CloseMultiKind};
    use codepp_shell::Tab;

    fn mk(id: i32) -> Tab {
        Tab {
            id,
            ..Tab::default()
        }
    }

    fn mk_pending(id: i32) -> Tab {
        // `pending_load` is `Option<RequestId>` where `RequestId`
        // is a plain `u64` alias; a dummy value is enough to make
        // `.is_some()` fire. The exact request-id doesn't affect
        // the filter.
        Tab {
            id,
            pending_load: Some(1),
            ..Tab::default()
        }
    }

    fn mk_pinned(id: i32) -> Tab {
        Tab {
            id,
            pinned: true,
            ..Tab::default()
        }
    }

    fn mk_dirty(id: i32) -> Tab {
        Tab {
            id,
            dirty: true,
            ..Tab::default()
        }
    }

    #[test]
    fn all_to_left_skips_pending_load_adjacent_to_keeper() {
        // [pending(1), real(2), keeper(3)] with keeper=3.
        // Old behaviour targeted absolute index 0 (the pending
        // tab) and would activate it, opening the empty-doc
        // hazard. The fix must return index 1 (the real tab).
        let tabs = vec![mk_pending(1), mk(2), mk(3)];
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllToLeft, 3),
            Some(1)
        );
    }

    #[test]
    fn all_to_left_returns_none_when_only_pending_left_of_keeper() {
        // [pending(1), keeper(2)] ŌĆö nothing closable to the left.
        // Under the old logic this returned Some(0), driving the
        // loop to activate the still-loading tab. The fix must
        // return None so the loop terminates cleanly.
        let tabs = vec![mk_pending(1), mk(2)];
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllToLeft, 2),
            None
        );
    }

    #[test]
    fn all_to_right_skips_pending_load_adjacent_to_keeper() {
        // [keeper(1), pending(2), real(3)] with keeper=1. Old
        // behaviour targeted keeper_pos+1 = 1 (the pending tab);
        // the fix must return index 2 (the real tab).
        let tabs = vec![mk(1), mk_pending(2), mk(3)];
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllToRight, 1),
            Some(2)
        );
    }

    #[test]
    fn all_to_right_returns_none_when_only_pending_right_of_keeper() {
        let tabs = vec![mk(1), mk_pending(2)];
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllToRight, 1),
            None
        );
    }

    #[test]
    fn all_but_active_skips_pending_load() {
        let tabs = vec![mk_pending(1), mk(2), mk(3)];
        // keeper=2, so 1 (pending) and 3 (real) are candidates ŌĆö
        // must pick 3 (position 2) not 0 (pending).
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllButActive, 2),
            Some(2)
        );
    }

    #[test]
    fn all_but_pinned_skips_pending_load() {
        // [pinned(1), pending(2), real(3)]. Neither pinned nor
        // pending should be chosen ŌĆö the real one at index 2
        // is the only valid target.
        let tabs = vec![mk_pinned(1), mk_pending(2), mk(3)];
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllButPinned, 3),
            Some(2)
        );
    }

    #[test]
    fn all_unchanged_skips_pending_load() {
        // A pending-load tab has `dirty = false` (initialised
        // that way), so the naive "not dirty" predicate would
        // pick it. The pending-load filter must gate that out
        // ŌĆö otherwise the pending tab still ends up activated
        // and re-opens the empty-doc hazard.
        let tabs = vec![mk_pending(1), mk_dirty(2), mk(3)];
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllUnchanged, 2),
            Some(2)
        );
    }

    #[test]
    fn all_pending_returns_none_across_every_variant() {
        // Only pending-load tabs remain. Every variant must
        // return None so the outer loop terminates instead of
        // spinning on an untouchable target.
        let tabs = vec![mk_pending(1), mk_pending(2), mk_pending(3)];
        for kind in [
            CloseMultiKind::AllButActive,
            CloseMultiKind::AllButPinned,
            CloseMultiKind::AllToLeft,
            CloseMultiKind::AllToRight,
            CloseMultiKind::AllUnchanged,
        ] {
            assert_eq!(
                pick_next_close_target(&tabs, kind, 2),
                None,
                "kind={kind:?} should return None"
            );
        }
    }

    #[test]
    fn baseline_no_pending_still_produces_expected_targets() {
        // Sanity that the filter doesn't over-fire on a clean
        // input (no pending tabs). [A(1), B(2), C(3), D(4), E(5)]
        // with keeper C(3).
        let tabs = vec![mk(1), mk(2), mk(3), mk(4), mk(5)];
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllToLeft, 3),
            Some(0)
        );
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllToRight, 3),
            Some(3)
        );
        assert_eq!(
            pick_next_close_target(&tabs, CloseMultiKind::AllButActive, 3),
            Some(0)
        );
    }
}

#[cfg(test)]
mod brace_match_tests {
    use super::{
        extra_fold_properties, is_brace, BG_BRACE_LIGHT, FG_BRACE_BAD, FG_BRACE_LIGHT, FOLD_MARGIN,
        FOLD_MARGIN_BG, FOLD_MARGIN_HI, FOLD_MARGIN_PX, FOLD_MARKER_ACTIVE, FOLD_MARKER_BG,
        FOLD_MARKER_FG,
    };
    use codepp_core::lang::{
        L_BASH, L_BATCH, L_C, L_CPP, L_CS, L_JAVA, L_JAVASCRIPT, L_LISP, L_LUA, L_MAKEFILE, L_OBJC,
        L_PYTHON, L_RC, L_RUST, L_SCHEME, L_TCL, L_TEXT,
    };

    #[test]
    fn is_brace_matches_all_eight_ascii_bracket_chars() {
        for c in [b'(', b')', b'[', b']', b'{', b'}', b'<', b'>'] {
            assert!(is_brace(c), "expected `{c}` (byte {c:#04x}) to be a brace");
        }
    }

    #[test]
    fn is_brace_rejects_non_bracket_bytes() {
        for c in [b'a', b'Z', b'0', b'9', b' ', b'"', b'\'', b'\\', b'/', 0u8] {
            assert!(!is_brace(c), "byte {c:#04x} must not be a brace");
        }
    }

    #[test]
    fn cpp_family_gets_preprocessor_and_explicit_comment_props() {
        for lang in [L_C, L_CPP, L_CS, L_JAVA, L_JAVASCRIPT, L_OBJC, L_RC, L_RUST] {
            let props = extra_fold_properties(lang);
            assert!(
                props
                    .iter()
                    .any(|(k, v)| *k == "fold.preprocessor" && *v == "1"),
                "{lang:?} missing fold.preprocessor=1"
            );
            assert!(
                props
                    .iter()
                    .any(|(k, v)| *k == "fold.cpp.comment.explicit" && *v == "0"),
                "{lang:?} missing fold.cpp.comment.explicit=0"
            );
        }
    }

    #[test]
    fn python_gets_fold_quotes_python() {
        assert_eq!(
            extra_fold_properties(L_PYTHON),
            &[("fold.quotes.python", "1")]
        );
    }

    #[test]
    fn non_extra_languages_get_empty_slice() {
        for lang in [L_BASH, L_TCL, L_LISP, L_SCHEME, L_LUA, L_TEXT] {
            assert!(
                extra_fold_properties(lang).is_empty(),
                "{lang:?} unexpectedly has fold sub-properties"
            );
        }
    }

    #[test]
    fn non_foldable_lexers_still_get_empty_slice() {
        for lang in [L_BATCH, L_MAKEFILE] {
            assert!(
                extra_fold_properties(lang).is_empty(),
                "{lang:?} must not attempt to set fold sub-properties ŌĆö lexer has no fold function"
            );
        }
    }

    #[test]
    fn npp_colour_and_geometry_defaults_pin_to_stylers_model_xml() {
        // Brace: N++ RGB #FF0000 (bold) and #800000 ŌåÆ BBGGRR encoded
        // as 0x0000FF and 0x000080.
        assert_eq!(FG_BRACE_LIGHT, 0x00_00_00_FF);
        assert_eq!(FG_BRACE_BAD, 0x00_00_00_80);
        assert_eq!(BG_BRACE_LIGHT, 0x00_FF_FF_FF);
        // Fold marker + margin: greys and white are palindromic in
        // COLORREF, so these values match N++'s RGB #F3F3F3 /
        // #808080 / #FF0000 / #E9E9E9 / #FFFFFF verbatim.
        assert_eq!(FOLD_MARKER_FG, 0x00_F3_F3_F3);
        assert_eq!(FOLD_MARKER_BG, 0x00_80_80_80);
        assert_eq!(FOLD_MARKER_ACTIVE, 0x00_00_00_FF);
        assert_eq!(FOLD_MARGIN_BG, 0x00_E9_E9_E9);
        assert_eq!(FOLD_MARGIN_HI, 0x00_FF_FF_FF);
        // Margin index + width match N++'s ScintillaEditView.cpp
        // defaults (index 3 in N++, index 2 here per Code++'s
        // change-history at index 4 layout).
        assert_eq!(FOLD_MARGIN, 2);
        assert_eq!(FOLD_MARGIN_PX, 14);
    }
}

#[cfg(test)]
mod save_confirm_result_tests {
    use super::{save_confirm_from_message_box, SaveConfirmResult};
    use windows::Win32::UI::WindowsAndMessaging::{IDABORT, IDCANCEL, IDNO, IDOK, IDYES};

    #[test]
    fn idyes_maps_to_yes() {
        assert_eq!(save_confirm_from_message_box(IDYES), SaveConfirmResult::Yes);
    }

    #[test]
    fn idno_maps_to_no() {
        assert_eq!(save_confirm_from_message_box(IDNO), SaveConfirmResult::No);
    }

    #[test]
    fn idcancel_maps_to_cancel() {
        assert_eq!(
            save_confirm_from_message_box(IDCANCEL),
            SaveConfirmResult::Cancel
        );
    }

    #[test]
    fn unexpected_dismissal_maps_to_cancel() {
        // Esc / Alt-F4 / dialog X / IDABORT / IDOK ŌĆö anything
        // that isn't an explicit Yes or No maps to Cancel
        // (the safe default: don't proceed with a destructive
        // action when the user didn't affirm one).
        assert_eq!(
            save_confirm_from_message_box(IDABORT),
            SaveConfirmResult::Cancel
        );
        assert_eq!(
            save_confirm_from_message_box(IDOK),
            SaveConfirmResult::Cancel
        );
    }
}

